UPDATE hadiths SET urdu = 'ہمیں حدیث بیان کی یعقوب بن ابراہیم نے، ان کو ابن علیہ نے، وہ عبدالعزیز بن صہیب سے روایت کرتے ہیں، وہ انس رضی اللہ عنہ سے وہ نبی کریم صلی اللہ علیہ وسلم سے نقل کرتے ہیں اور ہم کو آدم بن ابی ایاس نے حدیث بیان کی، ان کو شعبہ نے، وہ قتادہ سے نقل کرتے ہیں، وہ انس رضی اللہ عنہ سے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا تم میں سے کوئی شخص ایماندار نہ ہو گا جب تک اس کے والد اور اس کی اولاد اور تمام لوگوں سے زیادہ اس کے دل میں میری محبت نہ ہو جائے۔' WHERE id = 16;
UPDATE hadiths SET urdu = 'اس حدیث کو ہم سے عبداللہ بن محمد مسندی نے بیان کیا، ان سے ابوروح حرمی بن عمارہ نے، ان سے شعبہ نے، وہ واقد بن محمد سے روایت کرتے ہیں، وہ کہتے ہیں میں نے یہ حدیث اپنے باپ سے سنی، وہ ابن عمر رضی اللہ عنہما سے روایت کرتے ہیں کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا، مجھے ( اللہ کی طرف سے ) حکم دیا گیا ہے کہ لوگوں سے جنگ کروں اس وقت تک کہ وہ اس بات کا اقرار کر لیں کہ اللہ کے سوا کوئی معبود نہیں ہے اور یہ کہ محمد صلی اللہ علیہ وسلم اللہ کے سچے رسول ہیں اور نماز ادا کرنے لگیں اور زکوٰۃ دیں، جس وقت وہ یہ کرنے لگیں گے تو مجھ سے اپنے جان و مال کو محفوظ کر لیں گے، سوائے اسلام کے حق کے۔ ( رہا ان کے دل کا حال تو ) ان کا حساب اللہ کے ذمے ہے۔' WHERE id = 26;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، انہیں شعیب نے خبر دی، کہا ان سے ابوالزناد نے اعرج کے واسطے سے بیان کیا، اعرج نے ابوہریرہ رضی اللہ عنہ سے نقل کیا، وہ کہتے ہیں کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا، جو شخص شب قدر ایمان کے ساتھ محض ثواب آخرت کے لیے ذکر و عبادت میں گزارے، اس کے گزشتہ گناہ بخش دئیے جاتے ہیں۔' WHERE id = 36;
UPDATE hadiths SET urdu = 'ہم سے اس حدیث کو حسن بن صباح نے بیان کیا، انہوں نے جعفر بن عون سے سنا، وہ ابوالعمیس سے بیان کرتے ہیں، انہیں قیس بن مسلم نے طارق بن شہاب کے واسطے سے خبر دی۔ وہ عمر بن خطاب رضی اللہ عنہ سے روایت کرتے ہیں کہ ایک یہودی نے ان سے کہا کہ اے امیرالمؤمنین! تمہاری کتاب ( قرآن ) میں ایک آیت ہے جسے تم پڑھتے ہو۔ اگر وہ ہم یہودیوں پر نازل ہوتی تو ہم اس ( کے نزول کے ) دن کو یوم عید بنا لیتے۔ آپ نے پوچھا وہ کون سی آیت ہے؟ اس نے جواب دیا ( سورۃ المائدہ کی یہ آیت کہ ) ”آج میں نے تمہارے دین کو مکمل کر دیا اور اپنی نعمت تم پر تمام کر دی اور تمہارے لیے دین اسلام پسند کیا“ عمر رضی اللہ عنہ نے فرمایا کہ ہم اس دن اور اس مقام کو ( خوب ) جانتے ہیں جب یہ آیت رسول اللہ صلی اللہ علیہ وسلم پر نازل ہوئی ( اس وقت ) آپ صلی اللہ علیہ وسلم عرفات میں جمعہ کے دن کھڑے ہوئے تھے۔' WHERE id = 46;
UPDATE hadiths SET urdu = 'ہم سے حجاج بن منہال نے بیان کیا، وہ کہتے ہیں کہ ہم سے شعبہ نے بیان کیا، وہ کہتے ہیں مجھ کو عدی بن ثابت نے خبر دی، انہوں نے عبداللہ بن یزید سے سنا، انہوں نے عبداللہ بن مسعود سے نقل کیا انہوں نے نبی کریم صلی اللہ علیہ وسلم سے کہ آپ صلی اللہ علیہ وسلم نے فرمایا جب آدمی ثواب کی نیت سے اپنے اہل و عیال پر خرچ کرے پس وہ بھی اس کے لیے صدقہ ہے۔' WHERE id = 56;
UPDATE hadiths SET urdu = 'ہم سے ابوالحسن محمد بن مقاتل نے بیان کیا، ان سے عبداللہ نے، انہیں شعبہ نے قتادہ سے خبر دی، وہ انس بن مالک رضی اللہ عنہ سے روایت کرتے ہیں، انہوں نے فرمایا کہ رسول اللہ صلی اللہ علیہ وسلم نے ( کسی بادشاہ کے نام دعوت اسلام دینے کے لیے ) ایک خط لکھا یا لکھنے کا ارادہ کیا تو آپ صلی اللہ علیہ وسلم سے کہا گیا کہ وہ بغیر مہر کے خط نہیں پڑھتے ( یعنی بے مہر کے خط کو مستند نہیں سمجھتے ) تب آپ صلی اللہ علیہ وسلم نے چاندی کی انگوٹھی بنوائی۔ جس میں «محمد رسول الله‏» کندہ تھا۔ گویا میں ( آج بھی ) آپ صلی اللہ علیہ وسلم کے ہاتھ میں اس کی سفیدی دیکھ رہا ہوں۔ ( شعبہ راوی حدیث کہتے ہیں کہ ) میں نے قتادہ سے پوچھا کہ یہ کس نے کہا ( کہ ) اس پر «محمد رسول الله‏» کندہ تھا؟ انہوں نے جواب دیا، انس رضی اللہ عنہ نے۔' WHERE id = 66;
UPDATE hadiths SET urdu = 'ہم سے ابومعمر نے بیان کیا، ان سے عبدالوارث نے، ان سے خالد نے عکرمہ کے واسطے سے بیان کیا، وہ ابن عباس رضی اللہ عنہما سے روایت کرتے ہیں۔ انہوں نے فرمایا کہ ( ایک مرتبہ ) رسول اللہ صلی اللہ علیہ وسلم نے مجھے ( سینے سے ) لگا لیا اور دعا دیتے ہوئے فرمایا کہ ”اے اللہ اسے علم کتاب ( قرآن ) عطا فرمائیو“۔' WHERE id = 76;
UPDATE hadiths SET urdu = 'ہم سے مکی ابن ابراہیم نے بیان کیا، انہیں حنظلہ نے سالم سے خبر دی، انہوں نے ابوہریرہ رضی اللہ عنہ سے سنا، وہ رسول اللہ صلی اللہ علیہ وسلم سے روایت کرتے ہیں آپ صلی اللہ علیہ وسلم نے فرمایا کہ ( ایک وقت ایسا آئے گا کہ جب ) علم اٹھا لیا جائے گا۔ جہالت اور فتنے پھیل جائیں گے اور ہرج بڑھ جائے گا۔ آپ سے پوچھا گیا کہ یا رسول اللہ! ہرج سے کیا مراد ہے؟ آپ صلی اللہ علیہ وسلم نے اپنے ہاتھ کو حرکت دے کر فرمایا اس طرح، گویا آپ صلی اللہ علیہ وسلم نے اس سے قتل مراد لیا۔' WHERE id = 86;
UPDATE hadiths SET urdu = 'ہم سے عبدہ نے بیان کیا، ان سے عبدالصمد نے، ان سے عبداللہ بن مثنی نے، ان سے ثمامہ بن عبداللہ بن انس نے، انہوں نے انس بن مالک رضی اللہ عنہ سے بیان کیا، وہ رسول اللہ صلی اللہ علیہ وسلم سے روایت کرتے ہیں کہ جب آپ صلی اللہ علیہ وسلم کوئی کلمہ ارشاد فرماتے تو اسے تین بار لوٹاتے یہاں تک کہ خوب سمجھ لیا جاتا۔ اور جب کچھ لوگوں کے پاس آپ صلی اللہ علیہ وسلم تشریف لاتے اور انہیں سلام کرتے تو تین بار سلام کرتے۔' WHERE id = 96;
UPDATE hadiths SET urdu = '(ہم سے عبداللہ بن عبدالوہاب نے بیان کیا، ان سے حماد نے ایوب کے واسطے سے نقل کیا، وہ محمد سے اور وہ ابن ابی بکرہ سے روایت کرتے ہیں کہ ایک مرتبہ ) ابوبکرہ رضی اللہ عنہ نے رسول اللہ صلی اللہ علیہ وسلم کا ذکر کیا کہ آپ صلی اللہ علیہ وسلم نے ( یوں ) فرمایا، تمہارے خون اور تمہارے مال، محمد کہتے ہیں کہ میرے خیال میں آپ صلی اللہ علیہ وسلم نے «وأعراضكم» کا لفظ بھی فرمایا۔ ( یعنی ) اور تمہاری آبروئیں تم پر حرام ہیں۔ جس طرح تمہارے آج کے دن کی حرمت تمہارے اس مہینے میں۔ سن لو! یہ خبر حاضر غائب کو پہنچا دے۔ اور محمد ( راوی حدیث ) کہتے تھے کہ رسول اللہ صلی اللہ علیہ وسلم نے سچ فرمایا۔ ( پھر ) دوبارہ فرمایا کہ کیا میں نے ( اللہ کا یہ حکم ) تمہیں نہیں پہنچا دیا۔' WHERE id = 106;
UPDATE hadiths SET urdu = 'صدقہ نے ہم سے بیان کیا، انہیں ابن عیینہ نے معمر کے واسطے سے خبر دی، وہ زہری سے روایت کرتے ہیں، زہری ہند سے، وہ ام سلمہ رضی اللہ عنہا سے، (دوسری سند میں) عمرو اور یحییٰ بن سعید زہری سے، وہ ایک عورت سے، وہ ام سلمہ رضی اللہ عنہا سے روایت کرتی ہیں کہ ایک رات نبی کریم صلی اللہ علیہ وسلم نے بیدار ہوتے ہی فرمایا کہ سبحان اللہ! آج کی رات کس قدر فتنے اتارے گئے ہیں اور کتنے ہی خزانے بھی کھولے گئے ہیں۔ ان حجرہ والیوں کو جگاؤ۔ کیونکہ بہت سی عورتیں ( جو ) دنیا میں ( باریک ) کپڑا پہننے والی ہیں وہ آخرت میں ننگی ہوں گی۔' WHERE id = 116;
UPDATE hadiths SET urdu = 'ہم سے قیس بن حفص نے بیان کیا، ان سے عبدالواحد نے، ان سے اعمش سلیمان بن مہران نے ابراہیم کے واسطے سے بیان کیا، انہوں نے علقمہ سے نقل کیا، انہوں نے عبداللہ بن مسعود سے روایت کیا، وہ کہتے ہیں کہ ( ایک مرتبہ ) میں رسول اللہ صلی اللہ علیہ وسلم کے ساتھ مدینہ کے کھنڈرات میں چل رہا تھا اور آپ کھجور کی چھڑی پر سہارا دے کر چل رہے تھے، تو کچھ یہودیوں کا ( ادھر سے ) گزر ہوا، ان میں سے ایک نے دوسرے سے کہا کہ آپ سے روح کے بارے میں کچھ پوچھو، ان میں سے کسی نے کہا مت پوچھو، ایسا نہ ہو کہ وہ کوئی ایسی بات کہہ دیں جو تمہیں ناگوار ہو ( مگر ) ان میں سے بعض نے کہا کہ ہم ضرور پوچھیں گے، پھر ایک شخص نے کھڑے ہو کر کہا، اے ابوالقاسم! روح کیا چیز ہے؟ آپ صلی اللہ علیہ وسلم نے خاموشی اختیار فرمائی، میں نے ( دل میں ) کہا کہ آپ پر وحی آ رہی ہے۔ اس لیے میں کھڑا ہو گیا۔ جب آپ صلی اللہ علیہ وسلم سے ( وہ کیفیت ) دور ہو گئی تو آپ صلی اللہ علیہ وسلم نے ( قرآن کی یہ آیت جو اس وقت نازل ہوئی تھی ) تلاوت فرمائی ” ( اے نبی! ) تم سے یہ لوگ روح کے بارے میں پوچھ رہے ہیں۔ کہہ دو کہ روح میرے رب کے حکم سے ہے۔ اور تمہیں علم کا بہت تھوڑا حصہ دیا گیا ہے۔“ ( اس لیے تم روح کی حقیقت نہیں سمجھ سکتے ) اعمش کہتے ہیں کہ ہماری قرآت میں «وما اوتوا» ہے۔ ( «‏‏‏‏وما اوتيتم» ‏‏‏‏ ) نہیں۔' WHERE id = 126;
UPDATE hadiths SET urdu = 'ہم سے اسحاق بن ابراہیم الحنظلی نے بیان کیا۔ انہیں عبدالرزاق نے خبر دی، انہیں معمر نے ہمام بن منبہ کے واسطے سے بتلایا کہ انہوں نے ابوہریرہ رضی اللہ عنہ سے سنا، وہ کہہ رہے تھے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ جو شخص حدث کرے اس کی نماز قبول نہیں ہوتی جب تک کہ وہ ( دوبارہ ) وضو نہ کر لے۔ حضر موت کے ایک شخص نے پوچھا کہ حدث ہونا کیا ہے؟ آپ صلی اللہ علیہ وسلم نے فرمایا کہ ( پاخانہ کے مقام سے نکلنے والی ) آواز والی یا بےآواز والی ہوا۔' WHERE id = 136;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، انہوں نے کہا کہ ہم کو امام مالک نے یحییٰ بن سعید سے خبر دی۔ وہ محمد بن یحییٰ بن حبان سے، وہ اپنے چچا واسع بن حبان سے روایت کرتے ہیں، وہ عبداللہ بن عمر رضی اللہ عنہما سے روایت کرتے ہیں۔ وہ فرماتے تھے کہ لوگ کہتے تھے کہ جب قضاء حاجت کے لیے بیٹھو تو نہ قبلہ کی طرف منہ کرو نہ بیت المقدس کی طرف ( یہ سن کر ) عبداللہ بن عمر رضی اللہ عنہما نے فرمایا کہ ایک دن میں اپنے گھر کی چھت پر چڑھا تو میں نے نبی کریم صلی اللہ علیہ وسلم کو دیکھا کہ آپ بیت المقدس کی طرف منہ کر کے دو اینٹوں پر قضاء حاجت کے لیے بیٹھے ہیں۔ پھر عبداللہ بن عمر رضی اللہ عنہما نے ( واسع سے ) کہا کہ شاید تم ان لوگوں میں سے ہو جو اپنے چوتڑوں کے بل نماز پڑھتے ہیں۔ تب میں نے کہا اللہ کی قسم! میں نہیں جانتا ( کہ آپ کا مطلب کیا ہے ) امام مالک رحمہ اللہ نے کہا کہ عبداللہ بن عمر رضی اللہ عنہما نے اس سے وہ شخص مراد لیا جو نماز میں زمین سے اونچا نہ رہے، سجدہ میں زمین سے چمٹ جائے۔' WHERE id = 146;
UPDATE hadiths SET urdu = 'ہم سے احمد بن محمد المکی نے بیان کیا، کہا کہ ہم سے عمرو بن یحییٰ بن سعید بن عمرو المکی نے اپنے دادا کے واسطے سے بیان کیا۔ وہ ابوہریرہ رضی اللہ عنہ سے نقل کرتے ہیں، وہ کہتے ہیں کہ رسول اللہ صلی اللہ علیہ وسلم ( ایک مرتبہ ) رفع حاجت کے لیے تشریف لے گئے۔ آپ صلی اللہ علیہ وسلم کی عادت مبارکہ تھی کہ آپ صلی اللہ علیہ وسلم ( چلتے وقت ) ادھر ادھر نہیں دیکھا کرتے تھے۔ تو میں بھی آپ صلی اللہ علیہ وسلم کے پیچھے پیچھے آپ صلی اللہ علیہ وسلم کے قریب پہنچ گیا۔ ( مجھے دیکھ کر ) آپ صلی اللہ علیہ وسلم نے فرمایا کہ مجھے پتھر ڈھونڈ دو، تاکہ میں ان سے پاکی حاصل کروں، یا اسی جیسا ( کوئی لفظ ) فرمایا اور فرمایا کہ ہڈی اور گوبر نہ لانا۔ چنانچہ میں اپنے دامن میں پتھر ( بھر کر ) آپ صلی اللہ علیہ وسلم کے پاس لے گیا اور آپ صلی اللہ علیہ وسلم کے پہلو میں رکھ دئیے اور آپ صلی اللہ علیہ وسلم کے پاس سے ہٹ گیا، جب آپ صلی اللہ علیہ وسلم ( قضاء حاجت سے ) فارغ ہوئے تو آپ صلی اللہ علیہ وسلم نے پتھروں سے استنجاء کیا۔' WHERE id = 156;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا، انہوں نے کہا ہم سے شعبہ نے بیان کیا، انہوں نے کہا ہم سے محمد بن زیاد نے بیان کیا، وہ کہتے ہیں کہ میں نے ابوہریرہ رضی اللہ عنہ سے سنا وہ ہمارے پاس سے گزرے اور لوگ لوٹے سے وضو کر رہے تھے۔ آپ نے کہا اچھی طرح وضو کرو کیونکہ ابوالقاسم صلی اللہ علیہ وسلم نے فرمایا ( خشک ) ایڑیوں کے لیے آگ کا عذاب ہے۔' WHERE id = 166;
UPDATE hadiths SET urdu = 'ہم سے حفص بن عمر نے بیان کیا، کہا کہ ہم سے شعبہ نے ابن ابی السفر کے واسطے سے بیان کیا، وہ شعبی سے نقل فرماتے ہیں، وہ عدی بن حاتم سے روایت کرتے ہیں کہ میں نے رسول اللہ صلی اللہ علیہ وسلم سے ( کتے کے شکار کے متعلق ) دریافت کیا۔ تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ جب تو اپنے سدھائے ہوئے کتے کو چھوڑے اور وہ شکار کر لے تو، تو اس ( شکار ) کو کھا اور اگر وہ کتا اس شکار میں سے خود ( کچھ ) کھا لے تو، تو ( اس کو ) نہ کھائیو۔ کیونکہ اب اس نے شکار اپنے لیے پکڑا ہے۔ میں نے کہا کہ بعض دفعہ میں ( شکار کے لیے ) اپنے کتے چھوڑتا ہوں، پھر اس کے ساتھ دوسرے کتے کو بھی پاتا ہوں۔ آپ صلی اللہ علیہ وسلم نے فرمایا۔ پھر مت کھا۔ کیونکہ تم نے «بسم الله» اپنے کتے پر پڑھی تھی۔ دوسرے کتے پر نہیں پڑھی۔' WHERE id = 176;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، انہوں نے کہا ہم کو امام مالک نے عمرو بن یحییٰ المازنی سے خبر دی، وہ اپنے باپ سے نقل کرتے ہیں کہ ایک آدمی نے عبداللہ بن زید رضی اللہ عنہ جو عمرو بن یحییٰ کے دادا ہیں، سے پوچھا کہ کیا آپ مجھے دکھا سکتے ہیں کہ رسول اللہ صلی اللہ علیہ وسلم نے کس طرح وضو کیا ہے؟ عبداللہ بن زید رضی اللہ عنہ نے کہا کہ ہاں! پھر انہوں نے پانی کا برتن منگوایا پہلے پانی اپنے ہاتھوں پر ڈالا اور دو مرتبہ ہاتھ دھوئے۔ پھر تین مرتبہ کلی کی، تین بار ناک صاف کی، پھر تین دفعہ اپنا چہرہ دھویا۔ پھر کہنیوں تک اپنے دونوں ہاتھ دو دو مرتبہ دھوئے۔ پھر اپنے دونوں ہاتھوں سے اپنے سر کا مسح کیا۔ اس طور پر اپنے ہاتھ ( پہلے ) آگے لائے پھر پیچھے لے گئے۔ ( مسح ) سر کے ابتدائی حصے سے شروع کیا۔ پھر دونوں ہاتھ گدی تک لے جا کر وہیں واپس لائے جہاں سے ( مسح ) شروع کیا تھا، پھر اپنے پیر دھوئے۔' WHERE id = 186;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن منیر نے بیان کیا، انہوں نے عبداللہ بن بکر سے سنا، کہا ہم کو حمید نے یہ حدیث بیان کی۔ انہوں نے انس سے نقل کیا۔ وہ کہتے ہیں کہ ( ایک مرتبہ ) نماز کا وقت آ گیا، تو جس شخص کا مکان قریب ہی تھا وہ وضو کرنے اپنے گھر چلا گیا اور کچھ لوگ ( جن کے مکان دور تھے ) رہ گئے۔ تو رسول اللہ صلی اللہ علیہ وسلم کے پاس پتھر کا ایک لگن لایا گیا۔ جس میں کچھ پانی تھا اور وہ اتنا چھوٹا تھا کہ آپ اس میں اپنی ہتھیلی نہیں پھیلا سکتے تھے۔ ( مگر ) سب نے اس برتن کے پانی سے وضو کر لیا، ہم نے انس رضی اللہ عنہ سے پوچھا کہ تم کتنے نفر تھے؟ کہا اسی ( 80 ) سے کچھ زیادہ ہی تھے۔' WHERE id = 196;
UPDATE hadiths SET urdu = 'ہم سے عبدان نے بیان کیا، کہا ہمیں عبداللہ نے خبر دی، کہا ہم کو اوزاعی نے یحییٰ کے واسطے سے خبر دی، وہ ابوسلمہ سے، وہ جعفر بن عمرو سے، وہ اپنے باپ سے روایت کرتے ہیں کہ میں نے رسول اللہ صلی اللہ علیہ وسلم کو اپنے عمامے اور موزوں پر مسح کرتے دیکھا۔ اس کو روایت کیا معمر نے یحییٰ سے، وہ ابوسلمہ سے، انہوں نے عمرو سے متابعت کی اور کہا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم کو دیکھا ( آپ واقعی ایسا ہی کیا کرتے تھے ) ۔' WHERE id = 206;
UPDATE hadiths SET urdu = 'ہم سے خالد بن مخلد نے بیان کیا، انہوں نے کہا ہم سے سلیمان نے بیان کیا، انہوں نے کہا مجھے یحییٰ بن سعید نے خبر دی، انہیں بشیر بن یسار نے خبر دی، انہوں نے کہا مجھے سوید بن نعمان رضی اللہ عنہ نے بتلایا انہوں نے کہا کہ ہم خیبر والے سال رسول اللہ صلی اللہ علیہ وسلم کے ہمراہ جب صہباء میں پہنچے تو رسول اللہ صلی اللہ علیہ وسلم نے ہمیں عصر کی نماز پڑھائی۔ جب نماز پڑھ چکے تو آپ صلی اللہ علیہ وسلم نے کھانے منگوائے۔ مگر ( کھانے میں ) صرف ستو ہی لایا گیا۔ سو ہم نے ( اسی کو ) کھایا اور پیا۔ پھر رسول اللہ صلی اللہ علیہ وسلم مغرب کی نماز کے لیے کھڑے ہو گئے۔ تو آپ صلی اللہ علیہ وسلم نے کلی کی، پھر ہمیں مغرب کی نماز پڑھائی اور ( نیا ) وضو نہیں کیا۔' WHERE id = 216;
UPDATE hadiths SET urdu = 'ہم سے عثمان ابن ابی شیبہ نے بیان کیا، کہا ہم سے جریر نے منصور کے واسطے سے بیان کیا، وہ ابووائل سے، وہ حذیفہ سے روایت کرتے ہیں۔ وہ کہتے ہیں کہ ( ایک مرتبہ ) میں اور رسول اللہ صلی اللہ علیہ وسلم جا رہے تھے کہ ایک قوم کی کوڑی پر ( جو ) ایک دیوار کے پیچھے ( تھی ) پہنچے۔ تو آپ صلی اللہ علیہ وسلم اس طرح کھڑے ہو گئے جس طرح ہم تم میں سے کوئی ( شخص ) کھڑا ہوتا ہے۔ پھر آپ صلی اللہ علیہ وسلم نے پیشاب کیا اور میں ایک طرف ہٹ گیا۔ تب آپ صلی اللہ علیہ وسلم نے مجھے اشارہ کیا تو آپ صلی اللہ علیہ وسلم کے پاس ( پردہ کی غرض سے ) آپ صلی اللہ علیہ وسلم کی ایڑیوں کے قریب کھڑا ہو گیا۔ یہاں تک کہ آپ صلی اللہ علیہ وسلم پیشاب سے فارغ ہو گئے۔ ( بوقت ضرورت ایسا بھی کیا جا سکتا ہے۔)' WHERE id = 226;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل نے بیان کیا، انہوں نے کہا مجھ کو مالک نے ابن شہاب کے واسطے سے روایت کی، وہ عبیداللہ بن عبداللہ بن عتبہ بن مسعود سے، وہ عبداللہ بن عباس رضی اللہ عنہما سے وہ ام المؤمنین میمونہ رضی اللہ عنہا سے روایت کرتے ہیں کہ رسول اللہ صلی اللہ علیہ وسلم سے چوہے کے بارہ میں پوچھا گیا جو گھی میں گر گیا تھا۔ فرمایا اس کو نکال دو اور اس کے آس پاس ( کے گھی ) کو نکال پھینکو اور اپنا ( باقی ) گھی استعمال کرو۔' WHERE id = 236;
UPDATE hadiths SET urdu = 'ہم سے عثمان بن ابی شیبہ نے بیان کیا، کہا ہم سے جریر نے منصور کے واسطے سے، وہ ابووائل سے، وہ حذیفہ سے روایت کرتے ہیں کہ رسول اللہ صلی اللہ علیہ وسلم جب رات کو اٹھتے تو اپنے منہ کو مسواک سے صاف کرتے۔' WHERE id = 246;
UPDATE hadiths SET urdu = 'محمد بن بشار نے ہم سے حدیث بیان کی، انہوں نے کہا ہم سے غندر نے بیان کیا، انہوں نے کہا کہ ہم سے شعبہ نے بیان کیا، مخول بن راشد کے واسطے سے، وہ محمد ابن علی سے، وہ جابر بن عبداللہ رضی اللہ عنہما سے، انہوں نے فرمایا کہ نبی کریم صلی اللہ علیہ وسلم اپنے سر پر تین مرتبہ پانی بہاتے تھے۔' WHERE id = 256;
UPDATE hadiths SET urdu = 'ہم سے محمد بن محبوب نے بیان کیا، انہوں نے کہا ہم سے عبدالواحد بن زیاد نے بیان کیا، انہوں نے کہا ہم سے اعمش نے سالم بن ابی الجعد کے واسطے سے بیان کیا، انہوں نے کریب مولیٰ ابن عباس سے، انہوں نے عبداللہ بن عباس رضی اللہ عنہما سے کہ میمونہ رضی اللہ عنہا نے کہا کہ میں نے نبی کریم صلی اللہ علیہ وسلم کے لیے غسل کا پانی رکھا۔ تو آپ صلی اللہ علیہ وسلم نے پہلے پانی اپنے ہاتھوں پر گرا کر انہیں دو یا تین بار دھویا۔ پھر اپنے داہنے ہاتھ سے بائیں پر گرا کر اپنی شرمگاہوں کو دھویا۔ پھر ہاتھ کو زمین پر رگڑا۔ پھر کلی کی اور ناک میں پانی ڈالا پھر اپنے چہرے اور ہاتھوں کو دھویا۔ پھر اپنے سر کو تین مرتبہ دھویا، پھر اپنے سارے بدن پر پانی بہایا، پھر آپ اپنی غسل کی جگہ سے الگ ہو گئے۔ پھر اپنے قدموں کو دھویا۔' WHERE id = 266;
UPDATE hadiths SET urdu = 'ہم سے خلاد بن یحییٰ نے بیان کیا، انہوں نے کہا کہ ہم سے ابراہیم بن نافع نے بیان کیا، انہوں نے حسن بن مسلم سے روایت کی، وہ صفیہ بنت شیبہ سے، وہ عائشہ رضی اللہ عنہا سے، آپ نے فرمایا کہ ہم ازواج ( مطہرات ) میں سے کسی کو اگر جنابت لاحق ہوتی تو وہ ہاتھوں میں پانی لے کر سر پر تین مرتبہ ڈالتیں۔ پھر ہاتھ میں پانی لے کر سر کے داہنے حصے کا غسل کرتیں اور دوسرے ہاتھ سے بائیں حصے کا غسل کرتیں۔' WHERE id = 277;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، انہوں نے کہا ہم سے لیث بن سعد نے بیان کیا، انہوں نے نافع سے، وہ ابن عمر رضی اللہ عنہما سے کہ عمر بن خطاب رضی اللہ عنہ نے رسول اللہ صلی اللہ علیہ وسلم سے پوچھا کہ کیا ہم میں سے کوئی جنابت کی حالت میں سو سکتا ہے؟ فرمایا ہاں، وضو کر کے جنابت کی حالت میں بھی سو سکتے ہو۔' WHERE id = 287;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم فضل بن دکین نے بیان کیا، انہوں نے زہیر سے سنا، انہوں نے منصور بن صفیہ سے کہ ان کی ماں نے ان سے بیان کیا کہ عائشہ رضی اللہ عنہا نے ان سے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم میری گود میں سر رکھ کر قرآن مجید پڑھتے، حالانکہ میں اس وقت حیض والی ہوتی تھی۔' WHERE id = 297;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا ہم سے یزید بن زریع نے خالد سے، وہ عکرمہ سے، وہ عائشہ رضی اللہ عنہا سے، آپ نے فرمایا کہ رسول اللہ صلی اللہ علیہ وسلم کے ساتھ آپ صلی اللہ علیہ وسلم کی ازواج میں سے ایک نے اعتکاف کیا۔ وہ خون اور زردی ( نکلتے ) دیکھتیں، طشت ان کے نیچے ہوتا اور نماز ادا کرتی تھیں۔' WHERE id = 308;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد مسندی نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے ہشام بن عروہ سے، وہ اپنے باپ سے، وہ عائشہ سے کہ فاطمہ بنت ابی حبیش کو استحاضہ کا خون آیا کرتا تھا۔ تو انہوں نے نبی کریم صلی اللہ علیہ وسلم سے اس کے متعلق پوچھا۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ یہ رگ کا خون ہے اور حیض نہیں ہے۔ اس لیے جب حیض کے دن آئیں تو نماز چھوڑ دیا کر اور جب حیض کے دن گزر جائیں تو غسل کر کے نماز پڑھ لیا کر۔' WHERE id = 318;
UPDATE hadiths SET urdu = 'ہم سے احمد بن ابی سریح نے بیان کیا، کہا ہم سے شبابہ بن سوار نے، کہا ہم سے شعبہ نے حسین سے۔ وہ عبداللہ بن بریدہ سے، وہ سمرہ بن جندب سے کہ ایک عورت ( ام کعب ) زچگی میں مر گئی، تو رسول اللہ صلی اللہ علیہ وسلم نے ان کی نماز جنازہ پڑھی، اس وقت آپ صلی اللہ علیہ وسلم ان کے ( جسم کے ) وسط میں کھڑے ہو گئے۔' WHERE id = 329;
UPDATE hadiths SET urdu = 'ہم سے مسلم بن ابراہیم نے بیان کیا، کہا ہم سے شعبہ نے حکم سے، انہوں نے ذر بن عبداللہ سے، انہوں نے سعید بن عبدالرحمٰن بن ابزیٰ سے۔ انہوں نے عبدالرحمٰن بن ابزیٰ سے، انہوں نے کہا کہ میں عمر رضی اللہ عنہ کی خدمت میں موجود تھا کہ عمار رضی اللہ عنہ نے ان سے کہا۔ پھر انہوں نے پوری حدیث بیان کی۔' WHERE id = 339;
UPDATE hadiths SET urdu = 'ہم سے احمد بن یونس نے بیان کیا، انہوں نے کہا ہم سے عاصم بن محمد نے بیان کیا، انہوں نے کہا کہ مجھ سے واقد بن محمد نے محمد بن منکدر کے حوالہ سے بیان کیا، انہوں نے کہا کہ جابر بن عبداللہ رضی اللہ عنہما نے تہبند باندھ کر نماز پڑھی۔ جسے انہوں نے سر تک باندھ رکھا تھا اور آپ کے کپڑے کھونٹی پر ٹنگے ہوئے تھے۔ ایک کہنے والے نے کہا کہ آپ ایک تہبند میں نماز پڑھتے ہیں؟ آپ نے جواب دیا کہ میں نے ایسا اس لیے کیا کہ تجھ جیسا کوئی احمق مجھے دیکھے۔ بھلا رسول اللہ صلی اللہ علیہ وسلم کے زمانہ میں دو کپڑے بھی کس کے پاس تھے؟' WHERE id = 349;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے یحییٰ بن سعید قطان نے، انہوں نے سفیان ثوری سے، انہوں نے کہا مجھ سے ابوحازم سلمہ بن دینار نے بیان کیا سہل بن سعد ساعدی سے، انہوں نے کہا کہ کئی آدمی نبی کریم صلی اللہ علیہ وسلم کے ساتھ بچوں کی طرح اپنی گردنوں پر ازاریں باندھے ہوئے نماز پڑھتے تھے اور عورتوں کو ( آپ کے زمانے میں ) حکم تھا کہ اپنے سروں کو ( سجدے سے ) اس وقت تک نہ اٹھائیں جب تک مرد سیدھے ہو کر بیٹھ نہ جائیں۔' WHERE id = 359;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، انہوں نے کہا کہ ہم کو شعیب نے زہری سے خبر دی، کہا کہ مجھے عروہ بن زبیر نے خبر دی کہ عائشہ رضی اللہ عنہا نے فرمایا کہ نبی کریم صلی اللہ علیہ وسلم فجر کی نماز پڑھتے اور آپ صلی اللہ علیہ وسلم کے ساتھ نماز میں کئی مسلمان عورتیں اپنی چادریں اوڑھے ہوئے شریک نماز ہوتیں، پھر اپنے گھروں کو واپس چلی جاتی تھیں، اس وقت انہیں کوئی پہچان نہیں سکتا تھا۔' WHERE id = 369;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل بن ابی اویس نے بیان کیا، کہ کہا مجھ سے امام مالک نے عمر بن عبیداللہ کے غلام ابوالنضر سالم کے حوالہ سے، انہوں نے ابوسلمہ بن عبدالرحمٰن سے، انہوں نے نبی کریم صلی اللہ علیہ وسلم کی زوجہ مطہرہ عائشہ رضی اللہ عنہا سے۔ آپ نے بتلایا کہ میں رسول اللہ صلی اللہ علیہ وسلم کے آگے سو جاتی اور میرے پاؤں آپ صلی اللہ علیہ وسلم کے قبلہ میں ہوتے۔ جب آپ صلی اللہ علیہ وسلم سجدہ کرتے، تو میرے پاؤں کو آہستہ سے دبا دیتے۔ میں اپنے پاؤں سمیٹ لیتی اور آپ جب کھڑے ہو جاتے تو میں انہیں پھر پھیلا دیتی۔ ان دنوں گھروں میں چراغ بھی نہیں ہوا کرتے تھے۔' WHERE id = 379;
UPDATE hadiths SET urdu = 'ہم سے نعیم بن حماد نے بیان کیا، کہا ہم سے عبداللہ ابن مبارک نے حمید طویل کے واسطہ سے، انہوں نے روایت کیا انس بن مالک رضی اللہ عنہ سے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا مجھے حکم دیا گیا ہے کہ میں لوگوں کے ساتھ جنگ کروں یہاں تک کہ وہ «لا إله إلا الله» کہیں۔ پس جب وہ اس کا اقرار کر لیں اور ہماری طرح نماز پڑھنے لگیں اور ہمارے قبلہ کی طرف نماز میں منہ کریں اور ہمارے ذبیحہ کو کھانے لگیں تو ان کا خون اور ان کے اموال ہم پر حرام ہو گئے۔ مگر کسی حق کے بدلے اور ( باطن میں ) ان کا حساب اللہ پر رہے گا۔' WHERE id = 389;
UPDATE hadiths SET urdu = 'ہم سے مسدد بن مسرہد نے بیان کیا کہ کہا ہم سے یحییٰ بن سعید بن قطان نے شعبہ کے واسطے سے، انہوں نے ابراہیم سے، انہوں نے علقمہ سے انہوں نے عبداللہ سے، انہوں نے فرمایا کہ نبی کریم صلی اللہ علیہ وسلم نے ( بھولے سے ) ظہر کی نماز ( ایک مرتبہ ) پانچ رکعت پڑھی ہیں۔ عبداللہ بن مسعود رضی اللہ عنہ نے فرمایا کہ پھر آپ نے اپنے پاؤں موڑ لیے اور ( سہو کے ) دو سجدے کئے۔' WHERE id = 401;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، انہوں نے کہا کہ ہمیں امام مالک نے ابوالزناد سے خبر دی، انہوں نے اعرج سے، انہوں نے ابوہریرہ رضی اللہ عنہ سے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کیا تمہارا یہ خیال ہے کہ میرا منہ ( نماز میں ) قبلہ کی طرف ہے، اللہ کی قسم مجھ سے نہ تمہارا خشوع چھپتا ہے نہ رکوع، میں اپنی پیٹھ کے پیچھے سے تم کو دیکھتا رہتا ہوں۔' WHERE id = 413;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، انہوں نے کہا ہم سے عبدالوارث نے بیان کیا، انہوں نے ابوالتیاح کے واسطہ سے بیان کیا، انہوں نے انس بن مالک رضی اللہ عنہ سے، انہوں نے کہا کہ جب نبی کریم صلی اللہ علیہ وسلم مدینہ تشریف لائے تو یہاں کے بلند حصہ میں بنی عمرو بن عوف کے یہاں آپ اترے اور یہاں چوبیس راتیں قیام فرمایا۔ پھر آپ صلی اللہ علیہ وسلم نے بنونجار کو بلا بھیجا، تو وہ لوگ تلواریں لٹکائے ہوئے آئے۔ انس نے کہا، گویا میری نظروں کے سامنے نبی کریم صلی اللہ علیہ وسلم اپنی سواری پر تشریف فرما ہیں، جبکہ ابوبکر صدیق رضی اللہ عنہ آپ صلی اللہ علیہ وسلم کے پیچھے بیٹھے ہوئے ہیں اور بنو نجار کے لوگ آپ صلی اللہ علیہ وسلم کے چاروں طرف ہیں۔ یہاں تک کہ آپ صلی اللہ علیہ وسلم ابوایوب کے گھر کے سامنے اترے اور آپ صلی اللہ علیہ وسلم یہ پسند کرتے تھے کہ جہاں بھی نماز کا وقت آ جائے فوراً نماز ادا کر لیں۔ آپ بکریوں کے باڑوں میں بھی نماز پڑھ لیتے تھے، پھر آپ نے یہاں مسجد بنانے کے لیے حکم فرمایا۔ چنانچہ بنو نجار کے لوگوں کو آپ صلی اللہ علیہ وسلم نے بلوا کر فرمایا کہ اے بنو نجار! تم اپنے اس باغ کی قیمت مجھ سے لے لو۔ انہوں نے جواب دیا نہیں یا رسول اللہ! اس کی قیمت ہم صرف اللہ سے مانگتے ہیں۔ انس رضی اللہ عنہ نے بیان کیا کہ میں جیسا کہ تمہیں بتا رہا تھا یہاں مشرکین کی قبریں تھیں، اس باغ میں ایک ویران جگہ تھی اور کچھ کھجور کے درخت بھی تھے پس نبی کریم صلی اللہ علیہ وسلم نے مشرکین کی قبروں کو اکھڑوا دیا ویرانہ کو صاف اور برابر کرایا اور درختوں کو کٹوا کر ان کی لکڑیوں کو مسجد کے قبلہ کی جانب بچھا دیا اور پتھروں کے ذریعہ انہیں مضبوط بنا دیا۔ صحابہ پتھر اٹھاتے ہوئے رجز پڑھتے تھے اور نبی کریم صلی اللہ علیہ وسلم بھی ان کے ساتھ تھے اور یہ کہہ رہے تھے کہ اے اللہ! آخرت کے فائدہ کے علاوہ اور کوئی فائدہ نہیں پس انصار و مہاجرین کی مغفرت فرمانا۔' WHERE id = 423;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، انہوں نے کہا کہ ہم سے یحییٰ نے عبیداللہ کے واسطہ سے بیان کیا، انہوں نے کہا کہ مجھ کو نافع نے بیان کیا، کہا کہ مجھے عبداللہ بن عمر رضی اللہ عنہما نے خبر دی کہ وہ اپنی نوجوانی میں جب کہ ان کے بیوی بچے نہیں تھے نبی کریم صلی اللہ علیہ وسلم کی مسجد میں سویا کرتے تھے۔' WHERE id = 434;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن سلیمان نے بیان کیا انہوں نے کہا کہ ہم سے عبداللہ بن وہب نے بیان کیا، انہوں نے کہا کہ مجھ سے عمرو بن حارث نے بیان کیا، انہوں نے کہا ہم سے بکیر بن عبداللہ نے بیان کیا، ان سے عاصم بن عمرو بن قتادہ نے بیان کیا، انہوں نے عبیداللہ بن اسود خولانی سے سنا، انہوں نے عثمان بن عفان رضی اللہ عنہ سے سنا کہ مسجد نبوی کی تعمیر کے متعلق لوگوں کی باتوں کو سن کر آپ نے فرمایا کہ تم لوگوں نے بہت زیادہ باتیں کی ہیں۔ حالانکہ میں نے نبی کریم صلی اللہ علیہ وسلم سے سنا ہے کہ جس نے مسجد بنائی بکیر ( راوی ) نے کہا میرا خیال ہے کہ آپ نے یہ بھی فرمایا کہ اس سے مقصود اللہ تعالیٰ کی رضا ہو، تو اللہ تعالیٰ ایسا ہی ایک مکان جنت میں اس کے لیے بنائے گا۔' WHERE id = 444;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، انہوں نے کہا ہم سے لیث بن سعد نے بیان کیا، انہوں نے کہا مجھ سے سعید بن ابی سعید مقبری نے، انہوں نے ابوہریرہ رضی اللہ عنہ سے سنا کہ رسول اللہ صلی اللہ علیہ وسلم نے کچھ سوار نجد کی طرف بھیجے ( جو تعداد میں تیس تھے ) یہ لوگ بنو حنیفہ کے ایک شخص کو جس کا نام ثمامہ بن اثال تھا پکڑ کر لائے۔ انہوں نے اسے مسجد کے ایک ستون میں باندھ دیا۔ پھر رسول اللہ صلی اللہ علیہ وسلم تشریف لائے۔ اور ( تیسرے روز ثمامہ کی نیک طبیعت دیکھ کر ) آپ صلی اللہ علیہ وسلم نے فرمایا کہ ثمامہ کو چھوڑ دو۔ ( رہائی کے بعد ) وہ مسجد نبوی سے قریب ایک کھجور کے باغ تک گئے۔ اور وہاں غسل کیا۔ پھر مسجد میں داخل ہوئے اور کہا «أشهد أن لا إله إلا الله وأن محمدا رسول الله‏» میں گواہی دیتا ہوں کہ اللہ کے سوا کوئی معبود نہیں اور یہ کہ محمد اللہ کے سچے رسول ہیں۔' WHERE id = 455;
UPDATE hadiths SET urdu = 'ہم سے مسدد بن مسرہد نے بیان کیا کہ کہا ہم سے بشر بن مفضل نے عبیداللہ بن عمر سے، انہوں نے نافع سے، انہوں نے عبداللہ بن عمر رضی اللہ عنہما سے کہ ایک شخص نے نبی کریم صلی اللہ علیہ وسلم سے پوچھا ( جبکہ ) اس وقت آپ صلی اللہ علیہ وسلم منبر پر تھے کہ رات کی نماز ( یعنی تہجد ) کس طرح پڑھنے کے لیے آپ فرماتے ہیں؟ آپ صلی اللہ علیہ وسلم نے فرمایا کہ دو دو رکعت کر کے پڑھ اور جب صبح قریب ہونے لگے تو ایک رکعت پڑھ لے۔ یہ ایک رکعت اس ساری نماز کو طاق بنا دے گی اور آپ صلی اللہ علیہ وسلم فرمایا کرتے تھے کہ رات کی آخری نماز کو طاق رکھا کرو کیونکہ نبی کریم صلی اللہ علیہ وسلم نے اس کا حکم دیا۔' WHERE id = 465;
UPDATE hadiths SET urdu = 'ہم سے ابراہیم بن المنذر حزامی نے بیان کیا، کہا ہم سے انس بن عیاض نے، کہا ہم سے موسیٰ بن عقبہ نے نافع سے، ان کو عبداللہ بن عمر رضی اللہ عنہما نے خبر دی کہ نبی کریم صلی اللہ علیہ وسلم جب عمرہ کے قصد سے تشریف لے گئے اور حجۃ الوداع کے موقعہ پر جب حج کے لیے نکلے تو آپ صلی اللہ علیہ وسلم نے ذوالحلیفہ میں قیام فرمایا۔ ذوالحلیفہ کی مسجد کے قریب آپ صلی اللہ علیہ وسلم ایک ببول کے درخت کے نیچے اترے اور جب آپ کسی جہاد سے واپس ہوتے اور راستہ ذوالحلیفہ سے ہو کر گزرتا یا حج یا عمرہ سے واپسی ہوتی تو آپ وادی عتیق کے نشیبی علاقہ میں اترتے، پھر جب وادی کے نشیب سے اوپر چڑھتے تو وادی کے بالائی کنارے کے اس مشرقی حصہ پر پڑاؤ ہوتا جہاں کنکریوں اور ریت کا کشادہ نالا ہے۔ ( یعنی بطحاء میں ) یہاں آپ صلی اللہ علیہ وسلم رات کو صبح تک آرام فرماتے۔ یہ مقام اس مسجد کے قریب نہیں ہے جو پتھروں کی بنی ہے، آپ اس ٹیلے پر بھی نہیں ہوتے جس پر مسجد بنی ہوئی ہے۔ وہاں ایک گہرا نالہ تھا عبداللہ بن عمر رضی اللہ عنہما وہیں نماز پڑھتے۔ اس کے نشیب میں ریت کے ٹیلے تھے اور رسول اللہ صلی اللہ علیہ وسلم وہاں نماز پڑھا کرتے تھے۔ کنکریوں اور ریت کے کشادہ نالہ کی طرف سے سیلاب نے آ کر اس جگہ کے آثار و نشانات کو پاٹ دیا ہے، جہاں عبداللہ بن عمر رضی اللہ عنہما نماز پڑھا کرتے تھے۔' WHERE id = 476;
UPDATE hadiths SET urdu = 'ہم سے اسحاق بن منصور نے بیان کیا، کہا ہم سے عبداللہ بن نمیر نے کہا کہ ہم سے عبیداللہ بن عمر نے نافع کے واسطہ سے بیان کیا۔ انہوں نے عبداللہ بن عمر رضی اللہ عنہما سے کہ رسول اللہ صلی اللہ علیہ وسلم جب عید کے دن ( مدینہ سے ) باہر تشریف لے جاتے تو چھوٹے نیزہ ( برچھا ) کو گاڑنے کا حکم دیتے وہ جب آپ صلی اللہ علیہ وسلم کے آگے گاڑ دیا جاتا تو آپ صلی اللہ علیہ وسلم اس کی طرف رخ کر کے نماز پڑھتے اور لوگ آپ صلی اللہ علیہ وسلم کے پیچھے کھڑے ہوتے۔ یہی آپ صلی اللہ علیہ وسلم سفر میں بھی کیا کرتے تھے۔ ( مسلمانوں کے ) خلفاء نے اسی وجہ سے برچھا ساتھ رکھنے کی عادت بنا لی ہے۔' WHERE id = 486;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، کہا ہم سے جویریہ بن اسماء نے نافع سے، انہوں نے عبداللہ بن عمر رضی اللہ عنہما سے، انہوں نے کہا کہ نبی کریم صلی اللہ علیہ وسلم بیت اللہ کے اندر تشریف لے گئے اور اسامہ بن زید عثمان بن طلحہ اور بلال رضی اللہ عنہم بھی آپ کے ساتھ تھے۔ آپ صلی اللہ علیہ وسلم دیر تک اندر رہے۔ پھر باہر آئے۔ اور میں سب لوگوں سے پہلے آپ صلی اللہ علیہ وسلم کے پیچھے ہی وہاں آیا۔ میں نے بلال رضی اللہ عنہ سے پوچھا کہ نبی کریم صلی اللہ علیہ وسلم نے کہاں نماز پڑھی تھی۔ انہوں نے بتایا کہ آگے کے دو ستونوں کے بیچ میں آپ صلی اللہ علیہ وسلم نے نماز پڑھی تھی۔' WHERE id = 496;
UPDATE hadiths SET urdu = 'ہم سے عمر بن حفص بن غیاث نے بیان کیا کہا، کہ مجھ سے میرے باپ نے بیان کیا، کہا کہ ہم سے اعمش نے بیان کیا، کہا کہ ہم سے ابراہیم نے اسود کے واسطہ سے بیان کیا، انہوں نے عائشہ رضی اللہ عنہا سے (دوسری سند) اور اعمش نے کہا کہ مجھ سے مسلم بن صبیح نے مسروق کے واسطہ سے بیان کیا، انہوں نے عائشہ رضی اللہ عنہا سے کہ ان کے سامنے ان چیزوں کا ذکر ہوا۔ جو نماز کو توڑ دیتی ہیں یعنی کتا، گدھا اور عورت۔ اس پر عائشہ رضی اللہ عنہا نے فرمایا کہ تم لوگوں نے ہمیں گدھوں اور کتوں کے برابر کر دیا۔ حالانکہ خود نبی کریم صلی اللہ علیہ وسلم اس طرح نماز پڑھتے تھے کہ میں چارپائی پر آپ صلی اللہ علیہ وسلم کے اور قبلہ کے بیچ میں لیٹی رہتی تھی۔ مجھے کوئی ضرورت پیش آئی اور چونکہ یہ بات پسند نہ تھی کہ آپ صلی اللہ علیہ وسلم کے سامنے ( جب کہ آپ صلی اللہ علیہ وسلم نماز پڑھ رہے ہوں ) بیٹھوں اور اس طرح آپ صلی اللہ علیہ وسلم کو تکلیف ہو۔ اس لیے میں آپ صلی اللہ علیہ وسلم کے پاؤں کی طرف سے خاموشی کے ساتھ نکل جاتی تھی۔' WHERE id = 506;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ نے بیان کیا، کہا کہ ہم سے یزید بن زریع نے بیان کیا، سلیمان تیمی کے واسطہ سے، انہوں نے ابوعثمان نہدی سے، انہوں نے ابن مسعود رضی اللہ عنہ سے کہ ایک شخص نے کسی غیر عورت کا بوسہ لے لیا۔ اور پھر نبی کریم صلی اللہ علیہ وسلم کی خدمت میں آیا اور آپ کو اس حرکت کی خبر دے دی۔ اس پر اللہ تعالیٰ نے یہ آیت نازل فرمائی، کہ نماز دن کے دونوں حصوں میں قائم کرو اور کچھ رات گئے بھی، اور بلاشبہ نیکیاں برائیوں کو مٹا دیتی ہیں۔ اس شخص نے کہا کہ یا رسول اللہ! کیا یہ صرف میرے لیے ہے۔ تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ نہیں بلکہ میری تمام امت کے لیے یہی حکم ہے۔' WHERE id = 517;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان حکم بن نافع نے بیان کیا، کہا ہم سے شعیب نے زہری کی روایت سے بیان کیا، انہوں نے کہا کہ مجھے انس بن مالک رضی اللہ عنہ نے خبر دی کہ جب سورج ڈھلا تو نبی کریم صلی اللہ علیہ وسلم حجرہ سے باہر تشریف لائے اور ظہر کی نماز پڑھی۔ پھر منبر پر تشریف لائے۔ اور قیامت کا ذکر فرمایا۔ اور آپ صلی اللہ علیہ وسلم نے فرمایا کہ قیامت میں بڑے عظیم امور پیش آئیں گے۔ پھر آپ صلی اللہ علیہ وسلم نے فرمایا کہ اگر کسی کو کچھ پوچھنا ہو تو پوچھ لے۔ کیونکہ جب تک میں اس جگہ پر ہوں تم مجھ سے جو بھی پوچھو گے۔ میں اس کا جواب ضرور دوں گا۔ لوگ بہت زیادہ رونے لگے۔ آپ صلی اللہ علیہ وسلم برابر فرماتے جاتے تھے کہ جو کچھ پوچھنا ہو پوچھو۔ عبداللہ بن حذافہ سہمی کھڑے ہوئے اور دریافت کیا کہ نبی کریم صلی اللہ علیہ وسلم میرے باپ کون ہیں؟ آپ صلی اللہ علیہ وسلم نے فرمایا کہ تمہارے باپ حذافہ تھے۔ آپ صلی اللہ علیہ وسلم اب بھی برابر فرما رہے تھے کہ پوچھو کیا پوچھتے ہو۔ اتنے میں عمر رضی اللہ عنہ ادب سے گھٹنوں کے بل بیٹھ گئے اور انہوں نے فرمایا کہ ہم اللہ تعالیٰ کے مالک ہونے، اسلام کے دین ہونے اور محمد ( صلی اللہ علیہ وسلم ) کے نبی ہونے سے راضی اور خوش ہیں۔ ( پس اس گستاخی سے ہم باز آتے ہیں کہ آپ صلی اللہ علیہ وسلم سے جا اور بے جا سوالات کریں ) اس پر نبی کریم صلی اللہ علیہ وسلم خاموش ہو گئے۔ پھر آپ صلی اللہ علیہ وسلم نے فرمایا کہ ابھی ابھی میرے سامنے جنت اور جہنم اس دیوار کے کونے میں پیش کی گئی تھی۔ پس میں نے نہ ایسی کوئی عمدہ چیز دیکھی ( جیسی جنت تھی ) اور نہ کوئی ایسی بری چیز دیکھی ( جیسی دوزخ تھی ) ۔' WHERE id = 529;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان حکم بن نافع نے بیان کیا کہ کہا ہمیں شعیب بن ابی حمزہ نے زہری سے خبر دی، انہوں نے کہا کہ مجھ سے انس بن مالک رضی اللہ عنہ نے بیان کیا، انہوں نے فرمایا کہ رسول اللہ صلی اللہ علیہ وسلم جب عصر کی نماز پڑھتے تو سورج بلند اور تیز روشن ہوتا تھا۔ پھر ایک شخص مدینہ کے بالائی علاقہ کی طرف جاتا وہاں پہنچنے کے بعد بھی سورج بلند رہتا تھا ( زہری نے کہا کہ ) مدینہ کے بالائی علاقہ کے بعض مقامات تقریباً چار میل پر یا کچھ ایسے ہی واقع ہیں۔' WHERE id = 539;
UPDATE hadiths SET urdu = 'ہم سے محمد بن بشار نے بیان کیا، کہا ہم سے محمد بن جعفر نے، کہا ہم سے شعبہ بن حجاج نے سعد بن ابراہیم سے، انہوں نے محمد بن عمرو بن حسن بن علی سے، انہوں نے کہا کہ حجاج کا زمانہ آیا ( اور وہ نماز دیر کر کے پڑھایا کرتا تھا اس لیے ) ہم نے جابر بن عبداللہ رضی اللہ عنہما سے اس کے بارے میں پوچھا تو انہوں نے فرمایا کہ نبی کریم صلی اللہ علیہ وسلم ظہر کی نماز ٹھیک دوپہر میں پڑھایا کرتے تھے۔ ابھی سورج صاف اور روشن ہوتا تو نماز عصر پڑھاتے۔ نماز مغرب وقت آتے ہی پڑھاتے اور نماز عشاء کو کبھی جلدی پڑھاتے اور کبھی دیر سے۔ جب دیکھتے کہ لوگ جمع ہو گئے ہیں تو جلدی پڑھا دیتے اور اگر لوگ جلدی جمع نہ ہوتے تو نماز میں دیر کرتے۔ ( اور لوگوں کا انتظار کرتے ) اور صبح کی نماز صحابہ رضی اللہ عنہم یا ( یہ کہا کہ ) نبی کریم صلی اللہ علیہ وسلم اندھیرے میں پڑھتے تھے۔' WHERE id = 549;
UPDATE hadiths SET urdu = 'ہم سے عبدالرحیم محاربی نے بیان کیا، کہا ہم سے زائدہ نے حمید طویل سے، انہوں نے انس رضی اللہ عنہ سے کہ نبی کریم صلی اللہ علیہ وسلم نے ( ایک دن ) عشاء کی نماز آدھی رات گئے پڑھی۔ اور فرمایا کہ دوسرے لوگ نماز پڑھ کر سو گئے ہوں گے۔ ( یعنی دوسری مساجد میں پڑھنے والے مسلمان ) اور تم لوگ جب تک نماز کا انتظار کرتے رہے ( گویا سارے وقت ) نماز ہی پڑھتے رہے۔ ابن مریم نے اس میں یہ زیادہ کیا کہ ہمیں یحییٰ بن ایوب نے خبر دی۔ کہا مجھ سے حمید طویل نے بیان کیا، انہوں نے انس رضی اللہ عنہ سے یہ سنا، گویا اس رات آپ کی انگوٹھی کی چمک کا نقشہ اس وقت بھی میری نظروں کے سامنے چمک رہا ہے۔' WHERE id = 560;
UPDATE hadiths SET urdu = 'ہم سے عبید بن اسماعیل نے بیان کیا، انہوں نے ابی اسامہ کے واسطے سے بیان کیا۔ انہوں نے عبیداللہ بن عمر سے، انہوں نے خبیب بن عبدالرحمٰن سے، انہوں نے حفص بن عاصم سے، انہوں نے ابوہریرہ رضی اللہ عنہ سے کہ نبی کریم صلی اللہ علیہ وسلم نے دو طرح کی خرید و فروخت اور دو طرح کے لباس اور دو وقتوں کی نمازوں سے منع فرمایا۔ آپ صلی اللہ علیہ وسلم نے نماز فجر کے بعد سورج نکلنے تک اور نماز عصر کے بعد غروب ہونے تک نماز پڑھنے سے منع فرمایا ( اور کپڑوں میں ) اشتمال صماء یعنی ایک کپڑا اپنے اوپر اس طرح لپیٹ لینا کہ شرمگاہ کھل جائے۔ اور ( احتباء ) یعنی ایک کپڑے میں گوٹ مار کر بیٹھنے سے منع فرمایا۔ ( اور خرید و فروخت میں ) آپ صلی اللہ علیہ وسلم نے منابذہ اور ملامسہ سے منع فرمایا۔' WHERE id = 571;
UPDATE hadiths SET urdu = 'ہم سے معاذ بن فضالہ نے بیان کیا، انہوں نے کہا کہ ہم سے ہشام دستوائی نے یحییٰ بن ابی کثیر سے بیان کیا، وہ قلابہ سے نقل کرتے ہیں کہ ابوالملیح عامر بن اسامہ ہذلی نے ان سے بیان کیا، انہوں نے کہا کہ ہم ابر کے دن ایک مرتبہ بریدہ بن حصیب رضی اللہ عنہ صحابی کے ساتھ تھے، انہوں نے فرمایا کہ نماز سویرے پڑھا کرو۔ کیونکہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ جس نے عصر کی نماز چھوڑی اس کا عمل اکارت ہو گیا۔' WHERE id = 581;
UPDATE hadiths SET urdu = 'ہم سے محمود بن غیلان نے بیان کیا، کہا کہ ہم سے عبدالرزاق بن ہمام نے، کہا کہ ہمیں عبدالملک ابن جریج نے خبر دی، کہا کہ مجھے نافع نے خبر دی کہ عبداللہ بن عمر رضی اللہ عنہما کہتے تھے کہ جب مسلمان ( ہجرت کر کے ) مدینہ پہنچے تو وقت مقرر کر کے نماز کے لیے آتے تھے۔ اس کے لیے اذان نہیں دی جاتی تھی۔ ایک دن اس بارے میں مشورہ ہوا۔ کسی نے کہا نصاریٰ کی طرح ایک گھنٹہ لے لیا جائے اور کسی نے کہا کہ یہودیوں کی طرح نرسنگا ( بگل بنا لو، اس کو پھونک دیا کرو ) لیکن عمر رضی اللہ عنہ نے فرمایا کہ کسی شخص کو کیوں نہ بھیج دیا جائے جو نماز کے لیے پکار دیا کرے۔ اس پر نبی کریم صلی اللہ علیہ وسلم نے ( اسی رائے کو پسند فرمایا اور بلال سے ) فرمایا کہ بلال! اٹھ اور نماز کے لیے اذان دے۔' WHERE id = 591;
UPDATE hadiths SET urdu = 'ہم سے علی بن عیاش ہمدانی نے بیان کیا، انہوں نے کہا کہ ہم سے شعیب بن ابی حمزہ نے بیان کیا، انہوں نے محمد بن المنکدر سے بیان کیا، انہوں نے جابر بن عبداللہ رضی اللہ عنہما سے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ جو شخص اذان سن کر یہ کہے «اللهم رب هذه الدعوة التامة والصلاة القائمة آت محمدا الوسيلة والفضيلة وابعثه مقاما محمودا الذي وعدته» اسے قیامت کے دن میری شفاعت ملے گی۔' WHERE id = 601;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، انہوں نے کہا کہ ہمیں شعیب نے خبر دی، انہوں نے زہری سے، انہوں نے کہا کہ مجھے عروہ بن زبیر نے خبر دی کہ ام المؤمنین عائشہ رضی اللہ عنہا نے فرمایا کہ جب مؤذن صبح کی دوسری اذان دے کر چپ ہوتا تو رسول اللہ صلی اللہ علیہ وسلم کھڑے ہوتے اور فرض سے پہلے دو رکعت ( سنت فجر ) ہلکی پھلکی ادا کرتے صبح صادق روشن ہو جانے کے بعد پھر داہنی کروٹ پر لیٹ رہتے۔ یہاں تک کہ مؤذن تکبیر کہنے کی اطلاع دینے کے لیے آپ صلی اللہ علیہ وسلم کے پاس آتا۔' WHERE id = 612;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا، کہا کہ ہم سے محمد بن عبدالرحمٰن بن ابی ذئب نے بیان کیا، کہا کہ ہم سے امام زہری نے سعید بن مسیب سے بیان کیا، انہوں نے ابوہریرہ رضی اللہ عنہ سے، انہوں نے نبی کریم صلی اللہ علیہ وسلم سے (دوسری سند) اور زہری نے ابوسلمہ سے، انہوں نے ابوہریرہ رضی اللہ عنہ سے، انہوں نے نبی کریم صلی اللہ علیہ وسلم سے آپ صلی اللہ علیہ وسلم نے فرمایا تم لوگ تکبیر کی آواز سن لو تو نماز کے لیے ( معمولی چال سے ) چل پڑو۔ سکون اور وقار کو ( بہرحال ) پکڑے رکھو اور دوڑ کے مت آؤ۔ پھر نماز کا جو حصہ ملے اسے پڑھ لو، اور جو نہ مل سکے اسے بعد میں پورا کر لو۔' WHERE id = 622;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، انہوں نے کہا کہ مجھ سے لیث نے بیان کیا، انہوں نے کہا کہ مجھ سے یزید بن ہاد نے بیان کیا، انہوں نے عبداللہ بن خباب سے، انہوں نے ابو سعید خدری رضی اللہ عنہ سے کہ انہوں نے نبی کریم صلی اللہ علیہ وسلم سے سنا آپ صلی اللہ علیہ وسلم فرماتے تھے کہ جماعت سے نماز تنہا نماز پڑھنے سے پچیس درجہ زیادہ فضیلت رکھتی ہے۔' WHERE id = 632;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن مسلمہ قعنبی نے بیان کیا امام مالک سے، انہوں نے ابوالزناد سے، انہوں نے اعرج سے، انہوں نے ابوہریرہ رضی اللہ عنہ سے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ ملائکہ تم میں سے اس نمازی کے لیے اس وقت تک یوں دعا کرتے رہتے ہیں۔ جب تک ( نماز پڑھنے کے بعد ) وہ اپنے مصلے پر بیٹھا رہے «اللهم اغفر له،‏‏‏‏ ‏‏‏‏ اللهم ارحمه‏» کہ اے اللہ! اس کی مغفرت کر۔ اے اللہ! اس پر رحم کر۔ تم میں سے وہ شخص جو صرف نماز کی وجہ سے رکا ہوا ہے۔ گھر جانے سے سوا نماز کے اور کوئی چیز اس کے لیے مانع نہیں، تو اس کا ( یہ سارا وقت ) نماز ہی میں شمار ہو گا۔' WHERE id = 642;
UPDATE hadiths SET urdu = 'ہم سے مسلم بن ابراہیم نے بیان کیا، کہا کہ ہم سے ہشام دستوائی نے یحییٰ بن کثیر سے بیان کیا، انہوں نے ابوسلمہ بن عبدالرحمٰن سے، انہوں نے کہا کہ میں نے ابو سعید خدری رضی اللہ عنہ سے ( شب قدر کو ) پوچھا۔ آپ نے فرمایا کہ بادل کا ایک ٹکڑا آیا اور برسا یہاں تک کہ ( مسجد کی چھت ) ٹپکنے لگی جو کھجور کی شاخوں سے بنائی گئی تھی۔ پھر نماز کے لیے تکبیر ہوئی۔ میں نے دیکھا کہ نبی کریم صلی اللہ علیہ وسلم کیچڑ اور پانی میں سجدہ کر رہے تھے۔ کیچڑ کا نشان آپ کی پیشانی پر بھی میں نے دیکھا۔' WHERE id = 652;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف تنیسی نے بیان کیا، انہوں نے کہا کہ ہمیں امام مالک رحمہ اللہ نے ہشام بن عروہ سے خبر دی، انہوں نے اپنے باپ عروہ بن زبیر سے، انہوں نے عائشہ رضی اللہ عنہا سے، انہوں نے کہا کہ رسول اللہ صلی اللہ علیہ وسلم نے اپنی بیماری میں فرمایا کہ ابوبکر ( رضی اللہ عنہ ) سے نماز پڑھانے کے لیے کہو۔ عائشہ رضی اللہ عنہا بیان کرتی ہیں کہ میں نے عرض کیا کہ ابوبکر آپ کی جگہ کھڑے ہوں گے تو روتے روتے وہ ( قرآن مجید ) سنا نہ سکیں گے، اس لیے آپ عمر رضی اللہ عنہ سے کہئے کہ وہ نماز پڑھائیں۔ آپ فرماتی تھیں کہ میں نے حفصہ رضی اللہ عنہا سے کہا کہ وہ بھی کہیں کہ اگر ابوبکر آپ کی جگہ کھڑے ہوئے تو روتے روتے لوگوں کو ( قرآن ) نہ سنا سکیں گے۔ اس لیے عمر رضی اللہ عنہ سے کہئے کہ وہ نماز پڑھائیں۔ حفصہ رضی اللہ عنہا ( ام المؤمنین اور عمر رضی اللہ عنہ کی صاحبزادی ) نے بھی اسی طرح کہا تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ خاموش رہو۔ تم صواحب یوسف کی طرح ہو۔ ابوبکر سے کہو کہ وہ لوگوں کو نماز پڑھائیں۔ پس حفصہ رضی اللہ عنہ نے عائشہ رضی اللہ عنہا سے کہا۔ بھلا مجھ کو کہیں تم سے بھلائی پہنچ سکتی ہے؟' WHERE id = 662;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف تنیسی نے بیان کیا، کہا کہ ہمیں امام مالک رحمہ اللہ نے ابن شہاب سے خبر دی، انہوں نے انس بن مالک رضی اللہ عنہ سے کہ رسول اللہ صلی اللہ علیہ وسلم ایک گھوڑے پر سوار ہوئے تو آپ صلی اللہ علیہ وسلم اس پر سے گر پڑے۔ اس سے آپ صلی اللہ علیہ وسلم کے دائیں پہلو پر زخم آئے۔ تو آپ صلی اللہ علیہ وسلم نے کوئی نماز پڑھی۔ جسے آپ صلی اللہ علیہ وسلم بیٹھ کر پڑھ رہے تھے۔ اس لیے ہم نے بھی آپ صلی اللہ علیہ وسلم کے پیچھے بیٹھ کر نماز پڑھی۔ جب آپ صلی اللہ علیہ وسلم فارغ ہوئے تو فرمایا کہ امام اس لیے مقرر کیا گیا ہے کہ اس کی اقتداء کی جائے۔ اس لیے جب وہ کھڑے ہو کر نماز پڑھے تو تم بھی کھڑے ہو کر پڑھو اور جب وہ رکوع کرے تو تم بھی رکوع کرو۔ جب وہ رکوع سے سر اٹھائے تو تم بھی اٹھاؤ اور جب وہ «سمع الله لمن حمده‏» کہے تو تم «ربنا ولك الحمد‏» کہو اور جب وہ بیٹھ کر نماز پڑھے تو تم بھی بیٹھ کر پڑھو۔ ابوعبداللہ ( امام بخاری رحمہ اللہ ) نے کہا کہ حمیدی نے آپ صلی اللہ علیہ وسلم کے اس قول ”جب امام بیٹھ کر نماز پڑھے تو تم بھی بیٹھ کر پڑھو۔“ کے متعلق کہا ہے کہ یہ ابتداء میں آپ صلی اللہ علیہ وسلم کی پرانی بیماری کا واقعہ ہے۔ اس کے بعد آخری بیماری میں آپ صلی اللہ علیہ وسلم نے خود بیٹھ کر نماز پڑھی تھی اور لوگ آپ صلی اللہ علیہ وسلم کے پیچھے کھڑے ہو کر اقتداء کر رہے تھے۔ آپ صلی اللہ علیہ وسلم نے اس وقت لوگوں کو بیٹھنے کی ہدایت نہیں فرمائی اور اصل یہ ہے کہ جو فعل آپ صلی اللہ علیہ وسلم کا آخری ہو اس کو لینا چاہئے اور پھر جو اس سے آخری ہو۔' WHERE id = 672;
UPDATE hadiths SET urdu = 'ہم سے مسدد بن مسرہد نے بیان کیا، کہا کہ ہم سے اسماعیل بن ابراہیم نے ایوب سختیانی سے بیان کیا، انہوں نے عبداللہ بن سعید بن جبیر سے، انہوں نے اپنے باپ سے، انہوں نے ابن عباس رضی اللہ عنہما سے کہ آپ نے بتلایا کہ میں نے ایک دفعہ اپنی خالہ میمونہ رضی اللہ عنہا کے گھر رات گذاری۔ نبی کریم صلی اللہ علیہ وسلم رات میں نماز پڑھنے کے لیے کھڑے ہوئے تو میں بھی آپ صلی اللہ علیہ وسلم کے ساتھ نماز میں شریک ہو گیا۔ میں ( غلطی سے ) آپ صلی اللہ علیہ وسلم کے بائیں طرف کھڑا ہو گیا تھا۔ پھر آپ صلی اللہ علیہ وسلم نے میرا سر پکڑ کے دائیں طرف کر دیا۔ ( تاکہ صحیح طور پر کھڑا ہو جاؤں ) ۔' WHERE id = 683;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ مدینی نے بیان کیا، کہا کہ ہم سے یزید بن زریع نے بیان کیا، کہا کہ ہم سے سعید بن ابی عروبہ نے بیان کیا۔ کہا کہ ہم سے قتادہ نے بیان کیا کہ انس بن مالک رضی اللہ عنہ نے ان سے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا میں نماز شروع کر دیتا ہوں۔ ارادہ یہ ہوتا ہے کہ نماز طویل کروں، لیکن بچے کے رونے کی آواز سن کر مختصر کر دیتا ہوں کیونکہ مجھے معلوم ہے کہ ماں کے دل پر بچے کے رونے سے کیسی چوٹ پڑتی ہے۔' WHERE id = 693;
UPDATE hadiths SET urdu = 'ہم سے احمد بن ابی رجاء نے بیان کیا، انہوں نے کہا کہ ہم سے معاویہ بن عمرو نے بیان کیا، انہوں نے کہا کہ ہم سے زائدہ بن قدامہ نے بیان کیا، کہا کہ ہم سے حمید طویل نے بیان کیا، کہا کہ ہم سے انس بن مالک رضی اللہ عنہ نے بیان کیا، انہوں نے کہا کہ نماز کے لیے تکبیر کہی گئی تو رسول اللہ صلی اللہ علیہ وسلم نے اپنا منہ ہماری طرف کیا اور فرمایا کہ اپنی صفیں برابر کر لو اور مل کر کھڑے ہو جاؤ۔ میں تم کو اپنی پیٹھ کے پیچھے سے بھی دیکھتا رہتا ہوں۔' WHERE id = 703;
UPDATE hadiths SET urdu = 'ہم سے عبدالاعلیٰ بن حماد نے بیان کیا، کہا کہ ہم سے وہیب بن خالد نے بیان کیا، کہا ہم سے موسیٰ بن عقبہ نے بیان کیا، ابوالنضر سالم سے، انہوں نے بسر بن سعید سے، انہوں نے زید بن ثابت رضی اللہ عنہ سے کہ رسول اللہ صلی اللہ علیہ وسلم نے رمضان میں ایک حجرہ بنا لیا یا اوٹ ( پردہ ) بسر بن سعید نے کہا میں سمجھتا ہوں وہ بورئیے کا تھا۔ آپ نے کئی رات اس میں نماز پڑھی۔ صحابہ میں سے بعض حضرات نے ان راتوں میں آپ کی اقتداء کی۔ جب آپ کو اس کا علم ہوا تو آپ نے بیٹھ رہنا شروع کیا ( نماز موقوف رکھی ) پھر برآمد ہوئے اور فرمایا تم نے جو کیا وہ مجھ کو معلوم ہے، لیکن لوگو! تم اپنے گھروں میں نماز پڑھتے رہو کیونکہ بہتر نماز آدمی کی وہی ہے جو اس کے گھر میں ہو۔ مگر فرض نماز ( مسجد میں پڑھنی ضروری ہے ) اور عفان بن مسلم نے کہا کہ ہم سے وہیب نے بیان کیا، کہا کہ ہم سے موسیٰ بن عقبہ نے بیان کیا، کہا کہ میں نے ابوالنضر ابن ابی امیہ سے سنا، وہ بسر بن سعید سے روایت کرتے تھے، وہ زید بن ثابت سے، وہ نبی کریم صلی اللہ علیہ وسلم سے۔' WHERE id = 714;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل بن ابی اویس نے بیان کیا، کہا کہ مجھ سے امام مالک رحمہ اللہ نے ابوالزناد سے بیان کیا، انہوں نے اعرج سے، انہوں نے ابوہریرہ رضی اللہ عنہ سے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ، کیا تم سمجھتے ہو کہ میرا منہ ادھر ( قبلہ کی طرف ) ہے۔ اللہ کی قسم تمہارا رکوع اور تمہارا خشوع مجھ سے کچھ چھپا ہوا نہیں ہے، میں تمہیں اپنے پیچھے سے بھی دیکھتا رہتا ہوں۔' WHERE id = 724;
UPDATE hadiths SET urdu = 'ہم سے مسدد بن مسرہد نے بیان کیا، کہا کہ ہم سے ابوالاحوص سلام بن سلیم نے بیان کیا، کہا کہ ہم سے اشعث بن سلیم نے بیان کیا اپنے والد کے واسطے سے، انہوں نے مسروق بن اجدع سے، انہوں نے عائشہ رضی اللہ عنہا سے آپ نے بتلایا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم سے نماز میں ادھر ادھر دیکھنے کے بارے میں پوچھا۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ یہ تو ڈاکہ ہے جو شیطان بندے کی نماز پر ڈالتا ہے۔' WHERE id = 734;
UPDATE hadiths SET urdu = 'ہم سے محمد بن یوسف بیکندی نے بیان کیا، کہا کہ ہم سے سفیان بن عیینہ نے اعمش سے، انہوں نے عمارہ بن عمیر سے، انہوں نے ابومعمر سے کہ میں نے خباب بن الارت سے پوچھا کہ کیا نبی کریم صلی اللہ علیہ وسلم ظہر اور عصر کی نمازوں میں قرآت کیا کرتے تھے؟ تو انہوں نے کہا کہ ہاں! میں نے کہا کہ نبی کریم صلی اللہ علیہ وسلم کی قرآت کرنے کو آپ لوگ کس طرح معلوم کر لیتے تھے؟ فرمایا کہ آپ صلی اللہ علیہ وسلم کی داڑھی مبارک کے ہلنے سے۔' WHERE id = 744;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا، انہوں نے کہا کہ ہم سے شعبہ نے بیان کیا، کہا کہ ہم سے سیار ابن سلامہ نے بیان کیا، انہوں نے بیان کیا کہ میں اپنے باپ کے ساتھ ابوبرزہ اسلمی صحابی رضی اللہ عنہ کے پاس گیا۔ ہم نے آپ سے نماز کے وقتوں کے متعلق پوچھا تو انہوں نے کہا کہ نبی کریم صلی اللہ علیہ وسلم ظہر کی نماز سورج ڈھلنے پر پڑھتے تھے۔ عصر جب پڑھتے تو مدینہ کے انتہائی کنارہ تک ایک شخص چلا جاتا۔ لیکن سورج اب بھی باقی رہتا۔ مغرب کے متعلق جو کچھ آپ نے کہا وہ مجھے یاد نہیں رہا اور عشاء کے لیے تہائی رات تک دیر کرنے میں کوئی حرج محسوس نہیں کرتے تھے اور آپ اس سے پہلے سونے کو اور اس کے بعد بات چیت کرنے کو ناپسند کرتے تھے۔ جب نماز صبح سے فارغ ہوتے تو ہر شخص اپنے قریب بیٹھے ہوئے کو پہچان سکتا تھا۔ آپ دونوں رکعات میں یا ایک میں ساٹھ سے لے کر سو تک آیتیں پڑھتے۔' WHERE id = 754;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف تینسی نے بیان کیا، انہوں نے کہا کہ ہمیں امام مالک نے ابوالزناد سے خبر دی، انہوں نے اعرج سے، انہوں نے ابوہریرہ رضی اللہ عنہ سے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ جب کوئی تم میں سے «آمين» کہے اور فرشتوں نے بھی اسی وقت آسمان پر «آمين» کہی۔ اس طرح ایک کی «آمين» دوسرے کے «آمين» کے ساتھ مل گئی تو اس کے پچھلے تمام گناہ معاف ہو جاتے ہیں۔' WHERE id = 765;
UPDATE hadiths SET urdu = 'ہم سے حفص بن عمر نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، سلیمان بن اعمش کے واسطہ سے کہا میں نے زید بن وہب سے سنا، انہوں نے بیان کیا کہ حذیفہ بن یمان رضی اللہ عنہ نے ایک شخص کو دیکھا کہ نہ رکوع پوری طرح کرتا ہے نہ سجدہ۔ اس لیے آپ نے اس سے کہا کہ تم نے نماز ہی نہیں پڑھی اور اگر تم مر گئے تو تمہاری موت اس سنت پر نہیں ہو گی جس پر اللہ تعالیٰ نے محمد صلی اللہ علیہ وسلم کو پیدا کیا تھا۔' WHERE id = 775;
UPDATE hadiths SET urdu = 'ہم سے ابوالولید ہشام بن عبدالملک نے بیان کیا، کہا کہ ہم سے شعبہ نے حکم سے بیان کیا، انہوں نے ابن ابی لیلیٰ سے، انہوں نے براء بن عازب رضی اللہ عنہ سے، انہوں نے کہا کہ نبی کریم صلی اللہ علیہ وسلم کے رکوع، سجدہ، رکوع سے سر اٹھاتے وقت اور دونوں سجدوں کے درمیان کا بیٹھنا تقریباً برابر ہوتا تھا۔' WHERE id = 785;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا، کہا کہ ہم سے اسرائیل نے ابواسحاق سے بیان کیا، انہوں نے عبداللہ بن یزید سے، انہوں نے کہا کہ ہم سے براء بن عازب رضی اللہ عنہ نے بیان کیا، وہ جھوٹ نہیں بول سکتے تھے۔ آپ نے فرمایا کہ ہم نبی کریم صلی اللہ علیہ وسلم کی اقتداء میں نماز پڑھتے تھے۔ جب آپ «سمع الله لمن حمده‏» کہتے ( یعنی رکوع سے سر اٹھاتے ) تو ہم میں سے کوئی اس وقت تک اپنی پیٹھ نہ جھکاتا جب تک آپ صلی اللہ علیہ وسلم اپنی پیشانی زمین پر نہ رکھ دیتے۔' WHERE id = 795;
UPDATE hadiths SET urdu = 'ہم سے محمد بن صباح نے بیان کیا، انہوں نے کہا کہ ہمیں ہشیم نے خبر دی، انہوں نے کہا ہمیں خالد حذاء نے خبر دی، ابوقلابہ سے، انہوں نے بیان کیا کہ مجھے مالک بن حویرث لیثی رضی اللہ عنہ نے خبر دی کہ آپ نے نبی کریم صلی اللہ علیہ وسلم کو نماز پڑھتے دیکھا۔ آپ صلی اللہ علیہ وسلم جب طاق رکعت میں ہوتے تو اس وقت تک نہ اٹھتے جب تک تھوڑی دیر بیٹھ نہ لیتے۔' WHERE id = 806;
UPDATE hadiths SET urdu = 'ہم سے مسدد بن مسرہد نے بیان کیا، کہا کہ ہم سے یحییٰ بن سعید قطان نے اعمش سے بیان کیا، انہوں نے کہا کہ مجھ سے شقیق نے عبداللہ بن مسعود رضی اللہ عنہ سے بیان کیا، انہوں نے فرمایا کہ ( پہلے ) جب ہم نبی کریم صلی اللہ علیہ وسلم کے ساتھ نماز پڑھتے تو ہم ( قعدہ میں ) یہ کہا کرتے تھے کہ اس کے بندوں کی طرف سے اللہ پر سلام ہو اور فلاں پر اور فلاں پر سلام ہو۔ اس پر نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ یہ نہ کہو کہ ”اللہ پر سلام ہو“ کیونکہ اللہ تو خود سلام ہے۔ بلکہ یہ کہو «التحيات لله،‏‏‏‏ والصلوات والطيبات،‏‏‏‏ السلام عليك أيها النبي ورحمة الله وبركاته،‏‏‏‏ السلام علينا وعلى عباد الله الصالحين‏» آداب بندگان اور تمام عبادات اور تمام پاکیزہ خیراتیں اللہ ہی کے لیے ہیں آپ پر اے نبی سلام ہو اور اللہ کی رحمتیں اور برکتیں نازل ہوں ہم پر اور اللہ کے صالح بندوں پر سلام ہو اور جب تم یہ کہو گے تو آسمان پر اللہ کے تمام بندوں کو پہنچے گا آپ صلی اللہ علیہ وسلم نے فرمایا کہ آسمان اور زمین کے درمیان تمام بندوں کو پہنچے گا «أشهد أن لا إله إلا الله،‏‏‏‏ وأشهد أن محمدا عبده ورسوله» میں گواہی دیتا ہوں کہ اللہ کے سوا کوئی معبود نہیں اور میں گواہی دیتا ہوں کہ محمد اس کے بندے اور رسول ہیں۔ اس کے بعد دعا کا اختیار ہے جو اسے پسند ہو کرے۔' WHERE id = 817;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن مسلمہ قعنبی نے بیان کیا، انہوں نے امام مالک سے بیان کیا، انہوں نے صالح بن کیسان سے بیان کیا، ان سے عبیداللہ بن عبداللہ بن عتبہ بن مسعود نے بیان کیا، ان سے زید بن خالد جہنی رضی اللہ عنہ نے بیان کیا، انہوں نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے ہمیں حدیبیہ میں صبح کی نماز پڑھائی اور رات کو بارش ہو چکی تھی نماز سے فارغ ہونے کے بعد آپ صلی اللہ علیہ وسلم نے لوگوں کی طرف منہ کیا اور فرمایا معلوم ہے تمہارے رب نے کیا فرمایا ہے۔ لوگوں نے کہا کہ اللہ اور اس کے رسول خوب جانتے ہیں ( آپ صلی اللہ علیہ وسلم نے فرمایا کہ ) تمہارے رب کا ارشاد ہے کہ صبح ہوئی تو میرے کچھ بندے مجھ پر ایمان لائے۔ اور کچھ میرے منکر ہوئے جس نے کہا کہ اللہ کے فضل اور اس کی رحمت سے ہمارے لیے بارش ہوئی تو وہ میرا مومن ہے اور ستاروں کا منکر اور جس نے کہا کہ فلاں تارے کے فلانی جگہ پر آنے سے بارش ہوئی وہ میرا منکر ہے اور ستاروں کا مومن۔' WHERE id = 827;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ مدینی نے بیان کیا، انہوں نے کہا کہ ہم سے سفیان نے بیان کیا، انہوں نے کہا کہ مجھ سے صفوان بن سلیم نے عطاء سے بیان کیا، ان سے ابو سعید خدری رضی اللہ عنہ نے بیان کیا ان سے نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ جمعہ کے دن ہر بالغ کے لیے غسل ضروری ہے۔' WHERE id = 838;
UPDATE hadiths SET urdu = 'ہم سے محمد بن مسکین نے بیان کیا، کہا کہ ہم سے بشر بن بکر نے بیان کیا، کہا کہ ہمیں امام اوزاعی نے خبر دی، کہا کہ مجھ سے یحییٰ بن ابی کثیر نے بیان کیا، ان سے عبداللہ بن ابی قتادہ انصاری نے، ان سے ان کے والد ابوقتادہ انصاری رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ میں نماز کے لیے کھڑا ہوتا ہوں، میرا ارادہ یہ ہوتا ہے کہ نماز لمبی کروں لیکن کسی بچے کے رونے کی آواز سن کر نماز کو مختصر کر دیتا ہوں کہ مجھے اس کی ماں کو تکلیف دینا برا معلوم ہوتا ہے۔' WHERE id = 848;
UPDATE hadiths SET urdu = 'ہم سے علی بن مدینی نے بیان کیا، انہوں نے کہا کہ ہمیں حرمی بن عمارہ نے خبر دی انہوں نے کہا کہ ہم سے شعبہ بن حجاج نے ابوبکر بن منکدر سے بیان کیا، انہوں نے کہا کہ مجھ سے عمرو بن سلیم انصاری نے بیان کیا، انہوں نے کہا کہ میں گواہ ہوں کہ ابو سعید خدری رضی اللہ عنہ نے فرمایا تھا کہ میں گواہ ہوں کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ جمعہ کے دن ہر جوان پر غسل، مسواک اور خوشبو لگانا اگر میسر ہو، ضروری ہے۔ عمرو بن سلیم نے کہا کہ غسل کے متعلق تو میں گواہی دیتا ہوں کہ وہ واجب ہے لیکن مسواک اور خوشبو کا علم اللہ تعالیٰ کو زیادہ ہے کہ وہ بھی واجب ہیں یا نہیں۔ لیکن حدیث میں اسی طرح ہے۔ ابوعبداللہ ( امام بخاری رحمہ اللہ ) نے فرمایا کہ ابوبکر بن منکدر محمد بن منکدر کے بھائی تھے اور ان کا نام معلوم نہیں ( ابوبکر ان کی کنیت تھی ) بکیر بن اشج۔ سعید بن ابی ہلال اور بہت سے لوگ ان سے روایت کرتے ہیں۔ اور محمد بن منکدر ان کے بھائی کی کنیت ابوبکر اور ابوعبداللہ بھی تھی۔' WHERE id = 860;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل بن ابی اویس نے بیان کیا، انہوں نے کہا کہ ہم سے سلیمان بن ہلال نے بیان کیا کہ ہشام بن عروہ نے کہا کہ مجھے میرے باپ عروہ بن زبیر نے ام المؤمنین عائشہ صدیقہ رضی اللہ عنہا سے خبر دی، انہوں نے کہا کہ عبدالرحمٰن بن ابی بکر ( ایک مرتبہ ) آئے۔ ان کے ہاتھ میں مسواک تھی جسے وہ استعمال کیا کرتے تھے۔ رسول اللہ صلی اللہ علیہ وسلم نے بیماری کی حالت میں ان سے کہا عبدالرحمٰن یہ مسواک مجھے دیدے۔ انہوں نے دے دی۔ میں نے اس کے سرے کو پہلے توڑا یعنی اتنی لکڑی نکال دی جو عبدالرحمٰن اپنے منہ سے لگایا کرتے تھے، پھر اسے چبا کر رسول اللہ صلی اللہ علیہ وسلم کو دے دیا۔ نبی کریم صلی اللہ علیہ وسلم نے اس سے دانت صاف کئے اور آپ صلی اللہ علیہ وسلم اس وقت میرے سینے پر ٹیک لگائے ہوئے تھے۔' WHERE id = 870;
UPDATE hadiths SET urdu = 'ہم سے مسدد بن مسرہد نے بیان کیا۔ انہوں نے کہا کہ ہم سے اسماعیل بن علیہ بیان کیا، انہوں نے کہا کہ ہمیں صاحب الزیادی عبدالحمید نے خبر دی، کہا کہ ہم سے محمد بن سیرین کے چچازاد بھائی عبداللہ بن حارث نے بیان کیا کہ عبداللہ بن عباس رضی اللہ عنہما نے اپنے مؤذن سے ایک دفعہ بارش کے دن کہا کہ «أشهد أن محمدا رسول الله‏» کے بعد «حى على الصلاة‏» ( نماز کی طرف آؤ ) نہ کہنا بلکہ یہ کہنا کہ «صلوا في بيوتكم‏» ( اپنے گھروں میں نماز پڑھ لو ) لوگوں نے اس بات پر تعجب کیا تو آپ نے فرمایا کہ اسی طرح مجھ سے بہتر انسان ( رسول اللہ صلی اللہ علیہ وسلم ) نے کیا تھا۔ بیشک جمعہ فرض ہے اور میں مکروہ جانتا ہوں کہ تمہیں گھروں سے باہر نکال کر مٹی اور کیچڑ پھسلوان میں چلاؤں۔' WHERE id = 880;
UPDATE hadiths SET urdu = 'ہم سے محمد بن سلام بیکندی رحمہ اللہ نے بیان کیا، کہا کہ ہمیں مخلد بن یزید نے خبر دی، کہا کہ ہمیں ابن جریج نے خبر دی، کہا کہ میں نے نافع سے سنا، انہوں نے کہا میں نے عبداللہ بن عمر سے سنا، انہوں نے کہا کہ نبی کریم صلی اللہ علیہ وسلم نے اس سے منع فرمایا ہے کہ کوئی شخص اپنے مسلمان بھائی کو اٹھا کر اس کی جگہ خود بیٹھ جائے۔ میں نے نافع سے پوچھا کہ کیا یہ جمعہ کے لیے ہے تو انہوں نے جواب دیا کہ جمعہ اور غیر جمعہ سب کے لیے یہی حکم ہے۔' WHERE id = 890;
UPDATE hadiths SET urdu = 'ہم سے معاذ بن فضالہ نے بیان کیا، کہا کہ ہم سے ہشام دستوائی نے یحیی بن ابی کثیر سے بیان کیا، ان سے ہلال بن ابی میمونہ نے، انہوں نے کہا ہم سے عطاء بن یسار نے بیان کیا، انہوں نے ابو سعید خدری رضی اللہ عنہ سے سنا کہ نبی کریم صلی اللہ علیہ وسلم ایک دن منبر پر تشریف فرما ہوئے اور ہم سب آپ صلی اللہ علیہ وسلم کے ارد گرد بیٹھ گئے۔' WHERE id = 900;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ نے بیان کیا، کہا کہ ہم سے سفیان بن عیینہ نے عمرو سے بیان کیا، انہوں نے جابر رضی اللہ عنہ سے سنا کہ ایک شخص جمعہ کے دن مسجد میں آیا۔ نبی کریم صلی اللہ علیہ وسلم خطبہ پڑھ رہے تھے۔ آپ صلی اللہ علیہ وسلم نے اس سے پوچھا کہ کیا تم نے ( تحیۃ المسجد کی ) نماز پڑھ لی ہے؟ آنے والے نے جواب دیا کہ نہیں۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ اٹھو اور دو رکعت نماز ( تحیۃ المسجد ) پڑھ لو۔' WHERE id = 910;
UPDATE hadiths SET urdu = 'ہم سے سعید بن ابی مریم نے بیان کیا، کہا کہ ہم سے ابوغسان نے بیان کیا، کہا کہ مجھ سے ابوحازم نے سہل بن سعد رضی اللہ عنہ سے بیان کیا، انہوں نے بتلایا کہ ہم نبی کریم صلی اللہ علیہ وسلم کے ساتھ جمعہ پڑھتے، پھر دوپہر کی نیند لیا کرتے تھے۔' WHERE id = 920;
UPDATE hadiths SET urdu = 'ہم سے محمد بن عبدالرحیم نے بیان کیا کہ ہم کو سعید بن سلیمان نے خبر دی کہ ہمیں ہشیم بن بشیر نے خبر دی، کہا کہ ہمیں عبداللہ بن ابی بکر بن انس نے خبر دی اور انہیں انس بن مالک رضی اللہ عنہ نے، آپ نے بتلایا کہ رسول اللہ صلی اللہ علیہ وسلم عیدالفطر کے دن نہ نکلتے جب تک کہ آپ صلی اللہ علیہ وسلم چند کھجوریں نہ کھا لیتے اور مرجی بن رجاء نے کہا کہ مجھ سے عبیداللہ بن ابی بکر نے بیان کیا، کہا کہ مجھ سے انس رضی اللہ عنہ نے نبی کریم صلی اللہ علیہ وسلم سے، پھر یہی حدیث بیان کی کہ آپ طاق عدد کھجوریں کھاتے تھے۔' WHERE id = 931;
UPDATE hadiths SET urdu = 'ہم سے احمد بن یعقوب نے بیان کیا، کہا کہ ہم سے اسحاق بن سعید بن عمرو بن سعید بن عاص نے اپنے باپ سے بیان کیا، انہوں نے کہا کہ حجاج عبداللہ بن عمر رضی اللہ عنہما کے پاس آیا میں بھی آپ کی خدمت میں موجود تھا۔ حجاج نے مزاج پوچھا عبداللہ بن عمر رضی اللہ عنہما نے فرمایا کہ اچھا ہوں۔ اس نے پوچھا کہ آپ کو یہ برچھا کس نے مارا؟ ابن عمر رضی اللہ عنہما نے فرمایا کہ مجھے اس شخص نے مارا جس نے اس دن ہتھیار ساتھ لے جانے کی اجازت دی جس دن ہتھیار ساتھ نہیں لے جایا جاتا تھا۔ آپ کی مراد حجاج ہی سے تھی۔' WHERE id = 942;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا کہ ہم سے یحییٰ بن سعید قطان نے سفیان ثوری سے بیان کیا، کہا کہ مجھ سے عبدالرحمٰن بن عابس نے بیان کیا، کہا کہ میں نے ابن عباس رضی اللہ عنہما سے سنا، ان سے دریافت کیا گیا تھا کہ کیا آپ نبی کریم صلی اللہ علیہ وسلم کے ساتھ عیدگاہ گئے تھے؟ انہوں نے فرمایا کہ ہاں اور اگر باوجود کم عمری کے میری قدر و منزلت آپ کے یہاں نہ ہوتی تو میں جا نہیں سکتا تھا۔ آپ اس نشان پر آئے جو کثیر بن صلت کے گھر کے قریب ہے۔ آپ نے وہاں نماز پڑھائی پھر خطبہ دیا۔ اس کے بعد عورتوں کی طرف آئے۔ آپ کے ساتھ بلال رضی اللہ عنہ بھی تھے۔ آپ نے انہیں وعظ اور نصیحت کی اور صدقہ کے لیے کہا۔ چنانچہ میں نے دیکھا کہ عورتیں اپنے ہاتھوں سے بلال رضی اللہ عنہ کے کپڑے میں ڈالے جا رہی تھیں۔ پھر نبی کریم صلی اللہ علیہ وسلم اور بلال رضی اللہ عنہ گھر واپس ہوئے۔' WHERE id = 952;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، کہا کہ ان سے لیث بن سعد نے بیان کیا، ان سے عقیل نے، ان سے ابن شہاب نے، ان سے عروہ نے، ان سے عائشہ رضی اللہ عنہا نے کہا ابوبکر رضی اللہ عنہ ان کے یہاں ( منٰی کے دنوں میں ) تشریف لائے اس وقت گھر میں دو لڑکیاں دف بجا رہی تھیں اور بعاث کی لڑائی کی نظمیں گا رہی تھیں۔ نبی کریم صلی اللہ علیہ وسلم چہرہ مبارک پر کپڑا ڈالے ہوئے تشریف فرما تھے۔ ابوبکر رضی اللہ عنہ نے ان دونوں کو ڈانٹا۔ اس پر آپ صلی اللہ علیہ وسلم نے چہرہ مبارک سے کپڑا ہٹا کر فرمایا کہ ابوبکر جانے بھی دو یہ عید کے دن ہیں ( اور وہ بھی منٰی میں ) ۔' WHERE id = 962;
UPDATE hadiths SET urdu = 'ہم سے مسدد بن مسرہد نے بیان کیا، کہا کہ ہم سے یحییٰ بن سعید نے بیان کیا، ان سے عبیداللہ عمری نے ان سے نافع نے عبداللہ بن عمر رضی اللہ عنہما سے بیان کیا اور ان سے نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ وتر رات کی تمام نمازوں کے بعد پڑھا کرو۔' WHERE id = 972;
UPDATE hadiths SET urdu = 'ہم سے حسن بن محمد بن صباح نے بیان کیا، کہا کہ ہم سے محمد بن عبداللہ بن مثنی انصاری نے بیان کیا، کہا کہ مجھ سے میرے باپ عبداللہ بن مثنی نے بیان کیا، ان سے ثمامہ بن عبداللہ بن انس رضی اللہ عنہ نے، ان سے انس بن مالک رضی اللہ عنہ نے کہ جب کبھی عمر رضی اللہ عنہ کے زمانہ میں قحط پڑتا تو عمر رضی اللہ عنہ عباس بن عبدالمطلب رضی اللہ عنہ کے وسیلہ سے دعا کرتے اور فرماتے کہ اے اللہ! پہلے ہم تیرے پاس اپنے نبی کریم صلی اللہ علیہ وسلم کا وسیلہ لایا کرتے تھے۔ تو، تو پانی برساتا تھا۔ اب ہم اپنے نبی کریم صلی اللہ علیہ وسلم کے چچا کو وسیلہ بناتے ہیں تو، تو ہم پر پانی برسا۔ انس رضی اللہ عنہ نے کہا کہ چنانچہ بارش خوب ہی برسی۔' WHERE id = 983;
UPDATE hadiths SET urdu = 'ہم سے محمد بن کثیر نے بیان کیا، ان سے سفیان ثوری نے، انہوں نے بیان کیا کہ ہم سے منصور اور اعمش نے بیان کیا، ان سے ابوالضحی نے، ان سے مسروق نے، آپ نے کہا کہ میں ابن مسعود رضی اللہ عنہ کی خدمت میں حاضر تھا۔ آپ نے فرمایا کہ قریش کا اسلام سے اعراض بڑھتا گیا تو نبی کریم صلی اللہ علیہ وسلم نے ان کے حق میں بددعا کی۔ اس بددعا کے نتیجے میں ایسا قحط پڑا کہ کفار مرنے لگے اور مردار اور ہڈیاں کھانے لگے۔ آخر ابوسفیان آپ کی خدمت میں حاضر ہوا اور عرض کیا اے محمد! ( صلی اللہ علیہ وسلم ) آپ صلہ رحمی کا حکم دیتے ہیں لیکن آپ کی قوم مر رہی ہے۔ اللہ عزوجل سے دعا کیجئے۔ آپ نے اس آیت کی تلاوت کی ( ترجمہ ) اس دن کا انتظار کر جب آسمان پر صاف کھلا ہوا دھواں نمودار ہو گا الآیہ ( خیر آپ نے دعا کی بارش ہوئی قحط جاتا رہا ) لیکن وہ پھر کفر کرنے لگے اس پر اللہ پاک کا یہ فرمان نازل ہوا ( ترجمہ ) جس دن ہم انہیں سختی کے ساتھ پکڑ کریں گے اور یہ پکڑ بدر کی لڑائی میں ہوئی اور اسباط بن محمد نے منصور سے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے دعائے استسقاء کی ( مدینہ میں ) جس کے نتیجہ میں خوب بارش ہوئی کہ سات دن تک وہ برابر جاری رہی۔ آخر لوگوں نے بارش کی زیادتی کی شکایت کی تو رسول اللہ صلی اللہ علیہ وسلم نے دعا کی «اللهم حوالينا ولا علينا» کہ اے اللہ! ہمارے اطراف و جوانب میں بارش برسا، مدینہ میں بارش کا سلسلہ ختم کر۔ چنانچہ بادل آسمان سے چھٹ گیا اور مدینہ کے اردگرد خوب بارش ہوئی۔' WHERE id = 993;
UPDATE hadiths SET urdu = 'عبدالعزیز اویسی نے کہا کہ مجھ سے محمد بن جعفر نے بیان کیا ان سے یحییٰ بن سعید اور شریک نے، انہوں نے کہا کہ ہم نے انس رضی اللہ عنہ سے سنا کہ نبی کریم صلی اللہ علیہ وسلم ( نے استسقاء میں دعا کرنے کے لیے ) اس طرح ہاتھ اٹھائے کہ میں نے آپ صلی اللہ علیہ وسلم کی بغلوں کی سفیدی دیکھ لی۔' WHERE id = 1003;
UPDATE hadiths SET urdu = 'ہم سے عمرو بن عون نے بیان کیا، انہوں نے کہا کہ ہم سے خالد بن عبداللہ نے یونس سے بیان کیا، ان سے امام حسن بصری نے بیان کیا، ان سے ابوبکرہ نفیع بن حارث رضی اللہ عنہ نے کہ ہم سے عمرو بن عون نے بیان کیا، انہوں نے کہا کہ ہم سے خالد بن عبداللہ نے یونس سے بیان کیا، ان سے امام حسن بصری نے بیان کیا، ان سے ابوبکرہ نفیع بن حارث رضی اللہ عنہ نے کہ' WHERE id = 1013;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن مسلمہ قعنبی نے بیان کیا، ان سے امام مالک نے بیان کیا، ان سے زید بن اسلم نے بیان کیا، ان سے عطاء بن یسار نے بیان کیا، ان سے عبداللہ بن عباس رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم کے زمانے میں سورج کو گرہن لگا تو آپ صلی اللہ علیہ وسلم نے نماز پڑھی تھی آپ صلی اللہ علیہ وسلم نے اتنا لمبا قیام کیا کہ اتنی دیر میں سورۃ البقرہ پڑھی جا سکتی تھی۔ پھر آپ صلی اللہ علیہ وسلم نے رکوع لمبا کیا اور اس کے بعد کھڑے ہوئے تو اب کی مرتبہ بھی قیام بہت لمبا تھا لیکن پہلے سے کچھ کم پھر ایک دوسرا لمبا رکوع کیا جو پہلے رکوع سے کچھ کم تھا پھر آپ صلی اللہ علیہ وسلم سجدہ میں گئے، سجدہ سے اٹھ کر پھر لمبا قیام کیا لیکن پہلے قیام کے مقابلے میں کم لمبا تھا پھر ایک لمبا رکوع کیا۔ یہ رکوع بھی پہلے رکوع کے مقابلہ میں کم تھا رکوع سے سر اٹھا نے کے بعد پھر آپ صلی اللہ علیہ وسلم بہت دیر تک کھڑے رہے اور یہ قیام بھی پہلے سے مختصر تھا۔ پھر ( چوتھا ) رکوع کیا یہ بھی بہت لمبا تھا لیکن پہلے سے کچھ کم۔ پھر آپ صلی اللہ علیہ وسلم نے سجدہ کیا اور نماز سے فارغ ہوئے تو سورج صاف ہو چکا تھا۔ اس کے بعد آپ صلی اللہ علیہ وسلم نے خطبہ میں فرمایا کہ سورج اور چاند دونوں اللہ تعالیٰ کی نشانیاں ہیں اور کسی کی موت و زندگی کی وجہ سے ان میں گرہن نہیں لگتا اس لیے جب تم کو معلوم ہو کہ گرہن لگ گیا ہے تو اللہ تعالیٰ کا ذکر کرو۔ صحابہ رضی اللہ عنہم نے عرض کیا یا رسول اللہ! ہم نے دیکھا کہ ( نماز میں ) اپنی جگہ سے آپ کچھ آگے بڑھے اور پھر اس کے بعد پیچھے ہٹ گئے۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ میں نے جنت دیکھی اور اس کا یک خوشہ توڑنا چاہا تھا اگر میں اسے توڑ سکتا تو تم اسے رہتی دنیا تک کھاتے اور مجھے جہنم بھی دکھائی گئی میں نے اس سے زیادہ بھیانک اور خوفناک منظر کبھی نہیں دیکھا۔ میں نے دیکھا اس میں عورتیں زیادہ ہیں۔ کسی نے پوچھا یا رسول اللہ! اس کی کیا وجہ ہے؟ آپ صلی اللہ علیہ وسلم نے فرمایا کہ اپنے کفر ( انکار ) کی وجہ سے، پوچھا گیا۔ کیا اللہ تعالیٰ کا کفر ( انکار ) کرتی ہیں؟ آپ صلی اللہ علیہ وسلم نے فرمایا کہ شوہر کا اور احسان کا کفر کرتی ہیں۔ زندگی بھر تم کسی عورت کے ساتھ حسن سلوک کرو لیکن کبھی اگر کوئی خلاف مزاج بات آ گئی تو فوراً یہی کہے گی کہ میں نے تم سے کبھی بھلائی نہیں دیکھی۔' WHERE id = 1024;
UPDATE hadiths SET urdu = 'ہم سے محمود بن غیلان نے بیان کیا، انہوں نے کہا کہ ہم سے ابواحمد محمد بن عبداللہ زبیری نے بیان کیا، انہوں نے کہا ہم سے سفیان ثوری نے بیان کیا، ان سے یحییٰ بن سعید انصاری نے، ان سے عمرہ نے، ان سے عائشہ رضی اللہ عنہا نے کہ نبی کریم صلی اللہ علیہ وسلم نے سورج گرہن کی دو رکعتوں میں چار رکوع کئے اور پہلی رکعت دوسری رکعت سے لمبی تھی۔' WHERE id = 1035;
UPDATE hadiths SET urdu = 'ہم سے بشر بن آدم نے بیان کیا، کہا کہ ہم سے علی بن مسہر نے بیان کیا، کہا کہ ہمیں عبیداللہ عمری نے خبر دی، انہیں نافع نے اور نافع کو ابن عمر رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم آیت سجدہ کی تلاوت اگر ہماری موجودگی میں کرتے تو آپ صلی اللہ علیہ وسلم کے ساتھ ہم بھی سجدہ کرتے تھے۔ اس وقت اتنا اژدھام ہو جاتا کہ سجدہ کے لیے پیشانی رکھنے کی جگہ نہ ملتی جس پر سجدہ کرنے والا سجدہ کر سکے۔' WHERE id = 1046;
UPDATE hadiths SET urdu = 'ہم سے اسحاق بن راہویہ نے بیان کیا، انہوں نے ابواسامہ سے، میں نے پوچھا کہ کیا آپ سے عبیداللہ عمری نے نافع سے یہ حدیث بیان کی تھی کہ ان سے عبداللہ بن عمر رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم کا یہ فرمان نقل کیا تھا کہ عورتیں تین دن کا سفر ذی رحم محرم کے بغیر نہ کریں ( ابواسامہ نے کہا ہاں ) ۔' WHERE id = 1056;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا انہوں نے کہا کہ ہم سے لیث نے بیان کیا، ان سے عقیل نے بیان کیا، ان سے ابن شہاب نے بیان کیا، ان سے عبداللہ بن عامر بن ربیعہ نے کہ عامر بن ربیعہ نے انہیں خبر دی انہوں نے کہا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم کو اونٹنی پر نماز نفل پڑھتے دیکھا۔ آپ صلی اللہ علیہ وسلم سر کے اشاروں سے پڑھ رہے تھے اس کا خیال کئے بغیر کہ سواری کا منہ کدھر ہوتا ہے لیکن فرض نمازوں میں آپ صلی اللہ علیہ وسلم اس طرح نہیں کرتے تھے۔' WHERE id = 1066;
UPDATE hadiths SET urdu = 'اور ابراہیم بن طہمان نے کہا کہ ان سے حسین معلم نے بیان کیا، ان سے یحییٰ بن ابی کثیر نے بیان کیا، ان سے عکرمہ نے بیان کیا اور ان سے عبداللہ بن عباس رضی اللہ عنہما نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم سفر میں ظہر اور عصر کی نماز ایک ساتھ ملا کر پڑھتے، اسی طرح مغرب اور عشاء کی بھی ایک ساتھ ملا کر پڑھتے تھے۔' WHERE id = 1076;
UPDATE hadiths SET urdu = 'ہم سے عبدان نے بیان کیا، ان سے امام عبداللہ بن مبارک نے، ان سے ابراہیم بن طہمان نے، انہوں نے کہا کہ مجھ سے حسین مکتب نے (جو بچوں کو لکھنا سکھاتا تھا) بیان کیا، ان سے ابن بریدہ نے اور ان سے عمران بن حصین رضی اللہ عنہما نے کہا کہ مجھے بواسیر کا مرض تھا۔ اس لیے میں نے نبی کریم صلی اللہ علیہ وسلم سے نماز کے بارے میں دریافت کیا۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ کھڑے ہو کر نماز پڑھا کرو اگر اس کی بھی طاقت نہ ہو تو بیٹھ کر اور اگر اس کی بھی نہ ہو تو پہلو کے بل لیٹ کر پڑھ لو۔' WHERE id = 1086;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف تنیسی نے بیان کیا، انہوں نے کہا کہ ہمیں امام مالک رحمہ اللہ نے خبر دی، انہیں ابن شہاب زہری نے، انہیں عروہ بن زبیر نے، انہیں ام المؤمنین عائشہ رضی اللہ عنہا نے کہ رسول اللہ صلی اللہ علیہ وسلم نے ایک رات مسجد میں نماز پڑھی۔ صحابہ نے بھی آپ صلی اللہ علیہ وسلم کے ساتھ یہ نماز پڑھی۔ دوسری رات بھی آپ صلی اللہ علیہ وسلم نے یہ نماز پڑھی تو نمازیوں کی تعداد بہت بڑھ گئی تیسری یا چوتھی رات تو پورا اجتماع ہی ہو گیا تھا۔ لیکن نبی کریم صلی اللہ علیہ وسلم اس رات نماز پڑھانے تشریف نہیں لائے۔ صبح کے وقت آپ صلی اللہ علیہ وسلم نے فرمایا کہ تم لوگ جتنی بڑی تعداد میں جمع ہو گئے تھے۔ میں نے اسے دیکھا لیکن مجھے باہر آنے سے یہ خیال مانع رہا کہ کہیں تم پر یہ نماز فرض نہ ہو جائے۔ یہ رمضان کا واقعہ تھا۔' WHERE id = 1097;
UPDATE hadiths SET urdu = 'ہم سے اسحاق بن راہویہ نے بیان کیا، کہا کہ ہم سے عبیداللہ بن موسیٰ نے بیان کیا، کہا کہ ہمیں اسرائیل نے خبر دی، انہیں ابوحصین عثمان بن عاصم نے، انہیں یحییٰ بن وثاب نے، انہیں مسروق بن اجدع نے، آپ نے کہا کہ میں نے عائشہ صدیقہ رضی اللہ عنہا سے نبی کریم صلی اللہ علیہ وسلم کی رات کی نماز کے متعلق پوچھا تو آپ نے فرمایا کہ آپ صلی اللہ علیہ وسلم سات، نو اور گیارہ تک رکعتیں پڑھتے تھے۔ فجر کی سنت اس کے سوا ہوتی۔' WHERE id = 1108;
UPDATE hadiths SET urdu = 'ہم سے اسحاق بن نصر نے بیان کیا، انہوں نے کہا کہ ہم سے ابواسامہ حماد بن اسابہ نے بیان کیا، ان سے ابوحیان یحییٰ بن سعید نے بیان کیا، ان سے ابوزرعہ نے بیان کیا اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے بلال رضی اللہ عنہ سے فجر کے وقت پوچھا کہ اے بلال! مجھے اپنا سب سے زیادہ امید والا نیک کام بتاؤ جسے تم نے اسلام لانے کے بعد کیا ہے کیونکہ میں نے جنت میں اپنے آگے تمہارے جوتوں کی چاپ سنی ہے۔ بلال رضی اللہ عنہ نے عرض کیا میں نے تو اپنے نزدیک اس سے زیادہ امید کا کوئی کام نہیں کیا کہ جب میں نے رات یا دن میں کسی وقت بھی وضو کیا تو میں اس وضو سے نفل نماز پڑھتا رہتا جتنی میری تقدیر لکھی گئی تھی۔' WHERE id = 1118;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ مدینی نے بیان کیا، ان سے سفیان بن عیینہ نے بیان کیا، ان سے ابوالنضر سالم نے بیان کیا کہ مجھ سے میرے باپ ابوامیہ نے بیان کیا، ان سے ابوسلمہ نے اور ان سے عائشہ رضی اللہ عنہا نے کہ نبی کریم صلی اللہ علیہ وسلم جب دو رکعت ( فجر کی سنت ) پڑھ چکتے تو اس وقت اگر میں جاگتی ہوتی تو آپ صلی اللہ علیہ وسلم مجھ سے باتیں کرتے ورنہ لیٹ جاتے۔ میں نے سفیان سے کہا کہ بعض راوی فجر کی دو رکعتیں اسے بتاتے ہیں تو انہوں نے فرمایا کہ ہاں یہ وہی ہیں۔' WHERE id = 1129;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا، کہا کہ ہم سے شعبہ نے بیان کیا، کہا کہ ہم سے عمرو بن مرہ نے بیان کیا، انہوں نے کہا کہ میں نے عبدالرحمٰن بن ابی لیلی سے سنا، وہ کہتے تھے کہ مجھ سے ام ہانی رضی اللہ عنہا کے سوا کسی ( صحابی ) نے یہ نہیں بیان کیا کہ انہوں نے نبی کریم صلی اللہ علیہ وسلم کو چاشت کی نماز پڑھتے دیکھا ہے۔ صرف ام ہانی رضی اللہ عنہا نے فرمایا کہ فتح مکہ کے دن آپ صلی اللہ علیہ وسلم ان کے گھر تشریف لائے، آپ صلی اللہ علیہ وسلم نے غسل کیا اور پھر آٹھ رکعت ( چاشت کی ) نماز پڑھی۔ تو میں نے ایسی ہلکی پھلکی نماز کبھی نہیں دیکھی۔ البتہ آپ صلی اللہ علیہ وسلم رکوع اور سجدہ پوری طرح ادا کرتے تھے۔' WHERE id = 1142;
UPDATE hadiths SET urdu = '(دوسری سند) ہم سے علی بن مدینی نے بیان کیا، کہا کہ ہم سے سفیان بن عیینہ نے بیان کیا، ان سے زہری نے، ان سے سعید بن مسیب نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ تین مسجدوں کے سوا کسی کے لیے کجاوے نہ باندھے جائیں۔ ( یعنی سفر نہ کیا جائے ) ایک مسجد الحرام، دوسری رسول اللہ صلی اللہ علیہ وسلم کی مسجد ( مسجد نبوی ) اور تیسری مسجد الاقصیٰ یعنی بیت المقدس۔' WHERE id = 1153;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن مسلمہ قعنبی نے بیان کیا، کہا کہ ہم سے عبدالعزیز بن ابی حازم نے بیان کیا، ان سے ان کے باپ ابوحازم سلمہ بن دینار نے اور ان سے سہل بن سعد رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم بنو عمرو بن عوف ( قباء ) کے لوگوں میں صلح کروانے تشریف لائے، اور جب نماز کا وقت ہو گیا تو بلال رضی اللہ عنہ نے ابوبکر صدیق رضی اللہ عنہ سے کہا کہ نبی کریم صلی اللہ علیہ وسلم تو اب تک نہیں تشریف لائے اس لیے اب آپ نماز پڑھائیے۔ انہوں نے فرمایا اچھا اگر تمہاری خواہش ہے تو میں پڑھا دیتا ہوں۔ خیر بلال رضی اللہ عنہ نے تکبیر کہی۔ ابوبکر رضی اللہ عنہ آگے بڑھے اور نماز شروع کی۔ اتنے میں نبی کریم صلی اللہ علیہ وسلم تشریف لے آئے اور آپ صلی اللہ علیہ وسلم صفوں سے گزرتے ہوئے پہلی صف تک پہنچ گئے۔ لوگوں نے ہاتھ پر ہاتھ مارنا شروع کیا۔ ( سہل نے ) کہا کہ جانتے ہو «تصفيح‏» کیا ہے یعنی تالیاں بجانا اور ابوبکر رضی اللہ عنہ نماز میں کسی طرف بھی دھیان نہیں کیا کرتے تھے، لیکن جب لوگوں نے زیادہ تالیاں بجائیں تو آپ متوجہ ہوئے۔ کیا دیکھتے ہیں کہ نبی کریم صلی اللہ علیہ وسلم صف میں موجود ہیں۔ نبی کریم صلی اللہ علیہ وسلم نے اشارہ سے انہیں اپنی جگہ رہنے کے لیے کہا۔ اس پر ابوبکر رضی اللہ عنہ نے ہاتھ اٹھا کر اللہ کا شکر کیا اور الٹے پاؤں پیچھے آ گئے اور نبی کریم صلی اللہ علیہ وسلم آگے بڑھ گئے۔' WHERE id = 1165;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا، کہا کہ ہم سے شعبہ نے بیان کیا، ان سے ارزق بن قیس نے بیان کیا، کہا کہ ہم اہواز میں ( جو کئی بستیاں ہیں بصرہ اور ایران کے بیچ میں ) خارجیوں سے جنگ کر رہے تھے۔ ایک بار میں نہر کے کنارے بیٹھا تھا۔ اتنے میں ایک شخص ( ابوبرزہ صحابی رضی اللہ عنہ ) آیا اور نماز پڑھنے لگا۔ کیا دیکھتا ہوں کہ ان کے گھوڑے کی لگام ان کے ہاتھ میں ہے۔ اچانک گھوڑا ان سے چھوٹ کر بھاگنے لگا۔ تو وہ بھی اس کا پیچھا کرنے لگے۔ شعبہ نے کہا یہ ابوبرزہ اسلمی رضی اللہ عنہ تھے۔ یہ دیکھ کر خوارج میں سے ایک شخص کہنے لگا کہ اے اللہ! اس شیخ کا ناس کر۔ جب وہ شیخ واپس لوٹے تو فرمایا کہ میں نے تمہاری باتیں سن لی ہیں۔ میں نے رسول اللہ صلی اللہ علیہ وسلم کے ساتھ چھ یا سات یا آٹھ جہادوں میں شرکت کی ہے اور میں نے آپ صلی اللہ علیہ وسلم کی آسانیوں کو دیکھا ہے۔ اس لیے مجھے یہ اچھا معلوم ہوا کہ اپنا گھوڑا ساتھ لے کر لوٹوں نہ کہ اس کو چھوڑ دوں وہ جہاں چاہے چل دے اور میں تکلیف اٹھاؤں۔' WHERE id = 1175;
UPDATE hadiths SET urdu = 'ہم سے اسحاق بن منصور نے بیان کیا، کہا کہ ہم سے روح بن عبادہ نے، کہا کہ ہم سے عمر نے جو سعید کے بیٹے ہیں، انہوں نے کہا کہ مجھے ابن ابی ملیکہ نے خبر دی عقبہ بن حارث رضی اللہ عنہ سے، انہوں نے کہا کہ میں نے نبی کریم صلی اللہ علیہ وسلم کے ساتھ عصر کی نماز پڑھی۔ آپ صلی اللہ علیہ وسلم سلام پھیرتے ہی بڑی تیزی سے اٹھے اور اپنی ایک بیوی کے حجرہ میں تشریف لے گئے، پھر باہر تشریف لائے۔ آپ صلی اللہ علیہ وسلم نے اپنی جلدی پر اس تعجب و حیرت کو محسوس کیا جو صحابہ کے چہروں سے ظاہر ہو رہا تھا، اس لیے آپ صلی اللہ علیہ وسلم نے فرمایا کہ نماز میں مجھے سونے کا ایک ڈلا یاد آ گیا جو ہمارے پاس تقسیم سے باقی رہ گیا تھا۔ مجھے برا معلوم ہوا کہ ہمارے پاس وہ شام تک یا رات تک رہ جائے۔ اس لیے میں نے اسے تقسیم کرنے کا حکم دے دیا۔' WHERE id = 1185;
UPDATE hadiths SET urdu = 'ہم سے معاذ بن فضالہ نے بیان کیا، انہوں نے کہا کہ ہم سے ہشام بن ابی عبداللہ دستوائی نے بیان کیا، ان سے یحییٰ بن ابی کثیر نے، ان سے ابوسلمہ نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ جب نماز کے لیے اذان ہوتی ہے تو شیطان ہوا خارج کرتا ہوا بھاگتا ہے تاکہ اذان نہ سنے، جب اذان پوری ہو جاتی ہے تو پھر آ جاتا ہے۔ جب اقامت ہوتی ہے تو پھر بھاگ پڑتا ہے۔ لیکن اقامت ختم ہوتے ہی پھر آ جاتا ہے اور نمازی کے دل میں طرح طرح کے وسوسے ڈالتا ہے اور کہتا ہے کہ فلاں فلاں بات یاد کرو، اس طرح اسے وہ باتیں یاد دلاتا ہے جو اس کے ذہن میں نہیں تھیں۔ لیکن دوسری طرف نمازی کو یہ بھی یاد نہیں رہتا کہ کتنی رکعتیں اس نے پڑھی ہیں۔ اس لیے اگر کسی کو یہ یاد نہ رہے کہ تین رکعت پڑھیں یا چار تو بیٹھے ہی بیٹھے سہو کے دو سجدے کر لے۔' WHERE id = 1196;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، کہا کہ ہم سے لیث بن سعد نے کہا، ان سے عقیل نے، ان سے ابن شہاب نے، انہوں نے فرمایا کہ مجھے خارجہ بن زید بن ثابت نے خبر دی کہ ام العلاء رضی اللہ عنہا انصار کی ایک عورت نے جنہوں نے نبی کریم صلی اللہ علیہ وسلم سے بیعت کی تھی، نے انہیں خبر دی کہ مہاجرین قرعہ ڈال کر انصار میں بانٹ دیئے گئے تو عثمان بن مظعون رضی اللہ عنہ ہمارے حصہ میں آئے۔ چنانچہ ہم نے انہیں اپنے گھر میں رکھا۔ آخر وہ بیمار ہوئے اور اسی میں وفات پا گئے۔ وفات کے بعد غسل دیا گیا اور کفن میں لپیٹ دیا گیا تو رسول اللہ صلی اللہ علیہ وسلم تشریف لائے۔ میں نے کہا ابوسائب آپ پر اللہ کی رحمتیں ہوں میری آپ کے متعلق شہادت یہ ہے کہ اللہ تعالیٰ نے آپ کی عزت فرمائی ہے۔ اس پر نبی کریم صلی اللہ علیہ وسلم نے فرمایا تمہیں کیسے معلوم ہوا کہ اللہ تعالیٰ نے ان کی عزت فرمائی ہے؟ میں نے کہا یا رسول اللہ! میرے ماں باپ آپ پر قربان ہوں پھر کس کی اللہ تعالیٰ عزت افزائی کرے گا؟ آپ صلی اللہ علیہ وسلم نے فرمایا اس میں شبہ نہیں کہ ان کی موت آ چکی، قسم اللہ کی کہ میں بھی ان کے لیے خیر ہی کی امید رکھتا ہوں لیکن واللہ! مجھے خود اپنے متعلق بھی معلوم نہیں کہ میرے ساتھ کیا معاملہ ہو گا۔ حالانکہ میں اللہ کا رسول ہوں۔ ام العلاء رضی اللہ عنہا نے کہا کہ اللہ کی قسم! اب میں کبھی کسی کے متعلق ( اس طرح کی ) گواہی نہیں دوں گی۔' WHERE id = 1207;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ نے بیان کیا، انہوں نے کہا کہ ہم سے اسماعیل بن ابراہیم نے بیان کیا، انہوں نے کہا کہ ہم سے خالد نے بیان کیا، ان سے حفصہ بنت سیرین نے اور ان سے ام عطیہ رضی اللہ عنہا نے کہ رسول اللہ صلی اللہ علیہ وسلم نے اپنی بیٹی کے غسل کے وقت فرمایا تھا کہ دائیں طرف سے اور اعضاء وضو سے غسل شروع کرنا۔' WHERE id = 1218;
UPDATE hadiths SET urdu = 'ہم سے ابوالنعمان نے بیان کیا، انہوں نے کہا کہ ہم کو ابوعوانہ نے خبر دی، انہیں ابوبشر جعفر نے، انہیں سعید بن جبیر نے، انہیں عبداللہ بن عباس رضی اللہ عنہما نے کہ ایک مرتبہ ہم لوگ نبی کریم صلی اللہ علیہ وسلم کے ساتھ احرام باندھے ہوئے تھے کہ ایک شخص کی گردن اس کے اونٹ نے توڑ ڈالی۔ تو نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ انہیں پانی اور بیری کے پتوں سے غسل دے دو اور کپڑوں کا کفن دو اور خوشبو نہ لگاؤ نہ ان کے سر کو ڈھکو۔ اس لیے کہ اللہ تعالیٰ انہیں اٹھائے گا۔ اس حالت میں کہ وہ لبیک پکارتا ہو گا۔' WHERE id = 1229;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن مسلمہ قعنبی نے بیان کیا ‘ کہا کہ ہم سے عبدالعزیز بن ابی حازم نے بیان کیا ‘ ان سے ان کے باپ نے اور ان سے سہل رضی اللہ عنہ نے کہ ایک عورت نبی کریم صلی اللہ علیہ وسلم کی خدمت میں ایک بنی ہوئی حاشیہ دار چادر آپ صلی اللہ علیہ وسلم کے لیے تحفہ لائی۔ سہل بن سعد رضی اللہ عنہ نے ( حاضرین سے ) پوچھا کہ تم جانتے ہو چادر کیا؟ لوگوں نے کہا کہ جی ہاں! شملہ۔ سہل رضی اللہ عنہ نے کہا ہاں شملہ ( تم نے ٹھیک بتایا ) خیر اس عورت نے کہا کہ میں نے اپنے ہاتھ سے اسے بنا ہے اور آپ صلی اللہ علیہ وسلم کو پہنانے کے لیے لائی ہوں۔ نبی کریم صلی اللہ علیہ وسلم نے وہ کپڑا قبول کیا۔ آپ صلی اللہ علیہ وسلم کو اس کی اس وقت ضرورت بھی تھی پھر اسے ازار کے طور پر باندھ کر آپ صلی اللہ علیہ وسلم باہر تشریف لائے تو ایک صاحب ( عبدالرحمٰن بن عوف رضی اللہ عنہ ) نے کہا کہ یہ تو بڑی اچھی چادر ہے ‘ یہ آپ صلی اللہ علیہ وسلم مجھے پہنا دیجئیے۔ لوگوں نے کہا کہ آپ نے ( مانگ کر ) کچھ اچھا نہیں کیا۔ رسول اللہ صلی اللہ علیہ وسلم نے اسے اپنی ضرورت کی وجہ سے پہنا تھا اور تم نے یہ مانگ لیا حالانکہ تم کو معلوم ہے کہ نبی کریم صلی اللہ علیہ وسلم کسی کا سوال رد نہیں کرتے۔ عبدالرحمٰن بن عوف رضی اللہ عنہ نے جواب دیا کہ اللہ کی قسم! میں نے اپنے پہننے کے لیے آپ صلی اللہ علیہ وسلم سے یہ چادر نہیں مانگی تھی۔ بلکہ میں اسے اپنا کفن بناؤں گا۔ سہل رضی اللہ عنہ نے بیان کیا کہ وہی چادر ان کا کفن بنی۔' WHERE id = 1239;
UPDATE hadiths SET urdu = 'ہم سے عبد ان عبداللہ بن عثمان نے بیان کیا ‘ کہا کہ مجھے میرے باپ نے خبر دی ‘ انہیں شعبہ نے ‘ انہیں قتادہ نے ‘ انہیں سعید بن مسیب نے ‘ انہیں عبداللہ بن عمر رضی اللہ عنہما نے اپنے باپ عمر رضی اللہ عنہ سے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ میت کو اس پر نوحہ کئے جانے کی وجہ سے بھی قبر میں عذاب ہوتا ہے۔ عبدان کے ساتھ اس حدیث کو عبدالاعلیٰ نے بھی یزید بن زریع سے روایت کیا۔ انہوں نے کہا ہم سے سعید بن ابی عروبہ نے بیان کیا ‘ کہا ہم سے قتادہ نے۔ اور آدم بن ابی ایاس نے شعبہ سے یوں روایت کیا کہ میت پر زندے کے رونے سے عذاب ہوتا ہے۔' WHERE id = 1251;
UPDATE hadiths SET urdu = 'ہم سے محمد بن بشار نے بیان کیا ‘ انہوں نے کہا کہ ہم سے غندر نے بیان کیا ‘ ان سے شعبہ نے ان سے ثابت نے، انہوں نے بیان کیا کہ میں نے انس رضی اللہ عنہ سے سنا۔ آپ نبی کریم صلی اللہ علیہ وسلم کے حوالہ سے نقل کرتے تھے کہ آپ صلی اللہ علیہ وسلم نے فرمایا صبر تو وہی ہے جو صدمہ کے شروع میں کیا جائے۔' WHERE id = 1261;
UPDATE hadiths SET urdu = 'ہم سے عبدالعزیز نے بیان کیا ‘ انہوں نے کہا کہ ہم سے لیث نے بیان کیا ‘ انہوں نے کہا کہ ہم سے سعید مقبری نے بیان کیا ‘ ان سے ان کے باپ کیسان نے کہ انہوں نے ابو سعید خدری رضی اللہ عنہ سے سنا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ جب میت چارپائی پر رکھی جاتی ہے اور مرد اسے کاندھوں پر اٹھاتے ہیں تو اگر وہ نیک ہو تو کہتا ہے کہ مجھے آگے لے چلو۔ لیکن اگر نیک نہیں تو کہتا ہے ہائے بربادی! مجھے کہاں لیے جا رہے ہو۔ اس آواز کو انسان کے سوا تمام اللہ کی مخلوق سنتی ہے۔ اگر انسان کہیں سن پائے تو بیہوش ہو جائے۔' WHERE id = 1272;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن مسلمہ نے بیان کیا ‘ کہا کہ میں نے ابن ابی ذئب کے سامنے یہ حدیث پڑھی ‘ ان سے ابوسعید مقبری نے بیان کیا ‘ ان سے ان کے باپ نے ‘ انہوں نے ابوہریرہ رضی اللہ عنہ سے پوچھا تو آپ نے فرمایا کہ میں نے نبی کریم صلی اللہ علیہ وسلم سے سنا تھا۔ ( دوسری سند ) ہم سے احمد بن شبیب نے بیان کیا ‘ کہا کہ مجھ سے میرے والد نے بیان کیا ‘ ان سے یونس نے بیان کیا کہ ابن شہاب نے کہا کہ ( مجھ سے فلاں نے یہ بھی حدیث بیان کی ) اور مجھ سے عبدالرحمٰن اعرج نے بھی کہا کہ ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ جس نے جنازہ میں شرکت کی پھر نماز جنازہ پڑھی تو اسے ایک قیراط کا ثواب ملتا ہے اور جو دفن تک ساتھ رہا تو اسے دو قیراط کا ثواب ملتا ہے۔ پوچھا گیا کہ دو قیراط کتنے ہوں گے؟ فرمایا کہ دو عظیم پہاڑوں کے برابر۔' WHERE id = 1282;
UPDATE hadiths SET urdu = 'ہم سے محمد بن فضل نے کیا ‘ انہوں نے کہا کہ ہم سے حماد بن زید نے بیان کیا ‘ ان سے ثابت نے بیان کیا ‘ ان سے ابورافع نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ کالے رنگ کا ایک مرد یا ایک کالی عورت مسجد کی خدمت کیا کرتی تھیں ‘ ان کی وفات ہو گئی لیکن نبی کریم صلی اللہ علیہ وسلم کو ان کی وفات کی خبر کسی نے نہیں دی۔ ایک دن آپ صلی اللہ علیہ وسلم نے خود یاد فرمایا کہ وہ شخص دکھائی نہیں دیتا۔ صحابہ نے کہا کہ یا رسول اللہ ( صلی اللہ علیہ وسلم ) ! ان کا تو انتقال ہو گیا۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ پھر تم نے مجھے خبر کیوں نہیں دی؟ صحابہ نے عرض کی کہ یہ وجوہ تھیں ( اس لیے آپ کو تکلیف نہیں دی گئی ) گویا لوگوں نے ان کو حقیر جان کر قابل توجہ نہیں سمجھا لیکن آپ صلی اللہ علیہ وسلم نے فرمایا کہ چلو مجھے ان کی قبر بتا دو۔ چنانچہ آپ صلی اللہ علیہ وسلم اس کی قبر پر تشریف لائے اور اس پر نماز جنازہ پڑھی۔' WHERE id = 1293;
UPDATE hadiths SET urdu = 'ہم سے محمد بن عبداللہ بن حوشب نے بیان کیا ‘ کہا کہ ہم سے عبدالوہاب نے بیان کیا۔ کہا ہم سے خالد حذاء نے ‘ ان سے عکرمہ نے ‘ ان سے ابن عباس رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اللہ تعالیٰ نے مکہ کو حرم کیا ہے۔ نہ مجھ سے پہلے کسی کے لیے ( یہاں قتل و خون ) حلال تھا اور نہ میرے بعد ہو گا اور میرے لیے بھی تھوڑی دیر کے لیے ( فتح مکہ کے دن ) حلال ہوا تھا۔ پس نہ اس کی گھاس اکھاڑی جائے نہ اس کے درخت قلم کئے جائیں۔ نہ یہاں کے جانوروں کو ( شکار کے لیے ) بھگایا جائے اور سوا اس شخص کے جو اعلان کرنا چاہتا ہو ( کہ یہ گری ہوئی چیز کس کی ہے ) کسی کے لیے وہاں سے کوئی گری ہوئی چیز اٹھانی جائز نہیں۔ اس پر عباس رضی اللہ عنہ نے کہا ”لیکن اس سے اذخر کا استثناء کر دیجئیے کہ یہ ہمارے سناروں کے اور ہماری قبروں میں کام آتی ہے۔“ آپ صلی اللہ علیہ وسلم نے فرمایا کہ مگر اذخر کی اجازت ہے۔ ابوہریرہ رضی اللہ عنہ کی نبی کریم صلی اللہ علیہ وسلم سے روایت میں ہے۔ ”ہماری قبروں اور گھروں کے لیے۔“ اور ابان بن صالح نے بیان کیا ‘ ان سے حسن بن مسلم نے ‘ ان سے صفیہ بنت شیبہ نے کہ انہوں نے نبی کریم صلی اللہ علیہ وسلم سے اسی طرح سنا تھا۔ اور مجاہد نے طاؤس کے واسطہ سے بیان کیا اور ان سے ابن عباس رضی اللہ عنہما نے یہ الفاظ بیان کئے۔ ہمارے قین ( لوہاروں ) اور گھروں کے لیے ( اذخر اکھاڑنا حرم سے ) جائز کر دیجئیے۔' WHERE id = 1304;
UPDATE hadiths SET urdu = 'ہم سے اسحاق بن راہویہ نے بیان کیا ‘ کہا کہ ہمیں یعقوب بن ابراہیم نے خبر دی ‘ کہا کہ مجھے میرے باپ (ابراہیم بن سعد) نے صالح بن کیسان سے خبر دی ‘ انہیں ابن شہاب نے ‘ انہوں نے بیان کیا کہ مجھے سعید بن مسیب نے اپنے باپ (مسیب بن حزن رضی اللہ عنہ) سے خبر دی ‘ ان کے باپ نے انہیں یہ خبر دی کہ جب ابوطالب کی وفات کا وقت قریب آیا تو رسول اللہ صلی اللہ علیہ وسلم ان کے پاس تشریف لائے۔ دیکھا تو ان کے پاس اس وقت ابوجہل بن ہشام اور عبداللہ بن ابی امیہ بن مغیرہ موجود تھے۔ آپ صلی اللہ علیہ وسلم نے ان سے فرمایا کہ چچا! آپ ایک کلمہ «لا إله إلا الله» ( اللہ کے سوا کوئی معبود نہیں کوئی معبود نہیں ) کہہ دیجئیے تاکہ میں اللہ تعالیٰ کے ہاں اس کلمہ کی وجہ سے آپ کے حق میں گواہی دے سکوں۔ اس پر ابوجہل اور عبداللہ بن ابی امیہ مغیرہ نے کہا ابوطالب! کیا تم اپنے باپ عبدالمطلب کے دین سے پھر جاؤ گے؟ رسول اللہ صلی اللہ علیہ وسلم برابر کلمہ اسلام ان پر پیش کرتے رہے۔ ابوجہل اور ابن ابی امیہ بھی اپنی بات دہراتے رہے۔ آخر ابوطالب کی آخری بات یہ تھی کہ وہ عبدالمطلب کے دین پر ہیں۔ انہوں نے «لا إله إلا الله» کہنے سے انکار کر دیا پھر بھی رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ میں آپ کے لیے استغفار کرتا رہوں گا۔ تاآنکہ مجھے منع نہ کر دیا جائے اس پر اللہ تعالیٰ نے آیت «ما كان للنبي‏» الآية‏ نازل فرمائی۔ ( التوبہ:)' WHERE id = 1314;
UPDATE hadiths SET urdu = 'ہم سے عبدان نے بیان کیا ‘ کہا مجھ کو میرے باپ (عثمان) نے خبر دی ‘ انہیں شعبہ نے ‘ انہوں نے اشعث سے سنا ‘ انہوں نے اپنے والد ابوالشعثاء سے ‘ انہوں نے مسروق سے اور انہوں نے عائشہ رضی اللہ عنہا سے کہ ایک یہودی عورت ان کے پاس آئی۔ اس نے عذاب قبر کا ذکر چھیڑ دیا اور کہا کہ اللہ تجھ کو عذاب قبر سے محفوظ رکھے۔ اس پر عائشہ رضی اللہ عنہا نے رسول اللہ صلی اللہ علیہ وسلم سے عذاب قبر کے بارے میں دریافت کیا۔ آپ صلی اللہ علیہ وسلم نے اس کا جواب یہ دیا کہ ہاں عذاب قبر حق ہے۔ عائشہ رضی اللہ عنہا نے بیان کیا کہ پھر میں نے کبھی ایسا نہیں دیکھا کہ آپ صلی اللہ علیہ وسلم نے کوئی نماز پڑھی ہو اور اس میں عذاب قبر سے اللہ کی پناہ نہ مانگی ہو۔ غندر نے «عذاب القبر حق» کے الفاظ زیادہ کئے۔' WHERE id = 1325;
UPDATE hadiths SET urdu = 'ہم سے ابوالولید نے بیان کیا ‘ کہا ہم سے شعبہ نے بیان کیا ‘ ان سے عدی بن ثابت نے بیان کیا ‘ انہوں نے براء بن عازب رضی اللہ عنہ سے سنا ‘ انہوں نے فرمایا کہ جب ابراہیم ( نبی کریم صلی اللہ علیہ وسلم کے صاحبزادے ) کا انتقال ہوا تو رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ بہشت میں ان کے لیے ایک دودھ پلانے والی ہے۔' WHERE id = 1335;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ نے بیان کیا ‘ کہا کہ ہم سے جریر بن عبدالحمید نے بیان کیا ‘ کہا کہ ہم سے حصین بن عبدالرحمٰن نے بیان کیا ‘ ان سے عمرو بن میمون اودی نے بیان کیا کہ میری موجودگی میں عمر بن خطاب رضی اللہ عنہ نے عبداللہ بن عمر رضی اللہ عنہما سے فرمایا کہ اے عبداللہ! ام المؤمنین عائشہ رضی اللہ عنہا کی خدمت میں جا اور کہہ کہ عمر بن خطاب نے آپ کو سلام کہا ہے اور پھر ان سے معلوم کرنا کہ کیا مجھے میرے دونوں ساتھیوں کے ساتھ دفن ہونے کی آپ کی طرف سے اجازت مل سکتی ہے؟ عائشہ رضی اللہ عنہا نے کہا کہ میں نے اس جگہ کو اپنے لیے پسند کر رکھا تھا لیکن آج میں اپنے پر عمر رضی اللہ عنہ کو ترجیح دیتی ہوں۔ جب ابن عمر رضی اللہ عنہما واپس آئے تو عمر رضی اللہ عنہ نے دریافت کیا کہ کیا پیغام لائے ہو؟ کہا کہ امیرالمؤمنین انہوں نے آپ کو اجازت دے دی ہے۔ عمر رضی اللہ عنہ یہ سن کر بولے کہ اس جگہ دفن ہونے سے زیادہ مجھے اور کوئی چیز عزیز نہیں تھی۔ لیکن جب میری روح قبض ہو جائے تو مجھے اٹھا کر لے جانا اور پھر دوبارہ عائشہ رضی اللہ عنہا کو میرا سلام پہنچا کر ان سے کہنا کہ عمر نے آپ سے اجازت چاہی ہے۔ اگر اس وقت بھی وہ اجازت دے دیں تو مجھے وہیں دفن کر دینا ‘ ورنہ مسلمانوں کے قبرستان میں دفن کر دینا۔ میں اس امر خلافت کا ان چند صحابہ سے زیادہ اور کسی کو مستحق نہیں سمجھتا جن سے رسول اللہ صلی اللہ علیہ وسلم اپنی وفات کے وقت تک خوش اور راضی رہے۔ وہ حضرات میرے بعد جسے بھی خلیفہ بنائیں ‘ خلیفہ وہی ہو گا اور تمہارے لیے ضروری ہے کہ تم اپنے خلیفہ کی باتیں توجہ سے سنو اور اس کی اطاعت کرو۔ آپ نے اس موقع پر عثمان ‘ علی ‘ طلحہ ‘ زبیر ‘ عبدالرحمٰن بن عوف اور سعد بن ابی وقاص رضی اللہ عنہم کے نام لیے۔ اتنے میں ایک انصاری نوجوان داخل ہوا اور کہا کہ اے امیرالمؤمنین آپ کو بشارت ہو ‘ اللہ عزوجل کی طرف سے ‘ آپ کا اسلام میں پہلے داخل ہونے کی وجہ سے جو مرتبہ تھا وہ آپ کو معلوم ہے۔ پھر جب آپ خلیفہ ہوئے تو آپ نے انصاف کیا۔ پھر آپ نے شہادت پائی۔ عمر رضی اللہ عنہ بولے میرے بھائی کے بیٹے! کاش ان کی وجہ سے میں برابر چھوٹ جاؤں۔ نہ مجھے کوئی عذاب ہو اور نہ کوئی ثواب۔ ہاں میں اپنے بعد آنے والے خلیفہ کو وصیت کرتا ہوں کہ وہ مہاجرین اولین کے ساتھ اچھا برتاو رکھے ‘ ان کے حقوق پہچانے اور ان کی عزت کی حفاظت کرے اور میں اسے انصار کے بارے میں بھی اچھا برتاو رکھنے کی وصیت کرتا ہوں۔ یہ وہ لوگ ہیں جنہوں نے ایمان والوں کو اپنے گھروں میں جگہ دی۔ ( میری وصیت ہے کہ ) ان کے اچھے لوگوں کے ساتھ بھلائی کی جائے اور ان میں جو برے ہوں ان سے درگذر کیا جائے اور میں ہونے والے خلیفہ کو وصیت کرتا ہوں اس ذمہ داری کو پورا کرنے کی جو اللہ اور رسول کی ذمہ داری ہے ( یعنی غیر مسلموں کی جو اسلامی حکومت کے تحت زندگی گذارتے ہیں ) کہ ان سے کئے گئے وعدوں کو پورا کیا جائے۔ انہیں بچا کر لڑا جائے اور طاقت سے زیادہ ان پر کوئی بار نہ ڈالا جائے۔' WHERE id = 1347;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ مدینی نے بیان کیا ‘ انہوں نے کہا ہم سے ہاشم بن قاسم نے بیان کیا کہ ہم سے عبدالرحمٰن بن عبداللہ بن دینار نے اپنے والد سے بیان کیا ‘ ان سے ابوصالح سمان نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ جسے اللہ نے مال دیا اور اس نے اس کی زکوٰۃ نہیں ادا کی تو قیامت کے دن اس کا مال نہایت زہریلے گنجے سانپ کی شکل اختیار کر لے گا۔ اس کی آنکھوں کے پاس دو سیاہ نقطے ہوں گے۔ جیسے سانپ کے ہوتے ہیں ‘ پھر وہ سانپ اس کے دونوں جبڑوں سے اسے پکڑ لے گا اور کہے گا کہ میں تیرا مال اور خزانہ ہوں۔ اس کے بعد آپ صلی اللہ علیہ وسلم نے یہ آیت پڑھی ”اور وہ لوگ یہ گمان نہ کریں کہ اللہ تعالیٰ نے انہیں جو کچھ اپنے فضل سے دیا ہے وہ اس پر بخل سے کام لیتے ہیں کہ ان کا مال ان کے لیے بہتر ہے۔ بلکہ وہ برا ہے جس مال کے معاملہ میں انہوں نے بخل کیا ہے۔ قیامت میں اس کا طوق بنا کر ان کی گردن میں ڈالا جائے گا۔“' WHERE id = 1357;
UPDATE hadiths SET urdu = 'ہم سے ابوقدامہ عبیداللہ بن سعید نے بیان کیا ‘ کہا ہم سے ابوالنعمان حکم بن عبداللہ بصریٰ نے بیان کیا ‘ کہا ہم سے شعبہ بن حجاج نے بیان کیا ‘ ان سے سلیمان اعمش نے ‘ ان سے ابووائل نے اور ان سے ابومسعود انصاری رضی اللہ عنہ نے فرمایا کہ جب آیت صدقہ نازل ہوئی تو ہم بوجھ ڈھونے کا کام کیا کرتے تھے ( تاکہ اس طرح جو مزدوری ملے اسے صدقہ کر دیا جائے ) اسی زمانہ میں ایک شخص ( عبدالرحمٰن بن عوف ) آیا اور اس نے صدقہ کے طور پر کافی چیزیں پیش کیں۔ اس پر لوگوں نے یہ کہنا شروع کیا کہ یہ آدمی ریاکار ہے۔ پھر ایک اور شخص ( ابوعقیل نامی ) آیا اور اس نے صرف ایک صاع کا صدقہ کیا۔ اس کے بارے میں لوگوں نے یہ کہہ دیا کہ اللہ تعالیٰ کو ایک صاع صدقہ کی کیا حاجت ہے۔ اس پر یہ آیت نازل ہوئی «الذين يلمزون المطوعين من المؤمنين في الصدقات والذين لا يجدون إلا جهدهم» ”وہ لوگ جو ان مومنوں پر عیب لگاتے ہیں جو صدقہ زیادہ دیتے ہیں اور ان پر بھی جو محنت سے کما کر لاتے ہیں۔ ( اور کم صدقہ کرتے ہیں ) “ آخر تک۔' WHERE id = 1368;
UPDATE hadiths SET urdu = 'ہم سے عثمان بن ابی شیبہ نے بیان کیا ‘ کہا ہم سے جریر نے بیان کیا ‘ ان سے منصور نے۔ ان سے شقیق نے ‘ ان سے مسروق نے اور ان سے عائشہ رضی اللہ عنہا نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا اگر عورت اپنے شوہر کے مال سے کچھ خرچ کرے اور اس کی نیت شوہر کی پونجی برباد کرنے کی نہ ہو تو اسے خرچ کرنے کا ثواب ملے گا اور شوہر کو بھی اس کا ثواب ملے گا اس نے کمایا ہے اور خزانچی کا بھی یہی حکم ہے۔ ایک کا ثواب دوسرے کے ثواب میں کوئی کمی نہیں کرتا۔' WHERE id = 1378;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا ‘ انہوں نے کہا کہ ہم سے جریر نے اعمش سے بیان کیا ‘ ان سے ابووائل نے ‘ ان سے مسروق نے اور ان سے عائشہ رضی اللہ عنہا نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ جب بیوی اپنے خاوند کے کھانے میں سے کچھ صدقہ کرے اور اس کی نیت اسے برباد کرنے کی نہیں ہوتی تو اسے بھی اس کا ثواب ملتا ہے اور اس کے خاوند کو کمانے کا ثواب ملتا ہے۔ اسی طرح خزانچی کو بھی اس کا ثواب ملتا ہے۔' WHERE id = 1389;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف تنیسی نے بیان کیا ‘ انہوں نے کہا کہ ہمیں امام مالک نے خبر دی ‘ انہیں عمرو بن یحییٰ مازنی نے ‘ انہیں ان کے باپ یحییٰ نے۔ انہوں نے کہا کہ میں نے ابو سعید خدری رضی اللہ عنہ سے سنا ‘ انہوں نے کہا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ پانچ اونٹ سے کم میں زکوٰۃ نہیں اور پانچ اوقیہ سے کم ( چاندی ) میں زکوٰۃ نہیں۔ اسی طرح پانچ وسق سے کم ( غلہ ) میں زکوٰۃ نہیں۔' WHERE id = 1399;
UPDATE hadiths SET urdu = 'ہم عبداللہ بن یوسف تنیسی نے بیان کیا ‘ انہوں نے کہا کہ ہمیں امام مالک نے خبر دی ‘ انہیں محمد بن عبدالرحمٰن بن ابی صعصعہ مازنی نے ‘ انہیں ان کے باپ نے اور انہیں ابو سعید خدری رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ پانچ وسق سے کم کھجوروں میں زکوٰۃ نہیں اور پانچ اوقیہ سے کم چاندی میں زکوٰۃ نہیں۔ اسی طرح پانچ اونٹوں سے کم میں زکوٰۃ نہیں ہے۔' WHERE id = 1410;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا ‘ کہا کہ ہمیں امام مالک نے ‘ ابن شہاب سے خبر دی ‘ انہیں عطاء بن یزید لیثی نے اور انہیں ابو سعید خدری رضی اللہ عنہ نے کہ انصار کے کچھ لوگوں نے رسول اللہ صلی اللہ علیہ وسلم سے سوال کیا تو آپ صلی اللہ علیہ وسلم نے انہیں دیا۔ پھر انہوں نے سوال کیا اور آپ صلی اللہ علیہ وسلم نے پھر دیا۔ یہاں تک کہ جو مال آپ صلی اللہ علیہ وسلم کے پاس تھا۔ اب وہ ختم ہو گیا۔ پھر آپ صلی اللہ علیہ وسلم نے فرمایا کہ اگر میرے پاس جو مال و دولت ہو تو میں اسے بچا کر نہیں رکھوں گا۔ مگر جو شخص سوال کرنے سے بچتا ہے تو اللہ تعالیٰ بھی اسے سوال کرنے سے محفوظ ہی رکھتا ہے۔ اور جو شخص بے نیازی برتتا ہے تو اللہ تعالیٰ اسے بےنیاز بنا دیتا ہے اور جو شخص اپنے اوپر زور ڈال کر بھی صبر کرتا ہے تو اللہ تعالیٰ بھی اسے صبر و استقلال دے دیتا ہے۔ اور کسی کو بھی صبر سے زیادہ بہتر اور اس سے زیادہ بےپایاں خیر نہیں ملی۔ ( صبر تمام نعمتوں سے بڑھ کر ہے ) ۔' WHERE id = 1420;
UPDATE hadiths SET urdu = 'ہم سے سعید بن ابی مریم نے بیان کیا ‘ کہا کہ ہم سے عبداللہ بن وہب نے بیان کیا ‘ کہا کہ مجھے یونس بن یزید نے خبر دی ‘ انہیں شہاب نے ‘ انہیں سالم بن عبداللہ بن عمر نے ‘ انہیں ان کے والد نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا۔ وہ زمین جسے آسمان ( بارش کا پانی ) یا چشمہ سیراب کرتا ہو۔ یا وہ خودبخود نمی سے سیراب ہو جاتی ہو تو اس کی پیداوار سے دسواں حصہ لیا جائے اور وہ زمین جسے کنویں سے پانی کھینچ کر سیراب کیا جاتا ہو تو اس کی پیداوار سے بیسواں حصہ لیا جائے۔ ابوعبداللہ ( امام بخاری رحمہ اللہ ) نے کہا کہ یہ حدیث یعنی عبداللہ بن عمر رضی اللہ عنہما کی حدیث کہ جس کھیتی میں آسمان کا پانی دیا جائے ‘ دسواں حصہ ہے پہلی حدیث یعنی ابوسعید کی حدیث کی تفسیر ہے۔ اس میں زکوٰۃ کی کوئی مقدار مذکور نہیں ہے اور اس میں مذکور ہے۔ اور زیادتی قبول کی جاتی ہے۔ اور گول مول حدیث کا حکم صاف صاف حدیث کے موافق لیا جاتا ہے۔ جب اس کا راوی ثقہ ہو۔ جیسے فضل بن عباس رضی اللہ عنہ نے روایت کیا کہ نبی کریم صلی اللہ علیہ وسلم نے کعبہ میں نماز نہیں پڑھی۔ لیکن بلال رضی اللہ عنہ نے بتلایا کہ آپ صلی اللہ علیہ وسلم نے نماز ( کعبہ میں ) پڑھی تھی۔ اس موقع پر بھی بلال رضی اللہ عنہ کی بات قبول کی گئی اور فضل رضی اللہ عنہ کا قول چھوڑ دیا گیا۔' WHERE id = 1432;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا ‘ کہا کہ ہم سے شعبہ نے بیان کیا ‘ کہا کہ ہم سے حکم بن عتبہ نے بیان کیا ‘ ان سے ابراہیم نخعی نے ‘ ان سے اسود نے اور ان سے عائشہ رضی اللہ عنہا نے کہ ان کا ارادہ ہوا کہ بریرہ رضی اللہ عنہا کو ( جو باندی تھیں ) آزاد کر دینے کے لیے خرید لیں۔ لیکن اس کے اصل مالک یہ چاہتے تھے کہ ولاء انہیں کے لیے رہے۔ اس کا ذکر عائشہ رضی اللہ عنہا نے نبی کریم صلی اللہ علیہ وسلم سے کیا۔ تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ تم خرید کر آزاد کر دو ‘ ولاء تو اسی کی ہوتی ہے ‘ جو آزاد کرے۔ انہوں نے کہا کہ نبی کریم صلی اللہ علیہ وسلم کی خدمت میں گوشت پیش کیا گیا۔ میں نے کہا کہ یہ بریرہ رضی اللہ عنہا کو کسی نے صدقہ کے طور پر دیا ہے تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ یہ ان کے لیے صدقہ تھا۔ لیکن اب ہمارے لیے یہ ہدیہ ہے۔' WHERE id = 1442;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن محمد بن سکن نے بیان کیا ‘ انہوں نے کہا کہ ہم سے محمد بن جھضم نے بیان کیا ‘ انہوں نے کہا کہ ہم سے اسماعیل بن جعفر نے بیان کیا ‘ ان سے عمر بن نافع نے ان سے ان کے باپ نے اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فطر کی زکوٰۃ ( صدقہ فطر ) ایک صاع کھجور یا ایک صاع جَو فرض قرار دی تھی۔ غلام ‘ آزاد ‘ مرد ‘ عورت ‘ چھوٹے اور بڑے تمام مسلمانوں پر۔ آپ صلی اللہ علیہ وسلم کا حکم یہ تھا کہ نماز ( عید ) کے لیے جانے سے پہلے یہ صدقہ ادا کر دیا جائے۔' WHERE id = 1452;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، انہوں نے کہا کہ ہمیں امام مالک نے خبر دی انہیں ابن شہاب نے، انہیں سلیمان بن یسار نے، اور ان سے عبداللہ بن عباس رضی اللہ عنہما نے بیان کیا کہ فضل بن عباس ( حجۃ الوداع میں ) رسول اللہ صلی اللہ علیہ وسلم کے ساتھ سواری کے پیچھے بیٹھے ہوئے تھے کہ قبیلہ خثعم کی ایک خوبصورت عورت آئی۔ فضل اس کو دیکھنے لگے وہ بھی انہیں دیکھ رہی تھی۔ لیکن رسول اللہ صلی اللہ علیہ وسلم فضل رضی اللہ عنہ کا چہرہ بار بار دوسری طرف موڑ دینا چاہتے تھے۔ اس عورت نے کہا یا رسول اللہ! اللہ کا فریضہ حج میرے والد کے لیے ادا کرنا ضروری ہو گیا ہے۔ لیکن وہ بہت بوڑھے ہیں اونٹنی پر بیٹھ نہیں سکتے۔ کیا میں ان کی طرف سے حج ( بدل ) کر سکتی ہوں؟ آپ صلی اللہ علیہ وسلم نے فرمایا کہ ہاں۔ یہ حجتہ الوداع کا واقعہ تھا۔' WHERE id = 1462;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بشر نے بیان کیا، انہوں نے کہا کہ ہم سے شبابہ بن سوار نے بیان کیا، ان سے ورقاء بن عمرو نے، ان سے عمرو بن دینار نے، ان سے عکرمہ نے بیان کیا اور ان سے عبداللہ بن عباس رضی اللہ عنہما نے بیان کیا کہ یمن کے لوگ راستہ کا خرچ ساتھ لائے بغیر حج کے لیے آ جاتے تھے۔ کہتے تو یہ تھے کہ ہم توکل کرتے ہیں لیکن جب مکہ آتے تو لوگوں سے مانگنے لگتے۔ اس پر اللہ تعالیٰ نے یہ آیت نازل فرمائی ”اور توشہ لے لیا کرو کہ سب سے بہتر توشہ تو تقویٰ ہی ہے۔“ اس کو ابن عیینہ نے عمرو سے بواسطہ عکرمہ مرسلاً نقل کیا ہے۔' WHERE id = 1472;
UPDATE hadiths SET urdu = 'ہم سے ابراہیم بن المنذر نے بیان کیا، انہوں نے کہا کہ ہم سے انس بن عیاض نے بیان کیا، ان سے عبیداللہ عمری نے بیان کیا، ان سے نافع نے بیان کیا اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم شجرہ کے راستے سے گزرتے ہوئے ”معرس“ کے راستے سے مدینہ آتے۔ نبی کریم صلی اللہ علیہ وسلم جب مکہ جاتے تو شجرہ کی مسجد میں نماز پڑھتے لیکن واپسی میں ذوالحلیفہ کے نشیب میں نماز پڑھتے۔ آپ صلی اللہ علیہ وسلم رات وہیں گزارتے تاآنکہ صبح ہو جاتی۔' WHERE id = 1482;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا کہ ہم سے عبدالوہاب نے بیان کیا، کہ ہم سے ایوب سختیانی نے بیان کیا، ان سے ابوقلابہ نے اور ان سے انس بن مالک نے کہ رسول اللہ صلی اللہ علیہ وسلم نے مدینہ میں ظہر چار رکعت پڑھی لیکن ذوالحلیفہ میں عصر دو رکعت۔ انہوں نے کہا کہ میرا خیال ہے کہ رات صبح تک آپ صلی اللہ علیہ وسلم نے ذوالحلیفہ میں ہی گزار دی۔' WHERE id = 1494;
UPDATE hadiths SET urdu = 'ہم سے مکی بن ابراہیم نے بیان کیا، ان سے ابن جریج نے، ان سے عطاء بن ابی رباح نے بیان کیا کہ کہ جابر رضی اللہ عنہ نے فرمایا کہ نبی کریم صلی اللہ علیہ وسلم نے علی رضی اللہ عنہ کو حکم دیا تھا کہ وہ اپنے احرام پر قائم رہیں۔ انہوں نے سراقہ کا قول بھی ذکر کیا تھا۔ اور محمد بن ابی بکر نے ابن جریج سے یوں روایت کیا کہ نبی کریم صلی اللہ علیہ وسلم نے دریافت فرمایا علی! تم نے کس چیز کا احرام باندھا ہے؟ انہوں نے عرض کی نبی کریم صلی اللہ علیہ وسلم نے جس کا احرام باندھا ہو ( اسی کا میں نے بھی باندھا ہے ) نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ پھر قربانی کر اور اپنی اسی حالت پر احرام جاری رکھ۔' WHERE id = 1504;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا، کہا کہ ہم سے شعبہ نے بیان کیا، کہا کہ ہم سے ابوجمرہ نصر بن عمران ضبعی نے بیان کیا، انہوں نے کہا کہ میں نے حج اور عمرہ کا ایک ساتھ احرام باندھا تو کچھ لوگوں نے مجھے منع کیا۔ اس لیے میں نے ابن عباس رضی اللہ عنہما سے اس کے متعلق دریافت کیا۔ آپ نے تمتع کرنے کے لیے کہا۔ پھر میں نے ایک شخص کو دیکھا کہ مجھ سے کہہ رہا ہے ”حج بھی مبرور ہوا اور عمرہ بھی قبول ہوا“ میں نے یہ خواب ابن عباس رضی اللہ عنہما کو سنایا، تو آپ نے فرمایا کہ یہ نبی کریم صلی اللہ علیہ وسلم کی سنت ہے۔ پھر آپ نے فرمایا کہ میرے یہاں قیام کر، میں اپنے پاس سے تمہارے لیے کچھ مقرر کر کے دیا کروں گا۔ شعبہ نے بیان کیا کہ میں نے ( ابوجمرہ سے ) پوچھا کہ ابن عباس رضی اللہ عنہما نے یہ کیوں کیا تھا؟ ( یعنی مال کس بات پر دینے کے لیے کہا ) انہوں نے بیان کیا کہ اسی خواب کی وجہ سے جو میں نے دیکھا تھا۔' WHERE id = 1514;
UPDATE hadiths SET urdu = 'ہم سے حمیدی اور محمد بن مثنیٰ نے بیان کیا، انہوں نے کہا کہ ہم سے سفیان بن عیینہ نے بیان کیا، ان سے ہشام بن عروہ نے، ان سے ان کے والد نے، ان سے عائشہ رضی اللہ عنہا نے کہ جب رسول اللہ صلی اللہ علیہ وسلم مکہ میں تشریف لائے تو اوپر کی بلند جانب سے شہر کے اندر داخل ہوئے اور ( مکہ سے ) واپس جب گئے تو نیچے کی طرف سے نکل گئے۔' WHERE id = 1524;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ بن جعفر نے بیان کیا، کہا کہ ہم سے جریر بن عبدالحمید نے منصور سے بیان کیا ان سے مجاہد نے، ان سے طاؤس نے اور ان سے ابن عباس رضی اللہ عنہما نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فتح مکہ پر فرمایا تھا کہ اللہ تعالیٰ نے اس شہر ( مکہ ) کو حرمت والا بنایا ہے ( یعنی عزت دی ہے ) پس اس کے ( درختوں کے ) کانٹے تک بھی نہیں کاٹے جا سکتے یہاں کے شکار بھی نہیں ہنکائے جا سکتے۔ اور ان کے علاوہ جو اعلان کر کے ( مالک تک پہنچانے کا ارادہ رکھتے ہوں ) کوئی شخص یہاں کی گری پڑی چیز بھی نہیں اٹھا سکتا ہے۔' WHERE id = 1534;
UPDATE hadiths SET urdu = 'ہم سے محمد بن کثیر نے بیان کیا، انہوں نے کہا کہ ہمیں سفیان ثوری نے خبر دی، انہیں اعمش نے، انہیں ابراہیم نے، انہیں عابس بن ربیعہ نے کہ عمر رضی اللہ عنہ حجر اسود کے پاس آئے اور اسے بوسہ دیا اور فرمایا ”میں خوب جانتا ہوں کہ تو صرف ایک پتھر ہے، نہ کسی کو نقصان پہنچا سکتا ہے نہ نفع۔ اگر رسول اللہ صلی اللہ علیہ وسلم کو تجھے بوسہ دیتے ہوئے میں نہ دیکھتا تو میں بھی کبھی تجھے بوسہ نہ دیتا۔“' WHERE id = 1544;
UPDATE hadiths SET urdu = 'ہم سے احمد بن صالح اور یحییٰ بن سلیمان نے بیان کیا، انہوں نے بیان کیا کہ ہم سے عبداللہ بن وہب نے بیان کیا، کہا کہ ہمیں یونس نے ابن شہاب سے خبر دی، انہیں عبیداللہ بن عبداللہ نے اور ان سے ابن عباس رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے حجتہ الوداع کے موقع پر اپنی اونٹنی پر طواف کیا تھا اور آپ صلی اللہ علیہ وسلم حجر اسود کا استلام ایک چھڑی کے ذریعہ کر رہے تھے اور اس چھڑی کو چومتے تھے۔ اور یونس کے ساتھ اس حدیث کو دراوردی نے زہری کے بھتیجے سے روایت کیا اور انہوں نے اپنے چچا ( زہری ) سے۔' WHERE id = 1554;
UPDATE hadiths SET urdu = 'ہم سے اسمٰعیل بن ابی اویس نے بیان کیا، انہوں نے کہا کہ ہم سے امام مالک رحمہ اللہ نے بیان کیا، ان سے محمد بن عبدالرحمٰن بن نوفل نے بیان کیا، ان سے عروہ بن زبیر نے بیان کیا، ان سے زینب بنت ابی سلمہ نے، ان سے نبی کریم صلی اللہ علیہ وسلم کی زوجہ مطہرہ ام سلمہ رضی اللہ عنہا نے بیان کیا، انہوں نے کہا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم سے اپنے بیمار ہونے کی شکایت کی ( کہ میں پیدل طواف نہیں کر سکتی ) تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ سواری پر چڑھ کر اور لوگوں سے علیحدہ رہ کر طواف کر لے۔ چنانچہ میں نے عام لوگوں سے الگ رہ کر طواف کیا۔ اس وقت رسول اللہ صلی اللہ علیہ وسلم کعبہ کے پہلو میں نماز پڑھ رہے تھے اور آپ صلی اللہ علیہ وسلم «والطور * وكتاب مسطور‏» قرآت کر رہے تھے۔' WHERE id = 1565;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن مسلمہ قعنبی نے بیان کیا انہوں نے کہا کہ ہم سے امام مالک رحمہ اللہ نے بیان کیا، ان سے محمد بن عبدالرحمٰن بن نوفل نے، ان سے عروہ نے بیان کیا، ان سے زینب بنت ام سلمہ نے، ان سے ام سلمہ رضی اللہ عنہا نے کہ میں نے رسول اللہ صلی اللہ علیہ وسلم سے شکایت کی کہ میں بیمار ہو گئی ہوں۔ آپ صلی اللہ علیہ وسلم نے فرمایا پھر لوگوں کے پیچھے سے سوار ہو کر طواف کر لے۔ چنانچہ میں نے جب طواف کیا تو اس وقت رسول اللہ صلی اللہ علیہ وسلم بیت اللہ کے پہلو میں ( نماز کے اندر ) «والطور وكتاب مسطور‏» کی قرآت کر رہے تھے۔' WHERE id = 1577;
UPDATE hadiths SET urdu = 'ہم نے محمد بن عبید نے بیان کیا، انہوں نے کہا کہ ہم سے عیسیٰ بن یونس نے بیان کیا، ان سے عبیداللہ بن عمر نے، ان سے نافع نے اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا کہ جب رسول اللہ صلی اللہ علیہ وسلم پہلا طواف کرتے تو اس کے تین چکروں میں رمل کرتے اور بقیہ چار میں معمول کے مطابق چلتے اور جب صفا اور مروہ کی سعی کرتے تو آپ نالے کے نشیب میں دوڑا کرتے تھے۔ عبیداللہ نے کہا میں نے نافع سے پوچھا، ابن عمر رضی اللہ عنہما جب رکن یمانی کے پاس پہنچتے تو کیا حسب معمول چلنے لگتے تھے؟ انہوں نے فرمایا کہ نہیں۔ البتہ اگر رکن یمانی پر ہجوم ہوتا تو حجر اسود کے پاس آ کر آپ آہستہ چلنے لگتے کیونکہ وہ بغیر چومے اس کو نہیں چھوڑتے تھے۔' WHERE id = 1587;
UPDATE hadiths SET urdu = 'ہم سے ابراہیم بن المنذر نے بیان کیا، کہا کہ ہم سے عبداللہ بن وہب نے بیان کیا، کہا کہ مجھے یونس نے ابن شہاب سے خبر دی، کہا کہ مجھے عبیداللہ بن عبداللہ بن عمر رضی اللہ عنہما نے اپنے باپ سے خبر دی کہ رسول اللہ صلی اللہ علیہ وسلم نے منیٰ میں دو رکعات پڑھیں اور ابوبکر اور عمر رضی اللہ عنہما بھی ایسا کرتے رہے اور عثمان رضی اللہ عنہ بھی خلافت کے شروع ایام میں ( دو ) ہی رکعت پڑھتے تھے۔' WHERE id = 1597;
UPDATE hadiths SET urdu = 'ہم سے فروہ بن ابی المغراء نے بیان کیا، انہوں نے کہا کہ ہم سے علی بن مسہر نے بیان کیا، ان سے ہشام بن عروہ نے، ان سے عروہ بن زبیر رضی اللہ عنہ نے کہا کہ حمس کے سوا بقیہ سب لوگ جاہلیت میں ننگے ہو کر طواف کرتے تھے، حمس قریش اور اس کی آل اولاد کو کہتے تھے، ( اور بنی کنانہ وغیرہ، جیسے خزاعہ ) لوگوں کو ( اللہ کے واسطے ) کپڑے دیا کرتے تھے۔ ( قریش ) کے مرد دوسرے مردوں کو تاکہ انہیں پہن کر طواف کر سکیں اور ( قریش کی ) عورتیں دوسری عورتوں کو تاکہ وہ انہیں پہن کر طواف کر سکیں، اور جن کو قریش کپڑا نہیں دیتے وہ بیت اللہ کا طواف ننگے ہو کر کرتے۔ دوسرے سب لوگ تو عرفات سے واپس ہوتے لیکن قریش مزدلفہ ہی سے ( جو حرم میں تھا ) واپس ہو جاتے۔ ہشام بن عروہ نے کہا کہ میرے باپ عروہ بن زبیر نے مجھے ام المؤمنین عائشہ رضی اللہ عنہا سے خبر دی کہ یہ آیت قریش کے بارے میں نازل ہوئی کہ ”پھر تم بھی ( قریش ) وہیں سے واپس آؤ جہاں سے اور لوگ واپس آتے ہیں“ ( یعنی عرفات سے، سورۃ البقرہ ) انہوں نے بیان کیا کہ قریش مزدلفہ ہی سے لوٹ آتے تھے اس لیے انہیں بھی عرفات سے لوٹنے کا حکم ہوا۔' WHERE id = 1607;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا، کہا کہ ہم سے حماد بن زید نے بیان کیا، ان سے ایوب سختیانی نے، ان سے عکرمہ نے اور ان سے عبداللہ بن عباس رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم نے مجھے مزدلفہ سے رات ہی میں منیٰ روانہ کر دیا تھا۔' WHERE id = 1618;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، کہا کہ ہم سے امام مالک نے خبر دی، انہیں ابوالزناد نے، انہیں اعرج اور انہیں ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے ایک شخص کو قربانی کا جانور لے جاتے دیکھا تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ اس پر سوار ہو جا۔ اس شخص نے کہا کہ یہ تو قربانی کا جانور ہے، آپ صلی اللہ علیہ وسلم نے فرمایا کہ اس پر سوار ہو جانا۔ اس نے کہا کہ یہ تو قربانی کا جانور ہے تو آپ صلی اللہ علیہ وسلم نے پھر فرمایا افسوس! سوار بھی ہو جاؤ ( «ويلك» آپ صلی اللہ علیہ وسلم نے ) دوسری یا تیسری مرتبہ فرمایا۔' WHERE id = 1629;
UPDATE hadiths SET urdu = 'ہم سے نعیم نے بیان کیا، ان سے اعمش نے بیان کیا، ان سے ابراہیم نے، ان سے اسود نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ ایک مرتبہ رسول اللہ صلی اللہ علیہ وسلم نے قربانی کے لیے ( بیت اللہ ) بکریاں بھیجی تھیں۔' WHERE id = 1640;
UPDATE hadiths SET urdu = 'ہم سے ابراہیم بن المنذر نے بیان کیا، کہا ہم سے انس بن عیاض نے بیان کیا، کہا ہم سے موسیٰ بن عقبہ نے بیان کیا، ان سے نافع نے کہ ابن عمر رضی اللہ عنہما اپنی قربانی کے جانوروں کو مزدلفہ سے آخر رات میں منیٰ بھجوا دیتے، یہ قربانیاں جن میں حاجی لوگ نیز غلام اور آزاد دونوں طرح کے لوگ ہوتے، اس مقام میں لے جاتے جہاں نبی کریم صلی اللہ علیہ وسلم نحر کیا کرتے تھے۔' WHERE id = 1650;
UPDATE hadiths SET urdu = 'ہم سے محمد بن عبداللہ بن حوشب نے بیان کیا، ان سے ہشیم بن بشیر نے بیان کیا، انہیں منصور بن ذاذان نے خبر دی، انہیں عطا بن ابی رباح نے اور ان سے ابن عباس رضی اللہ عنہما نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم سے اس شخص کے بارے میں پوچھا گیا جو قربانی کا جانور ذبح کرنے سے پہلے ہی سر منڈوا لے، تو آپ صلی اللہ علیہ وسلم نے فرمایا کوئی قباحت نہیں، کوئی قباحت نہیں۔ ( ترجمہ اور باب میں موافقت ظاہر ہے ) ۔' WHERE id = 1660;
UPDATE hadiths SET urdu = 'ہم سے محمد بن ابی بکر نے بیان کیا، ان سے فضیل بن سلیمان نے بیان کیا، ان سے موسیٰ بن عقبہ نے، انہیں کریب نے خبر دی، ان سے ابن عباس رضی اللہ عنہما نے کہا کہ جب نبی کریم صلی اللہ علیہ وسلم مکہ میں تشریف لائے تو آپ صلی اللہ علیہ وسلم نے اپنے اصحاب کو یہ حکم دیا کہ بیت اللہ کا طواف اور صفا و مروہ کی سعی کرنے کے بعد احرام کھول دیں پھر سر منڈوا لیں یا بال کتروا لیں۔' WHERE id = 1670;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد نے بیان کیا، کہا ہم سے ابوعامر نے بیان کیا، ان سے قرہ نے بیان کیا، ان سے محمد بن سیرین نے کہا کہ مجھے عبدالرحمٰن بن ابی بکرہ نے اور ایک اور شخص نے جو میرے نزدیک عبدالرحمٰن سے بھی افضل ہے یعنی حمید بن عبدالرحمٰن نے خبر دی کہ ابوبکر رضی اللہ عنہ نے بتلایا کہ نبی کریم صلی اللہ علیہ وسلم نے دسویں تاریخ کو منیٰ میں خطبہ سنایا، آپ صلی اللہ علیہ وسلم نے پوچھا لوگو! معلوم ہے آج یہ کون سا دن ہے؟ ہم نے عرض کی اللہ اور اس کا رسول زیادہ جانتے ہیں، آپ صلی اللہ علیہ وسلم اس پر خاموش ہو گئے اور ہم نے سمجھا کہ آپ صلی اللہ علیہ وسلم اس دن کا کوئی اور نام رکھیں گے لیکن آپ صلی اللہ علیہ وسلم نے فرمایا: کیا یہ قربانی کا دن نہیں۔ ہم بولے ہاں ضرور ہے، پھر آپ صلی اللہ علیہ وسلم نے پوچھا یہ مہینہ کون سا ہے؟ ہم نے کہا اللہ اور اس کے رسول زیادہ جانتے لیے۔ آپ اس مرتبہ بھی خاموش ہو گئے اور ہمیں خیال ہوا کہ آپ صلی اللہ علیہ وسلم اس مہینہ کا نام کوئی اور نام رکھیں گے، لیکن آپ نے فرمایا کیا یہ ذی الحجہ کا مہینہ نہیں ہے؟ ہم بولے کیوں نہیں، پھر آپ صلی اللہ علیہ وسلم نے پوچھا یہ شہر کون سا ہے؟ ہم نے عرض کی اللہ اور اس کے رسول بہتر جانتے ہیں، اس مرتبہ بھی آپ صلی اللہ علیہ وسلم اس طرح خاموش ہو گئے کہ ہم نے سمجھا کہ آپ صلی اللہ علیہ وسلم اس کا کوئی اور نام رکھیں گے، لیکن آپ صلی اللہ علیہ وسلم نے فرمایا کہ یہ حرمت کا شہر نہیں ہے؟ ہم نے عرض کی کیوں نہیں ضرور ہے، اس کے بعد آپ صلی اللہ علیہ وسلم نے ارشاد فرمایا بس تمہارا خون اور تمہارے مال تم پر اسی طرح حرام ہیں جیسے اس دن کی حرمت اس مہینہ اور اس شہر میں ہے، تاآنکہ تم اپنے رب سے جا ملو۔ کہو کیا میں نے تم کو اللہ کا پیغام پہنچا دیا؟ لوگوں نے کہا کہ ہاں۔ آپ صلی اللہ علیہ وسلم نے فرمایا اے اللہ! تو گواہ رہنا اور ہاں! یہاں موجود غائب کو پہنچا دیں کیونکہ بہت سے لوگ جن تک یہ پیغام پہنچے گا سننے والوں سے زیادہ ( پیغام کو ) یاد رکھنے والے ثابت ہوں گے اور میرے بعد کافر نہ بن جانا کہ ایک دوسرے کی ( ناحق ) گردنیں مارنے لگو۔' WHERE id = 1680;
UPDATE hadiths SET urdu = 'ہم سے عثمان بن ابی شیبہ نے بیان کیا، انہوں نے کہا کہ ہم سے طلحہ بن یحییٰ نے بیان کیا، ان سے یونس نے زہری سے بیان کیا، ان سے سالم نے کہ عبداللہ بن عمر رضی اللہ عنہما پہلے جمرہ کی رمی سات کنکریوں کے ساتھ کرتے اور ہر کنکری پر «الله اكبر» کہتے تھے، پھر آگے بڑھتے اور ایک نرم ہموار زمین پر پہنچ کر قبلہ رخ کھڑے ہو جاتے اسی طرح دیر تک کھڑے دونوں ہاتھ اٹھا کر دعا کرتے، پھر جمرہ وسطیٰ کی رمی کرتے، پھر بائیں طرف بڑھتے اور ایک ہموار زمین پر قبلہ رخ ہو کر کھڑے ہو جاتے، یہاں بھی دیر تک کھڑے کھڑے دونوں ہاتھ اٹھا کر دعائیں کرتے رہتے، اس کے بعد والے نشیب سے جمرہ عقبہ کی رمی کرتے اس کے بعد آپ کھڑے نہ ہوتے بلکہ واپس چلے آتے اور فرماتے کہ میں نے نبی کریم صلی اللہ علیہ وسلم کو اسی طرح کرتے دیکھا تھا۔' WHERE id = 1690;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم نے بیان کیا، کہا کہ ہم سے سفیان نے بیان کیا، ان سے ہشام بن عروہ نے، ان سے ان کے والد نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم منیٰ سے کوچ کر کے یہاں محصب میں اس لیے اترے تھے تاکہ آسانی کے ساتھ مدینہ کو نکل سکیں۔ آپ صلی اللہ علیہ وسلم کی مراد ابطح میں اترنے سے تھی۔' WHERE id = 1702;
UPDATE hadiths SET urdu = 'ہم سے ابوالولید ہشام بن عبدالملک نے بیان کیا، کہا کہ ہم سے ہمام نے بیان کیا، ان سے قتادہ نے بیان کیا کہ میں نے انس رضی اللہ عنہ سے نبی کریم صلی اللہ علیہ وسلم کے عمرہ کے متعلق پوچھا تو آپ نے فرمایا کہ نبی کریم صلی اللہ علیہ وسلم نے ایک عمرہ وہاں کیا جہاں سے آپ صلی اللہ علیہ وسلم کو مشرکین نے واپس کر دیا تھا اور دوسرے سال ( اسی ) عمرہ حدیبیہ ( کی قضاء ) کی تھی اور ایک عمرہ ذی قعدہ میں اور ایک اپنے حج کے ساتھ کیا تھا۔' WHERE id = 1714;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم نے بیان کیا، کہا کہ ہم سے ہمام نے بیان کیا، ان سے عطا بن ابی رباح نے بیان کیا، انہوں نے کہا کہ مجھ سے صفوان بن یعلیٰ بن امیہ نے بیان کیا، ان سے ان کے والد نے کہ نبی کریم صلی اللہ علیہ وسلم جعرانہ میں تھے، تو آپ صلی اللہ علیہ وسلم کی خدمت میں ایک شخص حاضر ہوا جبہ پہنے ہوئے اور اس پر خلوق یا زردی کا نشان تھا۔ اس نے پوچھا مجھے اپنے عمرہ میں آپ صلی اللہ علیہ وسلم کس طرح کرنے کا حکم دیتے ہیں؟ اس پر اللہ تعالیٰ نے نبی کریم صلی اللہ علیہ وسلم پر وحی نازل کی اور آپ صلی اللہ علیہ وسلم پر کپڑا ڈال دیا گیا، میری بڑی آرزو تھی کہ جب نبی کریم صلی اللہ علیہ وسلم پر وحی نازل ہو رہی ہو تو میں آپ صلی اللہ علیہ وسلم کو دیکھوں۔ عمر رضی اللہ عنہ نے فرمایا یہاں آؤ نبی کریم صلی اللہ علیہ وسلم پر جب وحی نازل ہو رہی ہو، اس وقت تم نبی کریم صلی اللہ علیہ وسلم کو دیکھنے کے آرزو مند ہو؟ میں نے کہا ہاں! انہوں نے کپڑے کا کنارہ اٹھایا اور میں نے اس میں سے آپ صلی اللہ علیہ وسلم کو دیکھا آپ زور زور سے خراٹے لے رہے تھے، میرا خیال ہے کہ انہوں نے بیان کیا ”جیسے اونٹ کے سانس کی آواز ہوتی ہے“ پھر جب وحی اترنی بند ہوئی تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ پوچھنے والا کہاں ہے جو عمرہ کے بارے میں پوچھتا تھا؟ اپنا جبہ اتار دے، خلوق کے اثر کو دھو ڈال اور ( زعفران کی ) زردی صاف کر لے اور جس طرح حج میں کرتے ہو اسی طرح اس میں بھی کرو۔' WHERE id = 1724;
UPDATE hadiths SET urdu = 'ہم سے سعید بن ابی مریم نے بیان کیا، کہا کہ ہم کو محمد بن جعفر نے خبر دی، کہا کہ مجھے حمید طویل نے خبر دی انہوں نے انس بن مالک رضی اللہ عنہ سے سنا کہ آپ رضی اللہ عنہ نے کہا کہ جب رسول اللہ صلی اللہ علیہ وسلم سفر سے مدینہ واپس ہوتے اور مدینہ کے بالائی علاقوں پر نظر پڑتی تو اپنی اونٹنی کو تیز کر دیتے، کوئی دوسرا جانور ہوتا تو اسے بھی ایڑ لگاتے۔ ابوعبداللہ ( امام بخاری رحمہ اللہ ) نے کہا کہ حارث بن عمیر نے حمید سے یہ لفظ زیادہ کئے ہیں کہ ”مدینہ سے محبت کی وجہ سے سواری تیز کر دیتے تھے۔“ ہم سے قتیبہ نے بیان کیا، کہا ہم سے اسماعیل بن جعفر نے بیان کیا، ان سے حمید طویل نے اور ان سے انس رضی اللہ عنہ نے، انہوں نے ( درجات کے بجائے ) «جدرات» کہا، اس کی متابعت حارث بن عمیر نے کی۔' WHERE id = 1735;
UPDATE hadiths SET urdu = 'ہم سے محمد بن عبدالرحیم نے بیان کیا، انہوں نے کہا کہ ہم کو ابوبدر شجاع بن ولید نے خبر دی، انہوں نے کہا کہ ہم سے معمر بن محمد عمری نے بیان کیا اور ان سے نافع نے بیان کیا کہ عبداللہ اور سالم نے عبداللہ بن عمر رضی اللہ عنہما سے گفتگو کی، ( کہ وہ اس سال مکہ نہ جائیں ) تو انہوں نے فرمایا کہ ہم رسول اللہ صلی اللہ علیہ وسلم کے ساتھ عمرہ کا احرام باندھ کر گئے تھے اور کفار قریش نے ہمیں بیت اللہ سے روک دیا تھا تو رسول اللہ صلی اللہ علیہ وسلم نے اپنی قربانی کو نحر کیا اور سر منڈایا۔' WHERE id = 1745;
UPDATE hadiths SET urdu = 'ہم سے سعید بن ربیع نے بیان کیا، کہا ہم سے علی بن مبارک نے بیان کیا، ان سے یحییٰ بن ابی کثیر نے، ان سے عبداللہ بن ابی قتادہ نے، کہا ان سے ان کے باپ نے بیان کیا انہوں نے کہا کہ ہم صلح حدیبیہ کے موقع پر نبی کریم صلی اللہ علیہ وسلم کے ساتھ چلے ان کے ساتھیوں نے تو احرام باندھ لیا تھا لیکن ان کا بیان تھا کہ میں نے احرام نہیں باندھا تھا۔ ہمیں غیقہ میں دشمن کے موجود ہونے کی اطلاع ملی اس لیے ہم ان کی تلاش میں ( نبی کریم صلی اللہ علیہ وسلم کے حکم کے مطابق ) نکلے پھر میرے ساتھیوں نے گورخر دیکھا اور ایک دوسرے کو دیکھ کر ہنسنے لگے میں نے جو نظر اٹھائی تو اسے دیکھ لیا گھوڑے پر ( سوار ہو کر ) اس پر جھپٹا اور اسے زخمی کر کے ٹھنڈا کر دیا۔ میں نے اپنے ساتھیوں سے کچھ امداد چاہی لیکن انہوں نے انکار کر دیا پھر ہم سب نے اسے کھایا اور اس کے بعد میں رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوا ( پہلے ) ہمیں ڈر ہوا کہ کہیں ہم نبی کریم صلی اللہ علیہ وسلم سے دور نہ رہ جائیں اس لیے میں کبھی اپنا گھوڑا تیز کر دیتا اور کبھی آہستہ آخر میری ملاقات ایک بنی غفار کے آدمی سے آدھی رات میں ہوئی میں نے پوچھا کہ رسول اللہ صلی اللہ علیہ وسلم کہاں ہیں؟ انہوں نے بتایا کہ میں آپ صلی اللہ علیہ وسلم سے تعہن نامی جگہ میں الگ ہوا تھا اور آپ صلی اللہ علیہ وسلم کا ارادہ یہ تھا کہ دوپہر کو مقام سقیا میں آرام کریں گے پھر جب میں رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوا تو میں نے عرض کی یا رسول اللہ! آپ کے اصحاب نے آپ کو سلام کہا ہے اور انہیں ڈر ہے کہ کہیں دشمن آپ کے اور ان کے درمیان حائل نہ ہو جائے اس لیے آپ ان کا انتظار کیجئے چنانچہ آپ نے ایسا ہی کیا، میں نے یہ بھی عرض کی کہ یا رسول اللہ! میں نے ایک گورخر کا شکار کیا اور کچھ بچا ہوا گوشت اب بھی موجود ہے اس پر آپ صلی اللہ علیہ وسلم نے اپنے اصحاب سے فرمایا کے کھاؤ حالانکہ وہ سب احرام باندھے ہوئے تھے۔' WHERE id = 1755;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا ہم سے لیث بن سعد نے بیان کیا، ان سے سعید بن ابی سعید مقبری نے، ان سے ابوشریح عدوی رضی اللہ عنہ نے کہ جب عمرو بن سعید مکہ پر لشکر کشی کر رہا تھا تو انہوں نے کہا امیر اجازت دے تو میں ایک ایسی حدیث سناؤں جو رسول اللہ صلی اللہ علیہ وسلم نے فتح مکہ کے دوسرے دن ارشاد فرمائی تھی، اس حدیث مبارک کو میرے ان کانوں نے سنا، اور میرے دل نے پوری طرح اسے یاد کر لیا تھا اور جب آپ ارشاد فرما رہے تھے تو میری آنکھیں آپ کو دیکھ رہی تھیں۔ آپ صلی اللہ علیہ وسلم نے اللہ کی حمد اور اس کی ثنا بیان کی، پھر فرمایا کہ مکہ کی حرمت اللہ نے قائم کی ہے لوگوں نے نہیں! اس لیے کسی ایسے شخص کے لیے جو اللہ اور یوم آخرت پر ایمان رکھتا ہو یہ جائز اور حلال نہیں کہ یہاں خون بہائے اور کوئی یہاں کا ایک درخت بھی نہ کاٹے لیکن اگر کوئی شخص رسول اللہ صلی اللہ علیہ وسلم کے قتال ( فتح مکہ کے موقع پر ) سے اس کا جواز نکالے تو اس سے یہ کہہ دو کہ رسول اللہ صلی اللہ علیہ وسلم کو اللہ نے اجازت دی تھی، لیکن تمہیں اجازت نہیں ہے اور مجھے بھی تھوڑی سی دیر کے لیے اجازت ملی تھی پھر دوبارہ آج اس کی حرمت ایسی ہی قائم ہو گئی جیسے پہلے تھی اور ہاں جو موجود ہیں وہ غائب کو ( اللہ کا یہ پیغام ) پہنچا دیں، ابوشریح سے کسی نے پوچھا کہ پھر عمرو بن سعید نے ( یہ حدیث سن کر ) آپ کو کیا جواب دیا تھا؟ انہوں نے بتایا کہ عمرو نے کہا ابوشریح! میں یہ حدیث تم سے بھی زیادہ جانتا ہوں مگر حرم کسی مجرم کو پناہ نہیں دیتا اور نہ خون کر کے اور نہ کسی جرم کر کے بھاگنے والے کو پناہ دیتا ہے۔ «خربة» سے مراد «خربة بلية‏» ہے۔' WHERE id = 1765;
UPDATE hadiths SET urdu = 'ہم سے احمد بن یونس نے بیان کیا، انہوں نے کہا کہ ہم سے ابراہیم بن سعد نے بیان کیا، انہوں نے کہا کہ ہم سے ابن شہاب نے بیان کیا، ان سے سالم نے اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم سے پوچھا گیا کہ محرم کون سے کپڑے پہن سکتا ہے؟ آپ صلی اللہ علیہ وسلم نے فرمایا کہ قمیص، عمامہ، پاجامہ اور برنس ( کن ٹوپ یا باران کوٹ ) نہ پہنے اور نہ کوئی ایسا کپڑا پہنے جس میں زعفران یا ورس لگی ہو اور اگر جوتیاں نہ ہوں تو موزے پہن لے، البتہ اس طرح کاٹ لے کہ ٹخنوں سے نیچے ہو جائیں۔' WHERE id = 1775;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، کہا ہم سے ابوعوانہ وضاح شکری نے بیان کیا، ان سے ابوبشر جعفر بن ایاس نے، ان سے سعید بن جبیر نے اور ان سے ابن عباس رضی اللہ عنہما نے کہ قبیلہ جہینہ کی ایک عورت نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئی اور کہا کہ میری والدہ نے حج کی منت مانی تھی لیکن وہ حج نہ کر سکیں اور ان کا انتقال ہو گیا تو کیا میں ان کی طرف سے حج کر سکتی ہوں؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ ہاں ان کی طرف سے تو حج کر۔ کیا تمہاری ماں پر قرض ہوتا تو تم اسے ادا نہ کرتیں؟ اللہ تعالیٰ کا قرضہ تو اس کا سب سے زیادہ مستحق ہے کہ اسے پورا کیا جائے۔ پس اللہ تعالیٰ کا قرض ادا کرنا بہت ضروری ہے۔' WHERE id = 1785;
UPDATE hadiths SET urdu = 'ہم سے ابوالنعمان نے بیان کیا، کہا ہم سے حماد بن زید نے بیان کیا، ان سے عمرو بن دینار نے بیان کیا، ان سے ابن عباس رضی اللہ عنہما کے غلام ابومعبد نے اور ان سے ابن عباس رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ کوئی عورت اپنے محرم رشتہ دار کے بغیر سفر نہ کرے اور کوئی شخص کسی عورت کے پاس اس وقت تک نہ جائے جب تک وہاں ذی محرم موجود نہ ہو۔ ایک شخص نے پوچھا کہ یا رسول اللہ! میں فلاں لشکر میں جہاد کے لیے نکلنا چاہتا ہوں، لیکن میری بیوی کا ارادہ حج کا ہے؟ تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ تو اپنی بیوی کے ساتھ حج کو جا۔' WHERE id = 1795;
UPDATE hadiths SET urdu = 'ہم سے خالد بن مخلد نے بیان کیا، کہا کہ ہم سے سلیمان بن بلال نے بیان کیا، کہا کہ مجھ سے عمرو بن یحییٰ نے بیان کیا، ان سے عباس بن سہل بن سعد نے اور ان سے ابو حمید ساعدی رضی اللہ عنہ نے یہ بیان کیا کہ ہم غزوہ تبوک سے نبی کریم صلی اللہ علیہ وسلم کے ساتھ واپس ہوتے ہوئے جب مدینہ کے قریب پہنچے تو آپ نے فرمایا کہ یہ طابہ آ گیا۔' WHERE id = 1805;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، انہوں نے کہا کہ ہم سے لیث بن سعد نے بیان کیا، ان سے عقیل نے، ان سے ابن شہاب نے، انہوں نے بیان کیا کہ مجھے عبیداللہ بن عتبہ نے خبر دی کہ ابو سعید خدری رضی اللہ عنہ نے بیان کیا کہ ہم سے رسول اللہ صلی اللہ علیہ وسلم نے دجال کے متعلق ایک لمبی حدیث بیان کی، آپ صلی اللہ علیہ وسلم نے اپنی حدیث میں یہ بھی فرمایا تھا کہ دجال مدینہ کی ایک کھاری شور زمین تک پہنچے گا اس پر مدینہ میں داخلہ تو حرام ہو گا۔ ( مدینہ سے ) اس دن ایک شخص اس کی طرف نکل کر بڑھے گا، یہ لوگوں میں ایک بہترین نیک مرد ہو گا یا ( یہ فرمایا کہ ) بزرگ ترین لوگوں میں سے ہو گا وہ شخص کہے گا کہ میں گواہی دیتا ہوں کہ تو وہی دجال ہے جس کے متعلق ہمیں رسول اللہ صلی اللہ علیہ وسلم نے اطلاع دی تھی دجال کہے گا کیا میں اسے قتل کر کے پھر زندہ کر ڈالوں تو تم لوگوں کو میرے معاملہ میں کوئی شبہ رہ جائے گا؟ اس کے حواری کہیں گے نہیں، چنانچہ دجال انہیں قتل کر کے پھر زندہ کر دے گا۔ جب دجال انہیں زندہ کر دے گا تو وہ بندہ کہے گا بخدا اب تو مجھ کو پورا حال معلوم ہو گیا کہ تو ہی دجال ہے دجال کہے گا لاؤ اسے پھر قتل کر دوں لیکن اس مرتبہ وہ قابو نہ پا سکے گا۔' WHERE id = 1815;
UPDATE hadiths SET urdu = 'ہم سے مسدد بن مسرہد نے بیان کیا، کہا ہم سے اسماعیل بن علیہ نے بیان کیا ان سے ایوب نے، ان سے نافع نے اور ان سے ابن عمر رضی اللہ عنہما نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے یوم عاشورہ کا روزہ رکھا تھا اور آپ صلی اللہ علیہ وسلم نے اس کے رکھنے کا صحابہ رضی اللہ عنہم کو ابتداء اسلام میں حکم دیا تھا، جب ماہ رمضان کے روزے فرض ہو گئے تو عاشورہ کا روزہ بطور فرض چھوڑ دیا گیا، عبداللہ بن عمر رضی اللہ عنہما عاشورہ کے دن روزہ نہ رکھتے مگر جب ان کے روزے کا دن ہی یوم عاشورہ آن پڑتا۔' WHERE id = 1825;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، انہوں نے کہا ہم سے ابراہیم بن سعد نے بیان کیا، انہیں ابن شہاب نے خبر دی، انہیں عبیداللہ بن عبداللہ بن عتبہ نے کہ عبداللہ بن عباس رضی اللہ عنہما نے کہا نبی کریم صلی اللہ علیہ وسلم سخاوت اور خیر کے معاملہ میں سب سے زیادہ سخی تھے اور آپ صلی اللہ علیہ وسلم کی سخاوت اس وقت اور زیادہ بڑھ جاتی تھی جب جبرائیل علیہ السلام آپ صلی اللہ علیہ وسلم سے رمضان میں ملتے، جبرائیل علیہ السلام نبی کریم صلی اللہ علیہ وسلم سے رمضان شریف کی ہر رات میں ملتے یہاں تک کہ رمضان گزر جاتا۔ نبی کریم صلی اللہ علیہ وسلم جبرائیل علیہ السلام سے قرآن کا دور کرتے تھے، جب جبرائیل علیہ السلام آپ صلی اللہ علیہ وسلم سے ملنے لگتے تو آپ صلی اللہ علیہ وسلم چلتی ہوا سے بھی زیادہ بھلائی پہنچانے میں سخی ہو جایا کرتے تھے۔' WHERE id = 1835;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے معتمر بن سلیمان نے بیان کیا، کہا کہ میں نے اسحاق سے سنا، انہوں نے عبدالرحمٰن بن ابی بکرہ رضی اللہ عنہ سے، انہوں نے اپنے والد سے، انہوں نے نبی کریم صلی اللہ علیہ وسلم سے (دوسری سند) امام بخاری رحمہ اللہ نے کہا اور مجھے مسدد نے خبر دی، ان سے معتمر نے بیان کیا، ان سے خالد حذاء نے بیان کیا کہ مجھے عبدالرحمٰن بن ابی بکرہ رضی اللہ عنہ نے خبر دی اور انہیں ان کے والد نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا دونوں مہینے ناقص نہیں رہتے۔ مراد رمضان اور ذی الحجہ کے دونوں مہینے ہیں۔' WHERE id = 1845;
UPDATE hadiths SET urdu = 'ہم سے ابوعاصم نے بیان کیا، کہا کہ ہم سے یزید بن ابی عبید نے بیان کیا، ان سے سلمہ بن اکوع نے کہ نبی کریم صلی اللہ علیہ وسلم نے عاشورہ کے دن ایک شخص کو یہ اعلان کرنے کے لیے بھیجا کہ جس نے کھانا کھا لیا وہ اب ( دن ڈوبنے تک روزہ کی حالت میں ) پورا کرے یا ( یہ فرمایا کہ ) روزہ رکھے اور جس نے نہ کھایا ہو ( تو وہ روزہ رکھے ) کھانا نہ کھائے۔' WHERE id = 1856;
UPDATE hadiths SET urdu = 'ہم سے معلی بن اسد نے بیان کیا، ان سے وہیب نے، وہ ایوب سے، وہ عکرمہ سے، وہ ابن عباس رضی اللہ عنہما سے روایت کرتے ہیں کہ نبی کریم صلی اللہ علیہ وسلم نے احرام میں اور روزے کی حالت میں پچھنا لگوایا۔' WHERE id = 1868;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، انہوں نے کہا ہم سے ابوعوانہ نے، ان سے منصور نے، ان سے مجاہد نے، ان سے طاؤس نے اور ان سے عبداللہ بن عباس رضی اللہ عنہما نے کہ رسول اللہ صلی اللہ علیہ وسلم نے ( غزوہ فتح میں ) مدینہ سے مکہ کے لیے سفر شروع کیا تو آپ صلی اللہ علیہ وسلم روزہ سے تھے، جب آپ عسفان پہنچے تو پانی منگوایا اور اسے اپنے ہاتھ سے ( منہ تک ) اٹھایا تاکہ لوگ دیکھ لیں پھر آپ صلی اللہ علیہ وسلم نے روزہ چھوڑ دیا یہاں تک کہ مکہ پہنچے۔ ابن عباس رضی اللہ عنہما کہا کرتے تھے کہ رسول اللہ صلی اللہ علیہ وسلم نے ( سفر میں ) روزہ رکھا بھی اور نہیں بھی رکھا اس لیے جس کا جی چاہے روزہ رکھے اور جس کا جی چاہے نہ رکھے۔' WHERE id = 1878;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، ان سے بشر بن مفضل نے بیان کیا، ان سے خالد بن ذکوان نے بیان کیا، ان سے ربیع بنت معوذ رضی اللہ عنہا نے کہا کہ عاشورہ کی صبح نبی کریم صلی اللہ علیہ وسلم نے انصار کے محلوں میں کہلا بھیجا کہ صبح جس نے کھا پی لیا ہو وہ دن کا باقی حصہ ( روزہ دار کی طرح ) پورے کرے اور جس نے کچھ کھایا پیا نہ ہو وہ روزے سے رہے۔ ربیع نے کہا کہ پھر بعد میں بھی ( رمضان کے روزے کی فرضیت کے بعد ) ہم اس دن روزہ رکھتے اور اپنے بچوں سے بھی رکھواتے تھے۔ انہیں ہم اون کا ایک کھلونا دے کر بہلائے رکھتے۔ جب کوئی کھانے کے لیے روتا تو وہی دے دیتے، یہاں تک کہ افطار کا وقت آ جاتا۔' WHERE id = 1890;
UPDATE hadiths SET urdu = 'ہم سے معاذ بن فضالہ نے بیان کیا، ان سے ہشام نے بیان کیا، ان سے یحییٰ نے، ان سے ابوسلمہ نے اور ان سے عائشہ رضی اللہ عنہا نے کہا کہ رسول اللہ صلی اللہ علیہ وسلم شعبان سے زیادہ اور کسی مہینہ میں روزے نہیں رکھتے تھے، شعبان کے پورے دنوں میں آپ صلی اللہ علیہ وسلم روزہ سے رہتے۔ آپ صلی اللہ علیہ وسلم فرمایا کرتے تھے کہ عمل وہی اختیار کرو جس کی تم میں طاقت ہو کیونکہ اللہ تعالیٰ ( ثواب دینے سے ) نہیں تھکتا۔ تم خود ہی اکتا جاؤ گے۔ نبی کریم صلی اللہ علیہ وسلم اس نماز کو سب سے زیادہ پسند فرماتے جس پر ہمیشگی اختیار کی جائے خواہ کم ہی کیوں نہ ہو۔ چنانچہ نبی کریم صلی اللہ علیہ وسلم جب کوئی نماز شروع کرتے تو اسے ہمیشہ پڑھتے تھے۔' WHERE id = 1900;
UPDATE hadiths SET urdu = 'ہم سے اسحٰق واسطی نے بیان کیا، کہا ہم سے خالد نے بیان کیا، ان سے خالد حذاء نے اور ان سے ابوقلابہ نے کہ مجھے ابوملیح نے خبر دی، کہا کہ میں آپ کے والد کے ساتھ عبداللہ بن عمرو رضی اللہ عنہما کی خدمت میں حاضر ہوا۔ انہوں نے ہم سے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم کو میرے روزے کے متعلق خبر ہو گئی۔ ( کہ میں مسلسل روزے رکھتا ہوں ) آپ صلی اللہ علیہ وسلم میرے یہاں تشریف لائے اور میں نے ایک گدہ آپ صلی اللہ علیہ وسلم کے لیے بچھا دیا۔ جس میں کھجور کی چھال بھری ہوئی تھی لیکن نبی کریم صلی اللہ علیہ وسلم زمین پر بیٹھ گئے۔ اور تکیہ میرے اور آپ صلی اللہ علیہ وسلم کے درمیان ہو گیا۔ آپ صلی اللہ علیہ وسلم نے فرمایا، کیا تمہارے لیے ہر مہینہ میں تین دن کے روزے کافی نہیں ہیں۔ انہوں نے کہا کہ میں نے عرض کی، یا رسول اللہ! ( کچھ اور بڑھا دیجئیے ) آپ نے فرمایا، اچھا پانچ دن کے روزے ( رکھ لے ) میں نے عرض کی، یا رسول اللہ کچھ اور آپ صلی اللہ علیہ وسلم نے فرمایا چلو چھ دن، میں نے عرض کی یا رسول اللہ! ( کچھ اور بڑھائیے، مجھ میں اس سے بھی زیادہ کی طاقت ہے ) آپ صلی اللہ علیہ وسلم نے فرمایا! اچھا نو دن، میں نے عرض کی، یا رسول اللہ! کچھ اور فرمایا، اچھا گیارہ دن۔ آخر آپ نے فرمایا کہ داؤد علیہ السلام کے روزے کے طریقے کے سوا اور کوئی طریقہ ( شریعت میں ) جائز نہیں۔ یعنی زندگی کے آدھے دنوں میں ایک دن کا روزہ رکھ اور ایک دن کا روزہ چھوڑ دیا کر۔' WHERE id = 1910;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، انہوں نے کہا کہ ہم کو امام مالک رحمہ اللہ نے خبر دی، انہیں ابن شہاب نے، انہوں نے کہا کہ ہم سے ابن ازہر کے غلام ابوعبید نے بیان کیا کہ عید کے دن میں عمر بن خطاب رضی اللہ عنہ کے خدمت میں حاضر تھا۔ آپ صلی اللہ علیہ وسلم نے فرمایا یہ دو دن ایسے ہیں جن کے روزوں کی نبی کریم صلی اللہ علیہ وسلم نے ممانعت فرمائی ہے۔ ( رمضان کے ) روزوں کے بعد افطار کا دن ( عیدالفطر ) اور دوسرا وہ دن جس میں تم اپنی قربانی کا گوشت کھاتے ہو ( یعنی عید الاضحی کا دن ) ۔ امام بخاری رحمہ اللہ نے کہا سفیان بن عیینہ نے کہا، جس نے ابوعبداللہ کو ابن ازہر کا غلام کہا اس نے بھی ٹھیک کہا، اور جس نے عبدالرحمٰن بن عوف رضی اللہ عنہ کا غلام کہا اس نے بھی ٹھیک کہا۔ ( اس کی وجہ یہ ہے کہ ابن ازہر اور عبدالرحمٰن بن عوف رضی اللہ عنہ دونوں اس غلام میں شریک تھے ) ۔' WHERE id = 1920;
UPDATE hadiths SET urdu = 'ہم سے ابومعمر نے بیان کیا، کہا کہ ہم سے عبدالوارث نے بیان کیا، کہا کہ ہم سے ایوب نے بیان کیا، کہا کہ ہم سے عبداللہ بن سعید بن جبیر نے بیان کیا، ان سے ان کے باپ نے اور ان سے ابن عباس رضی اللہ عنہما نے فرمایا کہ نبی کریم صلی اللہ علیہ وسلم مدینہ میں تشریف لائے۔ ( دوسرے سال ) آپ صلی اللہ علیہ وسلم نے یہودیوں کو دیکھا کہ وہ عاشوراء کے دن روزہ رکھتے ہیں۔ آپ صلی اللہ علیہ وسلم نے ان سے اس کا سبب معلوم فرمایا تو انہوں نے بتایا کہ یہ ایک اچھا دن ہے۔ اسی دن اللہ تعالیٰ نے بنی اسرائیل کو ان کے دشمن ( فرعون ) سے نجات دلائی تھی۔ اس لیے موسیٰ علیہ السلام نے اس دن کا روزہ رکھا تھا۔ آپ نے فرمایا پھر موسیٰ علیہ السلام کے ( شریک مسرت ہونے میں ) ہم تم سے زیادہ مستحق ہیں۔ چنانچہ آپ صلی اللہ علیہ وسلم نے اس دن روزہ رکھا اور صحابہ رضی اللہ عنہم کو بھی اس کا حکم دیا۔' WHERE id = 1932;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ مدینی نے بیان کیا، کہا کہ ہم سے سفیان بن عیینہ نے بیان کیا، انہوں نے کہا کہ ہم نے اس روایت کو یاد کیا تھا اور یہ روایت انہوں نے زہری سے (سن کر) یاد کی تھی۔ ان سے ابوسلمہ نے بیان کیا اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا جو شخص رمضان کے روزے ایمان اور احتساب ( حصول اجر و ثواب کی نیت ) کے ساتھ رکھے، اس کے اگلے تمام گناہ معاف کر دئیے جاتے ہیں۔ اور جو لیلۃ القدر میں ایمان و احتساب کے ساتھ نماز میں کھڑا رہے اس کے بھی اگلے تمام گناہ معاف کر دیئے جاتے ہیں، سفیان کے ساتھ سلیمان بن کثیر نے بھی اس حدیث کو زہری سے روایت کیا۔' WHERE id = 1942;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ مدینی نے بیان کیا، کہا کہ ہم سے سفیان بن عیینہ نے بیان کیا، ان سے ابویعفور نے بیان کیا، ان سے ابوالضحیٰ نے، ان سے مسروق نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ جب ( رمضان کا ) آخری عشرہ آتا تو نبی کریم صلی اللہ علیہ وسلم اپنا تہبند مضبوط باندھتے ( یعنی اپنی کمر پوری طرح کس لیتے ) اور ان راتوں میں آپ خود بھی جاگتے اور اپنے گھر والوں کو بھی جگایا کرتے تھے۔' WHERE id = 1952;
UPDATE hadiths SET urdu = 'مجھ سے عبداللہ بن منیر نے بیان کیا، انہوں نے ہارون بن اسماعیل سے سنا، انہوں نے کہا کہ ہم سے علی بن مبارک نے بیان کیا کہا کہ مجھ سے یحییٰ بن ابی کثیر نے بیان کیا، انہوں نے کہا کہ میں نے ابوسلمہ بن عبدالرحمٰن سے سنا، انہوں نے کہا میں نے ابو سعید خدری رضی اللہ عنہ سے سنا، میں نے ان سے پوچھا تھا کہ کیا آپ نے رسول اللہ صلی اللہ علیہ وسلم سے شب قدر کا ذکر سنا ہے؟ انہوں نے کہا کہ ہاں! ہم نے رسول اللہ صلی اللہ علیہ وسلم کے ساتھ رمضان کے دوسرے عشرے میں اعتکاف کیا تھا، ابوسعید رضی اللہ عنہ نے بیان کیا کہ پھر بیس کی صبح کو ہم نے اعتکاف ختم کر دیا۔ اسی صبح کو رسول اللہ صلی اللہ علیہ وسلم نے ہمیں خطاب فرمایا کہ مجھے شب قدر دکھائی گئی تھی، لیکن پھر بھلا دی گئی، اس لیے اب اسے آخری عشرے کی طاق راتوں میں تلاش کرو۔ میں نے ( خواب میں ) دیکھا ہے کہ میں کیچڑ، پانی میں سجدہ کر رہا ہوں اور جن لوگوں نے رسول اللہ صلی اللہ علیہ وسلم کے ساتھ ( اس سال ) اعتکاف کیا تھا وہ پھر دوبارہ کریں۔ چنانچہ وہ لوگ مسجد میں دوبارہ آ گئے۔ آسمان میں کہیں بادل کا ایک ٹکڑا بھی نہیں تھا کہ اچانک بادل آیا اور بارش شروع ہو گئی۔ پھر نماز کی تکبیر ہوئی اور رسول اللہ صلی اللہ علیہ وسلم نے کیچڑ میں سجدہ کیا۔ میں نے خود آپ کی ناک اور پیشانی پر کیچڑ لگا ہوا دیکھا۔' WHERE id = 1963;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد مسندی نے بیان کیا، ان سے ہشام نے بیان کیا، انہیں معمر نے خبر دی، انہیں زہری نے، انہیں عروہ نے اور انہیں عائشہ رضی اللہ عنہا نے کہ وہ حائضہ ہوتی تھیں اور رسول اللہ صلی اللہ علیہ وسلم مسجد میں اعتکاف میں ہوتے تھے، پھر بھی وہ آپ کے سر میں اپنے حجرہ ہی میں کنگھا کرتی تھیں۔ آپ اپنا سر مبارک ان کی طرف بڑھا دیتے۔' WHERE id = 1973;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم فضل بن دکین نے بیان کیا، کہا کہ ہم سے سفیان بن عیینہ نے بیان کیا، ان سے زہری نے، ان سے عباد بن تمیم نے اور ان سے ان کے چچا عبداللہ بن زید مازنی رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم کے سامنے ایک ایسے شخص کا ذکر آیا جسے نماز میں کچھ شبہ ہوا نکلنے کا ہو جاتا ہے۔ آیا اسے نماز توڑ دینی چاہئے؟ فرمایا کہ نہیں۔ جب تک وہ آواز نہ سن لے یا بدبو نہ محسوس کر لے ( اس وقت تک نماز نہ توڑے ) ابن ابی حفصہ نے زہری سے بیان کیا ( ایسے شخص پر ) وضو واجب نہیں جب تک حدث کی بدبو نہ محسوس کرے یا آواز نہ سن لے۔' WHERE id = 1983;
UPDATE hadiths SET urdu = 'ہم سے معلی بن اسد نے بیان کیا، انہوں نے کہا کہ ہم سے عبدالواحد نے بیان کیا، کہا کہ ہم سے اعمش نے بیان کیا کہ ابراہیم نخعی کی مجلس میں ہم نے ادھار لین دین میں ( سامان ) گروی رکھنے کا ذکر کیا تو انہوں نے کہا کہ مجھ سے اسود نے عائشہ رضی اللہ عنہا سے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے ایک یہودی سے کچھ غلہ ایک مدت مقرر کر کے ادھا خریدا اور اپنی لوہے کی ایک زرہ اس کے پاس گروی رکھی۔' WHERE id = 1994;
UPDATE hadiths SET urdu = 'ہم سے ہشام بن عمار نے بیان کیا، کہا کہ ہم سے یحییٰ بن حمزہ نے بیان کیا، ان سے محمد بن ولید زبیدی نے بیان کیا، ان سے زہری نے، ان سے عبیداللہ بن عبداللہ نے، انہوں نے ابوہریرہ رضی اللہ عنہ سے سنا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا، ایک تاجر لوگوں کو قرض دیا کرتا تھا جب کسی تنگ دست کو دیکھتا تو اپنے نوکروں سے کہہ دیتا کہ اس سے درگزر کر جاؤ۔ شاید کہ اللہ تعالیٰ بھی ہم سے ( آخرت میں ) درگزر فرمائے۔ چنانچہ اللہ تعالیٰ نے ( اس کے مرنے کے بعد ) اس کو بخش دیا۔' WHERE id = 2004;
UPDATE hadiths SET urdu = 'ہم سے عمرو بن محمد نے بیان کیا، کہا کہ ہم سے ہشیم نے بیان کیا، کہا کہ ہم کو عوام بن حوشب نے خبر دی، انہیں ابراہیم بن عبدالرحمٰن نے اور انہیں عبداللہ بن ابی اوفی رضی اللہ عنہ نے کہ بازار میں ایک شخص نے ایک سامان دکھا کر قسم کھائی کہ اس کی اتنی قیمت لگ چکی ہے۔ حالانکہ اس کی اتنی قیمت نہیں لگی تھی اس قسم سے اس کا مقصد ایک مسلمان کو دھوکہ دینا تھا۔ اس پر یہ آیت اتری «إن الذين يشترون بعهد الله وأيمانهم ثمنا قليلا» ”جو لوگ اللہ کے عہد اور اپنی قسموں کو تھوڑی قیمت کے بدلہ میں بیچتے ہیں۔“' WHERE id = 2014;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ نے بیان کیا، انہوں نے کہا کہ ہم سے سفیان بن عیینہ نے بیان کیا، ان سے عمرو بن دینار نے اور ان سے ابن عباس رضی اللہ عنہما نے کہ عکاظ، مجنہ اور ذوالمجاز یہ سب زمانہ جاہلیت کے بازار تھے۔ جب اسلام آیا تو لوگوں نے ان میں تجارت کو گناہ سمجھا۔ اس پر اللہ تعالیٰ نے یہ آیت نازل کی «ليس عليكم جناح‏** في مواسم الحج»،‏‏‏‏ ابن عباس رضی اللہ عنہما نے اسی طرح قرآت کی ہے۔' WHERE id = 2024;
UPDATE hadiths SET urdu = 'ہم سے حفص بن عمر نے بیان کیا، کہا کہ ہم سے ہمام نے بیان کیا، ان سے قتادہ نے، ان سے ابوالخلیل نے، ان سے عبداللہ بن حارث نے اور ان سے حکیم بن حزام رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا، بیچنے اور خریدنے والوں کو جب تک وہ جدا نہ ہوں ( معاملہ کو باقی رکھنے یا توڑ دینے کا ) اختیار ہوتا ہے۔ احمد نے یہ زیادتی کی کہ ہم سے بہز نے بیان کیا کہ ہمام نے بیان کیا کہ میں نے اس کا ذکر ابوالتیاح کے سامنے کیا تو انہوں نے بتلایا کہ جب عبداللہ بن حارث نے یہ حدیث بیان کی تھی، تو میں بھی اس وقت ابوالخلیل کے ساتھ موجود تھا۔' WHERE id = 2034;
UPDATE hadiths SET urdu = 'ہم سے محمد بن صباح نے بیان کیا، کہا کہ ہم سے اسماعیل بن زکریا نے بیان کیا، ان سے محمد بن سوقہ نے، ان سے نافع بن جبیر بن مطعم نے بیان کیا، کہا کہ مجھ سے عائشہ رضی اللہ عنہا نے بیان کیا، کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا، قیامت کے قریب ایک لشکر کعبہ پر چڑھائی کرے گا۔ جب وہ مقام بیداء میں پہنچے گا تو انہیں اول سے آخر تک سب کو زمین میں دھنسا دیا جائے گا۔ عائشہ رضی اللہ عنہا نے بیان کیا، کہ میں نے کہا، یا رسول اللہ! اسے شروع سے آخر تک کیوں کر دھنسایا جائے گا جب کہ وہیں ان کے بازار بھی ہوں گے اور وہ لوگ بھی ہوں گے جو ان لشکریوں میں سے نہیں ہوں گے؟ آپ صلی اللہ علیہ وسلم نے فرمایا کہ ہاں! شروع سے آخر تک ان سب کو دھنسا دیا جائے گا۔ پھر ان کی نیتوں کے مطابق وہ اٹھائے جائیں گے۔' WHERE id = 2044;
UPDATE hadiths SET urdu = 'ہم سے اسحاق بن ابراہیم نے بیان کیا، کہا کہ ہم کو ولید بن مسلم نے خبر دی، انہیں اوزاعی نے، انہیں زہری نے، انہیں سالم نے، اور ان سے ان کے باپ نے بیان کیا، کہ میں نے رسول اللہ صلی اللہ علیہ وسلم کے زمانے میں ان لوگوں کو دیکھا جو اناج کے ڈھیر ( بغیر تولے ہوئے محض اندازہ کر کے ) خرید لیتے ان کو مار پڑتی تھی۔ اس لیے کہ جب تک اپنے گھر نہ لے جائیں نہ بچیں۔' WHERE id = 2056;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن مسلمہ قعنبی نے بیان کیا، کہا کہ ہم سے امام مالک نے بیان کیا، ان سے نافع نے، اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم نے «نجش» ( فریب، دھوکہ ) سے منع فرمایا تھا۔' WHERE id = 2067;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، کہا کہ ہم سے لیث نے بیان کیا، کہا کہ مجھے سعید مقبری نے خبر دی، ان سے ان کے باپ نے، اور انہوں نے ابوہریرہ رضی اللہ عنہ کو یہ کہتے سنا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا جب کوئی باندی زنا کرے اور اس کے زنا کا ثبوت ( شرعی ) مل جائے تو اسے کوڑے لگوائے، پھر اس کی لعنت ملامت نہ کرے۔ اس کے بعد اگر پھر وہ زنا کرے تو پھر کوڑے لگوائے مگر پھر لعنت ملامت نہ کرے۔ پھر اگر تیسری مرتبہ بھی زنا کرے تو اسے بیچ دے چاہے بال کی ایک رسی کے بدلہ ہی میں کیوں نہ ہو۔' WHERE id = 2077;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا کہ ہم سے یزید بن زریع نے بیان کیا، کہ ہم سے تیمی نے بیان کیا، ان سے ابوعثمان نے اور ان سے عبداللہ بن مسعود رضی اللہ عنہ نے بیان کیا کہ جو کوئی دودھ جمع کی ہوئی بکری خریدے ( وہ بکری پھیر دے ) اور اس کے ساتھ ایک صاع دیدے اور نبی کریم صلی اللہ علیہ وسلم نے قافلہ والوں سے آگے بڑھ کر ملنے سے منع فرمایا۔' WHERE id = 2088;
UPDATE hadiths SET urdu = 'ہم سے عبیداللہ بن سعد نے بیان کیا، کہا کہ مجھ سے میرے چچا نے بیان کیا، کہا ہم سے زہری کے بھتیجے نے بیان کیا، ان سے ان کے چچا نے بیان کیا کہ مجھ سے سالم بن عبداللہ رضی اللہ عنہ نے بیان کیا، ان سے عبداللہ بن عمر رضی اللہ عنہما نے کہ ابو سعید خدری رضی اللہ عنہ نے اسی طرح ایک حدیث رسول اللہ صلی اللہ علیہ وسلم کے حوالہ سے بیان کی ( جیسے ابوبکرہ رضی اللہ عنہ یا عمر رضی اللہ عنہ سے گزری ) پھر ایک مرتبہ عبداللہ بن عمر رضی اللہ عنہما کی ان سے ملاقات ہوئی تو انہوں نے پوچھا، اے ابوسعید! آپ رسول اللہ صلی اللہ علیہ وسلم کے حوالہ سے یہ کون سی حدیث بیان کرتے ہیں؟ ابو سعید خدری رضی اللہ عنہ نے فرمایا کہ حدیث بیع صرف ( یعنی روپیہ اشرفیاں بدلنے یا تڑوانے ) سے متعلق ہے۔ میں نے رسول اللہ صلی اللہ علیہ وسلم کا فرمان سنا تھا کہ سونا سونے کے بدلے میں برابر برابر ہی بیچا جا سکتا ہے اور چاندی، چاندی کے بدلہ میں برابر برابر ہی بیچی جا سکتی ہے۔' WHERE id = 2099;
UPDATE hadiths SET urdu = 'ہم سے محمد بن مقاتل نے بیان کیا، کہا کہ ہم کو امام عبداللہ بن مبارک نے خبر دی، انہوں نے کہا کہ ہمیں موسیٰ بن عقبہ نے، انہیں نافع نے، انہیں عبداللہ بن عمر رضی اللہ عنہما نے، انہیں زید بن ثابت رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے عریہ کی اجازت دی کہ وہ اندازے سے بیچی جا سکتی ہے۔ موسیٰ بن عقبہ نے کہا کہ عرایا کچھ معین درخت جن کا میوہ تو اترے ہوئے میوے کے بدل خریدے۔' WHERE id = 2112;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، کہا کہ ہم کو امام مالک نے خبر دی، انہیں نافع نے، انہیں عبداللہ بن عمر رضی اللہ عنہما نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا اگر کسی نے کھجور کے ایسے درخت بیچے ہوں جن کو پیوندی کیا جا چکا تھا تو اس کا پھل بیچنے والے ہی کا رہتا ہے۔ البتہ اگر خریدنے والے نے شرط لگا دی ہو۔ ( کہ پھل سمیت سودا ہو رہا ہے تو پھل بھی خریدار کی ملکیت میں آ جائیں گے ) ۔' WHERE id = 2123;
UPDATE hadiths SET urdu = 'ہم سے محمد بن محبوب نے بیان کیا، انہوں نے کہا کہ ہم سے عبدالواحد نے بیان کیا، ان سے معمر نے بیان کیا، ان سے زہری نے، ان سے ابوسلمہ بن عبدالرحمٰن نے اور ان سے جابر بن عبداللہ رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے ہر ایسے مال میں شفعہ کا حق قائم رکھا جو تقسیم نہ ہوا ہو، لیکن جب اس کی حدود قائم ہو گئی ہوں اور راستہ بھی پھیر دیا گیا ہو تو اب شفعہ کا حق باقی نہیں رہا۔' WHERE id = 2133;
UPDATE hadiths SET urdu = 'ہم سے عبدان نے بیان کیا، انہیں عبداللہ بن مبارک نے خبر دی، انہیں یونس نے خبر دی، انہیں ابن شہاب نے کہ میں نے سعید بن مسیب سے سنا، انہوں نے ابوہریرہ رضی اللہ عنہ سے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا اللہ یہودیوں کو تباہ کرے، ظالموں پر چربی حرام کر دی گئی تھی، لیکن انہوں نے اسے بیچ کر اس کی قیمت کھائی۔' WHERE id = 2144;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ نے بیان کیا، کہا کہ ہم سے لیث نے بیان کیا، انہوں نے کہا کہ ہم سے یزید بن ابی حبیب نے بیان کیا، ان سے عطاء بن ابی رباح نے بیان کیا، اور ان سے جابر بن عبداللہ رضی اللہ عنہما نے کہ انہوں نے رسول اللہ صلی اللہ علیہ وسلم سے سنا، فتح مکہ کے سال آپ صلی اللہ علیہ وسلم نے فرمایا، آپ کا قیام ابھی مکہ ہی میں تھا کہ اللہ اور اس کے رسول نے شراب، مردار، سور اور بتوں کا بیچنا حرام قرار دے دیا ہے۔ اس پر پوچھا گیا کہ یا رسول اللہ! مردار کی چربی کے متعلق کیا حکم ہے؟ اسے ہم کشتیوں پر ملتے ہیں۔ کھالوں پر اس سے تیل کا کام لیتے ہیں اور لوگ اس سے اپنے چراغ بھی جلاتے ہیں۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ نہیں وہ حرام ہے۔ اسی موقع پر آپ صلی اللہ علیہ وسلم نے فرمایا کہ اللہ یہودیوں کو برباد کرے اللہ تعالیٰ نے جب چربی ان پر حرام کی تو ان لوگوں نے پگھلا کر اسے بیچا اور اس کی قیمت کھائی۔ ابوعاصم نے کہا کہ ہم سے عبدالحمید نے بیان کیا، ان سے یزید نے بیان کیا، انہیں عطاء نے لکھا کہ میں نے جابر رضی اللہ عنہ سے سنا اور انہوں نے نبی کریم صلی اللہ علیہ وسلم سے۔' WHERE id = 2155;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، انہیں جویریہ نے خبر دی، انہیں نافع نے اور ان سے عبداللہ رضی اللہ عنہ نے بیان کیا کہ لوگ اونٹ وغیرہ حمل کے حمل ہونے کی مدت تک کے لیے بیچتے تھے۔ نبی کریم صلی اللہ علیہ وسلم نے اس سے منع فرمایا۔ نافع نے «حبل الحبلة» کی تفسیر یہ کی ”یہاں تک کہ اونٹنی کے پیٹ میں جو کچھ ہے وہ اسے جن لے۔“' WHERE id = 2173;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا، ان سے حماد بن زید نے بیان کیا، ان سے ایوب سختیانی نے، ان سے نافع نے، ان سے ابن عمر رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا، تمہاری اور یہود و نصاریٰ کی مثال ایسی ہے کہ کسی شخص نے کئی مزدور کام پر لگائے اور کہا کہ میرا کام ایک قیراط پر صبح سے دوپہر تک کون کرے گا؟ اس پر یہودیوں نے ( صبح سے دوپہر تک ) اس کا کام کیا۔ پھر اس نے کہا کہ آدھے دن سے عصر تک ایک قیراط پر میرا کام کون کرے گا؟ چنانچہ یہ کام پھر نصاریٰ نے کیا، پھر اس شخص نے کہا کہ عصر کے وقت سے سورج ڈوبنے تک میرا کام دو قیراط پر کون کرے گا؟ اور تم ( امت محمدیہ ) ہی وہ لوگ ہو ( جن کو یہ درجہ حاصل ہوا ) اس پر یہود و نصاریٰ نے برا مانا، وہ کہنے لگے کہ کام تو ہم زیادہ کریں اور مزدوری ہمیں کم ملے، پھر اس شخص نے کہا کہ اچھا یہ بتاؤ کیا تمہارا حق تمہیں پورا نہیں ملا؟ سب نے کہا کہ ہمیں تو ہمارا پورا حق مل گیا۔ اس شخص نے کہا کہ پھر یہ میرا فضل ہے میں جسے چاہوں زیادہ دوں۔' WHERE id = 2184;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، کہا کہ ہم سے وہیب نے بیان کیا، کہا کہ ہم سے ابن طاؤس نے بیان کیا، ان سے ان کے باپ نے اور ان سے ابن عباس رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے پچھنا لگوایا اور پچھنا لگانے والے کو اجرت بھی دی۔ اگر پچھنا لگوانا ناجائز ہوتا تو آپ صلی اللہ علیہ وسلم نہ پچھنا لگواتے نہ اجرت دیتے۔' WHERE id = 2194;
UPDATE hadiths SET urdu = 'اور ابوالزناد نے بیان کیا، ان سے محمد بن حمزہ بن عمرو الاسلمی نے اور ان سے ان کے والد (حمزہ) نے کہ عمر رضی اللہ عنہ نے ( اپنے عہد خلافت میں ) انہیں زکوٰۃ وصول کرنے کے لیے بھیجا۔ ( جہاں وہ زکوٰۃ وصول کر رہے تھے وہاں کے ) ایک شخص نے اپنی بیوی کی باندی سے ہمبستری کر لی۔ حمزہ نے اس کی ایک شخص سے پہلے ضمانت لی، یہاں تک کہ وہ عمر رضی اللہ عنہ کی خدمت میں حاضر ہوئے۔ عمر رضی اللہ عنہ نے اس شخص کو سو کوڑوں کی سزا دی تھی۔ اس آدمی نے جو جرم اس پر لگا تھا اس کو قبول کیا تھا لیکن جہالت کا عذر کیا تھا۔ عمر رضی اللہ عنہ نے اس کو معذور رکھا تھا اور جریر اور اشعث نے عبداللہ بن مسعود سے مرتدوں کے بارے میں کہا کہ ان سے توبہ کرائیے اور ان کی ضمانت طلب کیجئے ( کہ دوبارہ مرتد نہ ہوں گے ) چنانچہ انہوں نے توبہ کر لی اور ضمانت خود انہیں کے قبیلہ والوں نے دے دی۔ حماد نے کہا جس کا حاضر ضامن ہو اگر وہ مر جائے تو ضامن پر کچھ تاوان نہ ہو گا۔ لیکن حکم نے کہا کہ ذمہ کا مال دینا پڑے گا۔' WHERE id = 2205;
UPDATE hadiths SET urdu = 'ہم سے عمرو بن خالد نے بیان کیا، ان سے لیث نے بیان کیا، ان سے یزید نے، ان سے ابوالخیر نے اور ان سے عقبہ بن عامر رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے کچھ بکریاں ان کے حوالہ کی تھیں تاکہ صحابہ رضی اللہ عنہم میں ان کو تقسیم کر دیں۔ ایک بکری کا بچہ باقی رہ گیا۔ جب اس کا ذکر انہوں نے نبی کریم صلی اللہ علیہ وسلم سے کیا تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ اس کی تو قربانی کر لے۔' WHERE id = 2215;
UPDATE hadiths SET urdu = 'ہم سے ابن سلام نے بیان کیا، کہا کہ ہم کو عبدالوہاب ثقفی نے خبر دی، انہیں ایوب نے، انہیں ابن ابی ملکیہ نے اور ان سے عقبہ بن حارث رضی اللہ عنہ نے بیان کیا کہ نعیمان یا ابن نعیمان کو نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر کیا گیا۔ انہوں نے شراب پی لی تھی۔ جو لوگ اس وقت گھر میں موجود تھے رسول اللہ صلی اللہ علیہ وسلم نے انہیں کو اسے مارنے کا حکم دیا۔ انہوں نے بیان کیا میں بھی مارنے والوں سے تھا۔ ہم نے جوتوں اور چھڑیوں سے انہیں مارا تھا۔' WHERE id = 2228;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، کہ ہم سے جویریہ نے بیان کیا، ان سے نافع نے، اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے بنی نضیر کے کھجوروں کے باغ جلا دیئے اور کاٹ دیئے۔ ان ہی کے باغات کا نام بویرہ تھا۔ اور حسان رضی اللہ عنہ کا یہ شعر اسی کے متعلق ہے۔ بنی لوی ( قریش ) کے سرداروں پر ( غلبہ کو ) بویرہ کی آگ نے آسان بنا دیا جو ہر طرف پھیلتی ہی جا رہی تھی۔' WHERE id = 2238;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا کہ ہم سے اسماعیل بن جعفر نے بیان کیا، ان سے موسیٰ بن عقبہ نے، ان سے سالم بن عبداللہ بن عمر رضی اللہ عنہما نے اور ان سے ان کے باپ نے کہ نبی کریم صلی اللہ علیہ وسلم نے ( مکہ کے لیے تشریف لے جاتے ہوئے ) جب ذوالحلیفہ میں نالہ کے نشیب میں رات کے آخری حصہ میں پڑاؤ کیا تو آپ صلی اللہ علیہ وسلم سے خواب میں کہا گیا کہ آپ اس وقت ایک مبارک وادی میں ہیں۔ موسیٰ بن عقبہ ( راوی حدیث ) نے بیان کیا کہ سالم ( سالم بن عبداللہ بن عمر رضی اللہ عنہما ) نے بھی ہمارے ساتھ وہیں اونٹ بٹھایا۔ جہاں عبداللہ بن عمر رضی اللہ عنہما بٹھایا کرتے تھے، تاکہ اس جگہ قیام کر سکیں، جہاں نبی کریم صلی اللہ علیہ وسلم نے قیام فرمایا تھا۔ یہ جگہ وادی عقیق کی مسجد سے نالہ کے نشیب میں ہے۔ وادی عقیق اور راستے کے درمیان میں۔' WHERE id = 2248;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، انہوں نے کہا کہ ہم کو شعیب نے خبر دی، ان سے زہری نے بیان کیا، اور ان سے انس بن مالک رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم کے لیے گھر میں پلی ہوئی ایک بکری کا دودھ دوہا گیا، جو انس بن مالک رضی اللہ عنہ ہی کے گھر میں پلی تھی۔ پھر اس کے دودھ میں اس کنویں کا پانی ملا کر جو انس رضی اللہ عنہ کے گھر میں تھا، نبی کریم صلی اللہ علیہ وسلم کی خدمت میں اس کا پیالہ پیش کیا گیا۔ آپ صلی اللہ علیہ وسلم نے اسے پیا۔ جب اپنے منہ سے پیالہ آپ نے جدا کیا تو بائیں طرف ابوبکر رضی اللہ عنہ تھے اور دائیں طرف ایک دیہاتی تھا۔ عمر رضی اللہ عنہ ڈرے کہ آپ صلی اللہ علیہ وسلم یہ پیالہ دیہاتی کو نہ دے دیں۔ اس لیے انہوں نے عرض کیا کہ یا رسول اللہ! ابوبکر ( رضی اللہ عنہ ) کو دے دیجئیے۔ آپ صلی اللہ علیہ وسلم نے پیالہ اسی دیہاتی کو دیا جو آپ کی دائیں طرف تھا۔ اور فرمایا کہ دائیں طرف والا زیادہ حقدار ہے۔ پھر وہ جو اس کی داہنی طرف ہو۔' WHERE id = 2261;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ نے بیان کیا کہا کہ ہم سے عبدالعزیز نے بیان کیا، ان سے ابوحازم نے اور ان سے سہل بن سعد رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں ایک پیالہ پیش کیا گیا اور آپ صلی اللہ علیہ وسلم نے اسے نوش فرمایا۔ آپ کی دائیں طرف ایک لڑکا تھا جو حاضرین میں سب سے کم عمر تھا۔ بڑی عمر والے صحابہ آپ کی بائیں طرف تھے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا، اے لڑکے! کیا تمہاری اجازت ہے کہ میں اس پیالے کا بچا ہوا پانی بوڑھوں کو دوں؟ اس نے جواب دیا، یا رسول اللہ! میں تو آپ کا جھوٹا اپنے حصہ کا کسی کو دینے والا نہیں ہوں۔ آخر آپ نے وہ پیالہ اسی کو دے دیا۔' WHERE id = 2273;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا، کہا کہ ہم سے حماد نے بیان کیا، ان سے یحییٰ بن سعید نے بیان کیا، کہا کہ میں نے انس رضی اللہ عنہ سے سنا، انہوں نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے بحرین میں کچھ قطعات اراضی بطور جاگیر ( انصار کو ) دینے کا ارادہ کیا تو انصار نے عرض کیا کہ ہم جب لیں گے کہ آپ ہمارے مہاجر بھائیوں کو بھی اسی طرح کے قطعات عنایت فرمائیں۔ اس پر آپ صلی اللہ علیہ وسلم نے فرمایا کہ میرے بعد ( دوسرے لوگوں کو ) تم پر ترجیح دی جایا کرے گی تو اس وقت تم صبر کرنا، یہاں تک کہ ہم سے ( آخرت میں آ کر ) ملاقات کرو۔' WHERE id = 2283;
UPDATE hadiths SET urdu = 'ہم سے احمد بن یونس نے بیان کیا، کہا کہ ہم سے ابوشہاب نے بیان کیا، ان سے اعمش نے، ان سے زید بن وہب نے اور ان سے ابوذر رضی اللہ عنہ نے بیان کیا کہ میں نبی کریم صلی اللہ علیہ وسلم کے ساتھ تھا۔ آپ صلی اللہ علیہ وسلم نے جب دیکھا، آپ کی مراد احد پہاڑ ( کو دیکھنے ) سے تھی۔ تو فرمایا کہ میں یہ بھی پسند نہیں کروں گا کہ احد پہاڑ سونے کا ہو جائے تو اس میں سے میرے پاس ایک دینار کے برابر بھی تین دن سے زیادہ باقی رہے۔ سوا اس دینار کے جو میں کسی کا قرض ادا کرنے کے لیے رکھ لوں۔ پھر فرمایا، ( دنیا میں ) دیکھو جو زیادہ ( مال ) والے ہیں وہی محتاج ہیں۔ سوا ان کے جو اپنے مال و دولت کو یوں اور یوں خرچ کریں۔ ابوشہاب راوی نے اپنے سامنے اور دائیں طرف اور بائیں طرف اشارہ کیا، لیکن ایسے لوگوں کی تعداد کم ہوتی ہے۔ پھر آپ صلی اللہ علیہ وسلم نے فرمایا یہیں ٹھہرے رہو اور آپ صلی اللہ علیہ وسلم تھوڑی دور آگے کی طرف بڑھے۔ میں نے کچھ آواز سنی ( جیسے آپ صلی اللہ علیہ وسلم کسی سے باتیں کر رہے ہوں ) میں نے چاہا کہ آپ صلی اللہ علیہ وسلم کی خدمت میں حاضر ہو جاؤں۔ لیکن آپ صلی اللہ علیہ وسلم کا یہ فرمان یاد آیا کہ ”یہیں اس وقت تک ٹھہرے رہنا جب تک میں نہ آ جاؤں“ اس کے بعد جب آپ صلی اللہ علیہ وسلم تشریف لائے تو میں نے پوچھا یا رسول اللہ! ابھی میں نے کچھ سنا تھا۔ یا ( راوی نے یہ کہا کہ ) میں نے کوئی آواز سنی تھی۔ آپ صلی اللہ علیہ وسلم نے فرمایا، تم نے بھی سنا! میں نے عرض کیا کہ ہاں۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ میرے پاس جبرائیل علیہ السلام آئے تھے اور کہہ گئے ہیں کہ تمہاری امت کا جو شخص بھی اس حالت میں مرے کہ وہ اللہ کے ساتھ کسی کو شریک نہ ٹھہراتا ہو، تو وہ جنت میں داخل ہو گا۔ میں نے پوچھا کہ اگرچہ وہ اس طرح ( کے گناہ ) کرتا رہا ہو۔ تو آپ صلی اللہ علیہ وسلم نے کہا کہ ہاں۔' WHERE id = 2294;
UPDATE hadiths SET urdu = 'ہم سے ابوالولید نے بیان کیا، ان سے شعبہ نے بیان کیا، ان سے عدی بن ثابت نے، ان سے ابوحازم نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا جو شخص ( اپنے انتقال کے وقت ) مال چھوڑے تو وہ اس کے وارثوں کا ہے اور جو قرض چھوڑے تو وہ ہمارے ذمہ ہے۔' WHERE id = 2304;
UPDATE hadiths SET urdu = 'ہم سے ابوالولید نے بیان کیا، کہا کہ ہم سے شعبہ نے بیان کیا کہ عبدالملک بن میسرہ نے مجھے خبر دی کہا کہ میں نے نزال بن سمرہ سے سنا، اور انہوں نے عبداللہ بن مسعود رضی اللہ عنہ سے سنا، انہوں نے کہا کہ میں نے ایک شخص کو قرآن کی آیت اس طرح پڑھتے سنا کہ رسول اللہ صلی اللہ علیہ وسلم سے میں نے اس کے خلاف سنا تھا۔ اس لیے میں ان کا ہاتھ تھامے آپ صلی اللہ علیہ وسلم کی خدمت میں لے گیا۔ آپ صلی اللہ علیہ وسلم نے ( میرا اعتراض سن کر ) فرمایا کہ تم دونوں درست ہو۔ شعبہ نے بیان کیا کہ میں سمجھتا ہوں کہ آپ صلی اللہ علیہ وسلم نے یہ بھی فرمایا کہ اختلاف نہ کرو، کیونکہ تم سے پہلے لوگ اختلاف ہی کی وجہ سے تباہ ہو گئے۔' WHERE id = 2315;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ نے بیان کیا، انہوں نے کہا کہ ہم سے لیث نے بیان کیا، ان سے سعید بن ابی سعید نے اور انہوں نے ابوہریرہ رضی اللہ عنہ کو یہ کہتے سنا کہ رسول اللہ صلی اللہ علیہ وسلم نے چند سواروں کا ایک لشکر نجد کی طرف بھیجا۔ یہ لوگ بنو حنیفہ کے ایک شخص کو جس کا نام ثمامہ بن اثال تھا اور جو اہل یمامہ کا سردار تھا، پکڑ لائے اور اسے مسجد نبوی کے ایک ستون میں باندھ دیا۔ پھر رسول اللہ صلی اللہ علیہ وسلم تشریف لائے اور آپ صلی اللہ علیہ وسلم نے پوچھا، ثمامہ! تو کس خیال میں ہے؟ انہوں نے کہا اے محمد ( صلی اللہ علیہ وسلم ) میں اچھا ہوں۔ پھر انہوں نے پوری حدیث ذکر کی۔ آپ صلی اللہ علیہ وسلم نے فرمایا تھا کہ ثمامہ کو چھوڑ دو۔' WHERE id = 2326;
UPDATE hadiths SET urdu = 'اور یحییٰ بن سعید قطان نے بیان کیا، کہ ہم سے سفیان ثوری نے بیان کیا، کہا مجھ سے منصور نے بیان کیا، اور زائدہ بن قدامہ نے بھی منصور سے بیان کیا، اور ان سے طلحہ نے، کہا کہ ہم سے انس رضی اللہ عنہ نے حدیث بیان کی (دوسری سند) اور ہم سے محمد بن مقاتل نے بیان کیا، انہیں عبداللہ بن مبارک نے خبر دی، انہیں معمر نے، انہیں ہمام بن منبہ نے اور انہیں ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا میں اپنے گھر جاتا ہوں، وہاں مجھے میرے بستر پر کھجور پڑی ہوئی ملتی ہے۔ میں اسے کھانے کے لیے اٹھا لیتا ہوں۔ لیکن پھر یہ ڈر ہوتا ہے کہ کہیں صدقہ کی کھجور نہ ہو۔ تو میں اسے پھینک دیتا ہوں۔' WHERE id = 2336;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، کہا کہ ہم سے لیث نے بیان کیا، ان سے عقیل نے، ان سے ابن شہاب نے، انہیں سالم نے خبر دی، اور انہیں عبداللہ بن عمر رضی اللہ عنہما نے فرمایا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ایک مسلمان دوسرے مسلمان کا بھائی ہے، پس اس پر ظلم نہ کرے اور نہ ظلم ہونے دے۔ جو شخص اپنے بھائی کی ضرورت پوری کرے، اللہ تعالیٰ اس کی ضرورت پوری کرے گا۔ جو شخص کسی مسلمان کی ایک مصیبت کو دور کرے، اللہ تعالیٰ اس کی قیامت کی مصیبتوں میں سے ایک بڑی مصیبت کو دور فرمائے گا۔ اور جو شخص کسی مسلمان کے عیب کو چھپائے اللہ تعالیٰ قیامت میں اس کے عیب چھپائے گا۔' WHERE id = 2347;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، انہوں نے کہا ہم کو شعیب نے خبر دی، انہوں نے کہا کہ ہم سے زہری نے بیان کیا، ان سے طلحہ بن عبداللہ نے بیان کیا، انہیں عبدالرحمٰن بن عمرو بن سہل نے خبر دی اور ان سے سعید بن زید رضی اللہ عنہ نے بیان کیا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم سے سنا، آپ صلی اللہ علیہ وسلم نے فرمایا جس نے کسی کی زمین ظلم سے لے لی، اسے قیامت کے دن سات زمینوں کا طوق پہنایا جائے گا۔' WHERE id = 2357;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن سلیمان نے بیان کیا، انہوں نے کہا کہ مجھ سے ابن وہب نے بیان کیا، انہوں نے کہا کہ مجھ سے امام مالک نے بیان کیا (دوسری سند) اور مجھ کو یونس نے خبر دی کہ ابن شہاب نے کہا، مجھ کو خبر دی عبیداللہ بن عبداللہ بن عتبہ نے، انہیں عبداللہ بن عباس رضی اللہ عنہما نے خبر دی کہ عمر رضی اللہ عنہ نے کہا، جب اپنے نبی صلی اللہ علیہ وسلم کو اللہ تعالیٰ نے وفات دے دی تو انصار بنو ساعدہ کے «سقيفة» چوپال میں جمع ہوئے۔ میں نے ابوبکر رضی اللہ عنہ سے کہا کہ آپ ہمیں بھی وہیں لے چلئے۔ چنانچہ ہم انصار کے یہاں سقیفہ بنو ساعدہ میں پہنچے۔' WHERE id = 2367;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف تنیسی نے بیان کیا، کہا ہم کو امام مالک نے خبر دی، انہیں سمی نے، انہیں ابوصالح نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا، ایک شخص راستے پر چل رہا تھا کہ اس نے وہاں کانٹے دار ڈالی دیکھی۔ اس نے اسے اٹھا لیا تو اللہ تعالیٰ نے اس کا یہ عمل قبول کیا اور اس کی مغفرت کر دی۔' WHERE id = 2377;
UPDATE hadiths SET urdu = 'ہم سے مسلم بن ابراہیم نے بیان کیا، کہا ہم سے جریر بن حازم نے بیان کیا، ان سے محمد بن سیرین نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا، بنی اسرائیل میں ایک صاحب تھے، جن کا نام جریج تھا۔ وہ نماز پڑھ رہے تھے کہ ان کی والدہ آئیں اور انہیں پکارا۔ انہوں نے جواب نہیں دیا۔ سوچتے رہے کہ جواب دوں یا نماز پڑھوں۔ پھر وہ دوبارہ آئیں اور ( غصے میں ) بددعا کر گئیں، اے اللہ! اسے موت نہ آئے جب تک کسی بدکار عورت کا منہ نہ دیکھ لے۔ جریج اپنے عبادت خانے میں رہتے تھے۔ ایک عورت نے ( جو جریج کے عبادت خانے کے پاس اپنی مویشی چرایا کرتی تھی اور فاحشہ تھی ) کہا کہ جریج کو فتنہ میں ڈالے بغیر نہ رہوں گی۔ چنانچہ وہ ان کے سامنے آئی اور گفتگو کرنی چاہی، لیکن انہوں نے منہ پھیر لیا۔ پھر وہ ایک چرواہے کے پاس گئی اور اپنے جسم کو اس کے قابو میں دے دیا۔ آخر لڑکا پیدا ہوا۔ اور اس عورت نے الزام لگایا کہ یہ جریج کا لڑکا ہے۔ قوم کے لوگ جریج کے یہاں آئے اور ان کا عبادت خانہ توڑ دیا۔ انہیں باہر نکالا اور گالیاں دیں۔ لیکن جریج نے وضو کیا اور نماز پڑھ کر اس لڑکے کے پاس آئے۔ انہوں نے اس سے پوچھا۔ بچے! تمہار باپ کون ہے؟ بچہ ( اللہ کے حکم سے ) بول پڑا کہ چرواہا! ( قوم خوش ہو گئی اور ) کہا کہ ہم آپ کے لیے سونے کا عبادت خانہ بنوا دیں۔ جریج نے کہا کہ میرا گھر تو مٹی ہی سے بنے گا۔' WHERE id = 2387;
UPDATE hadiths SET urdu = 'ہم سے بشیر بن محمد نے بیان کیا، کہا ہم کو عبداللہ بن مبارک نے خبر دی، کہا ہم کو سعید بن ابی عروبہ نے خبر دی، انہیں قتادہ نے، انہیں نضر بن انس نے، انہیں بشیر بن نہیک نے اور انہیں ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا جو شخص مشترک غلام میں سے اپنا حصہ آزاد کر دے تو اس کے لیے ضروری ہے کہ اپنے مال سے غلام کو پوری آزادی دلا دے۔ لیکن اگر اس کے پاس اتنا مال نہیں ہے تو انصاف کے ساتھ غلام کی قیمت لگائی جائے۔ پھر غلام سے کہا جائے کہ ( اپنی آزادی کی ) کوشش میں وہ باقی حصہ کی قیمت خود کما کر ادا کر لے۔ لیکن غلام پر اس کے لیے کوئی دباو نہ ڈالا جائے۔' WHERE id = 2397;
UPDATE hadiths SET urdu = 'ہم سے مسلم بن ابراہیم نے بیان کیا، کہا ہم سے ہشام دستوائی نے بیان کیا، کہا ہم سے قتادہ نے بیان کیا، اور ان سے انس بن مالک رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے اپنی زرہ جَو کے بدلے گروی رکھی تھی۔ ایک دن میں خود آپ کے پاس جَو کی روٹی اور باسی چربی لے کر حاضر ہوا تھا۔ میں نے خود آپ صلی اللہ علیہ وسلم سے سنا تھا۔ آپ صلی اللہ علیہ وسلم فرما رہے تھے کہ آل محمد پر کوئی صبح اور کوئی شام ایسی نہیں آئی کہ ایک صاع سے زیادہ کچھ اور موجود رہا ہو، حالانکہ آپ کے نو گھر تھے۔' WHERE id = 2410;
UPDATE hadiths SET urdu = 'ہم سے محمد بن ابی بکر نے بیان کیا، انہوں نے کہا ہم سے عثام نے بیان کیا، انہوں نے کہا ہم سے ہشام نے بیان کیا، ان سے فاطمہ بنت منذر نے بیان کیا اور ان سے اسماء بنت ابی بکر رضی اللہ عنہما نے بیان کیا کہ ہمیں سورج گرہن کے وقت غلام آزاد کرنے کا حکم دیا جاتا تھا۔' WHERE id = 2421;
UPDATE hadiths SET urdu = 'ہم سے محمد بن عبداللہ بن نمیر نے بیان کیا، ان سے محمد بن بشر نے، ان سے اسماعیل نے، ان سے قیس نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ جب وہ اسلام قبول کرنے کے ارادے سے ( مدینہ کے لیے ) نکلے تو ان کے ساتھ ان کا غلام بھی تھا۔ ( راستے میں ) وہ دونوں ایک دوسرے سے بچھڑ گئے۔ پھر جب ابوہریرہ رضی اللہ عنہ ( مدینہ پہنچنے کے بعد ) نبی کریم صلی اللہ علیہ وسلم کی خدمت میں بیٹھے ہوئے تھے تو ان کا غلام بھی اچانک آ گیا۔ آپ صلی اللہ علیہ وسلم نے فرمایا، ابوہریرہ! یہ لو تمہارا غلام بھی آ گیا۔ ابوہریرہ رضی اللہ عنہ نے کہا، یا رسول اللہ! میں آپ کو گواہ بناتا ہوں کہ یہ غلام اب آزاد ہے۔ راوی نے کہا کہ ابوہریرہ رضی اللہ عنہ نے مدینہ پہنچ کر یہ شعر کہے تھے۔ ہے پیاری گو کٹھن ہے اور لمبی میری رات، پر دلائی اس نے دالکفر سے مجھ کو نجات۔' WHERE id = 2431;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، کہا کہ ہم کو امام مالک نے خبر دی، انہیں ربیعہ بن ابی عبدالرحمٰن نے، انہیں محمد بن یحییٰ بن حبان نے، ان سے ابن محیریز نے کہ میں نے ابوسعید رضی اللہ عنہ کو دیکھا تو ان سے ایک سوال کیا، آپ نے جواب میں کہا کہ ہم رسول اللہ صلی اللہ علیہ وسلم کے ساتھ غزوہ بنی مصطلق کے لیے نکلے۔ اس غزوے میں ہمیں ( قبیلہ بنی مصطلق کے ) عرب قیدی ہاتھ آئے ( راستے ہی میں ) ہمیں عورتوں کی خواہش ہوئی اور عورت سے الگ رہنا ہم کو مشکل ہو گیا۔ ہم نے چاہا کہ عزل کر لیں۔ جب رسول اللہ صلی اللہ علیہ وسلم سے اس بارے میں پوچھا تو آپ صلی اللہ علیہ وسلم نے فرمایا، تم عزل کر سکتے ہو، اس میں کوئی قباحت نہیں لیکن جن روحوں کی بھی قیامت تک کے لیے پیدائش مقدر ہو چکی ہے وہ تو ضرور پیدا ہو کر رہیں گی ( لہٰذا تمہارا عزل کرنا بیکار ہے ) ۔' WHERE id = 2442;
UPDATE hadiths SET urdu = 'ہم سے محمد بن سلام نے بیان کیا، کہا ہم سے عبدالرزاق نے بیان کیا، کہا ہم کو معمر نے خبر دی، انہیں ہمام بن منبہ نے، انہوں نے ابوہریرہ رضی اللہ عنہ سے سنا، وہ نبی کریم صلی اللہ علیہ وسلم سے روایت کرتے ہیں کہ آپ صلی اللہ علیہ وسلم نے فرمایا ”کوئی شخص ( کسی غلام یا کسی بھی شخص سے ) یہ نہ کہے۔ اپنے رب ( مراد آقا ) کو کھانا کھلا، اپنے رب کو وضو کرا، اپنے رب کو پانی پلا“۔ بلکہ صرف میرے سردار، میرے آقا کے الفاظ کہنا چاہئے۔ اسی طرح کوئی شخص یہ نہ کہے۔ ”میرا بندہ، میری بندی، بلکہ یوں کہنا چاہئے میرا چھوکرا، میری چھوکری، میرا غلام۔“' WHERE id = 2452;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، انہوں نے کہا ہم کو امام مالک رحمہ اللہ نے خبر دی یحییٰ بن سعید سے، وہ عمرہ بنت عبدالرحمٰن سے کہ بریرہ رضی اللہ عنہا عائشہ رضی اللہ عنہا سے مدد لینے آئیں۔ عائشہ رضی اللہ عنہا نے اس سے کہا کہ اگر تمہارے مالک یہ صورت پسند کریں کہ میں ( مکاتبت کی ساری رقم ) انہیں ایک ہی مرتبہ ادا کر دوں اور پھر تمہیں آزاد کر دوں تو میں ایسا کر سکتی ہوں۔ بریرہ رضی اللہ عنہا نے اس کا ذکر اپنے مالک سے کیا تو انہوں نے کہا کہ ( ہمیں اس صورت میں یہ منظور ہے کہ ) تیری ولاء ہمارے ساتھ ہی قائم رہے۔ مالک نے بیان کیا، ان سے یحییٰ نے بیان کیا کہ عمرہ کو یقین تھا کہ عائشہ رضی اللہ عنہا نے اس کا ذکر رسول اللہ صلی اللہ علیہ وسلم سے کیا تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ تو اسے خرید کر آزاد کر دے۔ ولاء تو اسی کی ہوتی ہے جو آزاد کرے۔' WHERE id = 2463;
UPDATE hadiths SET urdu = 'ہم سے ابراہیم بن موسیٰ نے بیان کیا، کہا ہم سے عبدہ بن سلیمان نے بیان کیا، کہا ہم سے ہشام بن عروہ نے بیان کیا، ان سے ان کے والد نے اور ان سے عائشہ رضی اللہ عنہا نے کہ لوگ ( رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں ) تحائف بھیجنے کے لیے عائشہ رضی اللہ عنہا کی باری کا انتظار کیا کرتے تھے۔ اپنے ہدایا سے، یا اس خاص دن کے انتظار سے ( راوی کو شک ہے ) لوگ رسول اللہ صلی اللہ علیہ وسلم کی خوشی حاصل کرنا چاہتے تھے۔' WHERE id = 2473;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، انہوں نے کہا ہم کو امام مالک نے خبر دی ابن شہاب سے، وہ حمید بن عبدالرحمٰن اور محمد بن نعمان بن بشیر سے اور ان سے نعمان بن بشیر رضی اللہ عنہما نے کہا ان کے والد انہیں رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں لائے اور عرض کیا کہ میں نے اپنے اس بیٹے کو ایک غلام بطور ہبہ دیا ہے۔ آپ صلی اللہ علیہ وسلم نے دریافت فرمایا، کیا ایسا ہی غلام اپنے دوسرے لڑکوں کو بھی دیا ہے؟ انہوں نے کہا نہیں، تو آپ نے فرمایا کہ پھر ( ان سے بھی ) واپس لے لے۔' WHERE id = 2484;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، کہا ہم کو شعیب نے خبر دی، انہیں زہری نے، کہا کہ مجھے عبیداللہ بن عبداللہ بن عتبہ نے خبر دی، انہیں عبداللہ بن عباس رضی اللہ عنہما نے خبر دی کہ انہوں نے صعب بن جثامہ لیثی رضی اللہ عنہ سے سنا، وہ اصحاب رسول اللہ صلی اللہ علیہ وسلم میں سے تھے۔ ان کا بیان تھا کہ انہوں نے آپ صلی اللہ علیہ وسلم کی خدمت میں ایک گورخر ہدیہ کیا تھا۔ آپ صلی اللہ علیہ وسلم اس وقت مقام ابواء یا مقام ودان میں تھے اور محرم تھے۔ آپ نے وہ گورخر واپس کر دیا۔ صعب رضی اللہ عنہ نے کہا کہ اس کے بعد جب آپ صلی اللہ علیہ وسلم نے میرے چہرے پر ( ناراضی کا اثر ) ہدیہ کی واپسی کی وجہ سے دیکھا، تو فرمایا ”ہدیہ واپس کرنا مناسب تو نہ تھا لیکن بات یہ ہے کہ ہم احرام باندھے ہوئے ہیں۔“' WHERE id = 2494;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن عثمان بن جبلہ نے بیان کیا، انہوں نے کہا کہ مجھے میرے باپ نے خبر دی شعبہ سے، ان سے سلمہ نے بیان کیا کہ میں نے ابوسلمہ سے سنا اور ان سے ابوہریرہ رضی اللہ عنہ نے کہا کہ ایک شخص کا رسول اللہ صلی اللہ علیہ وسلم پر قرض تھا ( اس نے سختی کے ساتھ تقاضا کیا ) تو صحابہ اس کی طرف بڑھے۔ لیکن آپ صلی اللہ علیہ وسلم نے فرمایا اسے چھوڑ دو، حق والے کو کچھ نہ کچھ کہنے کی گنجائش ہوتی ہی ہے۔ پھر آپ صلی اللہ علیہ وسلم نے فرمایا کہ اس کے لیے ایک اونٹ اسی کے اونٹ کی عمر کا خرید کر اسے دے دو۔ صحابہ نے عرض کیا کہ اس سے اچھی عمر کا ہی اونٹ مل رہا ہے۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ اسی کو خرید کر دے دو کہ تم میں سب سے اچھا آدمی وہ ہے جو قرض کے ادا کرنے میں سب سے اچھا ہو۔' WHERE id = 2504;
UPDATE hadiths SET urdu = 'ہم سے خالد بن مخلد نے بیان کیا، کہا ہم سے سلیمان بن بلال نے بیان کیا، کہا کہ مجھ سے عبداللہ بن دینار نے بیان کیا اور ان سے عبداللہ بن عمر نے کہ عمر رضی اللہ عنہ نے دیکھا کہ ایک شخص کے یہاں ایک ریشمی جوڑا فروخت ہو رہا ہے۔ تو آپ نے نبی کریم صلی اللہ علیہ وسلم سے کہا کہ آپ یہ جوڑا خرید لیجئیے تاکہ جمعہ کے دن اور جب کوئی وفد آئے تو آپ اسے پہنا کریں۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ اسے تو وہ لوگ پہنتے ہیں جن کا آخرت میں کوئی حصہ نہیں ہوتا۔ پھر نبی کریم صلی اللہ علیہ وسلم کے پاس بہت سے ریشمی جوڑے آئے اور آپ صلی اللہ علیہ وسلم نے ان میں سے ایک جوڑا عمر رضی اللہ عنہ کو بھیجا۔ عمر رضی اللہ عنہ نے کہا کہ میں اسے کس طرح پہن سکتا ہوں جب کہ آپ خود ہی اس کے متعلق جو کچھ ارشاد فرمانا تھا، فرما چکے ہیں۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ میں نے تمہیں پہننے کے لیے نہیں دیا بلکہ اس لیے دیا کہ تم اسے بیچ دو یا کسی ( غیر مسلم ) کو پہنا دو۔ چنانچہ عمر رضی اللہ عنہ نے اسے مکے میں اپنے ایک بھائی کے گھر بھیج دیا جو ابھی اسلام نہیں لایا تھا۔' WHERE id = 2515;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، انہوں نے کہا ہم سے امام مالک نے بیان کیا، ان سے ابوالزناد نے، ان سے اعرج نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا، کیا ہی عمدہ ہے ہدیہ اس دودھ دینے والی اونٹنی کا جس نے ابھی حال ہی میں بچہ جنا ہو اور دودھ دینے والی بکری کا جو صبح و شام اپنے دودھ سے برتن بھر دیتی ہے۔ ہم سے عبداللہ بن یوسف اور اسماعیل نے بیان کیا، ان سے امام مالک نے بیان کیا کہ ( دودھ دینے والی اونٹنی کا ) صدقہ کیا ہی عمدہ ہے۔' WHERE id = 2525;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد نے بیان کیا، کہا ہم سے سفیان نے بیان کیا زہری سے اور ان سے عروہ نے اور ان سے عائشہ رضی اللہ عنہا نے کہ رفاعہ قرظی رضی اللہ عنہ کی بیوی رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئیں اور عرض کیا کہ میں رفاعہ کی نکاح میں تھی۔ پھر مجھے انہوں نے طلاق دے دی اور قطعی طلاق دے دی۔ پھر میں نے عبدالرحمٰن بن زبیر رضی اللہ عنہ سے شادی کر لی۔ لیکن ان کے پاس تو ( شرمگاہ ) اس کپڑے کی گانٹھ کی طرح ہے۔ آپ صلی اللہ علیہ وسلم نے دریافت کیا ”کیا تو رفاعہ کے پاس دوبارہ جانا چاہتی ہے لیکن تو اس وقت تک ان سے اب شادی نہیں کر سکتی جب تک تو عبدالرحمٰن بن زبیر کا مزا نہ چکھ لے اور وہ تمہارا مزا نہ چکھ لیں۔“ اس وقت ابوبکر رضی اللہ عنہ خدمت نبوی میں موجود تھے اور خالد بن سعید بن عاص رضی اللہ عنہ دروازے پر اپنے لیے ( اندر آنے کی ) اجازت کا انتظار کر رہے تھے۔ انہوں نے کہا، ابوبکر! کیا اس عورت کو نہیں دیکھتے نبی کریم صلی اللہ علیہ وسلم کے سامنے کس طرح کی باتیں زور زور سے کہہ رہی ہے۔' WHERE id = 2535;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، کہا ہم سے لیث نے بیان کیا عقیل سے، وہ ابن شہاب سے، ان سے عبیداللہ بن عبداللہ نے اور ان سے زید بن خالد رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے ان لوگوں کے لیے جو شادی شدہ نہ ہوں اور زنا کریں۔ یہ حکم دیا تھا کہ انہیں سو کوڑے لگائے جائیں اور ایک سال کے لیے جلا وطن کر دیا جائے۔' WHERE id = 2545;
UPDATE hadiths SET urdu = 'ہم سے ابوعاصم نے بیان کیا، کہا ہم سے ابن جریج نے، وہ ابن بی ملیکہ سے، ان سے عقبہ بن حارث رضی اللہ عنہ نے (دوسری سند) امام بخاری رحمہ اللہ نے کہا اور ہم سے علی بن عبداللہ نے بیان کیا، کہا ہم سے یحییٰ بن سعید نے بیان کیا، ان سے ابن جریج نے بیان کیا کہ میں نے ابن ابی ملیکہ سے سنا، کہا کہ مجھ سے عقبہ بن حارث رضی اللہ عنہ نے بیان کیا، یا (یہ کہا کہ) میں نے یہ حدیث ان سے سنی کہ انہوں نے ام یحیی بنت ابی اہاب سے شادی کی تھی۔ انہوں نے بیان کیا کہ پھر ایک سیاہ رنگ والی باندی آئی اور کہنے لگی کہ میں نے تم دونوں کو دودھ پلایا ہے۔ میں نے اس کا ذکر رسول اللہ صلی اللہ علیہ وسلم سے کیا، تو آپ صلی اللہ علیہ وسلم نے میری طرف سے منہ پھیر لیا پس میں جدا ہو گیا۔ میں نے پھر آپ صلی اللہ علیہ وسلم کے سامنے جا کر اس کا ذکر کیا، تو آپ صلی اللہ علیہ وسلم نے فرمایا، اب ( نکاح ) کیسے ( باقی رہ سکتا ہے ) جبکہ تمہیں اس عورت نے بتا دیا ہے کہ اس نے تم دونوں کو دودھ پلایا تھا۔ چنانچہ آپ صلی اللہ علیہ وسلم نے انہیں ام یحییٰ کو اپنے ساتھ رکھنے سے منع فرما دیا۔' WHERE id = 2555;
UPDATE hadiths SET urdu = 'ہم سے محمد بن بشار نے بیان کیا، کہا کہ ہم سے ابن ابی عدی نے بیان کیا، ان سے ہشام نے، ان سے عکرمہ نے بیان کیا اور ان سے ابن عباس رضی اللہ عنہما نے بیان کیا کہ ہلال بن امیہ رضی اللہ عنہ نے نبی کریم صلی اللہ علیہ وسلم کے سامنے اپنی بیوی پر شریک بن سمحاء کے ساتھ تہمت لگائی تو آپ صلی اللہ علیہ وسلم نے فرمایا ”اس پر گواہ لا ورنہ تمہاری پیٹھ پر حد لگائی جائے گی۔“ انہوں نے کہا یا رسول اللہ! کیا ہم میں سے کوئی شخص اگر اپنی عورت پر کسی دوسرے کو دیکھے گا تو گواہ ڈھونڈنے دوڑے گا؟ آپ صلی اللہ علیہ وسلم برابر یہی فرماتے رہے ”گواہ لا ورنہ تمہاری پیٹھ پر حد لگائی جائے گی۔“ پھر لعان کی حدیث کا ذکر کیا۔' WHERE id = 2565;
UPDATE hadiths SET urdu = 'ہم سے ابراہیم بن موسیٰ نے بیان کیا، کہا ہمیں ہشام نے خبر دی، ان سے ابن جریج نے بیان کیا، انہیں عمرو بن دینار نے خبر دی، انہیں محمد بن علی نے اور ان سے جابر بن عبداللہ رضی اللہ عنہما نے بیان کیا، کہا نبی کریم صلی اللہ علیہ وسلم کی وفات کے بعد ابوبکر رضی اللہ عنہ کے پاس ( بحرین کے عامل ) علاء بن حضرمی رضی اللہ عنہ کی طرف سے مال آیا۔ ابوبکر رضی اللہ عنہ نے اعلان کرا دیا کہ جس کسی کا بھی نبی کریم صلی اللہ علیہ وسلم پر کوئی قرض ہو، یا آپ صلی اللہ علیہ وسلم کا اس سے وعدہ ہو تو وہ ہمارے پاس آئے۔ جابر رضی اللہ عنہ نے بیان کیا کہ اس پر میں نے ان سے کہا کہ مجھ سے رسول اللہ صلی اللہ علیہ وسلم نے وعدہ فرمایا تھا کہ آپ صلی اللہ علیہ وسلم اتنا مال مجھے عطا فرمائیں گے۔ چنانچہ ابوبکر رضی اللہ عنہ نے تین مرتبہ اپنے ہاتھ بڑھائے اور میرے ہاتھ پر پانچ سو، پھر پانچ سو اور پھر پانچ سو گن دئیے۔' WHERE id = 2576;
UPDATE hadiths SET urdu = 'ہم سے محمد بن عبداللہ نے بیان کیا، انہوں نے کہا ہم سے عبدالعزیز بن عبداللہ اویسی اور اسحاق بن محمد فروی نے بیان کیا، انہوں نے کہا کہ ہم سے محمد بن جعفر نے بیان کیا، ان سے ابوحازم نے بیان کیا اور ان سے سہل بن سعد رضی اللہ عنہ نے بیان کیا کہ قباء کے لوگوں نے آپس میں جھگڑا کیا اور نوبت یہاں تک پہنچی کہ ایک نے دوسرے پر پتھر پھینکے، آپ صلی اللہ علیہ وسلم کو جب اس کی اطلاع دی گئی تو آپ صلی اللہ علیہ وسلم نے فرمایا ”چلو ہم ان میں صلح کرائیں گے۔“' WHERE id = 2586;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد مسندی نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے بیان کیا، ان سے ابوموسیٰ نے بیان کیا کہ میں نے امام حسن بصری سے سنا، وہ بیان کرتے تھے کہ قسم اللہ کی جب حسن بن علی رضی اللہ عنہما ( معاویہ رضی اللہ عنہ کے مقابلے میں ) پہاڑوں میں لشکر لے کر پہنچے، تو عمرو بن العاص رضی اللہ عنہ نے کہا ( جو امیر معاویہ رضی اللہ عنہ کے مشیر خاص تھے ) کہ میں ایسا لشکر دیکھ رہا ہوں جو اپنے مقابل کو نیست و نابود کیے بغیر واپس نہ جائے گا۔ معاویہ رضی اللہ عنہ نے اس پر کہا اور قسم اللہ کی، وہ ان دونوں اصحاب میں زیادہ اچھے تھے، کہ اے عمرو! اگر اس لشکر نے اس لشکر کو قتل کر دیا، یا اس نے اس کو قتل کر دیا، تو ( اللہ تعالیٰ کی بارگاہ میں ) لوگوں کے امور ( کی جواب دہی کے لیے ) میرے ساتھ کون ذمہ داری لے گا، لوگوں کی بیوہ عورتوں کی خبرگیری کے سلسلے میں میرے ساتھ کون ذمہ دار ہو گا۔ لوگوں کی آل اولاد کے سلسلے میں میرے ساتھ کون ذمہ دار ہو گا۔ آخر معاویہ رضی اللہ عنہ نے حسن رضی اللہ عنہ کے یہاں قریش کی شاخ بنو عبد شمس کے دو آدمی بھیجے۔ عبدالرحمٰن بن سمرہ اور عبداللہ بن عامر بن کریز، آپ نے ان دونوں سے فرمایا کہ حسن بن علی رضی اللہ عنہ کے یہاں جاؤ اور ان کے سامنے صلح پیش کرو، ان سے اس پر گفتگو کرو اور فیصلہ انہیں کی مرضی پر چھوڑ دو۔ چنانچہ یہ لوگ آئے اور آپ سے گفتگو کی اور فیصلہ آپ ہی کی مرضی پر چھوڑ دیا۔ حسن بن علی رضی اللہ عنہ نے فرمایا، ہم بنو عبدالمطلب کی اولاد ہیں اور ہم کو خلافت کی وجہ سے روپیہ پیسہ خرچ کرنے کی عادت ہو گئی ہے اور ہمارے ساتھ یہ لوگ ہیں، یہ خون خرابہ کرنے میں طاق ہیں، بغیر روپیہ دئیے ماننے والے نہیں۔ وہ کہنے لگے امیر معاویہ رضی اللہ عنہ آپ کو اتنا اتنا روپیہ دینے پر راضی ہیں اور آپ سے صلح چاہتے ہیں۔ فیصلہ آپ کی مرضی پر چھوڑا ہے اور آپ سے پوچھا ہے۔ حسن رضی اللہ عنہ نے فرمایا کہ اس کی ذمہ داری کون لے گا؟ ان دونوں قاصدوں نے کہا کہ ہم اس کے ذمہ دار ہیں۔ حسن نے جس چیز کے متعلق بھی پوچھا، تو انہوں نے یہی کہا کہ ہم اس کے ذمہ دار ہیں۔ آخر آپ نے صلح کر لی، پھر فرمایا کہ میں نے ابوبکرہ رضی اللہ عنہ سے سنا تھا، وہ بیان کرتے تھے کہ میں نے رسول اللہ صلی اللہ علیہ وسلم کو منبر پر یہ فرماتے سنا ہے اور حسن بن علی رضی اللہ عنہما آپ صلی اللہ علیہ وسلم کے پہلو میں تھے، آپ صلی اللہ علیہ وسلم کبھی لوگوں کی طرف متوجہ ہوتے اور کبھی حسن رضی اللہ عنہ کی طرف اور فرماتے کہ میرا یہ بیٹا سردار ہے اور شاید اس کے ذریعہ اللہ تعالیٰ مسلمانوں کے دو عظیم گروہوں میں صلح کرائے گا۔ امام بخاری رحمہ اللہ نے کہا مجھ سے علی بن عبداللہ مدینی نے بیان کیا کہ ہمارے نزدیک اس حدیث سے حسن بصری کا ابوبکرہ رضی اللہ عنہ سے سننا ثابت ہوا ہے۔' WHERE id = 2596;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، کہا ہم کو امام مالک نے خبر دی، انہیں نافع نے اور انہیں عبداللہ بن عمر رضی اللہ عنہما نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”جس نے کوئی ایسا کھجور کا باغ بیچا جس کی پیوند کاری ہو چکی تھی تو اس کا پھل ( اس سال کے ) بیچنے والے ہی کا ہو گا۔ ہاں اگر خریدار شرط لگا دے ( تو پھل سمیت بیع سمجھی جائے گی ) ۔' WHERE id = 2607;
UPDATE hadiths SET urdu = 'ہم سے ابراہیم بن موسیٰ نے بیان کیا، کہا کہ ہم کو ہشام بن یوسف نے خبر دی، انہیں ابن جریج نے خبر دی، کہا کہ مجھے یعلیٰ بن مسلم اور عمرو بن دینار نے خبر دی سعید بن جبیر سے اور ان میں ایک دوسرے سے زیادہ بیان کرتا ہے، ابن جریج نے کہا مجھ سے یہ حدیث یعلیٰ اور عمرو کے سوا اوروں نے بھی بیان کی، وہ سعید بن جبیر سے روایت کرتے ہیں کہ ہم ابن عباس رضی اللہ عنہما کی خدمت میں حاضر تھے۔ انہوں نے کہا کہ مجھ سے ابی بن کعب رضی اللہ عنہ نے بیان کیا، انہوں نے کہا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”خضر سے جو جا کر ملے تھے وہ موسیٰ علیہ السلام تھے۔“ پھر آخر تک حدیث بیان کی کہ خضر علیہ السلام نے موسیٰ علیہ السلام سے کہا کیا میں آپ کو پہلے ہی نہیں بتا چکا تھا کہ آپ میرے ساتھ صبر نہیں کر سکتے ( موسیٰ علیہ السلام کی طرف سے ) پہلا سوال تو بھول کر ہوا تھا، بیچ کا شرط کے طور پر اور تیسرا جان بوجھ کر ہوا تھا۔ آپ نے خضر سے کہا تھا کہ ”میں جس کو بھول گیا آپ اس میں مجھ سے مواخذہ نہ کیجئے اور نہ میرا کام مشکل بنائیے۔“ دونوں کو ایک لڑکا ملا جسے خضر علیہ السلام نے قتل کر دیا وہ وہ آگے بڑھے تو انہیں ایک دیوار ملی جو گرنے والی تھی لیکن خضر علیہ السلام نے اسے درست کر دیا۔ ابن عباس رضی اللہ عنہما نے «وراءهم ملك‏» «وراءهم‏» کے بجائے «أمامهم ملك‏.‏» پڑھا ہے۔' WHERE id = 2618;
UPDATE hadiths SET urdu = 'ہم سے ابراہیم بن حارث نے بیان کیا ‘ انہوں نے کہا ہم سے یحییٰ ابن ابی بکیر نے بیان کیا ‘ انہوں نے کہا ہم سے زہیر بن معاویہ جعفی نے بیان کیا ‘ انہوں نے کہا ہم سے ابواسحاق عمرو بن عبداللہ نے بیان کیا اور ان سے رسول اللہ صلی اللہ علیہ وسلم کے نسبتی بھائی عمرو بن حارث رضی اللہ عنہ نے جو جویریہ بنت حارث رضی اللہ عنہا ( ام المؤمنین ) کے بھائی ہیں ‘ بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے اپنی وفات کے بعد سوائے اپنے سفید خچر ‘ اپنے ہتھیار اور اپنی زمین کے جسے آپ صلی اللہ علیہ وسلم وقف کر گئے تھے نہ کوئی درہم چھوڑا تھا نہ دینار نہ غلام نہ باندی اور نہ کوئی چیز۔' WHERE id = 2628;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن داؤد ابوالربیع نے بیان کیا ‘ انہوں نے کہا ہم سے اسمٰعیل بن جعفر نے ‘ انہوں نے کہا ہم سے نافع بن مالک بن ابی عامر ابوسہیل نے ‘ انہوں نے اپنے باپ سے ‘ انہوں نے ابوہریرہ رضی اللہ عنہ سے انہوں نے نبی کریم صلی اللہ علیہ وسلم سے، آپ صلی اللہ علیہ وسلم نے فرمایا ”منافق کی تین نشانیاں ہیں جب بات کہے تو جھوٹ کہے اور جب اس کے پاس امانت رکھیں تو خیانت کرے اور جب وعدہ کرے تو خلاف کرے۔“' WHERE id = 2638;
UPDATE hadiths SET urdu = 'ہم سے ابوالنعمان محمد بن فضل نے بیان کیا ‘ کہا ہم سے ابوعوانہ نے بیان کیا ابوبشر جعفر سے ‘ ان سے سعید بن جبیر نے اور ان سے ابن عباس رضی اللہ عنہما نے فرمایا کہ کچھ لوگ گمان کرنے لگے ہیں کہ یہ آیت ( جس ذکر عنوان میں ہوا ) میراث کی آیت منسوخ ہو گئی ہے ‘ نہیں قسم اللہ کی آیت منسوخ نہیں ہوئی البتہ لوگ اس پر عمل کرنے میں سست ہو گئے ہیں۔ ترکے کے لینے والے دو طرح کے ہوتے ہیں ایک وہ جو وارث ہوں ان کو حصہ دیا جائے گا دوسرے وہ جو وارث نہ ہوں ان کو نرمی سے جواب دینے کا حکم ہے۔ وہ یوں کہے میاں میں تم کو دینے کا اختیار نہیں رکھتا۔' WHERE id = 2648;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن مسلمہ نے بیان کیا ‘ کہا ہم سے امام مالک نے ‘ ان سے اسحاق بن عبداللہ بن ابی طلحہ نے ‘ انہوں نے انس بن مالک رضی اللہ عنہ سے سنا آپ بیان کرتے تھے کہ ابوطلحہ رضی اللہ عنہ کھجور کے باغات کے اعتبار سے مدینہ کے انصار میں سب سے بڑے مالدار تھے اور انہیں اپنے تمام مالوں میں مسجد نبوی کے سامنے بیرحاء کا باغ سب سے زیادہ پسند تھا۔ خود نبی کریم صلی اللہ علیہ وسلم بھی اس باغ میں تشریف لے جاتے اور اس کا میٹھا پانی پیتے تھے۔ انس رضی اللہ عنہ نے بیان کیا کہ پھر جب یہ آیت نازل ہوئی «لن تنالوا البر حتى تنفقوا مما تحبون‏» ”نیکی تم ہرگز نہیں حاصل کرو گے جب تک اپنے اس مال سے نہ خرچ کرو جو تمہیں پسند ہوں۔“ تو ابوطلحہ رضی اللہ عنہ اٹھے اور آ کر رسول اللہ صلی اللہ علیہ وسلم سے عرض کیا کہ یا رسول اللہ! اللہ تعالیٰ فرماتا ہے «لن تنالوا البر حتى تنفقوا مما تحبون‏» ”تم نیکی ہرگز نہیں حاصل کر سکو گے جب تک اپنے ان مالوں میں سے نہ خرچ کرو جو تمہیں زیادہ پسند ہوں۔“ اور میرے اموال میں مجھے سب سے زیادہ پسند بیرحاء ہے اور یہ اللہ کے راستہ میں صدقہ ہے ‘ میں اللہ کی بارگاہ سے اس کی نیکی اور ذخیرہ آخرت ہونے کی امید رکھتا ہوں۔ آپ کو جہاں اللہ تعالیٰ بتائے اسے خرچ کریں۔ آپ صلی اللہ علیہ وسلم نے فرمایا شاباش یہ تو بڑا فائدہ بخش مال ہے یا آپ نے بجائے «رابح» رابع کے «رايح» کہا یہ شک عبداللہ بن مسلمہ راوی کو ہوا تھا۔۔۔ اور جو کچھ تم نے کہا میں نے سب سن لیا ہے اور میرا خیال ہے کہ تم اسے اپنے ناطے والوں کو دے دو۔ ابوطلحہ نے عرض کیا یا رسول اللہ! میں ایسا ہی کروں گا۔ چنانچہ انہوں نے اپنے عزیزوں اور اپنے چچا کے لڑکوں میں تقسیم کر دیا۔ اسماعیل ‘ عبداللہ بن یوسف اور یحییٰ بن یحییٰ نے مالک کے واسطہ سے۔ «رابح» کے بجائے «رايح» بیان کیا ہے۔' WHERE id = 2658;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا ‘ کہا ہم سے عبدالوارث نے بیان کیا ‘ ان سے ابوالتیاح نے اور ان سے انس رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا تھا ”اے بنو نجار! تم اپنے باغ کی قیمت مجھ سے وصول کر لو تو انہوں نے عرض کیا کہ ہم اس کی قیمت اللہ تعالیٰ کے سوا کسی سے نہیں چاہتے۔“' WHERE id = 2668;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا ‘ کہا ہم سے جریر نے ‘ کہا ہم سے ابورجاء نے ‘ ان سے سمرہ بن جندب رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”میں نے رات میں دو آدمی دیکھے جو میرے پاس آئے پھر وہ مجھے لے کر ایک درخت پر چڑھے اور اس کے بعد مجھے ایک ایسے مکان میں لے گئے جو نہایت خوبصورت اور بڑا پاکیزہ تھا، ایسا خوبصورت مکان میں نے کبھی نہیں دیکھا تھا۔ ان دونوں نے کہا کہ یہ گھر شہیدوں کا ہے۔“' WHERE id = 2679;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف تنیسی نے بیان کیا ‘ کہا ہم کو امام مالک نے خبر دی ابوالزناد سے ‘ انہوں نے اعرج سے اور انہوں نے ابوہریرہ رضی اللہ عنہ سے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”اس ذات کی قسم جس کے ہاتھ میں میری جان ہے جو شخص بھی اللہ کے راستے میں زخمی ہوا اور اللہ تعالیٰ خوب جانتا ہے کہ اس کے راستے میں کون زخمی ہوا ہے ‘ وہ قیامت کے دن اس طرح سے آئے گا کہ اس کے زخموں سے خون بہہ رہا ہو گا ‘ رنگ تو خون جیسا ہو گا لیکن اس میں خوشبو مشک جیسی ہو گی۔“' WHERE id = 2690;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل بن عبداللہ نے بیان کیا ‘ کہا کہ مجھ سے امام مالک نے بیان کیا اسحاق بن عبداللہ بن ابی طلحہ سے اور ان سے انس بن مالک رضی اللہ عنہ نے بیان کیا کہ اصحاب بئرمعونہ ( رضی اللہ عنہم ) کو جن لوگوں نے قتل کیا تھا ان پر رسول اللہ صلی اللہ علیہ وسلم نے تیس دن تک صبح کی نماز میں بددعا کی تھی۔ یہ رعل ‘ ذکوان اور عصیہ قبائل کے لوگ تھے جنہوں نے اللہ اور اس کے رسول کی نافرمانی کی تھی۔ انس رضی اللہ عنہ نے بیان کیا کہ جو ( 70 قاری ) صحابہ بئرمعونہ کے موقع پر شہید کر دئیے گئے تھے ‘ ان کے بارے میں قرآن کی یہ آیت نازل ہوئی تھی جسے ہم مدت تک پڑھتے رہے تھے بعد میں آیت منسوخ ہو گئی تھی ( اس آیت کا ترجمہ یہ ہے ) ”ہماری قوم کو پہنچا دو کہ ہم اپنے رب سے آ ملے ہیں ‘ ہمارا رب ہم سے راضی ہے اور ہم اس سے راضی ہیں۔“' WHERE id = 2700;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا ‘ انہوں نے کہا ہم سے حاتم نے بیان کیا محمد بن یوسف سے ‘ ان سے سائب بن یزید رضی اللہ عنہ نے بیان کیا کہ میں طلحہ بن عبیداللہ ‘ سعد بن ابی وقاص ‘ مقداد بن اسود اور عبدالرحمٰن بن عوف رضی اللہ عنہم کی صحبت میں بیٹھا ہوں لیکن میں نے کسی کو رسول اللہ صلی اللہ علیہ وسلم کی حدیث بیان کرتے نہیں سنا۔ البتہ طلحہ رضی اللہ عنہ سے سنا کہ وہ احد کی جنگ کے متعلق بیان کیا کرتے تھے۔' WHERE id = 2710;
UPDATE hadiths SET urdu = 'سے عبداللہ بن محمد مسندی نے بیان کیا ‘ کہا ہم سے معاویہ بن عمرو نے بیان کیا ‘ کہا ہم سے اسحاق نے بیان کیا ‘ ان سے حمید نے بیان کیا میں نے انس رضی اللہ عنہ سے سنا ‘ وہ بیان کرتے تھے کہ نبی کریم صلی اللہ علیہ وسلم میدان خندق کی طرف تشریف لے گئے ( غزوہ خندق کے شروع ہونے سے کچھ پہلے جب خندق کی کھدائی ہو رہی تھی ) ‘ آپ نے دیکھا کہ مہاجرین اور انصار رضوان اللہ علیہم اجمعین سردی کی سختی کے باوجود صبح ہی صبح خندق کھودنے میں مصروف ہیں ‘ ان کے پاس غلام بھی نہیں تھے جو ان کی اس کھدائی میں مدد کرتے۔ آپ صلی اللہ علیہ وسلم نے ان کی تھکن اور بھوک کو دیکھا تو آپ صلی اللہ علیہ وسلم نے دعا فرمائی ”اے اللہ! زندگی تو پس آخرت ہی کی زندگی ہے پس انصار اور مہاجرین کی مغفرت فرما۔“ یعنی درحقیقت جو مزہ ہے آخرت کا ہے مزہ۔۔۔ بخش دے انصار اور پردیسیوں کو اے اللہ۔۔۔ صحابہ نے اس کے جواب میں کہا ”ہم وہ ہیں جنہوں نے محمد صلی اللہ علیہ وسلم کے ہاتھ پر اس وقت تک جہاد کرنے کا عہد کیا ہے جب تک ہماری جان میں جان ہے۔“ اپنے پیغمبر محمد صلی اللہ علیہ وسلم سے یہ بیعت ہم نے کی جب تلک ہے زندگی۔۔۔ لڑتے رہیں گے ہم سدا۔' WHERE id = 2720;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ نے بیان کیا، کہا ہم سے ہمام نے بیان کیا، ان سے اسحاق بن عبداللہ نے اور ان سے انس بن مالک رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم مدینہ میں اپنی بیویوں کے سوا اور کسی کے گھر نہیں جایا کرتے تھے مگر ام سلیم کے پاس جاتے۔ آپ صلی اللہ علیہ وسلم سے جب اس کے متعلق پوچھا گیا تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ مجھے اس پر رحم آتا ہے، اس کا بھائی ( حرام بن ملحان ) میرے کام میں شہید کر دیا گیا۔' WHERE id = 2730;
UPDATE hadiths SET urdu = 'ہم سے محمد بن ابی بکر نے بیان کیا، کہا ہم سے فضیل بن سلیمان نے بیان کیا، ان سے ابوحازم نے، ان سے عبداللہ بن ابی قتادہ نے اور ان سے ان کے باپ نے کہ وہ نبی کریم صلی اللہ علیہ وسلم کے ساتھ ( صلح حدیبیہ کے موقع پر ) نکلے۔ ابوقتادہ رضی اللہ عنہ اپنے چند ساتھیوں کے ساتھ پیچھے رہ گئے تھے۔ ان کے دوسرے تمام ساتھی تو محرم تھے لیکن انہوں نے خود احرام نہیں باندھا تھا۔ ان کے ساتھیوں نے ایک گورخر دیکھا۔ ابوقتادہ رضی اللہ عنہ کے اس پر نظر پڑنے سے پہلے ان حضرات کی نظر اگرچہ اس پر پڑی تھی لیکن انہوں نے اسے چھوڑ دیا تھا لیکن ابوقتادہ رضی اللہ عنہ اسے دیکھتے ہی اپنے گھوڑے پر سوار ہوئے، ان کے گھوڑے کا نام جرادہ تھا، اس کے بعد انہوں نے ساتھیوں سے کہا کہ کوئی ان کا کوڑا اٹھا کر انہیں دیدے ( جسے لیے بغیر وہ سوار ہو گئے تھے ) ان لوگوں نے اس سے انکار کیا ( محرم ہونے کی وجہ سے ) اس لیے انہوں نے خود ہی لے لیا اور گورخر پر حملہ کر کے اس کی کونچیں کاٹ دیں انہوں نے خود بھی اس کا گوشت کھایا اور دوسرے ساتھیوں نے بھی کھایا پھر نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئے۔ جب یہ لوگ آپ صلی اللہ علیہ وسلم کے ساتھ ہو لیے آپ صلی اللہ علیہ وسلم نے پوچھا کہ کیا اس کا گوشت تمہارے پاس بچا ہوا باقی ہے؟ ابوقتادہ نے کہا کہ ہاں اس کی ایک ران ہمارے ساتھ باقی ہے۔ چنانچہ نبی کریم صلی اللہ علیہ وسلم نے بھی وہ گوشت کھایا۔ گھوڑے کا نام جرادہ تھا، ( اس سے باب کا مطلب ثابت ہوا ) ۔' WHERE id = 2740;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ نے بیان کیا، کہا ہم سے سہل بن یوسف نے بیان کیا، ان سے شعبہ نے، ان سے ابواسحاق نے کہ ایک شخص نے براء بن عازب رضی اللہ عنہ سے پوچھا کیا حنین کی لڑائی میں آپ لوگ رسول اللہ صلی اللہ علیہ وسلم کو چھوڑ کر چلے گئے تھے؟ براء رضی اللہ عنہ نے کہا ہاں لیکن رسول اللہ صلی اللہ علیہ وسلم اپنی جگہ پر ثابت قدم رہے۔ ہوازن کے لوگ ( جن سے اس لڑائی میں مقابلہ تھا ) بڑے تیرانداز تھے، جب ہمارا ان سے سامنا ہوا تو شروع میں ہم نے حملہ کر کے انہیں شکست دے دی، پھر مسلمان مال غنیمت پر ٹوٹ پڑے اور دشمن نے تیروں کی ہم پر بارش شروع کر دی پھر رسول اللہ صلی اللہ علیہ وسلم اپنی جگہ سے نہیں ہٹے۔ میں نے دیکھا کہ آپ صلی اللہ علیہ وسلم اپنے سفید خچر پر سوار تھے، ابوسفیان بن حارث بن عبدالمطلب رضی اللہ عنہ اس کی لگام تھامے ہوئے تھے اور آپ صلی اللہ علیہ وسلم یہ شعر فرما رہے تھے «أنا النبي لا كذب أنا ابن عبد المطلب» ”میں نبی ہوں اس میں جھوٹ کا کوئی دخل نہیں، میں عبدالمطلب کی اولاد ہوں۔“' WHERE id = 2750;
UPDATE hadiths SET urdu = 'ہم سے محمد بن مثنیٰ نے بیان کیا، کہا ہم سے یحییٰ بن سعید قطان نے بیان کیا، ان سے سفیان ثوری نے بیان کیا کہ مجھ سے ابواسحاق نے بیان کیا براء بن عازب رضی اللہ عنہ سے کہ ان سے ایک شخص نے پوچھا اے ابوعمارہ! کیا آپ لوگوں نے ( مسلمانوں کے لشکر نے ) حنین کی لڑائی میں پیٹھ پھیر لی تھی؟ انہوں نے فرمایا کہ نہیں اللہ گواہ ہے نبی کریم صلی اللہ علیہ وسلم نے پیٹھ نہیں پھیری تھی البتہ جلد باز لوگ ( میدان سے ) بھاگ پڑے تھے ( اور وہ لوٹ میں لگ گئے تھے ) قبیلہ ہوازن نے ان پر تیر برسانے شروع کر دئیے لیکن نبی کریم صلی اللہ علیہ وسلم اپنے سفید خچر پر سوار تھے اور ابوسفیان بن حارث اس کی لگام تھامے ہوئے تھے۔ نبی کریم صلی اللہ علیہ وسلم فرما رہے تھے «أنا النبي لا كذب أنا ابن عبد المطلب‏ ‏» میں نبی ہوں جس میں جھوٹ کا کوئی دخل نہیں۔ میں عبدالمطلب کی اولاد ہوں۔' WHERE id = 2760;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن یوسف نے بیان کیا، کہا ہم کو ابوبکر نے خبر دی، انہیں ابوحصین نے، انہیں ابوصالح اور انہیں ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”اشرفی کا بندہ، روپے کا بندہ، چادر کا بندہ، کمبل کا بندہ ہلاک ہوا کہ اگر اسے کچھ دے دیا جائے تب تو خوش ہو جاتا ہے اور اگر نہیں دیا جائے تو ناراض ہو جاتا ہے۔“ اس حدیث کو اسرائیل اور محمد بن جہادہ نے ابوحصین سے مرفوع نہیں کیا۔' WHERE id = 2771;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا ہم سے یعقوب بن عبدالرحمٰن نے بیان کیا، ان سے ابوحازم نے اور ان سے سہل بن سعد ساعدی رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم کی ( اپنے اصحاب کے ہمراہ احد یا خیبر کی لڑائی میں ) مشرکین سے مڈبھیڑ ہوئی اور جنگ چھڑ گئی، پھر جب آپ صلی اللہ علیہ وسلم ( اس دن لڑائی سے فارغ ہو کر ) اپنے پڑاؤ کی طرف واپس ہوئے اور مشرکین اپنے پڑاؤ کی طرف تو آپ صلی اللہ علیہ وسلم کی فوج کے ساتھ ایک شخص تھا، لڑائی لڑنے میں ان کا یہ حال تھا کہ مشرکین کا کوئی آدمی بھی اگر کسی طرف نظر آ جاتا تو اس کا پیچھا کر کے وہ شخص اپنی تلوار سے اسے قتل کر دیتا۔ سہل رضی اللہ عنہ نے اس کے متعلق کہا کہ آج جتنی سرگرمی کے ساتھ فلاں شخص لڑا ہے، ہم میں سے کوئی بھی شخص اس طرح نہ لڑ سکا۔ آپ صلی اللہ علیہ وسلم نے اس پر فرمایا کہ لیکن وہ شخص دوزخی ہے۔ مسلمانوں میں سے ایک شخص نے ( اپنے دل میں کہا اچھا میں اس کا پیچھا کروں گا ( دیکھوں ) نبی کریم صلی اللہ علیہ وسلم نے اسے کیوں دوزخی فرمایا ہے ) بیان کیا کہ وہ اس کے ساتھ ساتھ دوسرے دن لڑائی میں موجود رہا، جب کبھی وہ کھڑا ہو جاتا تو یہ بھی کھڑا ہو جاتا اور جب وہ تیز چلتا تو یہ بھی اس کے ساتھ تیز چلتا۔ بیان کیا کہ آخر وہ شخص زخمی ہو گیا زخم بڑا گہرا تھا۔ اس لیے اس نے چاہا کہ موت جلدی آ جائے اور اپنی تلوار کا پھل زمین پر رکھ کر اس کی دھار کو سینے کے مقابلہ میں کر لیا اور تلوار پر گر کر اپنی جان دے دی۔ اب وہ صاحب رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئے اور کہنے لگے کہ میں گواہی دیتا ہوں کہ آپ اللہ کے سچے رسول ہیں۔ آپ صلی اللہ علیہ وسلم نے دریافت فرمایا کہ کیا بات ہوئی؟ انہوں نے بیان کیا کہ وہی شخص جس کے متعلق آپ نے فرمایا تھا کہ وہ دوزخی ہے، صحابہ کرام رضی اللہ عنہم پر یہ آپ کا فرمان بڑا شاق گزرا تھا۔ میں نے ان سے کہا کہ تم سب لوگوں کی طرف سے میں اس کے متعلق تحقیق کرتا ہوں۔ چنانچہ میں اس کے پیچھے ہو لیا۔ اس کے بعد وہ شخص سخت زخمی ہوا اور چاہا کہ جلدی موت آ جائے۔ اس لیے اس نے اپنی تلوار کا پھل زمین پر رکھ کر اس کی دھار کو اپنے سینے کے مقابل کر لیا اور اس پر گر کر خود جان دے دی۔ اس وقت آپ صلی اللہ علیہ وسلم نے فرمایا کہ ایک آدمی زندگی بھر بظاہر اہل جنت کے سے کام کرتا ہے حالانکہ وہ اہل دوزخ میں سے ہوتا ہے اور ایک آدمی بظاہر اہل دوزخ کے کام کرتا ہے حالانکہ وہ اہل جنت میں سے ہوتا ہے۔' WHERE id = 2782;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، کہا کہ ہم کو شعیب نے خبر دی، ان سے زہری نے بیان کیا، کہا مجھ سے سنان بن ابی سنان الدولی اور ابوسلمہ بن عبدالرحمٰن نے بیان کیا اور انہیں جابر بن عبداللہ رضی اللہ عنہما نے خبر دی کہ وہ رسول اللہ صلی اللہ علیہ وسلم کے ساتھ نجد کے اطراف میں ایک غزوہ میں شریک تھے۔ جب رسول اللہ صلی اللہ علیہ وسلم جہاد سے واپس ہوئے تو آپ کے ساتھ یہ بھی واپس ہوئے۔ راستے میں قیلولہ کا وقت ایک ایسی وادی میں ہوا جس میں ببول کے درخت بکثرت تھے۔ رسول اللہ صلی اللہ علیہ وسلم نے اس وادی میں پڑاؤ کیا اور صحابہ پوری وادی میں ( درخت کے سائے کے لیے ) پھیل گئے۔ آپ صلی اللہ علیہ وسلم نے بھی ایک ببول کے نیچے قیام فرمایا اور اپنی تلوار درخت پر لٹکا دی۔ ہم سب سو گئے تھے کہ رسول اللہ صلی اللہ علیہ وسلم کے پکارنے کی آواز سنائی دی، دیکھا گیا تو ایک بدوی آپ صلی اللہ علیہ وسلم کے پاس تھا۔ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ اس نے غفلت میں میری ہی تلوار مجھ پر کھینچ لی تھی اور میں سویا ہوا تھا، جب بیدار ہوا تو ننگی تلوار اس کے ہاتھ میں تھی۔ اس نے کہا مجھ سے تمہیں کون بچائے گا؟ میں نے کہا کہ اللہ! تین مرتبہ ( میں نے اسی طرح کہا اور تلوار اس کے ہاتھ سے چھوٹ کر گر گئی ) رسول اللہ صلی اللہ علیہ وسلم نے اعرابی کو کوئی سزا نہیں دی بلکہ آپ صلی اللہ علیہ وسلم بیٹھ گئے ( پھر وہ خود متاثر ہو کر اسلام لایا ) ۔' WHERE id = 2793;
UPDATE hadiths SET urdu = 'ہم سے ابوالولید نے بیان کیا، کہا ہم سے ہمام نے بیان کیا، ان سے قتادہ نے اور ان سے انس رضی اللہ عنہ نے، دوسری سند ہم سے محمد بن سنان نے بیان کیا ان سے قتادۃ نے ان سے انس نے کہ عبدالرحمٰن بن عوف اور زبیر بن عوام رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم سے جوؤں کی شکایت کی تو رسول اللہ صلی اللہ علیہ وسلم نے انہیں ریشمی کپڑے کے استعمال کی اجازت دے دی، پھر میں نے جہاد میں انہیں ریشمی کپڑا پہنے ہوئے دیکھا۔' WHERE id = 2803;
UPDATE hadiths SET urdu = 'ہم سے عمرو بن خالد نے بیان کیا، کہا ہم سے زہیر نے بیان کیا، ان سے ابواسحاق نے بیان کیا، کہا کہ میں نے براء بن عازب رضی اللہ عنہ سے سنا، ان سے ایک صاحب نے پوچھا تھا کہ ابوعمارہ! کیا آپ لوگوں نے حنین کی لڑائی میں فرار اختیار کیا تھا؟ براء رضی اللہ عنہ نے کہا نہیں اللہ کی قسم، رسول اللہ صلی اللہ علیہ وسلم نے پشت ہرگز نہیں پھیری تھی۔ البتہ آپ صلی اللہ علیہ وسلم کے اصحاب میں جو نوجوان تھے بے سروسامان جن کے پاس نہ زرہ تھی، نہ خود اور کوئی ہتھیار بھی نہیں لے گئے تھے، انہوں نے ضرور میدان چھوڑ دیا تھا کیونکہ مقابلہ میں ہوازن اور بنو نصر کے بہترین تیرانداز تھے کہ کم ہی ان کا کوئی تیر خطا جاتا۔ چنانچہ انہوں نے خوب تیر برسائے اور شاید ہی کوئی نشانہ ان کا خطا ہوا ہو ( اس دوران میں مسلمان ) نبی کریم صلی اللہ علیہ وسلم کے پاس آ کر جمع ہو گئے۔ آپ صلی اللہ علیہ وسلم اپنے سفید خچر پر سوار تھے اور آپ صلی اللہ علیہ وسلم کے چچیرے بھائی ابوسفیان بن حارث ابن عبدالمطلب آپ صلی اللہ علیہ وسلم کی سواری کی لگام تھامے ہوئے تھے۔ آپ صلی اللہ علیہ وسلم نے سواری سے اتر کر اللہ تعالیٰ سے مدد کی دعا مانگی۔ پھر فرمایا: «أنا النبي لا كذب أنا ابن عبد المطلب» ”میں نبی ہوں اس میں غلط بیانی کا کوئی شائبہ نہیں، میں عبدالمطلب کی اولاد ہوں۔“ اس کے بعد آپ صلی اللہ علیہ وسلم نے اپنے اصحاب کی ( نئے طریقے پر ) صف بندی کی۔' WHERE id = 2813;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن مسلمہ قعنبی نے بیان کیا، کہا ہم سے عبدالعزیز بن ابی حازم نے بیان کیا، ان سے ان کے والد نے، ان سے سہل بن سعد ساعدی رضی اللہ عنہ نے اور انہوں نے نبی کریم صلی اللہ علیہ وسلم سے سنا، آپ صلی اللہ علیہ وسلم نے خیبر کی لڑائی کے دن فرمایا تھا کہ اسلامی جھنڈا میں ایک ایسے شخص کے ہاتھ میں دوں گا جس کے ذریعہ اللہ تعالیٰ فتح عنایت فرمائے گا۔ اب سب اس انتظار میں تھے کہ دیکھئیے جھنڈا کسے ملتا ہے، جب صبح ہوئی تو سب سرکردہ لوگ اسی امید میں رہے کہ کاش! انہیں کو مل جائے لیکن آپ صلی اللہ علیہ وسلم نے دریافت فرمایا: علی کہاں ہیں؟ عرض کیا گیا کہ وہ آنکھوں کے درد میں مبتلا ہیں، آخر آپ صلی اللہ علیہ وسلم کے حکم سے انہیں بلایا گیا۔ آپ صلی اللہ علیہ وسلم نے اپنا لعاب دہن مبارک ان کی آنکھوں میں لگا دیا اور فوراً ہی وہ اچھے ہو گئے۔ جیسے پہلے کوئی تکلیف ہی نہ رہی ہو۔ علی رضی اللہ عنہ نے کہا ہم ان ( یہودیوں سے ) اس وقت تک جنگ کریں گے جب تک یہ ہمارے جیسے ( مسلمان ) نہ ہو جائیں۔ لیکن آپ صلی اللہ علیہ وسلم نے فرمایا: ابھی ٹھہرو پہلے ان کے میدان میں اتر کر انہیں تم اسلام کی دعوت دے لو اور ان کے لیے جو چیز ضروری ہیں ان کی خبر کر دو ( پھر وہ نہ مانیں تو لڑنا ) اللہ کی قسم! اگر تمہارے ذریعہ ایک شخص کو بھی ہدایت مل جائے تو یہ تمہارے حق میں سرخ اونٹوں سے بہتر ہے۔' WHERE id = 2824;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن مسلمہ نے بیان کیا امام مالک سے، ان سے یحییٰ بن سعید نے، ان سے عمرہ بنت عبدالرحمٰن نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ مدینہ سے ( حجۃ الوداع کے لیے ) رسول اللہ صلی اللہ علیہ وسلم کے ساتھ ہم اس وقت نکلے جب ذی قعدہ کے پانچ دن باقی تھے۔ ہفتہ کے دن ہمارا مقصد حج کے سوا اور کچھ بھی نہ تھا۔ جب ہم مکہ سے قریب ہوئے تو رسول اللہ صلی اللہ علیہ وسلم نے حکم فرمایا کہ جس کے ساتھ قربانی کا جانور نہ ہو جب وہ بیت اللہ کے طواف اور صفا اور مروہ کی سعی سے فارغ ہو جائے تو احرام کھول دے۔ ( پھر حج کے لیے بعد میں احرام باندھے ) عائشہ رضی اللہ عنہا نے کہا کہ دسویں ذی الحجہ کو ہمارے یہاں گائے کا گوشت آیا، میں نے پوچھا کہ گوشت کیسا ہے؟ تو بتایا گیا کہ رسول اللہ صلی اللہ علیہ وسلم نے اپنی بیویوں کی طرف سے جو گائے قربانی کی ہے یہ اسی کا گوشت ہے۔ یحییٰ نے بیان کیا کہ میں نے اس کے بعد اس حدیث کا ذکر قاسم بن محمد سے کیا تو انہوں نے بتایا کہ قسم اللہ کی! عمرہ بنت عبدالرحمٰن نے تم سے یہ حدیث ٹھیک ٹھیک بیان کی ہے۔' WHERE id = 2834;
UPDATE hadiths SET urdu = 'ہم سے اسحاق بن ابراہیم نے بیان کیا، کہا ہم کو جریر نے خبر دی، انہیں مغیرہ نے، انہیں شعبی نے اور ان سے جابر بن عبداللہ رضی اللہ عنہما نے بیان کیا کہ میں رسول اللہ صلی اللہ علیہ وسلم کے ساتھ ایک غزوہ ( جنگ تبوک ) میں شریک تھا۔ انہوں نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم پیچھے سے آ کر میرے پاس تشریف لائے۔ میں اپنے پانی لادنے والے ایک اونٹ پر سوار تھا۔ چونکہ وہ تھک چکا تھا، اس لیے آہستہ آہستہ چل رہا تھا۔ آپ صلی اللہ علیہ وسلم نے مجھ سے دریافت فرمایا کہ جابر! تمہارے اونٹ کو کیا ہو گیا ہے؟ میں نے عرض کیا کہ تھک گیا ہے۔ جابر رضی اللہ عنہ نے بیان کیا کہ پھر آپ صلی اللہ علیہ وسلم پیچھے گئے اور اسے ڈانٹا اور اس کے لیے دعا کی۔ پھر تو وہ برابر دوسرے اونٹوں کے آگے آگے چلتا رہا۔ پھر آپ صلی اللہ علیہ وسلم نے دریافت فرمایا، اپنے اونٹ کے متعلق کیا خیال ہے؟ میں نے کہا کہ اب اچھا ہے۔ آپ کی برکت سے ایسا ہو گیا ہے۔ آپ صلی اللہ علیہ وسلم نے فرمایا پھر کیا اسے بیچو گے؟ انہوں نے بیان کیا کہ میں شرمندہ ہو گیا، کیونکہ ہمارے پاس پانی لانے کو اس کے سوا اور کوئی اونٹ نہیں رہا تھا۔ مگر میں نے عرض کیا، جی ہاں! آپ صلی اللہ علیہ وسلم نے فرمایا پھر بیچ دے۔ چنانچہ میں نے وہ اونٹ آپ صلی اللہ علیہ وسلم کو بیچ دیا اور یہ طے پایا کہ مدینہ تک میں اسی پر سوار ہو کر جاؤں گا۔ بیان کیا کہ میں نے عرض کیا، یا رسول اللہ! میری شادی ابھی نئی ہوئی ہے۔ میں نے آپ صلی اللہ علیہ وسلم سے ( آگے بڑھ کر اپنے گھر جانے کی ) اجازت چاہی تو آپ صلی اللہ علیہ وسلم نے اجازت عنایت فرما دی۔ اس لیے میں سب سے پہلے مدینہ پہنچ آیا۔ جب ماموں سے ملاقات ہوئی تو انہوں نے مجھ سے اونٹ کے متعلق پوچھا۔ جو معاملہ میں کر چکا تھا اس کی انہیں اطلاع دی۔ تو انہوں نے مجھے برا بھلا کہا۔ ( ایک اونٹ تھا تیرے پاس وہ بھی بیچ ڈالا اب پانی کس پر لائے گا ) جب میں نے نبی کریم صلی اللہ علیہ وسلم سے اجازت چاہی تھی تو آپ صلی اللہ علیہ وسلم نے مجھ سے دریافت فرمایا تھا کہ کنواری سے شادی کی ہے یا بیوہ سے؟ میں نے عرض کیا تھا بیوہ سے اس پر آپ صلی اللہ علیہ وسلم نے فرمایا تھا کہ باکرہ سے کیوں نہ کی، وہ بھی تمہارے ساتھ کھیلتی اور تم بھی اس کے ساتھ کھیلتے۔ ( کیونکہ جابر رضی اللہ عنہ بھی ابھی کنوارے تھے ) میں نے کہا یا رسول اللہ! میرے باپ کی وفات ہو گئی ہے یا ( یہ کہا کہ ) وہ ( احد ) میں شہید ہو چکے ہیں اور میری چھوٹی چھوٹی بہنیں ہیں۔ اس لیے مجھے اچھا نہیں معلوم ہوا کہ انہیں جیسی کسی لڑکی کو بیاہ کے لاؤں، جو نہ انہیں ادب سکھا سکے نہ ان کی نگرانی کر سکے۔ اس لیے میں نے بیوہ سے شادی کی تاکہ وہ ان کی نگرانی کرے اور انہیں ادب سکھائے۔ انہوں نے بیان کیا، پھر جب نبی کریم صلی اللہ علیہ وسلم مدینہ پہنچے تو صبح کے وقت میں اسی اونٹ پر آپ صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوا۔ آپ صلی اللہ علیہ وسلم نے مجھے اس اونٹ کی قیمت عطا فرمائی اور پھر وہ اونٹ بھی واپس کر دیا۔ مغیرہ راوی رحمہ اللہ نے کہا کہ ہمارے نزدیک بیع میں یہ شرط لگانا اچھا ہے کچھ برا نہیں۔' WHERE id = 2846;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، کہا ہم سے لیث نے بیان کیا، ان سے عقیل نے، ان سے ابن شہاب نے، ان سے سعید بن مسیب نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا۔ مجھے جامع کلام ( جس کی عبارت مختصر اور فصیح و بلیغ ہو اور معنی بہت وسیع ہوں ) دے کر بھیجا گیا ہے اور رعب کے ذریعہ میری مدد کی گئی ہے۔ میں سویا ہوا تھا کہ زمین کے خزانوں کی کنجیاں میرے پاس لائی گئیں اور میرے ہاتھ پر رکھ دی گئیں۔ ابوہریرہ رضی اللہ عنہ نے فرمایا کہ رسول اللہ صلی اللہ علیہ وسلم تو ( اپنے رب کے پاس ) جا چکے۔ اور ( جن خزانوں کی وہ کنجیاں تھیں ) انہیں اب تم نکال رہے ہو۔' WHERE id = 2856;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا ہم سے ابوصفوان نے بیان کیا، ان سے یونس بن یزید نے، ان سے ابن شہاب نے، ان سے عروہ نے، ان سے اسامہ بن زید رضی اللہ عنہما نے کہ رسول اللہ صلی اللہ علیہ وسلم ایک گدھے پر اس کی پالان رکھ کر سوار ہوئے۔ جس پر ایک چادر بچھی ہوئی تھی اور اسامہ رضی اللہ عنہ کو آپ نے اپنے پیچھے بٹھا رکھا تھا۔' WHERE id = 2866;
UPDATE hadiths SET urdu = 'ہم سے حمیدی نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے، کہا کہ ہم سے محمد بن منکدر نے بیان کیا، کہا کہ میں نے جابر بن عبداللہ رضی اللہ عنہما سے سنا، وہ بیان کرتے تھے کہ نبی کریم صلی اللہ علیہ وسلم نے ( ایک کام کے لیے ) غزوہ خندق کے موقع پر صحابہ کو پکارا، تو زبیر رضی اللہ عنہ نے اس کے لیے کہا کہ میں حاضر ہوں۔ پھر آپ صلی اللہ علیہ وسلم نے صحابہ کو پکارا، اور اس مرتبہ بھی زبیر رضی اللہ عنہ نے اپنے کو پیش کیا، آپ صلی اللہ علیہ وسلم نے پھر پکارا اور پھر زبیر رضی اللہ عنہ نے اپنے آپ کو پیش کیا، رسول اللہ صلی اللہ علیہ وسلم نے آخر فرمایا کہ ہر نبی کے حواری ہوتے ہیں اور میرے حواری زبیر ہیں۔ سفیان نے کہا کہ حواری کے معنی معاون، مددگار کے ہیں ( یا وفادار محرم راز کو حواری کہا گیا ہے ) ۔' WHERE id = 2876;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ نے بیان کیا ‘ کہا ہم سے سفیان بن عیینہ نے بیان کیا ‘ کہا ہم سے عمرو بن دینار نے بیان کیا ‘ سفیان نے یہ حدیث عمرو بن دینار سے دو مرتبہ سنی تھی۔ انہوں نے بیان کیا کہ مجھے حسن بن محمد نے خبر دی ‘ کہا کہ مجھے عبیداللہ بن ابی رافع نے خبر دی ‘ کہا کہ میں نے علی رضی اللہ عنہ سے سنا ‘ آپ بیان کرتے تھے کہ رسول اللہ صلی اللہ علیہ وسلم نے مجھے، زبیر اور مقداد بن اسود ( رضی اللہ عنہم ) کو ایک مہم پر بھیجا اور آپ صلی اللہ علیہ وسلم نے فرمایا کہ جب تم لوگ روضہ خاخ ( جو مدینہ سے بارہ میل کے فاصلہ پر ایک جگہ کا نام ہے ) پر پہنچ جاؤ تو وہاں ایک بڑھیا عورت تمہیں اونٹ پر سوار ملے گی اور اس کے پاس ایک خط ہو گا ‘ تم لوگ اس سے وہ خط لے لینا۔ ہم روانہ ہوئے اور ہمارے گھوڑے ہمیں تیزی کے ساتھ لیے جا رہے تھے۔ آخر ہم روضہ خاخ پر پہنچ گئے اور وہاں واقعی ایک بوڑھی عورت موجود تھی جو اونٹ پر سوار تھی۔ ہم نے اس سے کہا کہ خط نکال۔ اس نے کہا کہ میرے پاس تو کوئی خط نہیں۔ لیکن جب ہم نے اسے دھمکی دی کہ اگر تو نے خط نہ نکالا تو تمہارے کپڑے ہم خود اتار دیں گے۔ اس پر اس نے اپنی گندھی ہوئی چوٹی کے اندر سے خط نکال کر دیا ‘ اور ہم اسے رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں لے کر حاضر ہوئے ‘ اس کا مضمون یہ تھا ‘ حاطب بن ابی بلتعہ کی طرف سے مشرکین مکہ کے چند آدمیوں کی طرف ‘ اس میں انہوں نے رسول اللہ صلی اللہ علیہ وسلم کے بعض بھیدوں کی خبر دی تھی۔ آپ صلی اللہ علیہ وسلم نے فرمایا: اے حاطب! یہ کیا واقعہ ہے؟ انہوں نے عرض کیا: یا رسول اللہ! میرے بارے میں عجلت سے کام نہ لیجئے۔ میری حیثیت ( مکہ میں ) یہ تھی کہ قریش کے ساتھ میں نے رہنا سہنا اختیار کر لیا تھا ‘ ان سے رشتہ ناتہ میرا کچھ بھی نہ تھا۔ آپ کے ساتھ جو دوسرے مہاجرین ہیں ان کی تو مکہ میں سب کی رشتہ داری ہے اور مکہ والے اسی وجہ سے ان کے عزیزوں کی اور ان کے مالوں کی حفاظت و حمایت کریں گے مگر مکہ والوں کے ساتھ میرا کوئی نسبی تعلق نہیں ہے ‘ اس لیے میں نے سوچا کہ ان پر کوئی احسان کر دوں جس سے اثر لے کر وہ میرے بھی عزیزوں کی مکہ میں حفاظت کریں۔ میں نے یہ کام کفر یا ارتداد کی وجہ سے ہرگز نہیں کیا ہے اور نہ اسلام کے بعد کفر سے خوش ہو کر۔ رسول اللہ صلی اللہ علیہ وسلم نے سن کر فرمایا کہ حاطب نے سچ کہا ہے۔ عمر رضی اللہ عنہ نے کہا: یا رسول اللہ! اجازت دیجئیے میں اس منافق کا سر اڑا دوں ‘ آپ صلی اللہ علیہ وسلم نے فرمایا ”نہیں ‘ یہ بدر کی لڑائی میں ( مسلمانوں کے ساتھ مل کر ) لڑے ہیں اور تمہیں معلوم نہیں ‘ اللہ تعالیٰ مجاہدین بدر کے احوال ( موت تک کے ) پہلے ہی سے جانتا تھا ‘ اور وہ خود ہی فرما چکا ہے کہ تم جو چاہو کرو میں تمہیں معاف کر چکا ہوں۔“ سفیان بن عیینہ نے کہا کہ حدیث کی یہ سند بھی کتنی عمدہ ہے۔' WHERE id = 2886;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ نے بیان کیا ‘ کہا ہم سے سفیان نے بیان کیا ‘ ان سے ایوب نے ‘ ان سے عکرمہ نے کہ علی رضی اللہ عنہ نے ایک قوم کو ( جو عبداللہ بن سبا کی متبع تھی اور علی رضی اللہ عنہ کو اپنا رب کہتی تھی ) جلا دیا تھا۔ جب یہ خبر عبداللہ بن عباس رضی اللہ عنہما کو ملی تو آپ نے کہا کہ اگر میں ہوتا تو کبھی انہیں نہ جلاتا کیونکہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ہے کہ اللہ کے عذاب کی سزا کسی کو نہ دو ‘ البتہ میں انہیں قتل ضرور کرتا کیونکہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ہے جو شخص اپنا دین تبدیل کر دے اسے قتل کر دو۔' WHERE id = 2896;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا ‘ کہا ہم سے سفیان بن عیینہ نے ‘ ان سے عمرو بن دینار نے اور ان سے جابر بن عبداللہ رضی اللہ عنہما نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”کعب بن اشرف کا کام کون تمام کرے گا؟ وہ اللہ اور اس کے رسول کو بہت اذیتیں پہنچا چکا ہے۔“ محمد بن مسلمہ رضی اللہ عنہ نے عرض کیا: یا رسول اللہ! کیا آپ مجھے اجازت بخش دیں گے کہ میں اسے قتل کر آؤں؟ آپ صلی اللہ علیہ وسلم نے فرمایا ”ہاں۔“ راوی نے بیان کیا کہ پھر محمد بن مسلمہ کعب یہودی کے پاس آئے اور اس سے کہنے لگے کہ نبی کریم صلی اللہ علیہ وسلم نے تو ہمیں تھکا دیا ‘ اور ہم سے آپ زکوٰۃ مانگتے ہیں۔ کعب نے کہا کہ قسم اللہ کی! ابھی کیا ہے ابھی اور مصیبت میں پڑو گے۔ محمد بن مسلمہ رضی اللہ عنہ اس پر کہنے لگے کہ بات یہ ہے کہ ہم نے ان کی پیروی کر لی ہے۔ اس لیے اس وقت تک اس کا ساتھ چھوڑنا ہم مناسب بھی نہیں سمجھتے جب تک ان کی دعوت کا کوئی انجام ہمارے سامنے نہ آ جائے۔ غرض محمد بن مسلمہ رضی اللہ عنہ اس سے اسی طرح باتیں کرتے رہے۔ آخر موقع پا کر اسے قتل کر دیا۔' WHERE id = 2908;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا ‘ کہا ہم سے شعبہ نے بیان کیا ‘ ان سے سعد بن ابراہیم نے ‘ ان سے ابوامامہ نے ‘ جو سہل بن حنیف کے لڑکے تھے کہ ابو سعید خدری رضی اللہ عنہ نے بیان کیا جب بنو قریظہ سعد بن معاذ رضی اللہ عنہ کی ثالثی کی شرط پر ہتھیار ڈال کر قلعہ سے اتر آئے تو رسول اللہ صلی اللہ علیہ وسلم نے انہیں ( سعد رضی اللہ عنہ کو ) بلایا۔ آپ وہیں قریب ہی ایک جگہ ٹھہرے ہوئے تھے ( کیونکہ زخمی تھے ) سعد رضی اللہ عنہ گدھے پر سوار ہو کر آئے ‘ جب وہ آپ کے قریب پہنچے تو آپ صلی اللہ علیہ وسلم نے فرمایا ‘ اپنے سردار کی طرف کھڑے ہو جاؤ ( اور ان کو سواری سے اتارو ) آخر آپ اتر کر آپ صلی اللہ علیہ وسلم کے قریب آ کر بیٹھ گئے۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ ان لوگوں ( بنو قریظہ کے یہودی ) نے آپ کی ثالثی کی شرط پر ہتھیار ڈال دیئے ہیں۔ ( اس لیے آپ ان کا فیصلہ کر دیں ) انہوں نے کہا کہ پھر میرا فیصلہ یہ ہے کہ ان میں جتنے آدمی لڑنے والے ہیں ‘ انہیں قتل کر دیا جائے ‘ اور ان کی عورتوں اور بچوں کو غلام بنا لیا جائے۔ آپ صلی اللہ علیہ وسلم نے فرمایا تو نے اللہ تعالیٰ کے حکم کے مطابق فیصلہ کیا ہے۔' WHERE id = 2919;
UPDATE hadiths SET urdu = 'ہم سے قبیصہ نے بیان کیا ‘ کہا ہم سے سفیان بن عیینہ نے بیان کیا ‘ ان سے سلیمان احول نے ‘ ان سے سعید بن جبیر نے اور ان سے ابن عباس رضی اللہ عنہما نے بیان کیا کہ جمعرات کے دن ‘ اور معلوم ہے جمعرات کا دن کیا ہے؟ پھر آپ اتنا روئے کہ کنکریاں تک بھیگ گئیں۔ آخر آپ نے کہا کہ رسول اللہ صلی اللہ علیہ وسلم کی بیماری میں شدت اسی جمعرات کے دن ہوئی تھی۔ تو آپ صلی اللہ علیہ وسلم نے صحابہ سے فرمایا کہ قلم دوات لاؤ ‘ تاکہ میں تمہارے لیے ایک ایسی کتاب لکھوا جاؤں کہ تم ( میرے بعد اس پر چلتے رہو تو ) کبھی گمراہ نہ ہو سکو اس پر صحابہ میں اختلاف ہو گیا۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ نبی کے سامنے جھگڑنا مناسب نہیں ہے۔ صحابہ نے کہا کہ نبی کریم صلی اللہ علیہ وسلم ( بیماری کی شدت سے ) ہیں۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ اچھا ‘ اب مجھے میری حالت پر چھوڑ دو ‘ میں جس حال میں اس وقت ہوں وہ اس سے بہتر ہے جو تم کرانا چاہتے ہو۔ آخر آپ صلی اللہ علیہ وسلم نے اپنی وفات کے وقت تین وصیتیں فرمائی تھیں۔ یہ مشرکین کو جزیرہ عرب سے باہر کر دینا۔ دوسرے یہ کہ وفود سے ایسا ہی سلوک کرتے رہنا ‘ جیسے میں کرتا رہا ( ان کی خاطرداری ضیافت وغیرہ ) اور تیسری ہدایت میں بھول گیا۔ اور یعقوب بن محمد نے بیان کیا کہ میں نے مغیرہ بن عبدالرحمٰن سے جزیرہ عرب کے بارے میں پوچھا تو انہوں نے فرمایا کہا مکہ ‘ مدینہ ‘ یمامہ اور یمن ( کا نام جزیرہ عرب ) ہے۔ اور یعقوب نے کہا کہ عرج سے تہامہ شروع ہوتا ہے ( عرج مکہ اور مدینہ کے راستے میں ایک منزل کا نام ہے ) ۔' WHERE id = 2929;
UPDATE hadiths SET urdu = 'ہم سے محمد بن بشار نے بیان کیا ‘ کہا ہم سے محمد بن ابی عدی اور سہل بن یوسف نے بیان کیا ‘ ان سے سعید بن ابی عروبہ نے ‘ ان سے قتادہ نے اور ان سے انس رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم کی خدمت میں رعل ‘ ذکوان ‘ عصیہ اور بنو لحیان قبائل کے کچھ لوگ آئے اور یقین دلایا کہ وہ لوگ اسلام لا چکے ہیں اور انہوں نے اپنی کافر قوم کے مقابل امداد اور تعلیم و تبلیغ کے لیے آپ سے مدد چاہی۔ تو نبی کریم صلی اللہ علیہ وسلم نے ستر انصاریوں کو ان کے ساتھ کر دیا۔ انس رضی اللہ عنہ نے بیان کیا ‘ کہ ہم انہیں قاری کہا کرتے تھے۔ وہ لوگ دن میں جنگل سے لکڑیاں جمع کرتے اور رات میں نماز پڑھتے رہتے۔ یہ حضرات ان قبیلہ والوں کے ساتھ چلے گئے ‘ لیکن جب بئرمعونہ پر پہنچے تو انہیں قبیلہ والوں نے ان صحابہ کے ساتھ دغا کی اور انہیں شہید کر ڈالا۔ نبی کریم صلی اللہ علیہ وسلم نے ایک مہینہ تک ( نماز میں ) قنوت پڑھی اور رعل و ذکوان اور بنو لحیان کے لیے بددعا کرتے رہے۔ قتادہ نے کہا کہ ہم سے انس رضی اللہ عنہ نے کہا کہ ( ان شہداء کے بارے میں ) قرآن مجید میں ہم یہ آیت یوں پڑھتے رہے ”ہاں! ہماری قوم ( مسلم ) کو بتا دو کہ ہم اپنے رب سے جا ملے۔ اور وہ ہم سے راضی ہو گیا ہے اور ہمیں بھی اس نے خوش کیا ہے۔“ پھر یہ آیت منسوخ ہو گئی تھی۔' WHERE id = 2939;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ نے بیان کیا ‘ کہا ہم سے سفیان ثوری نے بیان کیا ‘ ان سے عمرو نے ‘ ان سے سالم بن ابی الجعد نے ‘ ان سے عبداللہ بن عمرو رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم کے سامان و اسباب پر ایک صاحب مقرر تھے ‘ جن کا نام کرکرہ تھا۔ ان کا انتقال ہو گیا ‘ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ وہ تو جہنم میں گیا۔ صحابہ انہیں دیکھنے گئے تو ایک عباء جسے خیانت کر کے انہوں نے چھپا لیا تھا ان کے یہاں ملی۔ ابوعبداللہ ( امام بخاری رحمہ اللہ ) نے کہا کہ محمد بن سلام نے ( ابن عیینہ سے نقل کیا اور ) کہا یہ لفظ «كركرة» بفتح کاف ہے اور اسی طرح منقول ہے۔' WHERE id = 2949;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ مدینی نے بیان کیا ‘ کہا ہم سے بشر بن مفضل نے بیان کیا ‘ کہا ہم سے یحییٰ بن ابی اسحاق نے بیان کیا اور ان سے انس بن مالک رضی اللہ عنہ نے بیان کیا کہ وہ اور ابوطلحہ رضی اللہ عنہ نبی کریم صلی اللہ علیہ وسلم کے ساتھ تھے، ام المؤمنین صفیہ رضی اللہ عنہا کو آپ صلی اللہ علیہ وسلم نے اپنی سواری پر پیچھے بٹھا رکھا تھا۔ راستے میں اتفاق سے آپ کی اونٹنی پھسل گئی اور آپ صلی اللہ علیہ وسلم گر گئے اور ام المؤمنین بھی گر گئیں۔ ابوطلحہ رضی اللہ عنہ نے یوں کہا کہ میں سمجھتا ہوں ‘ انہوں نے اپنے آپ کو اونٹ سے گرا دیا اور آپ صلی اللہ علیہ وسلم کے قریب پہنچ کر عرض کیا: اے اللہ کے رسول! اللہ مجھے آپ پر قربان کرے کوئی چوٹ تو آپ کو نہیں آئی؟ آپ صلی اللہ علیہ وسلم نے فرمایا کہ نہیں لیکن تم عورت کی خبر لو۔ چنانچہ انہوں نے ایک کپڑا اپنے چہرے پر ڈال لیا ‘ پھر ام المؤمنین کی طرف بڑھے اور وہی کپڑا ان پر ڈال دیا۔ اب ام المؤمنین کھڑی ہو گئیں۔ پھر ابوطلحہ رضی اللہ عنہ نے آپ دونوں کے لیے اونٹنی کو مضبوط کیا۔ تو آپ سوار ہوئے اور سفر شروع کیا۔ جب مدینہ منورہ کے سامنے پہنچ گئے یا راوی نے یہ کہا کہ جب مدینہ دکھائی دینے لگا تو نبی کریم صلی اللہ علیہ وسلم نے یہ دعا پڑھی «آيبون تائبون عابدون لربنا حامدون‏ ‏‏.‏» ”ہم اللہ کی طرف لوٹنے والے ہیں۔ توبہ کرنے والے ‘ اپنے رب کی عبادت کرنے والے اور اس کی تعریف کرنے والے ہیں!“ آپ صلی اللہ علیہ وسلم یہ دعا برابر پڑھتے رہے ‘ یہاں تک کی مدینہ میں داخل ہو گئے۔' WHERE id = 2960;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا ‘ کہا ہم سے یحییٰ قطان نے بیان کیا ‘ ان سے سفیان ثوری نے ‘ کہا کہ مجھ سے ابواسحاق نے بیان کیا ‘ کہا کہ میں نے عمرو بن حارث سے سنا ‘ وہ کہتے تھے کہ نبی کریم صلی اللہ علیہ وسلم نے ( اپنی وفات کے بعد ) اپنے ہتھیار ‘ ایک سفید خچر ‘ اور ایک زمین جسے آپ خود صدقہ کر گئے تھے ‘ کے سوا اور کوئی ترکہ نہیں چھوڑا تھا۔' WHERE id = 2971;
UPDATE hadiths SET urdu = 'مجھ سے محمد بن بشار نے بیان کیا ‘ کہا ہم سے عبدالوہاب ثقفی نے بیان کیا ‘ کہا ہم سے ایوب سختیانی نے بیان کیا ‘ ان سے حمید بن ہلال نے اور ان سے ابوبردہ بن ابوموسیٰ نے بیان کیا کہا عائشہ رضی اللہ عنہا نے ہمیں ایک پیوند لگی ہوئی چادر نکال کر دکھائی اور بتلایا کہ اسی کپڑے میں نبی کریم صلی اللہ علیہ وسلم کی روح قبض ہوئی تھی۔ اور سلیمان بن مغیرہ نے حمید سے بیان کیا ‘ انہوں نے ابوبردہ سے اتنا زیادہ بیان کیا کہ عائشہ رضی اللہ عنہا نے یمن کی بنی ہوئی ایک موٹی ازار ( تہمد ) اور ایک کمبل انہیں کمبلوں میں سے جن کو تم ملبہ ( اور موٹا پیوند دار کہتے ہو ) ہمیں نکال کر دکھائی۔' WHERE id = 2981;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یزید نے بیان کیا ‘ انہوں نے کہا کہ ہم سے سعید بن ابی ایوب نے بیان کیا ‘ انہوں نے کہا کہ مجھ سے ابوالاسود نے بیان کیا ‘ ان سے ابن ابی عیاش نے بیان کیا اور ان کا نام نعمان تھا ‘ ان سے خولہ بنت قیس انصاریہ رضی اللہ عنہا نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم سے میں نے سنا ‘ آپ صلی اللہ علیہ وسلم فرما رہے تھے کچھ لوگ اللہ تعالیٰ کے مال کو بے جا اڑاتے ہیں ‘ انہیں قیامت کے دن آگ ملے گی۔' WHERE id = 2991;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن ابی الاسود نے بیان کیا ‘ کہا ہم سے معتمر نے بیان کیا ‘ ان سے ان کے باپ سلیمان نے ‘ انہوں نے انس بن مالک رضی اللہ عنہ سے سنا ‘ انہوں نے بیان کیا کہ صحابہ ( انصار ) کچھ کھجور کے درخت نبی کریم صلی اللہ علیہ وسلم کی خدمت میں بطور تحفہ دے دیا کرتے تھے لیکن جب اللہ تعالیٰ نے بنو قریظہ اور بنو نضیر کے قبائل پر فتح دی تو نبی کریم صلی اللہ علیہ وسلم اس کے بعد اس طرح کے ہدایا واپس فرما دیا کرتے تھے۔' WHERE id = 3001;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، انہوں نے کہا ہم سے لیث نے بیان کیا، ان سے عقیل نے بیان کیا، ان سے ابن شہاب نے بیان کیا، ان سے ابن مسیب نے بیان کیا اور ان سے جبیر بن مطعم رضی اللہ عنہ نے بیان کیا کہ میں اور عثمان بن عفان رضی اللہ عنہ رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئے اور عرض کیا، یا رسول اللہ! آپ نے بنو مطلب کو تو عنایت فرمایا لیکن ہم کو چھوڑ دیا، حالانکہ ہم کو آپ سے وہی رشتہ ہے جو بنو مطلب کو آپ سے ہے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ بنو مطلب اور بنو ہاشم ایک ہی ہے۔ لیث نے بیان کیا کہ مجھ سے یونس نے بیان کیا اور ( اس روایت میں ) یہ زیادتی کی کہ جبیر رضی اللہ عنہ نے کہا نبی کریم صلی اللہ علیہ وسلم نے بنو عبدشمس اور بنو نوفل کو نہیں دیا تھا، اور ابن اسحاق ( صاحب مغازی ) نے کہا ہے کہ عبدشمس، ہاشم اور مطلب ایک ماں سے تھے اور ان کی ماں کا نام عاتکہ بن مرہ تھا اور نوفل باپ کی طرف سے ان کے بھائی تھے ( ان کی ماں دوسری تھیں ) ۔' WHERE id = 3012;
UPDATE hadiths SET urdu = 'ہم سے عثمان بن ابی شیبہ نے بیان کیا، کہا ہم سے جریر نے بیان کیا، ان سے منصور نے، ان سے ابووائل نے کہ عبداللہ بن مسعود رضی اللہ عنہ نے بیان کیا کہ حنین کی لڑائی کے بعد نبی کریم صلی اللہ علیہ وسلم نے ( غنیمت کی ) تقسیم میں بعض لوگوں کو زیادہ دیا۔ جیسے اقرع بن حابس رضی اللہ عنہ کو سو اونٹ دئیے، اتنے ہی اونٹ عیینہ بن حصین رضی اللہ عنہ کو دئیے اور کئی عرب کے اشراف لوگوں کو اسی طرح تقسیم میں زیادہ دیا۔ اس پر ایک شخص ( معتب بن قشیر منافق ) نے کہا، کہ اللہ کی قسم! اس تقسیم میں نہ تو عدل کو ملحوظ رکھا گیا ہے اور نہ اللہ کی خوشنودی کا خیال ہوا۔ میں نے کہا کہ واللہ! اس کی خبر میں رسول اللہ صلی اللہ علیہ وسلم کو ضرور دوں گا۔ چنانچہ میں آپ کی خدمت میں حاضر ہوا، اور آپ کو اس کی خبر دی۔ نبی کریم صلی اللہ علیہ وسلم نے سن کر فرمایا ”اگر اللہ اور اس کا رسول بھی عدل نہ کرے تو پھر کون عدل کرے گا۔ اللہ تعالیٰ موسیٰ علیہ السلام پر رحم فرمائے کہ ان کو لوگوں کے ہاتھ اس سے بھی زیادہ تکلیف پہنچی لیکن انہوں نے صبر کیا۔“' WHERE id = 3022;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ نے بیان کیا، انہوں نے کہا ہم سے اسماعیل بن ابراہیم نے بیان کیا، انہوں نے کہا کہ مجھے روح بن قاسم نے خبر دی، انہیں محمد بن منکدر نے بیان کیا کہ جابر بن عبداللہ رضی اللہ عنہما نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے مجھ سے فرمایا تھا کہ اگر ہمارے پاس بحرین سے روپیہ آیا، تو میں تمہیں اتنا، اتنا، اتنا ( تین لپ ) دوں گا۔ پھر جب رسول اللہ صلی اللہ علیہ وسلم کی وفات ہو گئی اور اس کے بعد بحرین کا روپیہ آیا تو ابوبکر رضی اللہ عنہ نے فرمایا کہ رسول اللہ صلی اللہ علیہ وسلم نے اگر کسی سے کوئی دینے کا وعدہ کیا ہو تو وہ ہمارے پاس آئے۔ چنانچہ میں حاضر ہوا اور عرض کیا کہ نبی کریم صلی اللہ علیہ وسلم نے مجھ سے فرمایا تھا کہ اگر بحرین کا روپیہ ہمارے یہاں آیا تو میں تمہیں اتنا، اتنا اور اتنا دوں گا۔ اس پر انہوں نے فرمایا کہ اچھا ایک لپ بھرو، میں نے ایک لپ بھری، تو انہوں نے فرمایا کہ اسے شمار کرو، میں نے شمار کیا تو پانچ سو تھا، پھر انہوں نے مجھے ڈیڑھ ہزار عنایت فرمایا۔' WHERE id = 3034;
UPDATE hadiths SET urdu = 'مجھ سے محمد بن مثنیٰ نے بیان کیا، کہا ہم سے یحییٰ نے بیان کیا، کہا ہم سے ہشام نے بیان کیا، کہا کہ مجھ سے میرے باپ نے بیان کیا اور ان سے عائشہ رضی اللہ عنہا نے کہ نبی کریم صلی اللہ علیہ وسلم پر جادو کر دیا گیا تھا۔ تو بعض دفعہ ایسا ہوتا کہ آپ سمجھتے کہ میں نے فلاں کام کر لیا ہے۔ حالانکہ آپ نے وہ کام نہ کیا ہوتا۔' WHERE id = 3044;
UPDATE hadiths SET urdu = 'ہم سے عبدان بن عثمان نے بیان کیا، انہوں نے کہا کہ مجھے میرے باپ نے خبر دی، انہیں شعبہ نے، انہیں ابواسحاق نے، انہیں عمرو بن میمون نے اور ان سے عبداللہ رضی اللہ عنہ نے بیان کیا کہ مکہ میں ( شروع اسلام کے زمانہ میں رسول اللہ صلی اللہ علیہ وسلم سجدہ کی حالت میں تھے اور قریب ہی قریش کے کچھ لوگ بیٹھے ہوئے تھے۔ پھر عقبہ بن ابی معیط اونٹ کی اوجھڑی لایا اور نبی کریم صلی اللہ علیہ وسلم کی پیٹھ پر اسے ڈال دیا۔ نبی کریم صلی اللہ علیہ وسلم سجدہ سے اپنا سر نہ اٹھا سکے۔ آخر فاطمہ رضی اللہ عنہا آئیں اور آپ صلی اللہ علیہ وسلم کی پیٹھ پر سے اس اوجھڑی کو ہٹایا اور جس نے یہ حرکت کی تھی اسے برا بھلا کہا، نبی کریم صلی اللہ علیہ وسلم نے بھی بددعا کی کہ اے اللہ! قریش کی اس جماعت کو پکڑ۔ اے اللہ! ابوجہل بن ہشام، عتبہ بن ربیعہ، شیبہ بن ربیعہ، عقبہ بن ابی معیط، امیہ بن خلف یا ابی بن خلف کو برباد کر۔ پھر میں نے دیکھا کہ یہ سب بدر کی لڑائی میں قتل کر دئیے گئے۔ اور ایک کنویں میں انہیں ڈال دیا گیا تھا۔ سوا امیہ یا ابی کے کہ یہ شخص بہت بھاری بھر کم تھا۔ جب اسے صحابہ نے کھینچا تو کنویں میں ڈالنے سے پہلے ہی اس کے جوڑ جوڑ الگ ہو گئے۔)' WHERE id = 3054;
UPDATE hadiths SET urdu = 'ہم سے محمد بن مثنیٰ نے بیان کیا، انہوں نے کہا ہم سے عبدالوہاب ثقفی نے بیان کیا، انہوں نے کہا ہم سے ایوب سختیانی نے بیان کیا، انہوں نے کہا کہ ہم سے محمد بن سیرین نے بیان کیا، ان سے ابوبکرہ کے صاحبزادے ( عبدالرحمٰن ) نے بیان کیا اور ان سے ابوبکرہ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”زمانہ گھوم پھر کر اسی حالت پر آ گیا جیسے اس دن تھا جس دن اللہ تعالیٰ نے آسمان اور زمین پیدا کی تھی۔ سال بارہ مہینوں کا ہوتا ہے، چار مہینے اس میں سے حرمت کے ہیں۔ تین تو پے در پے۔ ذی قعدہ، ذی الحجہ اور محرم اور ( چوتھا ) رجب مضر جو جمادی الاخریٰ اور شعبان کے بیچ میں پڑتا ہے۔“' WHERE id = 3065;
UPDATE hadiths SET urdu = 'ہم سے ہدبۃ بن خالد نے بیان کیا، کہا ہم سے ہمام نے بیان کیا، کہا ہم سے یزید بن زریع نے بیان کیا، کہا ہم سے سعید بن ابی عروبہ اور ہشام دستوائی نے بیان کیا، کہا ہم سے قتادہ نے بیان کیا، کہا ہم سے انس بن مالک رضی اللہ عنہ نے بیان کیا اور ان سے مالک بن صعصعہ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”میں ایک دفعہ بیت اللہ کے قریب نیند اور بیداری کی درمیانی حالت میں تھا، پھر آپ صلی اللہ علیہ وسلم نے دو آدمیوں کے درمیان لیٹے ہوئے ایک تیسرے آدمی کا ذکر فرمایا۔ اس کے بعد میرے پاس سونے کا ایک طشت لایا گیا، جو حکمت اور ایمان سے بھرپور تھا۔ میرے سینے کو پیٹ کے آخری حصے تک چاک کیا گیا۔ پھر میرا پیٹ زمزم کے پانی سے دھویا گیا اور اسے حکمت اور ایمان سے بھر دیا گیا۔ اس کے بعد میرے پاس ایک سواری لائی گئی۔ سفید، خچر سے چھوٹی اور گدھے سے بڑی یعنی براق، میں اس پر سوار ہو کر جبرائیل علیہ السلام کے ساتھ چلا۔ جب ہم آسمان دنیا پر پہنچے تو پوچھا گیا کہ یہ کون صاحب ہیں؟ انہوں نے کہا کہ جبرائیل۔ پوچھا گیا کہ آپ کے ساتھ اور کون صاحب آئے ہیں؟ انہوں نے بتایا کہ محمد ( صلی اللہ علیہ وسلم ) پوچھا گیا کہ کیا انہیں بلانے کے لیے آپ کو بھیجا گیا تھا؟ انہوں نے کہا کہ ہاں، اس پر جواب آیا کہ اچھی کشادہ جگہ آنے والے کیا ہی مبارک ہیں، پھر میں آدم علیہ السلام کی خدمت میں حاضر ہوا۔ اور انہیں سلام کیا۔ انہوں نے فرمایا، آؤ پیارے بیٹے اور اچھے نبی۔ اس کے بعد ہم دوسرے آسمان پر پہنچے یہاں بھی وہی سوال ہوا۔ کون صاحب ہیں؟ کہا جبرائیل، سوال ہوا، آپ کے ساتھ کوئی اور صاحب بھی آئے ہیں؟ کہا کہ محمد صلی اللہ علیہ وسلم ، سوال ہوا انہیں بلانے کے لیے آپ کو بھیجا گیا تھا؟ کہا کہ ہاں۔ اب ادھر سے جواب آیا، اچھی کشادہ جگہ آئے ہیں، آنے والے کیا ہی مبارک ہیں۔ اس کے بعد میں عیسیٰ اور یحییٰ علیہ السلام سے ملا، ان حضرات نے بھی خوش آمدید، مرحبا کہا اپنے بھائی اور نبی کو۔ پھر ہم تیسرے آسمان پر آئے یہاں بھی سوال ہوا کون صاحب ہیں؟ جواب ملا جبرائیل، سوال ہوا، آپ کے ساتھ بھی کوئی ہے؟ کہا کہ محمد صلی اللہ علیہ وسلم ، سوال ہوا، انہیں بلانے کے لیے آپ کو بھیجا گیا تھا؟ انہوں نے بتایا کہ ہاں، اب آواز آئی اچھی کشادہ جگہ آئے آنے والے کیا ہی صالح ہیں، یہاں یوسف علیہ السلام سے میں ملا اور انہیں سلام کیا، انہوں نے فرمایا، اچھی کشادہ جگہ آئے ہو میرے بھائی اور نبی، یہاں سے ہم چوتھے آسمان پر آئے اس پر بھی یہی سوال ہوا، کون صاحب، جواب دیا کہ جبرائیل، سوال ہوا، آپ کے ساتھ اور کون صاحب ہیں؟ کہا کہ محمد صلی اللہ علیہ وسلم ہیں۔ پوچھا کیا انہیں لانے کے لیے آپ کو بھیجا گیا تھا، جواب دیا کہ ہاں، پھر آواز آئی، اچھی کشادہ جگہ آئے کیا ہی اچھے آنے والے ہیں۔ یہاں میں ادریس علیہ السلام سے ملا اور سلام کیا، انہوں نے فرمایا، مرحبا، بھائی اور نبی۔ یہاں سے ہم پانچویں آسمان پر آئے۔ یہاں بھی سوال ہوا کہ کون صاحب؟ جواب دیا کہ جبرائیل، پوچھا گیا اور آپ کے ساتھ اور کون صاحب آئے ہیں؟ جواب دیا کہ محمد صلی اللہ علیہ وسلم ، پوچھا گیا، انہیں بلانے کے لیے بھیجا گیا تھا؟ کہا کہ ہاں، آواز آئی، اچھی کشادہ جگہ آئے ہیں۔ آنے والے کیا ہی اچھے ہیں۔ یہاں ہم ہارون علیہ السلام سے ملے اور میں نے انہیں سلام کیا۔ انہوں نے فرمایا، مبارک میرے بھائی اور نبی، تم اچھی کشادہ جگہ آئے، یہاں سے ہم چھٹے آسمان پر آئے، یہاں بھی سوال ہوا، کون صاحب؟ جواب دیا کہ جبرائیل، پوچھا گیا، آپ کے ساتھ اور بھی کوئی ہیں؟ کہا کہ ہاں محمد صلی اللہ علیہ وسلم ہیں۔ پوچھا گیا، کیا انہیں بلایا گیا تھا کہا ہاں، کہا اچھی کشادہ جگہ آئے ہیں، اچھے آنے والے ہیں۔ یہاں میں موسیٰ علیہ السلام سے ملا اور انہیں سلام کیا۔ انہوں نے فرمایا، میرے بھائی اور نبی اچھی کشادہ جگہ آئے، جب میں وہاں سے آگے بڑھنے لگا تو وہ رونے لگے کسی نے پوچھا بزرگوار آپ کیوں رو رہے ہیں؟ انہوں نے فرمایا کہ اے اللہ! یہ نوجوان جسے میرے بعد نبوت دی گئی، اس کی امت میں سے جنت میں داخل ہونے والے، میری امت کے جنت میں داخل ہونے والے لوگوں سے زیادہ ہوں گے۔ اس کے بعد ہم ساتویں آسمان پر آئے یہاں بھی سوال ہوا کہ کون صاحب ہیں؟ جواب دیا کہ جبرائیل، سوال ہوا کہ کوئی صاحب آپ کے ساتھ بھی ہیں؟ جواب دیا کہ محمد صلی اللہ علیہ وسلم پوچھا، انہیں بلانے کے لیے آپ کو بھیجا گیا تھا؟ مرحبا، اچھے آنے والے۔ یہاں میں ابراہیم علیہ السلام سے ملا اور انہیں سلام کیا۔ انہوں نے فرمایا میرے بیٹے اور نبی، مبارک، اچھی کشادہ جگہ آئے ہو، اس کے بعد مجھے بیت المعمور دکھایا گیا۔ میں نے جبرائیل علیہ السلام سے اس کے بارے میں پوچھا، تو انہوں نے بتلایا کہ یہ بیت المعمور ہے۔ اس میں ستر ہزار فرشتے روزانہ نماز پڑھتے ہیں۔ اور ایک مرتبہ پڑھ کر جو اس سے نکل جاتا ہے تو پھر کبھی داخل نہیں ہوتا۔ اور مجھے سدرۃ المنتہیٰ بھی دکھایا گیا، اس کے پھل ایسے تھے جیسے مقام ہجر کے مٹکے ہوتے ہیں اور پتے ایسے تھے جیسے ہاتھی کے کان، اس کی جڑ سے چار نہریں نکلتی تھیں، دو نہریں تو باطنی تھیں اور دو ظاہری، میں نے جبرائیل علیہ السلام سے پوچھا تو انہوں نے بتایا کہ جو دو باطنی نہریں ہیں وہ تو جنت میں ہیں اور دو ظاہری نہریں دنیا میں نیل اور فرات ہیں، اس کے بعد مجھ پر پچاس وقت کی نمازیں فرض کی گئیں۔ میں جب واپس ہوا اور موسیٰ علیہ السلام سے ملا تو انہوں نے پوچھا کہ کیا کر کے آئے ہو؟ میں نے عرض کیا کہ پچاس نمازیں مجھ پر فرض کی گئی ہیں۔ انہوں نے فرمایا کہ انسانوں کو میں تم سے زیادہ جانتا ہوں، بنی اسرائیل کا مجھے برا تجربہ ہو چکا ہے۔ تمہاری امت بھی اتنی نمازوں کی طاقت نہیں رکھتی، اس لیے اپنے رب کی بارگاہ میں دوبارہ حاضری دو، اور کچھ تخفیف کی درخواست کرو، میں واپس ہوا تو اللہ تعالیٰ نے نمازیں چالیس وقت کی کر دیں۔ پھر بھی موسیٰ علیہ السلام اپنی بات ( یعنی تخفیف کرانے ) پر مصر رہے۔ اس مرتبہ تیس وقت کی رہ گئیں۔ پھر انہوں نے وہی فرمایا اور اس مرتبہ بارگاہ رب العزت میں میری درخواست کی پیشی پر اللہ تعالیٰ نے انہیں دس کر دیا۔ میں جب موسیٰ علیہ السلام کے پاس آیا تو اب بھی انہوں نے کم کرانے کے لیے اپنا اصرار جاری رکھا۔ اور اس مرتبہ اللہ تعالیٰ نے پانچ وقت کی کر دیں۔ اب موسیٰ علیہ السلام سے ملا، تو انہوں نے پھر دریافت فرمایا کہ کیا ہوا؟ میں نے کہا کہ اللہ تعالیٰ نے پانچ کر دی ہیں۔ اس مرتبہ بھی انہوں نے کم کرانے کا اصرار کیا۔ میں نے کہا کہ اب تو میں اللہ کے سپرد کر چکا۔ پھر آواز آئی۔ میں نے اپنا فریضہ ( پانچ نمازوں کا ) جاری کر دیا۔ اپنے بندوں پر تخفیف کر چکا اور میں ایک نیکی کا بدلہ دس گنا دیتا ہوں۔ اور ہمام نے کہا، ان سے قتادہ نے کہا، ان سے حسن نے، ان سے ابوہریرہ رضی اللہ عنہ نے نبی کریم صلی اللہ علیہ وسلم سے بیت المعمور کے بارے میں الگ روایت کی ہے۔' WHERE id = 3075;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد مسندی نے بیان کیا، کہا ہم سے ہشام نے بیان کیا، کہا ہم کو معمر نے خبر دی، انہیں زہری نے، انہیں ابوسلمہ نے اور انہیں عائشہ رضی اللہ عنہا نے کہ نبی کریم صلی اللہ علیہ وسلم نے ایک مرتبہ فرمایا ”اے عائشہ! یہ جبرائیل علیہ السلام آئے ہیں، تم کو سلام کہہ رہے ہیں۔“ عائشہ رضی اللہ عنہا نے جواب میں کہا، کہ وعلیہ السلام ورحمۃ اللہ وبرکاتہ۔ آپ وہ چیزیں دیکھتے ہیں جنہیں میں نہیں دیکھ سکتی، عائشہ رضی اللہ عنہا کی مراد نبی کریم صلی اللہ علیہ وسلم سے تھی۔' WHERE id = 3085;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن سلیمان نے بیان کیا، کہا کہ مجھ سے عبداللہ بن وہب نے بیان کیا، کہا کہ مجھ سے عمرو نے بیان کیا، ان سے سالم نے اور ان سے ان کے باپ عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا کہ ایک مرتبہ نبی کریم صلی اللہ علیہ وسلم سے جبرائیل علیہ السلام نے آنے کا وعدہ کیا تھا ( لیکن نہیں آئے ) پھر جب آئے تو آپ صلی اللہ علیہ وسلم نے ان سے وجہ پوچھی، انہوں نے کہا کہ ہم کسی بھی ایسے گھر میں داخل نہیں ہوتے جس میں تصویر یا کتا موجود ہو۔' WHERE id = 3095;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے ابوعوانہ نے بیان کیا، ان سے اعمش نے، ان سے ابوحازم نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”اگر کسی مرد نے اپنی بیوی کو اپنے بستر پر بلایا، لیکن اس نے آنے سے انکار کر دیا اور مرد اس پر غصہ ہو کر سو گیا، تو صبح تک فرشتے اس عورت پر لعنت کرتے رہتے ہیں۔“ اس روایت کی متابعت، ابوحمزہ، ابن داود اور ابومعاویہ نے اعمش کے واسطہ سے کی ہے۔' WHERE id = 3105;
UPDATE hadiths SET urdu = 'ہم سے محمد بن ابی بکر مقدمی نے بیان کیا، انہوں نے کہا ہم سے فضیل بن سلیمان نے بیان کیا، ان سے ابوحازم نے بیان کیا اور ان سے سہل بن سعد رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”میری امت میں سے ستر ہزار یا ( آپ صلی اللہ علیہ وسلم نے یہ فرمایا کہ ) سات لاکھ کی ایک جماعت جنت میں ایک ہی وقت میں داخل ہوں گی اور ان سب کے چہرے ایسے چمکیں گے جیسے چودہویں کا چاند چمکتا ہے۔“' WHERE id = 3115;
UPDATE hadiths SET urdu = 'ہم سے محمد بن یوسف نے بیان کیا، کہا ہم سے سفیان ثوری نے بیان کیا، ان سے اعمش نے، ان سے ذکوان نے اور ان سے ابو سعید خدری رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”نماز ٹھنڈے وقت میں پڑھا کرو، کیونکہ گرمی کی شدت جہنم کی بھاپ سے پیدا ہوتی ہے۔“' WHERE id = 3126;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل بن ابی اویس نے بیان کیا، کہا مجھ سے میرے بھائی (عبدالحمید) نے بیان کیا، انہوں نے کہا ہم سے سلیمان بن بلال نے، ان سے یحییٰ بن سعید نے، ان سے سعید بن مسیب نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”جب کوئی تم میں سے سویا ہوا ہوتا ہے، تو شیطان اس کے سر کی گدی پر تین گرہیں لگا دیتا ہے خوب اچھی طرح سے اور ہر گرہ پر یہ افسون پھونک دیتا ہے کہ ابھی بہت رات باقی ہے۔ پڑا سوتا رہ۔ لیکن اگر وہ شخص جاگ کر اللہ کا ذکر شروع کرتا ہے تو ایک گرہ کھل جاتی ہے۔ پھر جب وضو کرتا ہے تو دوسری گرہ کھل جاتی ہے۔ پھر جب نماز فجر پڑھتا ہے تو تیسری گرہ بھی کھل جاتی ہے اور صبح کو خوش مزاج خوش دل رہتا ہے۔ ورنہ بدمزاج سست رہ کر وہ دن گزارتا ہے۔“' WHERE id = 3136;
UPDATE hadiths SET urdu = 'ہم سے محمود بن غیلان نے بیان کیا، کہا ہم سے عبدالرزاق نے بیان کیا، کہا ہم کو معمر نے خبر دی، انہیں زہری نے، انہیں زین العابدین علی بن حسین رضی اللہ عنہ نے اور ان سے صفیہ بنت حیی رضی اللہ عنہا نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم اعتکاف میں تھے تو میں رات کے وقت آپ سے ملاقات کے لیے ( مسجد میں ) آئی، میں آپ صلی اللہ علیہ وسلم سے باتیں کرتی رہی، پھر جب واپس ہونے کے لیے کھڑی ہوئی تو آپ صلی اللہ علیہ وسلم بھی مجھے چھوڑ آنے کے لیے کھڑے ہوئے۔ ام المؤمنین سیدہ صفیہ رضی اللہ عنہا کا مکان اسامہ بن زید رضی اللہ عنہما کے مکان ہی میں تھا۔ اسی وقت دو انصاری صحابہ ( اسید بن حضیر، عبادہ بن بشیر ) گزرے۔ جب انہوں نے آپ صلی اللہ علیہ وسلم کو دیکھا تو تیز چلنے لگے۔ آپ صلی اللہ علیہ وسلم نے ان سے فرمایا، ذرا ٹھہر جاؤ یہ صفیہ بنت حیی ہیں۔ ان دونوں صحابہ نے عرض کیا، سبحان اللہ: یا رسول اللہ! ( کیا ہم بھی آپ کے بارے میں کوئی شبہ کر سکتے ہیں ) آپ صلی اللہ علیہ وسلم نے فرمایا کہ شیطان انسان کے اندر خون کی طرح دوڑتا رہتا ہے۔ اس لیے مجھے ڈر لگا کہ کہیں تمہارے دلوں میں بھی کوئی وسوسہ نہ ڈال دے، یا آپ صلی اللہ علیہ وسلم نے ( لفظ «سوء» کی جگہ ) لفظ «شيئا» فرمایا، معنی ایک ہی ہیں۔' WHERE id = 3147;
UPDATE hadiths SET urdu = 'ہم سے حسن بن ربیع نے بیان کیا، کہا ہم سے ابوالاحوص نے، ان سے اشعث نے، ان سے ان کے والد نے، ان سے مسروق نے بیان کیا اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم سے نماز میں ادھر ادھر دیکھنے کے متعلق پوچھا تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ یہ شیطان کی ایک اچک ہے جو وہ تم میں سے ایک کی نماز سے کچھ اچک لیتا ہے۔' WHERE id = 3157;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ نے بیان کیا، انہوں نے کہا ہم سے لیث بن سعد نے بیان کیا، ان سے جعفر بن ربیعہ نے، ان سے اعرج نے بیان کیا اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”جب مرغ کی بانگ سنو تو اللہ سے اس کے فضل کا سوال کیا کرو، کیونکہ اس نے فرشتے کو دیکھا ہے اور جب گدھے کی آواز سنو تو شیطان سے اللہ کی پناہ مانگو کیونکہ اس نے شیطان کو دیکھا ہے۔“' WHERE id = 3168;
UPDATE hadiths SET urdu = 'ہم سے عبدہ بن عبداللہ نے بیان کیا، کہا ہم کو یحییٰ بن آدم نے خبر دی، انہیں اسرائیل نے، انہیں منصور نے، انہیں ابراہیم نے، انہیں علقمہ نے اور ان سے عبداللہ بن مسعود رضی اللہ عنہ نے بیان کیا کہ ( مقام منیٰ میں ) ہم نبی کریم صلی اللہ علیہ وسلم کے ساتھ ایک غار میں بیٹھے ہوئے تھے کہ آیت «والمرسلات عرفا‏» نازل ہوئی، ابھی ہم آپ کی زبان مبارک سے اسے سن ہی رہے تھے کہ ایک بل میں سے ایک سانپ نکلا۔ ہم اسے مارنے کے لیے جھپٹے، لیکن وہ بھاگ گیا اور اپنے بل میں داخل ہو گیا، ( آپ صلی اللہ علیہ وسلم نے ) اس پر فرمایا ”تمہارے ہاتھ سے وہ اسی طرح بچ نکلا جیسے تم اس کے شر سے بچ گئے“ اور یحییٰ نے اسرائیل سے روایت کیا ہے، ان سے اعمش نے، ان سے ابراہیم نے، ان سے علقمہ نے اور ان سے عبداللہ رضی اللہ عنہ نے اسی طرح روایت کیا اور کہا کہ نبی کریم صلی اللہ علیہ وسلم کی زبان مبارک سے اس سورۃ کو تازہ بتازہ سن رہے تھے اور اسرائیل کے ساتھ اس حدیث کو ابوعوانہ نے مغیرہ سے روایت کیا اور حفص بن غیاث اور ابومعاویہ اور سلیمان بن قرم نے بھی اعمش سے بیان کیا، ان سے ابراہیم نے، ان سے اسود نے اور ان سے عبداللہ بن مسعود رضی اللہ عنہ نے۔' WHERE id = 3180;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا ہم سے جریر نے بیان کیا، ان سے عمارہ نے ان سے ابوزرعہ نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”سب سے پہلا گروہ جو جنت میں داخل ہو گا ان کی صورتیں ایسی روشن ہوں گی جیسے چودھویں کا چاند روشن ہوتا ہے، پھر جو لوگ اس کے بعد داخل ہوں گے وہ آسمان کے سب سے زیادہ روشن ستارے کی طرح چمکتے ہوں گے۔ نہ تو ان لوگوں کو پیشاب کی ضرورت ہو گی نہ پاخانہ کی، نہ وہ تھوکیں گے نہ ناک سے آلائش نکالیں گے۔ ان کے کنگھے سونے کے ہوں گے اور ان کا پسینہ مشک کی طرح ہو گا۔ ان کی انگیٹھیوں میں خوشبودار عود جلتا ہو گا، یہ نہایت پاکیزہ خوشبودار عود ہو گا۔ ان کی بیویاں بڑی آنکھوں والی حوریں ہوں گی۔ سب کی صورتیں ایک ہوں گی۔ یعنی اپنے والد آدم علیہ السلام کے قد و قامت پر ساٹھ ساٹھ ہاتھ اونچے ہوں گے۔“' WHERE id = 3190;
UPDATE hadiths SET urdu = 'ہم سے عبدان نے بیان کیا، کہا ہم کو عبداللہ بن مبارک نے خبر دی، انہیں یونس نے، انہیں زہری نے کہ سالم نے بیان کیا اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم لوگوں میں خطبہ سنانے کھڑے ہوئے۔ پہلے اللہ تعالیٰ کی، اس کی شان کے مطابق ثنا بیان کی، پھر دجال کا ذکر فرمایا اور فرمایا کہ میں تمہیں دجال کے فتنے سے ڈراتا ہوں اور کوئی نبی ایسا نہیں گزرا جس نے اپنی قوم کو اس سے نہ ڈرایا ہو۔ نوح علیہ السلام نے بھی اپنی قوم کو اس سے ڈرایا تھا۔ لیکن میں تمہیں اس کے بارے میں ایک ایسی بات بتاتا ہوں جو کسی نبی نے بھی اپنی قوم کو نہیں بتائی تھی، تمہیں معلوم ہونا چاہئے کہ دجال کانا ہو گا اور اللہ تعالیٰ اس عیب سے پاک ہے۔' WHERE id = 3200;
UPDATE hadiths SET urdu = 'ہمیں مسلم بن ابراہیم نے بیان کیا، کہا ہم سے وہیب نے، ان سے ابن طاؤس نے، ان سے ان کے والد طاؤس نے، ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”اللہ پاک نے یاجوج ماجوج کی دیوار سے اتنا کھول دیا ہے، پھر آپ صلی اللہ علیہ وسلم نے اپنی انگلیوں سے نوے کا عدد بنا کر بتلایا۔“' WHERE id = 3210;
UPDATE hadiths SET urdu = 'ہم سے سعید بن تلید رعینی نے بیان کیا، انہوں نے کہا ہم کو عبداللہ بن وہب نے خبر دی، کہا کہ مجھے جریر بن حازم نے خبر دی، انہیں ایوب سختیانی نے، انہیں محمد بن سیرین نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”ابراہیم علیہ السلام نے توریہ تین مرتبہ کے سوا اور کبھی نہیں کیا۔“' WHERE id = 3220;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف تنیسی نے بیان کیا ‘ انہوں نے کہا ہم کو مالک بن انس نے خبر دی۔ انہیں عبداللہ بن ابی بکر بن محمد بن عمرو بن حزم نے ‘ انہیں ان کے والد نے ‘ انہیں عمرو بن سلیم زرقی نے ‘ انہوں نے کہا مجھ کو ابو حمید ساعدی رضی اللہ عنہ نے خبر دی کہ صحابہ نے عرض کیا: یا رسول اللہ! ہم آپ پر کس طرح درود بھیجا کریں؟ تو رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ یوں کہا کرو «اللهم صل على محمد وأزواجه وذريته،‏‏‏‏ ‏‏‏‏ كما صليت على آل إبراهيم،‏‏‏‏ ‏‏‏‏ وبارك على محمد وأزواجه وذريته،‏‏‏‏ ‏‏‏‏ كما باركت على آل إبراهيم،‏‏‏‏ ‏‏‏‏ إنك حميد مجيد‏ ‏‏.‏» ”اے اللہ! رحمت نازل فرما محمد پر اور ان کی بیویوں پر اور ان کی اولاد پر جیسا کہ تو نے رحمت نازل فرمائی ابراہیم پر اور اپنی برکت نازل فرما محمد پر اور ان کی بیویوں اور اولاد پر جیسا کہ تو نے برکت نازل فرمائی آل ابراہیم پر۔ بیشک تو انتہائی خوبیوں والا اور عظمت والا ہے۔“' WHERE id = 3231;
UPDATE hadiths SET urdu = 'ہم سے ابراہیم بن المنذر نے بیان کیا ‘ انہوں نے کہا ہم سے انس بن عیاض نے بیان کیا ‘ ان سے عبیداللہ نے ‘ ان سے نافع نے اور اور انہیں عبداللہ بن عمر رضی اللہ عنہما نے خبر دی کہ صحابہ رضوان اللہ علیہم اجمعین نے نبی کریم صلی اللہ علیہ وسلم کے ساتھ ثمود کی بستی حجر میں پڑاؤ کیا تو وہاں کے کنوؤں کا پانی اپنے برتنوں میں بھر لیا اور آٹا بھی اس پانی سے گوندھ لیا۔ لیکن نبی کریم صلی اللہ علیہ وسلم نے انہیں حکم دیا کہ جو پانی انہوں نے اپنے برتنوں میں بھر لیا ہے اسے انڈیل دیں اور گندھا ہوا آٹا جانوروں کو کھلا دیں۔ اس کے بجائے نبی کریم صلی اللہ علیہ وسلم نے انہیں یہ حکم دیا کہ اس کنویں سے پانی لیں جس سے صالح علیہ السلام کی اونٹنی پانی پیا کرتی تھی۔' WHERE id = 3241;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا ‘ کہا ہم سے لیث نے بیان کیا ‘ ان سے عقیل نے ‘ ان سے ابن شہاب نے ‘ کہا کہ مجھے عروہ نے خبر دی کہ انہوں نے نبی کریم صلی اللہ علیہ وسلم کی زوجہ مطہرہ عائشہ رضی اللہ عنہا سے آیت کے متعلق پوچھا «حتى إذا استيأس الرسل وظنوا أنهم قد كذبوا‏» ( تشدید کے ساتھ ) ہے یا «كذبوا‏» ( بغیر تشدید کے ) یعنی یہاں تک کہ جب انبیاء ناامید ہو گئے اور انہیں خیال گزرنے لگا کہ انہیں جھٹلا دیا گیا تو اللہ کی مدد پہنچی تو انہوں نے کہا کہ ( یہ تشدید کے ساتھ ہے اور مطلب یہ ہے کہ ) ان کی قوم نے انہیں جھٹلایا تھا۔ میں نے عرض کیا کہ پھر معنی کیسے بنیں گے ‘ پیغمبروں کو یقین تھا ہی کہ ان کی قوم انہیں جھٹلا رہی ہے۔ پھر قرآن میں لفظ «ظن‏.‏» گمان اور خیال کے معنی میں استعمال کیوں کیا گیا؟ عائشہ رضی اللہ عنہا نے کہا: اے چھوٹے سے عروہ! بیشک ان کو تو یقین تھا میں نے کہا تو شاید اس آیت میں بغیر تشدید کے «كذبوا‏» ہو گا یعنی پیغمبر یہ سمجھے کہ اللہ نے جو ان کی مدد کا وعدہ کیا تھا وہ غلط تھا۔ عائشہ رضی اللہ عنہا نے فرمایا: معاذاللہ! انبیاء اپنے رب کے ساتھ بھلا ایسا گمان کر سکتے ہیں۔ عائشہ رضی اللہ عنہا نے کہا مراد یہ ہے کہ پیغمبروں کے تابعدار لوگ جو اپنے مالک پر ایمان لائے تھے اور پیغمبروں کی تصدیق کی تھی ان پر جب مدت تک اللہ کی آزمائش رہی اور مدد آنے میں دیر ہوئی اور پیغمبر لوگ اپنی قوم کے جھٹلانے والوں سے ناامید ہو گئے ( سمجھے کہ اب وہ ایمان نہیں لائیں گے ) اور انہوں نے یہ گمان کیا کہ جو لوگ ان کے تابعدار بنے ہیں وہ بھی ان کو جھوٹا سمجھنے لگیں گے ‘ اس وقت اللہ کی مدد آن پہنچی۔ ابوعبداللہ ( امام بخاری رحمہ اللہ ) نے کہا کہ «استيأسوا‏»،‏‏‏‏ «افتعلوا» کے وزن پر ہے جو «يئست‏.‏ ‏منه‏» سے نکلا ہے۔ «اى من يوسف‏.‏» ( سورۃ یوسف کی آیت کا ایک جملہ ہے یعنی زلیخا یوسف علیہ السلام سے ناامید ہو گئی۔ ) «لا تيأسوا من روح الله‏» » ‏‏‏‏ ( سورۃ یوسف: 87 ) یعنی اللہ سے امید رکھو ناامید نہ ہو۔' WHERE id = 3251;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ مدینی نے بیان کیا ‘ کہا ہم سے سفیان بن عیینہ نے بیان کیا ‘ کہا ہم سے عمرو بن دینار نے بیان کیا ‘ کہا کہ مجھے سعید بن جبیر نے خبر دی ‘ انہوں نے کہا کہ میں نے ابن عباس رضی اللہ عنہما سے عرض کیا کہ نوف بکالی یہ کہتا ہے کہ موسیٰ ‘ صاحب خضر بنی اسرائیل کے موسیٰ نہیں ہیں بلکہ وہ دوسرے موسیٰ ہیں۔ ابن عباس رضی اللہ عنہما نے کہا کہ دشمن اللہ نے بالکل غلط بات کہی ہے۔ ابی بن کعب رضی اللہ عنہ نے نبی کریم صلی اللہ علیہ وسلم سے روایت کرتے ہوئے ہم سے بیان کیا کہ موسیٰ علیہ السلام بنی اسرائیل کو کھڑے ہو کر خطاب فرما رہے تھے کہ ان سے پوچھا گیا کون سا شخص سب سے زیادہ علم والا ہے۔ انہوں نے فرمایا کہ میں۔ اس پر اللہ تعالیٰ نے ان پر عتاب فرمایا کیونکہ انہوں علم کی نسبت اللہ تعالیٰ کی طرف نہیں کی۔ اللہ تعالیٰ نے ان سے فرمایا کہ کیوں نہیں میرا ایک بندہ ہے جہاں دو دریا آ کر ملتے ہیں وہاں رہتا ہے اور تم سے زیادہ علم والا ہے۔ انہوں نے عرض کیا: اے رب العالمین! میں ان سے کس طرح مل سکوں گا؟ سفیان نے ( اپنی روایت میں یہ الفاظ ) بیان کئے کہ ”اے رب! «وكيف لي به» “ اللہ تعالیٰ نے فرمایا کہ ایک مچھلی پکڑ کر اسے اپنے تھیلے میں رکھ لینا ‘ جہاں وہ مچھلی گم ہو جائے بس میرا بندہ وہیں تم کو ملے گا۔ بعض دفعہ راوی نے ( بجائے «فهو ثم» کے ) «فهو ثمه» کہا۔ چنانچہ موسیٰ علیہ السلام نے مچھلی لے لی اور اسے ایک تھیلے میں رکھ لیا۔ پھر وہ اور ایک ان کے رفیق سفر یوشع بن نون روانہ ہوئے ‘ جب یہ چٹان پر پہنچے تو سر سے ٹیک لگالی ‘ موسیٰ علیہ السلام کو نیند آ گئی اور مچھلی تڑپ کر نکلی اور دریا کے اندر چلی گئی اور اس نے دریا میں اپنا راستہ بنا لیا۔ اللہ تعالیٰ نے مچھلی سے پانی کے بہاؤ کو روک دیا اور وہ محراب کی طرح ہو گئی ‘ انہوں نے واضح کیا کہ یوں محراب کی طرح۔ پھر یہ دونوں اس دن اور رات کے باقی حصے میں چلتے رہے ‘ جب دوسرا دن آیا تو موسیٰ علیہ السلام نے اپنے رفیق سفر سے فرمایا کہ اب ہمارا کھانا لاؤ کیونکہ ہم اپنے سفر میں بہت تھک گئے ہیں۔ موسیٰ علیہ السلام نے اس وقت تک کوئی تھکان محسوس نہیں کی تھی جب تک وہ اس مقررہ جگہ سے آگے نہ بڑھ گئے جس کا اللہ تعالیٰ نے انہیں حکم دیا تھا۔ ان کے رفیق نے کہا کہ دیکھئیے تو سہی جب چٹان پر اترے تھے تو میں مچھلی ( کے متعلق کہنا ) آپ سے بھول گیا اور مجھے اس کی یاد سے شیطان نے غافل رکھا اور اس مچھلی نے تو وہیں ( چٹان کے قریب ) دریا میں اپنا راستہ عجیب طور پر بنا لیا تھا۔ مچھلی کو تو راستہ مل گیا اور یہ دونوں حیران تھے۔ موسیٰ علیہ السلام نے فرمایا کہ یہی وہ جگہ تھی جس کی تلاش میں ہم نکلے ہیں۔ چنانچہ یہ دونوں اسی راستے سے پیچھے کی طرف واپس ہوئے اور جب اس چٹان پر پہنچے تو وہاں ایک بزرگ اپنا سارا جسم ایک کپڑے میں لپیٹے ہوئے موجود تھے۔ موسیٰ علیہ السلام نے انہیں سلام کیا اور انہوں نے جواب دیا پھر کہا کہ تمہارے خطے میں سلام کا رواج کہاں سے آ گیا؟ موسیٰ علیہ اسلام نے فرمایا کہ میں موسیٰ ہوں۔ انہوں نے پوچھا ‘ بنی اسرائیل کے موسیٰ؟ فرمایا کہ جی ہاں۔ میں آپ کی خدمت میں اس لیے حاضر ہوا ہوں کہ آپ مجھے وہ علم نافع سکھا دیں جو آپ کو سکھایا گیا ہے۔ انہوں نے فرمایا: اے موسیٰ! میرے پاس اللہ کا دیا ہوا ایک علم ہے اللہ تعالیٰ نے مجھے وہ علم سکھایا ہے اور آپ اس کو نہیں جانتے۔ اسی طرح آپ کے پاس اللہ کا دیا ہوا ایک علم ہے اللہ تعالیٰ نے آپ کو سکھایا ہے اور میں اسے نہیں جانتا۔ موسیٰ علیہ السلام نے کہا: کیا میں آپ کے ساتھ رہ سکتا ہوں انہوں نے کہا کہ آپ میرے ساتھ صبر نہیں کر سکیں گے اور واقعی آپ ان کاموں کے بارے میں صبر کر بھی کیسے سکتے ہیں جو آپ کے علم میں نہیں ہیں۔ اللہ تعالیٰ کے ارشاد «إمرا‏» تک آخر موسیٰ اور خضر علیہم السلام دریا کے کنارے کنارے چلے۔ پھر ان کے قریب سے ایک کشتی گزری۔ ان حضرات نے کہا کہ انہیں بھی کشتی والے کشتی پر سوار کر لیں۔ کشتی والوں نے خضر علیہ السلام کو پہچان لیا اور کوئی مزدوری لیے بغیر ان کو سوار کر لیا۔ جب یہ حضرات اس پر سوار ہو گئے تو ایک چڑیا آئی اور کشتی کے ایک کنارے بیٹھ کر اس نے پانی میں اپنی چونچ کو ایک یا دو مرتبہ ڈالا۔ خضر علیہ السلام نے فرمایا: اے موسیٰ! میرے اور آپ کے علم کی وجہ سے اللہ کے علم میں اتنی بھی کمی نہیں ہوئی جتنی اس چڑیا کے دریا میں چونچ مارنے سے دریا کے پانی میں کمی ہوئی ہو گی۔ اتنے میں خضر علیہ السلام نے کلہاڑی اٹھائی اور اس کشتی میں سے ایک تختہ نکال لیا۔ موسیٰ علیہ السلام نے جو نظر اٹھائی تو وہ اپنی کلہاڑی سے تختہ نکال چکے تھے۔ اس پر موسیٰ علیہ السلام بول پڑے کہ یہ آپ نے کیا کیا؟ جن لوگوں نے ہمیں بغیر کسی اجرت کے سوار کر لیا انہیں کی کشتی پر آپ نے بری نظر ڈالی اور اسے چیر دیا کہ سارے کشتی والے ڈوب جائیں۔ اس میں کوئی شبہ نہیں کہ آپ نے نہایت ناگوار کام کیا۔ خضر علیہ السلام نے فرمایا: کیا میں نے آپ سے پہلے ہی نہیں کہہ دیا تھا کہ آپ میرے ساتھ صبر نہیں کر سکتے۔ موسیٰ علیہ السلام نے فرمایا کہ ( یہ بے صبری اپنے وعدہ کو بھول جانے کی وجہ سے ہوئی ‘ اس لیے ) آپ اس چیز کا مجھ سے مواخذہ نہ کریں جو میں بھول گیا تھا اور میرے معاملے میں تنگی نہ فرمائیں۔ یہ پہلی بات موسیٰ علیہ السلام سے بھول کر ہوئی تھی پھر جب دریائی سفر ختم ہوا تو ان کا گزر ایک بچے کے پاس سے ہوا جو دوسرے بچوں کے ساتھ کھیل رہا تھا۔ خضر علیہ السلام نے اس کا سر پکڑ کر اپنے ہاتھ سے ( دھڑ سے ) جدا کر دیا۔ سفیان نے اپنے ہاتھ سے ( جدا کرنے کی کیفیت بتانے کے لیے ) اشارہ کیا جیسے وہ کوئی چیز توڑ رہے ہوں۔ اس پر موسیٰ علیہ السلام نے فرمایا کہ آپ نے ایک جان کو ضائع کر دیا۔ کسی دوسری جان کے بدلے میں بھی یہ نہیں تھا۔ بلاشبہ آپ نے ایک برا کام کیا۔ خضر علیہ السلام نے فرمایا: کیا میں نے آپ سے پہلے ہی نہیں کہا تھا کہ آپ میرے ساتھ صبر نہیں کر سکتے۔ موسیٰ علیہ السلام نے کہا: اچھا اس کے بعد اگر میں نے آپ سے کوئی بات پوچھی تو پھر آپ مجھے ساتھ نہ لے چلئے گا، بیشک آپ میرے بارے میں حد عذر کو پہنچ چکے ہیں۔ پھر یہ دونوں آگے بڑھے اور جب ایک بستی میں پہنچے تو بستی والوں سے کہا کہ وہ انہیں اپنا مہمان بنا لیں ‘ لیکن انہوں نے انکار کیا۔ پھر اس بستی میں انہیں ایک دیوار دکھائی دی جو بس گرنے ہی والی تھی۔ خضر علیہ السلام نے اپنے ہاتھ سے یوں اشارہ کیا۔ سفیان نے ( کیفیت بتانے کے لیے ) اس طرح اشارہ کیا جیسے وہ کوئی چیز اوپر کی طرف پھیر رہے ہوں۔ میں نے سفیان سے «مائلا» کا لفظ صرف ایک مرتبہ سنا تھا۔ موسیٰ علیہ السلام نے کہا کہ یہ لوگ تو ایسے تھے کہ ہم ان کے یہاں آئے اور انہوں نے ہماری میزبانی سے بھی انکار کیا۔ پھر ان کی دیوار آپ نے ٹھیک کر دی ‘ اگر آپ چاہتے تو اس کی اجرت ان سے لے سکتے تھے۔ خضر علیہ السلام نے فرمایا کہ بس یہاں سے میرے اور آپ کے درمیان جدائی ہو گئی جن باتوں پر آپ صبر نہیں کر سکتے ‘ میں ان کی تاویل و توجیہ اب تم پر واضح کر دوں گا۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ہماری تو خواہش یہ تھی کہ موسیٰ علیہ السلام صبر کرتے اور اللہ تعالیٰ تکوینی واقعات ہمارے لیے بیان کرتا۔ سفیان نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا: اللہ تعالیٰ موسیٰ علیہ السلام پر رحم کرے ‘ اگر انہوں نے صبر کیا ہوتا تو ان کے ( مزید واقعات ) ہمیں معلوم ہوتے۔ ابن عباس رضی اللہ عنہما نے ( جمہور کی قرآت «ودرائهم» کے بجائے ) «أمامهم ملك يأخذ كل سفينة صالحة غصبا» پڑھا ہے۔ اور وہ بچہ ( جس کی خضر علیہ السلام نے جان لی تھی ) کافر تھا اور اس کے والدین مومن تھے۔ پھر مجھ سے سفیان نے بیان کیا کہ میں نے یہ حدیث عمرو بن دینار سے دو مرتبہ سنی تھی اور انہیں سے ( سن کر ) یاد کی تھی۔ سفیان نے کسی سے پوچھا تھا کہ کیا یہ حدیث آپ نے عمرو بن دینار سے سننے سے پہلے ہی کسی دوسرے شخص سے سن کر ( جس نے عمرو بن دینار سے سنی ہو ) یاد کی تھی؟ یا ( اس کے بجائے یہ جملہ کہا ) «تحفظته من إنسان» دو مرتبہ ( شک علی بن عبداللہ کو تھا ) تو سفیان نے کہا کہ دوسرے کسی شخص سے سن کر میں یاد کرتا ‘ کیا اس حدیث کو عمرو بن دینار سے میرے سوا کسی اور نے بھی روایت کیا ہے؟ میں نے ان سے یہ حدیث دو یا تین مرتبہ سنی اور انہیں سے سن کر یاد کی۔' WHERE id = 3262;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن جعفر نے بیان کیا ‘ انہوں نے کہا ہم سے وکیع نے بیان کیا ‘ ان سے شعبہ نے بیان کیا ‘ ان سے عمرو بن مرہ نے ‘ ان سے مرہ ہمدانی نے اور ان سے ابوموسیٰ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”مردوں میں تو بہت سے کامل لوگ اٹھے لیکن عورتوں میں فرعون کی بیوی آسیہ اور مریم بنت عمران علیہما السلام کے سوا اور کوئی کامل نہیں پیدا ہوئی ‘ ہاں عورتوں پر عائشہ رضی اللہ عنہا کی فضیلت ایسی ہے جیسے تمام کھانوں پر ثرید کی فضیلت ہے۔“' WHERE id = 3272;
UPDATE hadiths SET urdu = 'ہم سے محمد بن بشار نے بیان کیا، انہوں نے کہا ہم سے محمد بن جعفر نے بیان کیا، ان سے شعبہ نے بیان کیا، ان سے محمد بن زیاد نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”ایک سرکش جن کل رات میرے سامنے آ گیا تاکہ میری نماز خراب کر دے لیکن اللہ تعالیٰ نے مجھے اس پر قدرت دے دی اور میں نے اسے پکڑ لیا۔ پھر میں نے چاہا کہ اسے مسجد کے کسی ستون سے باندھ دوں کہ تم سب لوگ بھی دیکھ سکو۔ لیکن مجھے اپنے بھائی سلیمان علیہ السلام کی دعا یاد آ گئی کہ یا اللہ! مجھے ایسی سلطنت دے جو میرے سوا کسی کو میسر نہ ہو۔ اس لیے میں نے اسے نامراد واپس کر دیا۔ «عفريت» سرکش کے معنی میں ہے، خواہ انسانوں میں سے ہو یا جنوں میں سے۔“' WHERE id = 3283;
UPDATE hadiths SET urdu = 'اور ابن وہب نے بیان کیا کہ مجھے یونس نے خبر دی، ان سے ابن شہاب نے بیان کیا، کہا کہ مجھ سے سعید بن مسیب نے بیان کیا اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم سے سنا، آپ صلی اللہ علیہ وسلم نے فرمایا کہ اونٹ پر سوار ہونے والیوں ( عربی خواتین ) میں سب سے بہترین قریشی خواتین ہیں۔ اپنے بچے پر سب سے زیادہ محبت و شفقت کرنے والی اور اپنے شوہر کے مال و اسباب کی سب سے بہتر نگراں و محافظ۔ ابوہریرہ رضی اللہ عنہ یہ حدیث بیان کرنے کے بعد کہتے تھے کہ مریم بنت عمران اونٹ پر کبھی سوار نہیں ہوئی تھیں۔ یونس کے ساتھ اس حدیث کو زہری کے بھتیجے اور اسحاق کلبی نے بھی زہری سے روایت کیا ہے۔' WHERE id = 3293;
UPDATE hadiths SET urdu = 'ہم سے محمد بن مقاتل نے بیان کیا، کہا ہم کو عبداللہ بن مبارک نے خبر دی، کہا ہم کو صالح بن حیی نے خبر دی کہ خراسان کے ایک شخص نے شعبی سے پوچھا تو انہوں نے بیان کیا کہ مجھے ابوبردہ نے خبر دی اور ان سے ابوموسیٰ اشعری رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے بیان فرمایا ”اگر کوئی شخص اپنی لونڈی کو اچھی طرح ادب سکھلائے اور پورے طور پر اسے دین کی تعلیم دے۔ پھر اسے آزاد کر کے اس سے نکاح کر لے تو اسے دوگنا ثواب ملتا ہے اور وہ شخص جو پہلے عیسیٰ علیہ السلام پر ایمان رکھتا تھا، پھر مجھ پر ایمان لایا تو اسے بھی دوگنا ثواب ملتا ہے اور وہ غلام جو اپنے رب کا بھی ڈر رکھتا ہے اور اپنے آقا کی بھی اطاعت کرتا ہے تو اسے بھی دوگنا ثواب ملتا ہے۔“' WHERE id = 3304;
UPDATE hadiths SET urdu = 'ہم سے ابوعاصم ضحاک بن مخلد نے بیان کیا، کہا ہم کو اوزاعی نے خبر دی، کہا ہم سے حسان بن عطیہ نے بیان کیا، ان سے ابوکبشہ نے اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”میرا پیغام لوگوں کو پہنچاؤ! اگرچہ ایک ہی آیت ہو اور بنی اسرائیل کے واقعات تم بیان کر سکتے ہو، ان میں کوئی حرج نہیں اور جس نے مجھ پر قصداً جھوٹ باندھا تو اسے اپنے جہنم کے ٹھکانے کے لیے تیار رہنا چاہئے۔“' WHERE id = 3316;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ مدینی نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے بیان کیا، کہا ہم سے ابوالزناد نے بیان کیا، ان سے اعرج نے ان سے ابوسلمہ نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے صبح کی نماز پڑھی پھر لوگوں کی طرف متوجہ ہوئے اور فرمایا ”ایک شخص ( بنی اسرائیل کا ) اپنی گائے ہانکے لیے جا رہا تھا کہ وہ اس پر سوار ہو گیا اور پھر اسے مارا۔ اس گائے نے ( بقدرت الہیٰ ) کہا کہ ہم جانور سواری کے لیے نہیں پیدا کئے گئے۔ ہماری پیدائش تو کھیتی کے لیے ہوئی ہے۔“ لوگوں نے کہا سبحان اللہ! گائے بات کرتی ہے۔ پھر آپ صلی اللہ علیہ وسلم نے فرمایا کہ میں اس بات پر ایمان لاتا ہوں اور ابوبکر اور عمر بھی۔ حالانکہ یہ دونوں وہاں موجود بھی نہیں تھے۔ اسی طرح ایک شخص اپنی بکریاں چرا رہا تھا کہ ایک بھیڑیا آیا اور ریوڑ میں سے ایک بکری اٹھا کر لے جانے لگا۔ ریوڑ والا دوڑا اور اس نے بکری کو بھیڑئیے سے چھڑا لیا۔ اس پر بھیڑیا ( بقدرت الہیٰ ) بولا، آج تو تم نے مجھ سے اسے چھڑا لیا لیکن درندوں والے دن میں ( قرب قیامت ) اسے کون بچائے گا جس دن میرے سوا اور کوئی اس کا چرواہا نہ ہو گا؟ لوگوں نے کہا، سبحان اللہ! بھیڑیا باتیں کرتا ہے۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ میں تو اس بات پر ایمان لایا اور ابوبکر و عمر بھی حالانکہ وہ دونوں اس وقت وہاں موجود نہ تھے۔ امام بخاری رحمہ اللہ نے کہا اور ہم سے علی بن عبداللہ مدینی نے کہا، ہم سے سفیان بن عیینہ نے بیان کیا، انہوں نے مسعر سے، انہوں نے سعد بن ابراہیم سے، انہوں نے ابوسلمہ سے روایت کیا اور انہوں نے ابوہریرہ رضی اللہ عنہ سے اور انہوں نے رسول اللہ صلی اللہ علیہ وسلم سے یہی حدیث بیان کی۔' WHERE id = 3326;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد مسندی نے بیان کیا کہا ہم سے ہشام نے بیان کیا کہا ہم کو معمر نے خبر دی، انہیں زہری نے انہیں حمید بن عبدالرحمٰن نے اور انہیں ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”ایک شخص بہت گناہ کیا کرتا تھا جب اس کی موت کا وقت قریب آیا تو اپنے بیٹوں سے اس نے کہا کہ جب میں مر جاؤں تو مجھے جلا ڈالنا پھر میری ہڈیوں کو پیس کر ہوا میں اڑا دینا اللہ کی قسم! اگر میرے رب نے مجھے پکڑ لیا تو مجھے اتنا سخت عذاب کرے گا جو پہلے کسی کو بھی اس نے نہیں کیا ہو گا۔ جب وہ مر گیا تو ( اس کی وصیت کے مطابق ) اس کے ساتھ ایسا ہی کیا گیا۔ اللہ تعالیٰ نے زمین کو حکم فرمایا کہ اگر ایک ذرہ بھی کہیں اس کے جسم کا تیرے پاس ہے تو اسے جمع کر کے لا۔ زمین حکم بجا لائی اور وہ بندہ اب ( اپنے رب کے سامنے ) کھڑا ہوا تھا۔ اللہ تعالیٰ نے دریافت فرمایا: تو نے ایسا کیوں کیا؟ اس نے عرض کیا: اے رب! تیرے ڈر کی وجہ سے۔ آخر اللہ تعالیٰ نے اس کی مغفرت کر دی۔ ابوہریرہ رضی اللہ عنہ کے سوا دوسرے صحابہ نے اس حدیث میں لفظ «خشيتك‏» کے بدل «مخافتك» کہا ہے ( دونوں لفظوں کا مطلب ایک ہی ہے ) ۔' WHERE id = 3336;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، ان سے عبدالواحد نے، کہا ہم سے کلیب نے بیان کیا، اور ان سے ربیبہ نبی کریم صلی اللہ علیہ وسلم نے، میرا خیال ہے کہ ان سے مراد زینب بنت ابی سلمہ رضی اللہ عنہا ہیں، انہوں نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے دباء، حنتم، نقیر اور مزفت کے استعمال سے منع فرمایا تھا اور میں نے ان سے پوچھا تھا کہ آپ مجھے بتائیے کہ نبی کریم صلی اللہ علیہ وسلم کا تعلق کس قبیلہ سے تھا؟ کیا واقعی آپ کا تعلق قبیلہ مضر سے تھا؟ انہوں نے کہا پھر اور کس سے ہو سکتا ہے یقیناً آپ صلی اللہ علیہ وسلم کا تعلق اسی قبیلہ سے تھا۔ آپ نضر بنی بن کنانہ کی اولاد میں سے تھے۔' WHERE id = 3346;
UPDATE hadiths SET urdu = 'ہم سے عبدالعزیز بن عبداللہ نے بیان کیا، کہا ہم سے ابراہیم بن سعد نے بیان کیا، ان سے ابن شہاب نے اور ان سے انس رضی اللہ عنہ نے کہ عثمان رضی اللہ عنہ نے زید بن ثابت، عبداللہ بن زبیر، سعید بن عاص اور عبدالرحمٰن بن حارث بن ہشام رضی اللہ عنہم کو بلایا ( اور ان کو قرآن مجید کی کتابت پر مقرر فرمایا، چنانچہ ان حضرات نے ) قرآن مجید کو کئی مصحفوں میں نقل فرمایا اور عثمان رضی اللہ عنہ نے ( ان چاروں میں سے ) تین قریشی صحابہ سے فرمایا تھا کہ جب آپ لوگوں کا زید بن ثابت رضی اللہ عنہ سے ( جو مدینہ منورہ کے رہنے والے تھے ) قرآن کے کسی مقام پر ( اس کے کسی محاورے میں ) اختلاف ہو جائے تو اس کو قریش کے محاورے کے مطابق لکھنا، کیونکہ قرآن شریف قریش کے محاورہ میں نازل ہوا ہے۔ انہوں نے ایسا ہی کیا۔' WHERE id = 3358;
UPDATE hadiths SET urdu = 'مجھ سے محمد بن بشار نے بیان کیا، کہا ہم سے غندر نے بیان کیا، ان سے شعبہ نے بیان کیا، ان سے محمد بن ابی یعقوب نے بیان کیا، انہوں نے عبدالرحمٰن بن ابی بکرہ سے سنا، انہوں نے اپنے والد سے کہ ہم سے سلیمان بن حرب نے بیان کیا، کہا ہم سے حماد نے بیان کیا، ان سے ایوب نے، ان سے محمد نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ اقرع بن حابس رضی اللہ عنہ نے نبی کریم صلی اللہ علیہ وسلم سے عرض کیا کہ آپ سے ان لوگوں نے بیعت کی ہے کہ جو حاجیوں کا سامان چرایا کرتے تھے یعنی اسلم اور غفار اور مزینہ کے لوگ، محمد بن ابی یعقوب نے کہا کہ میں سمجھتا ہوں عبدالرحمٰن نے جہینہ کا بھی ذکر کیا، شعبہ نے کہا کہ یہ شک محمد بن ابی یعقوب کو ہوا۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”بتلاؤ اسلم، غفار، مزینہ، اور میں سمجھتا ہوں کہ جہینہ کو بھی کہا یہ چاروں قبیلے بنی تمیم، بنی عامر اور اسد اور غطفان سے بہتر نہیں ہیں؟ کیا یہ ( مؤخرالذکر ) خراب اور برباد نہیں ہوئے؟“ اقرع نے کہا: ہاں، آپ صلی اللہ علیہ وسلم نے فرمایا ”قسم ہے اس ذات کی جس کے ہاتھ میں میری جان ہے! یہ ان سے بہتر ہیں۔“ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ قبیلہ اسلم، غفار، مزینہ اور جہینہ کے کچھ لوگ یا انہوں نے بیان کیا کہ مزینہ کے کچھ لوگ یا ( بیان کیا کہ ) جہینہ کے کچھ لوگ اللہ تعالیٰ کے نزدیک یا بیان کیا کہ قیامت کے دن قبیلہ اسد، تمیم، ہوازن اور غطفان سے بہتر ہوں گے۔' WHERE id = 3368;
UPDATE hadiths SET urdu = '(امام بخاری رحمہ اللہ نے) کہا کہ ہم سے قبیصہ نے بیان کیا، انہیں سفیان نے خبر دی، انہیں حبیب بن ابی ثابت نے، انہیں سعید بن جبیر نے اور ان سے ابن عباس رضی اللہ عنہما نے بیان کیا کہ جب یہ آیت «وأنذر عشيرتك الأقربين‏» ”اور آپ اپنے قریبی رشتہ داروں کو ڈرائیے۔“ اتری تو نبی کریم صلی اللہ علیہ وسلم نے الگ الگ قبائل کو دعوت دی۔' WHERE id = 3378;
UPDATE hadiths SET urdu = 'ہم سے حفص بن عمر نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے حمید نے اور ان سے انس رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم بازار میں تھے کہ ایک صاحب کی آواز آئی۔ یا اباالقاسم! آپ ان کی طرف متوجہ ہوئے ( معلوم ہوا کہ انہوں نے کسی اور کو پکارا ہے ) اس پر آپ صلی اللہ علیہ وسلم نے فرمایا ”میرے نام پر نام رکھو لیکن میری کنیت مت رکھو۔“' WHERE id = 3388;
UPDATE hadiths SET urdu = 'مجھ سے یحییٰ بن بکیر نے بیان کیا، کہا کہ مجھ سے لیث نے بیان کیا، ان سے خالد نے، ان سے سعید بن ابی ہلال نے، ان سے ربیعہ بن ابی عبدالرحمٰن نے بیان کیا کہ میں نے انس بن مالک رضی اللہ عنہ سے سنا، آپ نے نبی کریم صلی اللہ علیہ وسلم کے اوصاف مبارکہ بیان کرتے ہوئے بتلایا کہ آپ صلی اللہ علیہ وسلم درمیانہ قد کے تھے۔ نہ بہت لمبے اور نہ چھوٹے قد والے۔ رنگ کھلتا ہوا تھا ( سرخ و سفید ) نہ خالی سفید تھے اور نہ بالکل گندم گوں۔ آپ کے بال نہ بالکل مڑے ہوئے سخت قسم کے تھے اور نہ سیدھے لٹکے ہوئے ہی تھے۔ نزول وحی کے وقت آپ کی عمر چالیس سال تھی۔ مکہ میں آپ نے دس سال تک قیام فرمایا اور اس پورے عرصہ میں آپ پر وحی نازل ہوتی رہی اور مدینہ میں بھی آپ کا قیام دس سال تک رہا۔ آپ کے سر اور داڑھی میں بیس بال بھی سفید نہیں ہوئے تھے۔ ربیعہ ( راوی حدیث ) نے بیان کیا کہ پھر میں نے آپ صلی اللہ علیہ وسلم کا ایک بال دیکھا تو وہ لال تھا میں نے اس کے متعلق پوچھا تو مجھے بتایا گیا کہ خوشبو لگاتے لگاتے لال ہو گیا ہے۔' WHERE id = 3398;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا ہم سے یعقوب بن عبدالرحمٰن نے بیان کیا، ان سے عمرو بن ابی عمرو نے، ان سے سعید مقبری نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”میں ( آدم علیہ السلام سے لے کر ) برابر آدمیوں کے بہتر قرنوں میں ہوتا آیا ہوں ( یعنی شریف اور پاکیزہ نسلوں میں ) یہاں تک کہ وہ قرن آیا جس میں میں پیدا ہوا۔“' WHERE id = 3408;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن مسلمہ نے بیان کیا، ان سے امام مالک نے، ان سے سعید مقبری نے، ان سے ابوسلمہ بن عبدالرحمٰن نے انہوں نے عائشہ رضی اللہ عنہا سے پوچھا کہ رمضان شریف میں رسول اللہ صلی اللہ علیہ وسلم کی نماز ( تہجد یا تراویح ) کی کیا کیفیت ہوتی تھی؟ انہوں نے بیان کیا کہ آپ صلی اللہ علیہ وسلم رمضان المبارک یا دوسرے کسی بھی مہینے میں گیارہ رکعت سے زیادہ نہیں پڑھتے تھے ( ان ہی کو تہجد کہو یا تراویح ) پہلے آپ صلی اللہ علیہ وسلم چار رکعت پڑھتے، وہ رکعتیں کتنی لمبی ہوتی تھیں۔ کتنی اس میں خوبی ہوتی تھیں اس کے بارے میں نہ پوچھو۔ پھر آپ صلی اللہ علیہ وسلم چار رکعتیں پڑھتے۔ یہ چاروں بھی کتنی لمبی ہوتیں اور ان میں کتنی خوبی ہوتی۔ اس کے متعلق نہ پوچھو۔ پھر آپ صلی اللہ علیہ وسلم تین رکعت وتر پڑھتے، میں نے عرض کیا: یا رسول اللہ! آپ وتر پڑھنے سے پہلے کیوں سو جاتے ہیں؟ آپ صلی اللہ علیہ وسلم نے فرمایا ”میری آنکھیں سوتی ہیں لیکن میرا دل بیدار رہتا ہے۔“' WHERE id = 3420;
UPDATE hadiths SET urdu = 'مجھ سے محمد بن مثنیٰ نے بیان کیا، کہا ہم سے ابواحمد زبیری نے بیان کیا، کہا ہم سے اسرائیل نے بیان کیا، ان سے منصور نے، ان سے ابراہیم نے ان سے علقمہ نے اور ان سے عبداللہ بن مسعود رضی اللہ عنہ نے بیان کیا کہ معجزات کو ہم تو باعث برکت سمجھتے تھے اور تم لوگ ان سے ڈرتے ہو۔ ایک مرتبہ ہم رسول اللہ صلی اللہ علیہ وسلم کے ساتھ ایک سفر میں تھے اور پانی تقریباً ختم ہو گیا۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ جو کچھ بھی پانی بچ گیا ہو اسے تلاش کرو۔ چنانچہ لوگ ایک برتن میں تھوڑا سا پانی لائے۔ آپ صلی اللہ علیہ وسلم نے اپنا ہاتھ برتن میں ڈال دیا اور فرمایا: برکت والا پانی لو اور برکت تو اللہ تعالیٰ ہی کی طرف سے ہوتی ہے، میں نے دیکھا کہ رسول اللہ صلی اللہ علیہ وسلم کی انگلیوں کے درمیان میں سے پانی فوارے کی طرح پھوٹ رہا تھا اور ہم تو نبی کریم صلی اللہ علیہ وسلم کے زمانے میں کھاتے وقت کھانے کے تسبیح سنتے تھے۔' WHERE id = 3430;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ مدینی نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے بیان کیا، کہا کہ اسماعیل نے بیان کیا کہ مجھ کو قیس نے خبر دی، انہوں نے کہا کہ ہم ابوہریرہ رضی اللہ عنہ کی خدمت میں حاضر ہوئے تو انہوں نے کہا کہ میں رسول اللہ صلی اللہ علیہ وسلم کی صحبت میں تین سال رہا ہوں، اپنی پوری عمر میں مجھے حدیث یاد کرنے کا اتنا شوق کبھی نہیں ہوا جتنا ان تین سالوں میں تھا۔ میں نے نبی کریم صلی اللہ علیہ وسلم کو فرماتے سنا، آپ نے اپنے ہاتھ سے یوں اشارہ کر کے فرمایا کہ قیامت کے قریب تم لوگ ( مسلمان ) ایک ایسی قوم سے جنگ کرو گے جن کے جوتے بالوں کے ہوں گے ( مراد یہی ایرانی ہیں ) سفیان نے ایک مرتبہ «وهو هذا البارز» کے بجائے الفاظ «وهم أهل البازر‏.‏» نقل کئے ( یعنی ایرانی، یا کُردی، یا دیلم والے لوگ مراد ہیں ) ۔' WHERE id = 3440;
UPDATE hadiths SET urdu = 'ہم سے محمد بن کثیر نے بیان کیا، کہا ہم کو سفیان نے خبر دی، انہیں اعمش نے، انہیں زید بن وہب نے اور انہیں عبداللہ بن مسعود رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”میرے بعد تم پر ایک ایسا زمانہ آئے گا جس میں تم پر دوسروں کو مقدم کیا جائے گا اور ایسی باتیں سامنے آئیں گی جن کو تم برا سمجھو گے۔“ لوگوں نے عرض کیا: یا رسول اللہ! اس وقت ہمیں آپ کیا حکم فرماتے ہیں؟ آپ صلی اللہ علیہ وسلم نے فرمایا کہ جو حقوق تم پر دوسروں کے واجب ہوں انہیں ادا کرتے رہنا اور اپنے حقوق اللہ ہی سے مانگنا۔ ( یعنی صبر کرنا اور اپنا حق لینے کے لیے خلیفہ اور حاکم وقت سے بغاوت نہ کرنا ) ۔' WHERE id = 3452;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ نے بیان کیا، کہا ہم سے ازہر بن سعد نے بیان کیا، کہا ہم سے عبداللہ بن عون نے بیان کیا، انہیں موسیٰ بن انس نے خبر دی اور انہیں انس بن مالک رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم کو ایک دن ثابت بن قیس رضی اللہ عنہ نہیں ملے تو ایک صحابی نے کہا: یا رسول اللہ! میں آپ کے لیے ان کی خبر لاتا ہوں۔ چنانچہ وہ ان کے یہاں آئے تو دیکھا کہ اپنے گھر میں سر جھکائے بیٹھے ہیں، انہوں نے پوچھا کہ کیا حال ہے؟ انہوں نے کہا کہ برا حال ہے۔ ان کی عادت تھی کہ نبی کریم صلی اللہ علیہ وسلم کے سامنے آپ صلی اللہ علیہ وسلم سے بھی اونچی آواز میں بولا کرتے تھے۔ انہوں نے کہا اسی لیے میرا عمل غارت ہو گیا اور میں دوزخیوں میں ہو گیا ہوں۔ وہ صحابی نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئے اور آپ صلی اللہ علیہ وسلم کو اطلاع دی کہ ثابت رضی اللہ عنہ یوں کہہ رہے ہیں۔ موسیٰ بن انس نے بیان کیا، لیکن دوسری مرتبہ وہی صحابی ثابت رضی اللہ عنہ کے پاس ایک بڑی خوشخبری لے کر واپس ہوئے۔ آپ صلی اللہ علیہ وسلم نے ان سے فرمایا تھا کہ ثابت کے پاس جاؤ اور اس سے کہو کہ وہ اہل جہنم میں سے نہیں ہیں بلکہ وہ اہل جنت میں سے ہیں۔' WHERE id = 3462;
UPDATE hadiths SET urdu = 'مجھ سے عبداللہ بن محمد مسندی نے بیان کیا، انہوں نے کہا ہم سے یحییٰ بن آدم نے بیان کیا، انہوں نے کہا ہم سے حسین جعفی نے بیان کیا، ان سے ابوموسیٰ نے، ان سے امام حسن بصری نے اور ان سے ابوبکرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم حسن رضی اللہ عنہ کو ایک دن ساتھ لے کر باہر تشریف لائے اور منبر پر ان کو لے کر چڑھ گئے پھر فرمایا ”میرا یہ بیٹا سید ہے اور امید ہے کہ اللہ تعالیٰ اس کے ذریعہ مسلمانوں کی دو جماعتوں میں ملاپ کرا دے گا۔“' WHERE id = 3475;
UPDATE hadiths SET urdu = 'مجھ سے محمد بن مثنیٰ نے بیان کیا، کہا ہم سے معاذ نے بیان کیا، کہا کہ مجھ سے میرے والد نے بیان کیا، ان سے قتادہ نے اور ان سے انس رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم سے دو صحابی ( اسید بن حضیر اور عباد بن بشر رضی اللہ عنہما ) اٹھ کر ( اپنے گھر ) واپس ہوئے۔ رات اندھیری تھی لیکن دو چراغ کی طرح کی کوئی چیز ان کے آگے روشنی کرتی جاتی تھیں۔ پھر جب یہ دونوں ( راستے میں، اپنے اپنے گھر کی طرف جانے کے لیے ) جدا ہوئے تو وہ چیز دونوں کے ساتھ الگ الگ ہو گئی اور اس طرح وہ اپنے گھر والوں کے پاس پہنچ گئے۔' WHERE id = 3485;
UPDATE hadiths SET urdu = 'ہم سے محمد بن کثیر نے بیان کیا، کہا ہم سے سفیان ثوری نے بیان کیا، ان سے منصور نے، ان سے ابراہیم نے، ان سے عبیدہ بن قیس سلمانی نے اور ان سے عبداللہ بن مسعود رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ بہترین زمانہ میرا ہے۔ پھر ان لوگوں کا جو اس زمانہ کے بعد آئیں گے پھر ان لوگوں کا جو اس کے بعد آئیں گے۔ اس کے بعد ایک ایسی قوم پیدا ہو گی کہ گواہی دینے سے پہلے قسم ان کی زبان پر آ جایا کرے گی اور قسم کھانے سے پہلے گواہی ان کی زبان پر آ جایا کرے گی۔ ابراہیم نے بیان کیا کہ جب ہم چھوٹے تھے تو گواہی اور عہد ( کے الفاظ زبان پر لانے ) کی وجہ سے ہمارے بڑے بزرگ ہم کو مارا کرتے تھے۔' WHERE id = 3496;
UPDATE hadiths SET urdu = 'مجھ سے ہشام بن عمار نے بیان کیا، کہا ہم سے صدقہ بن خالد نے بیان کیا، ان سے زید بن واقد نے بیان کیا، ان سے بسر بن عبیداللہ نے، ان سے عائذ اللہ ابوادریس نے اور ان سے ابودرداء رضی اللہ عنہ نے بیان کیا کہ میں نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر تھا کہ ابوبکر رضی اللہ عنہ اپنے کپڑے کا کنارہ پکڑے ہوئے، گھٹنا ظاہر کئے ہوئے آئے۔ نبی کریم صلی اللہ علیہ وسلم نے یہ حالت دیکھ کر فرمایا کہ معلوم ہوتا ہے تمہارے دوست کسی سے لڑ کر آئے ہیں۔ پھر ابوبکر رضی اللہ عنہ نے حاضر ہو کر سلام کیا اور عرض کیا: یا رسول اللہ! میرے اور عمر بن خطاب کے درمیان کچھ تکرار ہو گئی تھی اور اس سلسلے میں، میں نے جلدی میں ان کو سخت لفظ کہہ دیئے لیکن بعد میں مجھے سخت ندامت ہوئی تو میں نے ان سے معافی چاہی، اب وہ مجھے معاف کرنے کے لیے تیار نہیں ہیں۔ اسی لیے میں آپ کی خدمت میں حاضر ہوا ہوں۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ اے ابوبکر! تمہیں اللہ معاف کرے۔ تین مرتبہ آپ نے یہ جملہ ارشاد فرمایا عمر رضی اللہ عنہ کو بھی ندامت ہوئی اور ابوبکر رضی اللہ عنہ کے گھر پہنچے اور پوچھا کیا ابوبکر گھر پر موجود ہیں؟ معلوم ہوا کہ نہیں تو آپ بھی نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئے اور آپ نے سلام کیا۔ نبی کریم صلی اللہ علیہ وسلم کا چہرہ مبارک غصہ سے بدل گیا اور ابوبکر رضی اللہ عنہ ڈر گئے اور گھٹنوں کے بل بیٹھ کر عرض کرنے لگے، یا رسول اللہ! اللہ کی قسم زیادتی میری ہی طرف سے تھی۔ دو مرتبہ یہ جملہ کہا۔ اس کے بعد آپ صلی اللہ علیہ وسلم نے فرمایا کہ اللہ نے مجھے تمہاری طرف نبی بنا کر بھیجا تھا۔ اور تم لوگوں نے مجھ سے کہا تھا کہ تم جھوٹ بولتے ہو لیکن ابوبکر نے کہا تھا کہ آپ سچے ہیں اور اپنی جان و مال کے ذریعہ انہوں نے میری مدد کی تھی تو کیا تم لوگ میرے دوست کو ستانا چھوڑتے ہو یا نہیں؟ آپ نے دو دفعہ یہی فرمایا: آپ کے یہ فرمانے کے بعد پھر ابوبکر رضی اللہ عنہ کو کسی نے نہیں ستایا۔' WHERE id = 3506;
UPDATE hadiths SET urdu = 'مجھ سے محمد بن بشار نے بیان کیا، کہا کہ مجھ سے یحییٰ بن سعید قطان نے بیان کیا، ان سے سعید نے، ان سے قتادہ نے اور ان سے انس بن مالک رضی اللہ عنہ نے بیان کیا کہ جب نبی کریم صلی اللہ علیہ وسلم ، ابوبکر، عمر اور عثمان رضی اللہ عنہم کو ساتھ لے کر احد پہاڑ پر چڑھے تو احد کانپ اٹھا، آپ صلی اللہ علیہ وسلم نے فرمایا ”احد! قرار پکڑ کہ تجھ پر ایک نبی، ایک صدیق اور دو شہید ہیں۔“' WHERE id = 3518;
UPDATE hadiths SET urdu = 'ہم سے عبدان نے بیان کیا، کہا ہم کو عبداللہ نے خبر دی، کہا ہم سے عمر بن سعید نے بیان کیا، ان سے ابن ابی ملیکہ اور انہوں نے ابن عباس رضی اللہ عنہما کو کہتے سنا کہ جب عمر رضی اللہ عنہ کو ( شہادت کے بعد ) ان کی چارپائی پر رکھا گیا تو تمام لوگوں نے نعش مبارک کو گھیر لیا اور ان کے لیے ( اللہ سے ) دعا اور مغفرت طلب کرنے لگے، نعش ابھی اٹھائی نہیں گئی تھی، میں بھی وہیں موجود تھا۔ اسی حالت میں اچانک ایک صاحب نے میرا شانہ پکڑ لیا، میں نے دیکھا تو وہ علی رضی اللہ عنہ تھے، پھر انہوں نے عمر رضی اللہ عنہ کے لیے دعا رحمت کی اور ( ان کی نعش کو مخاطب کر کے ) کہا: آپ نے اپنے بعد کسی بھی شخص کو نہیں چھوڑا کہ جسے دیکھ کر مجھے یہ تمنا ہوتی کہ اس کے عمل جیسا عمل کرتے ہوئے میں اللہ سے جا ملوں اور اللہ کی قسم! مجھے تو ( پہلے سے ) یقین تھا کہ اللہ تعالیٰ آپ کو آپ کے دونوں ساتھیوں کے ساتھ ہی رکھے گا۔ میرا یہ یقین اس وجہ سے تھا کہ میں نے اکثر رسول اللہ صلی اللہ علیہ وسلم کی زبان مبارک سے یہ الفاظ سنے تھے کہ ”میں، ابوبکر اور عمر گئے۔ میں، ابوبکر اور عمر داخل ہوئے۔ میں، ابوبکر اور عمر باہر آئے۔“' WHERE id = 3528;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا، کہا ہم سے حماد بن زید نے بیان کیا، ان سے ایوب نے، ان سے ابوعثمان نے اور ان سے ابوموسیٰ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم ایک باغ ( بئراریس ) کے اندر تشریف لے گئے اور مجھ سے فرمایا کہ میں دروازہ پر پہرہ دیتا رہوں۔ پھر ایک صاحب آئے اور اجازت چاہی۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ انہیں اجازت دے دو اور جنت کی خوشخبری بھی سنا دو، وہ ابوبکر رضی اللہ عنہ تھے۔ پھر دوسرے ایک اور صاحب آئے اور اجازت چاہی۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ انہیں بھی اجازت دے دو اور جنت کی خوشخبری سنا دو، وہ عمر رضی اللہ عنہ تھے۔ پھر تیسرے ایک اور صاحب آئے اور اجازت چاہی۔ نبی کریم صلی اللہ علیہ وسلم تھوڑی دیر کے لیے خاموش ہو گئے پھر فرمایا کہ انہیں بھی اجازت دے دو اور ( دنیا میں ) ایک آزمائش سے گزرنے کے بعد جنت کی بشارت بھی سنا دو، وہ عثمان غنی رضی اللہ عنہ تھے۔ حماد بن سلمہ نے بیان کیا، ہم سے عاصم احول اور علی بن حکم نے بیان کیا، انہوں نے ابوعثمان سے سنا اور وہ ابوموسیٰ سے اسی طرح بیان کرتے تھے، لیکن عاصم نے اپنی اس روایت میں یہ زیادہ کیا ہے کہ نبی کریم صلی اللہ علیہ وسلم اس وقت ایک ایسی جگہ بیٹھے ہوئے تھے جس کے اندر پانی تھا اور آپ اپنے دونوں گھٹنے یا ایک گھٹنہ کھولے ہوئے تھے لیکن جب عثمان رضی اللہ عنہ داخل ہوئے تو آپ نے اپنے گھٹنے کو چھپا لیا۔' WHERE id = 3538;
UPDATE hadiths SET urdu = 'ہم سے محمد بن بشار نے بیان کیا، کہا ہم سے غندر نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے حکم نے، انہوں نے ابن ابی لیلیٰ سے سنا، کہا ہم سے علی رضی اللہ عنہ نے بیان کیا کہ فاطمہ رضی اللہ عنہا نے ( نبی کریم صلی اللہ علیہ وسلم سے ) چکی پیسنے کی تکلیف کی شکایت کی، اس کے بعد آپ صلی اللہ علیہ وسلم کے پاس کچھ قیدی آئے تو فاطمہ رضی اللہ عنہا آپ کے پاس آئیں لیکن آپ موجود نہیں تھے۔ عائشہ رضی اللہ عنہا سے ان کی ملاقات ہوئی تو ان سے اس کے بارے میں انہوں نے بات کی جب نبی کریم صلی اللہ علیہ وسلم تشریف لائے تو عائشہ رضی اللہ عنہا نے آپ صلی اللہ علیہ وسلم کو فاطمہ رضی اللہ عنہا کے آنے کی اطلاع دی، اس پر نبی کریم صلی اللہ علیہ وسلم خود ہمارے گھر تشریف لائے، اس وقت ہم اپنے بستروں پر لیٹ چکے تھے، میں نے چاہا کہ کھڑا ہو جاؤں لیکن آپ صلی اللہ علیہ وسلم نے فرمایا کہ یوں ہی لیٹے رہو، اس کے بعد آپ ہم دونوں کے درمیان بیٹھ گئے اور میں نے آپ صلی اللہ علیہ وسلم کے قدموں کی ٹھنڈک اپنے سینے میں محسوس کی،۔ پھر آپ صلی اللہ علیہ وسلم نے فرمایا کہ تم لوگوں نے مجھ سے جو طلب کیا ہے کیا میں تمہیں اس سے اچھی بات نہ بتاؤں، جب تم سونے کے لیے بستر پر لیٹو تو چونتیس مرتبہ اللہ اکبر، تینتیس مرتبہ سبحان اللہ اور تینتیس مرتبہ الحمدللہ پڑھ لیا کرو، یہ عمل تمہارے لیے کسی خادم سے بہتر ہے۔' WHERE id = 3548;
UPDATE hadiths SET urdu = 'مجھ سے عبید بن اسماعیل نے بیان کیا، کہا ہم سے اسامہ نے بیان کیا، ان سے ہشام نے، انہیں ان کے والد نے خبر دی کہ میں نے مروان سے سنا کہ میں عثمان رضی اللہ عنہ کی خدمت میں موجود تھا کہ اتنے میں ایک صاحب آئے اور کہا کہ کسی کو آپ اپنا خلیفہ بنا دیجئیے،۔ آپ نے دریافت فرمایا کیا اس کی خواہش کی جا رہی ہے؟ انہوں نے بتایا کہ جی ہاں، زبیر رضی اللہ عنہ کی طرف لوگوں کا رجحان ہے، آپ نے اس پر فرمایا ٹھیک ہے، تم کو بھی معلوم ہے کہ وہ تم میں بہتر ہیں، آپ نے تین مرتبہ یہ بات دہرائی۔' WHERE id = 3559;
UPDATE hadiths SET urdu = 'ہم سے خالد بن مخلد نے بیان کیا، کہا ہم سے سلیمان نے بیان کیا، کہا کہ مجھ سے عبداللہ بن دینار نے بیان کیا، ان سے عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے ایک فوج بھیجی اور اس کا امیر اسامہ بن زید کو بنایا۔ ان کے امیر بنائے جانے پر بعض لوگوں نے اعتراض کیا تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ اگر آج تم اس کے امیر بنائے جانے پر اعتراض کر رہے ہو تو اس سے پہلے اس کے باپ کے امیر بنائے جانے پر بھی تم نے اعتراض کیا تھا اور اللہ کی قسم! وہ ( زید رضی اللہ عنہ ) امارت کے مستحق تھے اور مجھے سب سے زیادہ عزیز تھے۔ اور یہ ( اسامہ رضی اللہ عنہ ) اب ان کے بعد مجھے سب سے زیادہ عزیز ہیں۔' WHERE id = 3570;
UPDATE hadiths SET urdu = 'ہم سے عمرو بن علی نے بیان کیا، کہا ہم سے عبدالاعلیٰ نے بیان کیا، کہا ہم سے خالد نے بیان کیا، ان سے ابوقلابہ نے بیان کیا، اور ان سے انس بن مالک رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ ہر امت میں امین ہوتے ہیں اور اس امت کے امین ابوعبیدہ بن جراح ہیں۔' WHERE id = 3582;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم نے بیان کیا، کہا ہم سے عبدالعزیز بن ابی سلمہ نے بیان کیا، ان سے محمد بن منکدر نے کہا ہم کو جابر بن عبداللہ رضی اللہ عنہما نے خبر دی کہ عمر رضی اللہ عنہ کہا کرتے تھے کہ ابوبکر رضی اللہ عنہ ہمارے سردار ہیں اور ہمارے سردار کو انہوں نے آزاد کیا ہے، ان کی مراد بلال حبشی رضی اللہ عنہ سے تھی۔' WHERE id = 3592;
UPDATE hadiths SET urdu = 'مجھ سے عمرو بن عباس نے بیان کیا، کہا ہم سے محمد بن جعفر نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے ابوالتیاح نے بیان کیا، انہوں نے حمران بن ابان سے سنا کہ معاویہ رضی اللہ عنہ نے کہا تم لوگ ایک خاص نماز پڑھتے ہو، ہم لوگ نبی کریم صلی اللہ علیہ وسلم کی صحبت میں رہے اور ہم نے کبھی آپ صلی اللہ علیہ وسلم کو اس وقت نماز پڑھتے نہیں دیکھا، بلکہ آپ نے تو اس سے منع فرمایا تھا۔ معاویہ رضی اللہ عنہ کی مراد عصر کے بعد دو رکعت نماز سے تھی ( جسے اس زمانے میں بعض لوگ پڑھتے تھے ) ۔' WHERE id = 3604;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا کہا ہم سے مہدی بن میمون نے، کہا ہم سے غیلان بن جریر نے بیان کیا میں نے انس رضی اللہ عنہ سے پوچھا بتلائیے ( انصار ) اپنا نام آپ لوگوں نے خود رکھ لیا تھا یا آپ لوگوں کا یہ نام اللہ تعالیٰ نے رکھا؟ انہوں نے کہا نہیں بلکہ ہمارا یہ نام اللہ تعالیٰ نے رکھا ہے۔ غیلان کی روایت ہے کہ ہم انس رضی اللہ عنہ کی خدمت میں حاضر ہوتے تو آپ ہم سے انصار کی فضیلتیں اور غزوات میں ان کے مجاہدانہ واقعات بیان کیا کرتے پھر میری طرف یا قبیلہ ازد کے ایک شخص کی طرف متوجہ ہو کر کہتے: تمہاری قوم ( انصار ) نے فلاں دن فلاں دن فلاں فلاں کام انجام دیے۔' WHERE id = 3614;
UPDATE hadiths SET urdu = 'ہم سے یعقوب بن ابراہیم بن کثیر نے بیان کیا، کہا ہم سے بہز بن اسد نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، کہا کہ مجھے ہشام بن زید نے خبر دی، کہا کہ میں نے انس بن مالک رضی اللہ عنہ سے سنا انہوں نے کہا کہ انصار کی ایک عورت نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئیں۔ ان کے ساتھ ایک ان کا بچہ بھی تھا۔ آپ صلی اللہ علیہ وسلم نے ان سے کلام کیا پھر فرمایا: اس ذات کی قسم! جس کے ہاتھ میں میری جان ہے۔ تم لوگ مجھے سب سے زیادہ محبوب ہو دو مرتبہ آپ صلی اللہ علیہ وسلم نے یہ جملہ فرمایا۔' WHERE id = 3624;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے حمید طویل نے، انہوں نے انس بن مالک رضی اللہ عنہ سے سنا آپ نے فرمایا کہ انصار غزوہ خندق کے موقعہ پر ( خندق کھودتے ہوئے ) یہ شعر پڑھتے تھے «نحن الذين بايعوا محمدا على الجهاد ما حيينا أبدا» ”ہم وہ ہیں جنہوں نے محمد ( صلی اللہ علیہ وسلم ) سے جہاد پر بیعت کی ہے، جب تک ہماری جان میں جان ہے۔“ آپ صلی اللہ علیہ وسلم نے ( جب یہ سنا تو ) اس کے جواب میں یوں فرمایا «اللهم لا عيش إلا عيش الآخره فأكرم الأنصار والمهاجره» ”اے اللہ! آخرت کی زندگی کے سوا اور کوئی زندگی حقیقی زندگی نہیں ہے، پس انصار اور مہاجرین پر اپنا فضل و کرم فرما۔“' WHERE id = 3634;
UPDATE hadiths SET urdu = 'مجھ سے محمد بن بشار نے بیان کیا، انہوں نے کہا ہم سے غندر نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے عمرو نے، ان سے ابراہیم نے، ان سے مسروق نے اور ان سے عبداللہ بن عمرو رضی اللہ عنہما نے بیان کیا کہ میں نے نبی کریم صلی اللہ علیہ وسلم سے سنا آپ صلی اللہ علیہ وسلم نے فرمایا ”قرآن چار ( صحابہ ) عبداللہ بن مسعود، ابوحذیفہ کے غلام سالم اور ابی بن کعب اور معاذ بن جبل ( رضی اللہ عنہم ) سے سیکھو۔“' WHERE id = 3644;
UPDATE hadiths SET urdu = 'ہم سے سعید بن عفیر نے بیان کیا، کہا ہم سے لیث نے بیان کیا، کہا کہ ہشام نے میرے پاس اپنے والد ( عروہ ) سے لکھ کر بھیجا کہ عائشہ رضی اللہ عنہا نے کہا نبی کریم صلی اللہ علیہ وسلم کی کسی بیوی کے معاملہ میں، میں نے اتنی غیرت نہیں محسوس کی جتنی غیرت خدیجہ رضی اللہ عنہا کے معاملہ میں محسوس کرتی تھی وہ میرے نکاح سے پہلے ہی وفات پا چکی تھیں لیکن نبی کریم صلی اللہ علیہ وسلم کی زبان سے میں ان کا ذکر سنتی رہتی تھی۔ اور اللہ تعالیٰ نے نبی کریم صلی اللہ علیہ وسلم کو حکم دیا تھا کہ انہیں ( جنت میں ) موتی کے محل کی خوشخبری سنا دیں۔ آپ صلی اللہ علیہ وسلم اگر کبھی بکری ذبح کرتے تو ان سے میل محبت رکھنے والی خواتین کو اس میں سے اتنا ہدیہ بھیجتے جو ان کے لیے کافی ہو جاتا۔' WHERE id = 3654;
UPDATE hadiths SET urdu = 'مجھ سے محمد بن ابی بکر نے بیان کیا، کہا ہم سے فضیل بن سلیمان نے بیان کیا، ان سے موسیٰ نے بیان کیا، ان سے سالم بن عبداللہ نے بیان کیا اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم کی زید بن عمرو بن نفیل رضی اللہ عنہ سے ( وادی ) بلدح کے نشیبی علاقہ میں ملاقات ہوئی، یہ قصہ نزول وحی سے پہلے کا ہے، پھر نبی کریم صلی اللہ علیہ وسلم کے سامنے ایک دستر خوان بچھایا گیا تو زید بن عمرو بن نفیل نے کھانے سے انکار کر دیا اور جن لوگوں نے دستر خوان بچھایا تھا ان سے کہا کہ اپنے بتوں کے نام پر جو تم ذبیحہ کرتے ہو میں اسے نہیں کھاتا میں تو بس وہی ذبیحہ کھایا کرتا ہوں جس پر صرف اللہ کا نام لیا گیا ہو، زید بن عمرو قریش پر ان کے ذبیحے کے بارے میں عیب لگایا کرتے اور کہتے تھے کہ بکری کو پیدا تو کیا اللہ تعالیٰ نے، اسی نے اس کے لیے آسمان سے پانی برسایا ہے اسی نے اس کے لیے زمین سے گھاس اگائی، پھر تم لوگ اللہ کے سوا دوسرے ( بتوں کے ) ناموں پر اسے ذبح کرتے ہو۔ زید نے یہ کلمات ان کے ان کاموں پر اعتراض کرتے ہوئے اور ان کے اس عمل کو بہت بڑی غلطی قرار دیتے ہوئے کہے تھے۔' WHERE id = 3664;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا ہم سے اسماعیل بن جعفر نے بیان کیا، ان سے عبداللہ بن دینار نے اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”ہاں! اگر کسی کو قسم کھانی ہی ہو تو اللہ کے سوا اور کسی کی قسم نہ کھائے۔“' WHERE id = 3674;
UPDATE hadiths SET urdu = 'مجھ سے عبید بن اسماعیل نے بیان کیا، کہا ہم سے ابواسامہ نے بیان کیا، ان سے ہشام نے، ان سے ان کے والد نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ بعاث کی لڑائی اللہ تعالیٰ نے ( مصلحت کی وجہ سے ) رسول اللہ صلی اللہ علیہ وسلم سے پہلے برپا کرا دی تھی۔ نبی کریم صلی اللہ علیہ وسلم جب مدینہ تشریف لائے تو یہاں انصار کی جماعت میں پھوٹ پڑی ہوئی تھی۔ ان کے سردار مارے جا چکے تھے یا زخمی ہو چکے تھے، اللہ تعالیٰ نے اس لڑائی کو اس لیے پہلے برپا کیا تھا کہ انصار اسلام میں داخل ہو جائیں۔' WHERE id = 3684;
UPDATE hadiths SET urdu = 'ہم سے عیاش بن ولید نے بیان کیا، کہا ہم سے ولید بن مسلم نے بیان کیا، کہا مجھ سے اوزاعی نے بیان کیا، ان سے یحییٰ بن ابی کثیر نے بیان کیا، ان سے محمد بن ابراہیم تیمی نے بیان کیا کہ مجھ سے عروہ بن زبیر نے بیان کیا کہ میں نے عبداللہ بن عمرو بن عاص رضی اللہ عنہما سے پوچھا کہ مجھے مشرکیں کے سب سے سخت ظلم کے متعلق بتاؤ جو مشرکین نے نبی کریم صلی اللہ علیہ وسلم کے ساتھ کیا تھا۔ انہوں نے کہا کہ نبی کریم صلی اللہ علیہ وسلم حطیم میں نماز پڑھ رہے تھے کہ عقبہ بن ابی معیط آیا اور ظالم اپنا کپڑا نبی کریم صلی اللہ علیہ وسلم کی گردن مبارک میں پھنسا کر زور سے آپ صلی اللہ علیہ وسلم کا گلا گھونٹنے لگا اتنے میں ابوبکر صدیق رضی اللہ عنہ آ گئے اور انہوں نے اس بدبخت کا کندھا پکڑ کر نبی کریم صلی اللہ علیہ وسلم کے پاس سے اسے ہٹا دیا اور کہا کہ تم لوگ ایک شخص کو صرف اس لیے مار ڈالنا چاہتے ہو کہ وہ کہتا ہے کہ میرا رب اللہ ہے الآیۃ۔ عیاش بن ولید کے ساتھ اس روایت کی متابعت ابن اسحاق نے کی ( اور بیان کیا کہ ) مجھ سے یحییٰ بن عروہ نے بیان کیا اور ان سے عروہ نے کہ میں نے عبداللہ بن عمرو رضی اللہ عنہما سے پوچھا اور عبدہ نے بیان کیا، ان سے ہشام نے، ان سے ان کے والد نے کہ عمرو بن العاص رضی اللہ عنہ سے کہا گیا اور محمد بن عمرو نے بیان کیا، ان سے ابوسلمہ نے، اس میں یوں ہے کہ مجھ سے عمرو بن العاص رضی اللہ عنہ نے بیان کیا۔' WHERE id = 3694;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن سلیمان نے بیان کیا، کہا کہ مجھ سے عبداللہ بن وہب نے بیان کیا، کہا کہ مجھ سے عمرو بن محمد بن زید نے بیان کیا، ان سے سالم نے بیان کیا اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا کہ جب بھی عمر رضی اللہ عنہ نے کسی چیز کے متعلق کہا کہ میرا خیال ہے کہ یہ اس طرح ہے تو وہ اسی طرح ہوئی جیسا وہ اس کے متعلق اپنا خیال ظاہر کرتے تھے۔ ایک دن وہ بیٹھے ہوئے تھے کہ ایک خوبصورت شخص وہاں سے گزرا۔ انہوں نے کہا یا تو میرا گمان غلط ہے یا یہ شخص اپنے جاہلیت کے دین پر اب بھی قائم ہے یا یہ زمانہ جاہلیت میں اپنی قوم کا کاہن رہا ہے۔ اس شخص کو میرے پاس بلاؤ۔ وہ شخص بلایا گیا تو عمر رضی اللہ عنہ نے اس کے سامنے بھی یہی بات دہرائی۔ اس پر اس نے کہا میں نے تو آج کے دن کا سا معاملہ کبھی نہیں دیکھا جو کسی مسلمان کو پیش آیا ہو۔ عمر رضی اللہ عنہ نے کہا لیکن میں تمہارے لیے ضروری قرار دیتا ہوں کہ تم مجھے اس سلسلے میں بتاؤ۔ اس نے اقرار کیا کہ زمانہ جاہلیت میں، میں اپنی قوم کا کاہن تھا۔ عمر رضی اللہ عنہ نے کہا غیب کی جو خبریں تمہاری جنیہ تمہارے پاس لاتی تھی، اس کی سب سے حیرت انگیز کوئی بات سناؤ؟ شخص مذکور نے کہا کہ ایک دن میں بازار میں تھا کہ جنیہ میرے پاس آئی۔ میں نے دیکھا کہ وہ گھبرائی ہوئی ہے، پھر اس نے کہا جنوں کے متعلق تمہیں معلوم نہیں۔ جب سے انہیں آسمانی خبروں سے روک دیا گیا ہے وہ کس درجہ ڈرے ہوئے ہیں، مایوس ہو رہے ہیں اور اونٹنیوں کے پالان کی کملیوں سے مل گئے ہیں۔ عمر رضی اللہ عنہ نے کہا کہ تم نے سچ کہا۔ ایک مرتبہ میں بھی ان دنوں بتوں کے قریب سویا ہوا تھا۔ ایک شخص ایک بچھڑا لایا اور اس نے بت پر اسے ذبح کر دیا اس کے اندر سے اس قدر زور کی آواز نکلی کہ میں نے ایسی شدید چیخ کبھی نہیں سنی تھی۔ اس نے کہا: اے دشمن! ایک بات بتلاتا ہوں جس سے مراد مل جائے ایک فصیح خوش بیان شخص یوں کہتا ہے لا الہٰ الا اللہ یہ سنتے ہی تمام لوگ ( جو وہاں موجود تھے ) چونک پڑے ( چل دئیے ) میں نے کہا میں تو نہیں جانے کا، دیکھو اس کے بعد کیا ہوتا ہے۔ پھر یہی آواز آئی ارے دشمن تجھ کو ایک بات بتلاتا ہوں جس سے مراد بر آئے ایک فصیح شخص یوں کہہ رہا ہے لا الہٰ الا اللہ۔ اس وقت میں کھڑا ہوا اور ابھی کچھ دیر نہیں گزری تھی کہ لوگ کہنے لگے یہ ( محمد صلی اللہ علیہ وسلم ) اللہ کے سچے رسول ہیں۔' WHERE id = 3704;
UPDATE hadiths SET urdu = 'ہم سے محمد بن علاء نے بیان کیا، ہم سے ابواسامہ نے بیان کیا، کہا ہم سے برید بن عبداللہ نے بیان کیا، ان سے ابوبردہ نے اور ان سے ابوموسیٰ رضی اللہ عنہ نے بیان کیا کہ جب ہمیں رسول اللہ صلی اللہ علیہ وسلم کی ہجرت مدینہ کی اطلاع ملی تو ہم یمن میں تھے۔ پھر ہم کشتی پر سوار ہوئے لیکن اتفاق سے ہوا نے ہماری کشتی کا رخ نجاشی کے ملک حبشہ کی طرف کر دیا۔ ہماری ملاقات وہاں جعفر بن ابی طالب رضی اللہ عنہ سے ہوئی ( جو ہجرت کر کے وہاں موجود تھے ) ہم انہیں کے ساتھ وہاں ٹھہرے رہے، پھر مدینہ کا رخ کیا اور نبی کریم صلی اللہ علیہ وسلم سے اس وقت ملاقات ہوئی جب آپ خیبر فتح کر چکے تھے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ تم نے اے کشتی والو! دو ہجرتیں کی ہیں۔' WHERE id = 3714;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، کہا ہم سے لیث نے بیان کیا، ان سے عقیل نے، ان سے ابن شہاب نے، کہ مجھ سے کہا ابوسلمہ بن عبدالرحمٰن نے کہ میں نے جابر بن عبداللہ رضی اللہ عنہما سے سنا اور انہوں نے رسول اللہ صلی اللہ علیہ وسلم سے سنا آپ صلی اللہ علیہ وسلم نے فرمایا تھا کہ جب قریش نے ( معراج کے واقعہ کے سلسلے میں ) مجھ کو جھٹلایا تو میں حطیم میں کھڑا ہو گیا اور اللہ تعالیٰ نے میرے لیے بیت المقدس کو روشن کر دیا اور میں نے اسے دیکھ کر قریش سے اس کے پتے اور نشان بیان کرنا شروع کر دیئے۔' WHERE id = 3724;
UPDATE hadiths SET urdu = 'مجھ سے عبید بن اسماعیل نے بیان کیا، انہوں نے کہا ہم سے ابواسامہ نے بیان کیا، ان سے ہشام نے، ان سے ان کے والد (عروہ بن زبیر) نے بیان کیا کہ خدیجہ رضی اللہ عنہا کی وفات نبی کریم صلی اللہ علیہ وسلم کی مدینہ کو ہجرت سے تین سال پہلے ہو گئی تھی۔ نبی کریم صلی اللہ علیہ وسلم نے آپ کی وفات کے تقریباً دو سال بعد عائشہ رضی اللہ عنہا سے نکاح کیا اس وقت ان کی عمر چھ سال تھی جب رخصتی ہوئی تو وہ نو سال کی تھیں۔' WHERE id = 3734;
UPDATE hadiths SET urdu = 'ابن شہاب نے بیان کیا اور مجھے عبدالرحمٰن بن مالک مدلجی نے خبر دی، وہ سراقہ بن مالک بن جعشم کے بھتیجے ہیں کہ ان کے والد نے انہیں خبر دی اور انہوں نے سراقہ بن جعشم رضی اللہ عنہ کو یہ کہتے سنا کہ ہمارے پاس کفار قریش کے قاصد آئے اور یہ پیش کش کی کہ رسول اللہ صلی اللہ علیہ وسلم اور ابوبکر رضی اللہ عنہ کو اگر کوئی شخص قتل کر دے یا قید کر لائے تو اسے ہر ایک کے بدلے میں ایک سو اونٹ دیئے جائیں گے۔ میں اپنی قوم بنی مدلج کی ایک مجلس میں بیٹھا ہوا تھا کہ ان کا ایک آدمی سامنے آیا اور ہمارے قریب کھڑا ہو گیا۔ ہم ابھی بیٹھے ہوئے تھے۔ اس نے کہا سراقہ! ساحل پر میں ابھی چند سائے دیکھ کر آ رہا ہوں میرا خیال ہے کہ وہ محمد اور ان کے ساتھی ہی ہیں ( صلی اللہ علیہ وسلم ) ۔ سراقہ رضی اللہ عنہ نے کہا میں سمجھ گیا اس کا خیال صحیح ہے لیکن میں نے اس سے کہا کہ وہ لوگ نہیں ہیں میں نے فلاں فلاں آدمی کو دیکھا ہے ہمارے سامنے سے اسی طرف گئے ہیں۔ اس کے بعد میں مجلس میں تھوڑی دیر اور بیٹھا رہا اور پھر اٹھتے ہی گھر گیا اور لونڈی سے کہا کہ میرے گھوڑے کو لے کر ٹیلے کے پیچھے چلی جائے اور وہیں میرا انتظار کرے، اس کے بعد میں نے اپنا نیزہ اٹھایا اور گھر کی پشت کی طرف سے باہر نکل آیا میں نیزے کی نوک سے زمین پر لکیر کھینچتا ہوا چلا گیا اور اوپر کے حصے کو چھپائے ہوئے تھا۔ ( سراقہ یہ سب کچھ اس لیے کر رہا تھا کہ کسی کو خبر نہ ہو ورنہ وہ بھی میرے انعام میں شریک ہو جائے گا ) میں گھوڑے کے پاس آ کر اس پر سوار ہوا اور صبا رفتاری کے ساتھ اسے لے چلا، جتنی جلدی کے ساتھ بھی میرے لیے ممکن تھا، آخر میں نے ان کو پا ہی لیا۔ اسی وقت گھوڑے نے ٹھوکر کھائی اور مجھے زمین پر گرا دیا۔ لیکن میں کھڑا ہو گیا اور اپنا ہاتھ ترکش کی طرف بڑھایا اس میں سے تیر نکال کر میں نے فال نکالی کہ آیا میں انہیں نقصان پہنچا سکتا ہوں یا نہیں۔ فال ( اب بھی ) وہ نکلی جسے میں پسند نہیں کرتا تھا۔ لیکن میں دوبارہ اپنے گھوڑے پر سوار ہو گیا اور تیروں کے فال کی پرواہ نہیں کی۔ پھر میرا گھوڑا مجھے تیزی کے ساتھ دوڑائے لیے جا رہا تھا۔ آخر جب میں نے رسول اللہ صلی اللہ علیہ وسلم کی قرآت سنی، نبی کریم صلی اللہ علیہ وسلم میری طرف کوئی توجہ نہیں کر رہے تھے لیکن ابوبکر رضی اللہ عنہ باربار مڑ کر دیکھتے تھے، تو میرے گھوڑے کے آگے کے دونوں پاؤں زمین میں دھنس گئے جب وہ ٹخنوں تک دھنس گیا تو میں اس کے اوپر گر پڑا اور اسے اٹھنے کے لیے ڈانٹا میں نے اسے اٹھانے کی کوشش کی لیکن وہ اپنے پاؤں زمین سے نہیں نکال سکا۔ بڑی مشکل سے جب اس نے پوری طرح کھڑے ہونے کی کوشش کی تو اس کے آگے کے پاؤں سے منتشر سا غبار اٹھ کر دھوئیں کی طرح آسمان کی طرف چڑھنے لگا۔ میں نے تیروں سے فال نکالی لیکن اس مرتبہ بھی وہی فال آئی جسے میں پسند نہیں کرتا تھا۔ اس وقت میں نے نبی کریم صلی اللہ علیہ وسلم کو امان کے لیے پکارا۔ میری آواز پر وہ لوگ کھڑے ہو گئے اور میں اپنے گھوڑے پر سوار ہو کر ان کے پاس آیا۔ ان تک برے ارادے کے ساتھ پہنچنے سے جس طرح مجھے روک دیا گیا تھا۔ اسی سے مجھے یقین ہو گیا تھا کہ رسول اللہ صلی اللہ علیہ وسلم کی دعوت غالب آ کر رہے گی۔ اس لیے میں نے نبی کریم صلی اللہ علیہ وسلم سے کہا کہ آپ کی قوم نے آپ کے مارنے کے لیے سو اونٹوں کے انعام کا اعلان کیا ہے۔ پھر میں نے آپ کو قریش کے ارادوں کی اطلاع دی۔ میں نے ان حضرات کی خدمت میں کچھ توشہ اور سامان پیش کیا لیکن آپ صلی اللہ علیہ وسلم نے اسے قبول نہیں فرمایا مجھ سے کسی اور چیز کا بھی مطالبہ نہیں کیا صرف اتنا کہا کہ ہمارے متعلق راز داری سے کام لینا لیکن میں نے عرض کیا کہ آپ میرے لیے ایک امن کی تحریر لکھ دیجئیے۔ آپ صلی اللہ علیہ وسلم نے عامر بن فہیرہ رضی اللہ عنہ کو حکم دیا اور انہوں نے چمڑے کے ایک رقعہ پر تحریر امن لکھ دی۔ اس کے بعد رسول اللہ صلی اللہ علیہ وسلم آگے بڑھے۔ ابن شہاب نے بیان کیا اور انہیں عروہ بن زبیر نے خبر دی کہ رسول اللہ صلی اللہ علیہ وسلم کی ملاقات زبیر رضی اللہ عنہ سے ہوئی جو مسلمانوں کے ایک تجارتی قافلہ کے ساتھ شام سے واپس آ رہے تھے۔ زبیر رضی اللہ عنہ نے نبی کریم صلی اللہ علیہ وسلم اور ابوبکر رضی اللہ عنہ کی خدمت میں سفید پوشاک پیش کی۔ ادھر مدینہ میں بھی مسلمانوں کو نبی کریم صلی اللہ علیہ وسلم کی مکہ سے ہجرت کی اطلاع ہو چکی تھی اور یہ لوگ روزانہ صبح کو مقام حرہ تک آتے اور انتظار کرتے رہتے لیکن دوپہر کی گرمی کی وجہ سے ( دوپہر کو ) انہیں واپس جانا پڑتا تھا۔ ایک دن جب بہت طویل انتظار کے بعد سب لوگ آ گئے اور اپنے گھر پہنچ گئے تو ایک یہودی اپنے ایک محل پر کچھ دیکھنے چڑھا۔ اس نے نبی کریم صلی اللہ علیہ وسلم اور آپ کے ساتھیوں کو دیکھا سفید سفید چلے آ رہے ہیں۔ ( یا تیزی سے جلدی جلدی آ رہے ہیں ) جتنا آپ نزدیک ہو رہے تھے اتنی ہی دور سے پانی کی طرح ریتی کا چمکنا کم ہوتا جاتا۔ یہودی بے اختیار چلا اٹھا کہ اے عرب کے لوگو! تمہارے یہ بزرگ سردار آ گئے جن کا تمہیں انتظار تھا۔ مسلمان ہتھیار لے کر دوڑ پڑے اور نبی کریم صلی اللہ علیہ وسلم کا مقام حرہ پر استقبال کیا۔ آپ نے ان کے ساتھ داہنی طرف کا راستہ اختیار کیا اور بنی عمرو بن عوف کے محلہ میں قیام کیا۔ یہ ربیع الاول کا مہینہ اور پیر کا دن تھا۔ ابوبکر رضی اللہ عنہ لوگوں سے ملنے کے لیے کھڑے ہو گئے اور رسول اللہ صلی اللہ علیہ وسلم خاموش بیٹھے رہے۔ انصار کے جن لوگوں نے رسول اللہ صلی اللہ علیہ وسلم کو اس سے پہلے نہیں دیکھا تھا، وہ ابوبکر رضی اللہ عنہ ہی کو سلام کر رہے تھے۔ لیکن جب نبی کریم صلی اللہ علیہ وسلم پر دھوپ پڑنے لگی تو ابوبکر رضی اللہ عنہ نے اپنی چادر سے نبی کریم صلی اللہ علیہ وسلم پر سایہ کیا۔ اس وقت سب لوگوں نے رسول اللہ صلی اللہ علیہ وسلم کو پہچان لیا۔ آپ صلی اللہ علیہ وسلم نے بنی عمرو بن عوف میں تقریباً دس راتوں تک قیام کیا اور وہ مسجد ( قباء ) جس کی بنیاد تقویٰ پر قائم ہے وہ اسی دوران میں تعمیر ہوئی اور آپ نے اس میں نماز پڑھی پھر ( جمعہ کے دن ) نبی کریم صلی اللہ علیہ وسلم اپنی اونٹنی پر سوار ہوئے اور صحابہ بھی آپ کے ساتھ پیدل روانہ ہوئے۔ آخر آپ کی سواری مدینہ منورہ میں اس مقام پر آ کر بیٹھ گئی جہاں اب مسجد نبوی ہے۔ اس مقام پر چند مسلمان ان دنوں نماز ادا کیا کرتے تھے۔ یہ جگہ سہیل اور سہل ( رضی اللہ عنہما ) دو یتیم بچوں کی تھی اور کھجور کا یہاں کھلیان لگتا تھا۔ یہ دونوں بچے اسعد بن زرارہ رضی اللہ عنہ کی پرورش میں تھے جب آپ کی اونٹنی وہاں بیٹھ گئی تو رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ان شاءاللہ یہی ہمارے قیام کی جگہ ہو گی۔ اس کے بعد آپ نے دونوں یتیم بچوں کو بلایا اور ان سے اس جگہ کا معاملہ کرنا چاہا تاکہ وہاں مسجد تعمیر کی جا سکے۔ دونوں بچوں نے کہا کہ نہیں یا رسول اللہ! ہم یہ جگہ آپ کو مفت دے دیں گے، لیکن نبی کریم صلی اللہ علیہ وسلم نے مفت طور پر قبول کرنے سے انکار کیا۔ زمین کی قیمت ادا کر کے لے لی اور وہیں مسجد تعمیر کی۔ اس کی تعمیر کے وقت خود آپ صلی اللہ علیہ وسلم بھی صحابہ رضی اللہ عنہم کے ساتھ اینٹوں کے ڈھونے میں شریک تھے۔ اینٹ ڈھوتے وقت آپ فرماتے جاتے تھے کہ ”یہ بوجھ خیبر کے بوجھ نہیں ہیں بلکہ اس کا اجر و ثواب اللہ کے یہاں باقی رہنے والا ہے اس میں بہت طہارت اور پاکی ہے“ اور نبی کریم صلی اللہ علیہ وسلم دعا فرماتے تھے کہ ”اے اللہ! اجر تو بس آخرت ہی کا ہے پس، تو انصار اور مہاجرین پر اپنی رحمت نازل فرما۔“ اس طرح آپ نے ایک مسلمان شاعر کا شعر پڑھا جن کا نام مجھے معلوم نہیں، ابن شہاب نے بیان کیا کہ احادیث سے ہمیں یہ اب تک معلوم نہیں ہوا کہ نبی کریم صلی اللہ علیہ وسلم نے اس شعر کے سوا کسی بھی شاعر کے پورے شعر کو کسی موقعہ پر پڑھا ہو۔' WHERE id = 3744;
UPDATE hadiths SET urdu = 'مجھ سے محمد بن صباح نے خود بیان کیا یا ان سے کسی اور نے نقل کر کے بیان کیا، کہا ہم سے اسماعیل بن علیہ نے، ان سے عاصم احول نے، ان سے ابوعثمان نے بیان کیا اور انہوں نے کہا کہ ابن عمر رضی اللہ عنہما سے میں نے سنا کہ جب ان سے کہا جاتا کہ تم نے اپنے والد سے پہلے ہجرت کی تو وہ غصہ ہو جایا کرتے تھے۔ انہوں نے بیان کیا کہ میں عمر رضی اللہ عنہ کے ساتھ رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوا، اس وقت آپ صلی اللہ علیہ وسلم آرام فرما رہے تھے، اس لیے ہم گھر واپس آ گئے پھر عمر رضی اللہ عنہ نے مجھے آپ کی خدمت میں بھیجا اور فرمایا کہ جا کر دیکھ آؤ نبی کریم صلی اللہ علیہ وسلم ابھی بیدار ہوئے یا نہیں چنانچہ میں آیا ( نبی کریم صلی اللہ علیہ وسلم بیدار ہو چکے تھے ) اس لیے اندر چلا گیا اور آپ صلی اللہ علیہ وسلم کے ہاتھ پر بیعت کی پھر میں عمر رضی اللہ عنہ کے پاس آیا اور آپ کو نبی کریم صلی اللہ علیہ وسلم کے بیدار ہونے کی خبر دی۔ اس کے بعد ہم آپ صلی اللہ علیہ وسلم کی خدمت میں دوڑتے ہوئے حاضر ہوئے عمر رضی اللہ عنہ بھی اندر گئے اور آپ صلی اللہ علیہ وسلم سے بیعت کی اور میں نے بھی ( دوبارہ ) بیعت کی۔' WHERE id = 3754;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، انہوں نے کہا ہم کو مالک نے خبر دی، انہیں ہشام بن عروہ نے، انہیں ان کے والد عروہ بن زبیر نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ جب رسول اللہ صلی اللہ علیہ وسلم مدینہ تشریف لائے تو ابوبکر اور بلال رضی اللہ عنہما کو بخار چڑھ آیا، میں ان کی خدمت میں حاضر ہوئی اور عرض کیا: والد صاحب! آپ کی طبیعت کیسی ہے؟ انہوں نے بیان کیا کہ ابوبکر رضی اللہ عنہ کو جب بخار چڑھا تو یہ شعر پڑھنے لگے۔ ”ہر شخص اپنے گھر والوں کے ساتھ صبح کرتا ہے اور موت تو جوتی کے تسمے سے بھی زیادہ قریب ہے.“ اور بلال رضی اللہ عنہ کے بخار میں جب کچھ تخفیف ہوتی تو زور زور سے روتے اور یہ شعر پڑھتے ”کاش مجھے یہ معلوم ہو جاتا کہ کبھی میں ایک رات بھی وادی مکہ میں گزار سکوں گا جب کہ میرے اردگرد ( خوشبودار گھاس ) اذخر اور جلیل ہوں گی، اور کیا ایک دن بھی مجھے ایسا مل سکے گا جب میں مقام مجنہ کے پانی پر جاؤں گا اور کیا شامہ اور طفیل کی پہاڑیوں کو ایک نظر دیکھ سکوں گا۔“ عائشہ رضی اللہ عنہا نے بیان کیا کہ پھر میں آپ صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئی اور آپ کو اطلاع دی تو آپ صلی اللہ علیہ وسلم نے دعا کی «اللهم حبب إلينا المدينة كحبنا مكة أو أشد،‏‏‏‏ وصححها وبارك لنا في صاعها ومدها،‏‏‏‏ وانقل حماها فاجعلها بالجحفة» ”اے اللہ! مدینہ کی محبت ہمارے دل میں اتنی پیدا کر دے جتنی مکہ کی تھی بلکہ اس سے بھی زیادہ، یہاں کی آب و ہوا کو صحت بخش بنا۔ ہمارے لیے یہاں کے صاع اور مد ( اناج ناپنے کے پیمانے ) میں برکت عنایت فرما اور یہاں کے بخار کو مقام جحفہ میں بھیج دے۔' WHERE id = 3764;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن قزعہ نے بیان کیا، کہا ہم سے ابراہیم بن سعد نے بیان کیا، ان سے زہری نے، ان سے عامر بن سعد بن مالک نے اور ان سے ان کے والد سعد بن ابی وقاص رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم حجۃ الوداع 10 ھ کے موقع پر میری مزاج پرسی کے لیے تشریف لائے۔ اس مرض میں میرے بچنے کی کوئی امید نہیں رہی تھی۔ میں نے عرض کیا: یا رسول اللہ! مرض کی شدت آپ خود ملاحظہ فرما رہے ہیں، میرے پاس مال بہت ہے اور صرف میری ایک لڑکی وارث ہے تو کیا میں اپنے دو تہائی مال کا صدقہ کر دوں؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ نہیں۔ میں نے عرض کیا پھر آدھے کا کر دوں؟ فرمایا کہ سعد! بس ایک تہائی کا کر دو، یہ بھی بہت ہے۔ تو اگر اپنی اولاد کو مالدار چھوڑ کر جائے تو یہ اس سے بہتر ہے کہ انہیں محتاج چھوڑے اور وہ لوگوں کے سامنے ہاتھ پھیلاتے پھریں۔ احمد بن یونس نے بیان کیا، ان سے ابراہیم بن سعد نے کہ تم اپنی اولاد کو چھوڑ کر جو کچھ بھی خرچ کرو گے اور اس سے اللہ تعالیٰ کی رضا مندی مقصود ہو گی تو اللہ تعالیٰ تمہیں اس کا ثواب دے گا، اللہ تمہیں اس لقمہ پر بھی ثواب دے گا جو تم اپنی بیوی کے منہ میں ڈالو گے۔ میں نے پوچھا: یا رسول اللہ! کیا میں اپنے ساتھیوں سے پیچھے مکہ میں رہ جاؤں گا۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ تم پیچھے نہیں رہو گے اور تم جو بھی عمل کرو گے اور اس سے مقصود اللہ تعالیٰ کی رضا مندی ہو گی تو تمہارا مرتبہ اس کی وجہ سے بلند ہوتا رہے گا اور شاید تم ابھی بہت دنوں تک زندہ رہو گے تم سے بہت سے لوگوں ( مسلمانوں ) کو نفع پہنچے گا اور بہتوں کو ( غیرمسلموں ) نقصان ہو گا۔ اے اللہ! میرے صحابہ کی ہجرت پوری کر دے اور انہیں الٹے پاؤں واپس نہ کر ( کہ وہ ہجرت کو چھوڑ کر اپنے گھروں کو واپس آ جائیں ) البتہ سعد بن خولہ نقصان میں پڑ گئے اور احمد بن یونس اور موسیٰ بن اسماعیل نے اس حدیث کو ابراہیم بن سعد سے روایت کیا اس میں ( اپنی اولاد ذریت کو چھوڑو، کے بجائے ) تم اپنے وارثوں کو چھوڑو یہ الفاظ مروی ہیں۔' WHERE id = 3774;
UPDATE hadiths SET urdu = 'مجھ سے حسن بن مدرک نے بیان کیا، کہا ہم سے یحییٰ بن حماد نے بیان کیا، کہا ہم کو ابوعوانہ نے خبر دی، انہیں عاصم احول نے، انہیں ابوعثمان نہدی نے اور ان سے سلمان فارسی رضی اللہ عنہ نے بیان کیا کہ عیسیٰ علیہ السلام اور محمد صلی اللہ علیہ وسلم کے درمیان میں «فترة» کا زمانہ ( یعنی جس میں کوئی پیغمبر نہیں آیا ) چھ سو برس کا وقفہ گزرا ہے۔' WHERE id = 3785;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن رجاء نے بیان کیا، ہم سے اسرائیل نے بیان کیا، ان سے اسحاق نے، انہوں نے براء رضی اللہ عنہ سے سنا، انہوں نے بیان کیا کہ ہم اصحاب محمد صلی اللہ علیہ وسلم آپس میں یہ گفتگو کرتے تھے کہ اصحاب بدر کی تعداد بھی اتنی ہی تھی جتنی اصحاب طالوت کی۔ جنہوں نے آپ کے ساتھ نہر فلسطین پار کی تھی اور ان کے ساتھ نہر کو پار کرنے والے صرف مومن ہی تھے یعنی تین سو دس سے کچھ زیادہ آدمی۔' WHERE id = 3795;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن جعفر نے بیان کیا، ہم کو وکیع نے خبر دی، انہیں سفیان نے، انہیں ابوہاشم نے، انہیں ابومجلز نے، انہیں قیس بن عباد نے اور انہوں نے ابوذر رضی اللہ عنہ سے سنا، وہ قسمیہ بیان کرتے تھے کہ یہ آیت ( «هذان خصمان اختصموا في ربهم» ) انہیں چھ آدمیوں کے بارے میں، بدر کی لڑائی کے موقع پر نازل ہوئی تھی۔ پہلی حدیث کی طرح راوی نے اسے بھی بیان کیا۔' WHERE id = 3806;
UPDATE hadiths SET urdu = 'مجھ سے عبداللہ بن محمد نے بیان کیا ‘ ہم سے معاویہ بن عمرو نے بیان کیا ‘ ہم سے ابواسحاق نے بیان کیا ‘ ان سے حمید نے بیان کیا کہ میں نے انس رضی اللہ عنہ سے سنا ‘ انہوں نے بیان کیا کہ حارثہ بن سراقہ انصاری رضی اللہ عنہ جو ابھی نوعمر لڑکے تھے ‘ بدر کے دن شہید ہو گئے تھے ( پانی پینے کے لیے حوض پر آئے تھے کہ ایک تیر نے شہید کر دیا ) پھر ان کی والدہ ( ربیع بنت النصر ‘ انس رضی اللہ عنہ کی پھوپھی ) رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئیں اور عرض کیا: یا رسول اللہ! آپ کو معلوم ہے کہ مجھے حارثہ سے کتنا پیار تھا۔ اگر وہ اب جنت میں ہے تو میں اس پر صبر کروں گی اور اللہ تعالیٰ کی امید رکھوں گی اور اگر کہیں دوسری جگہ ہے تو آپ دیکھ رہے ہیں کہ میں کس حال میں ہوں۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”اللہ تم پر رحم کرے، کیا دیوانی ہو رہی ہو، کیا وہاں کوئی ایک جنت ہے؟ بہت سی جنتیں ہیں اور تمہارا بیٹا جنت الفردوس میں ہے۔“' WHERE id = 3818;
UPDATE hadiths SET urdu = 'مجھ سے اسحاق بن ابرہیم نے بیان کیا، ہم کو جریر نے خبر دی، انہیں یحییٰ بن سعید انصاری نے، انہیں معاذ بن رفاعہ بن رافع زرقی نے اپنے والد (رفاعہ بن رافع) سے، جو بدر کی لڑائی میں شریک ہونے والوں میں سے تھے، انہوں نے بیان کیا کہ جبرائیل علیہ السلام نبی کریم صلی اللہ علیہ وسلم کی خدمت میں آئے اور آپ سے انہوں نے پوچھا کہ بدر کی لڑائی میں شریک ہونے والوں کا آپ کے یہاں درجہ کیا ہے؟ آپ صلی اللہ علیہ وسلم نے فرمایا کہ مسلمانوں میں سب سے افضل یا آپ صلی اللہ علیہ وسلم نے اسی طرح کا کوئی کلمہ ارشاد فرمایا۔ جبرائیل علیہ السلام نے کہا کہ جو فرشتے بدر کی لڑائی میں شریک ہوئے تھے ان کا بھی درجہ یہی ہے۔' WHERE id = 3828;
UPDATE hadiths SET urdu = 'ہم سے ابراہیم بن موسیٰ رازی نے بیان کیا، کہا ہم کو ہشام بن یوسف نے خبر دی، انہیں معمر بن راشد نے، انہیں زہری نے۔ (دوسری سند) اور ہم سے اسماعیل بن ابی اویس نے بیان کیا، کہا کہ مجھ سے میرے بھائی عبدالحمید نے بیان کیا، ان سے سلیمان بن بلال نے، ان سے محمد بن ابی عتیق نے، ان سے ابن شہاب (زہری) نے، ان سے عبیداللہ بن عبداللہ بن عتبہ بن مسعود نے اور ان سے ابن عباس رضی اللہ عنہما نے بیان کیا کہ مجھے رسول اللہ صلی اللہ علیہ وسلم کے صحابی ابوطلحہ رضی اللہ عنہ نے خبر دی وہ نبی کریم صلی اللہ علیہ وسلم کے ساتھ بدر کی لڑائی میں شریک تھے کہ فرشتے اس گھر میں نہیں آتے جس میں تصویر یا کتا ہو۔ ان کی مراد جاندار کی تصویر سے تھی۔' WHERE id = 3838;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے حصین بن عبدالرحمٰن نے، انہوں نے عبداللہ بن شداد بن ہاد لیثی سے سنا، انہوں نے بیان کیا کہ میں نے رفاعہ بن رافع انصاری رضی اللہ عنہ کو دیکھا ہے۔ وہ بدر کی لڑائی میں شریک ہوئے تھے۔' WHERE id = 3849;
UPDATE hadiths SET urdu = 'ہم سے ابراہیم بن المنذر نے بیان کیا، کہا ہم سے محمد بن فلیح بن سلیمان نے بیان کیا، ان سے موسیٰ بن عقبہ نے اور ان سے ابن شہاب نے بیان کیا۔ یہ رسول اللہ صلی اللہ علیہ وسلم کے غزوات کا بیان تھا۔ پھر انہوں نے بیان کیا کہ جب ( بدر کے ) کفار مقتولین کنویں میں ڈالے جانے لگے تو رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”کیا تم نے اس چیز کو پا لیا جس کا تم سے تمہارے رب نے وعدہ کیا تھا؟“ موسیٰ نے بیان کیا، ان سے نافع نے اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے کہ اس پر نبی کریم صلی اللہ علیہ وسلم کے چند صحابہ نے عرض کیا: یا رسول اللہ! آپ ایسے لوگوں کو آواز دے رہے ہیں جو مر چکے ہیں؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”جو کچھ میں نے ان سے کہا ہے اسے خود تم نے بھی ان سے زیادہ بہتر طریقہ پر نہیں سنا ہو گا۔“ ابوعبداللہ ( امام بخاری رحمہ اللہ ) نے کہا کہ قریش ( صحابہ ) کے جتنے لوگ بدر میں شریک ہوئے تھے اور جن کا حصہ بھی ( اس غنیمت میں ) لگا تھا، ان کی تعداد اکیاسی تھی۔ عروہ بن زبیر بیان کرتے تھے کہ زبیر رضی اللہ عنہ نے کہا، میں نے ( ان مہاجرین کے حصے ) تقسیم کئے تھے اور ان کی تعداد سو تھی اور زیادہ بہتر علم اللہ کو ہے۔' WHERE id = 3860;
UPDATE hadiths SET urdu = 'ہم سے احمد بن عثمان بن حکیم نے بیان کیا، ہم سے شریح ابن مسلمہ نے بیان کیا، ان سے ابراہیم بن یوسف نے بیان کیا، ان سے ان کے والد یوسف بن اسحاق نے، ان سے ابواسحاق نے کہ میں نے براء بن عازب رضی اللہ عنہ سے سنا، انہوں نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے عبداللہ بن عتیک اور عبداللہ بن عتبہ رضی اللہ عنہما کو چند صحابہ کے ساتھ ابورافع ( کے قتل ) کے لیے بھیجا۔ یہ لوگ روانہ ہوئے جب اس کے قلعہ کے نزدیک پہنچے تو عبداللہ بن عتیک رضی اللہ عنہ نے اپنے ساتھیوں سے کہا کہ تم لوگ یہیں ٹھہر جاؤ پہلے میں جاتا ہوں، دیکھوں صورت حال کیا ہے۔ عبداللہ بن عتیک رضی اللہ عنہ نے بیان کیا کہ ( قلعہ کے قریب پہنچ کر ) میں اندر جانے کے لیے تدابیر کرنے لگا۔ اتفاق سے قلعہ کا ایک گدھا گم تھا۔ انہوں نے بیان کیا کہ اس گدھے کو تلاش کرنے کے لیے قلعہ والے روشنی لے کر باہر نکلے۔ بیان کیا کہ میں ڈرا کہ کہیں مجھے کوئی پہچان نہ لے۔ اس لیے میں نے اپنا سر ڈھک لیا جیسے کوئی قضائے حاجت کر رہا ہے۔ اس کے بعد دربان نے آواز دی کہ اس سے پہلے کہ میں دروازہ بند کر لوں جسے قلعہ کے اندر داخل ہونا ہے وہ جلدی آ جائے۔ میں ( نے موقع غنیمت سمجھا اور ) اندر داخل ہو گیا اور قلعہ کے دروازے کے پاس ہی جہاں گدھے باندھے جاتے تھے وہیں چھپ گیا۔ قلعہ والوں نے ابورافع کے ساتھ کھانا کھایا اور پھر اسے قصے سناتے رہے۔ آخر کچھ رات گئے وہ سب قلعہ کے اندر ہی اپنے اپنے گھروں میں واپس آ گئے۔ اب سناٹا چھا چکا تھا اور کہیں کوئی حرکت نہیں ہوتی تھی۔ اس لیے میں اس طویلہ سے باہر نکلا۔ انہوں نے بیان کیا کہ میں نے پہلے ہی دیکھ لیا تھا کہ دربان نے کنجی ایک طاق میں رکھی ہے۔ میں نے پہلے کنجی اپنے قبضہ میں لے لی اور پھر سب سے پہلے قلعہ کا دروازہ کھولا۔ بیان کیا کہ میں نے یہ سوچا تھا کہ اگر قلعہ والوں کو میرا علم ہو گیا تو میں بڑی آسانی کے ساتھ بھاگ سکوں گا۔ اس کے بعد میں نے ان کے کمروں کے دروازے کھولنے شروع کئے اور انہیں اندر سے بند کرتا جاتا تھا۔ اب میں زینوں سے ابورافع کے بالاخانوں تک پہنچ چکا تھا۔ اس کے کمرہ میں اندھیرا تھا۔ اس کا چراغ گل کر دیا گیا تھا۔ میں یہ نہیں اندازہ کر پایا تھا کہ ابورافع کہاں ہے۔ اس لیے میں نے آواز دی۔ اے ابورافع! اس پر وہ بولا کہ کون ہے؟ انہوں نے بیان کیا کہ پھر آواز کی طرف میں بڑھا اور میں نے تلوار سے اس پر حملہ کیا۔ وہ چلانے لگا لیکن یہ وار اوچھا پڑا تھا۔ انہوں نے بیان کیا کہ پھر دوبارہ میں اس کے قریب پہنچا، گویا میں اس کی مدد کو آیا ہوں۔ میں نے آواز بدل کر پوچھا۔ ابورافع کیا بات پیش آئی ہے؟ اس نے کہا تیری ماں غارت ہو، ابھی کوئی شخص میرے کمرے میں آ گیا اور اس نے تلوار سے مجھ پر حملہ کیا ہے۔ انہوں نے بیان کیا کہ اس مرتبہ پھر میں نے اس کی آواز کی طرف بڑھ کر دوبارہ حملہ کیا۔ اس حملہ میں بھی وہ قتل، نہ ہو سکا۔ پھر وہ چلانے لگا اور اس کی بیوی بھی اٹھ گئی ( اور چلانے لگی ) ۔ انہوں نے بیان کیا کہ پھر میں بظاہر مددگار بن کر پہنچا اور میں نے اپنی آواز بدل لی۔ اس وقت وہ چت لیٹا ہوا تھا۔ میں نے اپنی تلوار اس کے پیٹ پر رکھ کر زور سے اسے دبایا۔ آخر جب میں نے ہڈی ٹوٹنے کی آواز سن لی تو میں وہاں سے نکلا، بہت گھبرایا ہوا۔ اب زینہ پر آ چکا تھا۔ میں اترنا چاہتا تھا کہ نیچے گر پڑا۔ جس سے میرا پاؤں ٹوٹ گیا۔ میں نے اس پر پٹی باندھی اور لنگڑاتے ہوئے اپنے ساتھیوں کے پاس پہنچا۔ میں نے ان سے کہا کہ تم لوگ جاؤ اور رسول اللہ صلی اللہ علیہ وسلم کو خوشخبری سناؤ۔ میں تو یہاں سے اس وقت تک نہیں ہٹوں گا جب تک کہ اس کی موت کا اعلان نہ سن لوں۔ چنانچہ صبح کے وقت موت کا اعلان کرنے والا ( قلعہ کی فصیل پر ) چڑھا اور اس نے اعلان کیا کہ ابورافع کی موت واقع ہو گئی ہے۔ انہوں نے بیان کیا کہ پھر میں چلنے کے لیے اٹھا، مجھے ( کامیابی کی خوشخبری میں ) کوئی تکلیف معلوم نہیں ہوتی تھی۔ اس سے پہلے کہ میرے ساتھی آپ صلی اللہ علیہ وسلم کی خدمت میں پہنچیں، میں نے اپنے ساتھیوں کو پا لیا تو میں نے نبی کریم صلی اللہ علیہ وسلم کو خوشخبری سنائی۔' WHERE id = 3872;
UPDATE hadiths SET urdu = 'ہم سے محمد بن یوسف نے بیان کیا، کہا ہم سے ابن عیینہ نے بیان کیا، ان سے عمرو نے، ان سے جابر بن عبداللہ رضی اللہ عنہما نے بیان کیا کہ یہ آیت ہمارے بارے میں نازل ہوئی تھی «إذ همت طائفتان منكم أن تفشلا‏» ( آل عمران: 122 ) یعنی بنی حارثہ اور بنی سلمہ کے بارے میں۔ میری خواہش نہیں ہے کہ یہ آیت نازل نہ ہوتی، جب کہ اللہ آگے فرما رہا ہے «والله وليهما‏» ”اور اللہ ان دونوں جماعتوں کا مددگار تھا۔“' WHERE id = 3882;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن ابی شیبہ نے بیان کیا، کہا ہم سے وکیع نے بیان کیا، ان سے اسماعیل نے، ان سے قیس نے بیان کیا کہ میں نے طلحہ رضی اللہ عنہ کا وہ ہاتھ دیکھا جو شل ہو چکا تھا۔ اس ہاتھ سے انہوں نے غزوہ احد کے دن نبی کریم صلی اللہ علیہ وسلم کی حفاظت کی تھی۔' WHERE id = 3893;
UPDATE hadiths SET urdu = 'ہم سے اسحاق بن نصر نے بیان کیا، کہا ہم سے عبدالرزاق نے بیان کیا، ان سے معمر نے، ان سے ہمام نے اور انہوں نے ابوہریرہ رضی اللہ عنہ سے سنا، انہوں نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”اللہ تعالیٰ کا غضب اس قوم پر انتہائی سخت ہوا جس نے اس کے نبی کے ساتھ یہ کیا۔“ آپ صلی اللہ علیہ وسلم کا اشارہ آگے کے دندان مبارک ( کے ٹوٹ جانے ) کی طرف تھا۔ اللہ تعالیٰ کا غضب اس شخص ( ابی بن خلف ) پر انتہائی سخت ہوا۔ جسے اس کے نبی نے اللہ کے راستے میں قتل کیا۔' WHERE id = 3903;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف تینسی نے بیان کیا، کہا ہم کو امام مالک نے خبر دی، انہیں مطلب کے غلام عمرو بن ابی عمرو نے اور انہیں انس بن مالک رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم کو ( خیبر سے واپس ہوتے ہوئے ) احد پہاڑ دکھائی دیا تو آپ صلی اللہ علیہ وسلم نے فرمایا ”یہ پہاڑ ہم سے محبت رکھتا ہے اور ہم اس سے محبت رکھتے ہیں۔ اے اللہ! ابراہیم علیہ السلام نے مکہ کو حرمت والا شہر قرار دیا تھا اور میں ان دو پتھریلے میدانوں کے درمیان والے علاقے ( مدینہ منورہ ) کو حرمت والا شہر قرار دیتا ہوں۔“' WHERE id = 3913;
UPDATE hadiths SET urdu = 'ہم سے محمد بن مقاتل نے بیان کیا، کہا ہم کو عبداللہ بن مبارک نے خبر دی، کہا ہم کو سلیمان تیمی نے خبر دی، انہیں ابومجلز (لاحق بن حمید) نے اور ان سے انس بن مالک رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے ایک مہینے تک رکوع کے بعد دعائے قنوت پڑھی۔ اس دعائے قنوت میں آپ صلی اللہ علیہ وسلم نے رعل اور ذکوان نامی قبائل کے لیے بددعا کی۔ آپ صلی اللہ علیہ وسلم فرماتے تھے کہ قبیلہ عصیہ نے اللہ اور اس کے رسول کی نافرمانی کی۔' WHERE id = 3923;
UPDATE hadiths SET urdu = 'ہم سے مسلم بن ابراہیم نے بیان کیا، کہا ہم سے شعبہ بن حجاج نے ان سے ابواسحاق سبیعی نے اور ان سے براء بن عازب رضی اللہ عنہ نے بیان کیا کہ غزوہ خندق میں ( خندق کی کھدائی کے وقت ) رسول اللہ صلی اللہ علیہ وسلم مٹی اٹھا اٹھا کر لا رہے تھے۔ یہاں تک کہ آپ صلی اللہ علیہ وسلم کا بطن مبارک غبار سے اٹ گیا تھا۔ نبی کریم صلی اللہ علیہ وسلم کی زبان پر یہ کلمات جاری تھے ”اللہ کی قسم! اگر اللہ نہ ہوتا تو ہمیں سیدھا راستہ نہ ملتا۔ نہ ہم صدقہ کرتے نہ نماز پڑھتے پس تو ہمارے دلوں پر سکینت و طمانیت نازل فرما اور اگر ہماری کفار سے مڈبھیڑ ہو جائے تو ہمیں ثابت قدمی عنایت فرما۔ جو لوگ ہمارے خلاف چڑھ آئے ہیں جب یہ کوئی فتنہ چاہتے ہیں تو ہم ان کی نہیں مانتے۔ «أبينا أبينا» ( ہم ان کی نہیں مانتے۔ ہم ان کی نہیں مانتے ) پر آپ صلی اللہ علیہ وسلم کی آواز بلند ہو جاتی۔“' WHERE id = 3933;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا ‘ کہا ہم سے لیث نے بیان کیا ‘ ان سے سعید بن ابی سعید نے ‘ ان سے ان کے والد نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم فرمایا کرتے تھے ”اللہ کے سوا کوئی معبود نہیں، وہ اکیلا ہے جس نے اپنے لشکر کو فتح دی۔ اپنے بندے کی مدد کی ( یعنی نبی کریم صلی اللہ علیہ وسلم کی ) اور احزاب ( یعنی افواج کفار ) کو تنہا بھگا دیا پس اس کے بعد کوئی چیز اس کے مدمقابل نہیں ہو سکتی۔“' WHERE id = 3943;
UPDATE hadiths SET urdu = 'اور ابراہیم بن طہمان نے شیبانی سے یہ زیادہ کیا ہے ان سے عدی بن ثابت نے بیان کیا اور ان سے براء بن عازب رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے غزوہ بنو قریظہ کے موقع پر حسان بن ثابت رضی اللہ عنہ سے فرمایا تھا کہ مشرکین کی ہجو کرو جبرائیل تمہاری مدد پر ہیں۔' WHERE id = 3953;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا ‘ کہا ہم سے شعیب نے بیان کیا ‘ ان سے زہری نے بیان کیا ‘ ان سے سنان اور ابوسلمہ نے بیان کیا اور انہیں جابر رضی اللہ عنہ نے خبر دی کہ وہ نبی کریم صلی اللہ علیہ وسلم کے ساتھ اطراف نجد میں لڑائی کے لیے گئے تھے۔' WHERE id = 3963;
UPDATE hadiths SET urdu = 'مجھ سے یحییٰ بن جعفر نے بیان کیا ‘ کہا ہم سے وکیع نے بیان کیا ‘ ان سے نافع بن عمر نے ‘ ان سے ابن ابی ملیکہ نے کہ عائشہ رضی اللہ عنہا ( سورۃ النور کی آیت میں ) قرآت «إذ تلقونه بألسنتكم‏» کرتی تھیں اور ( اس کی تفسیر میں ) فرماتی تھیں کہ «الولق» جھوٹ کے معنی میں ہے۔ ابن ابی ملیکہ نے بیان کیا کہ عائشہ رضی اللہ عنہا ان آیات کو دوسروں سے زیادہ جانتی تھیں کیونکہ وہ خاص ان ہی کے باب میں اتری تھیں۔' WHERE id = 3973;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ مدینی نے بیان کیا ‘ کہا ہم سے سفیان بن عیینہ نے بیان کیا ‘ ان سے عمرو بن دینار نے بیان کیا ‘ انہوں نے کہا کہ میں نے جابر بن عبداللہ رضی اللہ عنہما سے سنا ‘ انہوں نے بیان کیا کہ ہم سے رسول اللہ صلی اللہ علیہ وسلم نے غزوہ حدیبیہ کے موقع پر فرمایا تھا کہ تم لوگ تمام زمین والوں میں سب سے بہتر ہو۔ ہماری تعداد اس موقع پر چودہ سو تھی۔ اگر آج میری آنکھوں میں بینائی ہوتی تو میں تمہیں اس درخت کا مقام دکھاتا۔ اس روایت کی متابعت اعمش نے کی، ان سے سالم نے سنا اور انہوں نے جابر رضی اللہ عنہ سے سنا کہ چودہ سو صحابہ غزوہ حدیبیہ میں تھے۔' WHERE id = 3983;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن یعلیٰ محاربی نے بیان کیا ‘ کہا مجھ سے میرے والد نے بیان کیا ‘ ان سے ایاس بن سلمہ بن اکوع نے بیان کیا ‘ کہا کہ مجھ سے میرے والد نے بیان کیا ‘ وہ اصحاب شجرہ میں سے تھے ‘ انہوں نے بیان کیا کہ ہم رسول اللہ صلی اللہ علیہ وسلم کے ساتھ جمعہ کی نماز پڑھ کر واپس ہوئے تو دیواروں کا سایہ ابھی اتنا نہیں ہوا تھا کہ ہم اس میں آرام کر سکیں۔' WHERE id = 3995;
UPDATE hadiths SET urdu = 'ابن شہاب نے بیان کیا کہ مجھے عروہ بن زبیر رضی اللہ عنہ نے خبر دی اور ان سے نبی کریم صلی اللہ علیہ وسلم کی زوجہ مطہرہ عائشہ رضی اللہ عنہا نے بیان کیا کہ آیت «يا أيها النبي إذا جاءك المؤمنات‏» کے نازل ہونے کے بعد نبی کریم صلی اللہ علیہ وسلم ہجرت کر کے آنے والی عورتوں کو پہلے آزماتے تھے اور ان کے چچا سے روایت ہے کہ ہمیں وہ حدیث بھی معلوم ہے جب نبی کریم صلی اللہ علیہ وسلم نے حکم دیا تھا کہ جو مسلمان عورتیں ہجرت کر کے چلی آتی ہیں ان کے شوہروں کو وہ سب کچھ واپس کر دیا جائے جو اپنی ان بیویوں کو وہ دے چکے ہیں اور ہمیں یہ بھی معلوم ہوا ہے کہ ابوبصیر ‘ پھر انہوں نے تفصیل کے ساتھ حدیث بیان کی۔' WHERE id = 4007;
UPDATE hadiths SET urdu = 'مجھ سے عبدالاعلی بن حماد نے بیان کیا ‘ کہا ہم سے یزید بن زریع نے بیان کیا ‘ کہا ہم سے سعید نے بیان کیا ‘ ان سے قتادہ نے اور ان سے انس بن مالک رضی اللہ عنہ نے بیان کیا کہ قبائل عکل و عرینہ کے کچھ لوگ نبی کریم صلی اللہ علیہ وسلم کی خدمت میں مدینہ آئے اور اسلام میں داخل ہو گئے۔ پھر انہوں نے کہا: اے اللہ کے نبی! ہم لوگ مویشی رکھتے تھے ‘ کھیت وغیرہ ہمارے پاس نہیں تھے ‘ ( اس لیے ہم صرف دودھ پر بسر اوقات کیا کرتے تھے ) اور انہیں مدینہ کی آب و ہوا ناموافق آئی تو نبی کریم صلی اللہ علیہ وسلم نے کچھ اونٹ اور چرواہا ان کے ساتھ کر دیا اور فرمایا کہ انہیں اونٹوں کا دودھ اور پیشاب پیو ( تو تمہیں صحت حاصل ہو جائے گی ) وہ لوگ ( چراگاہ کی طرف ) گئے۔ لیکن مقام حرہ کے کنارے پہنچتے ہی وہ اسلام سے پھر گئے اور نبی کریم صلی اللہ علیہ وسلم کے چرواہے کو قتل کر دیا اور اونٹوں کو لے کر بھاگنے لگے۔ اس کی خبر جب آپ صلی اللہ علیہ وسلم کو ملی تو آپ نے چند صحابہ کو ان کے پیچھے دوڑایا۔ ( وہ پکڑ کر مدینہ لائے گئے۔ ) تو آپ صلی اللہ علیہ وسلم کے حکم سے ان کی آنکھوں میں گرم سلائیاں پھیر دی گئیں اور ان کے ہاتھ اور پیر کاٹ دیئے گئے ( کیونکہ انہوں نے بھی ایسا ہی کیا تھا ) اور انہیں حرہ کے کنارے چھوڑ دیا گیا۔ آخر وہ اسی حالت میں مر گئے۔ قتادہ نے بیان کیا کہ ہمیں یہ روایت پہنچی ہے کہ آپ صلی اللہ علیہ وسلم نے اس کے بعد صحابہ کو صدقہ کا حکم دیا اور مثلہ ( مقتول کی لاش بگاڑنا یا ایذا دے کر اسے قتل کرنا ) سے منع فرمایا اور شعبہ ‘ ابان اور حماد نے قتادہ سے بیان کیا کہ ( یہ لوگ ) عرینہ کے قبیلے کے تھے ( عکل کا نام نہیں لیا ) اور یحییٰ بن ابی کثیر اور ایوب نے بیان کیا ‘ ان سے ابوقلابہ نے اور ان سے انس رضی اللہ عنہ نے کہ قبیلہ عکل کے کچھ لوگ آئے۔' WHERE id = 4017;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ نے بیان کیا ‘ کہا ہم سے یعقوب بن عبدالرحمٰن نے بیان کیا ‘ ان سے ابوحازم نے اور ان سے سہل بن سعد ساعدی رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے ( اپنے لشکر کے ساتھ ) مشرکین ( یعنی ) یہود خیبر کا مقابلہ کیا۔ دونوں طرف سے لوگوں نے جنگ کی ‘ پھر جب آپ اپنے خیمے کی طرف واپس ہوئے اور یہودی بھی اپنے خیموں میں واپس چلے گئے تو رسول اللہ صلی اللہ علیہ وسلم کے ایک صحابی کے متعلق کسی نے ذکر کیا کہ یہودیوں کا کوئی بھی آدمی اگر انہیں مل جائے تو وہ اس کا پیچھا کر کے اسے قتل کئے بغیر نہیں رہتے۔ کہا گیا کہ آج فلاں شخص ہماری طرف سے جتنی بہادری اور ہمت سے لڑا ہے شاید اتنی بہادری سے کوئی بھی نہیں لڑا ہو گا لیکن نبی کریم صلی اللہ علیہ وسلم نے ان کے متعلق فرمایا کہ وہ اہل دوزخ میں سے ہے۔ ایک صحابی رضی اللہ عنہ نے اس پر کہا کہ پھر میں ان کے ساتھ ساتھ رہوں گا، بیان کیا کہ پھر وہ ان کے پیچھے ہو لیے جہاں وہ ٹھہرتے یہ بھی ٹھہر جاتے اور جہاں وہ دوڑ کر چلتے یہ بھی دوڑنے لگتے۔ بیان کیا کہ پھر وہ صاحب زخمی ہو گئے ‘ انتہائی شدید طور پر اور چاہا کہ جلدی موت آ جائے۔ اس لیے انہوں نے اپنی تلوار زمین میں گاڑ دی اور اس کی نوک سینہ کے مقابل کر کے اس پر گر پڑے اور اس طرح خودکشی کر لی۔ اب دوسرے صحابی ( جو ان کی جستجو میں لگے ہوئے تھے ) نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئے اور عرض کیا میں گواہی دیتا ہوں کہ آپ اللہ کے رسول ہیں۔ پوچھا کیا بات ہے؟ ان صحابی نے عرض کیا کہ جن کے متعلق ابھی آپ نے فرمایا تھا کہ وہ اہل دوزخ میں سے ہیں تو لوگوں پر آپ کا یہ فرمانا بڑا شاق گزرا تھا۔ میں نے ان سے کہا کہ میں تمہارے لیے ان کے پیچھے پیچھے جاتا ہوں۔ چنانچہ میں ان کے ساتھ ساتھ رہا۔ ایک موقع پر جب وہ شدید زخمی ہو گئے تو اس خواہش میں کہ موت جلدی آ جائے اپنی تلوار انہوں نے زمین میں گاڑ دی اور اس کی نوک کو اپنے سینہ کے سامنے کر کے اس پر گر پڑ ے اور اس طرح انہوں نے خود اپنی جان کو ہلاک کر دیا۔ اسی موقع پر آپ صلی اللہ علیہ وسلم نے فرمایا کہ انسان زندگی بھر جنت والوں کے عمل کرتا ہے حالانکہ وہ اہل دوزخ میں سے ہوتا ہے۔ اسی طرح دوسرا شخص زندگی بھر اہل دوزخ کے عمل کرتا ہے حالانکہ وہ جنتی ہوتا ہے۔' WHERE id = 4027;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل بن ابواویس نے بیان کیا ‘ کہا کہ مجھ سے میرے بھائی عبدالحمید نے بیان کیا ‘ ان سے سلیمان بن بلال نے ‘ ان سے یحییٰ بن سعید انصاری نے ‘ ان سے حمید طویل نے اور انہوں نے انس بن مالک رضی اللہ عنہ سے سنا کہ نبی کریم صلی اللہ علیہ وسلم نے صفیہ بنت حیی رضی اللہ عنہا کے لیے خیبر کے راستہ میں تین دن تک قیام فرمایا اور آخری دن ان سے خلوت فرمائی اور وہ بھی امہات المؤمنین میں شامل ہو گئیں۔' WHERE id = 4037;
UPDATE hadiths SET urdu = 'مجھ سے ابراہیم بن موسیٰ نے بیان کیا ‘ کہا ہم کو ابن ابی زائدہ نے خبر دی ‘ کہا ہم عاصم کونے خبر دی ‘ انہیں عامر نے اور ان سے براء بن عازب رضی اللہ عنہ نے بیان کیا کہ غزوہ خیبر کے موقع پر نبی کریم صلی اللہ علیہ وسلم نے حکم دیا کہ پالتو گدھوں کا گوشت ہم پھینک دیں ‘ کچا بھی اور پکا ہوا بھی ‘ پھر ہمیں اس کے کھانے کا کبھی آپ صلی اللہ علیہ وسلم نے حکم نہیں دیا۔' WHERE id = 4049;
UPDATE hadiths SET urdu = 'مجھ سے محمد بن مثنیٰ نے بیان کیا ‘ کہا ہم سے ابن مہدی نے بیان کیا ‘ ان سے امام مالک بن انس رضی اللہ عنہ نے ‘ ان سے زید بن اسلم نے ‘ ان سے ان کے والد نے کہ عمر رضی اللہ عنہ نے کہا اگر بعد میں آنے والے مسلمانوں کا خیال نہ ہوتا تو جو بستی بھی میرے دور میں فتح ہوتی ‘ میں اسے اسی طرح تقسیم کر دیتا جس طرح نبی کریم صلی اللہ علیہ وسلم نے خیبر کی تقسیم کر دی تھی۔' WHERE id = 4059;
UPDATE hadiths SET urdu = 'مجھ سے محمد بن رافع نے بیان کیا ‘ کہا ہم سے سریج نے بیان کیا ‘ کہا ہم سے فلیح نے بیان کیا۔ (دوسری سند اور مجھ سے محمد بن حسین بن ابراہیم نے بیان کیا ‘ کہا کہ مجھ سے میرے والد نے بیان کیا ‘ ان سے فلیح بن سلیمان نے بیان کیا ‘ ان سے نافع نے اور ان سے ابن عمر رضی اللہ عنہما نے کہ رسول اللہ صلی اللہ علیہ وسلم عمرہ کے ارادے سے نکلے ‘ لیکن کفار قریش نے بیت اللہ پہنچنے سے آپ کو روکا۔ چنانچہ نبی کریم صلی اللہ علیہ وسلم نے اپنا قربانی کا جانور حدیبیہ میں ہی ذبح کر دیا اور وہیں سر بھی منڈوایا اور ان سے معاہدہ کیا کہ آپ آئندہ سال عمرہ کر سکتے ہیں لیکن (نیام میں تلواروں کے سوا اور) کوئی ہتھیار ساتھ نہیں لا سکتے اور جتنے دنوں مکہ والے چاہیں گے ‘ اس سے زیادہ آپ وہاں ٹھہر نہیں سکیں گے۔ اس لیے نبی کریم صلی اللہ علیہ وسلم نے آئندہ سال عمرہ کیا اور معاہدہ کے مطابق مکہ میں داخل ہوئے۔ تین دن وہاں مقیم رہے۔ پھر قریش نے آپ سے جانے کے لیے کہا اور آپ مکہ سے چلے آئے۔' WHERE id = 4072;
UPDATE hadiths SET urdu = 'مجھ سے محمد بن ابی بکر نے بیان کیا ‘ کہا ہم سے عمر بن علی نے بیان کیا ‘ ان سے اسماعیل بن ابی خالد نے بیان کیا ‘ ان سے عامر شعبی نے بیان کیا کہ ابن عمر رضی اللہ عنہما جب جعفر بن ابی طالب رضی اللہ عنہ کے بیٹے کے لیے سلام بھیجتے تو السلام علیک یا ابن ذی الجناحین کہتے۔' WHERE id = 4083;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا ‘ کہا ہم سے سفیان بن عیینہ نے بیان کیا ‘ ان سے عمرو بن دینار نے بیان کیا ‘ انہیں حسن بن محمد بن علی نے خبر دی اور انہوں نے عبیداللہ بن رافع سے سنا ‘ انہوں نے بیان کیا کہ میں نے علی رضی اللہ عنہ سے سنا ‘ انہوں نے بیان کیا کہ مجھے، زبیر اور مقداد رضی اللہ عنہم کو رسول اللہ صلی اللہ علیہ وسلم نے روانہ کیا اور ہدایت کی کہ ( مکہ کے راستے پر ) چلے جانا جب تم مقام روضہ خاخ پر پہنچو تو وہاں تمہیں ہودج میں ایک عورت ملے گی۔ وہ ایک خط لیے ہوئے ہے ‘ تم اس سے وہ لے لینا۔ انہوں نے کہا کہ ہم روانہ ہوئے۔ ہمارے گھوڑے ہمیں تیزی کے ساتھ لیے جا رہے تھے۔ جب ہم روضہ خاخ پر پہنچے تو واقعی وہاں ہمیں ایک عورت ہودج میں سوار ملی ( جس کا نام سارا یا کناد ہے ) ہم نے اس سے کہا کہ خط نکال۔ وہ کہنے لگی کہ میرے پاس تو کوئی خط نہیں ہے لیکن جب ہم نے اس سے یہ کہا کہ اگر تو نے خود سے خط نکال کر ہمیں نہیں دیا تو ہم تیرا کپڑا اتار کر ( تلاشی لیں گے ) تب اس نے اپنی چوٹی میں سے وہ خط نکالا۔ ہم وہ خط لے کر نبی کریم صلی اللہ علیہ وسلم کی خدمت میں واپس ہوئے۔ اس میں یہ لکھا تھا کہ حاطب بن ابی بلتعہ کی طرف سے چند مشرکین مکہ کے نام ( صفوان بن امیہ اور سہیل بن عمرو اور عکرمہ بن ابوجہل ) پھر انہوں نے اس میں مشرکین کو نبی کریم صلی اللہ علیہ وسلم کے بعض بھیدوں کی خبر بھی دی تھی۔ ( آپ فوج لے کر آنا چاہتے ہیں ) نبی کریم صلی اللہ علیہ وسلم نے دریافت فرمایا کہ اے حاطب! تو نے یہ کیا کیا؟ انہوں نے عرض کیا یا رسول اللہ! میرے بارے میں فیصلہ کرنے میں آپ جلدی نہ فرمائیں ‘ میں اس کی وجہ عرض کرتا ہوں۔ بات یہ ہے کہ میں دوسرے مہاجرین کی طرح قریش کے خاندان سے نہیں ہوں ‘ صرف ان کا حلیف بن کر ان سے جڑ گیا ہوں اور دوسرے مہاجرین کے وہاں عزیز و اقرباء ہیں جو ان کے گھر بار مال و اسباب کی نگرانی کرتے ہیں۔ میں نے چاہا کہ خیر جب میں خاندان کی رو سے ان کا شریک نہیں ہوں تو کچھ احسان ہی ان پر ایسا کر دوں جس کے خیال سے وہ میرے کنبہ والوں کو نہ ستائیں۔ میں نے یہ کام اپنے دین سے پھر کر نہیں کیا اور نہ اسلام لانے کے بعد میرے دل میں کفر کی حمایت کا جذبہ ہے۔ اس پر نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ واقعی انہوں نے تمہارے سامنے سچی بات کہہ دی ہے۔ عمر رضی اللہ عنہ نے عرض کیا: یا رسول اللہ! اجازت ہو تو میں اس منافق کی گردن اڑا دوں لیکن نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ یہ غزوہ بدر میں شریک رہے ہیں اور تمہیں کیا معلوم اللہ تعالیٰ جو غزوہ بدر میں شریک ہونے والوں کے کام سے واقف ہے سورۃ الممتحنہ میں اس نے ان کے متعلق خود فرما دیا ہے کہ ”جو چاہو کرو میں نے تمہارے گناہ معاف کر دیئے“ اس پر اللہ تعالیٰ نے یہ آیت نازل کی «يا أيها الذين آمنوا لا تتخذوا عدوي وعدوكم أولياء تلقون إليهم بالمودة‏» ”اے وہ لوگو جو ایمان لا چکے ہو! میرے اور اپنے دشمنوں کو دوست نہ بناؤ کہ ان سے تم اپنی محبت کا اظہار کرتے رہو۔ آیت «فقد ضل سواء السبيل» تک۔' WHERE id = 4093;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن قزعہ نے بیان کیا ‘ کہا ہم سے مالک نے بیان کیا ‘ ان سے ابن شہاب نے اور ان سے انس بن مالک رضی اللہ عنہ نے بیان کیا کہ فتح مکہ کے موقع پر جب نبی کریم صلی اللہ علیہ وسلم مکہ میں داخل ہوئے تو سر مبارک پر خود تھی۔ آپ صلی اللہ علیہ وسلم نے اسے اتارا ہی تھا کہ ایک صحابی نے آ کر عرض کیا کہ ابن خطل کعبہ کے پردہ سے چمٹا ہوا ہے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اسے ( وہیں ) قتل کر دو۔ امام مالک رحمہ اللہ نے کہا جیسا کہ ہم سمجھتے ہیں آگے اللہ جانے ‘ نبی کریم صلی اللہ علیہ وسلم اس دن احرام باندھے ہوئے نہیں تھے۔' WHERE id = 4104;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ نے بیان کیا ‘ کہا ہم سے لیث نے بیان کیا ‘ ان سے یزید بن ابی حبیب نے ‘ ان سے عطاء بن ابی رباح نے اور ان سے جابر بن عبداللہ رضی اللہ عنہما نے بیان کیا انہوں نے نبی کریم صلی اللہ علیہ وسلم سے سنا آپ نے فتح مکہ کے موقع پر مکہ مکرمہ میں فرمایا تھا کہ اللہ اور اس کے رسول نے شراب کی خرید و فروخت مطلق حرام قرار دے دی ہے۔' WHERE id = 4114;
UPDATE hadiths SET urdu = 'نضر نے بیان کیا کہ ہمیں شعبہ نے خبر دی، انہیں ابوبشر نے خبر دی، انہوں نے مجاہد سے سنا کہ جب میں نے عبداللہ بن عمر رضی اللہ عنہما سے عرض کیا تو انہوں نے کہا کہ اب ہجرت باقی نہیں رہی یا ( فرمایا کہ ) رسول اللہ صلی اللہ علیہ وسلم کے بعد پھر ہجرت کہاں رہی۔' WHERE id = 4126;
UPDATE hadiths SET urdu = 'اور لیث بن سعد نے بیان کیا، مجھ سے یحییٰ بن سعید انصاری نے بیان کیا تھا کہ ان سے عمر بن کثیر بن افلح نے، ان سے ابوقتادہ رضی اللہ عنہ کے مولیٰ ابو محمد نے کہ ابوقتادہ رضی اللہ عنہ نے بیان کیا کہ غزوہ حنین کے دن میں نے ایک مسلمان کو دیکھا کہ ایک مشرک سے لڑ رہا تھا اور ایک دوسرا مشرک پیچھے سے مسلمان کو قتل کرنے کی گھات میں تھا، پہلے تو میں اسی کی طرف بڑھا، اس نے اپنا ہاتھ مجھے مارنے کے لیے اٹھایا تو میں نے اس کے ہاتھ پر وار کر کے کاٹ دیا۔ اس کے بعد وہ مجھ سے چمٹ گیا اور اتنی زور سے مجھے بھینچا کہ میں ڈر گیا۔ آخر اس نے مجھے چھوڑ دیا اور ڈھیلا پڑ گیا۔ میں نے اسے دھکا دے کر قتل کر دیا اور مسلمان بھاگ نکلے اور میں بھی ان کے ساتھ بھاگ پڑا۔ لوگوں میں عمر بن خطاب رضی اللہ عنہ نظر آئے تو میں نے ان سے پوچھا، کہ لوگ بھاگ کیوں رہے ہیں؟ انہوں نے فرمایا کہ اللہ تعالیٰ کا یہی حکم ہے، پھر لوگ نبی کریم صلی اللہ علیہ وسلم کے پاس آ کر جمع ہو گئے۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ جو شخص اس پر گواہ قائم کر دے گا کہ کسی مقتول کو اسی نے قتل کیا ہے تو اس کا سارا سامان اسے ملے گا۔ میں اپنے مقتول پر گواہ کے لیے اٹھا لیکن مجھے کوئی گواہ دکھائی نہیں دیا۔ آخر میں بیٹھ گیا پھر میرے سامنے ایک صورت آئی۔ میں نے اپنے معاملے کی اطلاع نبی کریم صلی اللہ علیہ وسلم کو دی۔ آپ صلی اللہ علیہ وسلم کے پاس بیٹھے ہوئے ایک صاحب ( اسود بن خزاعی اسلمی رضی اللہ عنہ ) نے کہا کہ ان کے مقتول کا ہتھیار میرے پاس ہے، آپ میرے حق میں انہیں راضی کر دیں۔ اس پر ابوبکر رضی اللہ عنہ نے کہا ہرگز نہیں، اللہ کے شیروں میں سے ایک شیر کو چھوڑ کر جو اللہ اور اس کے رسول کے لیے جنگ کرتا ہے، اس کا حق قریش کے ایک بزدل کو آپ صلی اللہ علیہ وسلم نہیں دے سکتے۔ ابوقتادہ رضی اللہ عنہ نے بیان کیا کہ آپ صلی اللہ علیہ وسلم کھڑے ہوئے اور مجھے وہ سامان عطا فرمایا۔ میں نے اس سے ایک باغ خریدا اور یہ سب سے پہلا مال تھا جسے میں نے اسلام لانے کے بعد حاصل کیا تھا۔' WHERE id = 4137;
UPDATE hadiths SET urdu = 'مجھ سے محمد بن بشار نے بیان کیا، انہوں نے کہا، ہم سے غندر نے بیان کیا، انہوں نے کہا ہم سے شعبہ نے بیان کیا، انہوں نے کہا کہ میں نے قتادہ سے سنا اور ان سے انس بن مالک رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے انصار کے کچھ لوگوں کو جمع کیا اور فرمایا کہ قریش کے کفر کا اور ان کی بربادیوں کا زمانہ قریب ہے۔ میرا مقصد صرف ان کی دلجوئی اور تالیف قلب تھا۔ کیا تم اس پر راضی اور خوش نہیں ہو کہ لوگ دنیا اپنے ساتھ لے کر جائیں اور تم اللہ کے رسول کو اپنے گھر لے جاؤ؟ سب انصاری بولے، کیوں نہیں ( ہم اسی پر راضی ہیں ) نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اگر دوسرے لوگ کسی وادی میں چلیں اور انصار کسی اور گھاٹی میں چلیں تو میں انصار کی وادی یا گھاٹی میں چلوں گا۔' WHERE id = 4148;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا، انہوں نے کہا ہم سے شعبہ نے بیان کیا، ان سے حبیب بن ابی ثابت نے بیان کیا، ان سے سعید بن جبیر نے بیان کیا، ان سے عمرو بن میمون نے اور ان سے معاذ رضی اللہ عنہ نے بیان کیا کہ جب وہ یمن پہنچے تو یمن والوں کو صبح کی نماز پڑھائی اور نماز میں آیت «واتخذ الله إبراهيم خليلا‏» کی قرآت کی تو ان میں سے ایک صاحب ( نماز ہی میں ) بولے کہ ابراہیم کی والدہ کی آنکھ ٹھنڈی ہو گئی ہو گی۔ معاذ بن معاذ بغوی نے شعبہ سے، انہوں نے حبیب سے، انہوں نے سعید سے، انہوں نے عمرو بن میمون سے اس حدیث میں صرف اتنا بڑھایا ہے کہ نبی کریم صلی اللہ علیہ وسلم نے معاذ کو یمن بھیجا وہاں انہوں نے صبح کی نماز میں سورۃ نساء پڑھی جب اس آیت پر پہنچے «واتخذ الله إبراهيم خليلا‏» تو ایک صاحب جو ان کے پیچھے کھڑے ہوئے تھے کہا کہ ابراہیم کی والدہ کی آنکھ ٹھنڈی ہو گئی ہو گی۔' WHERE id = 4160;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل بن ابی اویس نے بیان کیا، کہا کہ مجھ سے امام مالک رحمہ اللہ نے بیان کیا، ان سے وہیب بن کیسان نے بیان کیا اور ان سے جابر بن عبداللہ انصاری رضی اللہ عنہما نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے ساحل سمندر کی طرف ایک لشکر بھیجا اور اس کا امیر ابوعبیدہ بن جراح رضی اللہ عنہ کو بنایا۔ اس میں تین سو آدمی شریک تھے۔ خیر ہم مدینہ سے روانہ ہوئے اور ابھی راستے ہی میں تھے کہ راشن ختم ہو گیا، جو کچھ بچ رہا تھا وہ ابوعبیدہ رضی اللہ عنہ ہمیں روزانہ تھوڑا تھوڑا اسی میں سے کھانے کو دیتے رہے۔ آخر جب یہ بھی ختم کے قریب پہنچ گیا تو ہمارے حصے میں صرف ایک ایک کھجور آتی تھی۔ وہب نے کہا میں نے جابر رضی اللہ عنہ سے پوچھا کہ ایک کھجور سے کیا ہوتا رہا ہو گا؟ جابر رضی اللہ عنہ نے کہا وہ ایک کھجور ہی غنیمت تھی۔ جب وہ بھی نہ رہی تو ہم کو اس کی قدر معلوم ہوئی تھی، آخر ہم سمندر کے کنارے پہنچ گئے۔ وہاں کیا دیکھتے ہیں بڑے ٹیلے کی طرح ایک مچھلی نکل کر پڑی ہے۔ اس مچھلی کو سارا لشکر اٹھارہ راتوں تک کھاتا رہا۔ بعد میں ابوعبیدہ رضی اللہ عنہ کے حکم سے اس کی پسلی کی دو ہڈیاں کھڑی کی گئیں وہ اتنی اونچی تھیں کہ اونٹ پر کجاوہ کسا گیا وہ ان کے تلے سے نکل گیا اور ہڈیوں کو بالکل نہیں لگا۔' WHERE id = 4171;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن سلیمان نے بیان کیا، کہا مجھ سے عبداللہ بن وہب نے، کہا مجھ کو عمرو بن حارث نے خبر دی اور بکر بن مضر نے یوں بیان کیا کہ عبداللہ بن وہب نے عمرو بن حارث سے روایت کیا، ان سے بکیر نے اور ان سے کریب (ابن عباس رضی اللہ عنہما کے غلام) نے بیان کیا کہ ابن عباس، عبدالرحمٰن بن ازہر اور مسور بن مخرمہ نے انہیں عائشہ رضی اللہ عنہا کی خدمت میں بھیجا اور کہا کہ ام المؤمنین سے ہم سب کا سلام کہنا اور عصر کے بعد دو رکعتوں کے متعلق ان سے پوچھنا اور یہ کہ ہمیں معلوم ہوا ہے کہ آپ انہیں پڑھتی ہیں اور ہمیں یہ بھی معلوم ہوا ہے کہ رسول اللہ صلی اللہ علیہ وسلم نے انہیں پڑھنے سے روکا تھا۔ ابن عباس رضی اللہ عنہما نے کہا کہ میں ان دو رکعتوں کے پڑھنے پر عمر رضی اللہ عنہ کے ساتھ ( ان کے دور خلافت میں ) لوگوں کو مارا کرتا تھا۔ کریب نے بیان کیا کہ پھر میں ام المؤمنین کی خدمت میں حاضر ہوا اور ان کا پیغام پہنچایا۔ عائشہ رضی اللہ عنہا نے فرمایا کہ اس کے متعلق ام سلمہ سے پوچھو، میں نے ان حضرات کو آ کر اس کی اطلاع دی تو انہوں نے مجھ کو ام سلمہ رضی اللہ عنہا کی خدمت میں بھیجا، وہ باتیں پوچھنے کے لیے جو عائشہ سے انہوں نے پچھوائی تھیں۔ ام سلمہ رضی اللہ عنہا نے فرمایا کہ میں نے خود بھی رسول اللہ صلی اللہ علیہ وسلم سے سنا ہے کہ آپ عصر کے بعد دو رکعتوں سے منع کرتے تھے لیکن آپ صلی اللہ علیہ وسلم نے ایک مرتبہ عصر کی نماز پڑھی، پھر میرے یہاں تشریف لائے، میرے پاس اس وقت قبیلہ بنو حرام کی کچھ عورتیں بیٹھی ہوئی تھیں اور آپ نے دو رکعت نماز پڑھی۔ یہ دیکھ کر میں نے خادمہ کو آپ کی خدمت میں بھیجا اور اسے ہدایت کر دی کہ نبی کریم صلی اللہ علیہ وسلم کے پہلو میں کھڑی ہو جانا اور عرض کرنا کہ ام سلمہ رضی اللہ عنہا نے پوچھا ہے: یا رسول اللہ! میں نے تو آپ سے ہی سنا تھا اور آپ نے عصر کے بعد ان دو رکعتوں کے پڑھنے سے منع کیا تھا لیکن میں آج خود آپ کو دو رکعت پڑھتے دیکھ رہی ہوں۔ اگر نبی کریم صلی اللہ علیہ وسلم ہاتھ سے اشارہ کریں تو پھر پیچھے ہٹ جانا۔ خادمہ نے میری ہدایت کے مطابق کیا اور نبی کریم صلی اللہ علیہ وسلم نے ہاتھ سے اشارہ کیا تو وہ پیچھے ہٹ گئی۔ پھر جب آپ فارغ ہوئے تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ اے ابوامیہ کی بیٹی! عصر کے بعد کی دو رکعتوں کے متعلق تم نے سوال کیا ہے، وجہ یہ ہوئی تھی کہ قبیلہ عبدالقیس کے کچھ لوگ میرے یہاں اپنی قوم کا اسلام لے کر آئے تھے اور ان کی وجہ سے ظہر کے بعد کی دو رکعتیں میں نہیں پڑھ سکا تھا یہ وہی دو رکعتیں ہیں۔' WHERE id = 4181;
UPDATE hadiths SET urdu = 'مجھ سے عبداللہ بن محمد اور اسحاق بن نصر نے بیان کیا، کہا ہم سے یحییٰ بن آدم نے بیان کیا، کہا ہم سے یحییٰ بن زکریا بن ابی زائدہ نے بیان کیا، ان سے ان کے والد نے اور ان سے ابواسحاق عمرو بن عبداللہ نے، ان سے اسود بن یزید نے اور ان سے ابوموسیٰ اشعری رضی اللہ عنہ نے کہ میں اور میرے بھائی ابورحم یا ابوبردہ یمن سے آئے تو ہم ( ابتداء میں ) بہت دنوں تک یہ سمجھتے رہے کہ ابن مسعود رضی اللہ عنہ اور ان کی والدہ ام عبداللہ رضی اللہ عنہما دونوں نبی کریم صلی اللہ علیہ وسلم کے اہل بیت میں سے ہیں کیونکہ یہ نبی کریم صلی اللہ علیہ وسلم کے گھر میں رات دن بہت آیا جایا کرتے تھے اور ہر وقت نبی کریم صلی اللہ علیہ وسلم کے ساتھ رہا کرتے تھے۔' WHERE id = 4192;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، کہا ہم سے ابوعوانہ نے بیان کیا، کہا ہم سے عبدالملک بن عمیر نے بیان کیا، ان سے عمرو بن حریث نے اور ان سے عدی بن حاتم رضی اللہ عنہ نے بیان کیا کہ ہم عمر رضی اللہ عنہ کی خدمت میں ( ان کی دور خلافت میں ) ایک وفد کی شکل میں آئے۔ وہ ایک ایک شخص کو نام لے لے کر بلاتے جاتے تھے ) میں نے ان سے کہا کیا آپ مجھے پہچانتے نہیں؟ اے امیرالمؤمنین! فرمایا کیا تمہیں بھی نہیں پہچانوں گا، تم اس وقت اسلام لائے جب یہ سب کفر پر قائم تھے۔ تم نے اس وقت توجہ کی جب یہ سب منہ موڑ رہے تھے۔ تم نے اس وقت وفا کی جب یہ سب بے وفائی کر رہے تھے اور اس وقت پہچانا جب ان سب نے انکار کیا تھا۔ عدی رضی اللہ عنہ نے کہا بس اب مجھے کوئی پرواہ نہیں۔' WHERE id = 4202;
UPDATE hadiths SET urdu = 'مجھ سے محمد بن مثنیٰ نے بیان کیا، کہا ہم سے عبدالوہاب ثقفی نے بیان کیا، کہا ہم سے ایوب سختیانی نے بیان کیا، ان سے محمد بن سیرین نے، ان سے عبدالرحمٰن بن ابی بکرہ رضی اللہ عنہما نے اور ان سے ابوبکرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ زمانہ اپنی اصل حالت پر گھوم کر آ گیا ہے۔ اس دن کی طرح جب اللہ نے زمین و آسمان کو پیدا کیا تھا۔ دیکھو! سال کے بارہ مہینے ہوتے ہیں۔ چار ان میں سے حرمت والے مہینے ہیں۔ تین لگاتار ہیں، ذی قعدہ، ذی الحجہ اور محرم ( اور چوتھا ) رجب مضر جو جمادی الاولیٰ اور شعبان کے بیچ میں پڑتا ہے۔ ( پھر آپ نے دریافت فرمایا ) یہ کون سا مہینہ ہے؟ ہم نے کہا کہ اللہ اور ان کے رسول کو بہتر علم ہے۔ اس پر آپ صلی اللہ علیہ وسلم خاموش ہو گئے۔ ہم نے سمجھا شاید آپ مشہور نام کے سوا اس کا کوئی اور نام رکھیں گے۔ لیکن آپ نے فرمایا: کیا یہ ذی الحجہ نہیں ہے؟ ہم بولے کہ کیوں نہیں۔ پھر دریافت فرمایا اور یہ شہر کون سا ہے؟ ہم بولے کہ اللہ اور اس کے رسول کو زیادہ بہتر علم ہے۔ پھر آپ صلی اللہ علیہ وسلم خاموش ہو گئے۔ ہم نے سمجھا شاید اس کا کوئی اور نام آپ صلی اللہ علیہ وسلم رکھیں گے، جو مشہور نام کے علاوہ ہو گا۔، لیکن آپ صلی اللہ علیہ وسلم نے فرمایا: کیا یہ مکہ نہیں ہے؟ ہم بولے کیوں نہیں ( یہ مکہ ہی ہے ) پھر آپ صلی اللہ علیہ وسلم نے دریافت فرمایا اور یہ دن کون سا ہے؟ ہم بولے کہ اللہ اور اس کے رسول کو زیادہ بہتر علم ہے، پھر آپ صلی اللہ علیہ وسلم خاموش ہو گئے اور ہم نے سمجھا شاید اس کا آپ صلی اللہ علیہ وسلم اس کے مشہور نام کے سوا کوئی اور نام رکھیں گے، لیکن آپ صلی اللہ علیہ وسلم نے فرمایا: کیا یہ یوم النحر ( قربانی کا دن ) نہیں ہے؟ ہم بولے کہ کیوں نہیں۔ اس کے بعد آپ صلی اللہ علیہ وسلم نے فرمایا: پس تمہارا خون اور تمہارا مال۔ محمد نے بیان کیا کہ میرا خیال ہے کہ ابوبکرہ رضی اللہ عنہ نے یہ بھی کہا، اور تمہاری عزت تم پر اسی طرح حرام ہے جس طرح یہ دن کا تمہارے اس شہر اور تمہارے اس مہینے میں اور تم بہت جلد اپنے رب سے ملو گے اور وہ تم سے تمہارے اعمال کے بارے میں سوال کرے گا۔ ہاں، پس میرے بعد تم گمراہ نہ ہو جانا کہ ایک دوسرے کی گردن مارنے لگو۔ ہاں اور جو یہاں موجود ہیں وہ ان لوگوں کو پہنچا دیں جو موجود نہیں ہیں، ہو سکتا ہے کہ جسے وہ پہنچائیں ان میں سے کوئی ایسا بھی ہو جو یہاں بعض سننے والوں سے زیادہ اس ( حدیث ) کو یاد رکھ سکتا ہو۔ محمد بن سیرین جب اس حدیث کا ذکر کرتے تو فرماتے کہ محمد صلی اللہ علیہ وسلم نے سچ فرمایا۔ پھر آپ صلی اللہ علیہ وسلم نے فرمایا کہ تو کیا میں نے پہنچا دیا۔ آپ صلی اللہ علیہ وسلم نے دو مرتبہ یہ جملہ فرمایا۔' WHERE id = 4213;
UPDATE hadiths SET urdu = 'ہم سے مسدد بن مسرہد نے بیان کیا، کہا ہم سے یحییٰ بن سمیر قفان نے بیان کیا، ان سے شعبہ نے، ان سے حکم بن عتبہ نے، ان سے مصعب بن سعد نے اور ان سے ان کے والد نے کہ رسول اللہ صلی اللہ علیہ وسلم غزوہ تبوک کے لیے تشریف لے گئے تو علی رضی اللہ عنہ کو مدینہ میں اپنا نائب بنایا۔ علی رضی اللہ عنہ نے عرض کیا کہ آپ مجھے بچوں اور عورتوں میں چھوڑے جا رہے ہیں؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کیا تم اس پر خوش نہیں ہو کہ میرے لیے تم ایسے ہو جیسے موسیٰ کے لیے ہارون تھے۔ لیکن فرق یہ ہے کہ میرے بعد کوئی نبی نہیں ہو گا۔ اور ابوداؤد طیالسی نے اس حدیث کو یوں بیان کیا کہ ہم سے شعبہ نے بیان کیا، ان سے حکم بن عتبہ نے اور انہوں نے کہا میں نے مصعب سے سنا۔' WHERE id = 4223;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ مدینی نے بیان کیا، انہوں نے کہا ہم سے سفیان بن عیینہ نے بیان کیا، کہا کہ میں نے زہری سے سنا، انہوں نے سائب بن یزید رضی اللہ عنہ سے سنا، وہ بیان کرتے تھے کہ مجھے یاد ہے جب میں بچوں کے ساتھ ثنیۃ الوداع کی طرف رسول اللہ صلی اللہ علیہ وسلم کا استقبال کرنے گیا تھا۔ سفیان نے ایک مرتبہ ( «مع الغلمان» کے بجائے ) «مع الصبيان‏.‏» بیان کیا۔' WHERE id = 4233;
UPDATE hadiths SET urdu = 'ہم سے محمد بن یحییٰ ذہلی نے بیان کیا۔ کہا ہم سے عفان بن مسلم نے بیان کیا، ان سے صخر بن جویریہ نے، ان سے عبدالرحمٰن بن قاسم نے، ان سے ان کے والد (قاسم بن محمد) نے اور ان سے عائشہ رضی اللہ عنہا نے کہ ( ان کے بھائی ) عبدالرحمٰن بن ابی بکر رضی اللہ عنہ نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئے۔ نبی کریم صلی اللہ علیہ وسلم میرے سینے سے ٹیک لگائے ہوئے تھے۔ عبدالرحمٰن رضی اللہ عنہ کے ہاتھ میں ایک تازہ مسواک استعمال کے لیے تھی۔ آپ صلی اللہ علیہ وسلم اس مسواک کی طرف دیکھتے رہے۔ چنانچہ میں نے ان سے مسواک لے لی اور اسے اپنے دانتوں سے چبا کر اچھی طرح جھاڑنے اور صاف کرنے کے بعد نبی کریم صلی اللہ علیہ وسلم کو دے دی۔ آپ نے وہ مسواک استعمال کی جتنے عمدہ طریقہ سے آپ صلی اللہ علیہ وسلم اس وقت مسواک کر رہے تھے، میں نے آپ کو اتنی اچھی طرح مسواک کرتے کبھی نہیں دیکھا۔ مسواک سے فارغ ہونے کے بعد آپ نے اپنا ہاتھ یا اپنی انگلی اٹھائی اور فرمایا۔ «في الرفيق الأعلى» تین مرتبہ، اور آپ کا انتقال ہو گیا۔ عائشہ رضی اللہ عنہا کہا کرتی تھیں کہ نبی کریم صلی اللہ علیہ وسلم کی وفات ہوئی تو سر مبارک میری ہنسلی اور ٹھوڑی کے درمیان میں تھا۔' WHERE id = 4244;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل نے بیان کیا، کہا مجھ سے سلیمان بن بلال نے بیان کیا، کہا ہم سے ہشام بن عروہ نے بیان کیا، انہیں ان کے والد نے خبر دی اور انہیں عائشہ رضی اللہ عنہا نے کہ مرض الموت میں رسول اللہ صلی اللہ علیہ وسلم پوچھتے رہتے تھے کہ کل میرا قیام کہاں ہو گا، کل میرا قیام کہاں ہو گا؟ آپ عائشہ رضی اللہ عنہا کی باری کے منتظر تھے، پھر ازواج مطہرات رضی اللہ عنہن نے عائشہ رضی اللہ عنہا کے گھر قیام کی اجازت دے دی اور آپ کی وفات انہیں کے گھر میں ہوئی۔ عائشہ رضی اللہ عنہا نے بیان کیا کہ آپ کی وفات اسی دن ہوئی جس دن قاعدہ کے مطابق میرے یہاں آپ کے قیام کی باری تھی۔ رحلت کے وقت سر مبارک میرے سینے پر تھا اور میرا تھوک آپ کے تھوک کے ساتھ ملا تھا۔ انہوں نے بیان کیا کہ عبدالرحمٰن بن ابی بکر رضی اللہ عنہما داخل ہوئے اور ان کے ہاتھ میں استعمال کے قابل مسواک تھی۔ آپ صلی اللہ علیہ وسلم نے اس کی طرف دیکھا تو میں نے کہا: عبدالرحمٰن! یہ مسواک مجھے دے دو۔ انہوں نے مسواک مجھے دے دی۔ میں نے اسے اچھی طرح چبایا اور جھاڑ کر آپ صلی اللہ علیہ وسلم کو دی، پھر آپ نے وہ مسواک کی، اس وقت آپ میرے سینے سے ٹیک لگائے ہوئے تھے۔' WHERE id = 4255;
UPDATE hadiths SET urdu = 'ہم سے ابوعاصم ضحاک بن مخلد نے بیان کیا، کہا ہم سے فضیل بن سلیمان نے بیان کیا، ان سے موسیٰ بن عقبہ نے بیان کیا، ان سے سالم نے اور ان سے ان کے والد (عبداللہ بن عمر رضی اللہ عنہما) نے کہ نبی کریم صلی اللہ علیہ وسلم نے اسامہ بن زید رضی اللہ عنہما کو ایک لشکر کا امیر بنایا تو بعض صحابہ رضی اللہ عنہم نے ان کی امارت پر اعتراض کیا۔ اس پر نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ مجھے معلوم ہوا ہے کہ تم اسامہ رضی اللہ عنہ پر اعتراض کر رہے ہو حالانکہ وہ مجھے سب سے زیادہ عزیز ہے۔' WHERE id = 4268;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم نے بیان کیا، انہوں نے کہا کہ مجھ سے سفیان نے بیان کیا، ان سے عبدالملک نے، ان سے عمرو بن حریث نے اور ان سے سعید بن زید رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ” «كمأة» ( یعنی کھنبی ) بھی «من» کی قسم ہے اور اس کا پانی آنکھ کی دوا ہے۔“' WHERE id = 4278;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے یحییٰ نے بیان کیا، ان سے سفیان نے، ان سے عبداللہ بن دینار نے اور ان سے ابن عمر رضی اللہ عنہما نے کہ لوگ مسجد قباء میں صبح کی نماز پڑھ ہی رہے تھے کہ ایک صاحب آئے اور انہوں نے کہا کہ اللہ تعالیٰ نے نبی کریم صلی اللہ علیہ وسلم پر قرآن نازل کیا ہے کہ آپ نماز میں کعبہ کی طرف منہ کریں، لہٰذا آپ لوگ بھی کعبہ کی طرف رخ کر لیں۔ سب نمازی اسی وقت کعبہ کی طرف پھر گئے۔' WHERE id = 4288;
UPDATE hadiths SET urdu = 'ہم سے حمیدی نے بیان کیا، انہوں نے کہا ہم سے سفیان نے بیان کیا، ان سے عمرو نے بیان کیا، انہوں نے کہا کہ میں نے مجاہد سے سنا، انہوں نے کہا کہ میں نے ابن عباس رضی اللہ عنہما سے سنا، انہوں نے بیان کیا کہ بنی اسرائیل میں قصاص یعنی بدلہ تھا لیکن دیت نہیں تھی۔ اس لیے اللہ تعالیٰ نے اس امت سے کہا کہ ”تم پر مقتولوں کے باب میں قصاص فرض کیا گیا، آزاد کے بدلے میں آزاد اور غلام کے بدلے میں غلام اور عورت کے بدلے میں عورت، ہاں جس کسی کو اس کے فریق مقتول کی طرف سے کچھ معافی مل جائے۔“ تو معافی سے مراد یہی دیت قبول کرنا ہے۔ سو مطالبہ معقول اور نرم طریقہ سے ہو اور مطالبہ کو اس فریق کے پاس خوبی سے پہنچایا جائے۔ یہ تمہارے پروردگار کی طرف سے رعایت اور مہربانی ہے۔“ یعنی اس کے مقابلہ میں جو تم سے پہلی امتوں پر فرض تھا۔ ”سو جو کوئی اس کے بعد بھی زیادتی کرے گا، اس کے لیے آخرت میں درد ناک عذاب ہو گا۔“ ( زیادتی سے مراد یہ ہے کہ ) دیت بھی لے لی اور پھر اس کے بعد قتل بھی کر دیا۔' WHERE id = 4298;
UPDATE hadiths SET urdu = 'ہم سے عبیداللہ نے بیان کیا، انہوں نے کہا ہم سے اسرائیل نے بیان کیا، ان سے ابواسحاق نے اور ان سے براء رضی اللہ عنہ نے (دوسری سند) اور ہم سے احمد بن عثمان نے بیان کیا، ان سے شریح بن مسلمہ نے بیان کیا، کہا کہ مجھ سے ابراہیم بن یوسف نے بیان کا، ان سے ان کے والد نے، ان سے ابواسحاق نے بیان کیا، انہوں نے براء بن عازب رضی اللہ عنہ سے سنا کہ جب رمضان کے روزے کا حکم نازل ہوا تو مسلمان پورے رمضان میں اپنی بیویوں کے قریب نہیں جاتے تھے اور کچھ لوگوں نے اپنے کو خیانت میں مبتلا کر لیا تھا۔ اس پر اللہ تعالیٰ نے یہ آیت نازل فرمائی «علم الله أنكم كنتم تختانون أنفسكم فتاب عليكم وعفا عنكم‏» ”اللہ نے جان لیا کہ تم اپنے کو خیانت میں مبتلا کرتے رہتے تھے۔ پس اس نے تم پر رحمت سے توجہ فرمائی اور تم کو معاف کر دیا۔“' WHERE id = 4308;
UPDATE hadiths SET urdu = 'مجھ سے محمد بن ابی بکر نے بیان کیا، انہوں نے کہا ہم سے فضیل بن سلیمان نے بیان کیا، انہوں نے کہا ہم سے موسیٰ بن عقبہ نے بیان کیا، انہوں نے کہا مجھ کو کریب نے خبر دی اور انہوں نے عبداللہ بن عباس رضی اللہ عنہما سے بیان کیا کہ ( جو کوئی تمتع کرے عمرہ کر کے احرام کھول ڈالے وہ ) جب تک حج کا احرام نہ باندھے بیت اللہ کا نفل طواف کرتا رہے۔ جب حج کا احرام باندھے اور عرفات جانے کو سوار ہو تو حج کے بعد جو قربانی ہو سکے وہ کرے، اونٹ ہو یا گائے یا بکری۔ ان تینوں میں سے جو ہو سکے اگر قربانی میسر نہ ہو تو تین روزے حج کے دنوں میں رکھے عرفہ کے دن سے پہلے اگر آخری روزہ عرفہ کے دن آ جائے تب بھی کوئی قباحت نہیں۔ شہر مکہ سے چل کر عرفات کو جائے وہاں عصر کی نماز سے رات کی تاریکی ہونے تک ٹھہرے، پھر عرفات سے اس وقت لوٹے جب دوسرے لوگ لوٹیں اور سب لوگوں کے ساتھ رات مزدلفہ میں گزارے اور اللہ کی یاد، تکبیر اور تہلیل بہت کرتا رہے صبح ہونے تک۔ صبح کو لوگوں کے ساتھ مزدلفہ سے منیٰ کو لوٹے جیسے اللہ نے فرمایا «ثم أفيضوا من حيث أفاض الناس واستغفروا الله إن الله غفور رحيم‏» یعنی کنکریاں مارنے تک اسی طرح اللہ کی یاد اور تکبیر و تہلیل کرتے رہو۔' WHERE id = 4319;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، کہا ہم سے امام مالک نے بیان کیا، ان سے نافع نے کہ جب عبداللہ بن عمر رضی اللہ عنہما سے نماز خوف کے متعلق پوچھا جاتا تو وہ فرماتے کہ امام مسلمانوں کی ایک جماعت کو لے کر خود آگے بڑھے اور انہیں ایک رکعت نماز پڑھائے۔ اس دوران میں مسلمانوں کی دوسری جماعت ان کے اور دشمن کے درمیان میں رہے۔ یہ لوگ نماز میں ابھی شریک نہ ہوں، پھر جب امام ان لوگوں کو ایک رکعت پڑھا چکے جو پہلے اس کے ساتھ تھے تو اب یہ لوگ پیچھے ہٹ جائیں اور ان کی جگہ لے لیں، جنہوں نے اب تک نماز نہیں پڑھی ہے، لیکن یہ لوگ سلام نہ پھیریں۔ اب وہ لوگ آگے بڑھیں جنہوں نے نماز نہیں پڑھی ہے اور امام انہیں بھی ایک رکعت نماز پڑھائے، اب امام دو رکعت پڑھ چکنے کے بعد نماز سے فارغ ہو چکا۔ پھر دونوں جماعتیں ( جنہوں نے الگ الگ امام کے ساتھ ایک ایک رکعت نماز پڑھی تھی ) اپنی باقی ایک ایک رکعت ادا کر لیں۔ جبکہ امام اپنی نماز سے فارغ ہو چکا ہے۔ اس طرح دونوں جماعتوں کی دو دو رکعت پوری ہو جائیں گی۔ لیکن اگر خوف اس سے بھی زیادہ ہے تو ہر شخص تنہا نماز پڑھ لے، پیدل ہو یا سوار، قبلہ کی طرف رخ ہو یا نہ ہو۔ امام مالک نے بیان کیا، ان سے نافع نے کہ مجھ کو یقین ہے کہ عبداللہ بن عمر رضی اللہ عنہما نے یہ باتیں رسول اللہ صلی اللہ علیہ وسلم سے سن کر ہی بیان کی ہیں۔' WHERE id = 4331;
UPDATE hadiths SET urdu = 'ہم سے محمد بن یحییٰ نے بیان کیا، کہا ہم سے عبداللہ بن محمد نفیلی نے بیان کیا، کہا ہم سے مسکین بن بکیر حران نے بیان کیا، ان سے شعبہ نے، ان سے خالد حذاء نے، ان سے مروان اصفر نے اور ان سے نبی کریم صلی اللہ علیہ وسلم کے ایک صحابی یعنی ابن عمر رضی اللہ عنہما نے کہ آیت «وإن تبدوا ما في أنفسكم أو تخفوه‏» ”اور جو کچھ تمہارے نفسوں کے اندر ہے اگر تم ان کو ظاہر کر ویا چھپائے رکھو۔“ آخر تک منسوخ ہو گی تھی۔' WHERE id = 4341;
UPDATE hadiths SET urdu = 'ہم سے محمد بن یوسف نے بیان کیا، کہا ان سے سفیان نے، ان سے میسرہ نے، ان سے ابوحازم نے اور ان سے ابوہریرہ رضی اللہ عنہ نے آیت «كنتم خير أمة أخرجت للناس‏» ”تم لوگ لوگوں کے لیے سب لوگوں سے بہتر ہو“ اور کہا ان کو گردنوں میں زنجیریں ڈال کر ( لڑائی میں گرفتار کر کے ) لاتے ہو پھر وہ اسلام میں داخل ہو جاتے ہیں۔' WHERE id = 4352;
UPDATE hadiths SET urdu = 'ہم سے سعید بن ابی مریم نے بیان کیا، انہوں نے کہا ہم کو محمد بن جعفر نے خبر دی، انہوں نے کہا کہ مجھ سے زید بن اسلم نے بیان کیا، ان سے عطاء بن یسار نے اور ان سے ابو سعید خدری رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم کے زمانہ میں چند منافقین ایسے تھے کہ جب نبی کریم صلی اللہ علیہ وسلم جہاد کے لیے تشریف لے جاتے تو یہ مدینہ میں پیچھے رہ جاتے اور پیچھے رہ جانے پر بہت خوش ہوا کرتے تھے لیکن جب نبی کریم صلی اللہ علیہ وسلم واپس آتے تو عذر بیان کرتے اور قسمیں کھا لیتے بلکہ ان کو ایسے کام پر تعریف ہونا پسند آتا جس کو انہوں نے نہ کیا ہوتا اور بعد میں چکنی چیڑی باتوں سے اپنی بات بنانا چاہتے۔ اللہ تعالیٰ نے اسی پر یہ آیت «لا يحسبن الذين يفرحون‏» آخر آیت تک اتاری۔' WHERE id = 4362;
UPDATE hadiths SET urdu = 'ہم سے ابراہیم بن موسیٰ نے بیان کیا، کہا ہم سے ہشام بن یوسف نے بیان کیا کہ انہیں ابن جریج نے خبر دی، بیان کیا کہ مجھے ابن منکدر نے خبر دی اور ان سے جابر رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم اور ابوبکر صدیق رضی اللہ عنہ قبیلہ بنو سلمہ تک پیدل چل کر میری عیادت کے لیے تشریف لائے۔ آپ نے ملاحظہ فرمایا کہ مجھ پر بے ہوشی طاری ہے، اس لیے آپ نے پانی منگوایا اور وضو کر کے اس کا پانی مجھ پر چھڑکا، میں ہوش میں آ گیا، پھر میں نے عرض کیا: یا رسول اللہ! آپ کا کیا حکم ہے، میں اپنے مال کا کیا کروں؟ اس پر یہ آیت نازل ہوئی «يوصيكم الله في أولادكم‏» کہ ”اللہ تمہیں تمہاری اولاد ( کی میراث ) کے بارے میں حکم دیتا ہے۔“' WHERE id = 4372;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد نے بیان کیا، کہا ہم سے سفیان نے بیان کیا، ان سے عبیداللہ نے بیان کیا کہ میں نے ابن عباس رضی اللہ عنہما سے سنا، انہوں نے کہا کہ میں اور میری والدہ «مستضعفين‏» ( کمزوروں ) میں سے تھے۔' WHERE id = 4382;
UPDATE hadiths SET urdu = 'ہم سے ابوالنعمان نے بیان کیا، کہا ہم سے حماد بن زید نے بیان کیا، ان سے ایوب سختیانی نے، ان سے عبداللہ بن ابی ملیکہ نے اور ان سے ابن عباس رضی اللہ عنہما نے «إلا المستضعفين‏» کے متعلق فرمایا کہ میری ماں بھی ان ہی لوگوں میں تھیں جنہیں اللہ نے معذور رکھا تھا۔' WHERE id = 4392;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل بن ابی اویس نے بیان کیا، انہوں نے کہا کہ مجھ سے امام مالک نے بیان کیا، ان سے عبدالرحمٰن بن قاسم نے بیان کیا، ان سے ان کے والد قاسم بن محمد نے بیان کیا اور ان سے نبی کریم صلی اللہ علیہ وسلم کی زوجہ مطہرہ عائشہ رضی اللہ عنہا نے بیان کیا کہ ایک سفر میں ہم رسول اللہ صلی اللہ علیہ وسلم کے ساتھ روانہ ہوئے۔ جب ہم مقام بیداء یا ذات الجیش تک پہنچے تو میرا ہار گم ہو گیا۔ اس لیے رسول اللہ صلی اللہ علیہ وسلم نے اسے تلاش کروانے کے لیے وہیں قیام کیا اور صحابہ رضی اللہ عنہم نے بھی آپ صلی اللہ علیہ وسلم کے ساتھ قیام کیا۔ وہاں کہیں پانی نہیں تھا اور صحابہ رضی اللہ عنہم کے ساتھ بھی پانی نہیں تھا۔ لوگ ابوبکر صدیق رضی اللہ عنہ کے پاس آئے اور کہنے لگے، ملاحظہ نہیں فرماتے، عائشہ رضی اللہ عنہا نے کیا کر رکھا ہے اور نبی کریم صلی اللہ علیہ وسلم کو یہیں ٹھہرا لیا اور ہمیں بھی، حالانکہ یہاں کہیں پانی نہیں ہے اور نہ کسی کے پاس پانی ہے۔ ابوبکر رضی اللہ عنہ ( میرے یہاں ) آئے۔ نبی کریم صلی اللہ علیہ وسلم سر مبارک میری ران پر رکھ کر سو گئے تھے اور کہنے لگے تم نے نبی کریم صلی اللہ علیہ وسلم کو اور سب کو روک لیا، حالانکہ یہاں کہیں پانی نہیں ہے اور نہ کسی کے ساتھ پانی ہے۔ عائشہ رضی اللہ عنہا نے بیان کیا کہ ابوبکر صدیق رضی اللہ عنہ مجھ پر بہت خفا ہوئے اور جو اللہ کو منظور تھا مجھے کہا، سنا اور ہاتھ سے میری کوکھ میں کچوکے لگائے۔ میں نے صرف اس خیال سے کوئی حرکت نہیں کی کہ نبی کریم صلی اللہ علیہ وسلم میری ران پر اپنا سر رکھے ہوئے تھے۔ پھر نبی کریم صلی اللہ علیہ وسلم اٹھے اور صبح تک کہیں پانی کا نام و نشان نہیں تھا، پھر اللہ تعالیٰ نے تیمم کی آیت اتاری تو اسید بن حضیر نے کہا کہ آل ابی بکر! یہ تمہاری کوئی پہلی برکت نہیں ہے۔ بیان کیا کہ پھر ہم نے وہ اونٹ اٹھایا جس پر میں سوار تھی تو ہار اسی کے نیچے مل گیا۔' WHERE id = 4402;
UPDATE hadiths SET urdu = 'ہم سے یعقوب بن ابراہیم نے بیان کیا، کہا ہم سے ابن علیہ نے بیان کیا، کہا ہم سے عبدالعزیز بن صہیب نے بیان کیا، کہا کہ مجھ سے انس بن مالک رضی اللہ عنہ نے بیان کیا ہم لوگ تمہاری «فضيخ» ( کھجور سے بنائی ہوئی شراب ) کے سوا اور کوئی شراب استعمال نہیں کرتے تھے، یہی جس کا نام تم نے «فضيخ» رکھ رکھا ہے۔ میں کھڑا ابوطلحہ رضی اللہ عنہ کو پلا رہا تھا اور فلاں اور فلاں کو، کہ ایک صاحب آئے اور کہا: تمہیں کچھ خبر بھی ہے؟ لوگوں نے پوچھا کیا بات ہے؟ انہوں نے بتایا کہ شراب حرام قرار دی جا چکی ہے۔ فوراً ہی ان لوگوں نے کہا: انس رضی اللہ عنہ اب ان شراب کے مٹکوں کو بہا دو۔ انہوں نے بیان کیا کہ ان کی اطلاع کے بعد ان لوگوں نے اس میں سے ایک قطرہ بھی نہ مانگا اور نہ پھر اس کا استعمال کیا۔' WHERE id = 4412;
UPDATE hadiths SET urdu = 'ہم سے عبدالعزیز بن عبداللہ نے بیان کیا، کہا ہم سے ابراہیم بن سعد نے بیان کیا، ان سے ابن شہاب نے، ان سے سالم بن عبداللہ نے اور ان سے ان کے والد (عبداللہ بن عمر رضی اللہ عنہما) نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ غیب کے خزانے پانچ ہیں۔ جیسا کہ ارشاد باری ہے۔ بیشک اللہ ہی کو قیامت کی خبر ہے اور وہی جانتا ہے کہ رحموں میں کیا ہے اور کوئی بھی نہیں جان سکتا کہ وہ کل کیا عمل کرے گا اور نہ کوئی یہ جان سکتا ہے کہ وہ کس زمین پر مرے گا، بیشک اللہ ہی علم والا ہے، خبر رکھنے والا ہے۔“' WHERE id = 4422;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے عمرو بن مرہ نے، ان سے ابووائل نے اور ان سے عبداللہ بن مسعود رضی اللہ عنہ نے ( عمرو بن مرہ نے بیان کیا کہ ) میں نے ( ابووائل سے ) پوچھا، کیا تم نے یہ حدیث ابن مسعود رضی اللہ عنہ سے خود سنی ہے؟ انہوں نے کہا کہ جی ہاں اور انہوں نے رسول اللہ صلی اللہ علیہ وسلم سے بیان کیا، نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اللہ سے زیادہ اور کوئی غیرت مند نہیں ہے۔ اسی لیے اس نے بےحیائیوں کو حرام کیا خواہ ظاہر میں ہوں یا پوشیدہ اور اللہ سے زیادہ اپنی مدح کو پسند کرنے والا اور کوئی نہیں، اسی لیے اس نے اپنے نفس کی خود تعریف کی ہے۔' WHERE id = 4432;
UPDATE hadiths SET urdu = 'مجھ سے اسحاق بن راہویہ نے بیان کیا، کہا ہم کو روح بن عبادہ نے خبر دی، کہا ہم سے شعبہ نے بیان کیا، ان سے خبیب بن عبدالرحمٰن نے انہوں نے حفص بن عاصم سے سنا اور ان سے ابوسعید بن معلی رضی اللہ عنہ نے بیان کیا کہ میں نماز پڑھ رہا تھا کہ رسول اللہ صلی اللہ علیہ وسلم نے مجھے پکارا۔ میں آپ صلی اللہ علیہ وسلم کی خدمت میں نہ پہنچ سکا بلکہ نماز سے فارغ ہونے کے بعد حاضر ہوا۔ آپ صلی اللہ علیہ وسلم نے دریافت فرمایا کہ آنے میں دیر کیوں ہوئی؟ کیا اللہ تعالیٰ نے تمہیں حکم نہیں دیا ہے «يا أيها الذين آمنوا استجيبوا لله وللرسول إذا دعاكم» کہ ”اے ایمان والو! اللہ اور اس کے رسول کی آواز پر لبیک کہو، جبکہ وہ ( یعنی رسول ) تم کو بلائیں۔“ پھر آپ صلی اللہ علیہ وسلم نے فرمایا کہ مسجد سے نکلنے سے پہلے میں تمہیں قرآن کی عظیم ترین سورۃ سکھاؤں گا۔ تھوڑی دیر بعد آپ باہر تشریف لے جانے لگے تو میں نے آپ کو یاد دلایا۔ اور معاذ بن معاذ عنبری نے اس حدیث کو یوں روایت کیا کہ ہم سے شعبہ نے بیان کیا، ان سے خبیب نے، انہوں نے حفص سے سنا اور انہوں نے ابوسعید بن معلی رضی اللہ عنہ جو نبی کریم صلی اللہ علیہ وسلم کے صحابی تھے، سنا اور انہوں نے بیان کیا وہ ( سورۃ فاتحه ) «الحمد لله رب العالمين» ہے جس میں سات آیتیں ہیں جو ہر نماز میں مکرر پڑھی جاتی ہیں۔' WHERE id = 4442;
UPDATE hadiths SET urdu = 'ہم سے اسحاق بن منصور نے بیان کیا، کہا ہم سے یعقوب بن ابراہیم نے بیان کیا، کہا ہم سے ہمارے والد (ابراہیم بن سعد) نے بیان کیا، ان سے صالح نے، ان سے ابن شہاب نے، انہیں حمید بن عبدالرحمٰن نے خبر دی اور انہیں ابوہریرہ رضی اللہ عنہ نے خبر دی کہ ابوبکر رضی اللہ عنہ نے اس حج کے موقع پر جس کا انہیں رسول اللہ صلی اللہ علیہ وسلم نے امیر بنایا تھا۔ حجۃ الوداع سے ( ایک سال ) پہلے 9 ھ میں انہیں بھی ان اعلان کرنے والوں میں رکھا تھا جنہیں لوگوں میں آپ نے یہ اعلان کرنے کے لیے بھیجا تھا کہ آئندہ سال سے کوئی مشرک حج کرنے نہ آئے اور نہ کوئی بیت اللہ کا طواف ننگا ہو کر کرے۔ حمید نے کہا کہ ابوہریرہ رضی اللہ عنہ کی اس حدیث سے معلوم ہوتا ہے کہ یوم نحر بڑے حج کا دن ہے۔' WHERE id = 4452;
UPDATE hadiths SET urdu = 'ہم سے محمد بن کثیر نے بیان کیا، کہا ہم کو سفیان ثوری نے خبر دی، انہیں ان کے والد سعید بن مسروق نے، انہیں ابن ابی نعم نے اور ان سے ابو سعید خدری نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم کے پاس کچھ مال آیا تو آپ نے چار آدمیوں میں اسے تقسیم کر دیا۔ ( جو نو مسلم تھے ) اور فرمایا کہ میں یہ مال دے کر ان کی دلجوئی کرنا چاہتا ہوں اس پر ( بنو تمیم کا ) ایک شخص بولا کہ آپ نے انصاف نہیں کیا۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اس شخص کی نسل سے ایسے لوگ پیدا ہوں گے جو دین سے باہر ہو جائیں گے۔' WHERE id = 4462;
UPDATE hadiths SET urdu = 'مجھ سے محمد بن نصر نیشاپوری نے بیان کیا، کہا ہم سے احمد بن ابی شعیب نے بیان کیا، کہا ہم سے موسیٰ بن اعین نے بیان کیا، کہا ہم سے اسحاق بن راشد نے بیان کیا، ان سے زہری نے بیان کیا، کہا کہ مجھے عبدالرحمٰن بن عبداللہ بن کعب بن مالک نے خبر دی، ان سے ان کے والد عبداللہ نے بیان کیا کہ میں نے اپنے والد کعب بن مالک رضی اللہ عنہ سے سنا۔ وہ ان تین صحابہ میں سے تھے جن کی توبہ قبول کی گئی تھی۔ انہوں نے بیان کیا کہ دو غزووں، غزوہ عسرت ( یعنی غزوہ تبوک ) اور غزوہ بدر کے سوا اور کسی غزوے میں کبھی میں رسول اللہ صلی اللہ علیہ وسلم کے ساتھ جانے سے نہیں رکا تھا۔ انہوں نے بیان کیا چاشت کے وقت جب رسول اللہ صلی اللہ علیہ وسلم ( غزوہ سے واپس تشریف لائے ) تو میں نے سچ بولنے کا پختہ ارادہ کر لیا اور آپ کا سفر سے واپس آنے میں معمول یہ تھا کہ چاشت کے وقت ہی آپ ( مدینہ ) پہنچتے تھے اور سب سے پہلے مسجد میں تشریف لے جاتے اور دو رکعت نماز پڑھتے ( بہرحال ) آپ صلی اللہ علیہ وسلم نے مجھ سے اور میری طرح عذر بیان کرنے والے دو اور صحابہ سے دوسرے صحابہ کو بات چیت کرنے سے منع کر دیا۔ ہمارے علاوہ اور بھی بہت سے لوگ ( جو ظاہر میں مسلمان تھے ) اس غزوے میں شریک نہیں ہوئے لیکن آپ نے ان میں سے کسی سے بھی بات چیت کی ممانعت نہیں کی تھی۔ چنانچہ لوگوں نے ہم سے بات چیت کرنا چھوڑ دیا۔ میں اسی حالت میں ٹھہرا رہا۔ معاملہ بہت طول پکڑتا جا رہا تھا۔ ادھر میری نظر میں سب سے اہم معاملہ یہ تھا کہ اگر کہیں ( اس عرصہ میں ) میں مر گیا تو آپ صلی اللہ علیہ وسلم مجھ پر نماز جنازہ نہیں پڑھائیں گے یا آپ صلی اللہ علیہ وسلم کی وفات ہو جائے تو افسوس لوگوں کا یہی طرز عمل میرے ساتھ پھر ہمیشہ کے لیے باقی رہ جائے گا، نہ مجھ سے کوئی گفتگو کرے گا اور نہ مجھ پر نماز جنازہ پڑھے گا۔ آخر اللہ تعالیٰ نے ہماری توبہ کی بشارت آپ صلی اللہ علیہ وسلم پر اس وقت نازل کی جب رات کا آخری تہائی حصہ باقی رہ گیا تھا۔ آپ صلی اللہ علیہ وسلم اس وقت ام سلمہ رضی اللہ عنہا کے گھر میں تشریف رکھتے تھے۔ ام سلمہ رضی اللہ عنہا کا مجھ پر بڑا احسان و کرم تھا اور وہ میری مدد کیا کرتی تھیں۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ ام سلمہ! کعب کی توبہ قبول ہو گئی۔ انہوں نے عرض کیا۔ پھر میں ان کے یہاں کسی کو بھیج کر یہ خوشخبری نہ پہنچوا دوں؟ آپ صلی اللہ علیہ وسلم نے فرمایا کہ یہ خبر سنتے ہی لوگ جمع ہو جائیں گے اور ساری رات تمہیں سونے نہیں دیں گے۔ چنانچہ نبی کریم صلی اللہ علیہ وسلم نے فجر کی نماز پڑھنے کے بعد بتایا کہ اللہ نے ہماری توبہ قبول کر لی ہے۔ نبی کریم صلی اللہ علیہ وسلم نے جب یہ خوشخبری سنائی تو آپ کا چہرہ مبارک منور ہو گیا جیسے چاند کا ٹکڑا ہو اور ( غزوہ میں نہ شریک ہونے والے دوسرے لوگوں سے ) جنہوں نے معذرت کی تھی اور ان کی معذرت قبول بھی ہو گئی تھی۔ ہم تین صحابہ کا معاملہ بالکل مختلف تھا کہ اللہ تعالیٰ نے ہماری توبہ قبول ہونے کے متعلق وحی نازل کی، لیکن جب ان دوسرے غزوہ میں شریک نہ ہونے والے لوگوں کا ذکر کیا، جنہوں نے آپ صلی اللہ علیہ وسلم کے سامنے جھوٹ بولا تھا اور جھوٹی معذرت کی تھی تو اس درجہ برائی کے ساتھ کیا کہ کسی کا بھی اتنی برائی کے ساتھ ذکر نہ کیا ہو گا۔ اللہ تعالیٰ نے فرمایا «يعتذرون إليكم إذا رجعتم إليهم قل لا تعتذروا لن نؤمن لكم قد نبأنا الله من أخباركم وسيرى الله عملكم ورسوله‏» کہ ”یہ لوگ تمہارے سب کے سامنے عذر پیش کریں گے، جب تم ان کے پاس واپس جاؤ گے تو آپ کہہ دیں کہ بہانے نہ بناؤ ہم ہرگز تمہاری بات نہ مانیں گے! بیشک ہم کو اللہ تمہاری خبر دے چکا ہے اور عنقریب اللہ اور اس کا رسول تمہارا عمل دیکھ لیں گے۔“ آخر آیت تک۔' WHERE id = 4472;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے یزید بن زریع نے بیان کیا، کہا ہم سے سلیمان تیمی نے بیان کیا، ان سے ابوعثمان نے اور ان سے ابن مسعود رضی اللہ عنہ نے کہ ایک شخص نے کسی غیر عورت کو بوسہ دے دیا اور پھر وہ رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوا اور آپ سے اپنا گناہ بیان کیا۔ اس پر یہ آیت نازل ہوئی «وأقم الصلاة طرفى النهار وزلفا من الليل إن الحسنات يذهبن السيئات ذلك ذكرى للذاكرين‏» ”اور تم نماز کی پابندی کرو دن کے دونوں سروں پر اور رات کے کچھ حصوں میں بیشک نیکیاں مٹا دیتی ہیں بدیوں کو، یہ ایک نصیحت ہے نصیحت ماننے والوں کے لیے۔“ ان صاحب نے عرض کیا یہ آیت صرف میرے ہی لیے ہے ( کہ نیکیاں بدیوں کو مٹا دیتی ہیں ) ؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ میری امت کے ہر انسان کے لیے ہے جو اس پر عمل کرے۔' WHERE id = 4482;
UPDATE hadiths SET urdu = 'ہم سے ابوالولید نے بیان کیا، انہوں نے کہا ہم سے شعبہ نے بیان کیا، انہوں نے کہا کہ مجھے علقمہ بن مرثد نے خبر دی، انہوں نے کہا کہ میں نے سعد بن عبیدہ سے سنا اور انہوں نے براء بن عازب رضی اللہ عنہ سے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ مسلمان سے جب قبر میں سوال ہو گا تو وہ گواہی دے گا کہ اللہ کے سوا کوئی معبود نہیں اور یہ کہ محمد اللہ کے رسول ہیں۔ اللہ تعالیٰ کے ارشاد «يثبت الله الذين آمنوا بالقول الثابت في الحياة الدنيا وفي الآخرة‏» ”اللہ ایمان والوں کی اس پکی بات ( کی برکت ) سے مضبوط رکھتا ہے، دنیوی زندگی میں ( بھی ) اور آخرت میں ( بھی ) “ کا یہی مطلب ہے۔' WHERE id = 4494;
UPDATE hadiths SET urdu = 'ہم سے عبدان نے بیان کیا، کہا ہم سے عبداللہ بن مبارک نے بیان کیا، کہا ہم کو یونس بن یزید نے خبر دی (دوسری سند) امام بخاری رحمہ اللہ نے کہا اور ہم سے احمد بن صالح نے بیان کیا، کہا ہم سے عنبسہ بن خالد نے بیان کیا، کہا ہم سے یونس بن یزید نے بیان کیا، ان سے ابن شہاب نے کہ ابن مسیب نے بیان کیا اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ معراج کی رات میں نبی کریم صلی اللہ علیہ وسلم کے سامنے بیت المقدس میں دو پیالے پیش کئے گئے ایک شراب کا اور دوسرا دودھ کا۔ نبی کریم صلی اللہ علیہ وسلم نے دونوں کو دیکھا پھر دودھ کا پیالہ اٹھا لیا۔ اس پر جبرائیل علیہ السلام نے کہا کہ تمام حمد اس اللہ کے لیے ہے جس نے آپ کو فطرت ( اسلام ) کی ہدایت کی۔ اگر آپ شراب کا پیالہ اٹھا لیتے تو آپ کی امت گمراہ ہو جاتی۔' WHERE id = 4504;
UPDATE hadiths SET urdu = 'ہم سے علی بن عیاش نے بیان کیا، انہوں نے کہا ہم سے شعیب بن ابی حمزہ نے بیان کیا، ان سے محمد بن منکدر نے بیان کیا اور ان سے جابر بن عبداللہ انصاری رضی اللہ عنہما نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ جس نے اذان سن کر یہ دعا پڑھی «اللهم رب هذه الدعوة التامة والصلاة القائمة،‏‏‏‏ آت محمدا الوسيلة والفضيلة،‏‏‏‏ وابعثه مقاما محمودا الذي وعدته،‏‏‏‏ حلت له شفاعتي يوم القيامة‏ ‏‏.‏» ”اے اللہ! اس کامل پکار کے رب اور کھڑی ہونے والی نماز کے رب! محمد ( صلی اللہ علیہ وسلم ) کو قرب اور فضیلت عطا فرما اور انہیں مقام محمود پر کھڑا کیجؤ۔ جس کا تو نے ان سے وعدہ کیا ہے۔“ تو اس کے لیے قیامت کے دن میری شفاعت ضروری ہو گی۔ اس حدیث کو حمزہ بن عبداللہ نے بھی اپنے والد ( عبداللہ بن عمر رضی اللہ عنہما ) سے روایت کیا ہے اور انہوں نے نبی کریم صلی اللہ علیہ وسلم سے۔' WHERE id = 4514;
UPDATE hadiths SET urdu = 'ہم سے محمد بن عبداللہ ذہلی نے بیان کیا، کہا ہم سے سعید بن ابی مریم نے بیان کیا، کہا ہم کو مغیرہ بن عبدالرحمٰن نے خبر دی، کہا کہ مجھ سے ابوالزناد نے بیان کیا، ان سے اعرج نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ بلاشبہ قیامت کے دن ایک بہت بھاری بھر کم موٹا تازہ شخص آئے گا لیکن وہ اللہ کے نزدیک مچھر کے پر کے برابر بھی کوئی قدر نہیں رکھے گا اور فرمایا کہ پڑھو «فلا نقيم لهم يوم القيامة وزنا‏» ”قیامت کے دن ہم ان کا کوئی وزن نہ کریں گے۔“ اس حدیث کو محمد بن عبداللہ نے یحییٰ بن بکیر سے، انہوں نے مغیرہ بن عبدالرحمٰن سے، انہوں نے ابوالزناد سے ایسا ہی روایت کیا ہے۔' WHERE id = 4524;
UPDATE hadiths SET urdu = 'ہم سے محمد بن بشار نے بیان کیا، کہا ہم سے غندر نے، کہا ہم سے شعبہ نے، انہوں نے ابواسحاق سے سنا، کہا میں نے عبدالرحمٰن بن یزید سے سنا، انہوں نے عبداللہ بن مسعود رضی اللہ عنہ سے وہ کہتے تھے کہ سورۃ بنی اسرائیل اور سورۃ کہف اور سورۃ مریم اور سورۃ طہٰ اور سورۃ انبیاء اگلی بہت فصیح سورتوں میں سے ہیں ( جو مکہ میں اتری تھیں ) اور میری پرانی یاد کی ہوئی ہیں۔ قتادہ نے کہا «جذاذا‏» کا معنی ٹکڑے ٹکڑے۔ اور حسن بصری نے کہا «كل في فلك‏» یعنی ہر ایک تارہ ایک ایک آسمان میں گول گھومتا ہے، جیسے سوت کاتنے کا چرخہ۔ «يسبحون‏» یعنی گول گھومتے ہیں۔ ابن عباس رضی اللہ عنہما نے کہا «نفشت‏» کے معنی چر گئیں۔ «يصحبون‏» کے معنی روکے جائیں گے۔ بچائے جائیں گے۔ «أمتكم أمة واحدة‏» یعنی تمہارا دین اور مذہب ایک ہی دین اور مذہب ہے۔ اور عکرمہ نے کہا «حصب‏» حبشی زبان میں جلانے کی لکڑیوں ایندھن کو کہتے ہیں۔ اور لوگوں نے کہا لفظ «أحسوا‏» کے معنی توقع پائی یہ «أحسست‏» سے نکلا ہے یعنی آہٹ پائی۔ «خامدين‏» کے معنی بجھے ہوئے ( یعنی مرے ہوئے ) ۔ «حصيد» کے معنی جڑ سے اکھاڑا گیا، واحد اور تثنیہ اور جمع سب پر یہی لفظ بولا جاتا ہے۔ «لا يستحسرون‏» کے معنی نہیں تھکے اسی سے ہے لفظ «حسير» تھکا ہوا۔ اور «حسرت بعيري‏.‏» کے معنی میں نے اپنے اونٹ کو تھکا دیا۔ «عميق» ‏‏‏‏ کے معنی دور دراز۔ «نكسوا‏» یہ کفر کی طرف پھیرے گئے۔ «صنعة لبوس‏» زرہیں بنانا۔ «تقطعوا أمرهم‏» یعنی اختلاف کیا، جدا جدا طریقہ اختیار کیا۔ «لا يسمعون حسيسها» کے معنی اور لفظ «حس» اور «جرس» اور «همس» کے معانی ایک ہی ہیں یعنی پست آواز۔ «آذناك‏» ہم نے تجھ کو آگاہ کیا عرب لوگ کہتے ہیں۔ «آذنتكم‏» یعنی میں نے تم کو خبر دی تم ہم برابر ہو گئے میں نے کوئی دغا نہیں کی جب آپ مخاطب کو کسی بات کی خبر دے چکے تو آپ اور وہ دونوں برابر ہو گئے اور آپ نے اس سے کوئی دغا نہیں کی۔ اور مجاہد نے کہا «لعلكم تسألون‏» کے معنی یہ ہیں شاید تم سمجھو۔ «ارتضى‏» کے معنی پسند کیا راضی ہوا۔ «التماثيل‏» کے معنی مورتیں بت۔ «السجل» معنی کے خطوں کا مجموعہ دفتر۔' WHERE id = 4534;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم نے بیان کیا، کہا کہ ہم سے سفیان نے بیان کیا، ان سے معمر نے، ان سے زہری نے، ان سے عروہ نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا «والذي تولى كبره‏» یعنی اور جس نے ان میں سے سب سے بڑھ کر حصہ لیا تھا اور مراد عبداللہ بن ابی ابن سلول ( منافق ) ہے۔' WHERE id = 4544;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم نے بیان کیا، کہا ہم سے ابراہیم بن نافع نے بیان کیا، ان سے حسن بن مسلم نے، ان سے صفیہ بنت شیبہ نے اور ان سے عائشہ رضی اللہ عنہا بیان کرتی تھی کہ جب یہ آیت نازل ہوئی «وليضربن بخمرهن على جيوبهن‏» کہ ”اور اپنے دوپٹے اپنے سینوں پر ڈالے رہا کریں“ تو ( انصار کی عورتوں نے ) اپنے تہبندوں کو دونوں کنارے سے پھاڑ کر ان کی اوڑھنیاں بنا لیں۔' WHERE id = 4554;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل نے بیان کیا، کہا مجھ سے میرے بھائی (عبدالحمید) نے بیان کیا، ان سے ابن ابی ذئب نے، ان سے سعید مقبری نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ ابراہیم علیہ الصلٰوۃ والسلام اپنے والد سے ( قیامت کے دن ) جب ملیں گے تو اللہ تعالیٰ سے عرض کریں گے کہ اے رب! تو نے وعدہ کیا تھا کہ تو مجھے اس دن رسوا نہیں کرے گا جب سب اٹھائے جائیں گے لیکن اللہ تعالیٰ جواب دے گا کہ میں نے جنت کو کافروں پر حرام قرار دے دیا ہے۔' WHERE id = 4564;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ نے بیان کیا، کہا ہم سے سفیان نے بیان کیا، ان سے ابوالزناد نے، ان سے اعرج نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ اللہ تعالیٰ کا ارشاد ہے کہ ”میں نے اپنے صالح اور نیک بندوں کے لیے وہ چیزیں تیار کر رکھی ہیں جنہیں کسی آنکھ نے دیکھا نہ کسی کان نے سنا اور نہ کسی کے گمان و خیال میں وہ آئی ہیں۔“ ابوہریرہ رضی اللہ عنہ نے کہا کہ اگر چاہو تو اس آیت کو پڑھ لو «فلا تعلم نفس ما أخفي لهم من قرة أعين‏» کہ ”سو کسی کو نہیں معلوم جو جو سامان آنکھوں کی ٹھنڈک کا ان کے لیے جنت میں چھپا کر رکھا گیا ہے۔“ علی بن عبداللہ مدینی نے بیان کیا کہ ہم سے سفیان نے بیان کیا، ان سے ابوالزناد نے بیان کیا، ان سے اعرج نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ اللہ تعالیٰ نے فرمایا ہے، پہلی حدیث کی طرح۔ سفیان سے پوچھا گیا کہ یہ آپ نبی کریم صلی اللہ علیہ وسلم کی حدیث روایت کر رہے ہیں یا اپنے اجتہاد سے فرما رہے ہیں؟ انہوں نے فرمایا کہ ( اگر یہ نبی کریم صلی اللہ علیہ وسلم کی حدیث نہیں ہے ) تو پھر اور کیا ہے؟ ابومعاویہ نے بیان کیا، ان سے اعمش نے اور ان سے صالح نے کہ ابوہریرہ رضی اللہ عنہ نے ( آیت مذکورہ میں ) قرآت ( صیغہ جمع کے ساتھ ) پڑھا ہے۔' WHERE id = 4574;
UPDATE hadiths SET urdu = 'ہم سے حبان بن موسیٰ نے بیان کیا، کہا ہم کو عبداللہ نے خبر دی، کہا ہم کو عاصم احول نے خبر دی، انہیں معاذہ نے اور انہیں عائشہ رضی اللہ عنہا نے کہ رسول اللہ صلی اللہ علیہ وسلم اس آیت کے نازل ہونے کے بعد بھی «ترجئ من تشاء منهن وتؤوي إليك من تشاء ومن ابتغيت ممن عزلت فلا جناح عليك‏» کہ ”ان میں سے آپ جس کو چاہیں اپنے سے دور رکھیں اور جن کو آپ نے الگ کر رکھا تھا ان میں سے کسی کو طلب کر لیں جب بھی آپ پر کوئی گناہ نہیں۔“ اگر ( ازواج مطہرات ) میں سے کسی کی باری میں کسی دوسری بیوی کے پاس جانا چاہتے تو جن کی باری ہوتی ان سے اجازت لیتے تھے ( معاذہ نے بیان کیا کہ ) میں نے اس پر عائشہ رضی اللہ عنہا سے پوچھا کہ ایسی صورت میں آپ نبی کریم صلی اللہ علیہ وسلم سے کیا کہتی تھیں؟ انہوں نے فرمایا کہ میں تو یہ عرض کر دیتی تھی کہ یا رسول اللہ! اگر یہ اجازت آپ مجھ سے لے رہے ہیں تو میں تو اپنی باری کا کسی دوسرے پر ایثار نہیں کر سکتی۔ اس روایت کی متابعت عباد بن عباد نے کی، انہوں نے عاصم سے سنا۔' WHERE id = 4584;
UPDATE hadiths SET urdu = 'ہم سے اسحاق بن ابراہیم نے بیان کیا، انہوں نے کہا ہم کو روح بن عبادہ نے خبر دی، انہوں نے کہا ہم سے عوف نے بیان کیا، ان سے حسن بصری اور محمد بن سیرین اور خلاس نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ موسیٰ علیہ السلام بڑے باحیاء تھے، انہیں کے متعلق اللہ تعالیٰ کا یہ ارشاد ہے «يا أيها الذين آمنوا لا تكونوا كالذين آذوا موسى فبرأه الله مما قالوا وكان عند الله وجيها‏» کہ ”اے ایمان والو! ان لوگوں کی طرح نہ ہو جانا جنہوں نے موسیٰ علیہ السلام کو ایذا پہنچائی تھی، سو اللہ نے انہیں بَری ثابت کر دیا اور اللہ کے نزدیک وہ بڑے عزت والے تھے۔“' WHERE id = 4594;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا ہم سے جریر نے بیان کیا، ان سے اعمش نے، ان سے ابوالضحیٰ نے، ان سے مسروق نے کہ ہم عبداللہ بن مسعود رضی اللہ عنہ کی خدمت میں حاضر ہوئے۔ انہوں نے کہا: اے لوگو! جس شخص کو کسی چیز کا علم ہو تو وہ اسے بیان کرے اگر علم نہ ہو تو کہے کہ اللہ ہی کو زیادہ علم ہے کیونکہ یہ بھی علم ہی ہے کہ جو چیز نہ جانتا ہو اس کے متعلق کہہ دے کہ اللہ ہی زیادہ جاننے والا ہے۔ اللہ تعالیٰ نے اپنے نبی صلی اللہ علیہ وسلم سے بھی کہہ دیا تھا «قل ما أسألكم عليه من أجر وما أنا من المتكلفين‏» کہ ”آپ کہہ دیجئیے کہ میں تم سے اس قرآن یا تبلیغ وحی پر کوئی اجرت نہیں چاہتا ہوں اور نہ میں بناوٹ کرنے والا ہوں۔“ اور میں «دخان» ( دھوئیں ) کے بارے میں بتاؤں گا ( جس کا ذکر قرآن میں آیا ہے ) رسول اللہ صلی اللہ علیہ وسلم نے قریش کو اسلام کی دعوت دی تو انہوں نے تاخیر کی، نبی کریم صلی اللہ علیہ وسلم نے ان کے حق میں بددعا کی «اللهم أعني عليهم بسبع كسبع يوسف» ”اے اللہ! ان پر یوسف علیہ السلام کے زمانہ کی سی قحط سالی کے ذریعہ میری مدد کر۔“ چنانچہ قحط پڑا اور اتنا زبردست کہ ہر چیز ختم ہو گئی اور لوگ مردار اور چمڑے کھانے پر مجبور ہو گئے۔ بھوک کی شدت کی وجہ سے یہ حال تھا کہ آسمان کی طرف دھواں ہی دھواں نظر آتا۔ اسی کے بارے میں اللہ تعالیٰ نے فرمایا «فارتقب يوم تأتي السماء بدخان مبين * يغشى الناس هذا عذاب أليم‏» کہ ”پس انتظار کرو اس دن کا جب آسمان کھلا ہوا دھواں لائے گا جو لوگوں پر چھا جائے گا یہ درد ناک عذاب ہے۔“ بیان کیا کہ پھر قریش دعا کرنے لگے «ربنا اكشف عنا العذاب إنا مؤمنون * أنى لهم الذكرى وقد جاءهم رسول مبين * ثم تولوا عنه وقالوا معلم مجنون * إنا كاشفو العذاب قليلا إنكم عائدون‏» کہ ”اے ہمارے رب! اس عذاب کو ہم سے ہٹا لے تو ہم ایمان لائیں گے لیکن وہ نصیحت سننے والے کہاں ہیں ان کے پاس تو رسول صاف معجزات و دلائل کے ساتھ آ چکا اور وہ اس سے منہ موڑ چکے ہیں اور کہہ چکے ہیں کہ اسے تو سکھایا جا رہا ہے، یہ مجنون ہے، بیشک ہم تھوڑے دنوں کے لیے ان سے عذاب ہٹا لیں گے یقیناً تم پھر کفر ہی کی طرف لوٹ جاؤ گے کیا قیامت میں بھی عذاب ہٹایا جائے گا۔“ ابن مسعود رضی اللہ عنہ نے بیان کیا کہ پھر یہ عذاب تو ان سے دور کر دیا گیا لیکن جب وہ دوبارہ کفر میں مبتلا ہو گئے تو جنگ بدر میں اللہ نے انہیں پکڑا۔ اللہ تعالیٰ کے اس ارشاد میں اسی طرف اشارہ ہے «يوم نبطش البطشة الكبرى إنا منتقمون‏» کہ ”جس دن ہم سخت پکڑ کریں گے، بلاشبہ ہم بدلہ لینے والے ہیں۔“' WHERE id = 4604;
UPDATE hadiths SET urdu = 'ہم سے حجاج بن منہال نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے بیان کیا، ان سے عمرو نے، ان سے عطاء نے، ان سے صفوان بن یعلیٰ نے اور ان سے ان کے والد نے کہ میں نے رسول اللہ صلی اللہ علیہ وسلم کو منبر پر یہ آیت پڑھتے سنا «ونادوا يا مالك ليقض علينا ربك‏» ”اور یہ لوگ پکاریں گے کہ اے مالک! تمہارا پروردگار ہمارا کام ہی تمام کر دے۔“ اور قتادہ نے کہا «مثلا للآخرين» یعنی پچھلوں کے لیے نصیحت۔ دوسرے نے کہا «مقرنين‏» کا معنی قابو میں رکھنے والے۔ عرب لوگ کہتے ہیں فلانا فلانے کا «مقرن» ہے یعنی اس پر اختیار رکھتا ہے ( اس کو قابو میں لایا ہے ) ۔ «أكواب» وہ کوزے جن میں ٹونٹی نہ ہو بلکہ منہ کھلا ہوا ہو جہاں سے آدمی چاہے پئے۔ «ان کان للرحمن ولد» کا معنی یہ ہے کہ اس کی کوئی اولاد نہیں ہے۔ ( اس صورت میں «ان نافيه» ہے ) «عابدين» سے «آنفين» مراد ہے۔ یعنی سب سے پہلے میں اس سے «عار» کرتا ہوں۔ اس میں دو لغت ہیں «عابد وعبد» اور عبداللہ بن مسعود رضی اللہ عنہ نے اس کو «وقال الرسول يا رب‏» پڑھا ہے۔ «أول العابدين» کے معنی سب سے پہلا انکار کرنے والا یعنی اگر خدا کی اولاد ثابت کرتے ہو تو میں اس کا سب سے پہلا انکاری ہوں۔ اس صورت میں «عابدين» باب «عبد يعبد‏.‏» سے آئے گا اور قتادہ نے کہا «في أم الكتاب‏» کا معنی یہ ہے کہ مجموعی کتاب اور اصل کتاب ( یعنی لوح محفوظ میں ) ۔' WHERE id = 4614;
UPDATE hadiths SET urdu = 'ہم سے خالد بن مخلد نے بیان کیا، انہوں نے کہا کہ ہم سے سلیمان نے بیان کیا، کہا کہ مجھ سے معاویہ بن ابی مزرد نے بیان کیا، ان سے سعید بن یسار نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اللہ تعالیٰ نے مخلوق پیدا کی، جب وہ اس کی پیدائش سے فارغ ہوا تو رحم نے کھڑے ہو کر رحم کرنے والے اللہ کے دامن میں پناہ لی۔ اللہ تعالیٰ نے اس سے فرمایا کیا تجھے یہ پسند نہیں کہ جو تجھ کو جوڑے میں بھی اسے جوڑوں اور جو تجھے توڑے میں بھی اسے توڑ دوں۔ رحم نے عرض کیا، ہاں اے میرے رب! اللہ تعالیٰ نے فرمایا، پھر ایسا ہی ہو گا۔ ابوہریرہ رضی اللہ عنہ نے کہا کہ اگر تمہارا جی چاہے تو یہ آیت پڑھ لو «فهل عسيتم إن توليتم أن تفسدوا في الأرض وتقطعوا أرحامكم» ”اگر تم کنارہ کش رہو تو آیا تم کو یہ احتمال بھی ہے کہ تم لوگ دین میں فساد مچا دو گے اور آپس میں قطع تعلق کر لو گے۔“' WHERE id = 4624;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا ہم سے سفیان نے بیان کیا، ان سے عمرو نے اور ان سے جابر رضی اللہ عنہ نے بیان کیا کہ صلح حدیبیہ کے موقع پر لشکر میں ہم ( مسلمان ) ایک ہزار چار سو تھے۔' WHERE id = 4634;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد نے بیان کیا، انہوں نے کہا ہم سے عبدالرزاق نے بیان کیا، انہوں نے کہا ہم کو معمر نے خبر دی، انہیں حمام نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ جنت اور دوزخ نے بحث کی، دوزخ نے کہا میں متکبروں اور ظالموں کے لیے خاص کی گئی ہوں۔ جنت نے کہا مجھے کیا ہوا کہ میرے اندر صرف کمزور اور کم رتبہ والے لوگ داخل ہوں گے۔ اللہ تعالیٰ نے اس پر جنت سے کہا کہ تو میری رحمت ہے، تیرے ذریعہ میں اپنے بندوں میں جس پر چاہوں رحم کروں اور دوزخ سے کہا کہ تو عذاب ہے تیرے ذریعہ میں اپنے بندوں میں سے جسے چاہوں عذاب دوں۔ جنت اور دوزخ دونوں بھریں گی۔ دوزخ تو اس وقت تک نہیں بھرے گی جب تک اللہ رب العزت اپنا قدم اس نہیں رکھ دے گا۔ اس وقت وہ بولے گی کہ بس بس بس! اور اس وقت بھر جائے گی اور اس کا بعض حصہ بعض دوسرے حصے پر چڑھ جائے گا اور اللہ تعالیٰ اپنے بندوں میں کسی پر ظلم نہیں کرے گا اور جنت کے لیے اللہ تعالیٰ ایک مخلوق پیدا کرے گا «وسبح بحمد ربك قبل طلوع الشمس وقبل الغروب» ”اور اپنے رب کی حمد و تسبیح کرتے رہئیے سورج کے نکلنے سے پہلے اور اس کے چھپنے سے پہلے۔“' WHERE id = 4644;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد مسندی نے بیان کیا، انہوں نے کہا ہم کو ہشام بن یوسف نے خبر دی، انہوں نے کہا ہم کو معمر نے خبر دی، انہوں نے کہا ہمیں زہری نے، انہیں حمید بن عبدالرحمٰن نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ جو شخص قسم کھائے اور کہے کہ قسم ہے لات اور عزیٰ کی تو اسے تجدید ایمان کے لیے کہنا چاہئے «لا إله إلا الله» اور جو شخص اپنے ساتھی سے یہ کہے کہ آؤ جوا کھیلیں تو اسے صدقہ دینا چاہئے۔' WHERE id = 4654;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، ان سے یحییٰ بن سعید قطان نے بیان کیا، ان سے شعبہ نے، ان سے ابواسحاق نے، ان سے اسود نے اور ان سے عبداللہ بن مسعود رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم «فهل من مدكر‏» ( سو ہے کوئی نصیحت حاصل کرنے والا؟ ) پڑھا کرتے تھے۔' WHERE id = 4664;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے بیان کیا، ان سے ابوالزناد نے، ان سے اعرج نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا، وہ کہتے تھے کہ انہوں نے رسول اللہ صلی اللہ علیہ وسلم سے سنا تھا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ جنت میں ایک درخت طویل ہو گا ( اتنا بڑا کہ ) سوار اس کے سایہ میں سو سال تک چلے گا اور پھر بھی اس کا سایہ ختم نہ ہو گا اگر تمہارا جی چاہے تو اس آیت «وظل ممدود‏» کی قرآت کر لو۔' WHERE id = 4674;
UPDATE hadiths SET urdu = 'ہم سے اسحاق بن منصور نے بیان کیا، کہا ہم سے یعقوب بن ابراہیم نے بیان کیا، کہا ہم سے ابن شہاب کے بھتیجے نے اپنے چچا محمد بن مسلم سے، انہیں عروہ نے خبر دی اور انہیں نبی کریم صلی اللہ علیہ وسلم کی زوجہ مطہرہ عائشہ رضی اللہ عنہا نے خبر دی کہ رسول اللہ صلی اللہ علیہ وسلم اس آیت کے نازل ہونے کے بعد ان مومن عورتوں کا امتحان لیا کرتے تھے جو ہجرت کر کے مدینہ آتی تھیں۔ اللہ تعالیٰ نے ارشاد فرمایا تھا «يا أيها النبي إذا جاءك المؤمنات يبايعنك‏» کہ ”اے نبی! جب آپ سے مسلمان عورتیں بیعت کرنے کے لیے آئیں“ ارشاد «غفور رحيم‏» تک۔ عروہ نے بیان کیا کہ عائشہ رضی اللہ عنہا نے کہا چنانچہ جو عورت اس شرط ( آیت میں مذکور یعنی ایمان وغیرہ ) کا اقرار کر لیتی نبی کریم صلی اللہ علیہ وسلم اس سے زبانی طور پر فرماتے کہ میں نے تمہاری بیعت قبول کر لی اور ہرگز نہیں، اللہ کی قسم! نبی کریم صلی اللہ علیہ وسلم کے ہاتھ نے کسی عورت کا ہاتھ بیعت لیتے وقت کبھی نہیں چھوا صرف آپ ان سے زبانی بیعت لیتے تھے کہ آیت میں مذکورہ باتوں پر قائم رہنا۔ اس روایت کی متابعت یونس، معمر اور عبدالرحمٰن بن اسحاق نے زہری سے کی اور اسحاق بن راشد نے زہری سے بیان کیا کہ ان سے عروہ اور عمرہ بنت عبدالرحمٰن نے کہا۔' WHERE id = 4684;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا، انہوں نے کہا ہم سے اسرائیل بن یونس نے بیان کیا، انہوں نے کہا ان سے ابواسحاق سبیعی نے بیان کیا اور ان سے زید بن ارقم رضی اللہ عنہ نے بیان کیا کہ میں اپنے چچا ( سعد بن عبادہ یا عبداللہ بن رواحہ رضی اللہ عنہما ) کے ساتھ تھا میں نے عبداللہ بن ابی ابن سلول کو کہتے سنا کہ جو لوگ رسول اللہ صلی اللہ علیہ وسلم کے پاس ہیں ان پر خرچ مت کرو تاکہ وہ ان کے پاس سے بھاگ جائیں۔ یہ بھی کہا کہ اگر اب ہم مدینہ لوٹ کر جائیں گے تو عزت والا وہاں سے ذلیلوں کو نکال کر باہر کر دے گا۔ میں نے اس کی یہ بات چچا سے آ کر کہی اور انہوں نے رسول اللہ صلی اللہ علیہ وسلم سے اس کا ذکر کیا۔ نبی کریم صلی اللہ علیہ وسلم نے عبداللہ بن ابی اور اس کے ساتھیوں کو بلوایا انہوں نے قسم کھا لی کہ ایسی کوئی بات انہوں نے نہیں کہی تھی۔ نبی کریم صلی اللہ علیہ وسلم نے بھی ان کو سچا جانا اور مجھ کو جھوٹا سمجھا۔ مجھے اس اتنا صدمہ پہنچا کہ ایسا کبھی نہیں پہنچا ہو گا پھر میں گھر کے اندر بیٹھ گیا۔ پھر اللہ تعالیٰ نے یہ سورت نازل کی «إذا جاءك المنافقون‏» سے «هم الذين يقولون لا تنفقوا على من عند رسول الله‏» اور آیت «ليخرجن الأعز منها الأذل‏» تو نبی کریم صلی اللہ علیہ وسلم نے مجھے بلوایا اور میرے سامنے اس سورت کی تلاوت کی پھر فرمایا کہ اللہ نے تمہارے بیان کو سچا کر دیا ہے۔' WHERE id = 4694;
UPDATE hadiths SET urdu = 'ہم سے معاذ بن فضالہ نے بیان کیا، کہا ہم سے ہشام بن عروہ نے بیان کیا، ان سے یحییٰ بن سعید قطان نے، ان سے ابن حکیم نے، ان سے سعید بن جبیر نے اور ان سے ابن عباس نے کہا کہ اگر کسی نے اپنے اوپر کوئی حلال چیز حرام کر لی تو اس کا کفارہ دینا ہو گا۔ ابن عباس رضی اللہ عنہما نے کہا «لقد كان لكم في رسول الله إسوة حسنة‏» یعنی ”بیشک تمہارے لیے تمہارے رسول اللہ کی زندگی میں بہترین نمونہ ہے۔“' WHERE id = 4704;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، کہا کہ ہم سے ابوعوانہ نے بیان کیا، ان سے ابوبشر نے، ان سے سعید بن جبیر نے اور ان سے ابن عباس رضی اللہ عنہما نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے اپنے صحابہ کے ساتھ سوق عکاظ ( مکہ اور طائف کے درمیان ایک میدان جہاں عربوں کا مشہور میلہ لگتا تھا ) کا قصد کیا اس زمانہ میں شیاطین تک آسمان کی خبروں کے چرا لینے میں رکاوٹ پیدا کر دی گئی تھی اور ان پر آسمان سے آگ کے انگارے چھوڑے جاتے تھے جب وہ جِن اپنی قوم کے پاس لوٹ کر آئے تو ان کی قوم نے ان سے پوچھا کہ کیا بات ہوئی۔ انہوں نے بتایا کہ آسمان کی خبروں میں اور ہمارے درمیان رکاوٹ کر دی گئی ہے اور ہم پر آسمان سے آگ کے انگارے برسائے گئے ہیں، انہوں نے کہا کہ آسمان کی خبروں اور تمہارے درمیان رکاوٹ ہونے کی وجہ یہ ہے کہ کوئی خاص بات پیش آئی ہے۔ اس لیے ساری زمین پر مشرق و مغرب میں پھیل جاؤ اور تلاش کرو کہ کون سی بات پیش آ گئی ہے۔ چنانچہ شیاطین مشرق و مغرب میں پھیل گئے تاکہ اس بات کا پتہ لگائیں کہ آسمان کی خبروں کی ان تک پہنچنے میں رکاوٹ پیدا کی گئی ہے وہ کس بڑے واقعہ کی وجہ سے ہے۔ بیان کیا کہ جو شیاطین اس کھوج میں نکلے تھے ان کا ایک گروہ وادی تہامہ کی طرف بھی آ نکلا ( یہ جگہ مکہ معظمہ سے ایک دن کے سفر کی راہ پر ہے ) جہاں رسول اللہ صلی اللہ علیہ وسلم منڈی عکاظ کی طرف جاتے ہوئے کھجور کے ایک باغ کے پاس ٹھہرے ہوئے تھے۔ نبی کریم صلی اللہ علیہ وسلم اس وقت صحابہ کے ساتھ فجر کی نماز پڑھ رہے تھے۔ جب شیاطین نے قرآن مجید سنا تو یہ اس کو سننے لگ گئے پھر انہوں نے کہا کہ یہی چیز ہے وہ جس کی وجہ سے تمہارے اور آسمان کی خبروں کے درمیان رکاوٹ پیدا ہوئی ہے۔ اس کے بعد وہ اپنی قوم کی طرف لوٹ آئے اور ان سے کہا کہ «إنا سمعنا قرآنا عجبا» الایۃ ہم نے ایک عجیب قرآن سنا ہے جو نیکی کی راہ دکھلاتا ہے سو ہم تو اس پر ایمان لے آئے اور ہم اب اپنے پروردگار کو کسی کا ساجھی نہ بنائیں گے اللہ تعالیٰ نے اپنے نبی صلی اللہ علیہ وسلم پر یہ آیت نازل کی «قل أوحي إلى أنه استمع نفر من الجن‏» الایۃ۔ آپ کہئے کہ میرے پاس وحی آئی ہے اس بات کی کہ جِنوں کی ایک جماعت نے قرآن مجید سنا یہی جِنوں کا قول نبی کریم صلی اللہ علیہ وسلم پر نازل ہوا۔' WHERE id = 4714;
UPDATE hadiths SET urdu = 'ہم سے عبدہ بن عبداللہ خزاعی نے بیان کیا، کہا ہم کو یحییٰ بن آدم نے خبر دی، انہیں اسرائیل نے، انہیں منصور نے یہی حدیث اور اسرائیل نے اس حدیث کو اعمش سے، انہوں نے ابراہیم سے، انہوں نے علقمہ سے، انہوں نے عبداللہ بن مسعود رضی اللہ عنہ سے بھی روایت کیا ہے اور یحییٰ بن آدم کے ساتھ اس حدیث کو اسود بن عامر نے اسرائیل سے روایت کی اور حفص بن غیاث اور ابومعاویہ اور سلیمان بن قرم نے اعمش سے، انہوں نے ابراہیم سے، انہوں نے اسود سے روایت کیا اور یحییٰ بن حماد ( شیخ بخاری ) نے کہا ہم کو ابوعوانہ نے خبر دی، انہوں نے مغیرہ بن مقسم سے، انہوں نے ابراہیم سے، انہوں نے علقمہ سے، انہوں نے عبداللہ بن مسعود سے اور محمد بن اسحاق نے اس حدیث کو عبدالرحمٰن بن اسود سے روایت کیا، انہوں نے اپنے والد اسود سے، انہوں نے عبداللہ بن مسعود سے بیان کیا۔' WHERE id = 4724;
UPDATE hadiths SET urdu = 'ہم سے عبدان نے بیان کیا، کہا کہ مجھے میرے والد نے خبر دی، انہیں شعبہ نے، انہیں ابواسحاق نے اور ان سے براء بن عازب رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم کے ( مہاجر ) صحابہ میں سب سے پہلے ہمارے پاس مدینہ تشریف لانے والے مصعب بن عمیر اور ابن ام مکتوم رضی اللہ عنہما تھے۔ مدینہ پہنچ کر ان بزرگوں نے ہمیں قرآن مجید پڑھانا شروع کر دیا۔ پھر عمار، بلال اور سعد رضی اللہ عنہم آئے۔ اور عمر بن خطاب رضی اللہ عنہ بیس صحابہ کو ساتھ لے کر آئے اس کے بعد نبی کریم صلی اللہ علیہ وسلم تشریف لائے میں نے کبھی مدینہ والوں کو اتنا خوش ہونے والا نہیں دیکھا تھا، جتنا وہ نبی کریم صلی اللہ علیہ وسلم کی آمد پر خوش ہوئے تھے۔ بچیاں اور بچے بھی کہنے لگے تھے کہ آپ اللہ کے رسول ہیں، ہمارے یہاں تشریف لائے ہیں۔ میں نے نبی کریم صلی اللہ علیہ وسلم کی مدینہ میں تشریف آوری سے پہلے ہی «سبح اسم ربك الأعلى‏» اور اس جیسی اور سورتیں پڑھ لی تھیں۔' WHERE id = 4735;
UPDATE hadiths SET urdu = 'ہم سے محمد بن بشار نے بیان کیا، کہا ہم سے محمد بن جعفر غندر نے، کہا ہم سے شعبہ نے، ان سے اسود بن قیس نے بیان کیا کہ میں نے جندب بجلی رضی اللہ عنہ سے سنا کہ ایک عورت ام المؤمنین خدیجہ رضی اللہ عنہا نے کہا کہ یا رسول اللہ! میں دیکھتی ہوں کہ آپ کے دوست ( جبرائیل علیہ السلام ) آپ کے پاس آنے میں دیر کرتے ہیں۔ اس پر آیت نازل ہوئی «ما ودعك ربك وما قلى‏» یعنی ”آپ کے پروردگار نے نہ آپ کو چھوڑا ہے اور نہ آپ سے وہ بیزار ہوا ہے۔“' WHERE id = 4746;
UPDATE hadiths SET urdu = 'ہم سے احمد بن ابی داؤد ابو جعفر منادی نے بیان کیا، کہا ہم سے روح نے بیان کیا، کہا ہم سے سعید بن ابی عروبہ نے، ان سے قتادہ نے اور ان سے انس بن مالک رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے ابی بن کعب سے فرمایا کہ اللہ تعالیٰ نے مجھے حکم دیا ہے کہ تمہیں قرآن کی ( سورۃ لم یکن ) پڑھ کر سناؤں۔ انہوں نے پوچھا کیا اللہ نے آپ سے میرا نام بھی لیا ہے؟ آپ صلی اللہ علیہ وسلم نے فرمایا کہ ہاں۔ ابی بن کعب رضی اللہ عنہ بولے تمام جہانوں کے پالنے والے کے ہاں میرا ذکر ہوا؟ آپ صلی اللہ علیہ وسلم نے فرمایا کہ ہاں اس پر ان کی آنکھوں سے آنسو نکل پڑے۔' WHERE id = 4756;
UPDATE hadiths SET urdu = 'ہم سے یوسف بن موسیٰ نے بیان کیا، کہا ہم سے ابواسامہ نے بیان کیا، کہا ہم سے اعمش نے بیان کیا، ان سے عمرو بن مرہ نے بیان کیا، ان سے سعید بن جبیر نے اور ان سے ابن عباس رضی اللہ عنہما نے بیان کیا کہ جب یہ آیت نازل ہوئی «وأنذر عشيرتك الأقربين‏» ”آپ اپنے قریبی رشتہ داروں کو ڈرایئے اور اپنے گروہ کے ان لوگوں کو ڈرائیے جو مخلصین ہیں۔“ تو رسول اللہ صلی اللہ علیہ وسلم صفا پہاڑی پر چڑھ گئے اور پکارا: یاصباحاہ! قریش نے کہا یہ کون ہے، پھر وہاں سب آ کر جمع ہو گئے۔ نبی کریم صلی اللہ علیہ وسلم نے ان سے فرمایا کہ تمہارا کیا خیال ہے، اگر میں تمہیں بتاؤں کہ ایک لشکر اس پہاڑ کے پیچھے سے آنے والا ہے، تو کیا تم مجھ کو سچا نہیں سمجھو گے؟ انہوں نے کہا کہ ہمیں جھوٹ کا آپ سے تجربہ کبھی بھی نہیں ہے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ پھر میں تمہیں اس سخت عذاب سے ڈراتا ہوں جو تمہارے سامنے آ رہا ہے۔ یہ سن کر ابولہب بولا، تو تباہ ہو، کیا تو نے ہمیں اسی لیے جمع کیا تھا؟ پھر نبی کریم صلی اللہ علیہ وسلم وہاں سے چلے آئے اور آپ پر یہ سورت نازل ہوئی «تبت يدا أبي لهب وتب‏» الخ یعنی ”دونوں ہاتھ ٹوٹ گئے ابولہب کے اور وہ برباد ہو گیا۔“ اعمش نے یوں پڑھا «وقد تب» جس دن یہ حدیث روایت کی۔' WHERE id = 4766;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم نے بیان کیا، کہا ہم سے سفیان ثوری نے بیان کیا، ان سے اسود بن قیس نے، کہا کہ میں نے جندب بن عبداللہ بجلی رضی اللہ عنہ سے سنا، انہوں نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم بیمار پڑے اور ایک یا دو راتوں میں ( تہجد کی نماز کے لیے ) نہ اٹھ سکے تو ایک عورت ( عوراء بنت رب ابولہب کی جورو ) نبی کریم صلی اللہ علیہ وسلم کے پاس آئی اور کہنے لگی محمد! میرا خیال ہے کہ تمہارے شیطان نے تمہیں چھوڑ دیا ہے۔ اس پر اللہ تعالیٰ نے یہ آیت نازل کی «والضحى * والليل إذا سجى * ما ودعك ربك وما قلى‏» ”قسم ہے دن کی روشنی کی اور رات کی جب وہ قرار پکڑے کہ آپ کے پروردگار نے نہ آپ کو چھوڑ ا ہے اور نہ وہ آپ سے خفا ہوا ہے۔“' WHERE id = 4777;
UPDATE hadiths SET urdu = 'ہم سے ابراہیم بن موسیٰ نے بیان کیا، کہا ہم کو ہشام بن یوسف نے خبر دی، انہیں ابن جریج نے خبر دی، ان سے کیسان نے کہا کہ مجھے یوسف بن ماہک نے خبر دی، انہوں نے بیان کیا کہ میں ام المؤمنین عائشہ رضی اللہ عنہا کی خدمت میں حاضر تھا کہ ایک عراقی ان کے پاس آیا اور پوچھا کہ کفن کیسا ہونا چاہئے؟ ام المؤمنین نے کہا: افسوس اس سے مطلب! کسی طرح کا بھی کفن ہو تجھے کیا نقصان ہو گا۔ پھر اس شخص نے کہا ام المؤمنین مجھے اپنے مصحف دکھا دیجئیے۔ انہوں نے کہا کیوں؟ ( کیا ضرورت ہے ) اس نے کہا تاکہ میں بھی قرآن مجید اس ترتیب کے مطابق پڑھوں کیونکہ لوگ بغیر ترتیب کے پڑھتے ہیں۔ انہوں نے کہا پھر اس میں کیا قباحت ہے جونسی سورت تو چاہے پہلے پڑھ لے ( جونسی سورت چاہے بعد میں پڑھ لے اگر اترنے کی ترتیب دیکھتا ہے ) تو پہلے مفصل کی ایک سورت، اتری ( «اقرا باسم ربك» ) جس میں جنت و دوزخ کا ذکر ہے۔ جب لوگوں کا دل اسلام کی طرف رجوع ہو گیا ( اعتقاد پختہ ہو گئے ) اس کے بعد حلال و حرام کے احکام اترے، اگر کہیں شروع شروع ہی میں یہ اترتا کہ شراب نہ پینا تو لوگ کہتے ہم تو کبھی شراب پینا نہیں چھوڑیں گے۔ اگر شروع ہی میں یہ اترتا کہ زنا نہ کرو تو لوگ کہتے ہم تو زنا نہیں چھوڑیں گے اس کے بجائے مکہ میں محمد صلی اللہ علیہ وسلم پر اس وقت جب میں بچی تھی اور کھیلا کرتی تھی یہ آیت نازل ہوئی «بل الساعة موعدهم والساعة أدهى وأمر‏» لیکن سورۃ البقرہ اور سورۃ نساء اس وقت نازل ہوئیں، جب میں ( مدینہ میں ) نبی کریم صلی اللہ علیہ وسلم کے پاس تھی۔ بیان کیا کہ پھر انہوں نے اس عراقی کے لیے اپنا مصحف نکالا اور ہر سورت کی آیات کی تفصیل لکھوائی۔' WHERE id = 4787;
UPDATE hadiths SET urdu = 'ہم سے حفص بن عمر بن غیاث نے بیان کیا، کہا ہم سے ہمام بن یحییٰ نے بیان کیا، کہا ہم سے قتادہ نے بیان کیا، کہا کہ میں نے انس بن مالک رضی اللہ عنہ سے پوچھا کہ رسول اللہ صلی اللہ علیہ وسلم کے زمانہ میں قرآن کو کن لوگوں نے جمع کیا تھا، انہوں نے بتلایا کہ چار صحابیوں نے، یہ چاروں قبیلہ انصار سے ہیں۔ ابی بن کعب، معاذ بن جبل، زید بن ثابت اور ابوزید۔ اس روایت کی متابعت فضل نے حسین بن واقد سے کی ہے۔ ان سے ثمامہ نے اور ان سے انس رضی اللہ عنہ نے۔' WHERE id = 4797;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف تنیسی نے بیان کیا، کہا ہم کو امام مالک نے خبر دی، انہیں عبدالرحمٰن بن عبداللہ بن عبدالرحمٰن بن ابی صعصعہ نے، انہیں ان کے والد عبداللہ نے اور انہیں ابو سعید خدری رضی اللہ عنہ نے کہ ایک صحابی ( خود ابو سعید خدری ) نے ایک دوسرے صحابی ( قتادہ بن نعمان رضی اللہ عنہ ) اپنے ماں جائے بھائی کو دیکھا کہ وہ رات کو سورۃ «قل هو الله أحد‏» باربار پڑھ رہے ہیں۔ صبح ہوئی تو وہ صحابی ( ابوسعید رضی اللہ عنہ ) رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئے اور نبی کریم صلی اللہ علیہ وسلم سے اس کا ذکر کیا گویا انہوں نے سمجھا کہ اس میں کوئی بڑا ثواب نہ ہو گا۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اس ذات کی قسم جس کے ہاتھ میں میری جان ہے! یہ سورت قرآن مجید کے ایک تہائی حصہ کے برابر ہے۔' WHERE id = 4807;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، کہا کہ مجھ سے لیث بن سعد نے، ان سے عقیل نے، ان سے شہاب نے بیان کیا، کہا کہ مجھ کو ابوسلمہ بن عبدالرحمٰن نے خبر دی اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ اللہ نے کوئی چیز اتنی توجہ سے نہیں سنی جتنی توجہ سے اس نے نبی کریم صلی اللہ علیہ وسلم کا قرآن بہترین آواز کے ساتھ پڑھتے ہوئے سنا ہے۔ ابوسلمہ بن عبدالرحمٰن کا ایک دوست عبدالحمید بن عبدالرحمٰن کہتا تھا کہ اس حدیث میں «يتغنى بالقرآن» سے یہ مراد ہے کہ اچھی آواز سے اسے پکار کر پڑھے۔' WHERE id = 4817;
UPDATE hadiths SET urdu = 'ہم سے محمد بن علاء نے بیان کیا، کہا ہم سے ابواسامہ نے بیان کیا، ان سے برید نے، ان سے ابوبردہ نے اور ان سے ابوموسیٰ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”قرآن مجید کا پڑھتے رہنا لازم پکڑ لو“ اس ذات کی قسم جس کے ہاتھ میں میری جان ہے وہ اونٹ کے اپنی رسی تڑوا کر بھاگ جانے سے زیادہ تیزی سے بھاگتا ہے۔' WHERE id = 4828;
UPDATE hadiths SET urdu = 'ہم سے ابوالنعمان نے بیان کیا، کہا ہم سے مہدی بن میمون نے، کہا ہم سے واصل احدب نے، ان سے ابووائل نے عبداللہ بن مسعود رضی اللہ عنہ سے بیان کیا کہ ہم ان کی خدمت میں صبح سویرے حاضر ہوئے۔ حاضرین میں سے ایک صاحب نے کہا کہ رات میں نے ( تمام ) مفصل سورتیں پڑھ ڈالیں۔ اس پر عبداللہ بن مسعود رضی اللہ عنہ بولے جیسے اشعار جلدی جلدی پڑھتے ہیں تم نے ویسے ہی پڑھ لی ہو گی۔ ہم سے قرآت سنی ہے اور مجھے وہ جوڑ والی سورتیں بھی یاد ہیں جن کو ملا کر نمازوں میں نبی کریم صلی اللہ علیہ وسلم پڑھا کرتے تھے۔ یہ اٹھارہ سورتیں مفصل کی ہیں اور وہ دو سورتیں جن کے شروع میں «حم‏.‏» ہے۔' WHERE id = 4839;
UPDATE hadiths SET urdu = 'ہم سے سعد بن حفص نے بیان کیا، کہا ہم سے شیبان نے بیان کیا، ان سے یحییٰ بن ابی کثیر نے، ان سے محمد بن عبدالرحمٰن نے، ان سے ابوسلمہ بن عبدالرحمٰن بن عوف نے اور ان سے عبداللہ بن عمرو بن عاص رضی اللہ عنہما نے بیان کیا کہ مجھ سے رسول اللہ صلی اللہ علیہ وسلم نے دریافت فرمایا کہ قرآن مجید تم کتنے دن میں ختم کر لیتے ہو؟' WHERE id = 4850;
UPDATE hadiths SET urdu = 'ہم سے سعید بن ابی مریم نے بیان کیا، کہا ہم کو محمد بن جعفر نے خبر دی، کہا ہم کو حمید بن ابی حمید طویل نے خبر دی، انہوں نے انس بن مالک سے سنا، انہوں نے بیان کیا کہ تین حضرات ( علی بن ابی طالب، عبداللہ بن عمرو بن العاص اور عثمان بن مظعون رضی اللہ عنہم ) نبی کریم صلی اللہ علیہ وسلم کی ازواج مطہرات کے گھروں کی طرف آپ کی عبادت کے متعلق پوچھنے آئے، جب انہیں نبی کریم صلی اللہ علیہ وسلم کا عمل بتایا گیا تو جیسے انہوں نے اسے کم سمجھا اور کہا کہ ہمارا نبی کریم صلی اللہ علیہ وسلم سے کیا مقابلہ! آپ کی تو تمام اگلی پچھلی لغزشیں معاف کر دی گئی ہیں۔ ان میں سے ایک نے کہا کہ آج سے میں ہمیشہ رات بھر نماز پڑھا کروں گا۔ دوسرے نے کہا کہ میں ہمیشہ روزے سے رہوں گا اور کبھی ناغہ نہیں ہونے دوں گا۔ تیسرے نے کہا کہ میں عورتوں سے جدائی اختیار کر لوں گا اور کبھی نکاح نہیں کروں گا۔ پھر نبی کریم صلی اللہ علیہ وسلم تشریف لائے اور ان سے پوچھا کیا تم نے ہی یہ باتیں کہی ہیں؟ سن لو! اللہ تعالیٰ کی قسم! اللہ رب العالمین سے میں تم سب سے زیادہ ڈرنے والا ہوں۔ میں تم میں سب سے زیادہ پرہیزگار ہوں لیکن میں اگر روزے رکھتا ہوں تو افطار بھی کرتا ہوں۔ نماز پڑھتا ہوں ( رات میں ) اور سوتا بھی ہوں اور میں عورتوں سے نکاح کرتا ہوں۔ «فمن رغب عن سنتي فليس مني» میرے طریقے سے جس نے بے رغبتی کی وہ مجھ میں سے نہیں ہے۔' WHERE id = 4860;
UPDATE hadiths SET urdu = 'ہم سے احمد بن یونس نے بیان کیا، کہا ہم سے ابراہیم بن سعد نے بیان کیا، کہا ہم کو ابن شہاب نے خبر دی، انہوں نے سعید بن مسیب سے سنا، وہ کہتے ہیں کہ میں نے سعد بن ابی وقاص رضی اللہ عنہ سے سنا، انہوں نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے «تبتل» یعنی عورتوں سے الگ رہنے کی زندگی سے منع فرمایا تھا۔ اگر نبی کریم صلی اللہ علیہ وسلم انہیں اجازت دے دیتے تو ہم تو خصی ہی ہو جاتے۔' WHERE id = 4870;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسمٰعیل نے بیان کیا، کہا ہم سے عبدالوحد بن زیاد نے، کہا ہم سے صالح بن صالح ہمدانی نے، کہا ہم سے عامر شعبی نے، کہا کہ مجھ سے ابوبردہ نے بیان کیا اپنے والد سے، انہوں نے کہا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ جس شخص کے پاس لونڈی ہو وہ اسے تعلیم دے اور خوب اچھی طرح دے، اسے ادب سکھائے اور پوری کوشش اور محنت کے ساتھ سکھائے اور اس کے بعد اسے آزاد کر کے اس سے شادی کر لے تو اسے دہرا ثواب ملتا ہے اور اہل کتاب میں سے جو شخص بھی اپنے نبی پر ایمان رکھتا ہو اور مجھ پر ایمان لائے تو اسے دوہرا ثواب ملتا ہے اور جو غلام اپنے آقا کے حقوق بھی ادا کرتا ہے اور اپنے رب کے حقوق بھی ادا کرتا ہے اسے دہرا ثواب ملتا ہے۔ عامر شعبی نے ( اپنے شاگرد سے اس حدیث کو سنانے کے بعد کہا کہ بغیر کسی مشقت اور محنت کے اسے سیکھ لو۔ اس سے پہلے طالب علموں کو اس حدیث سے کم کے لیے بھی مدینہ تک کا سفر کرنا پڑتا تھا۔ اور ابوبکر نے بیان کیا ابوحصین سے، اس نے ابوبردہ سے، اس نے اپنے والد سے اور انہوں نے نبی کریم صلی اللہ علیہ وسلم سے کہ اس شخص نے باندی کو ( نکاح کرنے کے لیے ) آزاد کر دیا اور یہی آزادی اس کا مہر مقرر کی۔' WHERE id = 4880;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل بن ابی اویس نے بیان کیا، کہا کہ مجھ سے امام مالک نے بیان کیا، ان سے ابن شہاب نے، ان سے عبداللہ بن عمر رضی اللہ عنہما کے صاحبزادے حمزہ اور سالم نے اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ نحوست عورت میں، گھر میں اور گھوڑے میں ہو سکتی ہے ( نحوست بےبرکتی اگر ہو تو ان میں ہو سکتی ہے ) ۔' WHERE id = 4890;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، کہا ہم کو امام مالک نے خبر دی، انہیں ابن شہاب نے، انہیں عروہ بن زبیر نے، اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ ابوقعیس کے بھائی افلح نے ان کے یہاں اندر آنے کی اجازت چاہی۔ وہ عائشہ رضی اللہ عنہا کے رضاعی چچا تھے ( یہ واقعہ پردہ کا حکم نازل ہونے کے بعد کا ہے عائشہ رضی اللہ عنہا نے بیان کیا کہ ) میں نے انہیں اندر آنے کی اجازت نہیں دی پھر جب رسول اللہ صلی اللہ علیہ وسلم تشریف لائے تو میں نے آپ صلی اللہ علیہ وسلم کو ان کے ساتھ اپنے معاملے کو بتایا، نبی کریم صلی اللہ علیہ وسلم نے مجھے حکم دیا کہ میں انہیں اندر آنے کی اجازت دے دوں۔' WHERE id = 4900;
UPDATE hadiths SET urdu = 'ہم سے مالک بن اسماعیل نے بیان کیا، انہوں نے کہا ہم سے سفیان بن عیینہ نے بیان کیا، انہوں نے زہری سے سنا، وہ بیان کرتے تھے کہ مجھے حسن بن محمد بن علی اور ان کے بھائی عبداللہ بن محمد بن علی نے اپنے والد (محمد بن الحنفیہ) سے خبر دی کہ علی رضی اللہ عنہ نے عبداللہ بن عباس رضی اللہ عنہما سے کہا کہ نبی کریم صلی اللہ علیہ وسلم نے متعہ اور پالتو گدھے کے گوشت سے جنگ خیبر کے زمانہ میں منع فرمایا تھا۔' WHERE id = 4911;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن سلیمان نے بیان کیا، کہا ہم سے عبداللہ بن وہب نے بیان کیا، ان سے یونس نے (دوسری سند) امام بخاری رحمہ اللہ نے کہا ہم سے احمد بن صالح نے بیان کیا، کہا ہم سے عنبسہ بن خالد نے بیان کیا، کہا ہم سے یونس نے بیان کیا، ان سے ابن شہاب نے، کہا کہ مجھے عروہ بن زبیر نے خبر دی اور انہیں نبی کریم صلی اللہ علیہ وسلم کی زوجہ مطہرہ عائشہ رضی اللہ عنہا نے خبر دی کہ زمانہ جاہلیت میں نکاح چار طرح ہوتے تھے۔ ایک صورت تو یہی تھی جیسے آج کل لوگ کرتے ہیں، ایک شخص دوسرے شخص کے پاس اس کی زیر پرورش لڑکی یا اس کی بیٹی کے نکاح کا پیغام بھیجتا اور اس کا مہر دے کر اس سے نکاح کر لیتا۔ دوسرا نکاح یہ تھا کہ کوئی شوہر اپنی بیوی سے جب وہ حیض سے پاک ہو جاتی تو کہتا تو فلاں شخص کے پاس چلی جا اور اس سے منہ کالا کرا لے اس مدت میں شوہر اس سے جدا رہتا اور اسے چھوتا بھی نہیں۔ پھر جب اس غیر مرد سے اس کا حمل ظاہر ہو جاتا جس سے وہ عارضی طور پر صحبت کرتی رہتی، تو حمل کے ظاہر ہونے کے بعد اس کا شوہر اگر چاہتا تو اس سے صحبت کرتا۔ ایسا اس لیے کرتے تھے تاکہ ان کا لڑکا شریف اور عمدہ پیدا ہو۔ یہ نکاح ”استبضاع“ کہلاتا تھا۔ تیسری قسم نکاح کی یہ تھی کہ چند آدمی جو تعداد میں دس سے کم ہوتے کسی ایک عورت کے پاس آنا جانا رکھتے اور اس سے صحبت کرتے۔ پھر جب وہ عورت حاملہ ہوتی اور بچہ جنتی تو وضع حمل پر چند دن گزرنے کے بعد وہ عورت اپنے ان تمام مردوں کو بلاتی۔ اس موقع پر ان میں سے کوئی شخص انکار نہیں کر سکتا تھا۔ چنانچہ وہ سب اس عورت کے پاس جمع ہو جاتے اور وہ ان سے کہتی کہ جو تمہارا معاملہ تھا وہ تمہیں معلوم ہے اور اب میں نے یہ بچہ جنا ہے۔ پھر وہ کہتی کہ اے فلاں! یہ بچہ تمہارا ہے۔ وہ جس کا چاہتی نام لے دیتی اور وہ لڑکا اسی کا سمجھا جاتا، وہ شخص اس سے انکار کی جرات نہیں کر سکتا تھا۔ چوتھا نکاح اس طور پر تھا کہ بہت سے لوگ کسی عورت کے پاس آیا جایا کرتے تھے۔ عورت اپنے پاس کسی بھی آنے والے کو روکتی نہیں تھی۔ یہ کسبیاں ہوتی تھیں۔ اس طرح کی عورتیں اپنے دروازوں پر جھنڈے لگائے رہتی تھیں جو نشانی سمجھے جاتے تھے۔ جو بھی چاہتا ان کے پاس جاتا۔ اس طرح کی عورت جب حاملہ ہوتی اور بچہ جنتی تو اس کے پاس آنے جانے والے جمع ہوتے اور کسی قیافہ جاننے والے کو بلاتے اور بچہ کا ناک نقشہ جس سے ملتا جلتا ہوتا اس عورت کے اس لڑکے کو اسی کے ساتھ منسوب کر دیتے اور وہ بچہ اسی کا بیٹا کہا جاتا، اس سے کوئی انکار نہیں کرتا تھا۔ پھر جب محمد صلی اللہ علیہ وسلم حق کے ساتھ رسول ہو کر تشریف لائے آپ نے جاہلیت کے تمام نکاحوں کو باطل قرار دے دیا صرف اس نکاح کو باقی رکھا جس کا آج کل رواج ہے۔' WHERE id = 4922;
UPDATE hadiths SET urdu = 'ہم سے عمرو بن ربیع بن طارق نے بیان کیا، کہا کہ مجھے لیث بن سعد نے خبر دی، انہیں ابن ابی ملیکہ نے، انہیں عائشہ رضی اللہ عنہا کے غلام ابوعمرو ذکوان نے اور ان سے عائشہ رضی اللہ عنہا نے کہ انہوں نے عرض کیا: یا رسول اللہ! کنواری لڑکی ( کہتے ہوئے ) شرماتی ہے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اس کا خاموش ہو جانا ہی اس کی رضا مندی ہے۔' WHERE id = 4932;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ نے بیان کیا، کہا ہم سے سفیان نے، کہا میں نے ابوحازم سے سنا، وہ کہتے تھے کہ میں نے سہل بن سعد ساعدی سے سنا، انہوں نے بیان کیا کہ میں لوگوں کے ساتھ رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں حاضر تھا اس میں ایک خاتون کھڑی ہوئیں اور عرض کیا کہ یا رسول اللہ! میں اپنے آپ کو آپ کے لیے ہبہ کرتی ہوں آپ اب جو چاہیں کریں۔ نبی کریم صلی اللہ علیہ وسلم نے انہیں کوئی جواب نہیں دیا۔ وہ پھر کھڑی ہوئی اور عرض کیا کہ یا رسول اللہ! میں نے اپنے آپ کو آپ کے لیے ہبہ کر دیا ہے آپ جو چاہیں کریں۔ نبی کریم صلی اللہ علیہ وسلم نے اس مرتبہ بھی کوئی جواب نہیں دیا۔ وہ تیسری مرتبہ کھڑی ہوئیں اور کہا کہ انہوں نے اپنے آپ کو آپ صلی اللہ علیہ وسلم کے لیے ہبہ کر دیا، آپ جو چاہیں کریں۔ اس کے بعد ایک صحابی کھڑے ہوئے اور عرض کیا: یا رسول اللہ! ان کا نکاح مجھ سے کر دیجئیے۔ نبی کریم صلی اللہ علیہ وسلم نے ان سے دریافت فرمایا کہ تمہارے پاس کچھ ہے؟ انہوں نے عرض کیا کہ نہیں۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ جاؤ اور تلاش کرو ایک لوہے کی انگوٹھی بھی اگر مل جائے لے آؤ۔ وہ گئے اور تلاش کیا، پھر واپس آ کر عرض کیا کہ میں نے کچھ نہیں پایا، لوہے کی ایک انگوٹھی بھی نہیں ملی۔ نبی کریم صلی اللہ علیہ وسلم نے دریافت فرمایا کہ تمہارے پاس کچھ قرآن ہے؟ انہوں نے عرض کیا کہ جی ہاں۔ میرے پاس فلاں فلاں سورتیں ہیں نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ پھر جاؤ میں نے تمہارا نکاح ان سے اس قرآن پر کیا جو تم کو یاد ہے۔' WHERE id = 4943;
UPDATE hadiths SET urdu = 'ہم سے محمد بن سلام نے بیان کیا، کہا ہم سے اسماعیل بن جعفر نے خبر دی، انہیں حمید نے اور ان سے انس رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے مدینہ اور خیبر کے درمیان ( راستہ میں ) تین دن تک قیام کیا اور وہاں ام المؤمنین صفیہ بنت حیی رضی اللہ عنہا کے ساتھ خلوت کی۔ میں نے مسلمانوں کو نبی کریم صلی اللہ علیہ وسلم کے ولیمہ پر بلایا لیکن اس دعوت میں روٹی اور گوشت نہیں تھا۔ آپ نے دستر خوان بچھانے کا حکم دیا اور اس پر کھجور، پنیر اور گھی رکھ دیا گیا اور یہی نبی کریم صلی اللہ علیہ وسلم کا ولیمہ تھا۔ مسلمانوں نے صفیہ رضی اللہ عنہا کے بارے میں ( کہا کہ ) امہات المؤمنین میں سے ہیں یا نبی کریم صلی اللہ علیہ وسلم نے انہیں لونڈی ہی رکھا ہے ( کیونکہ وہ بھی جنگ خیبر کے قیدیوں میں سے تھیں۔ اس پر بعض نے کہا کہ اگر آپ صلی اللہ علیہ وسلم ان کے لیے پردہ کرائیں پھر تو وہ امہات المؤمنین میں سے ہیں اور اگر آپ ان کے لیے پردہ نہ کرائیں تو پھر وہ لونڈی کی حیثیت سے ہیں۔ جب سفر ہوا تو نبی کریم صلی اللہ علیہ وسلم نے ان کے لیے اپنی سواری پر پیچھے جگہ بنائی اور لوگوں کے اور ان کے درمیان پردہ ڈلوایا۔)' WHERE id = 4953;
UPDATE hadiths SET urdu = 'ہم سے مسدد بن مسرہد نے بیان کیا، ان سے عبدالوارث نے بیان کیا، ان سے شعیب نے اور ان سے انس رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے صفیہ رضی اللہ عنہا کو آزاد کیا اور پھر ان سے نکاح کیا اور ان کی آزادی کو ان کا مہر قرار دیا اور ان کا ولیمہ ملیدہ سے کیا۔' WHERE id = 4963;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ بن ابراہیم نے بیان کیا، انہوں نے کہا ہم سے حجاج بن محمد اعور نے بیان کیا، انہوں نے کہا کہ ابن جریج نے کہا کہ مجھ کو موسیٰ بن عقبہ نے خبر دی، انہیں نافع نے، انہوں نے کہا کہ میں نے عبداللہ بن عمر رضی اللہ عنہما سے سنا، انہوں نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ اس ولیمہ کی جب تمہیں دعوت دی جائے تو قبول کرو۔ بیان کیا کہ عبداللہ بن عمر رضی اللہ عنہما اگر روزے سے ہوتے جب بھی ولیمہ کی دعوت یا کسی دوسری دعوت میں شرکت کرتے تھے۔' WHERE id = 4973;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، کہا ہم کو شعیب نے خبر دی، انہیں زہری نے، کہا کہ مجھے عبیداللہ بن عبداللہ بن ابی ثور نے خبر دی اور ان سے عبداللہ بن عباس رضی اللہ عنہما نے بیان کیا کہ بہت دنوں تک میرے دل میں خواہش رہی کہ میں عمر بن خطاب رضی اللہ عنہ سے نبی کریم صلی اللہ علیہ وسلم کی ان دو بیویوں کے متعلق پوچھوں جن کے بارے میں اللہ نے یہ آیت نازل کی تھی۔ «إن تتوبا إلى الله فقد صغت قلوبكما‏» الخ۔ ایک مرتبہ انہوں نے حج کیا اور ان کے ساتھ میں نے بھی حج کیا۔ ایک جگہ جب وہ راستہ سے ہٹ کر ( قضائے حاجت کے لیے ) گئے تو میں بھی ایک برتن میں پانی لے کر ان کے ساتھ راستہ سے ہٹ گیا۔ پھر انہوں نے قضائے حاجت کی اور واپس آئے تو میں نے ان کے ہاتھوں پر پانی ڈالا۔ پھر انہوں نے وضو کیا تو میں نے اس وقت ان سے پوچھا کہ یا امیرالمؤمنین! نبی کریم صلی اللہ علیہ وسلم کی بیویوں میں وہ کون ہیں جن کے متعلق اللہ نے یہ ارشاد فرمایا کہ «إن تتوبا إلى الله فقد صغت قلوبكما‏» عمر بن خطاب رضی اللہ عنہ نے اس پر کہا اے ابن عباس! تم پر حیرت ہے۔ وہ عائشہ رضی اللہ عنہا اور حفصہ رضی اللہ عنہا ہیں پھر عمر رضی اللہ عنہ نے تفصیل کے ساتھ حدیث بیان کرنی شروع کی۔ انہوں نے کہا کہ میں اور میرے ایک انصاری پڑوسی جو بنو امیہ بن زید سے تھے اور عوالی مدینہ میں رہتے تھے۔ ہم نے ( عوالی سے ) رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں حاضر ہونے کے لیے باری مقرر کر رکھی تھی۔ ایک دن وہ حاضری دیتے اور ایک دن میں حاضری دیتا، جب میں حاضر ہوتا تو اس دن کی تمام خبریں جو وحی وغیرہ سے متعلق ہوتیں لاتا ( اور اپنے پڑوسی سے بیان کرتا ) اور جس دن وہ حاضر ہوتے تو وہ بھی ایسے کرتے۔ ہم قریشی لوگ اپنی عورتوں پر غالب تھے لیکن جب ہم مدینہ تشریف لائے تو یہ لوگ ایسے تھے کہ عورتوں سے مغلوب تھے، ہماری عورتوں نے بھی انصار کی عورتوں کا طریقہ سیکھنا شروع کر دیا۔ ایک دن میں نے اپنی بیوی کو ڈانٹا تو اس نے بھی میرا ترکی بہ ترکی جواب دیا۔ میں نے اس کے اس طرح جواب دینے پر ناگواری کا اظہار کیا تو اس نے کہا کہ میرا جواب دینا تمہیں برا کیوں لگتا ہے، اللہ کی قسم! نبی کریم صلی اللہ علیہ وسلم کی ازواج بھی ان کو جوابات دے دیتی ہیں اور بعض تو نبی کریم صلی اللہ علیہ وسلم سے ایک دن رات تک الگ رہتی ہیں۔ میں اس بات پر کانپ اٹھا اور کہا کہ ان میں سے جس نے بھی یہ معاملہ کیا یقیناً وہ نامراد ہو گئی۔ پھر میں نے اپنے کپڑے پہنے اور ( مدینہ کے لیے ) روانہ ہوا پھر میں حفصہ کے گھر گیا اور میں نے اس سے کہا: اے حفصہ! کیا تم میں سے کوئی بھی نبی کریم صلی اللہ علیہ وسلم سے ایک ایک دن رات تک غصہ رہتی ہے؟ انہوں نے کہا کہ جی ہاں کبھی ( ایسا ہو جاتا ہے ) میں نے اس پر کہا کہ پھر تم نے اپنے آپ کو خسارہ میں ڈال لیا اور نامراد ہوئی۔ کیا تمہیں اس کا کوئی ڈر نہیں کہ نبی کریم صلی اللہ علیہ وسلم کے غصہ کی وجہ سے اللہ تم پر غصہ ہو جائے اور پھر تم تنہا ہی ہو جاؤ گی۔ خبردار! نبی کریم صلی اللہ علیہ وسلم سے مطالبات نہ کیا کرو نہ کسی معاملہ میں نبی کریم صلی اللہ علیہ وسلم کو جواب دیا کرو اور نہ نبی کریم صلی اللہ علیہ وسلم کو چھوڑا کرو۔ اگر تمہیں کوئی ضرورت ہو تو مجھ سے مانگ لیا کرو۔ تمہاری سوکن جو تم سے زیادہ خوبصورت ہے اور نبی کریم صلی اللہ علیہ وسلم کو تم سے زیادہ پیاری ہے، ان کی وجہ سے تم کسی غلط فہمی میں نہ مبتلا ہو جانا۔ ان کا اشارہ عائشہ رضی اللہ عنہا کی طرف تھا۔ عمر رضی اللہ عنہ نے بیان کیا کہ ہمیں معلوم ہوا تھا کہ ملک غسان ہم پر حملہ کے لیے فوجی تیاریاں کر رہا ہے۔ میرے انصاری ساتھی اپنی باری پر مدینہ منورہ گئے ہوئے تھے۔ وہ رات گئے واپس آئے اور میرے دروازے پر بڑی زور زور سے دستک دی اور کہا کہ کیا عمر رضی اللہ عنہ گھر میں ہیں۔ میں گھبرا کر باہر نکلا تو انہوں نے کہا کہ آج تو بڑا حادثہ ہو گیا۔ میں نے کہا کیا بات ہوئی، کیا غسانی چڑھ آئے ہیں؟ انہوں نے کہا کہ نہیں، حادثہ اس سے بھی بڑا اور اس سے بھی زیادہ خوفناک ہے۔ نبی کریم صلی اللہ علیہ وسلم نے ازواج مطہرات کو طلاق دے دی ہے۔ میں نے کہا کہ حفصہ تو خاسر و نامراد ہوئی۔ مجھے تو اس کا خطرہ لگا ہی رہتا تھا کہ اس طرح کا کوئی حادثہ جلد ہی ہو گا پھر میں نے اپنے تمام کپڑے پہنے ( اور مدینہ کے لیے روانہ ہو گیا ) میں نے فجر کی نماز نبی کریم صلی اللہ علیہ وسلم کے ساتھ پڑھی ( نماز کے بعد ) نبی کریم صلی اللہ علیہ وسلم اپنے ایک بالا خانہ میں چلے گئے اور وہاں تنہائی اختیار کر لی۔ میں حفصہ کے پاس گیا تو وہ رو رہی تھی۔ میں نے کہا اب روتی کیا ہو۔ میں نے تمہیں پہلے ہی متنبہ کر دیا تھا۔ کیا نبی کریم صلی اللہ علیہ وسلم نے تمہیں طلاق دے دی ہے؟ انہوں نے کہا کہ مجھے معلوم نہیں۔ نبی کریم صلی اللہ علیہ وسلم اس وقت بالا خانہ میں تنہا تشریف رکھتے ہیں۔ میں وہاں سے نکلا اور منبر کے پاس آیا۔ اس کے گرد کچھ صحابہ کرام موجود تھے اور ان میں سے بعض رو رہے تھے۔ تھوڑی دیر تک میں ان کے ساتھ بیٹھا رہا۔ اس کے بعد میرا غم مجھ پر غالب آ گیا اور میں اس بالا خانہ کے پاس آیا۔ جہاں نبی کریم صلی اللہ علیہ وسلم تشریف رکھتے تھے۔ میں نے نبی کریم صلی اللہ علیہ وسلم کے ایک حبشی غلام سے کہا کہ عمر رضی اللہ عنہ کے لیے اندر آنے کی اجازت لے لو۔ غلام اندر گیا اور نبی کریم صلی اللہ علیہ وسلم سے گفتگو کر کے واپس آ گیا۔ اس نے مجھ سے کہا کہ میں نے نبی کریم صلی اللہ علیہ وسلم سے عرض کی اور نبی کریم صلی اللہ علیہ وسلم سے آپ کا ذکر کیا لیکن آپ خاموش رہے۔ چنانچہ میں واپس چلا آیا اور پھر ان لوگوں کے ساتھ بیٹھ گیا جو منبر کے پاس موجود تھے۔ میرا غم مجھ پر غالب آیا اور دوبارہ آ کر میں نے غلام سے کہا کہ عمر کے لیے اجازت لے لو۔ اس غلام نے واپس آ کر پھر کہا کہ میں نے نبی کریم صلی اللہ علیہ وسلم کے سامنے آپ کا ذکر کیا تو نبی کریم صلی اللہ علیہ وسلم خاموش رہے۔ میں پھر واپس آ گیا اور منبر کے پاس جو لوگ موجود تھے ان کے ساتھ بیٹھ گیا۔ لیکن میرا غم مجھ پر غالب آیا اور میں نے پھر آ کر غلام سے کہا کہ عمر کے لیے اجازت طلب کرو۔ غلام اندر گیا اور واپس آ کر جواب دیا کہ میں نے آپ کا ذکر نبی کریم صلی اللہ علیہ وسلم سے کیا اور نبی کریم صلی اللہ علیہ وسلم خاموش رہے۔ میں وہاں سے واپس آ رہا تھا کہ غلام نے مجھ کو پکارا اور کہا نبی کریم صلی اللہ علیہ وسلم نے تمہیں اجازت دے دی ہے۔ میں نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوا تو آپ اس بان کی چارپائی پر جس سے چٹائی بنی جاتی ہے لیٹے ہوئے تھے۔ اس پر کوئی بستر نہیں تھا۔ بان کے نشانات آپ کے پہلو مبارک پر پڑے ہوئے تھے۔ جس تکیہ پر آپ ٹیک لگائے ہوئے تھے اس میں چھال بھری ہوئی تھی۔ میں نے نبی کریم صلی اللہ علیہ وسلم کو سلام کیا اور کھڑے ہی کھڑے عرض کیا: یا رسول اللہ! کیا آپ نے اپنی ازواج کو طلاق دے دی ہے؟ نبی کریم صلی اللہ علیہ وسلم نے میری طرف نگاہ اٹھائی اور فرمایا نہیں۔ میں ( خوشی کی وجہ سے ) کہہ اٹھا۔ اللہ اکبر۔ پھر میں نے کھڑے ہی کھڑے نبی کریم صلی اللہ علیہ وسلم کو خوش کرنے کے لیے کہا کہ یا رسول اللہ! آپ کو معلوم ہے ہم قریش کے لوگ عورتوں پر غالب رہا کرتے تھے۔ پھر جب ہم مدینہ آئے تو یہاں کے لوگوں پر ان کی عورتیں غالب تھیں۔ نبی کریم صلی اللہ علیہ وسلم اس پر مسکرا دیئے۔ پھر میں نے عرض کیا: یا رسول اللہ! آپ کو معلوم ہے میں حفصہ کے پاس ایک مرتبہ گیا تھا اور اس سے کہہ آیا تھا کہ اپنی سوکن کی وجہ سے جو تم سے زیادہ خوبصورت اور تم سے زیادہ رسول اللہ صلی اللہ علیہ وسلم کو عزیز ہے، دھوکا میں مت رہنا۔ ان کا اشارہ عائشہ رضی اللہ عنہا کی طرف تھا۔ اس پر نبی کریم صلی اللہ علیہ وسلم دوبارہ مسکرا دیئے۔ میں نے نبی کریم صلی اللہ علیہ وسلم کو مسکراتے دیکھا تو بیٹھ گیا پھر نظر اٹھا کر میں نبی کریم صلی اللہ علیہ وسلم کے گھر کا جائزہ لیا۔ اللہ کی قسم! میں نے نبی کریم صلی اللہ علیہ وسلم کے گھر میں کوئی ایسی چیز نہیں دیکھی جس پر نظر رکتی۔ سوا تین چمڑوں کے ( جو وہاں موجود تھے ) میں نے عرض کیا: یا رسول اللہ! اللہ سے دعا فرمائیں کہ وہ آپ کی امت کو فراخی عطا فرمائے۔ فارس و روم کو فراخی اور وسعت حاصل ہے اور انہیں دنیا دی گئی ہے حالانکہ وہ اللہ کی عبادت نہیں کرتے۔ نبی کریم صلی اللہ علیہ وسلم ابھی تک ٹیک لگائے ہوئے تھے لیکن اب سیدھے بیٹھ گئے اور فرمایا: ابن خطاب! تمہاری نظر میں بھی یہ چیزیں اہمیت رکھتی ہیں، یہ تو وہ لوگ ہیں جنہیں جو کچھ بھلائی ملنے والی تھی سب اسی دنیا میں دے دی گئی ہے۔ میں نے عرض کیا: یا رسول اللہ! میرے لیے اللہ سے مغفرت کی دعا کر دیجئیے ( کہ میں نے دنیاوی شان و شوکت کے متعلق یہ غلط خیال دل میں رکھا ) چنانچہ نبی کریم صلی اللہ علیہ وسلم نے اپنی ازواج کو اسی وجہ سے انتیس دن تک الگ رکھا کہ حفصہ نے نبی کریم صلی اللہ علیہ وسلم کا راز عائشہ سے کہہ دیا تھا۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا تھا کہ ایک مہینہ تک میں اپنی ازواج کے پاس نہیں جاؤں گا۔ کیونکہ جب اللہ تعالیٰ نے نبی کریم صلی اللہ علیہ وسلم پر عتاب کیا تو نبی کریم صلی اللہ علیہ وسلم کو اس کا بہت رنج ہوا ( اور آپ نے ازواج سے الگ رہنے کا فیصلہ کیا ) پھر جب انتیسویں رات گزر گئی تو نبی کریم صلی اللہ علیہ وسلم عائشہ رضی اللہ عنہا کے گھر تشریف لے گئے اور آپ سے ابتداء کی۔ عائشہ رضی اللہ عنہا نے عرض کیا کہ یا رسول اللہ! آپ نے قسم کھائی تھی کہ ہمارے یہاں ایک مہینہ تک تشریف نہیں لائیں گے اور ابھی تو انتیس ہی دن گزرے ہیں میں تو ایک ایک دن گن رہی تھی۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ یہ مہینہ انتیس کا ہے۔ وہ مہینہ انتیس ہی کا تھا۔ عائشہ رضی اللہ عنہا نے بیان کیا کہ پھر اللہ تعالیٰ نے آیت «تخير» نازل کی اور نبی کریم صلی اللہ علیہ وسلم اپنی تمام ازواج میں سب سے پہلے میرے پاس تشریف لائے ( اور مجھ سے اللہ کی وحی کا ذکر کیا ) تو میں نے نبی کریم صلی اللہ علیہ وسلم کو ہی پسند کیا۔ اس کے بعد نبی کریم صلی اللہ علیہ وسلم نے اپنی تمام دوسری ازواج کو اختیار دیا اور سب نے وہی کہا جو عائشہ رضی اللہ عنہا کہہ چکی تھیں۔' WHERE id = 4984;
UPDATE hadiths SET urdu = 'ہم سے خالد بن مخلد نے بیان کیا، انہوں نے کہا ہم سے سلیمان نے بیان کیا، انہوں نے کہا کہ مجھ سے حمید نے بیان کیا اور ان سے انس رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم اپنی ازواج مطہرات سے ایک مہینہ تک الگ رہے اور اپنے ایک بالاخانہ میں قیام کیا۔ پھر آپ انتیس دن کے بعد گھر میں تشریف لائے تو کہا گیا کہ یا رسول اللہ! آپ نے تو ایک مہینہ کے لیے عہد کیا تھا نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ یہ مہینہ انتیس ( 29 ) کا ہے۔' WHERE id = 4994;
UPDATE hadiths SET urdu = 'ہم سے مسدد بن مسرہد نے بیان کیا، کہا ہم سے بشر بن مفضل نے، ان سے خالد حذاء نے، ان سے ابوقلابہ نے بیان کیا اور ان سے انس رضی اللہ عنہ نے (راوی ابوقلابہ یا انس رضی اللہ عنہ نے) کہا کہ اگر میں چاہوں تو کہہ سکتا ہوں کہ نبی کریم صلی اللہ علیہ وسلم نے ( آنے والی حدیث ) ارشاد فرمائی۔ لیکن بیان کیا کہ دستور یہ ہے کہ جب کنواری سے شادی کرے تو اس کے ساتھ سات دن تک رہنا چاہئے اور جب بیوہ سے شادی کرے تو اس کے ساتھ تین دن تک رہنا چاہئے۔' WHERE id = 5005;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم نے بیان کیا، کہا ہم سے شیبان بن عبدالرحمٰن نحوی نے بیان کیا، ان سے یحییٰ بن ابی کثیر نے، ان سے ابوسلمہ نے اور انہوں نے ابوہریرہ رضی اللہ عنہ سے سنا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اللہ تعالیٰ کو غیرت آتی ہے اور اللہ تعالیٰ کو غیرت اس وقت آتی ہے جب بندہ مومن وہ کام کرے جسے اللہ نے حرام کیا ہے۔' WHERE id = 5015;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ مدینی نے بیان کیا، کہ ہم سے سفیان بن عیینہ نے بیان کیا، ان سے عمرو بن دینار نے بیان کیا، ان سے ابو معبد نے اور ان سے عبداللہ بن عباس رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ محرم کے سوا کوئی مرد کسی عورت کے ساتھ تنہائی میں نہ بیٹھے۔ اس پر ایک صحابی نے عرض کیا: یا رسول اللہ! میری بیوی حج کرنے گئی ہے اور میرا نام فلاں غزوہ میں لکھا گیا ہے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ پھر تو واپس جا اور اپنی بیوی کے ساتھ حج کر۔' WHERE id = 5025;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، کہا ہم سے محارب بن دثار نے بیان کیا، کہا کہ میں نے جابر بن عبداللہ رضی اللہ عنہما سے سنا، انہوں نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم کسی شخص سے رات کے وقت اپنے گھر ( سفر سے اچانک ) آنے پر ناپسندیدگی کا اظہار فرماتے تھے۔' WHERE id = 5035;
UPDATE hadiths SET urdu = 'امام بخاری رحمہ اللہ نے کہا اور ابومعمر عبداللہ بن عمرو منقری نے کہا (یا ہم سے بیان کیا) کہا ہم سے عبدالوارث بن سعید نے، کہا ہم سے ایوب سختیانی نے، انہوں نے سعید بن جبیر سے، انہوں نے ابن عمر رضی اللہ عنہما سے، انہوں نے کہا یہ طلاق جو میں نے حیض میں دی تھی مجھ پر شمار کی گئی۔' WHERE id = 5045;
UPDATE hadiths SET urdu = 'ہم سے محمد بن سلام نے بیان کیا، کہا ہم سے ابومعاویہ نے بیان کیا، کہا ہم سے ہشام بن عروہ نے بیان کیا، ان سے ان کے والد نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ ایک شخص رفاعی نے اپنی بیوی ( تمیمہ بنت وہب ) کو طلاق دے دی، پھر ایک دوسرے شخص سے ان کی بیوی نے نکاح کیا لیکن انہوں نے بھی ان کو طلاق دے دی۔ ان دوسرے شوہر کے پاس کپڑے کے پلو کی طرح تھا۔ عورت کو اس سے پورا مزہ جیسا وہ چاہتی تھی نہیں ملا۔ آخر عبدالرحمٰن نے تھوڑے ہی دنوں رکھ کر اس کو طلاق دے دی۔ اب وہ عورت نبی کریم صلی اللہ علیہ وسلم کے پاس آئی اور عرض کیا کہ یا رسول اللہ! میرے شوہر نے مجھے طلاق دے دی تھی، پھر میں نے ایک دوسرے مرد سے نکاح کیا۔ وہ میرے پاس تنہائی میں آئے لیکن ان کے ساتھ تو کپڑے کے پلو کی طرح کے سوا اور کچھ نہیں ہے۔ کل ایک ہی بار اس نے مجھ سے صحبت کی وہ بھی بیکار ( دخول ہی نہیں ہوا اوپر ہی اوپر چھو کر رہ گیا ) کیا اب میں اپنے پہلے خاوند کے لیے حلال ہو گئی؟ آپ صلی اللہ علیہ وسلم نے فرمایا کہ تو اپنے پہلے خاوند کے لیے حلال نہیں ہو سکتی جب تک دوسرا خاوند تیری شیرینی نہ چکھے۔' WHERE id = 5057;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا، ان سے حماد بن یزید نے بیان کیا، ان سے ایوب سختیانی نے ان سے عکرمہ نے یہی قصہ ( مرسلاً ) نقل کیا اور اس میں خاتون کا نام جمیلہ آیا ہے۔' WHERE id = 5068;
UPDATE hadiths SET urdu = 'اور عطاء نے ابن عباس رضی اللہ عنہما سے بیان کیا کہ قریبہ بنت ابی امیہ عمر بن خطاب رضی اللہ عنہ کے نکاح میں تھیں، پھر عمر رضی اللہ عنہ نے ( مشرکین سے نکاح کی مخالفت کی آیت کے بعد ) انہیں طلاق دے دی تو معاویہ بن ابی سفیان رضی اللہ عنہما نے ان سے نکاح کر لیا اور ام الحکم بنت ابی سفیان عیاض بن غنم فہری کے نکاح میں تھیں، اس وقت اس نے انہیں طلاق دے دی ( اور وہ مدینہ ہجرت کر کے آ گئیں ) اور عبداللہ بن عثمان ثقفی نے ان سے نکاح کیا۔' WHERE id = 5078;
UPDATE hadiths SET urdu = 'اور لیث نے بیان کیا کہ ان سے جعفر بن ربیعہ نے بیان کیا، ان سے عبدالرحمٰن بن ہرمز نے، انہوں نے ابوہریرہ رضی اللہ عنہ سے سنا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ بخیل اور سخی کی مثال دو آدمیوں جیسی ہے جن پر لوہے کی دو زرہیں سینے سے گردن تک ہیں۔ سخی جب بھی کوئی چیز خرچ کرتا ہے تو زرہ اس کے چمڑے پر ڈھیلی ہو جاتی ہے اور اس کے پاؤں کی انگلیوں تک پہنچ جاتی ہے ( اور پھیل کر اتنی بڑھ جاتی ہے کہ ) اس کے نشان قدم کو مٹاتی چلتی ہے لیکن بخیل جب بھی خرچ کا ارادہ کرتا ہے تو اس کی زرہ کا ہر حلقہ اپنی اپنی جگہ چمٹ جاتا ہے، وہ اسے ڈھیلا کرنا چاہتا ہے لیکن وہ ڈھیلا نہیں ہوتا۔ اس وقت آپ نے اپنی انگلی سے اپنے حلق کی طرف اشارہ کیا۔' WHERE id = 5090;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن جعفر نے بیان کیا، کہا ہم کو عبدالرزاق بن ہمام نے خبر دی، انہیں ابن جریج نے خبر دی، کہا کہ مجھے ابن شہاب نے لعان کے بارے میں اور یہ کہ شریعت کی طرف سے اس کا سنت طریقہ کیا ہے، خبر دی بنی ساعدہ کے سہل بن سعد رضی اللہ عنہ نے، انہوں نے بیان کیا کہ قبیلہ انصار کے ایک صحابی رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئے اور عرض کیا: یا رسول اللہ! اس شخص کے متعلق آپ کا کیا ارشاد ہے جو اپنی بیوی کے ساتھ کسی غیر مرد کو دیکھے، کیا وہ اسے قتل کر دے یا اسے کیا کرنا چاہیئے؟ انہیں کے بارے میں اللہ تعالیٰ نے قرآن مجید کی وہ آیت نازل کی جس میں لعان کرنے والوں کے لیے تفصیلات بیان ہوئی ہیں۔ نبی کریم صلی اللہ علیہ وسلم نے ان سے فرمایا کہ اللہ تعالیٰ نے تمہاری بیوی کے بارے میں فیصلہ کر دیا ہے۔ بیان کیا کہ پھر دونوں نے مسجد میں لعان کیا، میں اس وقت وہاں موجود تھا۔ جب دونوں لعان سے فارغ ہوئے تو انصاری صحابی نے عرض کیا: یا رسول اللہ! اگر اب بھی میں اسے اپنے نکاح میں رکھوں تو اس کا مطلب یہ ہو گا کہ میں نے اس پر جھوٹی تہمت لگائی تھی۔ چنانچہ لعان سے فارغ ہونے کے بعد انہوں نے نبی کریم صلی اللہ علیہ وسلم کے حکم سے پہلے ہی انہیں تین طلاقیں دے دیں۔ نبی کریم صلی اللہ علیہ وسلم کی موجودگی میں ہی انہیں جدا کر دیا۔ ( سہل نے یا ابن شہاب نے ) کہا کہ ہر لعان کرنے والے میاں بیوی کے درمیان یہی جدائی کا سنت طریقہ مقرر ہوا۔ ابن جریج نے بیان کیا، ان سے ابن شہاب نے بیان کیا کہ ان کے بعد شریعت کی طرف سے طریقہ یہ متعین ہوا کہ دو لعان کرنے والوں کے درمیان تفریق کرا دی جایا کرے۔ اور وہ عورت حاملہ تھی۔ اور ان کا بیٹا اپنی ماں کی طرف منسوب کیا جاتا تھا۔ بیان کیا کہ پھر ایسی عورت کے میراث کے بارے میں بھی یہ طریقہ شریعت کی طرف سے مقرر ہو گیا کہ بچہ اس کا وارث ہو گا اور وہ بچہ کی وارث ہو گی۔ اس کے مطابق جو اللہ تعالیٰ نے وراثت کے سلسلہ میں فرض کیا ہے۔ ابن جریج نے بیان کیا، ان سے ابن شہاب نے اور ان سے سہل بن سعد ساعدی رضی اللہ عنہ نے، اسی حدیث میں کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا تھا کہ اگر ( لعان کرنے والی خاتون ) اس نے سرخ اور پستہ قد بچہ جنا جیسے وحرہ تو میں سمجھوں گا کہ عورت ہی سچی ہے اور اس کے شوہر نے اس پر جھوٹی تہمت لگائی ہے لیکن اگر کالا، بڑی آنکھوں والا اور بڑے سرینوں والا بچہ جنا تو میں سمجھوں گا کہ شوہر نے اس کے متعلق سچ کہا تھا۔ ( عورت جھوٹی ہے ) جب بچہ پیدا ہو تو وہ بری شکل کا تھا ( یعنی اس مرد کی صورت پر جس سے وہ بدنام ہوئی تھی ) ۔' WHERE id = 5100;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، ان سے لیث نے، ان سے یزید نے کہ ابن شہاب نے انہیں لکھا کہ عبیداللہ بن عبداللہ نے اپنے والد (عبداللہ بن عتبہ بن مسعود) سے انہیں خبر دی کہ انہوں نے ابن الارقم کو لکھا کہ سبیعہ اسلمیہ سے پوچھیں کہ نبی کریم صلی اللہ علیہ وسلم نے ان کے متعلق کیا فتویٰ دیا تھا تو انہوں نے فرمایا کہ جب میرے یہاں بچہ پیدا ہو گیا تو نبی کریم نے مجھے فتویٰ دیا کہ اب میں نکاح کر لوں۔' WHERE id = 5110;
UPDATE hadiths SET urdu = 'اور میں نے زینب بنت ام سلمہ سے سنا، وہ ام حبیبہ سے بیان کرتی تھیں کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ایک مسلمان عورت جو اللہ اور آخرت کے دن پر ایمان رکھتی ہو۔ اس کے لیے جائز نہیں کہ وہ کسی ( کی وفات ) کا سوگ تین دن سے زیادہ منائے سوا شوہر کے کہ اس کے لیے چار مہینے دس دن ہیں۔' WHERE id = 5126;
UPDATE hadiths SET urdu = 'ہم سے عمرو بن زرارہ نے بیان کیا، کہا ہم کو اسماعیل بن علیہ نے خبر دی، انہیں ایوب سختیانی نے اور ان سے سعید بن کبیر نے بیان کیا کہ میں نے ابن عمر رضی اللہ عنہما سے ایسے شخص کے بارے میں سوال کیا جس نے اپنی بیوی پر تہمت لگائی ہو تو انہوں نے کہا کہ نبی کریم صلی اللہ علیہ وسلم نے قبیلہ بنی عجلان کے میاں بیوی میں جدائی کرا دی تھی اور فرمایا تھا کہ اللہ خوب جانتا ہے کہ تم میں سے ایک جھوٹا ہے، تو کیا وہ رجوع کرے گا؟ لیکن دونوں نے انکار کیا، آپ صلی اللہ علیہ وسلم نے دوبارہ فرمایا کہ اللہ خوب جانتا ہے اسے جو تم میں سے ایک جھوٹا ہے وہ توبہ کرتا ہے یا نہیں؟ لیکن دونوں نے پھر توبہ سے انکار کیا۔ پس نبی کریم صلی اللہ علیہ وسلم نے ان میں جدائی کرا دی۔ ایوب نے بیان کیا کہ مجھ سے عمرو بن دینار نے کہا کہ یہاں حدیث میں ایک چیز اور ہے میں نے تمہیں اسے بیان کرتے نہیں دیکھا۔ وہ یہ ہے کہ ( تہمت لگانے والے ) شوہر نے کہا تھا کہ میرا مال ( مہر ) دلوا دیجئیے۔ نبی کریم صلی اللہ علیہ وسلم نے اس پر فرمایا کہ وہ تمہارا مال ہی نہیں رہا، اگر تم سچے بھی ہو تو تم اس سے خلوت کر چکے ہوا اور اگر جھوٹے ہو تب تو تم کو بطریق اولیٰ کچھ نہ ملنا چاہیئے۔' WHERE id = 5136;
UPDATE hadiths SET urdu = 'ہم سے محمد بن مقاتل نے بیان کیا، کہا ہم کو عبداللہ بن مبارک نے خبر دی، انہیں یونس بن یزید نے، انہیں ابن شہاب نے، انہیں عروہ نے خبر دی اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ ہند بنت عتبہ رضی اللہ عنہا حاضر ہوئیں اور عرض کیا: یا رسول اللہ! ابوسفیان ( ان کے شوہر ) بہت بخیل ہیں، تو کیا میرے لیے اس میں کوئی گناہ ہے اگر میں ان کے مال میں سے ( اس کے پیٹھ پیچھے ) اپنے بچوں کو کھلاؤں؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ نہیں، لیکن دستور کے مطابق ہونا چاہیے۔' WHERE id = 5146;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، کہا ہم سے وہیب نے بیان کیا، انہیں ہشام نے خبر دی، انہیں ان کے والد نے، انہیں زینب بنت ابی سلمہ رضی اللہ عنہا نے کہ م سلمہ رضی اللہ عنہا نے بیان کیا کہ میں نے عرض کیا: یا رسول اللہ! کیا مجھے ابوسلمہ ( ان کے پہلے شوہر ) کے لڑکوں کے بارے میں ثواب ملے گا اگر میں ان پر خرچ کروں۔ میں انہیں اس محتاجی میں دیکھ نہیں سکتی، وہ میرے بیٹے ہی تو ہیں۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ ہاں، تمہیں ہر اس چیز کا ثواب ملے گا جو تم ان پر خرچ کرو گی۔' WHERE id = 5156;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، ان سے امام مالک نے، ان سے اسحاق بن عبداللہ بن ابی طلحہ نے، انہوں نے انس بن مالک رضی اللہ عنہ سے سنا، انہوں نے بیان کیا کہ ایک درزی نے رسول اللہ صلی اللہ علیہ وسلم کی کھانے کی دعوت کی جو انہوں نے نبی کریم صلی اللہ علیہ وسلم کے لیے تیار کیا تھا۔ انس رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم کے ساتھ میں بھی گیا، میں نے دیکھا کہ نبی کریم صلی اللہ علیہ وسلم پیالہ میں چاروں طرف کدو تلاش کرتے تھے ( کھانے کے لیے ) بیان کیا کہ اسی دن سے کدو مجھ کو بھی بہت بھانے لگا۔' WHERE id = 5166;
UPDATE hadiths SET urdu = 'ہم سے ابونعمان نے بیان کیا، انہوں نے کہا ہم سے ابوعوانہ نے بیان کیا، ان سے ابوبشر نے، ان سے سعید بن جبیر نے اور ان سے ابن عباس رضی اللہ عنہما نے بیان کیا کہ ابن عباس رضی اللہ عنہما کی خالہ ام حفید بنت حارث بن حزن رضی اللہ عنہا نے نبی کریم صلی اللہ علیہ وسلم کو گھی، پنیر اور ساہنہ ہدیہ کے طور پر بھیجی۔ نبی کریم صلی اللہ علیہ وسلم نے عورتوں کو بلایا اور انہوں نے آپ کے دستر خوان پر ساہنہ کو کھایا لیکن آپ صلی اللہ علیہ وسلم نے اسے ہاتھ بھی نہیں لگایا جیسے آپ صلی اللہ علیہ وسلم اسے ناپسند کرتے ہیں۔ لیکن اگر ساہنہ حرام ہوتا تو آپ کے دستر خوان پر کھایا نہ جاتا اور نہ آپ انہیں کھانے کے لیے فرماتے۔' WHERE id = 5176;
UPDATE hadiths SET urdu = 'مجھ سے عثمان بن ابی شیبہ نے بیان کیا، کہا ہم کو جریر نے خبر دی، انہیں منصور نے، انہیں علی ابن الاقمر نے اور ان سے ابوجحیفہ رضی اللہ عنہ نے بیان کیا کہ میں نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر تھا۔ آپ صلی اللہ علیہ وسلم نے ایک صحابی سے جو آپ کے پاس موجود تھے فرمایا کہ میں ٹیک لگا کر نہیں کھاتا۔' WHERE id = 5186;
UPDATE hadiths SET urdu = 'ہم سے محمد بن کثیر نے بیان کیا، کہا ہم کو سفیان نے خبر دی، انہیں اعمش نے، انہیں ابوحازم نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے کبھی کسی کھانے میں کوئی عیب نہیں نکالا۔ اگر پسند ہوا تو کھا لیا اور اگر ناپسند ہوا تو چھوڑ دیا۔' WHERE id = 5196;
UPDATE hadiths SET urdu = 'ہم سے عمرو بن عون نے بیان کیا، کہا ہم سے خالد بن عبداللہ نے بیان کیا، ان سے ابوطوالہ نے اور ان سے انس نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ عورتوں پر عائشہ کی فضیلت ایسی ہے جیسے تمام کھانوں پر ثرید کی فضیلت ہے۔' WHERE id = 5206;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم نے بیان کیا، کہا ہم سے مالک نے بیان کیا، ان سے سمی نے، ان سے صالح نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ سفر عذاب کا ایک ٹکڑا ہے، جو انسان کو سونے اور کھانے سے روک دیتا ہے۔ پس جب کسی شخص کی سفری ضرورت حسب منشا پوری ہو جائے تو اسے جلد ہی گھر واپس آ جانا چاہیئے۔' WHERE id = 5216;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل نے بیان کیا، کہا کہ مجھ سے امام مالک نے بیان کیا، ان سے اسحاق بن عبداللہ بن ابی طلحہ نے، انہوں نے انس بن مالک رضی اللہ عنہ سے سنا کہ ایک درزی نے رسول اللہ صلی اللہ علیہ وسلم کو کھانے کی دعوت دی جو اس نے نبی کریم صلی اللہ علیہ وسلم کے لیے تیار کیا تھا۔ انس رضی اللہ عنہ نے بیان کیا کہ میں بھی نبی کریم صلی اللہ علیہ وسلم کے ساتھ اس دعوت میں گیا۔ انہوں نے آپ کی خدمت میں جَو کی روٹی اور شوربہ، جس میں کدو اور خشک کیا ہوا گوشت تھا، پیش کیا۔ انس رضی اللہ عنہ نے کہا کہ میں نے دیکھا کہ نبی کریم صلی اللہ علیہ وسلم پیالہ میں چاروں طرف کدو تلاش کر رہے ہیں۔ اسی دن سے میں بھی کدو پسند کرنے لگا۔ شمامہ نے بیان کیا اور ان سے انس رضی اللہ عنہ نے کہ پھر میں نبی کریم صلی اللہ علیہ وسلم کے سامنے کدو کے قتلے ( تلاش کر کر کے ) اکٹھے کرنے لگا۔' WHERE id = 5226;
UPDATE hadiths SET urdu = 'ہم سے ابن مقاتل نے بیان کیا، انہوں نے کہا ہم کو عبداللہ نے خبر دی، انہوں نے کہا ہم کو ابراہیم بن سعد نے خبر دی، انہیں ان کے والد نے اور ان سے عبداللہ بن جعفر رضی اللہ عنہما نے بیان کیا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم کو ککڑی کے ساتھ کھجور کھاتے ہوئے دیکھا ہے۔' WHERE id = 5237;
UPDATE hadiths SET urdu = 'ہم سے ابوعاصم نے بیان کیا، ان سے ثور بن یزید نے بیان کیا، ان سے خالد بن معدان نے اور ان سے ابوامامہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم جب کھانے سے فارغ ہوتے اور ایک مرتبہ بیان کیا کہ جب نبی کریم صلی اللہ علیہ وسلم اپنا دستر خوان اٹھاتے یہ دعا پڑھتے «الحمد لله الذي كفانا وأروانا،‏‏‏‏ غير مكفي،‏‏‏‏ ‏‏‏‏ولا مكفور، وقال مرة الحمد لله ربنا،‏‏‏‏ غير مكفي،‏‏‏‏ ولا مودع، ولا مستغنى،‏‏‏‏ ربنا‏ ‏‏.‏» ”تمام تعریفیں اس اللہ کے لیے ہیں جس نے ہماری کفایت کی اور ہمیں سیراب کیا۔ ہم اس کھانے کا حق پوری طرح ادا نہ کر سکے ورنہ ہم اس نعمت کے منکر نہیں ہیں۔ اور ایک مرتبہ فرمایا ”تیرے ہی لیے تمام تعریفیں ہیں اے ہمارے رب! اس کا حق ادا نہیں کر سکے اور نہ یہ ہمیشہ کے لیے رخصت کیا گیا ہے۔ ( یہ اس لیے کہا تاکہ ) اس سے ہم کو بے نیازی کا خیال نہ ہو۔ اے ہمارے رب!“۔' WHERE id = 5247;
UPDATE hadiths SET urdu = 'ہم سے اسحاق بن نضر نے بیان کیا، کہا ہم سے ابواسامہ نے بیان کیا، کہا ہم سے ہشام بن عروہ نے بیان کیا، ان سے ان کے والد نے اور ان سے اسماء بنت ابی بکر رضی اللہ عنہما نے بیان کیا کہ عبداللہ بن زبیر رضی اللہ عنہما مکہ میں ان کے پیٹ میں تھے۔ انہوں نے کہا کہ پھر میں ( جب ہجرت کے لیے ) نکلی تو وقت ولادت قریب تھا۔ مدینہ منورہ پہنچ کر میں نے پہلی منزل قباء میں کی اور یہیں عبداللہ بن زبیر رضی اللہ عنہما پیدا ہو گئے، میں نبی کریم صلی اللہ علیہ وسلم کی خدمت میں بچہ کو لے کر حاضر ہوئی اور اسے آپ کی گود میں رکھ دیا۔ نبی کریم صلی اللہ علیہ وسلم نے کھجور طلب فرمائی اور اسے چبایا اور بچہ کے منہ میں اپنا تھوک ڈال دیا۔ چنانچہ پہلی چیز جو اس بچہ کے پیٹ میں گئی وہ نبی کریم صلی اللہ علیہ وسلم کا تھوک مبارک تھا پھر آپ نے کھجور سے تحنیک کی اور اس کے لیے برکت کی دعا فرمائی۔ یہ سب سے پہلا بچہ اسلام میں ( ہجرت کے بعد مدینہ منورہ میں ) پیدا ہوا۔ صحابہ کرام رضی اللہ عنہم اس سے بہت خوش ہوئے کیونکہ یہ افواہ پھیلائی جا رہی تھی کہ یہودیوں نے تم ( مسلمانوں ) پر جادو کر دیا ہے۔ اس لیے تمہارے یہاں اب کوئی بچہ پیدا نہیں ہو گا۔' WHERE id = 5257;
UPDATE hadiths SET urdu = 'ہم سے یوسف بن راشد نے بیان کیا، کہا ہم سے وکیع اور یزید بن ہارون نے بیان کیا اور الفاظ حدیث یزید کے ہیں، ان سے کہمس بن حسن نے، ان سے عبداللہ بن بریدہ نے، عبداللہ بن مغفل رضی اللہ عنہ نے ایک شخص کو کنکری پھینکتے دیکھا تو فرمایا کہ کنکری نہ پھینکو کیونکہ رسول اللہ صلی اللہ علیہ وسلم نے کنکری پھینکنے سے منع فرمایا ہے یا ( انہوں نے بیان کیا کہ ) نبی کریم صلی اللہ علیہ وسلم کنکری پھینکنے کو پسند نہیں کرتے تھے اور کہا کہ اس سے نہ شکار کیا جا سکتا ہے اور نہ دشمن کو کوئی نقصان پہنچایا جا سکتا ہے البتہ یہ کبھی کسی کا دانت توڑ دیتی ہے اور آنکھ پھوڑ دیتی ہے۔ اس کے بعد بھی انہوں نے اس شخص کو کنکریاں پھینکتے دیکھا تو کہا کہ میں رسول اللہ صلی اللہ علیہ وسلم کی حدیث تمہیں سنا رہا ہوں کہ آپ نے کنکری پھینکنے سے منع فرمایا یا کنکری پھینکنے کو ناپسند کیا اور تم اب بھی پھینکے جا رہے ہو، میں تم سے اتنے دنوں تک کلام نہیں کروں گا۔' WHERE id = 5268;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے یحییٰ بن سعید قطان نے بیان کیا، ان سے شعبہ نے بیان کیا، ان سے ہشام بن زید نے بیان کیا اور ان سے انس بن مالک رضی اللہ عنہ نے بیان کیا کہ مرالظہران ( مکہ کے قریب ایک مقام ) میں ہم نے ایک خرگوش کو ابھارا لوگ اس کے پیچھے دوڑے مگر نہ پایا پھر میں اس کے پیچھے لگا اور میں نے اسے پکڑ لیا اور اسے ابوطلحہ رضی اللہ عنہ کے پاس لایا، انہوں نے نبی کریم صلی اللہ علیہ وسلم کی خدمت میں اس کا کولھا اور دونوں رانیں بھیجیں تو آپ نے انہیں قبول فرما لیا۔' WHERE id = 5278;
UPDATE hadiths SET urdu = 'ہم سے معلی بن اسد نے بیان کیا، کہا ہم سے عبدالعزیز یعنی ابن المختار نے بیان کیا، انہیں موسیٰ بن عقبہ نے خبر دی، کہا کہ مجھے سالم نے خبر دی، انہوں نے عبداللہ بن عمر رضی اللہ عنہما سے سنا اور ان سے رسول اللہ صلی اللہ علیہ وسلم نے کہ آپ صلی اللہ علیہ وسلم کی زید بن عمرو بن نوفل سے مقام بلد کے نشیبی حصہ میں ملاقات ہوئی۔ یہ آپ صلی اللہ علیہ وسلم پر وحی نازل ہونے سے پہلے کا زمانہ ہے۔ آپ نے وہ دستر خوان جس میں گوشت تھا جسے ان لوگوں نے آپ کی ضیافت کے لیے پیش کیا تھا مگر ان پر ذبح کے وقت بتوں کا نام لیا گیا تھا، آپ نے اسے زید بن عمرو کے سامنے واپس فرما دیا اور آپ صلی اللہ علیہ وسلم نے فرمایا کہ تم جو جانور اپنے بتوں کے نام پر ذبح کرتے ہو میں انہیں نہیں کھاتا، میں صرف اسی جانور کا گوشت کھاتا ہوں جس پر ( ذبح کرتے وقت ) اللہ کا نام لیا گیا ہو۔' WHERE id = 5288;
UPDATE hadiths SET urdu = 'ہم سے عمرو بن علی نے بیان کیا، کہا ہم سے یحییٰ نے بیان کیا، کہا ہم سے سفیان نے، ان سے ان کے والد نے، ان سے عبایہ بن رفاعہ بن رافع بن خدیج نے اور ان سے رافع بن خدیج رضی اللہ عنہ نے بیان کیا کہ میں نے عرض کی: یا رسول اللہ! کل ہمارا مقابلہ دشمن سے ہو گا اور ہمارے پاس چھریاں نہیں ہیں؟ آپ صلی اللہ علیہ وسلم نے فرمایا کہ پھر جلدی کر لو یا ( اس کے بجائے ) «أرن» کہا یعنی جلدی کر لو جو آلہ خون بہا دے اور ذبیحہ پر اللہ کا نام لیا گیا ہو تو اسے کھاؤ۔ البتہ دانت اور ناخن نہ ہونا چاہیئے اور اس کی وجہ بھی بتا دوں۔ دانت تو ہڈی ہے اور ناخن حبشیوں کی چھری ہے۔ اور ہمیں غنیمت میں اونٹ اور بکریاں ملیں ان میں سے ایک اونٹ بدک کر بھاگ پڑا تو ایک صاحب نے تیر سے مار کر گرا لیا۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ یہ اونٹ بھی بعض اوقات جنگلی جانوروں کی طرح بدکتے ہیں، اس لیے اگر ان میں سے بھی کوئی تمہارے قابو سے باہر ہو جائے تو اس کے ساتھ ایسا ہی کرو۔' WHERE id = 5298;
UPDATE hadiths SET urdu = 'ہم سے حمیدی نے بیان کیا، کہا ہم سے سفیان نے بیان کیا، کہا ہم سے ہشام نے بیان کیا، ان سے فاطمہ نے اور ان سے اسماء رضی اللہ عنہما نے بیان کیا کہ ہم نے رسول اللہ صلی اللہ علیہ وسلم کے زمانہ میں ایک گھوڑا ذبح کیا اور اسے کھایا۔' WHERE id = 5308;
UPDATE hadiths SET urdu = 'ہم سے زہیر بن حرب نے بیان کیا، کہا ہم سے یعقوب بن ابراہیم نے بیان کیا، کہا ہم سے ہمارے والد نے بیان کیا، ان سے صالح نے بیان کیا، کہا مجھ سے ابن شہاب نے بیان کیا، انہیں عبیداللہ بن عبداللہ نے خبر دی اور انہیں عبداللہ بن عباس رضی اللہ عنہما نے خبر دی کہ رسول اللہ صلی اللہ علیہ وسلم ایک مری ہوئی بکری کے قریب سے گزرے تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ تم نے اس کے چمڑے سے فائدہ کیوں نہیں اٹھایا؟ لوگوں نے کہا کہ یہ تو مری ہوئی ہے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ صرف اس کا کھانا حرام کیا گیا ہے۔' WHERE id = 5319;
UPDATE hadiths SET urdu = 'ہم سے عبیداللہ بن موسیٰ نے بیان کیا، ان سے حنظلہ نے، ان سے سالم نے، ان سے ابن عمر رضی اللہ عنہما نے کہ وہ چہرے پر نشان لگانے کو ناپسند کرتے تھے اور ابن عمر رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے چہرے پر مارنے سے منع کیا ہے۔ عبیداللہ بن موسیٰ کے ساتھ اس حدیث کو قتیبہ بن سعید نے بھی روایت کیا، کہا ہم کو عمرو بن محمد عنقزی نے خبر دی، انہوں نے حنظلہ سے۔' WHERE id = 5329;
UPDATE hadiths SET urdu = 'ہم سے محمد بن ابی بکر مقدمی نے بیان کیا، کہا ہم سے خالد بن حارث نے بیان کیا، کہا ہم سے عبیداللہ نے بیان کیا اور ان سے نافع نے بیان کیا کہ عبداللہ بن عمر رضی اللہ عنہما قربان گاہ میں نحر کیا کرتے تھے اور عبیداللہ نے بیان کیا کہ مراد وہ جگہ ہے جہاں نبی کریم صلی اللہ علیہ وسلم قربانی کرتے تھے۔' WHERE id = 5339;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ نے بیان کیا، کہا ہم سے اسماعیل بن ابراہیم نے بیان کیا، ان سے ایوب نے، ان سے محمد نے اور ان سے انس رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ جس نے نماز سے پہلے قربانی کر لی ہو وہ دوبارہ قربانی کرے۔ اس پر ایک صحابی اٹھے اور عرض کیا: ( یا رسول اللہ! ) اس دن گوشت کی لوگوں کو خواہش زیادہ ہوتی ہے پھر انہوں نے اپنے پڑوسیوں کی محتاجی کا ذکر کیا جیسے نبی کریم صلی اللہ علیہ وسلم نے ان کا عذر قبول کر لیا ہو ( انہوں نے یہ بھی کہا کہ ) میرے پاس ایک سال کا ایک بچہ ہے اور بکریوں سے بھی اچھا ہے۔ چنانچہ نبی کریم صلی اللہ علیہ وسلم نے انہیں اس کے قربانی کی اجازت دے دی لیکن مجھے اس کا علم نہیں کہ یہ اجازت دوسروں کو بھی تھی یا نہیں پھر نبی کریم صلی اللہ علیہ وسلم دو مینڈھوں کی طرف متوجہ ہوئے۔ ان کی مراد یہ تھی کہ انہیں نبی کریم صلی اللہ علیہ وسلم نے ذبح کیا پھر لوگ بکریوں کی طرف متوجہ ہوئے اور انہیں ذبح کیا۔' WHERE id = 5349;
UPDATE hadiths SET urdu = 'ہم سے حبان بن موسیٰ نے بیان کیا، انہوں نے کہا ہم کو عبداللہ نے خبر دی، انہوں نے کہا کہ مجھے یونس نے خبر دی، ان سے زہری نے، انہوں نے کہا کہ مجھے ابن ازہر کے غلام ابو عبید نے بیان کیا کہ وہ بقر عید کے دن عمر بن خطاب رضی اللہ عنہ کے ساتھ عیدگاہ میں موجود تھے۔ عمر رضی اللہ عنہ نے خطبہ سے پہلے عید کی نماز پڑھائی پھر لوگوں کے سامنے خطبہ دیا اور خطبہ میں فرمایا اے لوگو! رسول اللہ صلی اللہ علیہ وسلم نے تمہیں ان دو عیدوں میں روزہ رکھنے سے منع فرمایا ہے ایک وہ دن ہے جس دن تم ( رمضان کے ) روزے پورے کر کے افطار کرتے ہو ( عیدالفطر ) اور دوسرا تمہاری قربانی کا دن ہے۔' WHERE id = 5359;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے یحییٰ نے بیان کیا، کہا ان سے ابوحیان نے، کہا ہم سے عامر نے بیان کیا اور ان سے ابن عمر رضی اللہ عنہما نے کہ عمر رضی اللہ عنہ ممبر پر کھڑے ہوئے اور کہا امابعد! جب شراب کی حرمت کا حکم نازل ہوا تو وہ پانچ چیزوں سے بنتی تھی انگور، کھجور، شہد، گیہوں اور جَو اور شراب ( خمر ) وہ ہے جو عقل کو زائل کر دے۔' WHERE id = 5369;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا ہم سے یعقوب بن عبدالرحمٰن نے بیان کیا، ان سے ابوحازم سلمہ بن دینار نے بیان کیا کہ میں نے سہل بن سعد ساعدی سے سنا، انہوں نے کہا کہ ابواسید مالک بن ربیع آئے اور نبی کریم صلی اللہ علیہ وسلم کو اپنے ولیمہ کی دعوت دی، ان کی بیوی ہی سب کام کر رہی تھیں حالانکہ وہ نئی دلہن تھیں۔ سہل رضی اللہ عنہ نے بیان کیا تمہیں معلوم ہے کہ میں نے نبی کریم صلی اللہ علیہ وسلم کو کیا پلایا تھا۔ نبی کریم صلی اللہ علیہ وسلم کے لیے انہوں نے پتھر کے کونڈے میں رات کے وقت کھجور بھگو دی تھی۔' WHERE id = 5379;
UPDATE hadiths SET urdu = 'ہم سے ابوعاصم نے بیان کیا، ان سے ابن جریج نے، کہا مجھ کو عطاء بن ابی رباح نے خبر دی، انہوں نے جابر رضی اللہ عنہ سے سنا، انہوں نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے کشمش اور کھجور ( کے شیرہ ) کو اور تازہ ( پختہ، پکی ہوئی ) کھجور اور نیم پختہ ( کچی، گدری ہوئی ) کھجور کو ملا کر بھگونے سے منع فرمایا تھا، اس طور اس میں نشہ جلدی پیدا ہو جاتا ہے۔' WHERE id = 5389;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن مسلمہ نے بیان کیا، کہا ہم سے امام مالک نے، ان سے اسحاق بن عبداللہ نے، انہوں نے انس بن مالک رضی اللہ عنہ سے سنا، انہوں نے بیان کیا کہ ابوطلحہ رضی اللہ عنہ کے پاس مدینہ کے تمام انصار میں سب سے زیادہ کھجور کے باغات تھے اور ان کا سب سے پسندیدہ مال بیرحاء کا باغ تھا۔ یہ مسجد نبوی کے سامنے ہی تھا اور رسول اللہ صلی اللہ علیہ وسلم وہاں تشریف لے جاتے تھے اور اس کا عمدہ پانی پیتے تھے۔ انس رضی اللہ عنہ نے بیان کیا کہ پھر جب آیت «لن تنالوا البر حتى تنفقوا مما تحبون‏» ”تم ہرگز نیکی نہیں پاؤ گے جب تک وہ مال نہ خرچ کرو جو تمہیں عزیز ہو۔“ نازل ہوئی تو ابوطلحہ رضی اللہ عنہ کھڑے ہوئے اور عرض کیا: یا رسول اللہ! اللہ تعالیٰ فرماتا ہے «لن تنالوا البر حتى تنفقوا مما تحبون‏» ”تم ہرگز نیکی کو نہیں پاؤ گے جب تک وہ مال نہ خرچ کرو جو تمہیں عزیز ہو۔“ اور مجھے اپنے مال میں سب سے زیادہ عزیز بیرحاء کا باغ ہے اور وہ اللہ تعالیٰ کے راستہ میں صدقہ ہے، اس کا ثواب اور اجر میں اللہ کے یہاں پانے کی امید رکھتا ہوں، اس لیے یا رسول اللہ! آپ جہاں اسے مناسب خیال فرمائیں خرچ کریں۔ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ خوب یہ بہت ہی فائدہ بخش مال ہے یا ( اس کے بجائے آپ نے ) «رايح» ( یاء کے ساتھ فرمایا ) ۔ راوی حدیث عبداللہ کو اس میں شک تھا ( نبی کریم صلی اللہ علیہ وسلم نے ان سے مزید فرمایا کہ ) جو کچھ تو نے کہا ہے میں نے سن لیا میرا خیال ہے کہ تم اسے اپنے رشتہ داروں کو دے دو۔ ابوطلحہ رضی اللہ عنہ نے عرض کیا کہ ایسا ہی کروں گا یا رسول اللہ! چنانچہ انہوں نے اپنے رشتہ داروں اپنے چچا کے لڑکوں میں اسے تقسیم کر دیا۔ اور اسماعیل اور یحییٰ بن یحییٰ نے «رايح‏.‏» کا لفظ نقل کیا ہے۔' WHERE id = 5399;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن صالح نے بیان کیا، کہا ہم سے فلیح بن سلیمان نے بیان کیا، ان سے سعید بن حارث نے اور ان سے جابر بن عبداللہ انصاری رضی اللہ عنہما نے کہ ہم سے یحییٰ بن صالح نے بیان کیا، کہا ہم سے فلیح بن سلیمان نے بیان کیا، ان سے سعید بن حارث نے اور ان سے جابر بن عبداللہ انصاری رضی اللہ عنہما نے کہ' WHERE id = 5409;
UPDATE hadiths SET urdu = 'ہم سے ابوعاصم اور ابونعیم نے بیان کیا، انہوں نے کہا کہ ہم سے عروہ بن ثابت نے بیان کیا، انہوں نے کہا کہ مجھے شمامہ بن عبداللہ نے خبر دی، بیان کیا کہ انس رضی اللہ عنہ دو یا تین سانسوں میں پانی پیتے تھے۔' WHERE id = 5419;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے یحییٰ نے بیان کیا، ان سے سفیان نے، ان سے سعد نے، ان سے عبداللہ بن کعب نے اور ان سے ان کے والد نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ مومن کی مثال پودے کی سب سے پہلی نکلی ہوئی ہری شاخ جیسی ہے کہ ہوا اسے کبھی جھکا دیتی ہے اور کبھی برابر کر دیتی ہے اور منافق کی مثال صنوبر کے درخت جیسی ہے کہ وہ سیدھا ہی کھڑا رہتا ہے اور آخر ایک جھوکے میں کبھی اکھڑ ہی جاتا ہے۔ اور زکریا نے بیان کیا کہ ہم سے سعد نے بیان کیا، ان سے ابن کعب نے بیان کیا، ان سے ان کے والد ماجد محترم المقام کعب رضی اللہ عنہ نے نبی کریم صلی اللہ علیہ وسلم سے یہی بیان کیا۔' WHERE id = 5430;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف تینسی نے بیان کیا، کہا ہم سے لیث بن سعد نے بیان کیا، کہا کہ مجھ سے یزید بن عبداللہ بن ہاد نے بیان کیا، ان سے مطلب بن عبداللہ بن جذب کے غلام عمرو نے اور ان سے انس بن مالک رضی اللہ عنہ نے بیان کیا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم سے سنا، آپ صلی اللہ علیہ وسلم نے فرمایا کہ اللہ تعالیٰ کا ارشاد ہے کہ جب میں اپنے کسی بندہ کو اس کے دو محبوب اعضاء ( آنکھوں ) کے بارے میں آزماتا ہوں ( یعنی نابینا کر دیتا ہوں ) اور وہ اس پر صبر کرتا ہے تو اس کے بدلے میں اسے جنت دیتا ہوں۔' WHERE id = 5440;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، کہا ہم سے لیث نے بیان کیا، ان سے عقیل نے، ان سے ابن شہاب نے، ان سے عروہ نے، انہیں اسامہ بن زید رضی اللہ عنہما نے خبر دی کہ نبی کریم صلی اللہ علیہ وسلم گدھے کی پالان پر فدک کی چادر ڈال کر اس پر سوار ہوئے اور اسامہ بن زید رضی اللہ عنہما کو اپنے پیچھے سوار کیا، نبی کریم صلی اللہ علیہ وسلم سعد بن عبادہ رضی اللہ عنہ کی عیادت کو تشریف لے جا رہے تھے، یہ جنگ بدر سے پہلے کا واقعہ ہے۔ نبی کریم صلی اللہ علیہ وسلم روانہ ہوئے اور ایک مجلس سے گزرے جس میں عبداللہ بن ابی بن سلول بھی تھا۔ عبداللہ ابھی مسلمان نہیں ہوا تھا اس مجلس میں ہر گروہ کے لوگ تھے مسلمان بھی، مشرکین بھی یعنی بت پرست اور یہودی بھی۔ مجلس میں عبداللہ بن رواحہ رضی اللہ عنہ بھی تھے، سواری کی گرد جب مجلس تک پہنچی تو عبداللہ بن ابی نے اپنی چادر اپنی ناک پر رکھ لی اور کہا کہ ہم پر گرد نہ اڑاؤ۔ پھر نبی کریم صلی اللہ علیہ وسلم نے انہیں سلام کیا اور سواری روک کر وہاں اتر گئے پھر آپ نے انہیں اللہ کے طرف بلایا اور قرآن مجید پڑھ کر سنایا۔ اس پر عبداللہ بن ابی نے کہا میاں تمہاری باتیں میری سمجھ میں نہیں آتیں اگر حق ہیں تو ہماری مجلس میں انہیں بیان کر کے ہم کو تکلیف نہ پہنچایا کرو، اپنے گھر جاؤ وہاں جو تمہارے پاس آئے اس سے بیان کرو۔ اس پر ابن رواحہ رضی اللہ عنہ نے کہا کیوں نہیں یا رسول اللہ! آپ ہماری مجلسوں میں ضرور تشریف لائیں کیونکہ ہم ان باتوں کو پسند کرتے ہیں۔ اس پر مسلمانوں، مشرکوں اور یہودیوں میں جھگڑے بازی ہو گئی اور قریب تھا کہ ایک دوسرے پر حملہ کر بیٹھتے لیکن آپ انہیں خاموش کرتے رہے یہاں تک کہ سب خاموش ہو گئے پھر نبی کریم صلی اللہ علیہ وسلم اپنی سواری پر سوار ہو کر سعد بن عبادہ رضی اللہ عنہ کے یہاں تشریف لے گئے اور ان سے فرمایا سعد! تم نے سنا نہیں ابوحباب نے کیا کہا، آپ کا اشارہ عبداللہ بن ابی کی طرف تھا۔ اس پر سعد رضی اللہ عنہ بولے کہ یا رسول اللہ! اسے معاف کر دیجئیے اور اس سے درگزر فرمایئے۔ اللہ تعالیٰ نے آپ کو وہ نعمت عطا فرما دی جو عطا فرمانی تھی ( آپ کے مدینہ تشریف لانے سے پہلے ) اس بستی کے لوگ اس پر متفق ہو گئے تھے کہ اسے تاج پہنا دیں اور اپنا سردار بنا لیں لیکن جب اللہ تعالیٰ نے اس منصوبہ کو اس حق کے ذریعہ جو آپ کو اس نے عطا فرمایا ہے ختم کر دیا تو وہ اس پر بگڑ گیا یہ جو کچھ معاملہ اس نے آپ کے ساتھ کیا ہے اسی کا نتیجہ ہے۔' WHERE id = 5450;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، کہا ہم کو شعیب نے خبر دی، ان سے زہری نے بیان کیا، کہا ہمیں عبدالرحمٰن بن عوف رضی اللہ عنہ کے غلام ابوعبیدہ نے خبر دی اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم سے سنا، آپ صلی اللہ علیہ وسلم نے فرمایا کسی شخص کا عمل اسے جنت میں داخل نہیں کر سکے گا۔ صحابہ کرام رضی اللہ عنہم نے عرض کیا: یا رسول اللہ! آپ کا بھی نہیں؟ آپ صلی اللہ علیہ وسلم نے فرمایا نہیں، میرا بھی نہیں، سوا اس کے کہ اللہ اپنے فضل و رحمت سے مجھے نوازے اس لیے ( عمل میں ) میانہ روی اختیار کرو اور قریب قریب چلو اور تم میں کوئی شخص موت کی تمنا نہ کرے کیونکہ یا وہ نیک ہو گا تو امید ہے کہ اس کے اعمال میں اور اضافہ ہو جائے اور اگر وہ برا ہے تو ممکن ہے وہ توبہ ہی کرے۔' WHERE id = 5460;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم نے بیان کیا، انہوں نے کہا ہم سے عبدالرحمٰن بن غسیل نے بیان کیا، ان سے عاصم بن عمیر بن قتادہ نے بیان کیا، انہوں نے کہا کہ میں نے جابر بن عبداللہ رضی اللہ عنہما سے سنا، انہوں نے بیان کیا کہ میں نے نبی کریم صلی اللہ علیہ وسلم سے سنا، آپ صلی اللہ علیہ وسلم نے فرمایا کہ اگر تمہاری دواؤں میں کسی میں بھلائی ہے یا یہ کہا کہ تمہاری ( ان ) دواؤں میں بھلائی ہے۔ تو پچھنا لگوانے یا شہد پینے اور آگ سے داغنے میں ہے اگر وہ مرض کے مطابق ہو اور میں آگ سے داغنے کو پسند نہیں کرتا ہوں۔' WHERE id = 5470;
UPDATE hadiths SET urdu = 'ہم سے مسدد بن مسرہد نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے بیان کیا، ان سے عمرو بن دینار نے، ان سے طاؤس اور عطاء بن ابی رباح نے اور ان سے ابن عباس رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے پچھنا لگوایا جبکہ آپ احرام سے تھے۔' WHERE id = 5481;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ مدینی نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے، ان سے زہری نے، کہا مجھ کو عبیداللہ بن عبداللہ بن عتبہ نے خبر دی اور انہیں ام قیس رضی اللہ عنہا نے کہ میں اپنے ایک لڑکے کو لے کر رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئی۔ میں نے اس کی ناک میں بتی ڈالی تھی، اس کا حلق دبایا تھا چونکہ اس کو گلے کی بیماری ہو گئی تھی آپ صلی اللہ علیہ وسلم نے فرمایا تم اپنے بچوں کو انگلی سے حلق دبا کر کیوں تکلیف دیتی ہو یہ عود ہندی لو اس میں سات بیماریوں کی شفاء ہے ان میں ایک ذات الجنب ( پسلی کا ورم بھی ہے ) اگر حلق کی بیماری ہو تو اس کو ناک میں ڈالو اگر ذات الجنب ہو تو حلق میں ڈالو ( لدود کرو ) سفیان کہتے ہیں کہ میں نے زہری سے سنا، نبی کریم صلی اللہ علیہ وسلم نے دو بیماریوں کو تو بیان کیا باقی پانچ بیماریوں کو بیان نہیں فرمایا۔ علی بن عبداللہ مدینی نے کہا میں نے سفیان سے کہا، معمر تو زہری سے یوں نقل کرتا ہے «أعلقت عنه» انہوں نے کہا کہ معمر نے یاد نہیں رکھا۔ مجھے یاد ہے زہری نے یوں کہا تھا «أعلقت عليه‏.‏» اور سفیان نے اس تحنیک کو بیان کیا جو بچہ کو پیدائش کے وقت کی جاتی ہے سفیان نے انگلی حلق میں ڈال کر اپنے کوے کو انگلی سے اٹھایا تو سفیان نے «أعلاق» کا معنی بچے کے حلق میں انگلی ڈال کر تالو کو اٹھایا انہوں نے یہ نہیں کہا «أعلقوا عنه شيئا‏.‏» ۔' WHERE id = 5494;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے ابوالاحوص نے بیان کیا، کہا ہم سے سعید بن مسروق نے بیان کیا، ان سے عبایہ بن رفاعہ نے، ان سے ان کے دادا رافع بن خدیج نے بیان کیا کہ میں نے نبی کریم صلی اللہ علیہ وسلم سے سنا آپ صلی اللہ علیہ وسلم نے فرمایا ”بخار جہنم کی بھاپ میں سے ہے پس اسے پانی سے ٹھنڈا کر لیا کرو۔' WHERE id = 5505;
UPDATE hadiths SET urdu = 'مجھ سے محمد بن بشار نے بیان کیا، کہا ہم سے غندر نے، ان سے شعبہ نے، ان سے ابوبشر نے، ان سے ابوالمتوکل نے، ان سے ابو سعید خدری رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم کے چند صحابہ در حالت سفر عرب کے ایک قبیلہ پر گزرے۔ قبیلہ والوں نے ان کی ضیافت نہیں کی کچھ دیر بعد اس قبیلہ کے سردار کو بچھو نے کاٹ لیا، اب قبیلہ والوں نے ان صحابہ سے کہا کہ آپ لوگوں کے پاس کوئی دوا یا کوئی جھاڑنے والا ہے۔ صحابہ نے کہا کہ تم لوگوں نے ہمیں مہمان نہیں بنایا اور اب ہم اس وقت تک دم نہیں کریں گے جب تک تم ہمارے لیے اس کی مزدوری نہ مقرر کر دو۔ چنانچہ ان لوگوں نے چند بکریاں دینی منظور کر لیں پھر ( ابو سعید خدری رضی اللہ عنہ ) سورۃ فاتحہ پڑھنے لگے اور اس پر دم کرنے میں منہ کا تھوک بھی اس جگہ پر ڈالنے لگے۔ اس سے وہ شخص اچھا ہو گیا۔ چنانچہ قبیلہ والے بکریاں لے کر آئے لیکن صحابہ نے کہا کہ جب تک ہم نبی کریم صلی اللہ علیہ وسلم سے نہ پوچھ لیں یہ بکریاں نہیں لے سکتے پھر جب نبی کریم صلی اللہ علیہ وسلم سے پوچھا تو آپ مسکرائے اور فرمایا تمہیں کیسے معلوم ہو گیا تھا کہ سورۃ فاتحہ سے دم بھی کیا جا سکتا ہے، ان بکریوں کو لے لو اور اس میں میرا بھی حصہ لگاؤ۔' WHERE id = 5515;
UPDATE hadiths SET urdu = 'مجھ سے صدقہ بن فضل نے بیان کیا، کہا ہم کو ابن عیینہ نے خبر دی، انہیں عبداللہ بن سعید نے، انہیں عمرہ نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم دم کرتے وقت یہ دعا پڑھا کرتے تھے «تربة أرضنا،‏‏‏‏‏‏‏‏ وريقة بعضنا،‏‏‏‏ ‏‏‏‏يشفى سقيمنا،‏‏‏‏‏‏‏‏ بإذن ربنا‏ ‏‏.» ”ہماری زمین کی مٹی اور ہمارا بعض تھوک ہمارے رب کے حکم سے ہمارے مریض کو شفاء ہو۔“' WHERE id = 5525;
UPDATE hadiths SET urdu = 'ہم سے مسلم بن ابراہیم نے بیان کیا، کہا ہم سے ہشام دستوائی نے بیان کیا، ان سے قتادہ نے اور ان سے انس رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”چھوت لگ جانے کی کوئی اصل نہیں اور نہ بدشگونی کی کوئی اصل ہے اور مجھے اچھی فال پسند ہے۔“ یعنی کوئی کلمہ خیر اور نیک بات جو کسی کے منہ سے سنی جائے ( جیسا کہ اوپر بیان ہوا ) ۔' WHERE id = 5535;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ مدینی نے بیان کیا، کہا ہم سے مروان بن معاویہ فزاری نے بیان کیا، کہا ہم کو ہاشم بن ہاشم بن عقبہ نے خبر دی، کہا ہم کو عامر بن سعد نے خبر دی اور ان سے ان کے والد (سعد بن ابی وقاص رضی اللہ عنہ) نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ جو شخص روزانہ چند عجوہ کھجوریں کھا لیا کرے اسے اس دن رات تک زہر اور جادو نقصان نہیں پہنچا سکیں گے۔ علی بن عبداللہ مدینی کے سوا دوسرے راوی نے بیان کیا کہ سات کھجوریں کھا لیا کرے۔' WHERE id = 5546;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل بن ابی اویس نے بیان کیا، کہا مجھ سے امام مالک نے، انہوں نے نافع اور عبداللہ بن دینار اور زید بن اسلم سے، انہوں نے عبداللہ بن عمر رضی اللہ عنہما سے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”اللہ تعالیٰ اس کی طرف قیامت کے دن نظر رحمت نہیں کرے گا جو اپنا کپڑا تکبر و غرور سے زمین پر گھسیٹ کر چلتا ہے۔“' WHERE id = 5558;
UPDATE hadiths SET urdu = 'ہم سے عبدان نے بیان کیا، کہا ہم کو عبداللہ نے خبر دی، کہا ہم کو یونس نے، انہیں زہری نے، انہیں علی بن حسین نے خبر دی، انہیں حسین بن علی رضی اللہ عنہما نے خبر دی کہ علی رضی اللہ عنہ نے بیان کیا ( کہ حمزہ رضی اللہ عنہ نے حرمت شراب سے پہلے شراب کے نشہ میں جب ان کی اونٹنی ذبح کر دی اور انہوں نے نبی کریم صلی اللہ علیہ وسلم سے آ کر اس کی شکایت کی تو ) نبی کریم صلی اللہ علیہ وسلم نے اپنی چادر منگوائی اور اسے اوڑھ کر تشریف لے چلنے لگے۔ میں اور زید بن حارثہ رضی اللہ عنہ آپ کے پیچھے پیچھے تھے۔ آخر آپ اس گھر میں پہنچے جس میں حمزہ رضی اللہ عنہ تھے، آپ نے اندر آنے کی اجازت مانگی اور انہوں نے آپ حضرات کو اجازت دی۔' WHERE id = 5568;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل نے بیان کیا، انہوں نے کہا کہ مجھ سے امام مالک نے بیان کیا، ان سے نافع نے بیان کیا، ان سے عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا کہ ایک شخص نے عرض کیا: یا رسول اللہ! محرم کس طرح کا کپڑا پہنے؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ( محرم کے لیے ) کہ قمیص نہ پہنو، نہ عمامے، نہ پاجامے، نہ برنس اور نہ موزے البتہ اگر کسی کو چپل نہ ملے تو وہ ( چمڑے کے ) موزوں کو ٹخنہ سے نیچے تک کاٹ کر انہیں پہن سکتا ہے اور نہ کوئی ایسا کپڑا پہنو جس میں زعفران یا ورس لگایا گیا ہو۔' WHERE id = 5578;
UPDATE hadiths SET urdu = 'مجھ سے عبداللہ بن ابی الاسود نے بیان کیا، انہوں نے کہا ہم سے معاذ دستوائی نے بیان کیا، انہوں نے کہا کہ مجھ سے میرے والد نے بیان کیا، ان سے قتادہ نے اور ان سے انس بن مالک رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم کو تمام کپڑوں میں یمنی سبز چادر پہننا بہت پسند تھی۔' WHERE id = 5588;
UPDATE hadiths SET urdu = 'ہم سے محمد بن بشار نے بیان کیا، کہا ہم سے عبدالوہاب بن عبدالمجید ثقفی نے، کہا ہم کو ایوب سختیانی نے خبر دی، انہیں عکرمہ نے اور انہیں رفاعہ رضی اللہ عنہ نے کہ انہوں نے اپنی بیوی کو طلاق دے دی تھی۔ پھر ان سے عبدالرحمٰن بن زبیر قرظی رضی اللہ عنہ نے نکاح کر لیا تھا۔ عائشہ رضی اللہ عنہا نے بیان کیا کہ وہ خاتون سبز اوڑھنی اورڑھے ہوئے تھیں، انہوں نے عائشہ رضی اللہ عنہا سے ( اپنے شوہر کی ) شکایت کی اور اپنے جسم پر سبز نشانات ( چوٹ کے ) دکھائے پھر جب رسول اللہ صلی اللہ علیہ وسلم تشریف لائے تو ( جیسا کہ عادت ہے ) عکرمہ نے بیان کیا کہ عورتیں آپس میں ایک دوسرے کی مدد کرتی ہیں۔ عائشہ رضی اللہ عنہا نے ( نبی کریم صلی اللہ علیہ وسلم سے ) کہا کہ کسی ایمان والی عورت کا میں نے اس سے زیادہ برا حال نہیں دیکھا ان کا جسم ان کے کپڑے سے بھی زیادہ برا ہو گیا ہے۔ بیان کیا کہ ان کے شوہر نے بھی سن لیا تھا کہ ( ان کی ) بیوی نبی کریم صلی اللہ علیہ وسلم کے پاس گئی ہے چنانچہ وہ بھی آ گئے اور ان کے ساتھ ان کے دو بچے ان سے پہلی بیوی کے تھے۔ ان کی بیوی نے کہا: اللہ کی قسم! مجھے ان سے کوئی اور شکایت نہیں البتہ ان کے ساتھ اس سے زیادہ اور کچھ نہیں جس سے میرا کچھ نہیں ہوتا۔ انہوں نے اپنے کپڑے کا پلو پکڑ کر اشارہ کیا ( یعنی ان کے شوہر کمزور ہیں ) اس پر ان کے شوہر نے کہا: یا رسول اللہ! واللہ یہ جھوٹ بولتی ہے میں تو اس کو ( جماع کے وقت ) چمڑے کی طرح ادھیڑ کر رکھ دیتا ہوں مگر یہ شریر ہے، یہ مجھے پسند نہیں کرتی اور رفاعہ کے یہاں دوبارہ جانا چاہتی ہے۔ نبی کریم صلی اللہ علیہ وسلم نے اس پر فرمایا کہ اگر یہ بات ہے تو تمہارے لیے وہ ( رفاعہ ) اس وقت تک حلال نہیں ہو گا جب تک یہ ( عبدالرحمٰن دوسرے شوہر ) تمہارا مزا نہ چکھ لیں۔ بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے عبدالرحمٰن کے ساتھ دو بچے بھی دیکھے تو دریافت فرمایا کیا یہ تمہارے بچے ہیں؟ انہوں نے عرض کیا جی ہاں۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا: اچھا، اس وجہ سے تم یہ باتیں سوچتی ہو۔ اللہ کی قسم یہ بچے ان سے اتنے ہی مشابہ ہیں جتنا کہ کوا کوے سے مشابہ ہوتا ہے۔' WHERE id = 5599;
UPDATE hadiths SET urdu = 'مجھ سے محمد بن بشار نے بیان کیا، انہوں نے کہا ہم سے عثمان بن عمر نے بیان کیا، انہوں نے کہا ہم سے علی مبارک نے بیان کیا، انہوں نے کہا ہم سے یحییٰ بن ابی کثیر نے بیان کیا، ان سے عمران بن حطان نے بیان کیا کہ میں نے عائشہ رضی اللہ عنہا سے ریشم کے متعلق پوچھا تو انہوں نے بتلایا کہ عبداللہ بن عباس رضی اللہ عنہما کے پاس جاؤ اور ان سے پوچھو۔ بیان کی کہ میں نے عبداللہ بن عمر رضی اللہ عنہما سے پوچھا تو انہوں نے بیان کیا کہ مجھے ابوحفص یعنی عمر بن خطاب رضی اللہ عنہ نے خبر دی کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ دنیا میں ریشم تو وہی مرد پہنے گا جس کا آخرت میں کوئی حصہ نہ ہو۔ میں نے اس پر کہا کہ سچ کہا اور ابوحفص رسول اللہ صلی اللہ علیہ وسلم کی طرف کوئی جھوٹی بات نسبت نہیں کر سکتے اور عبداللہ بن رجاء نے بیان کیا کہ ہم سے جریر نے بیان کیا، ان سے یحییٰ نے اور ان سے عمران نے اور پوری حدیث بیان کی۔' WHERE id = 5609;
UPDATE hadiths SET urdu = 'ہم سے ابوالولید نے بیان کیا، کہا ہم سے اسحاق بن سعید بن عمرو بن سعید بن عاص نے بیان کیا، کہا کہ مجھ سے میرے والد نے بیان کیا، کہا کہ مجھ سے ام خالد بنت خالد رضی اللہ عنہا نے بیان کیا، انہوں نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم کے پاس کچھ کپڑے آئے جن میں ایک کالی چادر بھی تھی۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ تمہارا کیا خیال ہے، کسے یہ چادر دی جائے؟ صحابہ کرام رضی اللہ عنہم خاموش رہے پھر آپ صلی اللہ علیہ وسلم نے فرمایا کہ ام خالد کو بلا لاؤ۔ چنانچہ مجھے نبی کریم صلی اللہ علیہ وسلم کی خدمت میں لایا گیا اور مجھے وہ چادر نبی کریم صلی اللہ علیہ وسلم نے اپنے ہاتھ سے عنایت فرمائی اور فرمایا دیر تک جیتی رہو، دو مرتبہ آپ صلی اللہ علیہ وسلم نے فرمایا۔ پھر آپ اس چادر کے نقش و نگار کو دیکھنے لگے اور اپنے ہاتھ سے میری طرف اشارہ کر کے فرمایا ام خالد! «سنا ‏ ‏‏.‏ والسنا» یہ حبشی زبان کا لفظ ہے یعنی واہ کیا زیب دیتی ہے۔ اسحاق بن سعید نے بیان کیا کہ مجھ سے میرے گھر کی ایک عورت نے بیان کیا کہا کہ انہوں نے وہ چادر ام خالد رضی اللہ عنہا کے پاس دیکھی تھی۔' WHERE id = 5619;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن مسلمہ نے بیان کیا، ان سے امام مالک نے، ان سے ابوالزناد نے، ان سے اعرج نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ جب تم میں سے کوئی شخص جوتا پہنے تو دائیں طرف سے شروع کرے اور جب اتارے تو بائیں طرف سے اتارے تاکہ داہنی جانب پہننے میں اول ہو اور اتارنے میں آخر ہو۔' WHERE id = 5629;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے یحییٰ بن ابی کثیر نے بیان کیا، ان سے عبیداللہ نے بیان کیا، کہا کہ مجھ سے نافع نے بیان کیا اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے کہ رسول اللہ صلی اللہ علیہ وسلم نے سونے کی ایک انگوٹھی بنوائی اور اس کا نگینہ ہتھیلی کی جانب رکھا پھر کچھ دوسرے لوگوں نے بھی اسی طرح کی انگوٹھیاں بنوا لیں۔ آخر نبی کریم صلی اللہ علیہ وسلم نے اسے پھینک دیا اور چاندی کی انگوٹھی بنوا لی۔' WHERE id = 5639;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے قتادہ نے اور ان سے انس بن مالک رضی اللہ عنہ نے بیان کیا کہ جب نبی کریم صلی اللہ علیہ وسلم نے روم ( کے بادشاہ کو ) خط لکھانا چاہا تو آپ سے کہا گیا کہ اگر آپ کے خط پر مہر نہ ہوئی تو وہ خط نہیں پڑھتے۔ چنانچہ آپ صلی اللہ علیہ وسلم نے چاندی کی ایک انگوٹھی بنوائی اس پر لفظ «محمد رسول الله» کندہ کرایا۔ جیسے نبی کریم صلی اللہ علیہ وسلم کے ہاتھ میں اس کی سفیدی اب بھی میں دیکھ رہا ہوں۔' WHERE id = 5649;
UPDATE hadiths SET urdu = 'ہم سے محمد بن بشار نے بیان کیا، کہا ہم سے غندر نے بیان کیا، ان سے شعبہ نے بیان کیا، ان سے قتادہ نے، ان سے عکرمہ نے اور ان سے ابن عباس رضی اللہ عنہما نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے ان مردوں پر لعنت بھیجی جو عورتوں جیسا چال چلن اختیار کریں اور ان عورتوں پر لعنت بھیجی جو مردوں جیسا چال چلن اختیار کریں۔ غندر کے ساتھ اس حدیث کو عمرو بن مرزوق نے بھی شعبہ سے روایت کیا۔' WHERE id = 5659;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا، کہا ہم سے حماد بن زید نے بیان کیا، ان سے ثابت نے بیان کیا کہ انس رضی اللہ عنہ سے نبی کریم صلی اللہ علیہ وسلم کے خضاب کے متعلق سوال کیا گیا تو احول نے کہا کہ نبی کریم صلی اللہ علیہ وسلم کو خضاب کی نوبت ہی نہیں آئی تھی اگر میں آپ کی داڑھی کے سفید بال گننا چاہتا تو گن سکتا تھا۔' WHERE id = 5669;
UPDATE hadiths SET urdu = 'مجھ سے عمرو بن علی نے بیان کیا، کہا ہم سے وہب بن جریر نے، کہا کہ مجھ سے میرے والد نے بیان کیا، ان سے قتادہ نے بیان کیا کہ میں نے انس بن مالک رضی اللہ عنہ سے رسول اللہ صلی اللہ علیہ وسلم کے بالوں کے متعلق پوچھا تو انہوں نے کہا کہ آپ کے بال درمیانہ تھے، نہ بالکل سیدھے لٹکے ہوئے اور نہ گھونگھریالے اور وہ کانوں اور مونڈھوں کے بیچ تک تھے۔' WHERE id = 5679;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ مدینی نے بیان کیا، کہا ہم سے فضل بن عنبسہ نے بیان کیا، کہا ہم کو ہشیم بن بشیر نے خبر دی، کہا ہم کو ابوالبشر جعفر نے خبر دی (دوسری سند) امام بخاری رحمہ اللہ نے کہا اور ہم سے قریبہ بن سعید نے کہا کہ ہم سے ہشیم نے بیان کیا، ان سے ابوبشر نے، ان سے سعید بن جبیر نے اور ان سے ابن عباس رضی اللہ عنہما نے بیان کیا کہ میں نے ایک رات اپنی خالہ ام المؤمنین میمونہ بنت حارث رضی اللہ عنہا کے گھر گزاری، رسول اللہ صلی اللہ علیہ وسلم کے لیے اس رات انہیں کے ہاں باری تھی۔ ابن عباس رضی اللہ عنہما نے بیان کیا کہ پھر نبی کریم صلی اللہ علیہ وسلم رات کی نماز پڑھنے کھڑے ہوئے تو میں بھی آپ کے بائیں طرف کھڑا ہو گیا۔ ابن عباس رضی اللہ عنہما نے بیان کیا کہ اس پر نبی کریم صلی اللہ علیہ وسلم نے میرے سر کے بالوں کی ایک لٹ پکڑی اور مجھے اپنی داہنی طرف کر دیا۔' WHERE id = 5691;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم نے بیان کیا، کہا ہم سے عروہ بن ثابت انصاری نے بیان کیا، کہا کہ مجھ سے ثمامہ بن عبداللہ نے بیان کیا اور ان سے انس رضی اللہ عنہ نے کہ ( جب ان کو ) خوشبو ( ہدیہ کی جاتی تو ) آپ وہ واپس نہیں کیا کرتے تھے اور کہتے کہ نبی کریم صلی اللہ علیہ وسلم بھی خوشبو کو واپس نہیں فرمایا کرتے تھے۔' WHERE id = 5701;
UPDATE hadiths SET urdu = 'ہم سے اسحاق بن ابراہیم بن راہویہ نے بیان کیا، کہا ہم کو جریر نے خبر دی، انہیں منصور نے، انہیں ابراہیم نخعی نے اور ان سے علقمہ نے کہ عبداللہ بن مسعود رضی اللہ عنہ نے خوبصورتی کے لیے گودنے والیوں، چہرے کے بال اکھاڑنے والیوں اور سامنے کے دانتوں کے درمیان کشادگی پیدا کرنے والیوں جو اللہ کی پیدائش میں تبدیلی کرتی ہیں، ان سب پر لعنت بھیجی تو ام یعقوب نے کہا کہ یہ کیا بات ہوئی۔ عبداللہ بن مسعود رضی اللہ عنہ نے کہا آخر میں کیوں نہ ان پر لعنت بھیجوں جن پر رسول اللہ صلی اللہ علیہ وسلم نے لعنت بھیجی ہے اور کتاب اللہ میں اس پر لعنت موجود ہے۔ ام یعقوب نے کہا کہ اللہ کی قسم! میں نے پورا قرآن مجید پڑھ ڈالا اور کہیں بھی ایسی کوئی آیت مجھے نہیں ملی۔ عبداللہ بن مسعود رضی اللہ عنہ نے کہا: اللہ کی قسم! اگر تم نے پڑھا ہوتا تو تمہیں ضرور مل جاتا کیا تم کو یہ آیت معلوم نہیں «وما آتاكم الرسول فخذوه وما نهاكم عنه فانتهوا‏» یعنی ”اور جو کچھ رسول تمہیں دیں اسے لے لو اور جس سے بھی تمہیں منع کریں اس سے رک جاؤ۔“' WHERE id = 5711;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا، کہا ہم سے ابن ابی ذئب نے بیان کیا، ان سے زہری نے، ان سے عبیداللہ بن عبداللہ بن عتبہ نے، ان سے ابن عباس رضی اللہ عنہما نے اور ان سے ابوطلحہ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ رحمت کے فرشتے اس گھر میں داخل نہیں ہوتے جس میں کتا یا مورتیں ہوں۔ اور لیث بن سعد نے بیان کیا، ان سے یونس بن یزید نے، ان سے ابن شہاب نے کہا کہ مجھ کو عبیداللہ بن عبداللہ بن عتبہ نے خبر دی، انہوں نے ابن عباس رضی اللہ عنہما سے سنا، وہ کہتے تھے کہ میں نے ابوطلحہ رضی اللہ عنہ سے سنا، پھر انہوں نے نبی کریم صلی اللہ علیہ وسلم سے یہی حدیث نقل کی ہے۔' WHERE id = 5722;
UPDATE hadiths SET urdu = 'ہم سے عمران بن میسرہ نے بیان کیا، کہا ہم سے عبدالوارث نے بیان کیا، کہا ہم سے عبدالعزیز بن صہیب نے اور ان سے انس رضی اللہ عنہ نے بیان کیا کہ عائشہ رضی اللہ عنہا کے پاس ایک پردہ تھا۔ اسے انہوں نے گھر کے ایک کنارے پر لٹکا دیا تھا تو نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ یہ پردہ نکال ڈال، اس کی مورت اس نماز میں میرے سامنے آتی ہیں اور دل اچاٹ ہوتا ہے۔' WHERE id = 5732;
UPDATE hadiths SET urdu = 'ہم سے احمد بن یونس نے بیان کیا، کہا ہم سے ابراہیم بن سعد نے بیان کیا، کہا ہم سے ابن شہاب نے بیان کیا، ان سے عبادہ بن تمیم نے، ان سے ان کے چچا (عبداللہ بن زید انصاری رضی اللہ عنہ) نے کہ انہوں نے رسول اللہ صلی اللہ علیہ وسلم کو مسجد میں ( چت ) لیٹے ہوئے دیکھا کہ آپ ایک پاؤں کو دوسرے پاؤں پر اٹھا کر رکھے ہوئے تھے۔' WHERE id = 5742;
UPDATE hadiths SET urdu = 'اور لیث نے بیان کیا کہ مجھ سے ہشام نے بیان کیا، ان سے عروہ نے اور ان سے اسماء رضی اللہ عنہا نے بیان کیا کہ میری والدہ مشرکہ تھیں وہ نبی کریم صلی اللہ علیہ وسلم کے قریش کے ساتھ صلح کے زمانہ میں اپنے والد کے ساتھ ( مدینہ منورہ ) آئیں۔ میں نے نبی کریم صلی اللہ علیہ وسلم سے ان کے متعلق پوچھا کہ میری والدہ آئی ہیں اور وہ اسلام سے الگ ہیں ( کیا میں ان کے ساتھ صلہ رحمی کر سکتی ہوں؟ ) نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ ہاں اپنی والدہ کے ساتھ صلہ رحمی کرو۔' WHERE id = 5752;
UPDATE hadiths SET urdu = 'ہم سے سعید بن ابی مریم نے بیان کیا، انہوں نے کہا ہم سے سلیمان بن بلال نے، انہوں نے کہا مجھ کو معاویہ بن ابی مزرد نے خبر دی، انہوں نے یزید بن رومان سے، انہوں نے عروہ سے، ام المؤمنین انہوں نے عائشہ رضی اللہ عنہا سے کہ آپ صلی اللہ علیہ وسلم نے فرمایا کہ رحم ( رشتہ داری رحمن سے ملی ہوئی ) شاخ ہے جو شخص اس سے ملے میں اس سے ملتا ہوں اور جو اس سے قطع تعلق کرے میں اس سے قطع تعلق کرتا ہوں۔' WHERE id = 5762;
UPDATE hadiths SET urdu = 'ہم سے ابن ابی مریم نے بیان کیا، کہا ہم سے ابوغسان نے، کہا کہ مجھ سے زید بن اسلم نے، ان سے ان کے والد نے اور ان سے عمر بن خطاب رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم کے پاس کچھ قیدی آئے قیدیوں میں ایک عورت تھی جس کا پستان دودھ سے بھرا ہوا تھا اور وہ دوڑ رہی تھی، اتنے میں ایک بچہ اس کو قیدیوں میں ملا اس نے جھٹ اپنے پیٹ سے لگا لیا اور اس کو دودھ پلانے لگی۔ ہم سے نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ کیا تم خیال کر سکتے ہو کہ یہ عورت اپنے بچے کو آگ میں ڈال سکتی ہے ہم نے عرض کیا کہ نہیں جب تک اس کو قدرت ہو گی یہ اپنے بچے کو آگ میں نہیں پھینک سکتی۔ نبی کریم صلی اللہ علیہ وسلم نے اس پر فرمایا کہ اللہ اپنے بندوں پر اس سے بھی زیادہ رحم کرنے والا ہے جتنا یہ عورت اپنے بچہ پر مہربان ہو سکتی ہے۔' WHERE id = 5772;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل بن ابی اویس نے بیان کیا، کہا مجھ سے امام مالک نے بیان کیا، ان سے ابوبکر کے غلام سمی نے، ان سے ابوصالح سمان نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ ایک شخص راستہ میں چل رہا تھا کہ اسے شدت کی پیاس لگی اسے ایک کنواں ملا اور اس نے اس میں اتر کر پانی پیا۔ جب باہر نکلا تو وہاں ایک کتا دیکھا جو ہانپ رہا تھا اور پیاس کی وجہ سے تری کو چاٹ رہا تھا۔ اس شخص نے کہا کہ یہ کتا بھی اتنا ہی زیادہ پیاسا معلوم ہو رہا ہے جتنا میں تھا۔ چنانچہ وہ پھر کنویں میں اترا اور اپنے جوتے میں پانی بھرا اور منہ سے پکڑ کر اوپر لایا اور کتے کو پانی پلایا۔ اللہ تعالیٰ نے اس کے اس عمل کو پسند فرمایا اور اس کی مغفرت کر دی۔ صحابہ کرام رضی اللہ عنہم نے عرض کیا کہ یا رسول اللہ! کیا ہمیں جانوروں کے ساتھ نیکی کرنے میں بھی ثواب ملتا ہے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ تمہیں ہر تازہ کلیجے والے پر نیکی کرنے میں ثواب ملتا ہے۔' WHERE id = 5782;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، انہوں نے کہا ہم سے لیث بن سعد نے بیان کیا، انہوں نے کہا کہ مجھ سے سعید مقبری نے بیان کیا، ان سے ابوشریح عدوی رضی اللہ عنہ نے بیان کیا انہوں نے کہا کہ میرے کانوں نے سنا اور میری آنکھوں نے دیکھا جب رسول اللہ صلی اللہ علیہ وسلم گفتگو فرما رہے تھے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ جو شخص اللہ اور آخرت کے دن پر ایمان رکھتا ہو وہ اپنے پڑوسی کا اکرام کرے اور جو شخص اللہ اور آخرت کے دن پر ایمان رکھتا ہو وہ اپنے مہمان کی دستور کے موافق ہر طرح سے عزت کرے۔ پوچھا: یا رسول اللہ! دستور کے موافق کب تک ہے۔ فرمایا ایک دن اور ایک رات اور میزبانی تین دن کی ہے اور جو اس کے بعد ہو وہ اس کے لیے صدقہ ہے اور جو اللہ اور آخرت کے دن پر ایمان رکھتا ہو وہ بہتر بات کہے یا خاموش رہے۔' WHERE id = 5792;
UPDATE hadiths SET urdu = 'ہم سے اصبغ بن فرج نے بیان کیا، انہوں نے کہا کہ مجھے عبداللہ بن وہب نے خبر دی انہوں نے کہا ہم کو ابویحییٰ فلیح بن سلیمان نے خبر دی، انہیں ہلال بن اسامہ نے بیان کیا اور ان سے انس بن مالک رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نہ گالی دیتے تھے نہ بدگو تھے نہ بدخو تھے اور نہ لعنت ملامت کرتے تھے۔ اگر ہم میں سے کسی پر ناراض ہوتے اتنا فرماتے اسے کیا ہو گیا ہے، اس کی پیشانی میں خاک لگے۔' WHERE id = 5803;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے قتادہ نے اور ان سے انس بن مالک رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”کوئی شخص ایمان کی حلاوت ( مٹھاس ) اس وقت تک نہیں پا سکتا جب تک وہ کسی شخص سے محبت کرئے تو صرف اللہ کے لیے کرے اور اس کو آگ میں ڈالا جانا اچھا لگے لیکن ایمان کے بعد کفر میں جانا اسے پسند نہ ہو، اور جب تک اللہ اور اس کے رسول سے اسے ان کے سوا دوسری تمام چیزوں کے مقابلے میں زیادہ محبت نہ ہو۔' WHERE id = 5813;
UPDATE hadiths SET urdu = 'ہم سے حفص بن عمر حوضی نے بیان کیا، کہا ہم سے یزید بن ابراہیم نے بیان کیا، کہا ہم سے محمد بن سیرین نے بیان کیا اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے ہمیں ظہر کی نماز دو رکعت پڑھائی اور سلام پھیر دیا اس کے بعد آپ مسجد کے آگے کے حصہ یعنی دالان میں ایک لکڑی پر سہارا لے کر کھڑے ہو گئے اور اس پر اپنا ہاتھ رکھا، حاضرین میں ابوبکر اور عمر رضی اللہ عنہما بھی موجود تھے مگر آپ کے دبدبے کی وجہ سے کچھ بول نہ سکے اور جلد باز لوگ مسجد سے باہر نکل گئے آپس میں صحابہ نے کہا کہ شاید نماز میں رکعات کم ہو گئیں ہیں اسی لیے نبی کریم صلی اللہ علیہ وسلم نے ظہر کی نماز چار کے بجائے صرف دو ہی رکعات پڑھائیں ہیں۔ حاضرین میں ایک صحابی تھے جنہیں آپ ذوالیدین ( لمبے ہاتھوں والا ) کہہ کر مخاطب فرمایا کرتے تھے، انہوں نے عرض کیا: اے اللہ کے نبی! نماز کی رکعات کم ہو گئیں ہیں یا آپ بھول گئے ہیں؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ نہ میں بھولا ہوں اور نہ نماز کی رکعات کم ہوئیں ہیں۔ صحابہ نے عرض کیا: نہیں یا رسول اللہ! آپ بھول گئے ہیں، چنانچہ آپ نے یاد کر کے فرمایا کہ ذوالیدین نے صحیح کہا ہے۔ پھر آپ کھڑے ہوئے اور دو رکعات اور پڑھائیں پھر سلام پھیرا اور تکبیر کہہ کر سجدہ ( سجدہ سہو ) میں گئے، نماز کے سجدہ کی طرح بلکہ اس سے بھی زیادہ لمبا سجدہ کیا پھر سر اٹھایا اور تکبیر کہہ کر پھر سجدہ میں گئے پہلے سجدہ کی طرح یا اس سے بھی لمبا، پھر سر اٹھایا اور تکبیر کہی۔' WHERE id = 5823;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے خالد نے، ان سے عبدالرحمٰن بن ابی بکرہ نے، ان سے ان کے والد نے نبی کریم صلی اللہ علیہ وسلم کی مجلس میں ایک شخص کا ذکر آیا تو ایک دوسرے شخص نے ان کی مبالغہ سے تعریف کی تو نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ افسوس تم نے اپنے ساتھی کی گردن توڑ دی۔ نبی کریم صلی اللہ علیہ وسلم نے یہ جملہ کئی بار فرمایا، اگر تمہارے لیے کسی کی تعریف کرنی ضروری ہو تو یہ کہنا چاہیئے کہ میں اس کے متعلق ایسا خیال کرتا ہوں، باقی علم اللہ کو ہے وہ ایسا ہے۔ اگر اس کو یہ معلوم ہو کہ وہ ایسا ہی ہے اور یوں نہ کہے کہ وہ اللہ کے نزدیک اچھا ہی ہے۔ اور وہیب نے اسی سند کے ساتھ خالد سے یوں روایت کی ارے تیری خرابی تو نے اس کی گردن کاٹ ڈالی یعنی لفظ «ويحك» کے بجائے لفظ «ويلك» بیان کیا۔' WHERE id = 5833;
UPDATE hadiths SET urdu = 'ہم سے محمد بن کثیر نے بیان کیا، انہوں نے کہا ہم کو سفیان بن عیینہ نے خبر دی، انہوں نے کہا ہم سے معبد بن خالد قیسی نے بیان کیا، ان سے حارثہ بن وہب خزاعی رضی اللہ عنہ نے بیان کیا نبی کریم صلی اللہ علیہ وسلم نے فرمایا کیا میں تمہیں جنت والوں کی خبر نہ دوں۔ ہر کمزور و تواضع کرنے والا اگر وہ ( اللہ کا نام لے کر ) قسم کھا لے تو اللہ اس کی قسم پوری کر دے۔ کیا میں تمہیں دوزخ والوں کی خبر نہ دوں ہر تند خو، اکڑ کر چلنے والا اور متکبر۔' WHERE id = 5843;
UPDATE hadiths SET urdu = 'ہم سے حبان بن موسیٰ نے بیان کیا، کہا ہم کو عبداللہ نے خبر دی، کہا ہم کو معمر نے خبر دی، انہیں زہری نے، انہیں عروہ نے اور انہیں عائشہ رضی اللہ عنہا نے کہ رفاعہ قرظی نے اپنی بیوی کو طلاق دے دی اور طلاق رجعی نہیں دی۔ اس کے بعد ان سے عبدالرحمٰن بن زبیر رضی اللہ عنہما نے نکاح کر لیا، لیکن وہ نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئیں اور عرض کیا: یا رسول اللہ! میں رفاعہ رضی اللہ عنہ کے نکاح میں تھی لیکن انہوں نے مجھے تین طلاقیں دے دیں۔ پھر مجھ سے عبدالرحمٰن بن زبیر رضی اللہ عنہما نے نکاح کر لیا، لیکن اللہ کی قسم ان کے پاس تو پلو کی طرح کے سوا اور کچھ نہیں۔ ( مراد یہ کہ وہ نامرد ہیں ) اور انہوں نے اپنے چادر کا پلو پکڑ کر بتایا ( راوی نے بیان کیا کہ ) ابوبکر رضی اللہ عنہ نبی کریم صلی اللہ علیہ وسلم کے پاس بیٹھے ہوئے تھے اور سعید بن العاص کے لڑکے خالد حجرہ کے دروازے پر تھے اور اندر داخل ہونے کی اجازت کے منتظر تھے۔ خالد بن سعید اس پر ابوبکر رضی اللہ عنہ کو آواز دے کر کہنے لگے کہ آپ اس عورت کو ڈانتے نہیں کہ نبی کریم صلی اللہ علیہ وسلم کے سامنے کس طرح کی بات کہتی ہے اور نبی کریم صلی اللہ علیہ وسلم نے تبسم کے سوا اور کچھ نہیں فرمایا۔ پھر فرمایا، غالباً تم رفاعہ کے پاس دوبارہ جانا چاہتی ہو لیکن یہ اس وقت تک ممکن نہیں ہے جب تک تم ان کا ( عبدالرحمٰن رضی اللہ عنہ کا ) مزا نہ چکھ لو اور وہ تمہارا مزہ نہ چکھ لیں۔' WHERE id = 5854;
UPDATE hadiths SET urdu = 'ہم سے محمد بن سلام نے بیان کیا، کہا ہم سے اسماعیل بن جعفر نے بیان کیا، ان سے ابی سہیل نافع بن مالک بن ابی عامر نے، ان سے ان کے والد مالک بن ابی عامر نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”منافق کی تین نشانیاں ہیں، جب بولتا ہے جھوٹ بولتا ہے، جب وعدہ کرتا ہے خلاف کرتا ہے اور جب اسے امین بنایا جاتا ہے تو خیانت کرتا ہے۔“' WHERE id = 5864;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، کہا ہم سے وہیب نے بیان کیا، کہا ہم سے ایوب سختیانی نے بیان کیا، ان سے ابوقلابہ نے، ان سے ثابت بن ضحاک رضی اللہ عنہ نے اور ان سے نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ جس نے اسلام کے سوا کسی اور مذہب کی جھوٹ موٹ قسم کھائی تو وہ ویسا ہی ہو جاتا ہے، جس کی اس نے قسم کھائی ہے اور جس نے کسی چیز سے خودکشی کر لی تو اسے جہنم میں اسی سے عذاب دیا جائے گا اور مومن پر لعنت بھیجنا اسے قتل کرنے کے برابر ہے اور جس نے کسی مومن پر کفر کی تہمت لگائی تو یہ اس کے قتل کے برابر ہے۔' WHERE id = 5874;
UPDATE hadiths SET urdu = 'ہم سے عثمان بن ابی شیبہ نے بیان کیا، کہا ہم سے جریر نے بیان کیا، ان سے اعمش نے، ان سے عدی بن ثابت نے، ان سے سلیمان بن صرد رضی اللہ عنہ نے بیان کیا کہ دو آدمیوں نے نبی کریم صلی اللہ علیہ وسلم کی موجودگی میں جھگڑا کیا، ہم بھی نبی کریم صلی اللہ علیہ وسلم کی خدمت میں بیٹھے ہوئے تھے۔ ایک شخص دوسرے کو غصہ کی حالت میں گالی دے رہا تھا اور اس کا چہرہ سرخ تھا، نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ میں ایک ایسا کلمہ جانتا ہوں کہ اگر یہ شخص اسے کہہ لے تو اس کا غصہ دور ہو جائے۔ اگر یہ «أعوذ بالله من الشيطان الرجيم» کہہ لے۔ صحابہ نے اس سے کہا کہ سنتے نہیں، نبی کریم صلی اللہ علیہ وسلم کیا فرما رہے ہیں؟ اس نے کہا کہ کیا میں دیوانہ ہوں؟' WHERE id = 5884;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا، انہوں نے کہا ہم سے شعبہ نے بیان کیا، ان سے ابوالتیاح نے بیان کیا، انہوں نے انس بن مالک رضی اللہ عنہ سے سنا، انہوں نے کہا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”آسانی پیدا کرو، تنگی نہ پیدا کرو، لوگوں کو تسلی اور تشفی دو نفرت نہ دلاؤ۔“' WHERE id = 5894;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، کہا ہم کو امام مالک نے خبر دی، انہیں سعید بن ابی سعید مقبری نے، انہیں ابوشریح کعبی رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”جو شخص اللہ اور آخرت کے دن پر ایمان رکھتا ہو اسے اپنے مہمان کی عزت کرنا چاہیئے۔ اس کی خاطر داری بس ایک دن اور رات کی ہے مہمانی تین دن اور راتوں کی، اس کے بعد جو ہو وہ صدقہ ہے اور مہمان کے لیے جائز نہیں کہ وہ اپنے میزبان کے پاس اتنے دن ٹھہر جائے کہ اسے تنگ کر ڈالے۔“' WHERE id = 5904;
UPDATE hadiths SET urdu = 'ہم سے محمد بن بشار نے بیان کیا، انہوں نے کہا ہم سے عبدالرحمٰن بن مہدی نے بیان کیا، ان سے سفیان نے بیان کیا، ان سے عبدالملک نے، انہوں نے کہا ہم سے ابوسلمہ نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کی شعراء کے کلام میں سے سچا کلمہ لبید کا مصرعہ ہے جو یہ ہے کہ اللہ کے سوا جو کچھ ہے سب معدوم و فنا ہونے والا ہے۔ امیہ بن ابی الصلت شاعر تو قریب تھا کہ مسلمان ہو جائے۔' WHERE id = 5915;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا، انہوں نے کہا ہم سے شعبہ نے بیان کیا، انہوں نے کہا ہم سے حکم بن عتیبہ نے بیان کیا، ان سے ابراہیم نخعی نے، ان سے اسود نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے ( حج سے ) واپسی کا ارادہ کیا تو دیکھا کہ صفیہ رضی اللہ عنہا اپنے خیمے کے دروازہ پر رنجیدہ کھڑی ہیں کیونکہ وہ حائضہ ہو گئی تھیں۔ نبی کریم صلی اللہ علیہ وسلم نے ان سے فرمایا «عقرى حلقى» ( یہ قریش کا محاورہ ہے ) اب تم ہمیں روکو گی! پھر دریافت فرمایا کیا تم نے قربانی کے دن طواف افاضہ کر لیا تھا؟ انہوں نے کہا کہ جی ہاں، فرمایا کہ پھر چلو۔' WHERE id = 5925;
UPDATE hadiths SET urdu = 'ہم سے عمرو بن عاصم نے بیان کیا، کہا ہم سے ہمام بن یحییٰ نے بیان کیا، ان سے قتادہ نے اور ان سے انس نے کہ ایک بدوی نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوا اور پوچھا: یا رسول اللہ! قیامت کب آئے گی؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا، افسوس «ويلك» تم نے اس قیامت کے لیے کیا تیاری کر لی ہے؟ انہوں نے عرض کیا میں نے اس کے لیے تو کوئی تیاری نہیں کی ہے البتہ میں اللہ اور اس کے رسول سے محبت رکھتا ہوں۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ پھر تم قیامت کے دن ان کے ساتھ ہو، جس سے تم محبت رکھتے ہو۔ ہم نے عرض کیا اور ہمارے ساتھ بھی یہی معاملہ ہو گا؟ فرمایا کہ ہاں۔ ہم اس دن بہت زیادہ خوش ہوئے، پھر مغیرہ کے ایک غلام وہاں سے گزرے وہ میرے ہم عمر تھے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اگر یہ بچہ زندہ رہا تو اس کے بڑھاپا آنے سے پہلے قیامت قائم ہو جائے گی۔' WHERE id = 5935;
UPDATE hadiths SET urdu = 'ہم سے محمد بن یوسف نے بیان کیا، کہا ہم سے سفیان نے بیان کیا، ان سے ہشام بن عروہ نے، ان سے ان کے والد نے اور ان سے عائشہ رضی اللہ عنہا نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”تم میں کوئی شخص یہ نہ کہے کہ میرا نفس پلید ہو گیا ہے بلکہ یہ کہے کہ میرا دل خراب یا پریشان ہو گیا۔“' WHERE id = 5945;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد مسندی نے بیان کیا، کہا ہم سے سفیان نے بیان کیا، کہا کہ میں نے محمد بن المنکدر سے سنا کہ کہا کہ میں نے جابر بن عبداللہ انصاری رضی اللہ عنہما سے سنا کہ ہم میں سے ایک آدمی کے یہاں بچہ پیدا ہوا تو انہوں نے اس کا نام قاسم رکھا۔ صحابہ نے کہا کہ ہم تمہاری کنیت ابوالقاسم نہیں رکھیں گے اور نہ تیری آنکھ اس کنیت سے پکار کر ٹھنڈی کریں گے۔ وہ شخص نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوا اور آپ سے اس کا ذکر کیا۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ اپنے لڑکے کا نام عبدالرحمٰن رکھ لو۔' WHERE id = 5955;
UPDATE hadiths SET urdu = 'ہم سے ابوالولید نے بیان کیا، کہا ہم سے زائدہ نے، کہا ہم سے زیاد بن علاقہ نے، کہا ہم نے مغیرہ بن شعبہ رضی اللہ عنہ سے سنا، بیان کیا کہ جس دن ابراہیم رضی اللہ عنہ کی وفات ہوئی اس دن سورج گرہن ہوا تھا۔ اس کو ابوبکرہ نے بھی نبی کریم صلی اللہ علیہ وسلم سے روایت کیا ہے۔' WHERE id = 5965;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا، کہا ہم سے شعبہ نے، ان سے ثابت بنانی نے، ان سے انس بن مالک رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم ایک سفر میں تھے، راستہ میں حدی خواں نے حدی پڑھی تو نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”اے انجشہ! شیشوں کو آہستہ آہستہ لے کر چل، تجھ پر افسوس۔“' WHERE id = 5975;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، انہوں نے کہا ہم کو شعیب نے خبر دی، انہیں زہری نے (دوسری سند) اور ہم سے اسماعیل بن ابی اویس نے بیان کیا، انہوں نے کہا کہ مجھ سے میرے بھائی عبدالحمید نے بیان کیا، ان سے سلیمان نے بیان کیا، ان سے محمد بن ابی عتیق نے بیان کیا، ان سے ابن شہاب نے بیان کیا، ان سے امام زین العابدین علی بن حسین نے کہ نبی کریم صلی اللہ علیہ وسلم کی زوجہ مطہرہ صفیہ بنت حی رضی اللہ عنہا نے انہیں خبر دی کہ وہ نبی کریم صلی اللہ علیہ وسلم کے پاس ملنے آئیں۔ نبی کریم صلی اللہ علیہ وسلم اس وقت مسجد میں رمضان کے آخری عشرہ میں اعتکاف کئے ہوئے تھے۔ عشاء کے وقت تھوڑی دیر انہوں نے نبی کریم صلی اللہ علیہ وسلم سے باتیں کیں اور واپس لوٹنے کے لیے اٹھیں تو نبی کریم صلی اللہ علیہ وسلم بھی انہیں چھوڑ آنے کے لیے کھڑے ہو گئے۔ جب وہ مسجد کے اس دروازہ کے پاس پہنچیں جہاں نبی کریم صلی اللہ علیہ وسلم کی زوجہ مطہرہ ام سلمہ رضی اللہ عنہا کا حجرہ تھا، تو ادھر سے دو انصاری صحابی گزرے اور نبی کریم صلی اللہ علیہ وسلم کو سلام کیا اور آگے بڑھ گئے۔ لیکن نبی کریم صلی اللہ علیہ وسلم نے ان سے فرمایا کہ تھوڑی دیر کے لیے ٹھہر جاؤ۔ یہ صفیہ بنت حی میری بیوی ہیں۔ ان دونوں صحابہ نے عرض کیا: سبحان اللہ، یا رسول اللہ۔ ان پر بڑا شاق گزرا۔ لیکن آپ صلی اللہ علیہ وسلم نے فرمایا کہ شیطان انسان کے اندر خون کی طرح دوڑتا رہتا ہے، اس لیے مجھے خوف ہوا کہ کہیں وہ تمہارے دل میں کوئی شبہ نہ ڈال دے۔' WHERE id = 5985;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد نے بیان کیا، انہوں نے کہا ہم کو ابوعامر نے خبر دی، انہوں نے کہا ہم سے زہیر نے بیان کیا، ان سے زید بن اسلم نے بیان کیا، ان سے عطاء بن یسار نے بیان کیا اور ان سے ابو سعید خدری رضی اللہ عنہ نے بیان کیاکہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”راستوں پر بیٹھنے سے بچو! صحابہ نے عرض کیا: یا رسول اللہ! ہماری یہ مجالس تو بہت ضروری ہیں، ہم وہیں روزمرہ گفتگو کیا کرتے ہیں۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ اچھا جب تم ان مجلسوں میں بیٹھنا ہی چاہتے ہو تو راستے کا حق ادا کیا کرو یعنی راستے کو اس کا حق دو۔ صحابہ نے عرض کیا: راستے کا حق کیا ہے یا رسول اللہ! فرمایا ( غیر محرم عورتوں کو دیکھنے سے ) نظر نیچی رکھنا، راہ گیروں کو نہ ستانا، سلام کا جواب دینا، بھلائی کا حکم دینا اور برائی سے روکنا۔' WHERE id = 5995;
UPDATE hadiths SET urdu = 'ہم سے ابوالنعمان نے بیان کیا، کہا ہم سے معتمر نے بیان کیا، کہا مجھ سے میرے والد نے بیان کیا کہ ان سے ابومجلز نے بیان کیا اور ان سے انس رضی اللہ عنہ نے بیان کیا کہ جب نبی کریم صلی اللہ علیہ وسلم نے زینب رضی اللہ عنہا سے نکاح کیا تو لوگ اندر آئے اور کھانا کھایا پھر بیٹھ کے باتیں کرتے رہے۔ نبی کریم صلی اللہ علیہ وسلم نے اس طرح اظہار کیا گویا آپ کھڑے ہونا چاہتے ہیں۔ لیکن وہ کھڑے نہیں ہوئے جب نبی کریم صلی اللہ علیہ وسلم نے یہ دیکھا تو کھڑے ہو گئے۔ آپ کے کھڑے ہونے پر قوم کے جن لوگوں کو کھڑا ہونا تھا وہ بھی کھڑے ہو گئے لیکن بعض لوگ اب بھی بیٹھے رہے اور جب نبی کریم صلی اللہ علیہ وسلم اندر داخل ہونے کے لیے تشریف لائے تو کچھ لوگ بیٹھے ہوئے تھے ( آپ واپس ہو گئے ) اور پھر جب وہ لوگ بھی کھڑے ہوئے اور چلے گئے تو میں نے نبی کریم صلی اللہ علیہ وسلم کو اس کی اطلاع دی۔ نبی کریم صلی اللہ علیہ وسلم تشریف لائے اور اندر داخل ہو گئے۔ میں نے بھی اندر جانا چاہا لیکن نبی کریم صلی اللہ علیہ وسلم نے میرے اور اپنے درمیان پردہ ڈال لیا۔ اور اللہ تعالیٰ نے یہ آیت نازل کی «يا أيها الذين آمنوا لا تدخلوا بيوت النبي‏» ”اے ایمان والو! نبی کے گھر میں نہ داخل ہو۔“ آخر تک۔' WHERE id = 6005;
UPDATE hadiths SET urdu = 'ہم سے ابن مقاتل نے بیان کیا، کہا ہم کو عبداللہ نے خبر دی، کہا ہم کو معمر نے خبر دی انہیں زہری نے انہیں ابوسلمہ بن عبدالرحمٰن نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”اے عائشہ! یہ جبرائیل ہیں تمہیں سلام کہتے ہیں بیان کیا کہ میں نے عرض کیا «وعليه السلام ورحمة الله» آپ دیکھتے ہیں جو ہم نہیں دیکھ سکتے ام المؤمنین کا اشارہ نبی کریم صلی اللہ علیہ وسلم کی طرف تھا۔ معمر کے ساتھ اس حدیث کو شعیب اور یونس اور نعمان نے بھی زہری سے روایت کیا ہے یونس اور نعمان کی روایتوں میں «وبركاته‏.» کا لفظ زیادہ ہے۔' WHERE id = 6015;
UPDATE hadiths SET urdu = 'ہم سے یوسف بن بہلول نے بیان کیا، کہا ہم سے ابن ادریس نے بیان کیا، کہا کہ مجھ سے حصین بن عبدالرحمٰن نے بیان کیا، ان سے سعد بن عبیدہ نے، ان سے ابوعبدالرحمٰن سلمی نے اور ان سے علی رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے مجھے زبیر بن عوام اور ابومرثد غنوی کو بھیجا۔ ہم سب گھوڑ سوار تھے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ جاؤ اور جب روضہ خاخ ( مکہ اور مدینہ کے درمیان ایک مقام ) پر پہنچو تو وہاں تمہیں مشرکین کی ایک عورت ملے گی اس کے پاس حاطب بن ابی بلتعہ کا ایک خط ہے جو مشرکین کے پاس بھیجا گیا ہے ( اسے لے آؤ ) ۔ بیان کیا کہ ہم نے اس عورت کو پا لیا وہ اپنے اونٹ پر جا رہی تھی اور وہیں پر ملی ( جہاں ) نبی کریم صلی اللہ علیہ وسلم نے بتایا تھا۔ بیان کیا کہ ہم نے اس سے کہا کہ خط جو تم ساتھ لے جا رہی ہو وہ کہاں ہے؟ اس نے کہا کہ میرے پاس کوئی خط نہیں ہے۔ ہم نے اس کے اونٹ کو بٹھایا اور اس کے کجاوہ میں تلاشی لی لیکن ہمیں کوئی چیز نہیں ملی۔ میرے دونوں ساتھیوں نے کہا کہ ہمیں کوئی خط تو نظر آتا نہیں۔ بیان کیا کہ میں نے کہا، مجھے یقین ہے کہ نبی کریم صلی اللہ علیہ وسلم نے غلط بات نہیں کہی ہے۔ قسم ہے اس کی جس کی قسم کھائی جاتی ہے، تم خط نکالو ورنہ میں تمہیں ننگا کر دوں گا۔ بیان کیا کہ جب اس عورت نے دیکھا کہ میں واقعی اس معاملہ میں سنجیدہ ہوں تو اس نے ازار باندھنے کی جگہ کی طرف ہاتھ بڑھایا، وہ ایک چادر ازار کے طور پر باندھے ہوئے تھی اور خط نکالا۔ بیان کیا کہ ہم اسے لے کر رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئے۔ نبی کریم صلی اللہ علیہ وسلم نے دریافت فرمایا کہ حاطب تم نے ایسا کیوں کیا؟ انہوں نے کہا کہ میں اب بھی اللہ اور اس کے رسول پر ایمان رکھتا ہوں۔ میرے اندر کوئی تغیر و تبدیلی نہیں آئی ہے، میرا مقصد ( خط بھیجنے سے ) صرف یہ تھا کہ ( قریش پر آپ کی فوج کشی کی اطلاع دوں اور اس طرح ) میرا ان لوگوں پر احسان ہو جائے اور اس کی وجہ سے اللہ میرے اہل اور مال کی طرف سے ( ان سے ) مدافعت کرائے۔ آپ کے جتنے مہاجر صحابہ ہیں ان کے مکہ مکرمہ میں ایسے افراد ہیں جن کے ذریعہ اللہ ان کے مال اور ان کے گھر والوں کی حفاظت کرائے گا۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ انہوں نے سچ کہ دیا ہے اب تم لوگ ان کے بارے میں سوا بھلائی کے اور کچھ نہ کہو بیان کیا کہ اس پر عمر بن خطاب رضی اللہ عنہ نے فرمایا کہ اس شخص نے اللہ اور اس کے رسول اور مومنوں کے ساتھ خیانت کی، مجھے اجازت دیجئیے کہ میں اس کی گردن مار دوں بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا: عمر! تمہیں کیا معلوم، اللہ تعالیٰ بدر کی لڑائی میں شریک صحابہ کی زندگی پر مطلع تھا اور اس کے باوجود فرمایا کہ تم جو چاہو کرو، تمہارے لیے جنت لکھ دی گئی ہے، بیان کیا کہ اس پر عمر رضی اللہ عنہ کی آنکھیں اشک آلود ہو گئیں اور عرض کیا: اللہ اور اس کے رسول ہی زیادہ جاننے والے ہیں۔' WHERE id = 6025;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل بن عبداللہ نے بیان کیا، انہوں نے کہا کہ مجھ سے امام مالک نے بیان کیا، ان سے نافع نے بیان کیا اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”کوئی شخص کسی دوسرے شخص کو اس کے بیٹھنے کی جگہ سے نہ اٹھائے کہ خود وہاں بیٹھ جائے۔“' WHERE id = 6035;
UPDATE hadiths SET urdu = 'ہم سے محمد بن کثیر نے بیان کیا، کہا ہم سے سفیان ثوری نے بیان کیا، ان سے ابوحازم نے اور ان سے سہل بن سعد ساعدی رضی اللہ عنہ نے بیان کیا کہ ہم کھانا اور قیلولہ نماز جمعہ کے بعد کیا کرتے تھے۔' WHERE id = 6045;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے بیان کیا، ان سے زہری نے، ان سے سالم نے، ان سے ان کے والد نے اور ان سے نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”جب سونے لگو تو گھر میں آگ نہ چھوڑو۔“' WHERE id = 6057;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ مدینی نے بیان کیا، کہا ہم سے ابوسفیان ثوری نے، ان سے عمرو بن نشار نے اور ان سے ابن عمر رضی اللہ عنہما نے کہا کہ واللہ نبی کریم صلی اللہ علیہ وسلم کی وفات کے بعد نہ میں نے کوئی اینٹ کسی اینٹ پر رکھی اور نہ کوئی باغ لگایا۔ سفیان نے بیان کیا کہ جب میں نے اس کا ذکر ابن عمر رضی اللہ عنہما کے بعض گھرانوں کے سامنے کیا تو انہوں نے کہا کہ اللہ کی قسم انہوں نے گھر بنایا تھا۔ سفیان نے بیان کیا کہ میں نے کہا پھر یہ بات ابن عمر رضی اللہ عنہما نے گھر بنانے سے پہلے کہی ہو گی۔' WHERE id = 6067;
UPDATE hadiths SET urdu = 'ہم سے سعید بن ربیع اور محمد بن عرعرہ نے بیان کیا، ان دونوں نے کہا کہ ہم سے شعبہ نے بیان کیا، ان سے ابواسحاق نے بیان کیا، انہوں نے براء بن عازب رضی اللہ عنہما سے سنا کہ نبی کریم صلی اللہ علیہ وسلم نے ایک صحابی کو حکم دیا ( دوسری سند ) امام بخاری رحمہ اللہ نے کہا کہ ہم سے آدم نے بیان کیا، انہوں نے کہا ہم سے شعبہ نے بیان کیا ان سے ابواسحاق ہمدانی نے بیان کیا، اور ان سے براء بن عازب رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے ایک صحابی کو وصیت کی اور فرمایا کہ جب بستر پر جانے لگو تو یہ دعا پڑھا کرو «اللهم أسلمت نفسي إليك،‏‏‏‏ وفوضت أمري إليك،‏‏‏‏ ووجهت وجهي إليك،‏‏‏‏ وألجأت ظهري إليك،‏‏‏‏ رغبة ورهبة إليك،‏‏‏‏ لا ملجأ ولا منجا منك إلا إليك،‏‏‏‏ آمنت بكتابك الذي أنزلت،‏‏‏‏ وبنبيك الذي أرسلت‏.‏» ”اے اللہ! میں نے اپنی جان تیرے سپرد کی اور اپنا معاملہ تجھے سونپا اور اپنے آپ کو تیری طرف متوجہ کیا اور تجھ پر بھروسہ کیا، تیری طرف رغبت ہے تیرے خوف کی وجہ سے، تجھ سے تیرے سوا کوئی جائے پناہ نہیں، میں تیری کتاب پر ایمان لایا جو تو نے نازل کی اور تیرے نبی پر جنہیں تو نے بھیجا۔“ پھر اگر وہ مرا تو فطرت ( اسلام ) پر مرے گا۔' WHERE id = 6077;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے یزید بن زریع نے بیان کیا، کہا ہم سے حسین نے بیان کیا، کہا ہم سے عبداللہ بن بریدہ نے بیان کیا، ان سے بشیر بن کعب نے اور ان سے شداد بن اوس رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ سب سے عمدہ استغفار یہ ہے «اللهم أنت ربي لا إله إلا أنت،‏‏‏‏ خلقتني وأنا عبدك،‏‏‏‏ وأنا على عهدك ووعدك ما استطعت،‏‏‏‏ أبوء لك بنعمتك،‏‏‏‏ وأبوء لك بذنبي،‏‏‏‏ فاغفر لي،‏‏‏‏ فإنه لا يغفر الذنوب إلا أنت،‏‏‏‏ أعوذ بك من شر ما صنعت‏.‏» ”اے اللہ! تو میرا پالنے والا ہے تیرے سوا کوئی معبود نہیں تو نے مجھے پیدا کیا اور میں تیرا بندہ ہوں اور میں تیرے عہد پر قائم ہوں اور تیرے وعدہ پر۔ جہاں تک مجھ سے ممکن ہے۔ تیری نعمت کا طالب ہو کر تیری پناہ میں آتا ہوں اور اپنے گناہوں سے تیری پناہ چاہتا ہوں، پس تو میری مغفرت فرما کیونکہ تیرے سوا گناہ اور کوئی نہیں معاف کرتا۔ میں تیری پناہ مانگتا ہوں اپنے برے کاموں سے۔ اگر کسی نے رات ہوتے ہی یہ کہہ لیا اور اسی رات اس کا انتقال ہو گیا تو وہ جنت میں جائے گا۔ یا ( فرمایا کہ ) وہ اہل جنت میں ہو گا اور اگر یہ دعا صبح کے وقت پڑھی اور اسی دن اس کی وفات ہو گئی تو بھی ایسا ہی ہو گا۔' WHERE id = 6087;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ مدینی نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے بیان کیا، ان سے اسماعیل بن ابی خالد نے، ان سے قیس نے کہ میں نے جریر بن عبداللہ بجلی سے سنا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ کوئی ایسا مرد مجاہد ہے جو مجھ کو ذی الخلصہ بت سے آرام پہنچائے وہ ایک بت تھا جس کو جاہلیت میں لوگ پوجا کرتے تھے اور اس کو کعبہ کہا کرتے تھے۔ میں نے کہا: یا رسول اللہ! اس خدمت کے لیے میں تیار ہوں لیکن میں گھوڑے پر ٹھیک جم کر بیٹھ نہیں سکتا ہوں آپ نے میرے سینہ پر ہاتھ مبارک پھیر کر دعا فرمائی کہ اے اللہ! اسے ثابت قدمی عطا فرما اور اس کو ہدایت کرنے والا اور نور ہدایت پانے والا بنا۔ جریر نے کہا کہ پھر میں اپنی قوم احمس کے پچاس آدمی لے کر نکلا اور ابی سفیان نے یوں نقل کیا کہ میں اپنی قوم کی ایک جماعت لے کر نکلا اور میں وہاں گیا اور اسے جلا دیا پھر میں نبی کریم صلی اللہ علیہ وسلم کے پاس آیا اور میں نے کہا: اے اللہ کے رسول! اللہ کی قسم! میں آپ کے پاس نہیں آیا جب تک میں نے اسے جلے ہوئے خارش زدہ اونٹ کی طرح سیاہ نہ کر دیا۔ پس آپ نے قبیلہ احمس اور اس کے گھوڑوں کے لیے دعا فرمائی۔' WHERE id = 6097;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، انہوں نے کہا ہم سے وہیب بن خالد نے بیان کیا، انہوں نے کہا ہم سے عمرو بن یحییٰ نے بیان کیا، ان سے عبادہ بن تمیم نے بیان کیا اور ان سے عبداللہ بن زید انصاری رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم اس عیدگاہ میں استسقاء کی دعا کے لیے نکلے اور بارش کی دعا کی، پھر آپ قبلہ رخ ہو گئے اور اپنی چادر کو پلٹا۔' WHERE id = 6107;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف تنیسی نے بیان کیا، کہا ہم سے عبداللہ بن وہب نے بیان کیا، کہا ہم سے سعید بن ابی ایوب نے بیان کیا، ان سے ابوعقیل (زہرہ بن معبد) نے کہ انہیں ان کے دادا عبداللہ بن ہشام رضی اللہ عنہ ساتھ لے کر بازار سے نکلتے یا بازار جاتے اور کھانے کی کوئی چیز خریدتے، پھر اگر عبداللہ بن زبیر یا عبداللہ بن عمر رضی اللہ عنہم کی ان سے ملاقات ہو جاتی تو وہ کہتے کہ ہمیں بھی اس میں شریک کیجئے کہ رسول اللہ صلی اللہ علیہ وسلم نے آپ کے لیے برکت کی دعا فرمائی تھی۔ بعض دفعہ تو ایک اونٹ کے بوجھ کا پورا غلہ نفع میں آ جاتا اور وہ اسے گھر بھیج دیتے تھے۔' WHERE id = 6117;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا ہم سے اسماعیل بن جعفر نے بیان کیا، ان سے عمرو بن ابی عمرو، مطلب بن عبداللہ بن حنطب کے غلام نے بیان کیا، انہوں نے انس بن مالک رضی اللہ عنہ سے سنا، انہوں نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے ابوطلحہ رضی اللہ عنہ سے فرمایا کہ اپنے یہاں کے لڑکوں میں سے کوئی بچہ تلاش کرو جو میرا کام کر دیا کرے۔ چنانچہ ابوطلحہ رضی اللہ عنہ مجھے اپنی سواری پر پیچھے بیٹھا کر لے گئے نبی کریم صلی اللہ علیہ وسلم جب بھی گھر ہوتے تو میں آپ کی خدمت کیا کرتا تھا۔ میں نے سنا کہ نبی کریم صلی اللہ علیہ وسلم یہ دعا اکثر پڑھا کرتے تھے «اللهم إني أعوذ بك من الهم والحزن،‏‏‏‏ والعجز والكسل،‏‏‏‏ والبخل والجبن،‏‏‏‏ وضلع الدين،‏‏‏‏ وغلبة الرجال» ”اے اللہ! میں تیری پناہ مانگتا ہوں غم و الم سے، عاجزی و کمزوری سے اور بخل سے اور بزدلی سے اور قرض کے بوجھ سے اور انسانوں کے غلبہ سے۔“ میں نبی کریم صلی اللہ علیہ وسلم کی خدمت کرتا رہا۔ پھر ہم خیبر سے واپس آئے اور نبی کریم صلی اللہ علیہ وسلم ام المؤمنین صفیہ بنت حیی رضی اللہ عنہا کے ساتھ واپس ہوئے۔ نبی کریم صلی اللہ علیہ وسلم نے انہیں اپنے لیے منتخب کیا تھا۔ نبی کریم صلی اللہ علیہ وسلم نے ان کے لیے عبا یا چادر سے پردہ کیا اور انہیں اپنی سواری پر اپنے پیچھے بٹھایا۔ جب ہم مقام صہبا پہنچے تو آپ نے ایک چرمی دستر خوان پر کچھ مالیدہ تیار کرا کے رکھوایا پھر مجھے بھیجا اور میں کچھ صحابہ کو بلا لایا اور سب نے اسے کھایا، یہ آپ کی دعوت ولیمہ تھی۔ اس کے بعد آپ آگے بڑھے اور احد پہاڑ دکھائی دیا۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا یہ پہاڑ ہم سے محبت کرتا ہے اور ہم اس سے محبت کرتے ہیں۔ آپ جب مدینہ منورہ پہنچے تو فرمایا ”اے اللہ! میں اس شہر کے دونوں پہاڑوں کے درمیانی علاقہ کو اس طرح حرمت والا قرار دیتا ہوں جس طرح ابراہیم علیہ السلام نے مکہ کو حرمت والا قرار دیا تھا۔ اے اللہ! یہاں والوں کے مد میں اور ان کے صاع میں برکت عطا فرما۔“' WHERE id = 6127;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، کہا ہم سے ابراہیم بن سعد نے، کہا ہم کو ابن شہاب نے خبر دی، انہیں عامر بن سعد نے اور ان سے ان کے والد نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم حجۃ الوداع کے موقع پر میری عیادت کے لیے تشریف لائے۔ میری اس بیماری نے مجھے موت سے قریب کر دیا تھا۔ میں نے عرض کیا: یا رسول اللہ! آپ خود مشاہدہ فرما رہے ہیں کہ بیماری نے مجھے کہاں پہنچا دیا ہے اور میرے پاس مال و دولت ہے اور سوا ایک لڑکی کے اس کا اور کوئی وارث نہیں، کیا میں اپنی دولت کا دو تہائی صدقہ کر دوں؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ نہیں۔ میں نے عرض کیا پھر آدھی کا کر دوں؟ فرمایا کہ ایک تہائی بہت ہے اگر تم اپنے وارثوں کو مالدار چھوڑو تو یہ اس سے بہتر ہے کہ انہیں محتاج چھوڑو اور وہ لوگوں کے سامنے ہاتھ پھیلاتے پھریں اور یقین رکھو کہ تم جو کچھ بھی خرچ کرو گے اور اس سے مقصود اللہ کی خوشنودی ہوئی تمہیں تو اس پر ثواب ملے گا، یہاں تک کہ اگر تم اپنی بیوی کے منہ میں لقمہ رکھو ( تو اس پر بھی ثواب ملے گا ) میں نے عرض کیا میں اپنے ساتھیوں سے پیچھے چھوڑ دیا جاؤں گا؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اگر تم پیچھے چھوڑ دئیے جاؤ اور پھر کوئی عمل کرو جس سے مقصود اللہ کی رضا ہو تو تمہارا مرتبہ بلند ہو گا اور امید ہے کہ تم ابھی زندہ رہو گے اور کچھ قومیں تم سے فائدہ اٹھائیں گی اور کچھ نقصان اٹھائیں گی۔ اے اللہ! میرے صحابہ کی ہجرت کو کامیاب فرما اور انہیں الٹے پاؤں واپس نہ کر، البتہ افسوس سعد بن خولہ کا ہے۔ سعد نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے ان پر افسوس کا اظہار اس وجہ سے کیا تھا کہ ان کا انتقال مکہ معظمہ میں ہو گیا تھا۔' WHERE id = 6137;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، انہوں نے کہا ہم سے حماد بن زید رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے عبدالرحمٰن بن عوف رضی اللہ عنہ پر زردی کا اثر دیکھا تو فرمایا یہ کیا ہے؟ کہا کہ میں نے ایک عورت سے ایک گٹھلی کے برابر سونے پر شادی کی ہے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اللہ تمہیں برکت عطا فرمائے، ولیمہ کر، چاہے ایک بکری کا ہی ہو۔' WHERE id = 6148;
UPDATE hadiths SET urdu = 'ہم سے محمد بن مثنی ٰ نے بیان کیا، انہوں نے کہا ہم سے انصاری نے بیان کیا، ان سے ہشام بن حسان نے بیان کیا، کہا ہم سے محمد بن سیرین نے بیان کیا، ان سے عبیدہ نے بیان کیا، کہا ہم سے علی بن ابی طالب رضی اللہ عنہ نے بیان کیا کہ غزوہ خندق کے موقع پر ہم رسول اللہ صلی اللہ علیہ وسلم کے ساتھ تھے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”اللہ ان کی قبروں اور ان کے گھروں کو آگ سے بھر دے۔ انہوں نے ہمیں «صلاة الوسطى» ( عصر کی نماز ) نہیں پڑھنے دی جب تک کہ سورج غروب ہو گیا اور یہ عصر کی نماز تھی۔' WHERE id = 6158;
UPDATE hadiths SET urdu = 'ہم سے زہیر بن حرب نے بیان کیا، انہوں نے کہا ہم سے ابن فضیل نے بیان کیا، ان سے عمارہ نے، ان سے ابوزرعہ نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”دو کلمے جو زبان پر ہلکے ہیں ترازو میں بہت بھاری اور رحمان کو عزیز ہیں «سبحان الله العظيم،‏‏‏‏ سبحان الله وبحمده» ۔“' WHERE id = 6168;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ نے بیان کیا، انہوں نے کہا ہم سے محمد بن عبدالرحمٰن ابومنذر طفاوی نے بیان کیا، انہوں نے کہا ہم سے سلیمان اعمش نے بیان کیا، انہوں نے کہا مجھ سے مجاہد نے بیان کیا، انہوں نے کہا ہم سے عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے میرا شانہ پکڑ کر فرمایا ”دنیا میں اس طرح ہو جا جیسے تو مسافر یا راستہ چلنے والا ہو۔“ عبداللہ بن عمر رضی اللہ عنہما فرمایا کرتے تھے شام ہو جائے تو صبح کے منتظر نہ رہو اور صبح کے وقت شام کے منتظر نہ رہو، اپنی صحت کو مرض سے پہلے غنیمت جانو اور زندگی کو موت سے پہلے۔' WHERE id = 6178;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، انہوں نے کہا ہم سے لیث بن سعد نے بیان کیا، ان سے یزید بن ابی حبیب نے بیان کیا، ان سے ابوالخیر نے بیان کیا اور ان سے عقبہ بن عامر رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم باہر تشریف لائے اور جنگ احد کے شہیدوں کے لیے اس طرح نماز پڑھی جس طرح مردہ پر نماز پڑھی جاتی ہے۔ پھر آپ صلی اللہ علیہ وسلم ممبر پر تشریف لائے اور فرمایا آخرت میں میں تم سے آگے جاؤں گا اور میں تم پر گواہ ہوں گا، واللہ میں اپنے حوض کو اس وقت بھی دیکھ رہا ہوں اور مجھے زمین کے خزانوں کی کنجیاں دی گئی ہیں یا ( فرمایا کہ ) زمین کی کنجیاں دی گئی ہیں اور اللہ کی قسم! میں تمہارے متعلق اس سے نہیں ڈرتا کہ تم میرے بعد شرک کرو گے بلکہ مجھے تمہارے متعلق یہ خوف ہے کہ تم دنیا کے لیے ایک دوسرے سے آگے بڑھنے کی کوشش کرنے لگو گے۔' WHERE id = 6188;
UPDATE hadiths SET urdu = 'ہم سے ابوعاصم نبیل نے بیان کیا، ان سے ابن جریج نے بیان کیا، ان سے عطاء بن ابی رباح نے بیان کیا، کہا کہ میں نے ابن عباس رضی اللہ عنہما سے سنا، انہوں نے کہا کہ میں نے نبی کریم صلی اللہ علیہ وسلم سے سنا، نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”اگر انسان کے پاس مال کی دو وادیاں ہوں تو تیسری کا خواہشمند ہو گا اور انسان کا پیٹ مٹی کے سوا اور کوئی چیز نہیں بھر سکتی اور اللہ اس شخص کی توبہ قبول کرتا ہے جو ( دل سے ) سچی توبہ کرتا ہے۔“' WHERE id = 6198;
UPDATE hadiths SET urdu = 'ہم سے احمد بن یونس نے بیان کیا، کہا ہم سے ابوبکر بن عیاش نے بیان کیا، کہا ہم سے ابوحصین نے بیان کیا، ان سے ابوصالح ذکوان نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”تونگری یہ نہیں ہے کہ سامان زیادہ ہو، بلکہ امیری یہ ہے کہ دل غنی ہو۔“' WHERE id = 6208;
UPDATE hadiths SET urdu = 'مجھ سے احمد بن رجاء نے بیان کیا، کہا ہم سے نضر نے بیان کیا، ان سے ہشام بن عروہ نے کہا کہ مجھے میرے والد نے خبر دی اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم کا بستر چمڑے کا تھا اور اس میں کھجور کی چھال بھری ہوئی تھی۔' WHERE id = 6218;
UPDATE hadiths SET urdu = 'مجھ سے عثمان بن ابی شیبہ نے بیان کیا، انہوں نے کہا ہم سے جریر نے بیان کیا، ان سے منصور نے بیان کیا، ان سے ابراہیم نخعی نے اور ان سے علقمہ نے بیان کیا کہ میں نے ام المؤمنین عائشہ رضی اللہ عنہا سے پوچھا: ام المؤمنین! نبی کریم صلی اللہ علیہ وسلم کیونکر عبادت کیا کرتے تھے کیا آپ نے کچھ خاص دن خاص کر رکھے تھے؟ بتلایا کہ نہیں نبی کریم صلی اللہ علیہ وسلم کے عمل میں ہمیشگی ہوتی تھی اور تم میں کون ہے جو ان عملوں کی طاقت رکھتا ہو جن کی نبی کریم صلی اللہ علیہ وسلم طاقت رکھتے تھے۔' WHERE id = 6228;
UPDATE hadiths SET urdu = 'ہم سے ابوالولید نے بیان کیا، انہوں نے کہا ہم سے لیث بن سعد نے بیان کیا، انہوں نے کہا ہم سے سعید مقبری نے بیان کیا، ان سے ابوشریح خزاعی نے بیان کیا انہوں نے کہا کہ میرے دونوں کانوں نے سنا ہے اور میرے دل نے یاد رکھا ہے کہ نبی کریم صلی اللہ علیہ وسلم نے یہ فرمایا تھا ”مہمانی تین دن کی ہوتی ہے مگر جو لازمی ہے وہ تو پوری کرو۔“ پوچھا گیا لازمی کتنی ہے؟ فرمایا کہ ایک دن اور ایک رات اور جو کوئی اللہ اور آخرت کے دن پر ایمان رکھتا ہے اسے چاہئے کہ اپنے مہمان کی خاطر کرے اور جو شخص اللہ اور آخرت کے دن پر ایمان رکھتا ہے اسے چاہئے کہ اچھی بات کہے ورنہ چپ رہے۔' WHERE id = 6238;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا، انہوں نے کہا ہم سے شعبہ نے بیان کیا، ان سے موسیٰ بن انس نے بیان کیا اور ان سے انس بن مالک رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”اگر تمہیں وہ معلوم ہوتا جو میں جانتا ہوں تو تم ہنستے کم اور روتے زیادہ۔“' WHERE id = 6248;
UPDATE hadiths SET urdu = 'ہم سے محمد بن سنان نے بیان کیا، انہوں نے کہا ہم سے فلیح بن سلیمان نے بیان کیا، کہا ہم سے ہلال بن علی نے بیان کیا، ان سے عطاء بن یسار نے بیان کیا اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”جب امانت ضائع کی جائے تو قیامت کا انتظار کرو۔“ پوچھا: یا رسول اللہ! امانت کس طرح ضائع کی جائے گی؟ فرمایا ”جب کام نااہل لوگوں کے سپرد کر دئیے جائیں تو قیامت کا انتظار کرو۔“' WHERE id = 6258;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، کہا ہم کو شعیب نے خبر دی، کہا ہم سے ابوالزناد نے بیان کیا، ان سے عبدالرحمٰن نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”قیامت اس وقت تک قائم نہ ہو گی جب تک سورج مغرب سے نہ نکلے گا۔ جب سورج مغرب سے نکلے گا اور لوگ دیکھ لیں گے تو سب ایمان لے آئیں گے، یہی وہ وقت ہو گا جب کسی کو اس کا ایمان نفع نہیں دے گا جو اس سے پہلے ایمان نہ لایا ہو گا یا جس نے ایمان کے بعد عمل خیر نہ کیا ہو۔ پس قیامت آ جائے گی اور دو آدمی کپڑا درمیان میں ( خرید و فروخت کے لیے ) پھیلائے ہوئے ہوں گے۔ ابھی خرید و فروخت بھی نہیں ہوئی ہو گی اور نہ انہوں نے اسے لپیٹا ہی ہو گا ( کہ قیامت قائم ہو جائے گی ) اور قیامت اس حال میں قائم ہو جائے گی کہ ایک شخص اپنی اونٹنی کا دودھ لے کر آ رہا ہو گا اور اسے پی بھی نہیں سکے گا اور قیامت اس حال میں قائم ہو جائے گی کہ ایک شخص اپنا حوض تیار کرا رہا ہو گا اور اس کا پانی بھی نہ پی پائے گا۔ قیامت اس حال میں قائم ہو جائے گی کہ ایک شخص اپنا لقمہ اپنے منہ کی طرف اٹھائے گا اور اسے کھانے بھی نہ پائے گا۔“' WHERE id = 6268;
UPDATE hadiths SET urdu = 'ہم سے علی بن جعد نے بیان کیا، کہا ہم کو شعبہ بن حجاج نے خبر دی، انہیں اعمش نے، انہیں مجاہد نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”جو لوگ مر گئے ان کو برا نہ کہو کیونکہ جو کچھ انہوں نے آگے بھیجا تھا اس کے پاس وہ خود پہنچ چکے ہیں، انہوں نے برے بھلے جو بھی عمل کئے تھے ویسا بدلہ پا لیا۔“' WHERE id = 6278;
UPDATE hadiths SET urdu = 'مجھ سے محمد بن بشار نے بیان کیا، کہا ہم سے غندر نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے مغیرہ بن نعمان نے بیان کیا، ان سے سعید بن جبیر نے، ان سے ابن عباس رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم ہمیں خطبہ دینے کے لیے کھڑے ہوئے اور فرمایا ”تم لوگ قیامت کے دن اس حال میں جمع کئے جاؤ گے کہ ننگے پاؤں اور ننگے جسم ہو گے۔ جیسا کہ اللہ تعالیٰ نے فرمایا «كما بدأنا أول خلق نعيده‏» کہ ”جس طرح ہم نے شروع میں پیدا کیا تھا اسی طرح لوٹا دیں گے۔“ اور تمام مخلوقات میں سب سے پہلے جسے کپڑا پہنایا جائے گا وہ ابراہیم علیہ السلام ہوں گے اور میری امت کے بہت سے لوگ لائے جائیں گے جن کے اعمال نامے بائیں ہاتھ میں ہوں گے۔ میں اس پر کہوں گا: اے میرے رب! یہ تو میرے ساتھی ہیں۔ اللہ تعالیٰ فرمائے گا تمہیں معلوم نہیں کہ انہوں نے تمہارے بعد کیا کیا نئی نئی بدعات نکالی تھیں۔ اس وقت میں بھی وہی کہوں گا جو نیک بندے ( عیسیٰ علیہ السلام ) نے کہا «وكنت عليهم شهيدا ما دمت فيهم‏» کہ ”یا اللہ! میں جب تک ان میں موجود رہا اس وقت تک میں ان پر گواہ تھا۔“ رسول اللہ صلی اللہ علیہ وسلم نے بیان کیا کہ فرشتے ( مجھ سے ) کہیں گے کہ یہ لوگ ہمیشہ اپنی ایڑیوں کے بل پھرتے ہی رہے ( مرتد ہوتے رہے ) ۔' WHERE id = 6288;
UPDATE hadiths SET urdu = 'ہم سے عبیداللہ بن موسیٰ نے بیان کیا، ان سے عثمان بن اسود نے بیان کیا، ان سے ابن ابی ملیکہ نے، ان سے ام المؤمنین عائشہ رضی اللہ عنہا نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”جس کے حساب میں کھود کرید کی گئی اس کو ضرور عذاب ہو گا۔“ وہ کہتی ہیں کہ میں نے عرض کیا: کیا اللہ تعالیٰ کا یہ فرمان نہیں ہے «فسوف يحاسب حسابا يسيرا‏» ”پھر عنقریب ان سے ہلکا حساب لیا جائے گا۔“ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اس سے مراد صرف پیشی ہے۔' WHERE id = 6298;
UPDATE hadiths SET urdu = 'ہم سے عثمان بن ہثیم نے بیان کیا، کہا ہم سے عوف بن ابی جمیلہ نے بیان کیا، ان سے ابورجاء عمران عطاردی نے، ان سے عمران بن حصین رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم نے بیان کیا کہ میں نے جنت میں جھانک کر دیکھا تو وہاں رہنے والے اکثر غریب لوگ تھے اور میں نے جہنم میں جھانک کر دیکھا ( شب معراج میں ) تو وہاں عورتیں تھیں۔' WHERE id = 6308;
UPDATE hadiths SET urdu = 'راوی (عبدالعزیز) نے بیان کیا کہ پھر میں نے یہ حدیث نعمان بن ابی عیاش سے بیان کی تو انہوں نے کہا کہ میں گواہی دیتا ہوں کہ میں نے ابو سعید خدری رضی اللہ عنہ کو یہ حدیث بیان کرتے سنا اور اس میں وہ اس لفظ کا اضافہ کرتے تھے کہ ”جیسے تم مشرقی اور مغربی کناروں میں ڈوبتے ستاروں کو دیکھتے ہو۔“' WHERE id = 6318;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، انہوں نے کہا ہم سے یحییٰ نے بیان کیا، ان سے حسن بن ذکوان نے بیان کیا، انہوں نے کہا ہم سے ابوحازم نے بیان کیا، انہوں نے کہا ہم سے عمران بن حصین رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”ایک جماعت جہنم سے محمد ( صلی اللہ علیہ وسلم ) کی شفاعت کی وجہ سے نکلے گی اور جنت میں داخل ہو گی جن کو «جهنميين‏ ‏‏.» کے نام سے پکارا جائے گا۔“' WHERE id = 6328;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے یحییٰ نے بیان کیا، ان سے عبیداللہ نے، ان سے نافع نے بیان کیا اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”تمہارے سامنے ہی میرا حوض ہو گا وہ اتنا بڑا ہے جتنا جرباء اور اذرحاء کے درمیان فاصلہ ہے۔“' WHERE id = 6338;
UPDATE hadiths SET urdu = 'ہم سے ابراہیم بن المنذر حزامی نے بیان کیا، کہا ہم سے محمد بن فلیح نے بیان کیا، کہا ہم سے ہمارے والد نے، کہا کہ مجھ سے ہلال نے، ان سے عطاء بن یسار نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”میں ( حوض پر ) کھڑا ہوں گا کہ ایک جماعت میرے سامنے آئے گی اور جب میں انہیں پہچان لوں گا تو ایک شخص ( فرشتہ ) میرے اور ان کے درمیان سے نکلے گا اور ان سے کہے گا کہ ادھر آؤ۔ میں کہوں گا کہ کدھر؟ وہ کہے گا کہ واللہ جہنم کی طرف۔ میں کہوں گا کہ ان کے حالات کیا ہیں؟ وہ کہے گا کہ یہ لوگ آپ کے بعد الٹے پاؤں ( دین سے ) واپس لوٹ گئے تھے۔ پھر ایک اور گروہ میرے سامنے آئے گا اور جب میں انہیں بھی پہچان لوں گا تو ایک شخص ( فرشتہ ) میرے اور ان کے درمیان میں سے نکلے گا اور ان سے کہے گا کہ ادھر آؤ۔ میں پوچھوں گا کہ کہاں؟ تو وہ کہے گا، اللہ کی قسم! جہنم کی طرف۔ میں کہوں گا کہ ان کے حالات کیا ہیں؟ فرشتہ کہے گا کہ یہ لوگ آپ کے بعد الٹے پاؤں واپس لوٹ گئے تھے۔ میں سمجھتا ہوں کہ ان گروہوں میں سے ایک آدمی بھی نہیں بچے گا۔ ان سب کو دوزخ میں لے جائیں گے۔' WHERE id = 6348;
UPDATE hadiths SET urdu = 'ہم سے محمد بن بشار نے بیان کیا، کہا ہم سے غندر محمد بن جعفر نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے ابوبشر نے، ان سے سعید بن جبیر نے اور ان سے عبداللہ بن عباس رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم سے مشرکین کی اولاد کے بارے میں سوال کیا گیا تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ اللہ کو خوب معلوم ہے کہ وہ ( بڑے ہو کر ) کیا عمل کرتے۔' WHERE id = 6358;
UPDATE hadiths SET urdu = 'ہم سے بشر بن محمد نے بیان کیا، کہا ہم کو عبداللہ بن مبارک نے خبر دی، کہا ہم کو معمر نے خبر دی، انہیں ہمام بن منبہ نے، انہیں ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ نذر ( منت ) انسان کو کوئی چیز نہیں دیتی جو میں ( رب ) نے اس کی تقدیر میں نہ لکھی ہو بلکہ وہ تقدیر دیتی ہے جو میں ( رب ) نے اس کے لیے مقرر کر دی ہے، البتہ اس کے ذریعہ میں بخیل کا مال نکلوا لیتا ہوں۔' WHERE id = 6369;
UPDATE hadiths SET urdu = 'مجھ سے اسحاق بن ابراہیم حنظلی نے بیان کیا، انہوں نے کہا مجھ کو نضر نے خبر دی، انہوں نے کہا ہم سے داؤد بن ابی الفرات نے بیان کیا، ان سے عبداللہ بن بریدہ نے بیان کیا، ان سے یحییٰ بن یعمر نے بیان کیا اور انہیں عائشہ رضی اللہ عنہا نے خبر دی کہ انہوں نے رسول اللہ صلی اللہ علیہ وسلم سے طاعون کے متعلق پوچھا تو نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ یہ عذاب تھا اور اللہ تعالیٰ جس پر چاہتا ہے اسے بھیجتا تھا۔ پھر اللہ تعالیٰ نے اسے مومنوں کے لیے رحمت بنا دیا، کوئی بھی بندہ اگر کسی ایسے شہر میں ہے جس میں طاعون کی وبا پھوٹی ہوئی ہے اور اس میں ٹھہرا ہے اور اس شہر سے بھاگا نہیں صبر کئے ہوئے ہے اور اس پر اجر کا امیدوار ہے اور یقین رکھتا ہے کہ اس تک صرف وہی چیز پہنچ سکتی ہے جو اللہ نے اس کی تقدیر میں لکھ دی ہے تو اسے شہید کے برابر ثواب ملے گا۔' WHERE id = 6379;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، کہا ہم سے ابوعوانہ نے بیان کیا، ان سے عبدالملک نے، ان سے جابر بن سمرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”جب قیصر ہلاک ہو جائے گا تو پھر اس کے بعد کوئی قیصر نہیں پیدا ہو گا اور جب کسریٰ ہلاک ہو جائے گا تو اس کے بعد کوئی کسریٰ نہیں پیدا ہو گا اور اس ذات کی قسم جس کے ہاتھ میں میری جان ہے تم ان کے خزانے اللہ کے راستے میں خرچ کرو گے۔“' WHERE id = 6389;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، کہا ہم سے لیث بن سعد نے، انہوں نے یونس سے، انہوں نے ابن شہاب سے، کہا مجھ سے عروہ بن زبیر نے بیان کیا کہ عائشہ رضی اللہ عنہا نے کہا کہ ہند بنت عتبہ بن ربیعہ ( معاویہ رضی اللہ عنہ کی ماں ) نے عرض کیا: یا رسول اللہ! ساری زمین پر جتنے ڈیرے والے ہیں ( یعنی عرب لوگ جو اکثر ڈیروں اور خیموں میں رہا کرتے تھے ) میں کسی کا ذلیل و خوار ہونا مجھ کو اتنا پسند نہیں تھا جتنا آپ کا۔ یحییٰ بن بکیر راوی کو شک ہے ( کہ ڈیرے کا لفظ بہ صیغہ مفرد کہا یا بہ صیغہ جمع ) اب کوئی ڈیرہ والا یا ڈیرے والے ان کو عزت اور آبرو حاصل ہونا مجھ کو آپ کے ڈیرے والوں سے زیادہ پسند نہیں ہے ( یعنی اب میں آپ کی اور مسلمانوں کی سب سے زیادہ خیرخواہ ہوں ) نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ ابھی کیا ہے تو اور بھی زیادہ خیرخواہ بنے گی۔ قسم ہے اس کی جس کے ہاتھ میں محمد ( صلی اللہ علیہ وسلم ) کی جان ہے۔ پھر ہند کہنے لگی یا رسول اللہ! ابوسفیان تو ایک بخیل آدمی ہے مجھ پر گناہ تو نہیں ہو گا اگر میں اس کے مال میں سے ( اپنے بال بچوں کو کھلاؤں ) آپ صلی اللہ علیہ وسلم نے فرمایا نہیں اگر تو دستور کے موافق خرچ کرے۔' WHERE id = 6400;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا ہم سے لیث بن سعد نے بیان کیا، ان سے نافع نے، ان سے عبداللہ بن عمر رضی اللہ عنہما نے کہ رسول اللہ صلی اللہ علیہ وسلم نے سونے کی ایک انگوٹھی بنوائی اور نبی کریم صلی اللہ علیہ وسلم اسے پہنتے تھے، اس کا نگینہ ہتھیلی کے حصے کی طرف رکھتے تھے۔ پھر لوگوں نے بھی ایسی انگوٹھیاں بنوا لیں اس کے بعد ایک دن نبی کریم صلی اللہ علیہ وسلم منبر پر بیٹھے اور اپنی انگوٹھی اتار دی اور فرمایا کہ میں اسے پہنتا تھا اور اس کا نگینہ اندر کی جانب رکھتا تھا، پھر آپ صلی اللہ علیہ وسلم نے اسے اتار کر پھینک دیا اور فرمایا کہ اللہ کی قسم میں اب اسے کبھی نہیں پہنوں گا۔ پس لوگوں نے بھی اپنی انگوٹھیاں اتار کر پھینک دیں۔' WHERE id = 6410;
UPDATE hadiths SET urdu = 'مجھ سے محمد بن مثنیٰ نے بیان کیا، کہا ہم سے یحییٰ قطان نے بیان کیا، ان سے ہشام بن عروہ نے، کہا کہ مجھے میرے والد نے خبر دی، انہیں عائشہ رضی اللہ عنہا نے کہ آیت «لا يؤاخذكم الله باللغو‏» ”اللہ تعالیٰ تم سے لغو قسموں کے بارے میں پکڑ نہیں کرے گا۔“ راوی نے بیان کیا کہ ام المؤمنین رضی اللہ عنہا نے کہا کہ یہ آیت «لا،‏‏‏‏ والله بلى والله‏.‏» ( بے ساختہ جو قسمیں عادت بنا لی جاتی ہیں ) کے بارے میں نازل ہوئی تھی۔' WHERE id = 6421;
UPDATE hadiths SET urdu = 'ابوعبداللہ (امام بخاری رحمہ اللہ) نے کہا کہ محمد بن بشار نے مجھے لکھا کہ ہم سے معاذ بن معاذ نے بیان کیا، کہا ہم سے ابن عون نے بیان کیا، ان سے شعبی نے بیان کیا، کہ براء بن عازب رضی اللہ عنہ نے بیان کیا، ان کے یہاں کچھ ان کے مہمان ٹھہرے ہوئے تھے تو انہوں نے اپنے گھر والوں سے کہا کہ ان کے واپس آنے سے پہلے جانور ذبح کر لیں تاکہ ان کے مہمان کھائیں، چنانچہ انہوں نے نماز عید الاضحی سے پہلے جانور ذبح کر لیا۔ پھر نبی کریم صلی اللہ علیہ وسلم سے اس کا ذکر کیا تو آپ صلی اللہ علیہ وسلم نے حکم دیا کہ نماز کے بعد دوبارہ ذبح کریں۔ براء رضی اللہ عنہ نے عرض کیا کہ یا رسول اللہ! میرے پاس ایک سال سے زیادہ دودھ والی بکری ہے جو دو بکریوں کے گوشت سے بڑھ کر ہے۔ ابن عوف شعبی کی حدیث کے اس مقام پر ٹھہر جاتے تھے اور محمد بن سیرین سے اسی حدیث کی طرح حدیث بیان کرتے تھے اور اس مقام پر رک کر کہتے تھے کہ مجھے معلوم نہیں، یہ رخصت دوسرے لوگوں کے لیے بھی ہے یا صرف براء رضی اللہ عنہ کے لیے ہی تھی۔ اس کی روایت ایوب نے ابن سیرین سے کی ہے، ان سے انس رضی اللہ عنہ نے اور ان سے نبی کریم صلی اللہ علیہ وسلم نے۔' WHERE id = 6431;
UPDATE hadiths SET urdu = 'مجھ سے علی بن عبداللہ مدینی نے بیان کیا، انہوں نے عبدالعزیز بن ابی حازم سے سنا، کہا مجھ کو میرے والد نے خبر دی، انہیں سہل بن سعد رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم کے صحابی ابواسید رضی اللہ عنہ نے نکاح کیا اور نبی کریم صلی اللہ علیہ وسلم کو اپنی شادی کے موقع پر بلایا۔ دلہن ہی ان کی میزبانی کا کام کر رہی تھیں، پھر سہل رضی اللہ عنہ نے لوگوں سے پوچھا، تمہیں معلوم ہے، میں نے نبی کریم صلی اللہ علیہ وسلم کو کیا پلایا تھا۔ کہا کہ رات میں نبی کریم صلی اللہ علیہ وسلم کے لیے میں نے کھجور ایک بڑے پیالہ میں بھگو دی تھی اور صبح کے وقت اس کا پانی نبی کریم صلی اللہ علیہ وسلم کو پلایا تھا۔' WHERE id = 6442;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، ان سے یحییٰ نے، ان سے شعبہ نے بیان کیا، کہا مجھ سے ابوحمزہ نے بیان کیا، کہا ہم سے زہدم بن مضرب نے بیان کیا، کہا کہ میں نے عمران بن حصین سے سنا، وہ نبی کریم صلی اللہ علیہ وسلم سے بیان کرتے تھے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”تم میں سب سے بہتر میرا زمانہ ہے، اس کے بعد ان کا جو اس کے قریب ہوں گے۔ اس کے بعد وہ جو اس سے قریب ہوں گے۔“ عمران نے بیان کیا کہ مجھے یاد نہیں نبی کریم صلی اللہ علیہ وسلم نے اپنے زمانہ کے بعد دو کا ذکر کیا تھا یا تین کا ( فرمایا کہ ) پھر ایک ایسی قوم آئے گی جو نذر مانے گی اور اسے پورا نہیں کرے گی، خیانت کرے گی اور ان پر اعتماد نہیں رہے گا۔ وہ گواہی دینے کے لیے تیار رہیں گے جب کہ ان سے گواہی کے لیے کہا بھی نہیں جائے گا اور ان میں مٹاپا عام ہو جائے گا۔' WHERE id = 6452;
UPDATE hadiths SET urdu = 'ہم سے محمد بن ابوبکر مقدمی نے بیان کیا، انہوں نے کہا ہم سے فضیل بن سلیمان نے بیان کیا، انہوں نے کہا ہم سے موسیٰ بن عقبہ نے بیان کیا، کہا ہم سے حکیم بن ابی حرہ اسلمی نے بیان کیا، انہوں نے عبداللہ بن عمر رضی اللہ عنہما سے سنا ان سے ایسے شخص کے متعلق پوچھا گیا جس نے نذر مانی ہو کہ کچھ مخصوص دنوں میں روزے رکھے گا۔ پھر اتفاق سے انہیں دنوں میں بقر عید یا عید کے دن پڑ گئے ہوں؟ عبداللہ بن عمر رضی اللہ عنہما نے کہا کہ تمہارے لیے رسول اللہ صلی اللہ علیہ وسلم کی زندگی بہترین نمونہ ہے۔ نبی کریم صلی اللہ علیہ وسلم بقر عید اور عید کے دن روزے نہیں رکھتے تھے اور نہ ان دنوں میں روزے کو جائز سمجھتے تھے۔' WHERE id = 6462;
UPDATE hadiths SET urdu = 'ہم سے محمد بن عبدالرحیم نے بیان کیا، کہا ہم سے داؤد بن رشید نے بیان کیا، کہا ہم سے ولید بن مسلم نے بیان کیا، ان سے ابوغسان محمد بن مطرف نے، ان سے زید بن اسلم نے، ان سے زین العابدین علی بن حسین نے، ان سے سعید ابن مرجانہ نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”جس نے کسی مسلمان غلام کو آزاد کیا تو اللہ تعالیٰ اس کے ایک ایک ٹکڑے کے بدلے آزاد کرنے والے کا ایک ایک ٹکڑا جہنم سے آزاد کرے گا۔ یہاں تک کہ غلام کی شرمگاہ کے بدلے آزاد کرنے والے کی شرمگاہ بھی دوزخ سے آزاد ہو جائے گی۔“' WHERE id = 6472;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل بن ابان نے بیان کیا، کہا ہم کو عبداللہ بن مبارک نے خبر دی، انہیں یونس نے، انہیں زہری نے، انہیں عروہ نے اور ان سے عائشہ رضی اللہ عنہا نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”ہماری وراثت نہیں ہوتی ہم جو کچھ بھی چھوڑیں وہ صدقہ ہے۔“' WHERE id = 6483;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا، کہا ہم سے وہیب نے بیان کیا، ان سے ابن طاؤس نے، ان سے ان کے والد نے اور ان سے ابن عباس رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”میراث اس کے حقدار تک پہنچا دو اور جو باقی رہ جائے وہ سب سے قریب والے مرد کو دے دو۔“' WHERE id = 6493;
UPDATE hadiths SET urdu = 'مجھ سے اسحاق بن ابراہیم نے بیان کیا، انہوں نے کہا کہ میں نے ابواسامہ سے پوچھا کیا آپ سے ادریس نے بیان کیا تھا، ان سے طلحہ نے بیان کیا، ان سے سعید بن جبیر نے بیان کیا اور ان سے عبداللہ بن عباس رضی اللہ عنہما نے «ولكل جعلنا موالي‏» اور «والذين عقدت أيمانكم‏» کے متعلق بتلایا کہ مہاجرین جب مدینہ آئے تو ذوی الارحام کے علاوہ انصار و مہاجرین بھی ایک دوسرے کی وراثت پاتے تھے۔ اس بھائی چارگی کی وجہ سے جو نبی کریم صلی اللہ علیہ وسلم نے ان کے درمیان کرائی تھی، پھر جب آیت «جعلنا موالي‏» نازل ہوئی تو فرمایا کہ اس نے «والذين عقدت أيمانكم‏» کو منسوخ کر دیا۔' WHERE id = 6503;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، ان سے امام مالک رحمہ اللہ نے بیان کیا، ان سے نافع نے، ان سے ابن عمر رضی اللہ عنہما نے کہ ام المؤمنین عائشہ رضی اللہ عنہا نے ایک کنیز کو آزاد کرنے کے لیے خریدنا چاہا تو کنیز کے مالکوں نے کہا کہ ہم بیچ سکتے ہیں لیکن ولاء ہمارے ساتھ ہو گی۔ ام المؤمنین نے اس کا ذکر رسول اللہ صلی اللہ علیہ وسلم سے کیا تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ اس شرط کو مانع نہ بننے دو، ولاء ہمیشہ اسی کے ساتھ قائم ہوتی ہے جو آزاد کرے۔' WHERE id = 6513;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، کہا ہم کو شعیب نے خبر دی، کہا کہ ہم سے ابوالزناد نے بیان کیا، ان سے عبدالرحمٰن نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”دو عورتیں تھیں اور ان کے ساتھ ان کے دو بچے بھی تھے، پھر بھیڑیا آیا اور ایک بچے کو اٹھا کر لے گیا اس نے اپنی ساتھی عورت سے کہا کہ بھیڑیا تیرے بچے کو لے گیا ہے، دوسری عورت نے کہا کہ وہ تو تیرا بچہ لے گیا ہے۔ وہ دونوں عورتیں اپنا مقدمہ داؤد علیہ السلام کے پاس لائیں تو آپ نے فیصلہ بڑی کے حق میں کر دیا۔ وہ دونوں نکل کر سلیمان بن داؤد علیہما السلام کے پاس گئیں اور انہیں واقعہ کی اطلاع دی۔ سلیمان علیہ السلام نے کہا کہ چھری لاؤ میں لڑکے کے دو ٹکڑے کر کے دونوں کو ایک ایک دوں گا۔ اس پر چھوٹی عورت بول اٹھی کہ ایسا نہ کیجئے آپ پر اللہ رحم کرے، یہ بڑی ہی کا لڑکا ہے لیکن آپ علیہ السلام نے فیصلہ چھوٹی عورت کے حق میں کیا۔ ابوہریرہ رضی اللہ عنہ نے کہا کہ واللہ! میں نے «سكين» چھری کا لفظ سب سے پہلی مرتبہ ( نبی کریم صلی اللہ علیہ وسلم کی زبان سے ) اس دن سنا تھا اور ہم اس کے لیے ( اپنے قبیلہ میں ) «مدية‏.‏» کا لفظ بولتے تھے۔' WHERE id = 6524;
UPDATE hadiths SET urdu = 'ہم سے مکی بن ابراہیم نے بیان کیا، ان سے جعید نے، ان سے یزید بن خصیفہ نے، ان سے سائب بن یزید نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم اور ابوبکر رضی اللہ عنہ اور پھر عمر رضی اللہ عنہ کے ابتدائی دور خلافت میں شراب پینے والا ہمارے پاس لایا جاتا تو ہم اپنے ہاتھ، جوتے اور چادریں لے کر کھڑے ہو جاتے ( اور اسے مارتے ) آخر عمر رضی اللہ عنہ نے اپنے آخری دور خلافت میں شراب پینے والوں کو چالیس کوڑے مارے اور جب ان لوگوں نے مزید سرکشی کی اور فسق و فجور کیا تو ( 80 ) اسی کوڑے مارے۔' WHERE id = 6534;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن مسلمہ نے بیان کیا، کہا ہم سے ابراہیم بن سعد نے بیان کیا، ان سے ابن شہاب نے بیان کیا، ان سے عمرہ نے بیان کیا اور ان سے ام المؤمنین عائشہ رضی اللہ عنہا نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”چوتھائی دینار یا اس سے زیادہ پر ہاتھ کاٹ لیا جائے گا۔“ اس روایت کی متابعت عبدالرحمٰن بن خالد زہری کے بھتیجے اور معمر نے زہری کے واسطہ سے کی۔' WHERE id = 6544;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، انہوں نے کہا ہم سے عبدالواحد نے بیان کیا، انہوں نے کہا ہم سے اعمش نے بیان کیا، کہا کہ میں نے ابوصالح سے سنا، کہا کہ میں نے ابوہریرہ رضی اللہ عنہ سے سنا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”اللہ تعالیٰ نے چور پر لعنت کی ہے کہ ایک انڈا چراتا ہے اور اس کا ہاتھ کاٹا جاتا ہے , ایک رسی چراتا ہے اور اس کا ہاتھ کاٹا جاتا ہے۔' WHERE id = 6554;
UPDATE hadiths SET urdu = 'ہم سے محمد بن مثنیٰ نے بیان کیا، انہوں نے کہا ہم کو اسحاق بن یوسف نے خبر دی، کہا ہم کو فضیل بن غزوان نے خبر دی، انہیں عکرمہ نے اور ان سے ابن عباس رضی اللہ عنہما نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”بندہ جب زنا کرتا ہے تو وہ مومن نہیں رہتا۔ بندہ جب چوری کرتا ہے تو وہ مومن نہیں رہتا اور بندہ جب شراب پیتا ہے تو وہ مومن نہیں رہتا اور جب وہ قتل ناحق کرتا ہے تو وہ مومن نہیں رہتا۔ عکرمہ نے کہا کہ میں نے ابن عباس رضی اللہ عنہما سے پوچھا کہ ایمان اس سے کس طرح نکال لیا جاتا ہے؟ آپ صلی اللہ علیہ وسلم نے فرمایا کہ وہ اس طرح اور اس وقت آپ ان نے اپنی انگلیوں کو دوسرے ہاتھ کی انگلیوں میں ڈال کر پھر الگ کر لیا پھر اگر وہ توبہ کر لیتا ہے تو ایمان اس کے پاس لوٹ آتا ہے، اس طرح اور آپ نے اپنی انگلیوں کو دوسرے ہاتھ کی انگلیوں میں ڈالا۔' WHERE id = 6564;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، ان سے لیث بن سعد نے بیان کیا، ان سے ابن شہاب نے، ان سے حمید بن عبدالرحمٰن نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ ایک صاحب نے رمضان میں اپنی بیوی سے ہمبستری کر لی اور پھر رسول اللہ صلی اللہ علیہ وسلم سے اس کا حکم پوچھا تو نبی کریم صلی اللہ علیہ وسلم نے فرمایا کیا تمہارے پاس کوئی غلام ہے؟ انہوں نے کہا کہ نہیں۔ اس پر نبی کریم صلی اللہ علیہ وسلم نے دریافت فرمایا دو مہینے روزے رکھنے کی تم میں طاقت نہیں؟ انہوں نے کہا کہ نہیں۔ نبی کریم صلی اللہ علیہ وسلم نے اس پر کہا کہ پھر ساٹھ محتاجوں کو کھانا کھلاؤ۔' WHERE id = 6575;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل بن عبداللہ نے بیان کیا، کہا ہم سے امام مالک نے بیان کیا، ان سے نافع نے اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے کہ یہودی رسول اللہ صلی اللہ علیہ وسلم کے پاس آئے اور کہا کہ ان میں سے ایک مرد اور ایک عورت نے زناکاری کی ہے۔ نبی کریم صلی اللہ علیہ وسلم نے ان سے پوچھا کہ تورات میں رجم کے متعلق کیا حکم ہے؟ انہوں نے کہا کہ ہم انہیں رسوا کرتے ہیں اور کوڑے لگاتے ہیں۔ عبداللہ بن سلام رضی اللہ عنہ نے اس پر کہا کہ تم جھوٹے ہو اس میں رجم کا حکم موجود ہے۔ چنانچہ وہ تورات لائے اور کھولا۔ لیکن ان کے ایک شخص نے اپنا ہاتھ آیت رجم پر رکھ دیا اور اس سے پہلے اور بعد کا حصہ پڑھ دیا۔ عبداللہ بن سلام رضی اللہ عنہ نے اس سے کہا کہ اپنا ہاتھ اٹھاؤ۔ اس نے اپنا ہاتھ اٹھایا تو اس کے نیچے رجم کی آیت موجود تھی۔ پھر انہوں نے کہا: اے محمد! آپ نے سچ فرمایا کہ اس میں رجم کی آیت موجود ہے۔ چنانچہ نبی کریم صلی اللہ علیہ وسلم نے حکم دیا اور دونوں رجم کئے گئے۔ میں نے دیکھا کہ مرد عورت کو پتھروں سے بچانے کی کوشش میں اس پر جھکا رہا تھا۔' WHERE id = 6590;
UPDATE hadiths SET urdu = 'ہم سے عبدان نے بیان کیا، انہوں نے کہا ہم کو عبداللہ بن مبارک نے خبر دی، انہوں نے کہا ہم کو یونس نے خبر دی، انہیں زہری نے، انہیں عروہ نے خبر دی اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے اپنے ذاتی معاملہ میں کبھی کسی سے بدلہ نہیں لیا ہاں جب اللہ کی قائم کی ہوئی حد کو توڑا جاتا تو آپ پھر بدلہ لیتے تھے۔' WHERE id = 6601;
UPDATE hadiths SET urdu = 'ہم سے قبیصہ نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے بیان کیا، ان سے اعمش نے، ان سے عبداللہ بن مرہ نے، ان سے مسروق نے اور ان سے عبداللہ بن مسعود رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”جو جان ناحق قتل کی جائے اس کے ( گناہ کا ) ایک حصہ آدم علیہ السلام کے پہلے بیٹے ( قابیل پر ) پڑتا ہے۔“' WHERE id = 6613;
UPDATE hadiths SET urdu = 'ہم سے محمد نے بیان کیا، کہا ہم کو عبداللہ بن ادریس نے خبر دی، انہیں شعبہ نے، انہیں ہشام بن زید بن انس نے، ان سے ان کے دادا انس بن مالک رضی اللہ عنہ نے بیان کیا کہ مدینہ منورہ میں ایک لڑکی چاندی کے زیور پہنے باہر نکلی۔ راوی نے بیان کیا کہ پھر اسے ایک یہودی نے پتھر سے مار دیا۔ جب اسے نبی کریم صلی اللہ علیہ وسلم کے پاس لایا گیا تو ابھی اس میں جان باقی تھی۔ نبی کریم صلی اللہ علیہ وسلم نے پوچھا تمہیں فلاں نے مارا ہے؟ اس پر لڑکی نے اپنا سر ( انکار کے لیے ) اٹھایا، پھر نبی کریم صلی اللہ علیہ وسلم نے پوچھا تمہیں فلاں نے مارا ہے؟ لڑکی نے اس پر بھی اٹھایا۔ تیسری مرتبہ نبی کریم صلی اللہ علیہ وسلم نے پوچھا، فلاں نے تمہیں مارا ہے؟ اس پر لڑکی نے اپنا سر نیچے کی طرف جھکا لیا ( اقرار کرتے ہوئے جھکا لیا ) چنانچہ نبی کریم صلی اللہ علیہ وسلم نے اس شخص کو بلایا تب آپ صلی اللہ علیہ وسلم نے دو پتھروں سے کچل کر اسے قتل کرایا۔' WHERE id = 6623;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، کہا ہم کو شعیب نے خبر دی، کہا ہم سے ابوالزناد نے بیان کیا، ان سے اعرج نے بیان کیا، انہوں نے ابوہریرہ رضی اللہ عنہ سے سنا، بیان کیا کہ انہوں نے رسول اللہ صلی اللہ علیہ وسلم سے سنا، نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ ہم آخری امت ہیں لیکن ( قیامت کے دن ) سب سے آگے رہنے والے ہیں۔' WHERE id = 6633;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم نے بیان کیا، کہا ہم سے سعید بن عبید نے بیان کیا، ان سے بشیر بن یسار نے، وہ کہتے تھے کہ قبیلہ انصار کے ایک صاحب سہل بن ابی حثمہ نے انہیں خبر دی کہ ان کی قوم کے کچھ لوگ خیبر گئے اور ( اپنے اپنے کاموں کے لیے ) مختلف جگہوں میں الگ الگ گئے پھر اپنے میں کے ایک شخص کو مقتول پایا۔ جنہیں وہ مقتول ملے تھے، ان سے ان لوگوں نے کہا کہ ہمارے ساتھی کو تم نے قتل کیا ہے۔ انہوں نے کہا کہ نہ ہم نے قتل کیا اور نہ ہمیں قاتل کا پتہ معلوم ہے؟ پھر یہ لوگ نبی کریم صلی اللہ علیہ وسلم کے پاس گئے اور کہا: یا رسول اللہ! ہم خیبر گئے اور پھر ہم نے وہاں اپنے ایک ساتھی کو مقتول پایا۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ تم میں جو بڑا ہے وہ بات کرے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ قاتل کے خلاف گواہی لاؤ۔ انہوں نے کہا کہ ہمارے پاس کوئی گواہی نہیں ہے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ پھر یہ ( یہودی ) قسم کھائیں گے ( اور ان کی قسم پر فیصلہ ہو گا ) انہوں نے کہا کہ یہودیوں کی قسموں کا کوئی اعتبار نہیں۔ نبی کریم صلی اللہ علیہ وسلم نے اسے پسند نہیں فرمایا کہ مقتول کا خون رائیگاں جائے چنانچہ آپ نے صدقہ کے اونٹوں میں سے سو اونٹ ( خود ہی ) دیت میں دیئے۔' WHERE id = 6644;
UPDATE hadiths SET urdu = 'مجھ سے عمر بن زرارہ نے بیان کیا، کہا ہم کو اسماعیل بن ابراہیم نے خبر دی، انہیں عبدالعزیز نے اور ان سے انس رضی اللہ عنہ نے بیان کیا کہ جب رسول اللہ صلی اللہ علیہ وسلم مدینہ تشریف لائے تو طلحہ رضی اللہ عنہ میرا ہاتھ پکڑ کر نبی کریم صلی اللہ علیہ وسلم کے پاس لائے اور کہا: یا رسول اللہ! انس سمجھ دار لڑکا ہے اور یہ آپ کی خدمت کرے گا۔ انس رضی اللہ عنہ نے بیان کیا کہ پھر میں نے نبی کریم صلی اللہ علیہ وسلم کی خدمت سفر میں بھی کی اور گھر پر بھی۔ واللہ! نبی کریم صلی اللہ علیہ وسلم نے کبھی مجھ سے کسی چیز کے متعلق جو میں نے کر دیا ہو یہ نہیں فرمایا کہ یہ کام تم نے اس طرح کیوں کیا اور نہ کسی ایسی چیز کے متعلق جسے میں نے نہ کیا ہو آپ نے یہ نہیں فرمایا کہ یہ کام تم نے اس طرح کیوں نہیں کیا۔' WHERE id = 6656;
UPDATE hadiths SET urdu = 'ہم سے خلاد بن یحییٰ نے بیان کیا، کہا ہم سے سفیان ثوری نے، انہوں نے منصور اور اعمش سے، انہوں نے ابووائل سے، انہوں نے عبداللہ بن مسعود رضی اللہ عنہ سے، انہوں نے کہا ایک شخص ( نام نامعلوم ) نے عرض کیا: یا رسول اللہ! ہم نے جو گناہ ( اسلام لانے سے پہلے ) جاہلیت کے زمانہ میں کیے ہیں کیا ان کا مواخذہ ہم سے ہو گا؟ آپ صلی اللہ علیہ وسلم نے فرمایا ”جو شخص اسلام کی حالت میں نیک اعمال کرتا رہا اس سے جاہلیت کے گناہوں کا مواخذہ نہ ہو گا ( اللہ تعالیٰ معاف کر دے گا ) اور جو شخص مسلمان ہو کر بھی برے کام کرتا رہا اس سے دونوں زمانوں کے گناہوں کا مواخذہ ہو گا۔“' WHERE id = 6666;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد مسندی نے بیان کیا، کہا ہم سے ہشام بن یوسف نے بیان کیا، کہا ہم کو معمر نے خبر دی، انہیں زہری نے، انہیں ابوسلمہ بن عبدالرحمٰن بن عوف نے اور ان سے ابوسعید رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم تقسیم فرما رہے تھے کہ عبداللہ بن ذی الخویصرہ تمیمی آیا اور کہا: یا رسول اللہ! انصاف کیجئے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ افسوس اگر میں انصاف نہیں کروں گا تو اور کون کرے گا۔ اس پر عمر بن الخطاب رضی اللہ عنہ نے کہا کہ مجھے اجازت دیجئیے کہ میں اس کی گردن مار دوں۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ نہیں اس کے کچھ ایسے ساتھی ہوں گے کہ ان کی نماز اور روزے کے سامنے تم اپنی نماز اور روزے کو حقیر سمجھو گے لیکن وہ دین سے اس طرح باہر ہو جائیں گے جس طرح تیر جانور میں سے باہر نکل جاتا ہے۔ تیر کے پر کو دیکھا جائے لیکن اس پر کوئی نشان نہیں پھر اس پیکان کو دیکھا جائے اور وہاں بھی کوئی نشان نہیں پھر اس کے باڑ کو دیکھا جائے اور یہاں بھی کوئی نشان نہیں پھر اس کی لکڑی کو دیکھا جائے اور وہاں بھی کوئی نشان نہیں کیونکہ وہ ( جانور کے جسم سے تیر چلایا گیا تھا ) لید گوبر اور خون سب سے آگے ( بےداغ ) نکل گیا ( اسی طرح وہ لوگ اسلام سے صاف نکل جائیں گے ) ان کی نشانی ایک مرد ہو گا جس کا ایک ہاتھ عورت کی چھاتی کی طرح یا یوں فرمایا کہ گوشت کے تھل تھل کرتے لوتھڑے کی طرح ہو گا۔ یہ لوگ مسلمانوں میں پھوٹ کے زمانہ میں پیدا ہوں گے۔ ابو سعید خدری رضی اللہ عنہ نے کہا کہ میں گواہی دیتا ہوں کہ میں نے یہ حدیث نبی کریم صلی اللہ علیہ وسلم سے سنی ہے اور میں گواہی دیتا ہوں کہ علی رضی اللہ عنہ نے نہروان میں ان سے جنگ کی تھی اور میں اس جنگ میں ان کے ساتھ تھا اور ان کے پاس ان لوگوں کے ایک شخص کو قیدی بنا کر لایا گیا تو اس میں وہی تمام چیزیں تھیں جو نبی کریم صلی اللہ علیہ وسلم نے بیان فرمائی تھیں۔ راوی نے بیان کیا کہ پھر قرآن مجید کی یہ آیت نازل ہوئی «ومنهم من يلمزك في الصدقات‏» کہ ”ان میں سے بعض وہ ہیں جو آپ کے صدقات کی تقسیم میں عیب پکڑتے ہیں۔“' WHERE id = 6677;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے یحییٰ نے بیان کیا، ان سے اسماعیل نے، کہا ہم سے قیس نے بیان کیا، ان سے خباب بن الارت رضی اللہ عنہ نے کہ ہم نے رسول اللہ صلی اللہ علیہ وسلم سے اپنا حال زار بیان کیا۔ نبی کریم صلی اللہ علیہ وسلم اس وقت کعبہ کے سایہ میں اپنی چادر پر بیٹھے ہوئے تھے۔ ہم نے عرض کیا کیوں نہیں آپ ہمارے لیے اللہ تعالیٰ سے مدد مانگتے اور اللہ تعالیٰ سے دعا کرتے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ تم سے پہلے بہت سے نبیوں اور ان پر ایمان لانے والوں کا حال یہ ہوا کہ ان میں سے کسی ایک کو پکڑ لیا جاتا اور گڑھا کھود کر اس میں انہیں ڈال دیا جاتا پھر آرا لایا جاتا اور ان کے سر پر رکھ کر دو ٹکڑے کر دئیے جاتے اور لوہے کے کنگھے ان کے گوشت اور ہڈیوں میں دھنسا دئیے جاتے لیکن یہ آزمائشیں بھی انہیں اپنے دین سے نہیں روک سکتی تھیں۔ اللہ کی قسم! اس اسلام کا کام مکمل ہو گا اور ایک سوار صنعاء سے حضر موت تک اکیلا سفر کرے گا اور اسے اللہ کے سوا اور کسی کا خوف نہیں ہو گا اور بکریوں پر سوا بھیڑئیے کے خوف کے ( اور کسی لوٹ وغیرہ کا کوئی ڈر نہ ہو گا ) لیکن تم لوگ جلدی کرتے ہو۔' WHERE id = 6687;
UPDATE hadiths SET urdu = 'ہم سے ابوالنعمان نے بیان کیا، کہا ہم سے حماد بن زید نے بیان کیا، ان سے یحییٰ بن سعید انصاری نے، ان سے محمد بن ابراہیم تیمی نے، ان سے علقمہ بن وقاص لیثی نے بیان کیا کہ میں نے عمر بن خطاب رضی اللہ عنہ سے خطبہ میں سنا انہوں نے کہا کہ میں نے نبی کریم صلی اللہ علیہ وسلم کو یہ فرماتے ہوئے سنا تھا: اے لوگو! اعمال کا دارومدار نیتوں پر ہے اور ہر شخص کو وہی ملے گا جس کی وہ نیت کرے گا پس جس کی ہجرت اللہ اور اس کے رسول کی طرف ہو اسے ہجرت ( کا ثواب ملے گا ) اور جس کی ہجرت کا مقصد دنیا ہو گی کہ جسے وہ حاصل کر لے یا کوئی عورت ہو گی جس سے وہ شادی کر لے تو اس کی ہجرت اسی کے لیے ہو گی جس کے لیے اس نے ہجرت کی ہے۔' WHERE id = 6697;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، کہا ہم کو شعیب نے خبر دی، ان سے زہری نے کہ عروہ ان سے بیان کرتے تھے کہ عائشہ رضی اللہ عنہا نے آیت «وإن خفتم أن لا تقسطوا في اليتامى فانكحوا ما طاب لكم من النساء‏» ”اور اگر تمہیں خوف ہو کہ تم یتیموں کے بارے میں انصاف نہیں کر سکو گے تو پھر دوسری عورتوں سے نکاح کرو جو تمہیں پسند ہوں۔“ آپ نے کہا کہ اس آیت میں ایسی یتیم لڑکی کا ذکر ہے جو اپنے ولی کی پرورش میں ہو اور ولی لڑکی کے مال اور اس کے حسن سے رغبت رکھتا ہو اور چاہتا ہو کہ عورتوں ( کے مہر وغیرہ کے متعلق ) جو سب سے معمولی طریقہ ہے اس کے مطابق اس سے نکاح کرے تو ایسے ولیوں کو ان لڑکیوں کے نکاح سے منع کیا گیا ہے۔ سوا اس صورت کے کہ ولی مہر کو پورا کرنے میں انصاف سے کام لے۔ پھر لوگوں نے نبی کریم صلی اللہ علیہ وسلم سے اس کے بعد مسئلہ پوچھا تو اللہ تعالیٰ نے یہ آیت نازل کی «ويستفتونك في النساء‏» ”اور لوگ آپ سے عورتوں کے بارے میں مسئلہ پوچھتے ہیں۔“ اور اس واقعہ کا ذکر کیا۔' WHERE id = 6708;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم نے بیان کیا ‘ کہا ہم سے سفیان نے بیان کیا ‘ ان سے ایوب سختیانی نے ‘ ان سے عکرمہ نے اور ان سے ابن عباس رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”اپنے ہبہ کو واپس لینے والا اس کتے کی طرح ہے جو اپنی قے کو خود چاٹ جاتا ہے ‘ ہمارے لیے بری مثال مناسب نہیں۔“' WHERE id = 6718;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، کہا ہم سے لیث بن سعد نے بیان کیا، ان سے ابن الہاد نے، ان سے عبداللہ بن خباب نے اور ان سے ابو سعید خدری رضی اللہ عنہ نے کہ انہوں نے رسول اللہ صلی اللہ علیہ وسلم کو یہ فرماتے ہوئے سنا کہ جب تم میں سے کوئی ایسا خواب دیکھے جسے وہ پسند کرتا ہو تو وہ اللہ کی طرف سے ہوتا ہے۔ اس پر اللہ کی حمد کرے اور اسے بتا دینا چاہئیے لیکن اگر کوئی اس کے سوا کوئی ایسا خواب دیکھتا ہے جو اسے ناپسند ہے تو یہ شیطان کی طرف سے ہوتا ہے پس اس کے شر سے پناہ مانگے اور کسی سے ایسے خواب کا ذکر نہ کرے یہ خواب اسے کچھ نقصان نہیں پہنچا سکے گا۔“' WHERE id = 6728;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، کہا ہم سے لیث بن سعد نے بیان کیا، ان سے عبیداللہ بن ابی جعفر نے، کہا مجھ کو ابوسلمہ رضی اللہ عنہ نے خبر دی اور ان سے ابوقتادہ رضی اللہ عنہ نے بیان کیا نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”اچھے خواب اللہ کی طرف سے ہوتے ہیں اور برے خواب شیطان کی طرف سے پس جو شخص کوئی برا خواب دیکھے تو اپنے بائیں طرف کروٹ لے کر تین مرتبہ تھو تھو کرے اور شیطان سے اللہ کی پناہ مانگے وہ اس کو نقصان نہیں دے گا اور شیطان کبھی میری شکل میں نہیں آ سکتا۔“' WHERE id = 6738;
UPDATE hadiths SET urdu = 'ہم سے عبدان نے بیان کیا، کہا ہم کو یونس نے خبر دی، انہیں زہری نے، انہیں حمزہ بن عبداللہ نے خبر دی، ان سے ابن عمر رضی اللہ عنہما نے بیان کیا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم سے سنا، آپ صلی اللہ علیہ وسلم نے فرمایا کہ میں سویا ہوا تھا کہ میرے پاس دودھ کا ایک پیالہ لایا گیا اور میں نے اس کا دودھ پیا۔ یہاں تک کہ اس کی سیرابی کا اثر میں نے اپنے ناخنوں میں ظاہر ہوتا دیکھا، اس کے بعد میں نے اس کا بچا ہوا دے دیا۔ آپ کا اشارہ عمر رضی اللہ عنہ کی طرف تھا صحابہ نے پوچھا: آپ نے اس کی تعبیر کیا کی یا رسول اللہ؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ علم۔' WHERE id = 6748;
UPDATE hadiths SET urdu = 'ہم سے عبدان نے بیان کیا، کہا ہم کو عبداللہ نے خبر دی، کہا ہم کو معمر نے خبر دی، انہیں زہری نے، انہیں خارجہ بن زید بن ثابت نے اور ان سے ام علاء رضی اللہ عنہا نے بیان کیا جو انہیں کی ایک خاتون ہیں کہ میں نے رسول اللہ صلی اللہ علیہ وسلم سے بیعت کی تھی۔ انہوں نے بیان کیا کہ جب انصار نے مہاجرین کے قیام کے لیے قرعہ اندازی کی تو عثمان بن مظعون رضی اللہ عنہ کا نام ہمارے یہاں ٹھہرنے کے لیے نکلا۔ پھر وہ بیمار پڑ گئے، ہم نے ان کی تیمارداری کی لیکن ان کی وفات ہو گئی۔ پھر ہم نے انہیں ان کے کپڑوں میں لپیٹ دیا۔ اس کے بعد نبی کریم صلی اللہ علیہ وسلم ہمارے گھر تشریف لائے تو میں نے کہا: ابوالسائب! تم پر اللہ کی رحمتیں ہوں، میری گواہی ہے کہ تمہیں اللہ تعالیٰ نے عزت بخشی ہے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ تمہیں یہ کیسے معلوم ہوا؟ میں نے عرض کیا: اللہ کی قسم مجھے معلوم نہیں ہے۔ نبی کریم صلی اللہ علیہ وسلم نے اس کے بعد فرمایا کہ جہاں تک ان کا تعلق ہے تو یقینی بات ( موت ) ان تک پہنچ چکی ہے اور میں اللہ سے ان کے لیے خیر کی امید رکھتا ہوں لیکن اللہ کی قسم میں رسول اللہ ہوں اور اس کے باوجود مجھے معلوم نہیں کہ میرے ساتھ کیا معاملہ کیا جائے گا۔ ام العلاء رضی اللہ عنہا نے کہا کہ واللہ! اس کے بعد میں کسی انسان کی پاکی نہیں بیان کروں گی۔ انہوں نے بیان کیا کہ میں نے عثمان رضی اللہ عنہ کے لیے خواب میں ایک جاری چشمہ دیکھا تھا۔ چنانچہ میں نے حاضر ہو کر نبی کریم صلی اللہ علیہ وسلم سے اس کا ذکر کیا تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ یہ ان کا نیک عمل ہے جس کا ثواب ان کے لیے جاری ہے۔' WHERE id = 6759;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا ہم سے لیث بن سعد نے بیان کیا، ان سے عقیل نے، ان سے ابن شہاب نے، ان سے حمزہ بن عبداللہ نے اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم سے سنا، آپ صلی اللہ علیہ وسلم نے فرمایا کہ میں سویا ہوا تھا کہ میرے پاس دودھ کا پیالہ لایا گیا۔ میں نے اس میں سے پیا پھر میں نے اپنا بچا ہوا عمر بن خطاب کو دے دیا۔ لوگوں نے پوچھا: یا رسول اللہ! آپ نے اس کی تعبیر کیا لی؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ علم سے تعبیر لی۔' WHERE id = 6771;
UPDATE hadiths SET urdu = 'ہم سے علی بن مسلم نے بیان کیا، کہا ہم سے عبدالصمد نے بیان کیا، کہا ہم سے ابن عمر رضی اللہ عنہما کے غلام عبدالرحمٰن بن عبداللہ بن دینار نے بیان کیا، ان سے ان کے والد نے اور ان سے ابن عمر رضی اللہ عنہما نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”سب سے بدترین جھوٹ یہ ہے کہ انسان خواب میں ایسی چیز کو دیکھنے کا دعویٰ کرے جو اس کی آنکھوں نے نہ دیکھی ہو۔“' WHERE id = 6781;
UPDATE hadiths SET urdu = 'ہم سے محمد بن عرعرہ نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے قتادہ نے، ان سے انس بن مالک رضی اللہ عنہ نے اور ان سے اسید بن حضیر رضی اللہ عنہ نے ایک صاحب ( خود اسید ) نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئے اور عرض کیا: یا رسول اللہ! آپ نے فلاں عمرو بن العاص کو حاکم بنا دیا اور مجھے نہیں بنایا۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ تم لوگ انصاری میرے بعد اپنی حق تلفی دیکھو گے تو قیامت تک صبر کرنا یہاں تک کہ تم مجھ سے آ ملو۔' WHERE id = 6794;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، کہا ہم کو شعیب نے خبر دی، انہیں زہری نے۔ (دوسری سند امام بخاری رحمہ اللہ نے کہا) اور ہم سے اسماعیل نے بیان کیا، ان سے ان کے بھائی نے بیان کیا، ان سے سلیمان نے، ان سے محمد بن عقیق نے، ان سے ابن شہاب نے ‘ ان سے ہند بنت الحارث الفراسیہ نے کہ نبی کریم صلی اللہ علیہ وسلم کی زوجہ مطہرہ ام سلمہ رضی اللہ عنہا نے بیان کیا کہ ایک رات رسول اللہ صلی اللہ علیہ وسلم گھبرائے ہوئے بیدار ہوئے اور فرمایا اللہ کی ذات پاک ہے۔ اللہ تعالیٰ نے کیا کیا خزانے نازل کئے ہیں اور کتنے فتنے اتارے ہیں ان حجرہ والیوں کو کوئی بیدار کیوں نہ کرے آپ کی مراد ازواج مطہرات سے تھی تاکہ یہ نماز پڑھیں۔ بہت سے دنیا میں کپڑے باریک پہننے والیاں آخرت میں ننگی ہوں گی۔' WHERE id = 6805;
UPDATE hadiths SET urdu = 'ہم سے احمد بن اشکاب نے بیان کیا، انہوں نے کہا ہم سے محمد بن فضیل نے بیان کیا، ان سے ان کے والد نے بیان کیا، ان سے عکرمہ نے بیان کیا اور ان سے عبداللہ بن عباس رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”میرے بعد کافر نہ ہو جانا کہ تم میں بعض بعض کی گردن مارنے لگے۔“' WHERE id = 6815;
UPDATE hadiths SET urdu = 'ہم سے معاذ بن فضالہ نے بیان کیا، کہا ہم سے ہشام نے بیان کیا، ان سے قتادہ نے اور ان سے انس رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے لوگوں سے سوالات کئے آخر جب لوگ باربار سوال کرنے لگے تو نبی کریم صلی اللہ علیہ وسلم منبر پر ایک دن چڑھے اور فرمایا کہ آج تم مجھ سے جو سوال بھی کرو گے میں تمہیں اس کا جواب دوں گا۔ انس رضی اللہ عنہ نے بیان کیا کہ پھر میں دائیں بائیں دیکھنے لگا تو ہر شخص کا سر اس کے کپڑے میں چھپا ہوا تھا اور وہ رو رہا تھا۔ آخر ایک شخص نے خاموشی توڑی۔ اس کا جب کسی سے جھگڑا ہوتا تو انہیں ان کے باپ کے سوا دوسرے باپ کی طرف پکارا جاتا۔ انہوں نے کہا: یا رسول اللہ! میرے والد کون ہیں؟ فرمایا تمہارے والد حذافہ ہیں۔ پھر عمر رضی اللہ عنہ سامنے آئے اور عرض کیا ہم اللہ سے کہ وہ رب ہے، اسلام سے کہ وہ دین ہے، محمد صلی اللہ علیہ وسلم سے کہ وہ رسول ہیں راضی ہیں اور آزمائش کی برائی سے ہم اللہ کی پناہ مانگتے ہیں۔ پھر نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ میں نے خیر و شر آج جیسا دیکھا، کبھی نہیں دیکھا تھا۔ میرے سامنے جنت و دوزخ کی صورت پیش کی گئی اور میں نے انہیں دیوار کے قریب دیکھا۔ قتادہ نے بیان کیا کہ یہ بات اس آیت کے ساتھ ذکر کی جاتی ہے «يا أيها الذين آمنوا لا تسألوا عن أشياء إن تبد لكم تسؤكم‏» کہ ”اے لوگو! جو ایمان لائے ہو ایسی چیزوں کے بارے میں سوال نہ کرو اگر وہ ظاہر کر دی جائیں تو تمہیں بری معلوم ہوں۔“' WHERE id = 6825;
UPDATE hadiths SET urdu = 'ہم سے عثمان بن ہیثم نے بیان کیا، کہا ہم سے عوف نے بیان کیا، کہا ان سے حسن نے اور ان سے ابوبکرہ رضی اللہ عنہ نے بیان کیا کہ جنگ جمل کے زمانہ میں مجھے ایک کلمہ نے فائدہ پہنچایا جب نبی کریم صلی اللہ علیہ وسلم کو معلوم ہوا کہ فارس کی سلطنت والوں نے بوران نامی کسریٰ کی بیٹی کو بادشاہ بنا لیا ہے تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ وہ قوم کبھی فلاح نہیں پائے گی جس کی حکومت ایک عورت کے ہاتھ میں ہو۔' WHERE id = 6835;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل نے بیان کیا، کہا مجھ سے امام مالک نے بیان کیا، ان سے ابوالزناد نے، ان سے اعرج نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”قیامت قائم نہ ہو گی یہاں تک کہ ایک شخص دوسرے کی قبر کے پاس سے گزرے گا اور کہے گا، کاش! میں اسی کی جگہ ہوتا۔“' WHERE id = 6847;
UPDATE hadiths SET urdu = 'ہم سے عبدالعزیز بن عبداللہ اویسی نے بیان کیا، کہا ہم سے ابراہیم بن عبدالرحمٰن بن عوف کے دادا نے بیان کیا، انہوں نے ابوبکرہ سے انہوں نے نبی کریم صلی اللہ علیہ وسلم سے آپ صلی اللہ علیہ وسلم نے فرمایا ”مدینہ والوں پر دجال کا رعب نہیں پڑے گا اس دن مدینہ کے سات دروازے ہوں گے ہر دروازے پر دو فرشتے ( پہرہ دیتے ) ہوں گے۔“' WHERE id = 6857;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، کہا ہم کو شعیب نے خبر دی، انہیں زہری نے، (دوسری سند) اور امام بخاری رحمہ اللہ نے کہا کہ ہم سے اسماعیل بن ابی اویس نے بیان کیا، کہا مجھ سے میرے بھائی عبدالحمید نے، ان سے سلیمان بن بلال نے، ان سے محمد بن ابی عتیق نے، ان سے ابن شہاب نے، ان سے عروہ بن زبیر نے، ان سے زینب بنت ابی سلمہ نے بیان کیا، ان سے ام حبیبہ بنت ابی سفیان رضی اللہ عنہم نے اور ان سے زینب بنت جحش رضی اللہ عنہا نے کہ ایک دن رسول اللہ صلی اللہ علیہ وسلم ان کے پاس گھبرائے ہوئے داخل ہوئے، آپ صلی اللہ علیہ وسلم فرما رہے تھے کہ تباہی ہے عربوں کے لیے اس برائی سے جو قریب آ چکی ہے۔ آج یاجوج ماجوج کی دیوار سے اتنا کھل گیا ہے اور آپ نے اپنے انگوٹھے اور اس کی قریب والی انگلی کو ملا کر ایک حلقہ بنایا۔ اتنا سن کر زینب بن جحش رضی اللہ عنہا نے بیان کیا کہ میں نے عرض کیا: یا رسول اللہ! تو کیا ہم اس کے باوجود ہلاک ہو جائیں گے کہ ہم میں نیک صالح لوگ بھی زندہ ہوں گے؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ ہاں جب برائی بہت بڑھ جائے گی۔' WHERE id = 6867;
UPDATE hadiths SET urdu = 'ہم سے عمر بن حفص بن غیاث نے بیان کیا، انہوں نے کہا ہم سے اعمش نے بیان کیا، ان سے سعد بن عبیدہ نے بیان کیا، ان سے ابوعبدالرحمٰن نے بیان کیا اور ان سے علی رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے ایک دستہ بھیجا اور اس پر انصار کے ایک شخص کو امیر بنایا اور لوگوں کو حکم دیا کہ ان کی اطاعت کریں۔ پھر امیر فوج کے لوگوں پر غصہ ہوئے اور کہا کہ کیا نبی کریم صلی اللہ علیہ وسلم نے تمہیں میری اطاعت کا حکم نہیں دیا ہے؟ لوگوں نے کہا کہ ضرور دیا ہے۔ اس پر انہوں نے کہا کہ میں تمہیں حکم دیتا ہوں کہ لکڑی جمع کرو اور اس سے آگ جلاؤ اور اس میں کود پڑو۔ لوگوں نے لکڑی جمع کی اور آگ جلائی، جب کودنا چاہا تو ایک دوسرے کو لوگ دیکھنے لگے اور ان میں سے بعض نے کہا کہ ہم نے نبی کریم صلی اللہ علیہ وسلم کی فرمانبرداری آگ سے بچنے کے لیے کی تھی، کیا پھر ہم اس میں خود ہی داخل ہو جائیں۔ اسی دوران میں آگ ٹھنڈی ہو گئی اور امیر کا غصہ بھی جاتا رہا۔ پھر نبی کریم صلی اللہ علیہ وسلم سے اس کا ذکر کیا گیا تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ اگر یہ لوگ اس میں کود پڑتے تو پھر اس میں سے نہ نکل سکتے۔ اطاعت صرف اچھی باتوں میں ہے۔' WHERE id = 6877;
UPDATE hadiths SET urdu = 'ہم سے محمد بن خالد ذہلی نے بیان کیا، کہا ہم سے انصاری محمد نے بیان کیا، کہا ہم سے ہمارے والد نے بیان کیا، ان سے ثمامہ نے اور ان سے انس بن مالک رضی اللہ عنہ نے کہ قیس بن سعد رضی اللہ عنہ نبی کریم صلی اللہ علیہ وسلم کے ساتھ اس طرح رہتے تھے جیسے امیر کے ساتھ کوتوال رہتا ہے۔' WHERE id = 6887;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ نے بیان کیا، ان سے سفیان نے بیان کیا، ان سے زہری نے بیان کیا، ان سے سہل بن سعد رضی اللہ عنہ نے بیان کیا کہ میں نے دو لعان کرنے والوں کو دیکھا، میں اس وقت پندرہ سال کا تھا اور ان دونوں کے درمیان جدائی کرا دی گئی تھی۔' WHERE id = 6897;
UPDATE hadiths SET urdu = 'ہم سے عثمان بن صالح نے بیان کیا، انہوں نے کہا ہم سے عبداللہ بن وہب نے بیان کیا، انہوں نے کہا مجھ کو ابن جریج نے خبر دی، انہیں نافع نے خبر دی، انہیں عبداللہ بن عمر رضی اللہ عنہما نے خبر دی کہا کہ ابوحذیفہ رضی اللہ عنہ کے ( آزاد کردہ غلام ) سالم، مہاجر اولین کی اور نبی کریم صلی اللہ علیہ وسلم کے دوسرے صحابہ رضی اللہ عنہم مسجد قباء میں امامت کیا کرتے تھے۔ ان اصحاب میں ابوبکر، عمر، ابوسلمہ، زید اور عامر بن ربیعہ رضی اللہ عنہم بھی ہوتے تھے۔' WHERE id = 6907;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، انہوں نے کہا ہم سے یحییٰ بن سعید نے بیان کیا، ان سے ابن جریج نے بیان کیا، انہوں نے ابن ابی ملیکہ سے سنا، وہ عائشہ رضی اللہ عنہا سے بیان کرتے تھے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”اللہ کے نزدیک سب سے مبغوض وہ شخص ہے جو سخت جھگڑالو ہو۔“' WHERE id = 6918;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، انہوں نے کہا ہم کو امام مالک نے خبر دی، انہیں عبداللہ بن دینار نے اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا کہ جب ہم رسول اللہ صلی اللہ علیہ وسلم سے سننے اور اطاعت کرنے کی بیعت کرتے تو آپ ہم سے فرماتے کہ جتنی تمہیں طاقت ہو۔' WHERE id = 6930;
UPDATE hadiths SET urdu = 'ہم سے محمود بن غیلان نے بیان کیا، کہا ہم سے عبدالرزاق بن ہمام نے بیان کیا، کہا ہم کو معمر نے خبر دی، انہیں زہری نے، انہیں عروہ نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم عورتوں سے زبانی اس آیت کے احکام کی بیعت لیتے کہ وہ اللہ کے ساتھ کسی کو شریک نہیں ٹھہرائیں گی آخر آیت تک۔ بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم کے ہاتھ نے کبھی کسی عورت کا ہاتھ نہیں چھوا، سوا اس عورت کے جو آپ کی لونڈی ہو۔' WHERE id = 6942;
UPDATE hadiths SET urdu = 'ہم سے سعید بن عفیر نے بیان کیا، کہا مجھ سے لیث بن سعد نے، کہا مجھ سے عبدالرحمٰن بن خالد نے بیان کیا، ان سے ابن شہاب نے، ان سے ابوسلمہ اور سعید بن مسیب نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ میں نے رسول اللہ صلی اللہ علیہ وسلم نے سنا آپ صلی اللہ علیہ وسلم نے فرمایا ”اس ذات کی قسم جس کے ہاتھ میں میری جان ہے۔ اگر ان لوگوں کا خیال نہ ہوتا جو میرے ساتھ غزوہ میں شریک نہ ہو سکنے کو برا جانتے ہیں مگر اسباب کی کمی کی وجہ سے وہ شریک نہیں ہو سکتے اور کوئی ایسی چیز میرے پاس نہیں ہے جس پر انہیں سوار کروں تو میں کبھی ( غزاوات میں شریک ہونے سے ) پیچھے نہ رہتا۔ میری خواہش ہے کہ اللہ کے راستے میں قتل کیا جاؤں پھر زندہ کیا جاؤں، پھر قتل کیا جاؤں، پھر زندہ کیا جاؤں، پھر قتل کیا جاؤں، اور پھر زندہ کیا جاؤں اور پھر مارا جاؤں۔“' WHERE id = 6953;
UPDATE hadiths SET urdu = 'ہم سے عبدان نے بیان کیا، کہا ہم کو ہمارے والد عثمان بن جبلہ نے خبر دی، انہیں شعبہ نے، ان سے ابواسحاق نے بیان کیا اور ان سے براء بن عازب رضی اللہ عنہ نے کہ غزوہ خندق کے دن ( خندق کھودتے ہوئے ) رسول اللہ صلی اللہ علیہ وسلم بھی خود ہمارے ساتھ مٹی اٹھایا کرتے تھے۔ میں نے نبی کریم صلی اللہ علیہ وسلم کو اس حال میں دیکھا کہ مٹی نے آپ کے پیٹ کی سفیدی کو چھپا دیا تھا۔ آپ صلی اللہ علیہ وسلم فرماتے تھے ”اگر تو نہ ہوتا ( اے اللہ! ) تو ہم نہ ہدایت پاتے، نہ ہم صدقہ دیتے، نہ نماز پڑھتے۔ پس ہم پر دل جمعی نازل فرما۔ اس معاندین کی جمات نے ہمارے خلاف حد سے آگے بڑھ کر حملہ کیا ہے۔ جب یہ فتنہ چاہتے ہیں تو ہم ان کی بات نہیں مانتے، نہیں مانتے۔ اس پر آپ آواز کو بلند کر دیتے۔“' WHERE id = 6963;
UPDATE hadiths SET urdu = 'ہم سے محمد بن مثنیٰ نے بیان کیا، کہا ہم سے عبدالوہاب نے بیان کیا، کہا ہم سے ایوب نے بیان کیا، ان سے ابوقلابہ نے، ان سے مالک رضی اللہ عنہ نے بیان کیا کہ ہم نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئے۔ ہم سب جوان اور ہم عمر تھے، ہم آپ کی خدمت میں بیس دن تک ٹھہرے رہے۔ نبی کریم صلی اللہ علیہ وسلم بہت شفیق تھے۔ جب آپ نے معلوم کیا کہ اب ہمارا دل اپنے گھر والوں کی طرف مشتاق ہے تو آپ نے ہم سے پوچھا کہ اپنے پیچھے ہم کن لوگوں کو چھوڑ کر آئے ہیں۔ ہم نے آپ کو بتایا تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ اپنے گھر چلے جاؤ اور ان کے ساتھ رہو اور انہیں اسلام سکھاؤ اور دین بتاؤ اور بہت سی باتیں آپ نے کہیں جن میں بعض مجھے یاد نہیں ہیں اور بعض یاد ہیں اور ( فرمایا کہ ) جس طرح مجھے تم نے نماز پڑھتے دیکھا اسی طرح نماز پڑھو۔ پس جب نماز کا وقت آ جائے تو تم میں سے ایک تمہارے لیے اذان کہے اور جو عمر میں سب سے بڑا ہو وہ امامت کرائے۔' WHERE id = 6973;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا، انہوں نے کہا ہم سے حماد بن زید نے بیان کیا، ان سے یحییٰ بن سعید نے بیان کیا، ان سے عبید بن حنین نے بیان کیا، ان سے عبداللہ بن عباس رضی اللہ عنہما نے کہ عمر رضی اللہ عنہ نے بیان کیا کہ قبیلہ انصار کے ایک صاحب تھے ( اوس بن خولیٰ نام ) جب وہ رسول اللہ صلی اللہ علیہ وسلم کی مجلس میں شرکت نہ کر سکتے اور میں شریک ہوتا تو انہیں آ کر نبی کریم صلی اللہ علیہ وسلم کی مجلس کی خبریں بتاتا اور جب میں نبی کریم صلی اللہ علیہ وسلم کی مجلس میں شریک نہ ہو پاتا اور وہ شریک ہوتے تو وہ آ کر نبی کریم صلی اللہ علیہ وسلم کی مجلس کی خبر مجھے بتاتے۔' WHERE id = 6983;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن زبیر حمیدی نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے بیان کیا، ان سے مسعر بن کدام اور ان کے علاوہ (سفیان ثوری) نے، ان سے قیس بن مسلم نے، ان سے طارق بن شہاب نے بیان کیا کہ ایک یہودی ( کعب احبار اسلام لانے سے پہلے ) نے عمر رضی اللہ عنہ سے کہا: اے امیرالمؤمنین! اگر ہمارے یہاں سورۃ المائدہ کی یہ آیت نازل ہوتی «اليوم أكملت لكم دينكم وأتممت عليكم نعمتي ورضيت لكم الإسلام دينا‏» کہ ”آج میں نے تمہارے لیے تمہارے دین کو مکمل کر دیا اور تم پر اپنی نعمت کو پورا کر دیا اور تمہارے لیے اسلام کو بطور دین کے پسند کر لیا۔“ تو ہم اس دن کو عید ( خوشی ) کا دن بنا لیتے۔ عمر رضی اللہ عنہ نے کہا کہ میں جانتا ہوں کہ یہ آیت کس دن نازل ہوئی تھی، عرفہ کے دن نازل ہوئی اور جمعہ کا دن تھا۔ امام بخاری نے کہا یہ روایت سفیان نے مسعر سے سنی، مسعر نے قیس سے سنا اور قیس نے طارق سے۔' WHERE id = 6994;
UPDATE hadiths SET urdu = 'ہم سے محمد بن سنان نے بیان کیا، ان سے فلیح بن سلیمان نے بیان کیا، ان سے ہلال بن علی نے بیان کیا، ان سے عطاء بن یسار نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”ساری امت جنت میں جائے گی سوائے ان کے جنہوں نے انکار کیا۔“ صحابہ نے عرض کیا: یا رسول اللہ! انکار کون کرے گا؟ فرمایا ”جو میری اطاعت کرے گا وہ جنت میں داخل ہو گا اور جو میری نافرمانی کرے گا اس نے انکار کیا۔“' WHERE id = 7005;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، کہا ہم سے ابوعوانہ نے بیان کیا، کہا ہم سے عبدالملک بن عمیر کوفی نے بیان کیا، ان سے مغیرہ رضی اللہ عنہ کے کاتب وراد نے بیان کیا کہ معاویہ رضی اللہ عنہ نے مغیرہ رضی اللہ عنہ کو لکھا کہ جو تم نے رسول اللہ صلی اللہ علیہ وسلم سے سنا ہے وہ مجھے لکھئیے تو انہوں نے انہیں لکھا کہ نبی کریم صلی اللہ علیہ وسلم ہر نماز کے بعد کہتے تھے «لا إله إلا الله،‏‏‏‏ وحده لا شريك له،‏‏‏‏ له الملك وله الحمد،‏‏‏‏ وهو على كل شىء قدير،‏‏‏‏ اللهم لا مانع لما أعطيت،‏‏‏‏ ولا معطي لما منعت،‏‏‏‏ ولا ينفع ذا الجد منك الجد» ”تنہا اللہ کے سوا کوئی معبود نہیں، اس کا کوئی شریک نہیں، ملک اسی کا ہے اور تمام تعریف اسی کے لیے ہیں اور وہ ہر چیز پر قادر ہے! اے اللہ جو تو عطا کرے اسے کوئی روکنے والا نہیں اور جسے تو روکے اسے کوئی دینے والا نہیں اور کسی نصیبہ ور کا نصیبہ تیرے مقابلہ میں اسے نفع نہیں پہنچا سکے گا اور انہیں یہ بھی لکھا کہ نبی کریم صلی اللہ علیہ وسلم بےفائدہ بہت سوال کرنے سے منع کرتے تھے اور مال ضائع کرنے سے اور آپ ماؤں کی نافرمانی کرنے سے منع کرتے تھے اور لڑکیوں کو زندہ درگور کرنے سے اور اپنا حق محفوظ رکھنے اور دوسروں کا حق نہ دینے سے اور بےضرورت مانگنے سے منع فرماتے تھے۔' WHERE id = 7016;
UPDATE hadiths SET urdu = 'ہم سے محمد بن مقاتل ابوالحسن مروزی نے بیان کیا، کہا ہم کو وکیع نے خبر نے دی، انہیں نافع بن عمر نے، ان سے ابن ابی ملکیہ نے بیان کیا کہ امت کے دو بہترین انسان قریب تھا کہ ہلاک ہو جاتے ( یعنی ابوبکر و عمر رضی اللہ عنہما ) جس وقت نبی کریم صلی اللہ علیہ وسلم کے پاس بنی تمیم کا وفد آیا تو ان میں سے ایک صاحب ( عمر رضی اللہ عنہ ) نے بنی مجاشع میں سے اقرع بن حابس حنظلی رضی اللہ عنہ کو ان کا سردار بنائے جانے کا مشورہ دیا ( تو انہوں نے یہ درخواست کی کہ کسی کو ہمارا سردار بنا دیجئیے ) اور دوسرے صاحب ( ابوبکر رضی اللہ عنہ ) نے دوسرے ( قعقاع بن سعید بن زرارہ ) کو بنائے جانے کا مشورہ دیا۔ اس پر ابوبکر رضی اللہ عنہ نے عمر رضی اللہ عنہ سے کہا کہ آپ کا مقصد صرف میری مخالفت کرنا ہے۔ عمر رضی اللہ عنہ نے کہا کہ میری نیت آپ کی مخالفت کرنا نہیں ہے اور نبی کریم صلی اللہ علیہ وسلم کی موجودگی میں دونوں بزرگوں کی آواز بلند ہو گئی۔ چنانچہ یہ آیت نازل ہوئی «يا أيها الذين آمنوا لا ترفعوا أصواتكم‏» ”اے لوگوں! جو ایمان لے آئے ہو اپنی آواز کو بلند نہ کرو۔“ اللہ تعالیٰ کے ارشاد «عظيم‏» تک۔ ابن ابی ملکیہ نے بیان کیا کہ ابن زبیر رضی اللہ عنہا کہتے تھے کہ عمر رضی اللہ عنہ نے اس آیت کے اترنے کے بعد یہ طریقہ اختیار کیا اور ابن زبیر نے ابوبکر رضی اللہ عنہ اپنے نانا کا ذکر کیا وہ جب نبی کریم صلی اللہ علیہ وسلم سے کچھ عرض کرتے تو اتنی آہستگی سے جیسے کوئی کان میں بات کرتا ہے حتیٰ کہ نبی کریم صلی اللہ علیہ وسلم کو بات سنائی نہ دیتی تو آپ دوبارہ پوچھتے کیا کہا۔' WHERE id = 7026;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل بن ابی اویس نے بیان کیا، کہا ہم سے عبداللہ بن وہب نے بیان کیا، ان سے یونس نے، ان سے ابن شہاب نے انہیں حمید نے خبر دی، کہا کہ میں نے معاویہ بن ابی سفیان رضی اللہ عنہما سے سنا، وہ خطبہ دے رہے تھے، انہوں نے کہا کہ میں نے نبی کریم صلی اللہ علیہ وسلم سے سنا ہے، نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اللہ جس کے ساتھ خیر کا ارادہ کرتا ہے اسے دین کی سمجھ عطا فرما دیتا ہے اور میں تو صرف تقسیم کرنے والا ہوں اور دیتا اللہ ہے اور اس امت کا معاملہ ہمیشہ درست رہے گا، یہاں تک کہ قیامت قائم ہو جائے یا ( آپ صلی اللہ علیہ وسلم نے یوں فرمایا کہ ) یہاں تک کہ اللہ کا حکم آ پہنچے۔' WHERE id = 7036;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا، کہا ہم سے حماد بن زید نے، ان سے ایوب سختیانی نے، ان سے محمد بن سیرین نے بیان کیا کہ ہم ابوہریرہ رضی اللہ عنہ کے پاس تھے اور ان کے جسم پر کتان کے دو کپڑے گیرو میں رنگے ہوئے تھے۔ انہوں نے ان ہی کپڑوں میں ناک صاف کی اور کہا واہ واہ دیکھو ابوہریرہ کتان کے کپڑوں میں ناک صاف کرتا ہے، اب ایسا مالدار ہو گیا حالانکہ میں نے اپنے آپ کو ایک زمانہ میں ایسا پایا ہے کہ میں رسول اللہ صلی اللہ علیہ وسلم کے منبر اور عائشہ رضی اللہ عنہا کے حجرہ کے درمیان بیہوش ہو کر گڑ پڑتا تھا اور گزرنے والا میری گردن پر یہ سمجھ کر پاؤں رکھتا تھا کہ میں پاگل ہو گیا ہوں، حالانکہ مجھے جنون نہیں ہوتا تھا، بلکہ صرف بھوک کی وجہ سے میری یہ حالت ہو جاتی تھی۔' WHERE id = 7047;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، کہا ہم سے جویریہ نے بیان کیا، ان سے نافع نے اور ان سے عبداللہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے گھوڑوں کی دوڑ کرائی اور وہ گھوڑے چھوڑے گئے جو گھوڑ دوڑ کیلئے تیار کئے گئے تھے تو ان کے دوڑنے کا میدان مقام حفیاء سے ثنیۃ الوداع تک تھا اور جو تیار نہیں کئے گئے تھے ان کے دوڑنے کا میدان ثنیۃ الوداع سے مسجد بنی زریق تک تھا اور عبداللہ رضی اللہ عنہ بھی ان لوگوں میں تھے جنہوں نے مقابلے میں حصہ لیا تھا۔' WHERE id = 7058;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، ان سے لیث بن سعد نے بیان کیا، ان سے سعید مقبری نے، ان سے ان کے والد ابوسعید کیسان نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ ہم مسجد نبوی میں تھے کہ رسول اللہ صلی اللہ علیہ وسلم باہر تشریف لائے اور فرمایا کہ یہودیوں کے پاس چلو۔ چنانچہ ہم نبی کریم صلی اللہ علیہ وسلم کے ساتھ روانہ ہوئے۔ جب ہم ان کے مدرسہ تک پہنچے تو نبی کریم صلی اللہ علیہ وسلم نے کھڑے ہو کر انہیں آواز دی اور فرمایا، اے یہودیو! اسلام لاؤ تو تم سلامت رہو گے۔ اس پر یہودیوں نے کہا کہ ابوالقاسم! آپ نے اللہ کا حکم پہنچا دیا۔ راوی نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے دوبارہ ان سے فرمایا کہ یہی میرا مقصد ہے، اسلام لاؤ تو تم سلامت رہو گے۔ انہوں نے کہا ابوالقاسم! آپ نے اللہ کا پیغام پہنچا دیا۔ پھر آپ صلی اللہ علیہ وسلم نے یہی بات تیسری بار کہی اور فرمایا، جان لو کہ ساری زمین اللہ اور اس کے رسول کی ہے اور میں چاہتا ہوں کہ تمہیں اس جگہ سے باہر کر دوں۔ پس تم میں سے جو کوئی اپنی جائیداد کے بدلے میں کوئی قیمت پاتا ہو تو اسے بیچ لے ورنہ جان لو کہ زمین اللہ اور اس کے رسول کی ہے ( تم کو یہ شہر چھوڑنا ہو گا ) ۔' WHERE id = 7069;
UPDATE hadiths SET urdu = 'مجھ سے عبیداللہ بن سعد بن ابراہیم نے بیان کیا، کہا مجھ سے میرے والد اور چچا نے بیان کیا، کہا کہ مجھ سے میرے والد نے بیان کیا اور ان سے ان کے والد نے، انہیں محمد بن جبیر نے خبر دی اور انہیں ان کے والد جبیر بن مطعم رضی اللہ عنہ نے خبر دی کہ ایک خاتون رسول اللہ صلی اللہ علیہ وسلم کے پاس آئیں تو نبی کریم صلی اللہ علیہ وسلم نے انہیں ایک حکم دیا۔ انہوں نے عرض کیا: یا رسول اللہ! اگر میں آپ کو نہ پاؤں تو پھر کیا کروں گی؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ جب مجھے نہ پانا تو ابوبکر رضی اللہ عنہ کے پاس جانا۔ حمیدی نے ابراہیم بن سعد سے یہ اضافہ کیا کہ غالباً خاتون کی مراد وفات تھی۔ امام بخاری رحمہ اللہ نے کہا کہ حمیدی نے اس روایت میں ابراہیم بن سعد سے اتنا بڑھایا ہے کہ آپ کو نہ پاؤں، اس سے مراد یہ ہے کہ آپ کی وفات ہو جائے۔' WHERE id = 7080;
UPDATE hadiths SET urdu = 'ہم سے محمد بن حرب نے بیان کیا، کہا ہم سے یحییٰ بن زکریا نے بیان کیا، ان سے ہشام بن عروہ نے، ان سے عروہ اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے لوگوں کو خطاب کیا اور اللہ کی حمد و ثنا کے بعد فرمایا ”تم مجھے ان لوگوں کے بارے میں مشورہ دیتے ہو جو میرے اہل خانہ کو بدنام کرتے ہیں حالانکہ ان کے بارے میں مجھے کوئی بری بات کبھی نہیں معلوم ہوئی۔ عروہ سے روایت ہے، انہوں نے ہم سے بیان کیا کہ عائشہ رضی اللہ عنہا کو جب اس واقعہ کا علم ہوا ( کہ کچھ لوگ انہیں بدنام کر رہے ہیں ) تو انہوں نے نبی کریم صلی اللہ علیہ وسلم سے کہا: یا رسول اللہ! کیا مجھے آپ اپنے والد کے گھر جانے کی اجازت دیں گے؟ نبی کریم صلی اللہ علیہ وسلم نے انہیں اجازت دی اور ان کے ساتھ غلام کو بھیجا۔ انصار میں سے ایک صاحب ابوایوب رضی اللہ عنہ نے کہا «سبحانك ما يكون لنا أن نتكلم بهذا،‏‏‏‏ ‏‏‏‏ سبحانك هذا بهتان عظيم‏.‏» ”تیری ذات پاک ہے، اے اللہ! ہمارے لیے مناسب نہیں کہ ہم اس طرح کی باتیں کریں تیری ذات پاک ہے، یہ تو بہت بڑا بہتان ہے۔“' WHERE id = 7090;
UPDATE hadiths SET urdu = 'ہم سے محمد بن یوسف نے بیان کیا، انہوں نے کہا ہم سے سفیان نے بیان کیا، ان سے اسماعیل نے بیان کیا، ان سے شعبی نے بیان کیا، ان سے مسروق نے اور ان سے عائشہ رضی اللہ عنہما نے بیان کیا کہ اگر تم سے کوئی یہ کہتا ہے کہ محمد صلی اللہ علیہ وسلم نے اپنے رب کو دیکھا تو وہ غلط کہتا ہے کیونکہ اللہ تعالیٰ اپنے بارے میں خود کہتا ہے کہ نظریں اس کو دیکھ نہیں سکتیں اور جو کوئی کہتا ہے کہ نبی کریم صلی اللہ علیہ وسلم غیب جانتے تھے تو غلط کہتا ہے کیونکہ اللہ تعالیٰ خود کہتا ہے کہ غیب کا علم اللہ کے سوا اور کسی کو نہیں۔' WHERE id = 7100;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، انہوں نے کہا ہم کو شعیب نے خبر دی، کہا ہم سے ابوالزناد نے بیان کیا، ان سے اعرج نے بیان کیا اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”اللہ تعالیٰ کے ننانوے نام ہیں، جو انہیں یاد کر لے گا وہ جنت میں جائے گا۔“' WHERE id = 7111;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، کہا ہم کو شعیب نے خبر دی، انہیں زہری نے، انہیں عمرو بن ابی سفیان بن اسید بن جاریہ ثقفی نے خبر دی جو بنی زہرہ کے حلیف تھے اور ابوہریرہ رضی اللہ عنہ کے شاگردوں میں تھے کہ ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے عضل اور قارہ والوں کی درخواست پر دس اکابر صحابہ کو جن میں خبیب رضی اللہ عنہ بھی تھے، ان کے ہاں بھیجا۔ ابن شہاب نے کہا کہ مجھے عبیداللہ بن عیاض نے خبر دی کہ حارث کی صاحبزادی زینب نے انہیں بتایا کہ جب لوگ خبیب رضی اللہ عنہ کو قتل کرنے کے لیے آمادہ ہوئے ( اور قید میں تھے ) تو اسی زمانے میں انہوں نے ان سے صفائی کرنے کے لیے استرہ لیا تھا، جب وہ لوگ خبیب رضی اللہ عنہ کو حرم سے باہر قتل کرنے لے گئے تو انہوں نے یہ اشعار کہے۔ ”اور جب میں مسلمان ہونے کی حالت میں قتل کیا جا رہا ہوں تو مجھے اس کی پروا نہیں کہ مجھے کس پہلو پر قتل کیا جائے گا اور میرا یہ مرنا اللہ کے لیے ہے اور اگر وہ چاہے گا تو میرے ٹکڑے ٹکڑے کئے ہوئے اعضاء پر برکت نازل کرے گا۔“ پھر ابن الحارث نے انہیں قتل کر دیا اور نبی کریم صلی اللہ علیہ وسلم نے اپنے صحابہ کو اس حادثہ کی اطلاع اسی دن دی جس دن یہ حضرات شہید کئے گئے تھے۔' WHERE id = 7121;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، انہوں نے کہا اس نے یحییٰ بن سعید سے سنا، انہوں نے سفیان سے، انہوں نے کہا ہم سے منصور اور سلیمان نے بیان کیا، ان سے ابراہیم نے بیان کیا، ان سے عبیدہ نے بیان کیا اور ان سے عبداللہ نے بیان کیا کہ ایک یہودی نبی کریم صلی اللہ علیہ وسلم کے پاس آیا اور کہا: اے محمد! اللہ آسمانوں کو ایک انگلی پر روک لے گا اور زمین کو بھی ایک انگلی پر اور پہاڑوں کو ایک انگلی پر اور درختوں کو ایک انگلی پر اور مخلوقات کو ایک انگلی پر، پھر فرمائے گا کہ میں بادشاہ ہوں۔ اس کے بعد رسول اللہ صلی اللہ علیہ وسلم مسکرا دئیے یہاں تک کہ آپ کے آگے کے دندان مبارک دکھائی دینے لگے۔ پھر سورۃ الانعام کی یہ آیت پڑھی «وما قدروا الله حق قدره‏» ۔ یحییٰ بن سعید نے بیان کیا کہ اس روایت میں فضیل بن عیاض نے منصور سے اضافہ کیا، ان سے ابراہیم نے، ان سے عبیدہ نے، ان سے عبداللہ رضی اللہ عنہ نے کہ پھر نبی کریم صلی اللہ علیہ وسلم اس پر تعجب کی وجہ سے اور اس کی تصدیق کرتے ہوئے ہنس دیئے۔' WHERE id = 7132;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن جعفر نے بیان کیا، انہوں نے کہا ہم سے ابومعاویہ نے بیان کیا، ان سے اعمش نے اور ان سے ابراہیم تیمی نے، ان سے ان کے والد نے اور ان سے ابوذر رضی اللہ عنہ نے بیان کیا کہ میں مسجد میں داخل ہوا اور رسول اللہ صلی اللہ علیہ وسلم بیٹھے ہوئے تھے، پھر جب سورج غروب ہوا تو آپ صلی اللہ علیہ وسلم نے فرمایا ”اے ابوذر! کیا تمہیں معلوم ہے یہ کہاں جاتا ہے؟“ بیان کیا کہ میں نے عرض کیا کہ اللہ اور اس کا رسول زیادہ جاننے والے ہیں۔ فرمایا کہ یہ جاتا ہے اور سجدہ کی اجازت چاہتا ہے پھر اسے اجازت دی جاتی ہے اور گویا اس سے کہا جاتا ہے کہ واپس وہاں جاؤ جہاں سے آئے ہو۔ چنانچہ وہ مغرب کی طرف سے طلوع ہوتا ہے، پھر آپ نے یہ آیت پڑھی «ذلك مستقر لها‏» عبداللہ رضی اللہ عنہ کی قرآت یوں ہی ہے۔' WHERE id = 7142;
UPDATE hadiths SET urdu = 'ہم سے عبدۃ بن عبداللہ نے بیان کیا، کہا ہم سے حسین جعفی نے بیان کیا ان سے زائد نے، ان سے بیان بن بشر نے، ان سے قیس بن ابی حازم نے اور ان سے جریر رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم چودھویں رات کو ہمارے پاس تشریف لائے اور فرمایا کہ تم اپنے رب کو قیامت کے دن اس طرح دیکھو گے جس طرح اس چاند کو دیکھ رہے ہو۔ اس کے دیکھنے میں کوئی مزاحمت نہیں ہو گی۔ کھلم کھلا دیکھو گے، بےتکلف، بےمشقت، بےزحمت۔' WHERE id = 7153;
UPDATE hadiths SET urdu = 'ہم سے محمد بن مثنیٰ نے بیان کیا، انہوں نے کہا ہم سے عبدالوہاب نے بیان کیا، انہوں نے کہا ہم سے ایوب سختیانی نے بیان کیا، ان سے محمد بن سیرین نے بیان کیا، ان سے عبدالرحمٰن بن ابی بکرہ نے بیان کیا اور ان سے ابوبکرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”زمانہ اپنی اصلی قدیم ہیئت پر گھوم کر آ گیا ہے جس پر اللہ تعالیٰ نے زمین و آسمان کو پیدا کیا تھا۔ سال بارہ مہینے کا ہوتا ہے جن میں چار مہینے حرمت والے مہینے ہیں۔ تین مسلسل یعنی ذیقعدہ، ذی الحجہ اور محرم اور رجب مضر جو جمادی الاخریٰ اور شعبان کے درمیان میں آتا ہے۔ پھر آپ نے پوچھا کہ یہ کون سا مہینہ ہے؟ ہم نے کہا کہ اللہ اور اس کے رسول کو زیادہ علم ہے۔ آپ خاموش ہو گئے اور ہم نے سمجھا کہ آپ اس کا کوئی اور نام رکھیں گے لیکن آپ صلی اللہ علیہ وسلم نے فرمایا کیا یہ ذی الحجہ نہیں ہے؟ ہم نے کہا کیوں نہیں۔ پھر فرمایا یہ کون سا شہر ہے؟ ہم نے کہا اللہ اور اس کے رسول کو زیادہ علم ہے پھر آپ خاموش ہو گئے اور ہم نے سمجھا کہ آپ اس کا کوئی اور نام رکھیں گے لیکن آپ صلی اللہ علیہ وسلم نے فرمایا کیا یہ بلدہ طیبہ ( مکہ ) نہیں ہے؟ ہم نے عرض کیا کیوں نہیں۔ پھر فرمایا یہ کون سا دن ہے؟ ہم نے عرض کیا اللہ اور اس کے رسول کو زیادہ علم ہے۔ پھر آپ خاموش ہو گئے ہم نے سمجھا کہ آپ صلی اللہ علیہ وسلم اس کا کوئی اور نام رکھیں گے لیکن آپ صلی اللہ علیہ وسلم نے فرمایا کیا یہ یوم النحر ( قربانی کا دن ) نہیں ہے؟ ہم نے کہا کیوں نہیں پھر فرمایا کہ پھر تمہارا خون اور تمہارے اموال۔ محمد نے بیان کیا کہ مجھے خیال ہے کہ یہ بھی کہا کہ اور تمہاری عزت تم پر اسی طرح حرمت والے ہیں جیسے تمہارے اس دن کی حرمت تمہارے اس شہر اور اس مہینے میں ہے اور عنقریب تم اپنے رب سے ملو گے اور وہ تمہارے اعمال کے متعلق تم سے سوال کرے گا۔ آگاہ ہو جاؤ کہ میرے بعد گمراہ نہ ہو جانا کہ ایک دوسرے کو قتل کرنے لگو۔ آگاہ ہو جاؤ! جو موجود ہیں وہ غیر حاضروں کو میری یہ بات پہنچا دیں۔ شاید کوئی جسے بات پہنچائی گئی ہو وہ یہاں سننے والے سے زیادہ محفوظ رکھنے والا ہو۔ چنانچہ محمد بن سیرین جب اس کا ذکر کرتے تو کہتے کہ نبی کریم صلی اللہ علیہ وسلم نے سچ فرمایا۔ پھر آپ صلی اللہ علیہ وسلم نے فرمایا، ہاں کیا میں نے پہنچا دیا؟ ہاں! کیا میں نے پہنچا دیا؟' WHERE id = 7163;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل بن ابی اویس نے بیان کیا، کہا ہم سے امام مالک نے بیان کیا، ان سے ابوالزناد نے، ان سے اعرج نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”جس شخص نے اللہ کے راستہ میں جہاد کیا اور اس کے لیے نکلنے کا مقصد اس کے راستے میں جہاد اور اس کے کلام کی تصدیق کے سوا اور کچھ نہیں تھا تو اللہ اس کا ضامن ہے کہ اسے جنت میں داخل کرے ( اگر وہ شہید ہو گیا ) یا ثواب اور مال غنیمت کے ساتھ اسے وہیں واپس لوٹائے جہاں سے وہ آیا تھا۔“' WHERE id = 7173;
UPDATE hadiths SET urdu = 'ہم سے حکم بن نافع نے بیان کیا، انہوں نے کہا ہم کو شعیب نے خبر دی، انہیں زہری نے، کہا مجھ کو سالم بن عبداللہ نے خبر دی اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم سے سنا، آپ منبر پر کھڑے فرما رہے تھے کہ تمہارا زمانہ گزشتہ امتوں کے مقابلہ میں ایسا ہے جیسے عصر سے سورج ڈوبنے تک کا وقت ہوتا ہے۔ توریت والوں کو توریت دی گئی اور انہوں نے اس پر عمل کیا، یہاں تک کہ دن آدھا ہو گیا۔ پھر وہ عاجز ہو گئے تو انہیں اس کے بدلے میں ایک قیراط دیا گیا۔ پھر اہل انجیل کو انجیل دی گئی تو انہوں نے اس پر عصر کی نماز کے وقت تک عمل کیا اور پھر وہ عمل سے عاجز آ گئے تو انہیں بھی ایک ایک قیراط دیا گیا۔ پھر تمہیں قرآن دیا گیا اور تم نے اس پر سورج ڈوبنے تک عمل کیا اور تمہیں اس کے بدلے میں دو دو قیراط دئیے گئے۔ اہل توریت نے اس پر کہا کہ اے ہمارے رب! یہ لوگ مسلمان سب سے کم کام کرنے والے اور سب سے زیادہ اجر پانے والے ہیں۔ اللہ تعالیٰ نے اس پر فرمایا کہ کیا میں نے تمہیں اجر دینے میں کوئی ناانصافی کی ہے؟ وہ بولے کہ نہیں! تو اللہ تعالیٰ فرمایا کہ یہ تو میرا فضل ہے، میں جس پر چاہتا ہوں کرتا ہوں۔' WHERE id = 7183;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ نے بیان کیا، انہوں نے کہا ہم سے عبدالرزاق نے بیان کیا، ان سے معمر نے، ان سے ہمام نے اور انہوں نے ابوہریرہ رضی اللہ عنہ سے سنا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”کوئی شخص اس طرح دعا نہ کرے کہ اے اللہ! اگر تو چاہے تو میری مغفرت کر، اگر تو چاہے تو مجھ پر رحم کر، اگر تو چاہے تو مجھے روزی دے، بلکہ پختگی کے ساتھ سوال کرنا چاہئیے کیونکہ اللہ جو چاہتا ہے کرتا ہے کوئی اس پر جبر کرنے والا نہیں۔“' WHERE id = 7193;
UPDATE hadiths SET urdu = 'ہم سے محمد بن بشار نے بیان کیا، کہا ہم سے غندر نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے واصل نے بیان کیا، ان سے معرور نے بیان کیا کہ میں نے ابوذر رضی اللہ عنہ سے سنا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”میرے پاس جبرائیل علیہ السلام آئے اور مجھے بشارت دی کہ جو شخص اس حال میں مرے گا کہ وہ اللہ کے ساتھ کسی کو شریک نہیں ٹھہراتا ہو گا تو وہ جنت میں جائے گا۔ میں نے پوچھا گو اس نے چوری اور زنا بھی کیا ہو؟ فرمایا کہ گو اس نے چوری اور زنا کیا ہو۔“' WHERE id = 7203;
UPDATE hadiths SET urdu = 'ہم سے محمود بن غیلان نے بیان کیا، انہوں نے کہا ہم سے عبدالرزاق نے بیان کیا، کہا ہم کو ابن جریج نے خبر دی، انہوں نے مجھ کو سلیمان احول نے خبر دی، انہیں طاؤس یمانی نے خبر دی، انہوں نے عبداللہ بن عباس رضی اللہ عنہما سے سنا، انہوں نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم جب رات میں تہجد پڑھنے اٹھتے تو کہتے «اللهم لك الحمد أنت نور السموات والأرض،‏‏‏‏ ولك الحمد أنت قيم السموات والأرض،‏‏‏‏ ولك الحمد أنت رب السموات والأرض،‏‏‏‏ ومن فيهن أنت الحق،‏‏‏‏ ووعدك الحق وقولك الحق،‏‏‏‏ ولقاؤك الحق،‏‏‏‏ والجنة حق،‏‏‏‏ والنار حق،‏‏‏‏ والنبيون حق،‏‏‏‏ والساعة حق،‏‏‏‏ اللهم لك أسلمت،‏‏‏‏ وبك آمنت،‏‏‏‏ وعليك توكلت،‏‏‏‏ وإليك أنبت،‏‏‏‏ وبك خاصمت،‏‏‏‏ وإليك حاكمت،‏‏‏‏ فاغفر لي ما قدمت وما أخرت،‏‏‏‏ وما أسررت وما أعلنت،‏‏‏‏ أنت إلهي،‏‏‏‏ لا إله إلا أنت» ”حمد تیرے ہی لیے ہے کہ تو آسمان و زمین کا نور ہے، حمد تیرے ہی لیے ہے کہ تو آسمان و زمین کا تھامنے والا ہے، حمد تیرے ہی لیے ہے کہ تو آسمان و زمین کا اور جو کچھ اس میں ہے سب کا رب ہے۔ تو سچ ہے، تیرا وعدہ سچا ہے اور تیرا قول سچا ہے، تیری ملاقات سچی ہے، جنت سچ ہے اور دوزخ سچ ہے، سارے انبیاء سچے ہیں اور قیامت سچ ہے۔ اے اللہ! میں تیرے سامنے ہی جھکا، تجھ پر ایمان لایا، تجھ پر بھروسہ کیا، تیری ہی طرف رجوع کیا، تیرے ہی سامنے اپنا جھگڑا پیش کرتا اور تجھ ہی سے اپنا فیصلہ چاہتا ہوں، پس تو میری مغفرت کر دے اگلے پچھلے تمام گناہوں کی جو میں نے چھپا کر کئے اور جو ظاہر کئے، تو ہی میرا معبود ہے، تیرے سوا اور کوئی معبود نہیں۔“' WHERE id = 7214;
UPDATE hadiths SET urdu = 'ہم سے یوسف بن راشد نے بیان کیا، کہا ہم سے احمد بن عبداللہ یربوعی نے بیان کیا، کہا ہم سے ابوبکر بن عیاش نے، ان سے حمید نے بیان کیا کہ میں نے انس رضی اللہ عنہ سے سنا، کہا کہ میں نے نبی کریم صلی اللہ علیہ وسلم سے سنا، آپ صلی اللہ علیہ وسلم نے فرمایا کہ قیامت کے دن میری شفاعت قبول کی جائے گی۔ میں کہوں گا: اے رب! جس کے دل میں رائی کے دانہ کے برابر بھی ایمان ہو اس کو بھی جنت میں داخل فرما دے۔ ایسے لوگ جنت میں داخل کر دئیے جائیں گے۔ میں پھر عرض کروں گا: اے رب! جنت میں اسے بھی داخل کر دے جس کے دل میں معمولی سا بھی ایمان ہو۔ انس رضی اللہ عنہ نے کہا کہ گویا میں اس وقت بھی نبی کریم صلی اللہ علیہ وسلم کی انگلیوں کی طرف دیکھ رہا ہوں۔' WHERE id = 7224;
UPDATE hadiths SET urdu = 'ہم سے محمد بن سنان نے بیان کیا، انہوں نے کہا ہم سے فلیح بن سلیمان نے بیان کیا، انہوں نے کہا ہم سے ہلال بن علی نے بیان کیا، ان سے عطاء بن یسار نے بیان کیا اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم ایک دن گفتگو کر رہے تھے، اس وقت آپ کے پاس ایک بدوی بھی تھا ( فرمایا ) کہ اہل جنت میں سے ایک شخص نے اللہ تعالیٰ سے کھیتی کی اجازت چاہی تو اللہ تعالیٰ نے فرمایا کہ کیا وہ سب کچھ تمہارے پاس نہیں ہے جو تم چاہتے ہو؟ وہ کہے گا کہ ضرور لیکن میں چاہتا ہوں کہ کھیتی کروں۔ چنانچہ بہت جلدی وہ بیج ڈالے گا اور پلک جھپکنے تک اس کا اگنا، برابر کٹنا اور پہاڑوں کی طرح غلے کے انبار لگ جانا ہو جائے گا۔ اللہ تعالیٰ کہے گا: ابن آدم! اسے لے لے، تیرے پیٹ کو کوئی چیز نہیں بھر سکتی۔ دیہاتی نے کہا: یا رسول اللہ! اس کا مزہ تو قریشی یا انصاری ہی اٹھایں گے کیونکہ وہی کھیتی باڑی والے ہیں، ہم تو کسان ہیں نہیں۔ نبی کریم صلی اللہ علیہ وسلم کو یہ بات سن کر ہنسی آ گئی۔' WHERE id = 7234;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ مدینی نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے بیان کیا، ان سے زہری نے بیان کیا، ان سے سالم نے اور ان سے ان کے والد رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”رشک کے قابل تو دو ہی آدمی ہیں۔ ایک وہ جسے اللہ نے قرآن دیا اور وہ اس کی تلاوت رات دن کرتا رہتا ہے اور دوسرا وہ جسے اللہ نے مال دیا ہو اور وہ اسے رات و دن خرچ کرتا رہا۔“ علی بن عبداللہ نے کہا کہ میں نے یہ حدیث سفیان بن عیینہ سے کئی بار سنی «أخبرنا» کے لفظوں کے ساتھ انہیں کہتا سنا باوجود اس کے ان کی یہ حدیث صحیح اور متصل ہے۔' WHERE id = 7244;
UPDATE hadiths SET urdu = 'اور ابن عباس رضی اللہ عنہما نے بیان کیا کہ مجھے ابوسفیان بن حرب نے خبر دی کہ ہرقل نے اپنے ترجمان کو بلایا۔ پھر نبی کریم صلی اللہ علیہ وسلم کا خط منگوایا اور اسے پڑھا۔ شروع اللہ کے نام سے جو بہت نہایت رحم کرنے والا بڑا مہربان ہے۔ اللہ کے بندے اور اس کے رسول محمد صلی اللہ علیہ وسلم کی طرف سے ہرقل کی جانب۔ پھر یہ آیت لکھی تھی «يا أهل الكتاب تعالوا إلى كلمة سواء بيننا وبينكم» کہ ”اے کتاب والو! اس بات پر آ جاؤ جو ہم میں تم میں یکساں مانی جاتی ہے“ آخر آیت تک۔' WHERE id = 7256;
UPDATE hadiths SET urdu = 'ہم سے ابومعمر نے بیان کیا، کہا ہم سے عبدالوہاب نے، ان سے یزید نے کہ مجھ سے مطرف بن عبداللہ نے بیان کیا، ان سے عمران رضی اللہ عنہ نے کہ میں نے کہا یا رسول اللہ! پھر عمل کرنے والے کس لیے عمل کرتے ہیں؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ ہر شخص کے لیے اس عمل میں آسانی پیدا کر دی گئی ہے جس کے لیے وہ پیدا کیا گیا ہے۔' WHERE id = 7266;
